-- 1. DATABASE EXTENSIONS (Enhanced with Comprehensive Documentation)
-- =============================================================================--

-- Core Extensions for Functionality
CREATE EXTENSION IF NOT EXISTS "uuid-ossp" WITH SCHEMA public;
COMMENT ON EXTENSION "uuid-ossp" IS 'Generates universally unique identifiers for distributed system primary keys.
Ensures globally unique identifiers across multiple systems and databases, critical for distributed workforce scheduling
where multiple locations and systems need to synchronize data without conflicts. Provides UUID generation functions
(uuid_generate_v1, uuid_generate_v4) that create time-based and random UUIDs respectively. Essential for maintaining
data integrity in a microservices architecture where independent services create records that later need to be merged.';

CREATE EXTENSION IF NOT EXISTS pgcrypto WITH SCHEMA public;
COMMENT ON EXTENSION pgcrypto IS 'Provides cryptographic functions for password hashing and data security.
Includes bcrypt, SHA-256, and other strong hashing algorithms for secure password storage.
Also offers encryption/decryption capabilities for sensitive employee data such as social security numbers,
bank account information, and health records. Critical for compliance with GDPR, HIPAA, and other data protection
regulations. The extension is used in conjunction with security policies to ensure all personally identifiable
information (PII) is properly protected both at rest and in transit within the database.';

CREATE EXTENSION IF NOT EXISTS hstore WITH SCHEMA public;
COMMENT ON EXTENSION hstore IS 'Key-value store for flexible schema-less data storage.
Enables storage of dynamic attributes for workforce scheduling entities without requiring schema changes.
Used for storing custom attributes for employees, shifts, and locations that may vary by business unit or
region. Supports efficient indexing on key-value pairs for rapid retrieval of specific attributes.
Critical for implementing configurable business rules that may differ across departments or locations
without requiring database schema modifications. Allows the system to adapt to changing business requirements
without downtime or complex migrations.';

CREATE EXTENSION IF NOT EXISTS postgis WITH SCHEMA public;
COMMENT ON EXTENSION postgis IS 'Geographic object support for location-based features.
Provides spatial data types, functions, and indexes for working with geographic information.
Essential for location-aware scheduling, including proximity-based assignment of employees to shifts,
geofencing for attendance tracking, and territory management. Enables calculation of travel times between
locations, optimization of routes for mobile workforce, and visualization of workforce distribution on maps.
Supports integration with external mapping services and compliance with location-based labor regulations.';

CREATE EXTENSION IF NOT EXISTS pg_stat_statements WITH SCHEMA public;
COMMENT ON EXTENSION pg_stat_statements IS 'Tracks SQL execution statistics for performance monitoring.
Collects execution statistics of all SQL statements executed by a server, including total execution time,
number of calls, and resource usage. Critical for identifying performance bottlenecks in complex scheduling
algorithms and reporting queries. Enables proactive performance tuning by highlighting inefficient queries
that impact scheduling operations. Used in conjunction with monitoring systems to trigger alerts when query
performance degrades beyond acceptable thresholds. Essential for maintaining optimal performance during peak
scheduling periods when the system processes large volumes of scheduling data.';

CREATE EXTENSION IF NOT EXISTS pg_trgm WITH SCHEMA public;
COMMENT ON EXTENSION pg_trgm IS 'Trigram matching for advanced text search capabilities.
Enables fuzzy matching and similarity searches on textual data, critical for employee name matching,
skill search, and location identification. Supports efficient implementation of "Did you mean?" features
when users make typos in search terms. Used for matching employee names across different systems where
spelling variations might exist. Essential for improving user experience in workforce management systems
where accurate identification of personnel is critical for scheduling decisions.';

CREATE EXTENSION IF NOT EXISTS btree_gin WITH SCHEMA public;
COMMENT ON EXTENSION btree_gin IS 'GIN index support for B-tree functionality.
Enables efficient indexing of composite data types and arrays, critical for optimizing queries that
involve multiple conditions on scheduling data. Used for indexing employee availability patterns,
skill sets, and preference combinations. Supports fast filtering of employees based on multiple
criteria simultaneously, significantly improving performance of complex scheduling algorithms.
Essential for maintaining responsive user interfaces when working with large workforce datasets.';

CREATE EXTENSION IF NOT EXISTS tablefunc WITH SCHEMA public;
COMMENT ON EXTENSION tablefunc IS 'Table functions including crosstab for pivot tables.
Provides advanced data transformation capabilities essential for workforce analytics and reporting.
Enables conversion of scheduling data from long format to wide format for time-series analysis,
critical for identifying staffing patterns and trends. Supports generation of comprehensive workforce
dashboards that show staffing levels by hour, day, or week. Essential for business intelligence
reporting that helps managers identify scheduling inefficiencies and opportunities for optimization.';

