-- Scheduling Status Enums
-- Serial No: 1 | ENUM: scheduling.schedule_status_enum
-- Purpose: Defines the lifecycle status of schedules for workflow management
-- Business Case: This enumeration provides a standardized set of status values that represent the various stages
-- in a schedule's lifecycle, from creation through approval to execution and archiving. It enables consistent
-- tracking of schedule progression, facilitates automated workflow transitions, and supports status-based reporting.
-- The enumeration is critical for implementing approval workflows, managing schedule visibility, and ensuring
-- proper audit trails for schedule changes. It also enables filtering of schedules by status for user interfaces
-- and reporting, improving user experience and operational efficiency. The status values are designed to cover
-- all possible stages in a schedule's lifecycle while remaining flexible enough to accommodate future process changes.
-- KPI: Schedule approval cycle time, Draft schedule abandonment rate, Schedule publication timeliness,
--      Approval workflow efficiency, Schedule versioning frequency
-- Feature Reference: 1, 2, 3, 4, 5
DO $$BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'schedule_status_enum') THEN
        CREATE TYPE scheduling.schedule_status_enum AS ENUM (
            'DRAFT',                -- Schedule is being created or modified
            'PENDING_APPROVAL',     -- Schedule submitted for approval
            'APPROVED',             -- Schedule approved and ready for publication
            'PUBLISHED',            -- Schedule published to employees
            'EXECUTING',            -- Schedule is currently in effect
            'COMPLETED',            -- Schedule period has ended
            'ARCHIVED',             -- Schedule moved to long-term storage
            'CANCELLED',            -- Schedule was cancelled before execution
            'REVISION_REQUIRED'    -- Schedule needs changes before approval
        );
    END IF;
END$$;
COMMENT ON TYPE scheduling.schedule_status_enum IS 'Defines the lifecycle status of schedules for workflow management.
DRAFT: Schedule is being created or modified; PENDING_APPROVAL: Schedule submitted for approval;
APPROVED: Schedule approved and ready for publication; PUBLISHED: Schedule published to employees;
EXECUTING: Schedule is currently in effect; COMPLETED: Schedule period has ended;
ARCHIVED: Schedule moved to long-term storage; CANCELLED: Schedule was cancelled before execution;
REVISION_REQUIRED: Schedule needs changes before approval.';

-- Shift Status Enums
-- Serial No: 2 | ENUM: scheduling.shift_status_enum
-- Purpose: Defines the status of individual shifts within schedules
-- Business Case: This enumeration standardizes shift status tracking across the system, enabling consistent
-- handling of shift assignments, coverage status, and operational states. It supports real-time visibility
-- into shift coverage, facilitates automated gap detection, and enables status-based notifications. The
-- enumeration is critical for managing shift filling processes, tracking shift swaps, and monitoring
-- operational readiness. It also enables accurate reporting on shift coverage metrics and supports
-- compliance monitoring by tracking shifts that remain unfilled or require special attention. The status
-- values are designed to cover all possible shift states while supporting efficient workflow management.
-- KPI: Shift coverage rate, Time to fill open shifts, Shift swap completion rate,
--      Unfilled shift duration, Shift status transition efficiency
-- Feature Reference: 6, 7, 8, 9, 10
DO $$BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'shift_status_enum') THEN
        CREATE TYPE scheduling.shift_status_enum AS ENUM (
            'OPEN',                 -- Shift is available for assignment
            'ASSIGNED',             -- Shift is assigned to an employee
            'CONFIRMED',            -- Employee has confirmed the shift
            'PENDING_COVERAGE',     -- Shift needs coverage (employee called off)
            'COVERED',              -- Shift has been covered by replacement
            'CANCELLED',            -- Shift was cancelled
            'HOLD',                 -- Shift is on hold (e.g., awaiting approval)
            'IN_PROGRESS',          -- Shift is currently being worked
            'COMPLETED',            -- Shift has been completed
            'NO_SHOW',              -- Employee failed to show for shift
            'EARLY_LEAVE',          -- Employee left shift early
            'LATE_ARRIVAL'          -- Employee arrived late for shift
        );
    END IF;
END$$;
COMMENT ON TYPE scheduling.shift_status_enum IS 'Defines the status of individual shifts within schedules.
OPEN: Shift is available for assignment; ASSIGNED: Shift is assigned to an employee; CONFIRMED: Employee has confirmed the shift;
PENDING_COVERAGE: Shift needs coverage (employee called off); COVERED: Shift has been covered by replacement;
CANCELLED: Shift was cancelled; HOLD: Shift is on hold (e.g., awaiting approval); IN_PROGRESS: Shift is currently being worked;
COMPLETED: Shift has been completed; NO_SHOW: Employee failed to show for shift; EARLY_LEAVE: Employee left shift early;
LATE_ARRIVAL: Employee arrived late for shift.';

