-- =============================================================================--
-- 4. AUDIT COLUMNS AND TRIGGERS (Enhanced with Comprehensive Documentation)
-- =============================================================================--

-- Function to automatically update updated_at timestamp
-- Serial No: 6 | FUNCTION: public.update_updated_at_column()
-- Purpose: Automatically updates the updated_at timestamp on row modification
-- Business Case: This function ensures that all tables with timestamp tracking maintain accurate modification
-- timestamps without requiring application code to handle this detail. It provides a consistent mechanism for
-- tracking when records were last modified, which is critical for change tracking, data synchronization,
-- and debugging. The function is designed to be used as a trigger on tables that require modification
-- timestamp tracking. It handles both initial inserts (where updated_at may be null) and updates, ensuring
-- that the timestamp always reflects the most recent modification. This function is a foundational element
-- of the system's data integrity and audit capabilities, supporting compliance requirements and operational
-- visibility into data changes.
-- KPI: Data modification traceability, Audit completeness, Change detection accuracy,
--      Data synchronization reliability, Historical data accuracy
-- Feature Reference: 26, 27, 28, 29, 30
CREATE OR REPLACE FUNCTION public.update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION public.update_updated_at_column() IS 'Automatically updates updated_at timestamp on row modification.
Ensures all tables with timestamp tracking maintain accurate modification timestamps without requiring application code
to handle this detail. Provides consistent mechanism for tracking when records were last modified, critical for change
tracking, data synchronization, and debugging. Handles both initial inserts and updates, ensuring timestamp always reflects
most recent modification. Foundational element of system''s data integrity and audit capabilities.';

-- Function to generate audit entries
-- Serial No: 7 | FUNCTION: system.audit_trigger_function()
-- Purpose: Creates audit trail entries for data modifications
-- Business Case: This function implements comprehensive data auditing by capturing all changes to audited tables
-- in a centralized audit log. It records who made changes, when they were made, and what specific data was modified,
-- providing a complete historical record of data evolution. The audit trail is critical for compliance with regulatory
-- requirements, forensic analysis of data issues, and reconstruction of historical data states. The function is designed
-- to handle all common data modification operations (INSERT, UPDATE, DELETE) and captures both old and new values for
-- changed fields. It includes safeguards to prevent audit trail corruption and ensure completeness of the audit record.
-- The function supports both fine-grained field-level auditing and table-level change tracking, enabling flexible
-- auditing strategies based on data sensitivity and compliance requirements.
-- KPI: Audit coverage completeness, Audit data integrity, Audit query performance,
--      Compliance audit success rate, Audit trail retention compliance
-- Feature Reference: 31, 32, 33, 34, 35
CREATE OR REPLACE FUNCTION system.audit_trigger_function()
RETURNS TRIGGER AS $$
DECLARE
    v_old_data TEXT;
    v_new_data TEXT;
    v_user_id UUID;
BEGIN
    -- Get current user ID (could be from session context)
    SELECT current_setting('app.user_id', true) INTO v_user_id;
    IF v_user_id IS NULL THEN
        v_user_id = '00000000-0000-0000-0000-000000000000'::UUID;
    END IF;

    IF (TG_OP = 'DELETE') THEN
        v_old_data = row_to_json(OLD)::TEXT;
        INSERT INTO system.audit_log (
            table_name,
            record_id,
            operation,
            old_data,
            new_data,
            changed_by,
            changed_at
        ) VALUES (
            TG_TABLE_NAME,
            OLD.id,
            'DELETE',
            v_old_data,
            NULL,
            v_user_id,
            CURRENT_TIMESTAMP
        );
        RETURN OLD;

    ELSIF (TG_OP = 'UPDATE') THEN
        v_old_data = row_to_json(OLD)::TEXT;
        v_new_data = row_to_json(NEW)::TEXT;
        INSERT INTO system.audit_log (
            table_name,
            record_id,
            operation,
            old_data,
            new_data,
            changed_by,
            changed_at
        ) VALUES (
            TG_TABLE_NAME,
            NEW.id,
            'UPDATE',
            v_old_data,
            v_new_data,
            v_user_id,
            CURRENT_TIMESTAMP
        );
        RETURN NEW;

    ELSIF (TG_OP = 'INSERT') THEN
        v_new_data = row_to_json(NEW)::TEXT;
        INSERT INTO system.audit_log (
            table_name,
            record_id,
            operation,
            old_data,
            new_data,
            changed_by,
            changed_at
        ) VALUES (
            TG_TABLE_NAME,
            NEW.id,
            'INSERT',
            NULL,
            v_new_data,
            v_user_id,
            CURRENT_TIMESTAMP
        );
        RETURN NEW;
    END IF;
    RETURN NULL;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION system.audit_trigger_function() IS 'Creates audit trail entries for data modifications.
Implements comprehensive data auditing by capturing all changes to audited tables in a centralized audit log.
Records who made changes, when they were made, and what specific data was modified, providing complete historical
record of data evolution. Critical for compliance with regulatory requirements, forensic analysis of data issues,
and reconstruction of historical data states. Handles all common data modification operations (INSERT, UPDATE, DELETE)
and captures both old and new values for changed fields. Includes safeguards to prevent audit trail corruption and
ensure completeness of the audit record. Supports both fine-grained field-level auditing and table-level change tracking.';

-- Audit Log Table
-- Serial No: 8 | TABLE: system.audit_log
-- Description: Central repository for tracking all data modifications across the system
-- Business Case: The audit log table serves as the foundation for system-wide data auditing, capturing a complete
-- history of all significant data changes. It enables regulatory compliance by providing an immutable record of
-- who changed what and when, which is required by many data protection regulations. The table supports forensic
-- analysis of data issues by allowing reconstruction of historical data states and identification of change
-- patterns. It also facilitates data synchronization between systems by providing a reliable change feed. The
-- audit log is designed with performance in mind, using efficient storage formats and indexing strategies to
-- minimize impact on transactional operations while ensuring query performance for audit analysis. The table
-- includes mechanisms for managing retention periods and archiving older audit records to balance compliance
-- requirements with storage costs.
-- KPI: Audit record completeness, Audit query response time,
--      Audit data retention compliance, Audit trail integrity,
--      Audit-related support resolution time
-- Feature Reference: 36, 37, 38, 39, 40
CREATE TABLE IF NOT EXISTS system.audit_log (
    audit_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    table_name VARCHAR(100) NOT NULL,
    record_id UUID NOT NULL,
    operation VARCHAR(10) NOT NULL CHECK (operation IN ('INSERT', 'UPDATE', 'DELETE')),
    old_data JSONB,
    new_data JSONB,
    changed_by UUID NOT NULL,
    changed_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    client_ip INET,
    application_name VARCHAR(100),
    transaction_id UUID
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_audit_log_table_name ON system.audit_log(table_name);
CREATE INDEX IF NOT EXISTS idx_audit_log_record_id ON system.audit_log(record_id);
CREATE INDEX IF NOT EXISTS idx_audit_log_changed_by ON system.audit_log(changed_by);
CREATE INDEX IF NOT EXISTS idx_audit_log_changed_at ON system.audit_log(changed_at DESC);
CREATE INDEX IF NOT EXISTS idx_audit_log_operation ON system.audit_log(operation);

COMMENT ON TABLE system.audit_log IS 'Central repository for tracking all data modifications across the system.
Serves as foundation for system-wide data auditing, capturing complete history of all significant data changes.
Enables regulatory compliance by providing immutable record of who changed what and when. Supports forensic analysis
of data issues by allowing reconstruction of historical data states. Facilitates data synchronization between systems
by providing reliable change feed. Designed with performance in mind using efficient storage formats and indexing strategies.
Includes mechanisms for managing retention periods and archiving older audit records.';

COMMENT ON COLUMN system.audit_log.table_name IS 'Name of the table that was modified';
COMMENT ON COLUMN system.audit_log.record_id IS 'Primary key of the modified record';
COMMENT ON COLUMN system.audit_log.operation IS 'Type of database operation (INSERT, UPDATE, DELETE)';
COMMENT ON COLUMN system.audit_log.old_data IS 'JSON representation of data before modification (for UPDATE/DELETE)';
COMMENT ON COLUMN system.audit_log.new_data IS 'JSON representation of data after modification (for INSERT/UPDATE)';
COMMENT ON COLUMN system.audit_log.changed_by IS 'User who made the modification';
COMMENT ON COLUMN system.audit_log.changed_at IS 'Timestamp when modification occurred';
COMMENT ON COLUMN system.audit_log.client_ip IS 'IP address of client making the modification';
COMMENT ON COLUMN system.audit_log.application_name IS 'Name of application making the modification';
COMMENT ON COLUMN system.audit_log.transaction_id IS 'Database transaction ID for the modification';

