-- 5. COMPLETE DDL STATEMENTS - TABLES 1-200 (Enhanced with Comprehensive Documentation)
-- =============================================================================--
-- Serial No: 9 | TABLE: hr.employees
-- Description: Core employee master data with comprehensive personal and employment information
-- Business Case: The employees table serves as the central repository for all workforce data, forming the foundation
-- for all scheduling, payroll, and HR processes. It contains complete employee profiles including personal information,
-- employment details, compensation data, and organizational relationships. This table is critical for ensuring
-- accurate scheduling by providing the complete context about each employee's qualifications, availability, and
-- constraints. The data model supports complex employment arrangements including part-time, full-time, and temporary
-- workers with varying contractual terms. It integrates with skills and certification data to enable qualification-based
-- scheduling and compliance with regulatory requirements. The table includes robust history tracking to maintain
-- accurate records of employment changes for legal and reporting purposes. Designed with privacy considerations in mind,
-- it supports data masking for sensitive fields based on user roles and permissions. The table is optimized for high
-- performance during scheduling operations, which frequently query employee availability and qualifications.
-- KPI: Employee data completeness, Data accuracy rate, Profile update frequency,
--      Compliance with data retention policies, Integration success rate with external systems
-- Feature Reference: 41, 42, 43, 44, 45
CREATE TABLE IF NOT EXISTS hr.employees (
    employee_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    company_id UUID NOT NULL,
    employee_code VARCHAR(20) UNIQUE NOT NULL CHECK (employee_code ~ '^[A-Z0-9]{4,20}$'),
    first_name VARCHAR(100) NOT NULL,
    middle_name VARCHAR(100),
    last_name VARCHAR(100) NOT NULL,
    preferred_name VARCHAR(100),
    email VARCHAR(255) NOT NULL CHECK (email ~* '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$'),
    secondary_email VARCHAR(255) CHECK (secondary_email ~* '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$' OR secondary_email IS NULL),
    phone VARCHAR(20),
    mobile_phone VARCHAR(20),
    address_line1 VARCHAR(255),
    address_line2 VARCHAR(255),
    city VARCHAR(100),
    state_province VARCHAR(100),
    postal_code VARCHAR(20),
    country VARCHAR(100) NOT NULL,
    date_of_birth DATE CHECK (date_of_birth <= CURRENT_DATE - INTERVAL '18 years'),
    gender VARCHAR(20) CHECK (gender IN ('MALE', 'FEMALE', 'NON_BINARY', 'PREFER_NOT_TO_SAY', 'OTHER')),
    ethnicity VARCHAR(50),
    emergency_contact_name VARCHAR(255),
    emergency_contact_phone VARCHAR(20),
    -- Sensitive data - store as encrypted bytea using pgcrypto
    social_security_number BYTEA,
    tax_id BYTEA,
    hire_date DATE NOT NULL CHECK (hire_date <= CURRENT_DATE),
    termination_date DATE CHECK (termination_date IS NULL OR termination_date >= hire_date),
    employment_status VARCHAR(50) NOT NULL DEFAULT 'ACTIVE' CHECK (employment_status IN ('ACTIVE', 'ON_LEAVE', 'TERMINATED', 'SUSPENDED', 'PROBATION')),
    employment_type VARCHAR(50) NOT NULL CHECK (employment_type IN ('FULL_TIME', 'PART_TIME', 'TEMPORARY', 'SEASONAL', 'CONTRACTOR')),
    work_schedule_type VARCHAR(50) CHECK (work_schedule_type IN ('FLEXIBLE', 'FIXED', 'SHIFT_WORK', 'REMOTE', 'HYBRID')),
    weekly_hours NUMERIC(5,2) CHECK (weekly_hours > 0 AND weekly_hours <= 168),
    is_management BOOLEAN NOT NULL DEFAULT FALSE,
    reports_to UUID REFERENCES hr.employees(employee_id),
    department_id UUID NOT NULL,
    location_id UUID NOT NULL,
    position_id UUID NOT NULL,
    job_title VARCHAR(100) NOT NULL,
    cost_center VARCHAR(50),
    pay_grade VARCHAR(20),
    compensation_type VARCHAR(20) NOT NULL CHECK (compensation_type IN ('HOURLY', 'SALARY', 'COMMISSION')),
    hourly_rate NUMERIC(10,2) CHECK (hourly_rate >= 0),
    annual_salary NUMERIC(12,2) CHECK (annual_salary >= 0),
    currency VARCHAR(3) DEFAULT 'USD',
    direct_deposit BOOLEAN DEFAULT FALSE,
    benefits_eligibility_date DATE,
    probation_end_date DATE,
    last_performance_review DATE,
    next_review_date DATE,
    preferred_language VARCHAR(10) DEFAULT 'en-US',
    timezone VARCHAR(50) DEFAULT 'America/New_York',
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    data_sensitivity_level VARCHAR(20) DEFAULT 'CONFIDENTIAL' CHECK (data_sensitivity_level IN ('PUBLIC', 'INTERNAL', 'CONFIDENTIAL', 'SECRET'))
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_employees_company ON hr.employees(company_id);
CREATE INDEX IF NOT EXISTS idx_employees_department ON hr.employees(department_id);
CREATE INDEX IF NOT EXISTS idx_employees_location ON hr.employees(location_id);
CREATE INDEX IF NOT EXISTS idx_employees_position ON hr.employees(position_id);
CREATE INDEX IF NOT EXISTS idx_employees_status ON hr.employees(employment_status);
CREATE INDEX IF NOT EXISTS idx_employees_hire_date ON hr.employees(hire_date DESC);
CREATE INDEX IF NOT EXISTS idx_employees_name ON hr.employees(last_name, first_name);
CREATE INDEX IF NOT EXISTS idx_employees_email ON hr.employees(email);
CREATE INDEX IF NOT EXISTS idx_employees_reports_to ON hr.employees(reports_to);

