-- Serial No: 10 | TABLE: scheduling.schedules
-- Description: Master schedule records with metadata and status tracking
-- Business Case: The schedules table is the central entity for managing workforce schedules across the organization.
-- It tracks all schedule instances including their time periods, locations, departments, and current status in the
-- scheduling workflow. This table enables the system to manage multiple concurrent schedules for different business
-- units while maintaining a consistent scheduling process. It serves as the parent entity for all shift assignments
-- within a schedule period, providing the context for shift-level operations. The table includes comprehensive
-- metadata for schedule generation including optimization parameters, constraint settings, and performance metrics.
CREATE TABLE IF NOT EXISTS scheduling.schedules (
    schedule_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    schedule_code VARCHAR(50) UNIQUE NOT NULL CHECK (schedule_code ~ '^[A-Z0-9_-]{5,50}$'),
    name VARCHAR(200) NOT NULL,
    description TEXT,
    location_id UUID NOT NULL,
    department_id UUID NOT NULL,
    start_date DATE NOT NULL,
    end_date DATE NOT NULL CHECK (end_date >= start_date),
    schedule_status scheduling.schedule_status_enum NOT NULL DEFAULT 'DRAFT',
    created_by UUID NOT NULL,
    approved_by UUID,
    published_by UUID,
    template_id UUID, -- Will reference schedule_templates after it's created
    schedule_type VARCHAR(50) NOT NULL DEFAULT 'REGULAR' CHECK (schedule_type IN ('REGULAR', 'OVERTIME', 'EVENT_BASED', 'SEASONAL', 'EMERGENCY')),
    optimization_level VARCHAR(50) NOT NULL DEFAULT 'BALANCED' CHECK (optimization_level IN ('COST_MINIMIZED', 'EMPLOYEE_SATISFACTION', 'BALANCED', 'COMPLIANCE_FOCUSED')),
    constraint_violation_count INTEGER DEFAULT 0 CHECK (constraint_violation_count >= 0),
    coverage_percentage NUMERIC(5,2) DEFAULT 100.00 CHECK (coverage_percentage BETWEEN 0.00 AND 100.00),
    labor_cost_estimate NUMERIC(12,2),
    actual_labor_cost NUMERIC(12,2),
    performance_score NUMERIC(5,2) CHECK (performance_score BETWEEN 0.00 AND 100.00),
    notes TEXT,
    approval_chain JSONB,
    published_at TIMESTAMP WITH TIME ZONE,
    archived_at TIMESTAMP WITH TIME ZONE,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    created_by_uuid UUID NOT NULL,
    updated_by_uuid UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Add indexes for schedules
CREATE INDEX IF NOT EXISTS idx_schedules_location ON scheduling.schedules(location_id);
CREATE INDEX IF NOT EXISTS idx_schedules_department ON scheduling.schedules(department_id);
CREATE INDEX IF NOT EXISTS idx_schedules_status ON scheduling.schedules(schedule_status);
CREATE INDEX IF NOT EXISTS idx_schedules_dates ON scheduling.schedules(start_date, end_date);
CREATE INDEX IF NOT EXISTS idx_schedules_created_by ON scheduling.schedules(created_by_uuid);
CREATE INDEX IF NOT EXISTS idx_schedules_approved_by ON scheduling.schedules(approved_by);
CREATE INDEX IF NOT EXISTS idx_schedules_active ON scheduling.schedules(is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_schedules_metadata ON scheduling.schedules USING GIN(metadata);

-- Add triggers for schedules
CREATE TRIGGER trg_schedules_updated_at
BEFORE UPDATE ON scheduling.schedules
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

