-- Serial No: 11 | TABLE: scheduling.shifts
-- Description: Individual shift assignments within schedules
-- Business Case: The shifts table represents the atomic unit of workforce scheduling, capturing all details about
-- specific work periods assigned to employees.
CREATE TABLE IF NOT EXISTS scheduling.shifts (
    shift_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    schedule_id UUID NOT NULL REFERENCES scheduling.schedules(schedule_id) ON DELETE CASCADE,
    location_id UUID NOT NULL,
    department_id UUID NOT NULL,
    position_id UUID NOT NULL,
    role_id UUID NOT NULL,
    employee_id UUID REFERENCES hr.employees(employee_id),
    start_time TIMESTAMP WITH TIME ZONE NOT NULL,
    end_time TIMESTAMP WITH TIME ZONE NOT NULL CHECK (end_time > start_time),
    actual_start_time TIMESTAMP WITH TIME ZONE,
    actual_end_time TIMESTAMP WITH TIME ZONE,
    shift_status scheduling.shift_status_enum NOT NULL DEFAULT 'OPEN',
    shift_type VARCHAR(50) NOT NULL DEFAULT 'REGULAR' CHECK (shift_type IN ('REGULAR', 'OVERTIME', 'CALL_IN', 'STANDBY', 'TRAINING')),
    is_primary BOOLEAN NOT NULL DEFAULT TRUE,
    required_skill_level INTEGER CHECK (required_skill_level BETWEEN 1 AND 5),
    minimum_experience_months INTEGER CHECK (minimum_experience_months >= 0),
    pay_rate_multiplier NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (pay_rate_multiplier >= 0.50 AND pay_rate_multiplier <= 3.00),
    break_start TIMESTAMP WITH TIME ZONE,
    break_end TIMESTAMP WITH TIME ZONE,
    break_duration_minutes INTEGER CHECK (break_duration_minutes BETWEEN 0 AND 180),
    notes TEXT,
    priority INTEGER DEFAULT 0 CHECK (priority BETWEEN -10 AND 10),
    coverage_confidence NUMERIC(5,2) DEFAULT 100.00 CHECK (coverage_confidence BETWEEN 0.00 AND 100.00),
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
