-- Serial No: 12 | TABLE: scheduling.schedule_templates
-- Description: Reusable schedule patterns for consistent scheduling
-- Business Case: The schedule_templates table enables the creation and management of standardized schedule patterns
-- that can be reused across multiple schedule periods. This is critical for maintaining consistency in scheduling
-- practices while reducing the time and effort required to create new schedules. Templates capture proven scheduling
-- approaches that meet business requirements and compliance constraints, allowing organizations to leverage historical
-- knowledge in future scheduling efforts. The table supports versioning of templates to track evolution of scheduling
-- patterns over time and enables A/B testing of different template approaches. It includes metadata about template
-- performance to support data-driven selection of the most effective templates for specific contexts. The template
-- system facilitates knowledge transfer between scheduling managers and preserves institutional knowledge about
-- effective scheduling approaches. It also enables rapid response to recurring business patterns such as seasonal
-- fluctuations or regular events by providing pre-validated scheduling approaches. The design supports complex
-- template structures including conditional rules that adapt to changing business conditions.
-- KPI: Template usage rate, Template effectiveness score, Time saved through template usage,
--      Template adaptation frequency, Template compliance rate
-- Feature Reference: 56, 57, 58, 59, 60
CREATE TABLE IF NOT EXISTS scheduling.schedule_templates (
    template_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    template_code VARCHAR(50) UNIQUE NOT NULL CHECK (template_code ~ '^[A-Z0-9_]{5,50}$'),
    name VARCHAR(200) NOT NULL,
    description TEXT,
    location_id UUID,
    department_id UUID,
    position_id UUID,
    template_type VARCHAR(50) NOT NULL DEFAULT 'STANDARD' CHECK (template_type IN ('STANDARD', 'SEASONAL', 'EVENT_BASED', 'CUSTOM')),
    recurrence_pattern VARCHAR(50) NOT NULL DEFAULT 'WEEKLY' CHECK (recurrence_pattern IN ('DAILY', 'WEEKLY', 'BIWEEKLY', 'MONTHLY', 'CUSTOM')),
    recurrence_details JSONB,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_default BOOLEAN NOT NULL DEFAULT FALSE,
    priority INTEGER DEFAULT 0 CHECK (priority BETWEEN -10 AND 10),
    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
    based_on_template_id UUID REFERENCES scheduling.schedule_templates(template_id),
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_schedule_templates_location ON scheduling.schedule_templates(location_id) WHERE location_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_schedule_templates_department ON scheduling.schedule_templates(department_id) WHERE department_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_schedule_templates_position ON scheduling.schedule_templates(position_id) WHERE position_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_schedule_templates_type ON scheduling.schedule_templates(template_type);
CREATE INDEX IF NOT EXISTS idx_schedule_templates_active ON scheduling.schedule_templates(is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_schedule_templates_default ON scheduling.schedule_templates(is_default) WHERE is_default = TRUE;
CREATE INDEX IF NOT EXISTS idx_schedule_templates_version ON scheduling.schedule_templates(template_id, version_number DESC);
CREATE INDEX IF NOT EXISTS idx_schedule_templates_based_on ON scheduling.schedule_templates(based_on_template_id);
CREATE INDEX IF NOT EXISTS idx_schedule_templates_metadata ON scheduling.schedule_templates USING GIN(metadata);

-- Add triggers for audit columns
CREATE TRIGGER trg_schedule_templates_updated_at
BEFORE UPDATE ON scheduling.schedule_templates
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

