-- Serial No: 13 | TABLE: hr.skills
-- Description: Master list of skills and competencies
-- Business Case: The skills table provides a centralized repository of all skills and competencies recognized
-- by the organization, forming the foundation for skills-based workforce management. This standardized taxonomy
-- enables consistent assessment and tracking of employee capabilities across the organization. The table supports
-- hierarchical organization of skills to represent broader categories and specific sub-skills, facilitating
-- nuanced skill assessment and development planning. It includes metadata about each skill's importance,
-- required proficiency levels for different positions, and typical development paths. This information is
-- critical for career planning, succession management, and identifying high-potential employees. The skill
-- definitions also support integration with training systems by linking skills to specific courses and
-- development activities. The table is designed to accommodate industry-specific skill frameworks while
-- allowing for organizational customization. It serves as the reference point for all skills-related data
-- in the system, ensuring consistency in how skills are represented and utilized across different modules.
-- KPI: Skill taxonomy completeness, Skill utilization rate, Skills gap identification rate,
--      Skills framework adoption rate, Skills data quality
-- Feature Reference: 66, 67, 68, 69, 70
CREATE TABLE IF NOT EXISTS hr.skills (
    skill_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    skill_code VARCHAR(50) UNIQUE NOT NULL CHECK (skill_code ~ '^[A-Z0-9_]{3,50}$'),
    name VARCHAR(100) NOT NULL,
    description TEXT,
    category VARCHAR(50) NOT NULL,
    sub_category VARCHAR(50),
    is_certification_required BOOLEAN NOT NULL DEFAULT FALSE,
    typical_certification_duration INTERVAL,
    renewal_required BOOLEAN NOT NULL DEFAULT FALSE,
    renewal_interval INTERVAL,
    required_for_positions UUID[],
    proficiency_scale VARCHAR(50) NOT NULL DEFAULT 'STANDARD'
        CHECK (proficiency_scale IN ('STANDARD', 'INDUSTRY_SPECIFIC', 'CUSTOM')),
    proficiency_definitions JSONB,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    parent_skill_id UUID REFERENCES hr.skills(skill_id),
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_skills_category ON hr.skills(category);
CREATE INDEX IF NOT EXISTS idx_skills_subcategory ON hr.skills(sub_category);
CREATE INDEX IF NOT EXISTS idx_skills_certification ON hr.skills(is_certification_required);
CREATE INDEX IF NOT EXISTS idx_skills_active ON hr.skills(is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_skills_parent ON hr.skills(parent_skill_id) WHERE parent_skill_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_skills_metadata ON hr.skills USING GIN(metadata);

