-- Serial No: 14 | TABLE: hr.employee_skills
-- Description: Skills and proficiency levels for employees
-- Business Case: The employee_skills table forms the foundation for skills-based scheduling by capturing each
-- employee's capabilities and proficiency levels across various competencies. This information is critical
-- for ensuring that shifts are staffed with appropriately qualified personnel, particularly in environments
-- where specific skills are required for safety or regulatory compliance. The table supports multiple
-- dimensions of skill assessment including certification status, practical experience, and proficiency ratings.
-- It enables the system to match employee capabilities with shift requirements, optimizing both operational
-- effectiveness and employee development opportunities. The design accommodates skill decay over time by
-- tracking certification expiration dates and required refresh training. It also supports skills gap analysis
-- to identify training needs and career development opportunities. The table is optimized for rapid lookup
-- during scheduling operations, which frequently evaluate multiple skill requirements simultaneously.
-- The skill framework is designed to be extensible, allowing organizations to define custom skill taxonomies
-- that align with their specific business needs and industry requirements.
-- KPI: Skills coverage rate, Certification compliance rate, Skills gap closure rate,
--      Training completion rate, Skills-based scheduling accuracy
-- Feature Reference: 61, 62, 63, 64, 65
CREATE TABLE IF NOT EXISTS hr.employee_skills (
    employee_skill_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    employee_id UUID NOT NULL REFERENCES hr.employees(employee_id) ON DELETE CASCADE,
    skill_id UUID NOT NULL REFERENCES hr.skills(skill_id),
    proficiency_level INTEGER NOT NULL CHECK (proficiency_level BETWEEN 1 AND 5),
    certification_number VARCHAR(100),
    certification_issued_date DATE,
    certification_expiry_date DATE,
    last_assessment_date DATE,
    assessment_method VARCHAR(50) CHECK (assessment_method IN ('TEST', 'OBSERVATION', 'SUPERVISOR_EVAL', 'CERTIFICATION')),
    assessment_score NUMERIC(5,2) CHECK (assessment_score BETWEEN 0.00 AND 100.00),
    is_primary BOOLEAN NOT NULL DEFAULT FALSE,
    verified_by UUID REFERENCES hr.employees(employee_id),
    verification_date DATE,
    notes TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
	metadata JSONB
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_employee_skills_employee ON hr.employee_skills(employee_id);
CREATE INDEX IF NOT EXISTS idx_employee_skills_skill ON hr.employee_skills(skill_id);
CREATE INDEX IF NOT EXISTS idx_employee_skills_proficiency ON hr.employee_skills(proficiency_level);
CREATE INDEX IF NOT EXISTS idx_employee_skills_expiry ON hr.employee_skills(certification_expiry_date)
    WHERE certification_expiry_date IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_employee_skills_primary ON hr.employee_skills(is_primary) WHERE is_primary = TRUE;
CREATE INDEX IF NOT EXISTS idx_employee_skills_verified ON hr.employee_skills(verified_by) WHERE verified_by IS NOT NULL;

-- Add triggers for audit columns
CREATE TRIGGER trg_employee_skills_updated_at
BEFORE UPDATE ON hr.employee_skills
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE hr.employee_skills IS 'Skills and proficiency levels for employees.
Forms the foundation for skills-based scheduling by capturing each employee''s capabilities and proficiency levels across
various competencies. Critical for ensuring shifts are staffed with appropriately qualified personnel, particularly in
environments where specific skills are required for safety or regulatory compliance. Supports multiple dimensions of skill
assessment including certification status, practical experience, and proficiency ratings. Enables system to match employee
capabilities with shift requirements, optimizing operational effectiveness and employee development opportunities.
Accommodates skill decay over time by tracking certification expiration dates and required refresh training. Supports
skills gap analysis to identify training needs and career development opportunities. Optimized for rapid lookup during
scheduling operations, which frequently evaluate multiple skill requirements simultaneously. Skill framework is extensible,
allowing organizations to define custom skill taxonomies.';



-- Serial No: 15 | TABLE: scheduling.employee_availability
-- Description: Employee availability patterns and constraints
-- Business Case: The employee_availability table captures each employee's scheduling constraints and preferences,
-- which are critical inputs for the scheduling engine. It records both regular availability patterns (e.g.,
-- "available Monday-Friday 9am-5pm") and specific date exceptions (e.g., "unavailable July 4th"). This
-- information enables the system to create schedules that respect employee constraints while meeting
-- business needs, improving both schedule quality and employee satisfaction. The table supports multiple
-- types of availability specifications including standard patterns, temporary changes, and recurring
-- preferences. It also tracks the source of availability information (e.g., self-reported, manager-approved)
-- to support appropriate workflow handling. The design accommodates complex availability scenarios such
-- as split availability windows and partial-day availability. Availability data is versioned to track
-- changes over time, which is important for understanding historical scheduling patterns and resolving
-- disputes. The table is optimized for rapid querying during schedule generation, which involves evaluating
-- availability constraints for potentially hundreds of employees simultaneously.
-- KPI: Availability adherence rate, Schedule conflict rate,
--      Employee satisfaction with schedule, Availability update frequency,
--      Availability pattern consistency
-- Feature Reference: 71, 72, 73, 74, 75
CREATE TABLE IF NOT EXISTS scheduling.employee_availability (
    availability_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    employee_id UUID NOT NULL REFERENCES hr.employees(employee_id) ON DELETE CASCADE,
    availability_type scheduling.availability_type_enum NOT NULL DEFAULT 'STANDARD',
    start_date DATE NOT NULL,
    end_date DATE,
    day_of_week INTEGER CHECK (day_of_week BETWEEN 1 AND 7), -- 1=Monday, 7=Sunday
    start_time TIME NOT NULL,
    end_time TIME NOT NULL CHECK (end_time > start_time),
    is_recurring BOOLEAN NOT NULL DEFAULT FALSE,
    recurrence_pattern VARCHAR(50),
    recurrence_interval INTEGER,
    recurrence_end_date DATE,
    specific_date DATE,
    is_approved BOOLEAN NOT NULL DEFAULT FALSE,
    approval_notes TEXT,
    approved_by UUID REFERENCES hr.employees(employee_id),
    approval_date TIMESTAMP WITH TIME ZONE,
    source_system VARCHAR(50) NOT NULL DEFAULT 'EMPLOYEE_SELF_SERVICE'
        CHECK (source_system IN ('EMPLOYEE_SELF_SERVICE', 'MANAGER', 'HR_SYSTEM', 'IMPORTED')),
    notes TEXT,
    priority INTEGER DEFAULT 0 CHECK (priority BETWEEN -10 AND 10),
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_employee_availability_employee ON scheduling.employee_availability(employee_id);
CREATE INDEX IF NOT EXISTS idx_employee_availability_type ON scheduling.employee_availability(availability_type);
CREATE INDEX IF NOT EXISTS idx_employee_availability_dates ON scheduling.employee_availability(start_date, end_date);
CREATE INDEX IF NOT EXISTS idx_employee_availability_day ON scheduling.employee_availability(day_of_week)
    WHERE day_of_week IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_employee_availability_recurring ON scheduling.employee_availability(is_recurring)
    WHERE is_recurring = TRUE;
CREATE INDEX IF NOT EXISTS idx_employee_availability_specific ON scheduling.employee_availability(specific_date)
    WHERE specific_date IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_employee_availability_approved ON scheduling.employee_availability(is_approved)
    WHERE is_approved = FALSE;
CREATE INDEX IF NOT EXISTS idx_employee_availability_priority ON scheduling.employee_availability(priority DESC);
CREATE INDEX IF NOT EXISTS idx_employee_availability_metadata ON scheduling.employee_availability USING GIN(metadata);

-- Add triggers for audit columns
CREATE TRIGGER trg_employee_availability_updated_at
BEFORE UPDATE ON scheduling.employee_availability
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE scheduling.employee_availability IS 'Employee availability patterns and constraints.
Captures each employee''s scheduling constraints and preferences, which are critical inputs for the scheduling engine.
Records both regular availability patterns (e.g., "available Monday-Friday 9am-5pm") and specific date exceptions
(e.g., "unavailable July 4th"). Enables system to create schedules that respect employee constraints while meeting
