-- Serial No: 16 | TABLE: compliance.union_rules
-- Description: Union agreement rules and constraints
-- Business Case: The union_rules table stores the specific rules and constraints derived from collective
-- bargaining agreements, which are critical for ensuring compliance in unionized environments. It captures
-- detailed requirements around scheduling practices, including minimum rest periods, maximum consecutive
-- work hours, seniority-based assignment rules, and overtime regulations. The table supports versioning
-- of union agreements to maintain historical compliance and handle agreement changes over time. Each rule
-- includes metadata about its effective dates, jurisdiction, and enforcement priority to support appropriate
-- application in scheduling decisions. The design accommodates complex rule structures through a
-- combination of standard rule types and custom expression capabilities. This enables precise representation
-- of nuanced union requirements while maintaining computational efficiency during compliance checks.
-- The table also tracks rule exceptions and approvals to support proper documentation of compliance
-- deviations when necessary. This information is critical for mitigating legal risks associated with
-- improper scheduling in unionized environments and provides an audit trail for labor relations matters.
-- KPI: Union rule compliance rate, Rule violation resolution time,
--      Union grievance rate, Rule documentation completeness,
--      Compliance audit success rate
-- Feature Reference: 76, 77, 78, 79, 80
CREATE TABLE IF NOT EXISTS compliance.union_rules (
    rule_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    rule_code VARCHAR(50) UNIQUE NOT NULL CHECK (rule_code ~ '^[A-Z0-9_]{3,50}$'),
    title VARCHAR(200) NOT NULL,
    description TEXT NOT NULL,
    rule_type VARCHAR(50) NOT NULL CHECK (rule_type IN ('REST_PERIOD', 'MAX_HOURS', 'SENIORITY', 'OVERTIME', 'PREFERENCE', 'OTHER')),
    effective_date DATE NOT NULL,
    expiration_date DATE,
    jurisdiction VARCHAR(100) NOT NULL,
    applies_to_positions UUID[],
    applies_to_locations UUID[],
    applies_to_departments UUID[],
    rule_expression TEXT NOT NULL,
    rule_parameters JSONB,
    enforcement_level VARCHAR(50) NOT NULL DEFAULT 'MANDATORY'
        CHECK (enforcement_level IN ('MANDATORY', 'PREFERRED', 'INFORMATIONAL')),
    severity VARCHAR(20) NOT NULL DEFAULT 'HIGH'
        CHECK (severity IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
    based_on_rule_id UUID REFERENCES compliance.union_rules(rule_id),
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_union_rules_type ON compliance.union_rules(rule_type);
CREATE INDEX IF NOT EXISTS idx_union_rules_jurisdiction ON compliance.union_rules(jurisdiction);
CREATE INDEX IF NOT EXISTS idx_union_rules_effective ON compliance.union_rules(effective_date, expiration_date);
CREATE INDEX IF NOT EXISTS idx_union_rules_active ON compliance.union_rules(is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_union_rules_severity ON compliance.union_rules(severity);
CREATE INDEX IF NOT EXISTS idx_union_rules_version ON compliance.union_rules(rule_id, version_number DESC);
CREATE INDEX IF NOT EXISTS idx_union_rules_based_on ON compliance.union_rules(based_on_rule_id);
CREATE INDEX IF NOT EXISTS idx_union_rules_parameters ON compliance.union_rules USING GIN(rule_parameters);
CREATE INDEX IF NOT EXISTS idx_union_rules_metadata ON compliance.union_rules USING GIN(metadata);

-- Add triggers for audit columns
CREATE TRIGGER trg_union_rules_updated_at
BEFORE UPDATE ON compliance.union_rules
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE compliance.union_rules IS 'Union agreement rules and constraints.
Stores specific rules and constraints derived from collective bargaining agreements, critical for ensuring compliance in
unionized environments. Captures detailed requirements around scheduling practices, including minimum rest periods,
maximum consecutive work hours, seniority-based assignment rules, and overtime regulations. Supports versioning of union
