-- Serial No: 17 | TABLE: scheduling.shift_swaps
-- Description: Employee-initiated shift exchange requests
-- Business Case: The shift_swaps table manages the process of employees requesting to exchange shifts with
-- each other, which is a common requirement in workforce scheduling. It captures all details of swap requests
-- including the initiating employee, proposed swap partner, shift details, and current status in the approval
-- workflow. This functionality improves employee satisfaction by providing flexibility in schedule management
-- while maintaining proper oversight through manager approval. The table supports complex swap scenarios
-- including multi-party swaps and conditional swaps. It includes comprehensive tracking of swap history for
-- audit and analysis purposes. The design accommodates organizational policies around shift swapping through
-- configurable rules and constraints. The table also tracks the business impact of swaps, such as changes in
-- coverage levels or compliance status, to support informed approval decisions. This information is valuable
-- for understanding swap patterns and their impact on overall schedule quality. The table is optimized for
-- rapid processing of swap requests during peak periods when many employees may be seeking schedule adjustments.
-- KPI: Swap request completion rate, Average swap approval time,
--      Employee satisfaction with swap process, Swap-related coverage gaps,
--      Policy compliance rate for swaps
-- Feature Reference: 81, 82, 83, 84, 85
CREATE TABLE IF NOT EXISTS scheduling.shift_swaps (
    swap_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    requesting_employee_id UUID NOT NULL REFERENCES hr.employees(employee_id),
    requested_shift_id UUID NOT NULL REFERENCES scheduling.shifts(shift_id),
    offering_shift_id UUID NOT NULL REFERENCES scheduling.shifts(shift_id),
    proposed_with_employee_id UUID REFERENCES hr.employees(employee_id),
    status VARCHAR(50) NOT NULL DEFAULT 'PENDING'
        CHECK (status IN ('PENDING', 'APPROVED', 'REJECTED', 'CANCELLED', 'COMPLETED')),
    reason TEXT,
    manager_notes TEXT,
    requested_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    approved_at TIMESTAMP WITH TIME ZONE,
    approved_by UUID REFERENCES hr.employees(employee_id),
    rejected_at TIMESTAMP WITH TIME ZONE,
    rejected_by UUID REFERENCES hr.employees(employee_id),
    completed_at TIMESTAMP WITH TIME ZONE,
    is_automated BOOLEAN NOT NULL DEFAULT FALSE,
    business_impact JSONB,
    compliance_status VARCHAR(50) NOT NULL DEFAULT 'UNKNOWN'
        CHECK (compliance_status IN ('COMPLIANT', 'WARNING', 'VIOLATION', 'UNKNOWN')),
    compliance_details TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_shift_swaps_requesting ON scheduling.shift_swaps(requesting_employee_id);
CREATE INDEX IF NOT EXISTS idx_shift_swaps_proposed ON scheduling.shift_swaps(proposed_with_employee_id);
CREATE INDEX IF NOT EXISTS idx_shift_swaps_requested_shift ON scheduling.shift_swaps(requested_shift_id);
CREATE INDEX IF NOT EXISTS idx_shift_swaps_offering_shift ON scheduling.shift_swaps(offering_shift_id);
CREATE INDEX IF NOT EXISTS idx_shift_swaps_status ON scheduling.shift_swaps(status);
CREATE INDEX IF NOT EXISTS idx_shift_swaps_requested_at ON scheduling.shift_swaps(requested_at DESC);
CREATE INDEX IF NOT EXISTS idx_shift_swaps_compliance ON scheduling.shift_swaps(compliance_status);

-- Add triggers for audit columns
CREATE TRIGGER trg_shift_swaps_updated_at
BEFORE UPDATE ON scheduling.shift_swaps
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE scheduling.shift_swaps IS 'Employee-initiated shift exchange requests.
Manages process of employees requesting to exchange shifts with each other, a common requirement in workforce scheduling.
