-- Serial No: 18 | TABLE: hr.time_off_requests
-- Description: Employee time off and leave requests
-- Business Case: The time_off_requests table manages all employee requests for time away from work, including
-- vacation, sick leave, and other types of absences. It captures the complete lifecycle of time off requests
-- from submission through approval to completion, providing a centralized record for all absence management.
-- This functionality is critical for ensuring proper staffing levels by accounting for planned absences during
-- schedule creation. The table supports various types of time off with different accrual rules, eligibility
-- requirements, and approval workflows. It includes comprehensive tracking of time off balances and usage
-- to support compliance with paid time off policies and labor regulations. The design accommodates complex
-- time off scenarios such as partial-day requests, recurring time off patterns, and conditional approvals.
-- The table also tracks the business impact of time off requests to support informed approval decisions
-- that balance employee needs with operational requirements. This information is valuable for analyzing
-- absence patterns and their impact on scheduling efficiency. The table is optimized for rapid processing
-- during schedule creation when accounting for planned absences.
-- KPI: Time off request approval rate, Average approval time,
--      Schedule impact of time off, Time off balance accuracy,
--      Compliance with time off policies
-- Feature Reference: 86, 87, 88, 89, 90
CREATE TABLE IF NOT EXISTS hr.time_off_requests (
    request_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    employee_id UUID NOT NULL REFERENCES hr.employees(employee_id),
