-- Serial No: 19 | TABLE: analytics.forecasted_demand
-- Description: Historical and predicted business demand data
-- Business Case: The forecasted_demand table stores historical and predicted business demand patterns that
-- drive workforce scheduling decisions. This data is critical for aligning staffing levels with expected
-- business volumes, optimizing labor costs while maintaining service levels. The table captures demand
-- forecasts at various granularities (hourly, daily, weekly) and for different business metrics (customer
-- traffic, transaction volume, service requests). It supports multiple forecasting methods and tracks
-- forecast accuracy to enable continuous improvement of prediction models. The design accommodates
-- seasonality patterns, special events, and external factors that influence demand. Historical demand
-- data is versioned to support retrospective analysis of forecast performance. The table also tracks
-- confidence intervals for predictions to support risk-aware scheduling decisions. This information is
-- essential for proactive workforce planning and enables the system to recommend optimal staffing levels
-- based on anticipated business conditions. The table is optimized for rapid access during schedule
-- generation when determining required staffing levels for each time period.
-- KPI: Forecast accuracy rate, Demand prediction confidence,
--      Staffing alignment with demand, Forecast update frequency,
--      Impact of forecast errors on labor costs
-- Feature Reference: 91, 92, 93, 94, 95
CREATE TABLE IF NOT EXISTS analytics.forecasted_demand (
    forecast_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    location_id UUID NOT NULL,
    department_id UUID NOT NULL,
    position_id UUID NOT NULL,
    forecast_date DATE NOT NULL,
    time_period VARCHAR(20) NOT NULL CHECK (time_period IN ('HOURLY', 'DAILY', 'WEEKLY')),
    start_time TIMESTAMP WITH TIME ZONE NOT NULL,
    end_time TIMESTAMP WITH TIME ZONE NOT NULL CHECK (end_time > start_time),
    forecast_value NUMERIC(12,2) NOT NULL CHECK (forecast_value >= 0),
    forecast_method VARCHAR(50) NOT NULL,
    confidence_interval_low NUMERIC(12,2),
    confidence_interval_high NUMERIC(12,2),
    historical_value NUMERIC(12,2),
    actual_value NUMERIC(12,2),
    forecast_version VARCHAR(20) NOT NULL DEFAULT '1.0',
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

