-- -- =============================================================================--
-- -- 7. ROW LEVEL SECURITY POLICIES (Enhanced with Comprehensive Documentation)
-- -- =============================================================================--

-- RLS for employee data
-- Serial No: 25 | POLICY: employees_rls_policy
-- Purpose: Restricts access to employee data based on organizational hierarchy
-- Business Case: This Row Level Security policy ensures that users can only access employee data for
-- individuals within their organizational scope, enforcing the principle of least privilege for sensitive
-- workforce information. It supports complex organizational structures by following the reporting hierarchy,
-- allowing managers to see data for their direct reports and indirect reports through multiple levels.
-- The policy accommodates special roles like HR personnel who need broader access while still restricting
-- access to sensitive fields like compensation data. It also supports data localization requirements by
-- limiting access based on geographic boundaries when necessary. The implementation uses PostgreSQL's
-- RLS features to enforce these restrictions at the database level, providing a robust security boundary
-- that cannot be bypassed by application logic errors. This approach ensures consistent enforcement of
-- data access rules regardless of the access path, critical for compliance with data protection regulations
-- and internal security policies. The policy includes mechanisms for audit logging of access attempts to
-- sensitive data, supporting forensic analysis if needed.
-- KPI: Data access compliance rate, Unauthorized access attempts,
--      Policy violation resolution time, Audit completeness,
--      Data breach prevention rate
-- Feature Reference: 121, 122, 123, 124, 125
CREATE POLICY employees_rls_policy ON hr.employees
FOR SELECT
USING (
    -- Managers can see their direct and indirect reports
    (current_setting('app.role') = 'MANAGER' AND reports_to = uuid(current_setting('app.user_id')))
    OR
    -- HR personnel can see all employees but with field restrictions
    (current_setting('app.role') = 'HR' AND current_setting('app.department') = 'HR')
    OR
    -- Employees can see their own record
    (current_setting('app.role') = 'EMPLOYEE' AND employee_id = uuid(current_setting('app.user_id')))
);

ALTER TABLE hr.employees ENABLE ROW LEVEL SECURITY;

COMMENT ON POLICY employees_rls_policy ON hr.employees IS 'Restricts access to employee data based on organizational hierarchy.
Ensures users can only access employee data for individuals within their organizational scope, enforcing principle of least
privilege for sensitive workforce information. Supports complex organizational structures by following reporting hierarchy.
Accommodates special roles like HR personnel who need broader access while restricting sensitive fields. Supports data
localization requirements by limiting access based on geographic boundaries. Enforces restrictions at database level, providing
robust security boundary that cannot be bypassed by application logic errors. Ensures consistent enforcement of data access
rules regardless of access path. Includes mechanisms for audit logging of access attempts to sensitive data.';


-- Serial No: 22 | TABLE: operations.locations
-- Description: Physical and operational locations management
-- Business Case: The locations table serves as the master repository for all physical and operational locations
-- within the organization, including warehouses, stores, offices, distribution centers, and other facilities.
-- This table is fundamental to operations management, providing a centralized reference for location-based
-- activities including inventory management, workforce scheduling, asset tracking, and compliance reporting.
-- It supports hierarchical location structures allowing for parent-child relationships between locations
-- (e.g., regional offices containing multiple stores, warehouses with multiple sections). The timezone field
-- is critical for scheduling operations across different geographic regions, ensuring accurate shift timing
-- and compliance with local labor laws. The comprehensive address structure enables geocoding for route
-- optimization, delivery planning, and proximity-based searches. Location type categorization allows for
-- type-specific business rules and reporting. The table also tracks operational status (active/inactive)
-- to support location closures, renovations, or seasonal operations without losing historical data.
-- This information is essential for multi-entity operations, enabling proper segregation of data and
-- operations by location while maintaining a single source of truth. The hierarchical structure supports
-- organizational roll-ups for reporting, budgeting, and strategic planning. The metadata JSONB field
-- provides flexibility to capture location-specific attributes such as square footage, capacity, operating
-- hours, special certifications, or regional compliance requirements without schema modifications.
-- KPI: Location count by type, Active vs inactive locations ratio,
--      Geographic distribution coverage, Hierarchy depth analysis,
--      Location data completeness score
-- Feature Reference: 201, 202, 203, 204, 205
CREATE TABLE IF NOT EXISTS operations.locations (
    -- Primary identifiers
    location_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    location_code VARCHAR(50) NOT NULL UNIQUE,
    
    -- Core location information
    location_name VARCHAR(255) NOT NULL,
    location_type VARCHAR(50) NOT NULL 
        CHECK (location_type IN ('WAREHOUSE', 'STORE', 'OFFICE', 'DISTRIBUTION_CENTER', 'RETAIL', 'FACTORY', 'SERVICE_CENTER', 'OTHER')),
    
    -- Hierarchical relationship
    parent_location_id UUID REFERENCES operations.locations(location_id),
    hierarchy_level INTEGER DEFAULT 1 
        CHECK (hierarchy_level >= 1),
    
    -- Address information
    address_line1 VARCHAR(255) NOT NULL,
    address_line2 VARCHAR(255),
    city VARCHAR(100) NOT NULL,
    state VARCHAR(50),
    postal_code VARCHAR(20) NOT NULL,
    country VARCHAR(100) NOT NULL,
    
    -- Geographic coordinates
    latitude DECIMAL(10, 8),
    longitude DECIMAL(11, 8),
    geolocation GEOGRAPHY(POINT),
    
    -- Operational attributes
    timezone VARCHAR(50) NOT NULL DEFAULT 'UTC',
    country_code VARCHAR(3), -- ISO 3166-1 alpha-3
    region VARCHAR(100),
    district VARCHAR(100),
    
    -- Contact information
    phone VARCHAR(50),
    email VARCHAR(255),
    manager_id UUID REFERENCES hr.employees(employee_id),
    
    -- Status flags
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_headquarters BOOLEAN NOT NULL DEFAULT FALSE,
    
    -- Operational capacity (optional)
    square_footage DECIMAL(12, 2),
    maximum_capacity INTEGER,
    current_employee_count INTEGER DEFAULT 0,
    
    -- Operating hours stored as JSON for flexibility
    operating_hours JSONB DEFAULT '{}'::JSONB,
    
    -- Flexible metadata for location-specific attributes
    -- Examples: certifications (array), facilities (object), compliance_requirements (object)
    metadata JSONB DEFAULT '{}'::JSONB,
    
    -- Standard audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    updated_by UUID REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- Ensure no circular references in hierarchy
    CONSTRAINT chk_parent_not_self CHECK (parent_location_id != location_id)
);

-- Add indexes for performance optimization
-- Primary lookup indexes
CREATE INDEX IF NOT EXISTS idx_locations_code ON operations.locations(location_code);
CREATE INDEX IF NOT EXISTS idx_locations_type ON operations.locations(location_type) WHERE is_active = TRUE;
