-- Add triggers for audit columns
DROP TRIGGER IF EXISTS trg_locations_updated_at ON operations.locations;
CREATE TRIGGER trg_locations_updated_at
BEFORE UPDATE ON operations.locations
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

-- Add trigger to maintain hierarchy level
CREATE OR REPLACE FUNCTION operations.maintain_location_hierarchy()
RETURNS TRIGGER AS $$
DECLARE
    parent_level INTEGER;
BEGIN
    -- Calculate hierarchy level based on parent
    IF NEW.parent_location_id IS NULL THEN
        NEW.hierarchy_level = 1;
    ELSE
        SELECT hierarchy_level INTO parent_level
        FROM operations.locations
        WHERE location_id = NEW.parent_location_id;
        
        -- Default to 2 if parent not found or level is null
        IF parent_level IS NULL THEN
            NEW.hierarchy_level = 2;
        ELSE
            NEW.hierarchy_level = parent_level + 1;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_locations_hierarchy ON operations.locations;
CREATE TRIGGER trg_locations_hierarchy
BEFORE INSERT OR UPDATE OF parent_location_id ON operations.locations
FOR EACH ROW
EXECUTE FUNCTION operations.maintain_location_hierarchy();

-- Create a view for location hierarchy (FIXED VERSION)
CREATE OR REPLACE VIEW operations.vw_location_hierarchy AS
WITH RECURSIVE location_tree AS (
    -- Anchor: top-level locations
    SELECT 
        location_id,
        location_code,
        location_name,
        location_type,
        parent_location_id,
        hierarchy_level,
        -- Explicitly cast to TEXT to avoid type mismatches
        location_name::TEXT as path,
        ARRAY[location_name::TEXT] as path_array,
        1 as tree_depth
    FROM operations.locations
    WHERE parent_location_id IS NULL AND is_active = TRUE
    
    UNION ALL
    
    -- Recursive: child locations
    SELECT 
        c.location_id,
        c.location_code,
        c.location_name,
        c.location_type,
        c.parent_location_id,
        c.hierarchy_level,
        -- Concatenate with proper casting
        (lt.path || ' -> ' || c.location_name::TEXT)::TEXT,
        -- Append to array with proper typing
        lt.path_array || ARRAY[c.location_name::TEXT],
        lt.tree_depth + 1
    FROM operations.locations c
    INNER JOIN location_tree lt ON c.parent_location_id = lt.location_id
    WHERE c.is_active = TRUE
)
SELECT 
    location_id,
    location_code,
    location_name,
    location_type,
    parent_location_id,
    hierarchy_level,
    path,
    path_array,
    tree_depth
FROM location_tree
ORDER BY path;

-- Create a view for locations with manager details
CREATE OR REPLACE VIEW operations.vw_locations_with_manager AS
SELECT 
    l.location_id,
    l.location_code,
    l.location_name,
    l.location_type,
    l.parent_location_id,
    l.hierarchy_level,
    l.address_line1,
    l.address_line2,
    l.city,
    l.state,
    l.postal_code,
    l.country,
    l.latitude,
    l.longitude,
    l.timezone,
    l.region,
    l.district,
    l.phone,
    l.email,
    l.manager_id,
    l.is_active,
    l.is_headquarters,
    l.square_footage,
    l.maximum_capacity,
    l.current_employee_count,
    l.operating_hours,
    l.metadata,
    l.created_by,
    l.updated_by,
    l.created_at,
    l.updated_at,
    CONCAT(e.first_name, ' ', e.last_name) as manager_name,
    e.email as manager_email,
    e.phone as manager_phone,
    CONCAT(cre.first_name, ' ', cre.last_name) as created_by_name,
    CONCAT(upd.first_name, ' ', upd.last_name) as updated_by_name
FROM operations.locations l
LEFT JOIN hr.employees e ON l.manager_id = e.employee_id
LEFT JOIN hr.employees cre ON l.created_by = cre.employee_id
LEFT JOIN hr.employees upd ON l.updated_by = upd.employee_id;

-- Create function to find nearby locations
CREATE OR REPLACE FUNCTION operations.find_nearby_locations(
    p_latitude DECIMAL,
    p_longitude DECIMAL,
    p_radius_meters INTEGER DEFAULT 5000,
    p_location_type VARCHAR DEFAULT NULL
)
RETURNS TABLE(
    location_id UUID,
    location_name VARCHAR,
    location_type VARCHAR,
    distance_meters FLOAT,
    address_line1 VARCHAR,
    city VARCHAR,
    postal_code VARCHAR
) AS $$
BEGIN
    RETURN QUERY
    SELECT 
        l.location_id,
        l.location_name,
        l.location_type,
        ST_Distance(
            ST_SetSRID(ST_MakePoint(p_longitude, p_latitude), 4326)::GEOGRAPHY,
            l.geolocation
        ) as distance_meters,
        l.address_line1,
        l.city,
        l.postal_code
    FROM operations.locations l
    WHERE l.is_active = TRUE
        AND l.geolocation IS NOT NULL
        AND (p_location_type IS NULL OR l.location_type = p_location_type)
        AND ST_DWithin(
            ST_SetSRID(ST_MakePoint(p_longitude, p_latitude), 4326)::GEOGRAPHY,
            l.geolocation,
            p_radius_meters
        )
    ORDER BY distance_meters;
END;
$$ LANGUAGE plpgsql;

