-- Serial No: 21 | TABLE: security.user_locations
-- Description: User access permissions to physical and operational locations
-- Business Case: The user_locations table manages the assignment of user access permissions to various 
-- operational locations within the organization. This is critical for implementing role-based access control 
-- (RBAC) across the enterprise, ensuring that employees only have access to locations necessary for their 
-- job functions. The table supports granular permission levels from view-only access to full administrative 
-- control, enabling proper segregation of duties and maintaining operational security. It tracks the complete 
-- lifecycle of location access including grant dates, expiration dates, and revocation history to maintain 
-- a comprehensive audit trail for compliance with security policies and regulatory requirements. The design 
-- accommodates temporary access grants for contractors, project-based assignments, and emergency situations 
-- with automatic expiration handling. The metadata JSONB field provides flexibility to capture location-specific 
-- access parameters such as time-based restrictions, access device limitations, or conditional access rules. 
-- This table is fundamental to the security infrastructure, supporting location-based data filtering, 
-- operational reporting, and compliance audits. It enables the organization to demonstrate proper access 
-- controls and meet requirements for certifications like SOC2, ISO27001, and GDPR.
-- KPI: Active location assignments per user, Access revocation latency,
--      Expired access cleanup rate, Location access distribution by level,
--      Audit trail completeness score
-- Feature Reference: 101, 102, 103, 104, 105
CREATE TABLE IF NOT EXISTS security.user_locations (
    -- Primary identifiers
    user_location_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    
    -- Core relationships
    user_id UUID NOT NULL REFERENCES hr.employees(employee_id) ON DELETE CASCADE,
    location_id UUID NOT NULL REFERENCES operations.locations(location_id) ON DELETE CASCADE,
    
    -- Access control
    access_level VARCHAR(20) NOT NULL DEFAULT 'VIEWER'
        CHECK (access_level IN ('VIEWER', 'EDITOR', 'ADMIN', 'FULL')),
    
    -- Status flags
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    
    -- Grant tracking
    granted_by UUID REFERENCES hr.employees(employee_id),
    granted_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    expires_at TIMESTAMP WITH TIME ZONE,
    
    -- Revocation tracking (for audit purposes)
    revoked_at TIMESTAMP WITH TIME ZONE,
    revoked_by UUID REFERENCES hr.employees(employee_id),
    revocation_reason VARCHAR(255),
    
    -- Flexible metadata for location-specific access parameters
    -- Examples: time_restrictions (JSON), device_types (array), conditional_rules (object)
    metadata JSONB DEFAULT '{}'::JSONB,
    
    -- Standard audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    updated_by UUID REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- Ensure unique active user-location combination
    CONSTRAINT uq_user_location_active UNIQUE(user_id, location_id)
);

-- Add indexes for performance optimization
-- Core query patterns
CREATE INDEX IF NOT EXISTS idx_user_locations_user ON security.user_locations(user_id) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_user_locations_location ON security.user_locations(location_id) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_user_locations_access_level ON security.user_locations(access_level) WHERE is_active = TRUE;

-- Temporal queries
CREATE INDEX IF NOT EXISTS idx_user_locations_granted ON security.user_locations(granted_at DESC) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_user_locations_expires ON security.user_locations(expires_at) 
    WHERE expires_at IS NOT NULL AND is_active = TRUE;

-- Audit and compliance queries
CREATE INDEX IF NOT EXISTS idx_user_locations_revoked ON security.user_locations(revoked_at) 
    WHERE revoked_at IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_user_locations_audit_created ON security.user_locations(created_by, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_user_locations_audit_updated ON security.user_locations(updated_by, updated_at DESC);

-- JSONB metadata queries
CREATE INDEX IF NOT EXISTS idx_user_locations_metadata ON security.user_locations USING GIN(metadata);

-- Composite indexes for common query patterns
CREATE INDEX IF NOT EXISTS idx_user_locations_user_location ON security.user_locations(user_id, location_id);
CREATE INDEX IF NOT EXISTS idx_user_locations_expiring_soon ON security.user_locations(expires_at) 
    WHERE expires_at IS NOT NULL 
      AND expires_at > CURRENT_TIMESTAMP 
      AND expires_at < CURRENT_TIMESTAMP + INTERVAL '7 days'
      AND is_active = TRUE;

-- Add triggers for audit columns
CREATE TRIGGER trg_user_locations_updated_at
BEFORE UPDATE ON security.user_locations
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

-- Add trigger to handle expiration (optional - can be handled by application or scheduled job)
CREATE OR REPLACE FUNCTION security.handle_expired_location_access()
RETURNS TRIGGER AS $$
BEGIN
    -- Automatically deactivate expired access
    IF NEW.expires_at IS NOT NULL 
       AND NEW.expires_at <= CURRENT_TIMESTAMP 
       AND NEW.is_active = TRUE THEN
        NEW.is_active = FALSE;
        NEW.revoked_at = CURRENT_TIMESTAMP;
        NEW.revoked_by = NEW.updated_by;
        NEW.revocation_reason = 'Automatic revocation due to expiration';
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_user_locations_expiration
BEFORE INSERT OR UPDATE OF expires_at ON security.user_locations
FOR EACH ROW
EXECUTE FUNCTION security.handle_expired_location_access();

