-- Add foreign key constraint separately with validation option
DO $$
BEGIN
    -- Check if the foreign key constraint already exists
    IF NOT EXISTS (
        SELECT 1 
        FROM information_schema.table_constraints 
        WHERE constraint_name = 'fk_user_locations_location'
        AND table_schema = 'security'
        AND table_name = 'user_locations'
    ) THEN
        -- Add the foreign key constraint with validation
        EXECUTE 'ALTER TABLE security.user_locations 
                 ADD CONSTRAINT fk_user_locations_location 
                 FOREIGN KEY (location_id) 
                 REFERENCES operations.locations(location_id) 
                 ON DELETE CASCADE';
        
        RAISE NOTICE 'Foreign key constraint fk_user_locations_location added successfully.';
    END IF;
EXCEPTION
    WHEN foreign_key_violation THEN
        RAISE WARNING 'Foreign key constraint could not be added due to existing data issues.';
        RAISE WARNING 'Please clean up invalid location_id references and add constraint manually.';
    WHEN undefined_table THEN
        RAISE WARNING 'Table operations.locations still does not exist.';
        RAISE WARNING 'Please create operations.locations first and then add the foreign key constraint manually.';
END $$;

