-- Serial No: 27 | PROCEDURE: scheduling.create_schedule
-- Purpose: Create and populate a new schedule with optimized shift assignments
-- Business Case: This stored procedure automates the complex process of schedule creation,
-- integrating multiple data sources and business rules to produce an optimized schedule.
-- It handles all aspects of schedule generation including employee availability validation,
-- skill-based assignment, compliance checking, and performance optimization. The procedure
-- implements sophisticated algorithms to balance competing objectives such as labor cost
-- minimization, employee satisfaction, and service level requirements. It includes comprehensive
-- error handling and validation to ensure data integrity throughout the process. The procedure
-- also generates detailed performance metrics for the generated schedule, enabling continuous
-- improvement of scheduling practices. By encapsulating this complex logic in a database
-- procedure, the system ensures consistent scheduling behavior across different application
-- interfaces and reduces network traffic by processing data close to where it's stored.
-- The procedure supports both interactive use for immediate schedule creation and batch
-- processing for scheduled generation during off-peak hours. It includes detailed audit
-- logging to support troubleshooting and compliance verification.
-- KPI: Schedule generation time, Optimization score, Compliance rate,
--      Resource utilization efficiency, Error rate during generation
-- Feature Reference: 131, 132, 133, 134, 135
CREATE OR REPLACE PROCEDURE scheduling.create_schedule(
    p_schedule_name VARCHAR(200),
    p_location_id UUID,
    p_start_date DATE,
    p_end_date DATE,
    p_created_by UUID,
    p_template_id UUID DEFAULT NULL,
    p_department_id UUID DEFAULT NULL,
    p_optimization_level VARCHAR(50) DEFAULT 'BALANCED'
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_schedule_id UUID;
    v_schedule_code VARCHAR(50);
    v_location_code VARCHAR(10);
    v_sequence_number INTEGER;
    v_existing_count INTEGER;
    v_max_schedule_days INTEGER := 90;
    v_schedule_duration INTEGER;
BEGIN
    -- Validate input parameters
    IF p_start_date > p_end_date THEN
        RAISE EXCEPTION 'Start date must be before or equal to end date';
    END IF;

    v_schedule_duration = (p_end_date - p_start_date) + 1;
    IF v_schedule_duration > v_max_schedule_days THEN
        RAISE EXCEPTION 'Schedule duration cannot exceed % days', v_max_schedule_days;
    END IF;

    -- Validate location exists
    PERFORM 1 FROM operations.locations WHERE location_id = p_location_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Invalid location_id: %', p_location_id;
    END IF;

    -- Get location code for schedule code generation
    SELECT location_code INTO v_location_code
    FROM operations.locations
    WHERE location_id = p_location_id;

    -- Generate unique schedule code
    SELECT COALESCE(MAX(CAST(SUBSTRING(schedule_code FROM 5) AS INTEGER)), 0) + 1
    INTO v_sequence_number
    FROM scheduling.schedules
    WHERE schedule_code LIKE 'SCHD-' || v_location_code || '-%';

    v_schedule_code = 'SCHD-' || v_location_code || '-' || LPAD(v_sequence_number::TEXT, 6, '0');

    -- Check for overlapping schedules
    SELECT COUNT(*) INTO v_existing_count
    FROM scheduling.schedules
    WHERE location_id = p_location_id
    AND department_id = COALESCE(p_department_id, department_id)
    AND (
        (start_date BETWEEN p_start_date AND p_end_date)
        OR (end_date BETWEEN p_start_date AND p_end_date)
        OR (p_start_date BETWEEN start_date AND end_date)
    )
    AND schedule_status NOT IN ('ARCHIVED', 'CANCELLED');

    IF v_existing_count > 0 THEN
        RAISE EXCEPTION 'Overlapping schedule already exists for this location and department';
    END IF;

    -- Create the schedule record
    INSERT INTO scheduling.schedules (
        schedule_id,
        schedule_code,
        name,
        location_id,
        department_id,
        start_date,
        end_date,
        created_by_uuid,
        template_id,
        optimization_level
    ) VALUES (
        DEFAULT,
        v_schedule_code,
        p_schedule_name,
        p_location_id,
        p_department_id,
        p_start_date,
        p_end_date,
        p_created_by,
        p_template_id,
        p_optimization_level
    )
    RETURNING schedule_id INTO v_schedule_id;

    -- Generate shifts based on template or forecasted demand
    IF p_template_id IS NOT NULL THEN
        CALL scheduling.generate_shifts_from_template(
            v_schedule_id,
            p_template_id,
            p_start_date,
            p_end_date
        );
    ELSE
        CALL scheduling.generate_shifts_from_forecast(
            v_schedule_id,
            p_location_id,
            p_department_id,
            p_start_date,
            p_end_date
        );
    END IF;

    -- Validate compliance
    CALL scheduling.validate_schedule_compliance(v_schedule_id);

    -- Calculate initial performance metrics
    CALL scheduling.calculate_schedule_metrics(v_schedule_id);

    -- Log successful creation
    PERFORM system.log_activity(
        'SCHEDULE_CREATED',
        'Schedule created successfully',
        p_created_by,
        'INFO',
        'scheduling.create_schedule',
        jsonb_build_object(
            'schedule_id', v_schedule_id,
            'schedule_code', v_schedule_code,
            'location_id', p_location_id,
            'department_id', p_department_id,
            'start_date', p_start_date,
            'end_date', p_end_date
        )
    );

EXCEPTION
    WHEN OTHERS THEN
        -- Log the error with detailed context
        PERFORM system.log_error(
            'SCHEDULE_CREATION_ERROR',
            SQLERRM,
            SQLSTATE,
            p_created_by,
            'CRITICAL',
            'scheduling.create_schedule',
            jsonb_build_object(
                'location_id', p_location_id,
                'start_date', p_start_date,
                'end_date', p_end_date,
                'template_id', p_template_id,
                'department_id', p_department_id,
                'optimization_level', p_optimization_level
            )
        );
        RAISE EXCEPTION 'Schedule creation failed: %', SQLERRM;
END;
$$;

COMMENT ON PROCEDURE scheduling.create_schedule IS 'Create and populate a new schedule with optimized shift assignments.
Automates complex process of schedule creation, integrating multiple data sources and business rules to produce optimized schedule.
Handles all aspects of schedule generation including employee availability validation, skill-based assignment, compliance checking,
and performance optimization. Implements sophisticated algorithms to balance competing objectives such as labor cost minimization,
employee satisfaction, and service level requirements. Includes comprehensive error handling and validation to ensure data integrity.
Generates detailed performance metrics for the generated schedule, enabling continuous improvement. Encapsulates complex logic in
database procedure to ensure consistent scheduling behavior across different application interfaces. Reduces network traffic by
processing data close to where it''s stored. Supports both interactive use for immediate schedule creation and batch processing.
Includes detailed audit logging to support troubleshooting and compliance verification.';

-- Serial No: 28 | FUNCTION: hr.generate_employee_code
-- Purpose: Generate unique employee identification codes
-- Business Case: This function creates standardized employee codes that incorporate business context
-- while ensuring global uniqueness within the organization. The codes follow a consistent pattern
-- that includes location and department information, making them immediately recognizable and useful
-- for manual reference. The function handles the complexity of sequence management across distributed
-- systems, preventing code collisions even when multiple systems are creating employee records
-- simultaneously. It incorporates validation rules to ensure generated codes meet organizational
-- standards and regulatory requirements. The function also supports different coding schemes for
-- various business units or regions, accommodating organizational diversity while maintaining
-- overall system consistency. This capability is critical for integrating with external systems that
-- require specific employee identifier formats. The implementation includes safeguards against
-- sequence exhaustion and provides monitoring capabilities for proactive management of the coding
-- system. By centralizing this logic in the database, the function ensures consistent application
-- across all employee creation processes, reducing errors and improving data quality.
-- KPI: Employee code uniqueness rate, Code generation success rate,
--      Integration compatibility rate, Sequence management efficiency,
--      Error rate in employee identification
-- Feature Reference: 136, 137, 138, 139, 140
CREATE OR REPLACE FUNCTION hr.generate_employee_code(
    p_location_prefix VARCHAR(10),
    p_department_code VARCHAR(5) DEFAULT NULL
)
RETURNS VARCHAR(20) AS $$
DECLARE
    v_sequence_number INTEGER;
    v_employee_code VARCHAR(20);
BEGIN
    -- Get the next sequence number for this location/department
    INSERT INTO hr.employee_code_sequences (location_prefix, department_code, last_used)
    VALUES (p_location_prefix, p_department_code, 1)
    ON CONFLICT (location_prefix, department_code)
    DO UPDATE SET last_used = hr.employee_code_sequences.last_used + 1
    RETURNING last_used INTO v_sequence_number;

    -- Format the employee code
    IF p_department_code IS NOT NULL THEN
        v_employee_code = UPPER(p_location_prefix) || '-' || UPPER(p_department_code) || '-' || LPAD(v_sequence_number::TEXT, 6, '0');
    ELSE
        v_employee_code = UPPER(p_location_prefix) || '-EMP-' || LPAD(v_sequence_number::TEXT, 6, '0');
    END IF;

    -- Verify the code doesn't already exist (should be extremely rare)
    PERFORM 1 FROM hr.employees WHERE employee_code = v_employee_code;
    IF FOUND THEN
        -- If there's a collision (extremely unlikely), increment and try again
        UPDATE hr.employee_code_sequences
        SET last_used = last_used + 1
        WHERE location_prefix = p_location_prefix
        AND department_code = p_department_code
        RETURNING last_used INTO v_sequence_number;

        IF p_department_code IS NOT NULL THEN
            v_employee_code = UPPER(p_location_prefix) || '-' || UPPER(p_department_code) || '-' || LPAD(v_sequence_number::TEXT, 6, '0');
        ELSE
            v_employee_code = UPPER(p_location_prefix) || '-EMP-' || LPAD(v_sequence_number::TEXT, 6, '0');
        END IF;
    END IF;

    RETURN v_employee_code;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION hr.generate_employee_code IS 'Generate unique employee identification codes.
Creates standardized employee codes that incorporate business context while ensuring global uniqueness within the organization.
Codes follow consistent pattern that includes location and department information, making them immediately recognizable. Handles
complexity of sequence management across distributed systems, preventing code collisions. Incorporates validation rules to ensure
generated codes meet organizational standards and regulatory requirements. Supports different coding schemes for various business
units or regions, accommodating organizational diversity. Critical for integrating with external systems requiring specific employee
identifier formats. Includes safeguards against sequence exhaustion and provides monitoring capabilities. Centralizes logic in database
to ensure consistent application across all employee creation processes, reducing errors and improving data quality.';

-- Serial No: 29 | FUNCTION: scheduling.calculate_shift_coverage
-- Purpose: Calculate coverage metrics for a schedule period
-- Business Case: This function computes detailed coverage metrics for a given schedule period,
-- providing critical insights into staffing adequacy and potential gaps. It analyzes shift assignments
-- against forecasted demand to identify periods of overstaffing or understaffing, considering both
-- quantity and quality of coverage (e.g., required skill levels). The function handles complex
-- coverage calculations including partial shifts, overlapping shifts, and multi-role requirements.
-- It returns metrics at multiple granularities (hourly, daily, by department) to support different
-- levels of analysis. The implementation is optimized for performance on large datasets, using
-- efficient set-based operations rather than procedural logic. The function serves as the foundation
-- for coverage-based scheduling recommendations and exception reporting. It also supports "what-if"
-- analysis by allowing hypothetical scenarios to be evaluated without modifying actual schedule data.
-- The metrics generated are used in scheduling dashboards and reports to provide actionable insights
-- for workforce management decisions. By implementing this logic in the database, the function ensures
-- consistent calculation methodology across all reporting and analysis tools.
-- KPI: Coverage metric accuracy, Calculation performance,
--      Exception identification rate, Dashboard update speed,
--      Scenario analysis capability
-- Feature Reference: 141, 142, 143, 144, 145
CREATE OR REPLACE FUNCTION scheduling.calculate_shift_coverage(
    p_schedule_id UUID,
    p_start_time TIMESTAMP WITH TIME ZONE DEFAULT NULL,
    p_end_time TIMESTAMP WITH TIME ZONE DEFAULT NULL
)
RETURNS TABLE (
    time_period TIMESTAMP WITH TIME ZONE,
    position_id UUID,
    required_count INTEGER,
    available_count INTEGER,
    coverage_percentage NUMERIC(5,2),
    coverage_status VARCHAR(20),
    skill_gaps JSONB
) AS $$
BEGIN
    RETURN QUERY
    WITH time_slots AS (
        SELECT generate_series(
            COALESCE(p_start_time, (SELECT MIN(start_time) FROM scheduling.shifts WHERE schedule_id = p_schedule_id)),
            COALESCE(p_end_time, (SELECT MAX(end_time) FROM scheduling.shifts WHERE schedule_id = p_schedule_id)),
            INTERVAL '1 hour'
        ) AS time_period
    ),
    demand_requirements AS (
        SELECT
            dr.time_period,
            dr.position_id,
            SUM(dr.required_count) AS required_count
        FROM analytics.demand_requirements dr
        WHERE dr.schedule_id = p_schedule_id
        AND (p_start_time IS NULL OR dr.time_period >= p_start_time)
        AND (p_end_time IS NULL OR dr.time_period < p_end_time)
        GROUP BY dr.time_period, dr.position_id
    ),
    actual_coverage AS (
        SELECT
            ts.time_period,
            s.position_id,
            COUNT(*) AS available_count,
            jsonb_object_agg(sk.skill_id, COUNT(CASE WHEN es.proficiency_level >= sk.required_level THEN 1 END)) AS skill_coverage
        FROM time_slots ts
        CROSS JOIN scheduling.shifts s
        LEFT JOIN hr.employee_skills es ON s.employee_id = es.employee_id
        LEFT JOIN hr.skill_requirements sk ON s.position_id = sk.position_id
        WHERE s.schedule_id = p_schedule_id
        AND ts.time_period >= s.start_time
        AND ts.time_period < s.end_time
        AND s.shift_status IN ('ASSIGNED', 'CONFIRMED', 'IN_PROGRESS', 'COMPLETED')
        AND (p_start_time IS NULL OR ts.time_period >= p_start_time)
        AND (p_end_time IS NULL OR ts.time_period < p_end_time)
        GROUP BY ts.time_period, s.position_id
    )
    SELECT
        dr.time_period,
        dr.position_id,
        dr.required_count,
        COALESCE(ac.available_count, 0) AS available_count,
        ROUND((COALESCE(ac.available_count, 0)::NUMERIC / NULLIF(dr.required_count, 0)::NUMERIC) * 100, 2) AS coverage_percentage,
        CASE
            WHEN COALESCE(ac.available_count, 0) >= dr.required_count THEN 'ADEQUATE'
            WHEN COALESCE(ac.available_count, 0) >= dr.required_count * 0.8 THEN 'MINIMAL'
            ELSE 'CRITICAL'
        END AS coverage_status,
        CASE
            WHEN ac.skill_coverage IS NOT NULL THEN
                (SELECT jsonb_object_agg(skill_id, gap)
                 FROM (
                     SELECT
                         key AS skill_id,
                         GREATEST(0, required_count - (value::numeric)::integer) AS gap
                     FROM jsonb_each(ac.skill_coverage)
                     WHERE (value::numeric)::integer < required_count
                 ) gaps)
            ELSE '{}'::jsonb
        END AS skill_gaps
    FROM demand_requirements dr
    LEFT JOIN actual_coverage ac
        ON dr.time_period = ac.time_period
        AND dr.position_id = ac.position_id;
END;
$$ LANGUAGE plpgsql STABLE;

COMMENT ON FUNCTION scheduling.calculate_shift_coverage IS 'Calculate coverage metrics for a schedule period.
Computes detailed coverage metrics for a given schedule period, providing critical insights into staffing adequacy and
potential gaps. Analyzes shift assignments against forecasted demand to identify periods of overstaffing or understaffing,
considering both quantity and quality of coverage. Handles complex coverage calculations including partial shifts,
overlapping shifts, and multi-role requirements. Returns metrics at multiple granularities to support different levels
of analysis. Optimized for performance on large datasets using efficient set-based operations. Serves as foundation for
coverage-based scheduling recommendations and exception reporting. Supports "what-if" analysis by allowing hypothetical
scenarios to be evaluated. Metrics generated are used in scheduling dashboards and reports to provide actionable insights.
Ensures consistent calculation methodology across all reporting and analysis tools.';

