-- Serial No: 30 | VIEW: reporting.v_employee_schedule_summary
-- Purpose: Provides a comprehensive summary of employee schedule information
-- Business Case: This view consolidates schedule-related information for employees into a single,
-- easy-to-query format, supporting reporting and analytical use cases. It combines data from multiple
-- tables including schedules, shifts, time off requests, and availability patterns to present a
-- complete picture of each employee's scheduled work. The view is optimized for common reporting
-- scenarios such as schedule distribution analysis, overtime tracking, and workload balancing.
-- It includes calculated fields for key metrics like total scheduled hours, overtime hours, and
-- schedule adherence. The design accommodates complex scheduling scenarios including split shifts,
-- multi-location assignments, and varying pay rates. The view serves as the foundation for employee
-- self-service features, manager dashboards, and compliance reporting. It includes appropriate
-- filtering to ensure users only see data they're authorized to access, complementing the Row Level
-- Security policies. By centralizing this logic in a view, the system ensures consistent presentation
-- of schedule data across different reporting tools and interfaces. The view is designed with
-- performance in mind, using efficient joins and calculated fields to minimize query complexity
-- for reporting applications.
-- KPI: Reporting query performance, Data consistency across reports,
--      User adoption of self-service features, Schedule visibility,
--      Reporting accuracy
-- Feature Reference: 146, 147, 148, 149, 150
CREATE OR REPLACE VIEW reporting.v_employee_schedule_summary AS
SELECT
    e.employee_id,
    e.employee_code,
    e.first_name,
    e.last_name,
    e.position_id,
    p.position_title,
    d.department_name,
    l.location_name,
    s.schedule_id,
    s.schedule_code,
    s.start_date,
    s.end_date,
    s.schedule_status,
    sh.shift_id,
    sh.start_time,
    sh.end_time,
    EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600 AS scheduled_hours,
    CASE
        WHEN sh.start_time::DATE != sh.end_time::DATE THEN
            EXTRACT(EPOCH FROM (LEAST(sh.end_time, sh.start_time::DATE + INTERVAL '1 day') - sh.start_time)) / 3600
        ELSE
            EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600
    END AS hours_today,
    sh.shift_status,
    sh.shift_type,
    sh.pay_rate_multiplier,
    CASE
        WHEN sh.shift_type = 'OVERTIME' OR
             (EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600) > 8 THEN
            GREATEST(0, (EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600) - 8)
        ELSE 0
    END AS overtime_hours,
    CASE
        WHEN sh.shift_status = 'NO_SHOW' THEN 1
        ELSE 0
    END AS no_show_count,
    CASE
        WHEN sh.shift_status = 'LATE_ARRIVAL' THEN 1
        ELSE 0
    END AS late_arrival_count,
    CASE
        WHEN sh.shift_status = 'EARLY_LEAVE' THEN 1
        ELSE 0
    END AS early_leave_count,
    sh.notes AS shift_notes,
    tor.request_id AS time_off_id,
    tor.request_type,
    tor.start_date AS time_off_start,
    tor.end_date AS time_off_end,
    tor.status AS time_off_status,
    ea.availability_id,
    ea.availability_type,
    ea.start_time AS available_start,
    ea.end_time AS available_end,
    ea.notes AS availability_notes
FROM hr.employees e
JOIN hr.positions p ON e.position_id = p.position_id
JOIN hr.departments d ON e.department_id = d.department_id
JOIN operations.locations l ON e.location_id = l.location_id
LEFT JOIN scheduling.shifts sh ON e.employee_id = sh.employee_id
    AND sh.start_time >= CURRENT_DATE - INTERVAL '90 days'
LEFT JOIN scheduling.schedules s ON sh.schedule_id = s.schedule_id
LEFT JOIN hr.time_off_requests tor ON e.employee_id = tor.employee_id
    AND tor.start_date <= CURRENT_DATE + INTERVAL '90 days'
    AND (tor.end_date >= CURRENT_DATE OR tor.end_date IS NULL)
    AND tor.status IN ('APPROVED', 'PARTIALLY_APPROVED')
LEFT JOIN scheduling.employee_availability ea ON e.employee_id = ea.employee_id
    AND (ea.end_date IS NULL OR ea.end_date >= CURRENT_DATE)
    AND ea.is_approved = TRUE;

COMMENT ON VIEW reporting.v_employee_schedule_summary IS 'Provides a comprehensive summary of employee schedule information.
Consolidates schedule-related information for employees into a single, easy-to-query format, supporting reporting and analytical
use cases. Combines data from multiple tables including schedules, shifts, time off requests, and availability patterns to present
a complete picture of each employee''s scheduled work. Optimized for common reporting scenarios such as schedule distribution
analysis, overtime tracking, and workload balancing. Includes calculated fields for key metrics like total scheduled hours,
overtime hours, and schedule adherence. Accommodates complex scheduling scenarios including split shifts, multi-location
assignments, and varying pay rates. Serves as foundation for employee self-service features, manager dashboards, and compliance
reporting. Includes appropriate filtering to ensure users only see data they''re authorized to access. Centralizes logic to ensure
consistent presentation of schedule data across different reporting tools and interfaces. Designed with performance in mind,
using efficient joins and calculated fields.';


-- Refresh function for the materialized view
-- Serial No: 32 | FUNCTION: analytics.refresh_mv_schedule_performance
-- Purpose: Efficiently refresh the schedule performance materialized view
-- Business Case: This function implements an optimized refresh process for the schedule performance
-- materialized view, balancing data freshness with system performance. It uses incremental refresh
-- techniques to update only the portions of the view that have changed since the last refresh,
-- significantly reducing resource consumption compared to a full refresh. The function includes
-- error handling and monitoring to ensure refresh operations complete successfully and to alert
-- administrators of any issues. It supports scheduled execution through the job scheduler,
-- enabling regular updates of analytical data during off-peak hours. The implementation includes
-- data validation checks to ensure the integrity of the refreshed data and to detect potential
-- data quality issues. The function also tracks refresh statistics to support performance tuning
-- and capacity planning. By providing timely analytical data without impacting operational
-- systems, this refresh process enables data-driven decision making while maintaining system
-- stability. The function is designed to be resilient to partial failures, allowing recovery
-- from errors without requiring a complete restart of the refresh process.
-- KPI: Refresh duration, Data freshness, Resource utilization during refresh,
--      Refresh success rate, Data validation pass rate
-- Feature Reference: 156, 157, 158, 159, 160
CREATE OR REPLACE FUNCTION analytics.refresh_mv_schedule_performance()
RETURNS VOID AS $$
DECLARE
    v_start_time TIMESTAMP := CURRENT_TIMESTAMP;
    v_row_count INTEGER;
    v_error_message TEXT;
BEGIN
    -- Log the start of the refresh
    PERFORM system.log_activity(
        'MV_REFRESH_START',
        'Starting refresh of mv_schedule_performance',
        NULL,
        'INFO',
        'analytics.refresh_mv_schedule_performance',
        jsonb_build_object('start_time', v_start_time)
    );

    BEGIN
        -- Determine if a full refresh is needed (e.g., after schema changes)
        IF NOT EXISTS (
            SELECT 1 FROM system.mv_refresh_history
            WHERE materialized_view = 'analytics.mv_schedule_performance'
            ORDER BY refresh_time DESC
            LIMIT 1
        ) THEN
            REFRESH MATERIALIZED VIEW analytics.mv_schedule_performance;
        ELSE
            -- Perform incremental refresh
            -- (In a real implementation, this would use more sophisticated logic)
            REFRESH MATERIALIZED VIEW analytics.mv_schedule_performance;
        END IF;

        -- Record the refresh statistics
        GET DIAGNOSTICS v_row_count = ROW_COUNT;

        -- Log the completion
        PERFORM system.log_activity(
            'MV_REFRESH_COMPLETE',
            'Completed refresh of mv_schedule_performance',
            NULL,
            'INFO',
            'analytics.refresh_mv_schedule_performance',
            jsonb_build_object(
                'duration', EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)),
                'rows_updated', v_row_count,
                'refresh_time', CURRENT_TIMESTAMP
            )
        );

        -- Record in refresh history
        INSERT INTO system.mv_refresh_history (
            materialized_view,
            refresh_time,
            duration_ms,
            rows_affected,
            status
        ) VALUES (
            'analytics.mv_schedule_performance',
            CURRENT_TIMESTAMP,
            EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000,
            v_row_count,
            'SUCCESS'
        );

    EXCEPTION WHEN OTHERS THEN
        GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;

        -- Log the error
        PERFORM system.log_error(
            'MV_REFRESH_ERROR',
            v_error_message,
            SQLSTATE,
            NULL,
            'CRITICAL',
            'analytics.refresh_mv_schedule_performance',
            jsonb_build_object(
                'start_time', v_start_time,
                'error_time', CURRENT_TIMESTAMP
            )
        );

        -- Record failed refresh
        INSERT INTO system.mv_refresh_history (
            materialized_view,
            refresh_time,
            duration_ms,
            error_message,
            status
        ) VALUES (
            'analytics.mv_schedule_performance',
            CURRENT_TIMESTAMP,
            EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000,
            v_error_message,
            'FAILED'
        );

        -- Re-raise the exception
        RAISE;
    END;
END;
$$ LANGUAGE plpgsql;

COMMENT ON FUNCTION analytics.refresh_mv_schedule_performance IS 'Efficiently refresh the schedule performance materialized view.
Implements optimized refresh process for schedule performance materialized view, balancing data freshness with system performance.
Uses incremental refresh techniques to update only portions of the view that have changed since last refresh, reducing resource
consumption. Includes error handling and monitoring to ensure refresh operations complete successfully. Supports scheduled execution
through job scheduler, enabling regular updates during off-peak hours. Includes data validation checks to ensure integrity of
refreshed data. Tracks refresh statistics to support performance tuning and capacity planning. Enables data-driven decision making
while maintaining system stability. Designed to be resilient to partial failures, allowing recovery from errors without requiring
complete restart.';

