-- Data masking rules
-- Serial No: 33 | TABLE: data_governance.data_masks
-- Purpose: Defines rules for data masking based on user roles
-- Business Case: This table stores data masking rules that determine how sensitive information
-- should be transformed when presented to users with different access levels. It enables
-- context-aware data protection by applying appropriate masking techniques based on the
-- requesting user's role and the sensitivity of the data. The rules support multiple masking
-- methods including redaction, encryption, and generalization, allowing fine-grained control
-- over data exposure. This capability is critical for complying with data protection regulations
-- that require differential access to sensitive information based on user responsibilities.
-- The implementation allows for dynamic masking at query time, ensuring that users never see
-- data they're not authorized to access, even if application logic has vulnerabilities. The
-- table structure supports rule inheritance and priority ordering to handle complex access
-- scenarios. It also includes audit capabilities to track when and why specific masking rules
-- were applied. This approach provides a robust data protection layer that complements
-- application-level security controls and helps prevent accidental data exposure. The rules
-- can be updated without changing application code, providing flexibility to adapt to evolving
-- security requirements.
-- KPI: Data masking coverage rate, Masking rule effectiveness,
--      Unauthorized data access attempts, Compliance audit success rate,
--      Rule maintenance efficiency
-- Feature Reference: 161, 162, 163, 164, 165
CREATE TABLE IF NOT EXISTS data_governance.data_masks (
    mask_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    table_schema VARCHAR(50) NOT NULL,
    table_name VARCHAR(50) NOT NULL,
    column_name VARCHAR(50) NOT NULL,
    role_name VARCHAR(50) NOT NULL,
    mask_type VARCHAR(50) NOT NULL CHECK (mask_type IN ('REDACT', 'ENCRYPT', 'GENERALIZE', 'NULLIFY', 'PARTIAL')),
    mask_pattern TEXT,
    mask_function VARCHAR(100),
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    priority INTEGER NOT NULL DEFAULT 100,
    description TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_data_masks_table ON data_governance.data_masks(table_schema, table_name, column_name);
CREATE INDEX IF NOT EXISTS idx_data_masks_role ON data_governance.data_masks(role_name);
CREATE INDEX IF NOT EXISTS idx_data_masks_active ON data_governance.data_masks(is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_data_masks_priority ON data_governance.data_masks(priority);

-- Add triggers for audit columns
CREATE TRIGGER trg_data_masks_updated_at
BEFORE UPDATE ON data_governance.data_masks
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE data_governance.data_masks IS 'Defines rules for data masking based on user roles.
Stores data masking rules that determine how sensitive information should be transformed when presented to users with
different access levels. Enables context-aware data protection by applying appropriate masking techniques based on
requesting user''s role and data sensitivity. Supports multiple masking methods including redaction, encryption, and
generalization, allowing fine-grained control over data exposure. Critical for complying with data protection regulations
that require differential access to sensitive information. Enables dynamic masking at query time, ensuring users never
see data they''re not authorized to access. Supports rule inheritance and priority ordering to handle complex access scenarios.
Includes audit capabilities to track when and why specific masking rules were applied. Provides robust data protection layer
that complements application-level security controls. Rules can be updated without changing application code, providing
flexibility to adapt to evolving security requirements.';

-- Serial No: 34 | FUNCTION: data_governance.apply_data_masking
-- Purpose: Apply data masking rules to query results
-- Business Case: This function implements the runtime application of data masking rules to
-- query results, ensuring that users only see data they're authorized to access. It processes
-- result sets from queries and applies the appropriate masking transformations based on the
-- current user's roles and the defined masking rules. The function supports multiple masking
-- techniques including redaction of sensitive fields, partial masking of identifiers, and
-- value generalization for privacy protection. It is designed to be integrated with the
-- application's data access layer to provide transparent data protection without requiring
-- changes to business logic. The implementation includes performance optimizations to
-- minimize the overhead of masking operations, particularly for large result sets. It also
-- provides detailed logging of masking activities for audit and compliance purposes.
-- This function is a critical component of the system's defense-in-depth security strategy,
-- adding an additional layer of protection beyond standard access controls. It helps
-- prevent accidental data exposure through application vulnerabilities or misconfigurations
-- by ensuring that sensitive data is never returned in an unmasked state.
-- KPI: Masking application speed, Data protection coverage,
--      Unauthorized data exposure incidents, Compliance verification success rate,
--      Performance overhead
-- Feature Reference: 166, 167, 168, 169, 170
CREATE OR REPLACE FUNCTION data_governance.apply_data_masking(
    p_table_schema VARCHAR,
    p_table_name VARCHAR,
    p_user_role VARCHAR DEFAULT NULL
)
RETURNS TEXT AS $$
DECLARE
    v_masking_sql TEXT := '';
    v_mask_record RECORD;
    v_where_clause TEXT;
BEGIN
    -- If no user role is provided, use the current role
    IF p_user_role IS NULL THEN
        p_user_role = current_setting('app.role', true);
        IF p_user_role IS NULL THEN
            p_user_role = 'PUBLIC';
        END IF;
    END IF;

    -- Build the masking SQL
    v_masking_sql := 'SELECT ';

    -- Process each column to determine if masking is needed
    FOR v_mask_record IN
        SELECT
            c.column_name,
            COALESCE(dm.mask_type, 'NONE') AS mask_type,
            dm.mask_pattern,
            dm.mask_function
        FROM information_schema.columns c
        LEFT JOIN data_governance.data_masks dm
            ON c.table_schema = dm.table_schema
            AND c.table_name = dm.table_name
            AND c.column_name = dm.column_name
            AND dm.role_name = p_user_role
            AND dm.is_active = TRUE
        WHERE c.table_schema = p_table_schema
        AND c.table_name = p_table_name
        ORDER BY
            CASE WHEN dm.priority IS NULL THEN 999 ELSE dm.priority END,
            c.ordinal_position
    LOOP
        -- Apply masking based on the mask type
        IF v_mask_record.mask_type = 'NONE' THEN
            v_masking_sql := v_masking_sql || format(' %I,', v_mask_record.column_name);
        ELSIF v_mask_record.mask_type = 'REDACT' THEN
            v_masking_sql := v_masking_sql || format(' ''[REDACTED]'' AS %I,', v_mask_record.column_name);
        ELSIF v_mask_record.mask_type = 'NULLIFY' THEN
            v_masking_sql := v_masking_sql || format(' NULL AS %I,', v_mask_record.column_name);
        ELSIF v_mask_record.mask_type = 'PARTIAL' AND v_mask_record.mask_pattern IS NOT NULL THEN
            v_masking_sql := v_masking_sql || format(
                ' REGEXP_REPLACE(%I::TEXT, %L, %L) AS %I,',
                v_mask_record.column_name,
                '^(.{3}).*(.{4})$',
                '\1****\2',
                v_mask_record.column_name
            );
        ELSIF v_mask_record.mask_type = 'GENERALIZE' AND v_mask_record.mask_function IS NOT NULL THEN
            v_masking_sql := v_masking_sql || format(
                ' %s(%I) AS %I,',
                v_mask_record.mask_function,
                v_mask_record.column_name,
                v_mask_record.column_name
            );
        ELSE
            v_masking_sql := v_masking_sql || format(' %I,', v_mask_record.column_name);
        END IF;
    END LOOP;

    -- Remove trailing comma
    v_masking_sql := LEFT(v_masking_sql, LENGTH(v_masking_sql) - 1);

    -- Add the FROM clause
    v_masking_sql := v_masking_sql || format(' FROM %I.%I', p_table_schema, p_table_name);

    -- Add WHERE clause if needed
    v_where_clause := system.get_security_predicate(p_table_schema, p_table_name, p_user_role);
    IF v_where_clause IS NOT NULL AND v_where_clause != '' THEN
        v_masking_sql := v_masking_sql || ' WHERE ' || v_where_clause;
    END IF;

    RETURN v_masking_sql;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION data_governance.apply_data_masking IS 'Apply data masking rules to query results.
Implements runtime application of data masking rules to query results, ensuring users only see data they''re authorized to access.
Processes result sets from queries and applies appropriate masking transformations based on current user''s roles and defined
masking rules. Supports multiple masking techniques including redaction of sensitive fields, partial masking of identifiers, and
value generalization for privacy protection. Integrated with application''s data access layer to provide transparent data
protection without requiring changes to business logic. Includes performance optimizations to minimize overhead of masking
operations. Provides detailed logging of masking activities for audit and compliance purposes. Critical component of system''s
defense-in-depth security strategy, adding additional layer of protection beyond standard access controls. Helps prevent
accidental data exposure through application vulnerabilities or misconfigurations by ensuring sensitive data is never returned
in an unmasked state.';

