-- Serial No: 35 | TABLE: system.maintenance_jobs
-- Purpose: Tracks scheduled maintenance and background jobs
-- Business Case: This table manages the scheduling and execution of background maintenance
-- tasks that are critical for system health and performance. It provides a centralized
-- repository for job definitions, schedules, and execution history, enabling consistent
-- management of operational processes across the system. The table supports multiple job
-- types including data archiving, index maintenance, statistics gathering, and custom
-- business processes. Each job definition includes parameters for controlling execution
-- behavior, retry logic, and resource allocation. The design accommodates dependencies
-- between jobs to ensure proper execution order for complex maintenance workflows.
-- Comprehensive tracking of job execution history enables performance analysis and
-- troubleshooting of maintenance operations. The table also supports dynamic adjustment
-- of job schedules based on system load and business priorities, optimizing resource
-- utilization during maintenance windows. This functionality is essential for maintaining
-- system performance and reliability, particularly in environments with large data
-- volumes where maintenance operations can significantly impact availability. The
-- implementation includes safeguards against job overlap and resource contention to
-- prevent maintenance activities from interfering with operational workloads.
-- KPI: Job execution success rate, Maintenance window utilization,
--      System performance impact, Job completion time,
--      Error resolution time
-- Feature Reference: 171, 172, 173, 174, 175
CREATE TABLE IF NOT EXISTS system.maintenance_jobs (
    job_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    job_name VARCHAR(100) NOT NULL UNIQUE,
    job_type VARCHAR(50) NOT NULL CHECK (job_type IN ('DATA_ARCHIVE', 'INDEX_MAINTENANCE', 'STATISTICS_GATHERING', 'DATA_REFRESH', 'CUSTOM')),
    description TEXT,
    schedule_cron VARCHAR(50) NOT NULL,
    next_run_at TIMESTAMP WITH TIME ZONE NOT NULL,
    last_run_at TIMESTAMP WITH TIME ZONE,
    last_run_duration INTERVAL,
    last_run_status VARCHAR(20) CHECK (last_run_status IN ('SUCCESS', 'FAILED', 'RUNNING', 'SKIPPED')),
    last_run_message TEXT,
    max_runtime INTERVAL DEFAULT INTERVAL '2 hours',
    retry_count INTEGER DEFAULT 0,
    max_retries INTEGER DEFAULT 3,
    retry_interval INTERVAL DEFAULT INTERVAL '5 minutes',
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    parameters JSONB,
    dependencies UUID[] DEFAULT '{}',
    resource_group VARCHAR(50),
    priority INTEGER DEFAULT 50 CHECK (priority BETWEEN 1 AND 100),
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_schedule ON system.maintenance_jobs(next_run_at) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_status ON system.maintenance_jobs(last_run_status);
CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_type ON system.maintenance_jobs(job_type);
CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_active ON system.maintenance_jobs(is_active) WHERE is_active = TRUE;


-- Serial No: 36 | TABLE: ml.ml_models
-- Description: Machine learning model repository with version control and deployment tracking
-- Business Case: The ml_models table serves as the central repository for all machine learning models
-- used in workforce scheduling optimization and prediction. It tracks model versions, performance metrics,
-- and deployment status across different environments (development, testing, production). This table is
-- critical for implementing A/B testing of scheduling algorithms and ensuring model reproducibility.
-- It enables the organization to systematically evaluate model performance against business metrics
-- and make data-driven decisions about model deployment. The table supports multiple model types
-- including forecasting, classification, and optimization models that power various aspects of the
-- scheduling system. It includes metadata about model features, training data, and expected input
-- schema to ensure proper integration with the scheduling engine. The versioning system allows for
-- rollback to previous models if performance degrades, providing operational resilience. The table
-- also tracks model lineage to support regulatory compliance and audit requirements for AI-driven
-- decision making. By centralizing model management, the table facilitates collaboration between
-- data science and operations teams, ensuring that the best performing models are deployed for
-- workforce optimization.
-- KPI: Model deployment success rate, Model performance degradation rate,
--      A/B test conversion rate, Model versioning compliance,
--      Time to model productionization
-- Feature Reference: 176, 177, 178, 179, 180
CREATE TABLE IF NOT EXISTS ml.ml_models (
    model_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    model_name VARCHAR(100) NOT NULL,
    model_type VARCHAR(50) NOT NULL CHECK (model_type IN ('FORECASTING', 'CLASSIFICATION', 'REGRESSION', 'CLUSTERING',
        'ANOMALY_DETECTION', 'RECOMMENDATION', 'OPTIMIZATION')),
    version VARCHAR(50) NOT NULL,
    version_description TEXT,
    model_path TEXT NOT NULL,
    model_format VARCHAR(50) CHECK (model_format IN ('PICKLE', 'HDF5', 'ONNX', 'PMML', 'CUSTOM')),
    model_size_bytes INTEGER CHECK (model_size_bytes > 0),
    model_signature JSONB,
    training_data_id UUID,
    training_date TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    trained_by UUID NOT NULL,
    performance_metrics JSONB,
    is_production BOOLEAN NOT NULL DEFAULT FALSE,
    deployment_stage VARCHAR(50) NOT NULL DEFAULT 'DEVELOPMENT'
        CHECK (deployment_stage IN ('DEVELOPMENT', 'TESTING', 'STAGING', 'PRODUCTION')),
    is_ab_testing BOOLEAN NOT NULL DEFAULT FALSE,
    ab_test_group VARCHAR(20) CHECK (ab_test_group IN ('CONTROL', 'VARIANT_A', 'VARIANT_B')),
    traffic_allocation NUMERIC(5,2) DEFAULT 100.00
        CHECK (traffic_allocation BETWEEN 0.00 AND 100.00),
    deprecation_date TIMESTAMP WITH TIME ZONE,
    notes TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_ml_models_production ON ml.ml_models(deployment_stage, is_production)
    WHERE is_production = TRUE;
CREATE INDEX IF NOT EXISTS idx_ml_models_type ON ml.ml_models(model_type, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_ml_models_ab_testing ON ml.ml_models(is_ab_testing, ab_test_group)
    WHERE is_ab_testing = TRUE;
CREATE INDEX IF NOT EXISTS idx_ml_models_name ON ml.ml_models(model_name);
CREATE INDEX IF NOT EXISTS idx_ml_models_trained_by ON ml.ml_models(trained_by);
CREATE INDEX IF NOT EXISTS idx_ml_models_deprecation ON ml.ml_models(deprecation_date)
    WHERE deprecation_date IS NOT NULL;

-- Add triggers for audit columns
CREATE TRIGGER trg_ml_models_updated_at
BEFORE UPDATE ON ml.ml_models
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

