-- Serial No: 37 | TABLE: ml.model_deployment_history
-- Description: Audit trail of model deployment activities
-- Business Case: The model_deployment_history table provides a complete audit trail of all model
-- deployment activities, capturing when models were promoted between environments and who authorized
-- the changes. This information is critical for maintaining model governance and ensuring accountability
-- in the model deployment process. The table tracks deployment parameters including traffic allocation
-- for A/B tests, deployment duration, and verification results. It enables rollback to previous
-- deployments if issues are detected in production. The deployment history supports compliance
-- requirements for AI systems by providing evidence of proper validation and testing before
-- production deployment. It also facilitates root cause analysis when model performance issues
-- arise by correlating deployment events with performance metrics. The table includes detailed
-- error logging for failed deployments to support troubleshooting and process improvement.
-- By maintaining this comprehensive deployment history, the organization can demonstrate due
-- diligence in model management and meet regulatory requirements for AI transparency. The data
-- structure is optimized for rapid querying during incident response and performance analysis.
-- KPI: Deployment success rate, Mean time to recovery (MTTR),
--      Deployment verification completeness, Rollback frequency,
--      Deployment error resolution time
-- Feature Reference: 181, 182, 183, 184, 185
CREATE TABLE IF NOT EXISTS ml.model_deployment_history (
    deployment_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    model_id UUID NOT NULL REFERENCES ml.ml_models(model_id) ON DELETE CASCADE,
    from_version VARCHAR(50),
    to_version VARCHAR(50) NOT NULL,
    deployment_stage VARCHAR(50) NOT NULL
        CHECK (deployment_stage IN ('DEVELOPMENT', 'TESTING', 'STAGING', 'PRODUCTION')),
    deployed_by UUID NOT NULL,
    deployed_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    completed_at TIMESTAMP WITH TIME ZONE,
    deployment_duration_ms INTEGER CHECK (deployment_duration_ms >= 0),
    traffic_allocation NUMERIC(5,2) DEFAULT 100.00
        CHECK (traffic_allocation BETWEEN 0.00 AND 100.00),
    verification_results JSONB,
    deployment_status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
        CHECK (deployment_status IN ('PENDING', 'IN_PROGRESS', 'SUCCESS', 'FAILED', 'ROLLED_BACK')),
    deployment_log TEXT,
    rollback_initiated_by UUID REFERENCES hr.employees(employee_id),
    rollback_initiated_at TIMESTAMP WITH TIME ZONE,
    rollback_reason TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_model_deployment_model ON ml.model_deployment_history(model_id);
CREATE INDEX IF NOT EXISTS idx_model_deployment_stage ON ml.model_deployment_history(deployment_stage);
CREATE INDEX IF NOT EXISTS idx_model_deployment_status ON ml.model_deployment_history(deployment_status);
CREATE INDEX IF NOT EXISTS idx_model_deployment_time ON ml.model_deployment_history(deployed_at DESC);
CREATE INDEX IF NOT EXISTS idx_model_deployment_deployed_by ON ml.model_deployment_history(deployed_by);
CREATE INDEX IF NOT EXISTS idx_model_deployment_rollback ON ml.model_deployment_history(rollback_initiated_by)
    WHERE rollback_initiated_by IS NOT NULL;

-- Add triggers for audit columns
CREATE TRIGGER trg_model_deployment_history_updated_at
BEFORE UPDATE ON ml.model_deployment_history
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE ml.model_deployment_history IS 'Audit trail of model deployment activities.
Provides complete audit trail of all model deployment activities, capturing when models were promoted between environments
