CREATE INDEX IF NOT EXISTS idx_data_quality_issues_target ON data_quality.data_quality_issues(schema_name, table_name, column_name);
CREATE INDEX IF NOT EXISTS idx_data_quality_issues_severity ON data_quality.data_quality_issues(severity);
CREATE INDEX IF NOT EXISTS idx_data_quality_issues_status ON data_quality.data_quality_issues(status);
CREATE INDEX IF NOT EXISTS idx_data_quality_issues_detected ON data_quality.data_quality_issues(detected_at DESC);
CREATE INDEX IF NOT EXISTS idx_data_quality_issues_assigned ON data_quality.data_quality_issues(assigned_to)
    WHERE assigned_to IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_data_quality_issues_resolved ON data_quality.data_quality_issues(resolved_at)
