-- Serial No: 40 | TABLE: system.export_jobs
-- Description: Secure data export and sharing management
-- Business Case: The export_jobs table manages all data export requests from the workforce scheduling
-- system, providing a secure and auditable mechanism for data sharing. It tracks export parameters
-- including requested data, format, filters, and intended recipients. The table enforces security
-- policies by validating that users have appropriate access to the requested data and that exports
-- comply with data retention and privacy regulations. Each export job includes encryption status,
-- access controls, and expiration policies to prevent unauthorized data dissemination. The design
-- supports multiple export formats (CSV, Excel, PDF) and delivery methods (email, secure download,
-- API). Comprehensive audit logging captures who requested the export, when it was accessed, and
-- by whom, supporting compliance with data protection regulations. The table also tracks download
-- statistics and automatically purges expired exports according to retention policies. For sensitive
-- data exports, the system integrates with data loss prevention tools to scan for PII and prevent
-- accidental exposure. The implementation includes safeguards against large data exports that could
-- impact system performance. By centralizing export management, the table ensures consistent
-- application of data security policies while providing necessary flexibility for business operations.
-- KPI: Export request approval rate, Data exposure incidents,
--      Export processing time, Policy compliance rate,
--      Unauthorized access attempts
-- Feature Reference: 196, 197, 198, 199, 200
CREATE TABLE IF NOT EXISTS system.export_jobs (
    export_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    job_code VARCHAR(50) UNIQUE NOT NULL CHECK (job_code ~ '^[A-Z0-9_-]{5,50}$'),
    name VARCHAR(200) NOT NULL,
    description TEXT,
    export_type VARCHAR(50) NOT NULL CHECK (export_type IN ('SCHEDULE', 'REPORT', 'AUDIT_TRAIL', 'ANALYTICS', 'CUSTOM')),
    query_parameters JSONB NOT NULL,
    format VARCHAR(20) NOT NULL DEFAULT 'CSV' CHECK (format IN ('CSV', 'EXCEL', 'PDF', 'JSON')),
    filter_criteria JSONB,
    requested_by UUID NOT NULL,
    requested_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    processed_at TIMESTAMP WITH TIME ZONE,
    completed_at TIMESTAMP WITH TIME ZONE,
    status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
        CHECK (status IN ('PENDING', 'PROCESSING', 'COMPLETED', 'FAILED', 'CANCELLED')),
    file_path TEXT,
    file_size_bytes BIGINT CHECK (file_size_bytes >= 0),
    is_encrypted BOOLEAN NOT NULL DEFAULT TRUE,
    encryption_key_id UUID,
    expiry_time TIMESTAMP WITH TIME ZONE,
    max_downloads INTEGER NOT NULL DEFAULT 5 CHECK (max_downloads >= 0),
    download_count INTEGER NOT NULL DEFAULT 0,
    allowed_recipients UUID[],
    download_links JSONB,
    error_message TEXT,
    data_retention_policy VARCHAR(50) NOT NULL DEFAULT 'STANDARD'
        CHECK (data_retention_policy IN ('STANDARD', 'SENSITIVE', 'CONFIDENTIAL', 'HIGHLY_CONFIDENTIAL')),
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);

