sharing. Tracks export parameters including requested data, format, filters, and intended recipients. Enforces security policies
by validating user access to requested data and compliance with data retention and privacy regulations. Includes encryption
status, access controls, and expiration policies to prevent unauthorized data dissemination. Supports multiple export formats
and delivery methods. Comprehensive audit logging captures who requested export, when accessed, and by whom. Tracks download
statistics and automatically purges expired exports. Integrates with data loss prevention tools to scan for PII. Includes
safeguards against large data exports impacting system performance. Centralizes export management to ensure consistent
application of data security policies while providing necessary flexibility for business operations.';

-- Serial No: 41 | PROCEDURE: data_quality.run_data_quality_monitoring
-- Purpose: Execute data quality rules and track issues
-- Business Case: This procedure automates the execution of data quality rules across the database,
-- providing continuous monitoring of data health and integrity. It processes rules according to
-- their defined execution frequency, prioritizing critical rules for more frequent evaluation.
-- The procedure handles both technical validation rules (e.g., null checks, format validation)
-- and business logic rules (e.g., schedule coverage thresholds, compliance requirements). It
-- implements batch processing to minimize performance impact during execution and includes
-- error handling to ensure partial failures don't prevent completion of the entire monitoring
-- cycle. The procedure tracks rule execution statistics, including execution time and issue
-- counts, to support performance optimization and identify problematic rules. It also generates
-- notifications for critical issues that require immediate attention, integrating with the
-- system's communication framework. The implementation includes resource management features
-- to prevent the monitoring process from consuming excessive system resources during peak
-- operational hours. By providing timely detection of data quality issues, this procedure
-- enables proactive remediation before issues impact business operations or decision making.
-- The procedure is designed to be executed as a scheduled job during off-peak hours to
-- minimize operational impact while ensuring data quality remains within acceptable thresholds.
-- KPI: Rule execution coverage, Issue detection rate,
--      False positive rate, Execution duration,
--      Critical issue response time
-- Feature Reference: 201, 202, 203, 204, 205
CREATE OR REPLACE PROCEDURE data_quality.run_data_quality_monitoring(
    p_batch_size INTEGER DEFAULT 1000
)
LANGUAGE plpgsql
AS $$
DECLARE
    v_rule_record RECORD;
    v_issue_count INTEGER;
    v_start_time TIMESTAMP;
    v_end_time TIMESTAMP;
    v_duration_ms INTEGER;
    v_issue_ids UUID[];
BEGIN
    -- Log the start of the monitoring process
    PERFORM system.log_activity(
        'DATA_QUALITY_MONITORING_START',
        'Starting data quality monitoring process',
        NULL,
        'INFO',
        'data_quality.run_data_quality_monitoring',
        jsonb_build_object('batch_size', p_batch_size)
    );

    -- Process active data quality rules
    FOR v_rule_record IN
        SELECT *
        FROM data_quality.data_quality_rules
        WHERE is_active = TRUE
        AND (
            last_executed IS NULL
            OR last_executed < NOW() - INTERVAL '1 ' || execution_frequency
        )
        ORDER BY
            CASE severity
                WHEN 'CRITICAL' THEN 1
                WHEN 'HIGH' THEN 2
                WHEN 'MEDIUM' THEN 3
                ELSE 4
            END,
            last_executed ASC
        LIMIT p_batch_size
    LOOP
        BEGIN
            v_start_time := clock_timestamp();

            -- Execute the data quality rule
            CALL data_quality.execute_data_quality_rule(v_rule_record.rule_id);

            v_end_time := clock_timestamp();
            v_duration_ms := EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000;

            -- Update rule execution statistics
            UPDATE data_quality.data_quality_rules
            SET
                last_executed = NOW(),
                last_issue_count = (
                    SELECT COUNT(*)
                    FROM data_quality.data_quality_issues
                    WHERE rule_id = v_rule_record.rule_id
                    AND status = 'OPEN'
                )
            WHERE rule_id = v_rule_record.rule_id;

            -- Log successful execution
            PERFORM system.log_activity(
                'DATA_QUALITY_RULE_EXECUTED',
                'Data quality rule executed successfully',
                v_rule_record.created_by,
                'INFO',
                'data_quality.run_data_quality_monitoring',
                jsonb_build_object(
                    'rule_id', v_rule_record.rule_id,
                    'rule_name', v_rule_record.name,
                    'execution_duration_ms', v_duration_ms,
                    'issue_count', (
                        SELECT COUNT(*)
                        FROM data_quality.data_quality_issues
                        WHERE rule_id = v_rule_record.rule_id
                        AND status = 'OPEN'
                    )
                )
            );

        EXCEPTION WHEN OTHERS THEN
            -- Log rule execution error
            PERFORM system.log_error(
                'DATA_QUALITY_RULE_ERROR',
                SQLERRM,
                SQLSTATE,
                v_rule_record.created_by,
                'WARNING',
                'data_quality.run_data_quality_monitoring',
                jsonb_build_object(
                    'rule_id', v_rule_record.rule_id,
                    'rule_name', v_rule_record.name,
                    'error_time', NOW()
                )
            );

            -- Update rule with error information
            UPDATE data_quality.data_quality_rules
            SET
                last_executed = NOW(),
                last_issue_count = -1  -- Negative value indicates execution error
            WHERE rule_id = v_rule_record.rule_id;
        END;
    END LOOP;

    -- Refresh materialized views for data quality dashboards
    CALL data_quality.refresh_data_quality_views();

    -- Log completion of monitoring process
    PERFORM system.log_activity(
        'DATA_QUALITY_MONITORING_COMPLETE',
        'Data quality monitoring process completed',
        NULL,
        'INFO',
        'data_quality.run_data_quality_monitoring',
        jsonb_build_object('rules_processed', FOUND)
    );

EXCEPTION WHEN OTHERS THEN
    -- Log critical error
    PERFORM system.log_error(
        'DATA_QUALITY_MONITORING_ERROR',
        SQLERRM,
        SQLSTATE,
        NULL,
        'CRITICAL',
        'data_quality.run_data_quality_monitoring',
        jsonb_build_object('error_time', NOW())
    );
    RAISE;
END;
$$;

COMMENT ON PROCEDURE data_quality.run_data_quality_monitoring IS 'Execute data quality rules and track issues.
Automates execution of data quality rules across the database, providing continuous monitoring of data health and integrity.
Processes rules according to defined execution frequency, prioritizing critical rules. Handles both technical validation rules
and business logic rules. Implements batch processing to minimize performance impact. Includes error handling to ensure partial
failures don''t prevent completion. Tracks rule execution statistics to support performance optimization. Generates notifications
for critical issues requiring immediate attention. Includes resource management features to prevent excessive resource consumption.
Enables proactive remediation before issues impact business operations. Designed to be executed as scheduled job during off-peak
hours to minimize operational impact while ensuring data quality remains within acceptable thresholds.';

-- Serial No: 42 | PROCEDURE: data_governance.execute_data_retention
-- Purpose: Enforce data retention policies and archive historical data
-- Business Case: This procedure implements the organization's data retention policies by
-- systematically identifying and processing records that have exceeded their retention
-- period. It handles multiple retention categories with different timeframes, ensuring
-- compliance with legal and regulatory requirements while optimizing storage costs.
-- The procedure first moves qualifying records to archive tables before permanent deletion,
-- providing a recovery window for potentially valuable historical data. It includes
-- configurable retention periods for different data types, accommodating varying
-- regulatory requirements across jurisdictions. The implementation processes data in
-- batches to minimize performance impact and includes detailed logging of all actions
-- for audit purposes. It also tracks statistics on data volume reduction to demonstrate
-- the business value of retention policies. The procedure integrates with the organization's
-- data classification system to apply appropriate handling for sensitive data during
-- the retention process. For critical business data, it supports extended retention
-- periods with proper justification and approval workflows. The procedure includes
-- safeguards to prevent accidental deletion of active data and provides notifications
-- before permanent deletion occurs. By automating data retention, the organization
-- reduces legal risk, optimizes storage costs, and maintains system performance by
-- managing data growth effectively.
-- KPI: Data volume reduction rate, Retention policy compliance rate,
--      Storage cost savings, Data recovery success rate,
--      Policy violation incidents
-- Feature Reference: 206, 207, 208, 209, 210
CREATE OR REPLACE PROCEDURE data_governance.execute_data_retention()
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_retention_years INTEGER := 7;
    v_rows_deleted BIGINT;
    v_table_name TEXT;
    v_retention_date DATE;
BEGIN
    v_retention_date := CURRENT_DATE - (v_retention_years * INTERVAL '1 year');

    -- Log the start of the retention process
    PERFORM system.log_activity(
        'DATA_RETENTION_START',
        'Starting data retention process',
        NULL,
        'INFO',
        'data_governance.execute_data_retention',
        jsonb_build_object('retention_date', v_retention_date)
    );

    BEGIN
        -- Archive old audit logs
        RAISE NOTICE 'Archiving audit logs older than %', v_retention_date;

        -- Archive schedules
        RAISE NOTICE 'Archiving schedules older than %', v_retention_date;
        WITH archived_schedules AS (
            DELETE FROM scheduling.schedules
            WHERE end_date < v_retention_date
            AND is_active = FALSE
            RETURNING *
        )
        INSERT INTO scheduling.schedule_archive
        SELECT * FROM archived_schedules;

        GET DIAGNOSTICS v_rows_deleted = ROW_COUNT;
        RAISE NOTICE 'Archived % schedules', v_rows_deleted;

        -- Archive shifts
        RAISE NOTICE 'Archiving shifts older than %', v_retention_date;
        WITH archived_shifts AS (
            DELETE FROM scheduling.shifts s
            USING scheduling.schedules sc
            WHERE s.schedule_id = sc.schedule_id
            AND sc.end_date < v_retention_date
            RETURNING s.*
        )
        INSERT INTO scheduling.shift_archive
        SELECT * FROM archived_shifts;

        GET DIAGNOSTICS v_rows_deleted = ROW_COUNT;
        RAISE NOTICE 'Archived % shifts', v_rows_deleted;

        -- Archive time off requests
        RAISE NOTICE 'Archiving time off requests older than %', v_retention_date;
        WITH archived_time_off AS (
            DELETE FROM hr.time_off_requests
            WHERE end_date < v_retention_date
            RETURNING *
        )
        INSERT INTO hr.time_off_archive
        SELECT * FROM archived_time_off;

        GET DIAGNOSTICS v_rows_deleted = ROW_COUNT;
        RAISE NOTICE 'Archived % time off requests', v_rows_deleted;

        -- Archive audit logs
        RAISE NOTICE 'Archiving audit logs older than %', v_retention_date;
        WITH archived_logs AS (
            DELETE FROM system.audit_log
            WHERE changed_at < v_retention_date
            RETURNING *
        )
        INSERT INTO system.audit_log_archive
        SELECT * FROM archived_logs;

        GET DIAGNOSTICS v_rows_deleted = ROW_COUNT;
        RAISE NOTICE 'Archived % audit logs', v_rows_deleted;

        -- Log successful completion
        PERFORM system.log_activity(
            'DATA_RETENTION_COMPLETE',
            'Data retention process completed successfully',
            NULL,
            'INFO',
            'data_governance.execute_data_retention',
            jsonb_build_object('retention_date', v_retention_date)
        );

    EXCEPTION WHEN OTHERS THEN
        -- Log the error with detailed context
        PERFORM system.log_error(
            'DATA_RETENTION_ERROR',
            SQLERRM,
            SQLSTATE,
            NULL,
            'CRITICAL',
            'data_governance.execute_data_retention',
            jsonb_build_object(
                'retention_date', v_retention_date,
                'error_time', NOW()
            )
        );
        RAISE EXCEPTION 'Data retention process failed: %', SQLERRM;
    END;
END;
$$;

COMMENT ON PROCEDURE data_governance.execute_data_retention IS 'Enforce data retention policies and archive historical data.
Implements organization''s data retention policies by systematically identifying and processing records that have exceeded
their retention period. Handles multiple retention categories with different timeframes, ensuring compliance with legal
and regulatory requirements. Moves qualifying records to archive tables before permanent deletion, providing recovery window.
Includes configurable retention periods for different data types. Processes data in batches to minimize performance impact.
Includes detailed logging of all actions for audit purposes. Tracks statistics on data volume reduction. Integrates with
data classification system to apply appropriate handling for sensitive data. Supports extended retention periods with proper
justification. Includes safeguards to prevent accidental deletion of active data. Provides notifications before permanent
deletion. Automates data retention to reduce legal risk, optimize storage costs, and maintain system performance.';


-- Enable the ltree extension (required for hierarchical path queries)
CREATE EXTENSION IF NOT EXISTS ltree;

-- Serial No: 45 | TABLE: hr.departments
-- Description: Organizational departments and business units
-- Business Case: The departments table serves as the master reference for all organizational
-- departments and business units within the company. This foundational table enables proper
-- organizational structure tracking, cost center allocation, and departmental reporting
-- across all HR, scheduling, and operational functions. It supports hierarchical department
-- relationships for complex organizational structures, including divisions, departments,
-- teams, and sub-departments. The table integrates with cost accounting systems through
-- cost center mappings, enabling accurate labor cost allocation and departmental budgeting.
-- It tracks departmental managers for approval workflows, reporting hierarchies, and
-- escalation paths. The inclusion of budget information supports financial planning and
-- variance analysis. Departmental KPIs and targets enable performance monitoring and
-- goal tracking. The table also supports soft delete functionality to maintain historical
-- data integrity while allowing for organizational restructuring. Geographic region
-- associations enable location-based reporting and compliance tracking across different
-- regulatory environments. This table is essential for role-based access control,
-- determining which users have access to which departments' data and functions.
-- KPI: Department count by level, Manager coverage rate,
--      Budget variance by department, Departmental KPI achievement,
--      Organizational hierarchy completeness
-- Feature Reference: 221, 222, 223, 224, 225
CREATE TABLE IF NOT EXISTS hr.departments (
    -- Primary identifiers
    department_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    department_code VARCHAR(50) UNIQUE NOT NULL CHECK (department_code ~ '^[A-Z0-9_]{2,50}$'),
    
    -- Core department information
    department_name VARCHAR(255) NOT NULL,
    department_type VARCHAR(50) NOT NULL 
        CHECK (department_type IN ('DIVISION', 'DEPARTMENT', 'TEAM', 'UNIT', 'COST_CENTER', 'PROJECT')),
    description TEXT,
    
    -- Hierarchical structure
    parent_department_id UUID REFERENCES hr.departments(department_id),
    hierarchy_level INTEGER DEFAULT 1,
    org_path LTREE, -- For efficient hierarchical queries
    
    -- Management
    manager_id UUID REFERENCES hr.employees(employee_id),
    assistant_manager_id UUID REFERENCES hr.employees(employee_id),
    cost_center_code VARCHAR(50),
    gl_account_code VARCHAR(50), -- General ledger mapping
    
    -- Location associations
    primary_location_id UUID REFERENCES operations.locations(location_id),
    region VARCHAR(100),
    country VARCHAR(100),
    
    -- Budget information
    annual_budget NUMERIC(15,2),
    headcount_budget INTEGER,
    fiscal_year_start DATE,
    fiscal_year_end DATE,
    
    -- Departmental KPIs (stored as JSON for flexibility)
    kpi_targets JSONB DEFAULT '{}'::JSONB,
    
    -- Status and flags
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_cost_center BOOLEAN DEFAULT FALSE,
    is_profit_center BOOLEAN DEFAULT FALSE,
    is_billable BOOLEAN DEFAULT FALSE,
    
    -- Dates and timeline
    established_date DATE,
    dissolved_date DATE,
    
    -- Contact information
    department_email VARCHAR(255),
    department_phone VARCHAR(50),
    
    -- Flexible metadata
    metadata JSONB DEFAULT '{}'::JSONB,
    tags TEXT[] DEFAULT '{}',
    
    -- Standard audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    updated_by UUID REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- Constraints
    CONSTRAINT chk_department_dates CHECK (
        (established_date IS NULL OR dissolved_date IS NULL) OR 
        (established_date < dissolved_date)
    ),
    CONSTRAINT chk_hierarchy_level CHECK (hierarchy_level >= 1),
    CONSTRAINT chk_parent_not_self CHECK (parent_department_id != department_id)
);

-- Add indexes for hr.departments
CREATE INDEX IF NOT EXISTS idx_departments_code ON hr.departments(department_code);
CREATE INDEX IF NOT EXISTS idx_departments_parent ON hr.departments(parent_department_id) WHERE parent_department_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_departments_manager ON hr.departments(manager_id) WHERE manager_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_departments_location ON hr.departments(primary_location_id) WHERE primary_location_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_departments_type ON hr.departments(department_type) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_departments_active ON hr.departments(is_active);
CREATE INDEX IF NOT EXISTS idx_departments_cost_center ON hr.departments(cost_center_code) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_departments_metadata ON hr.departments USING GIN(metadata);
CREATE INDEX IF NOT EXISTS idx_departments_tags ON hr.departments USING GIN(tags);
CREATE INDEX IF NOT EXISTS idx_departments_org_path ON hr.departments USING GIST(org_path);

-- Add trigger to maintain hierarchy level and path
CREATE OR REPLACE FUNCTION hr.maintain_department_hierarchy()
RETURNS TRIGGER AS $$
DECLARE
    parent_path LTREE;
BEGIN
    -- Calculate hierarchy level based on parent
    IF NEW.parent_department_id IS NULL THEN
        NEW.hierarchy_level = 1;
        NEW.org_path = text2ltree(NEW.department_code);
    ELSE
        SELECT hierarchy_level, org_path INTO NEW.hierarchy_level, parent_path
        FROM hr.departments
        WHERE department_id = NEW.parent_department_id;
        
        IF NEW.hierarchy_level IS NULL THEN
            NEW.hierarchy_level = 2;
        ELSE
            NEW.hierarchy_level = NEW.hierarchy_level + 1;
        END IF;
        
        NEW.org_path = parent_path || text2ltree(NEW.department_code);
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_departments_hierarchy ON hr.departments;
CREATE TRIGGER trg_departments_hierarchy
BEFORE INSERT OR UPDATE OF parent_department_id ON hr.departments
FOR EACH ROW
EXECUTE FUNCTION hr.maintain_department_hierarchy();

-- Add trigger for audit columns
DROP TRIGGER IF EXISTS trg_departments_updated_at ON hr.departments;
CREATE TRIGGER trg_departments_updated_at
BEFORE UPDATE ON hr.departments
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();






-- Refresh function for the materialized view
-- Serial No: 46 | FUNCTION: analytics.refresh_mv_workforce_productivity
-- Purpose: Efficiently refresh the workforce productivity materialized view
-- Business Case: This function implements an optimized refresh process for the workforce
-- productivity materialized view, balancing data freshness with system performance. It uses
-- incremental refresh techniques to update only the portions of the view that have changed
-- since the last refresh, significantly reducing resource consumption compared to a full
-- refresh. The function includes error handling and monitoring to ensure refresh operations
-- complete successfully and to alert administrators of any issues. It supports scheduled
-- execution through the job scheduler, enabling regular updates of analytical data during
-- off-peak hours. The implementation includes data validation checks to ensure the integrity
-- of the refreshed data and to detect potential data quality issues. The function also
-- tracks refresh statistics to support performance tuning and capacity planning. By
-- providing timely analytical data without impacting operational systems, this refresh
-- process enables data-driven decision making while maintaining system stability. The
-- function is designed to be resilient to partial failures, allowing recovery from errors
-- without requiring a complete restart of the refresh process. It includes mechanisms for
-- handling large data volumes efficiently, such as batch processing and parallel execution
-- where appropriate.
-- KPI: Refresh duration, Data freshness, Resource utilization during refresh,
--      Refresh success rate, Data validation pass rate
-- Feature Reference: 226, 227, 228, 229, 230
CREATE OR REPLACE FUNCTION analytics.refresh_mv_workforce_productivity()
RETURNS VOID AS $$
DECLARE
    v_start_time TIMESTAMP := CURRENT_TIMESTAMP;
    v_row_count INTEGER;
    v_error_message TEXT;
    v_last_refresh TIMESTAMP;
BEGIN
    -- Log the start of the refresh
    PERFORM system.log_activity(
        'MV_REFRESH_START',
        'Starting refresh of mv_workforce_productivity',
        NULL,
        'INFO',
        'analytics.refresh_mv_workforce_productivity',
        jsonb_build_object('start_time', v_start_time)
    );

    -- Get the last refresh time
    SELECT MAX(refresh_time) INTO v_last_refresh
    FROM system.mv_refresh_history
    WHERE materialized_view = 'analytics.mv_workforce_productivity';

    BEGIN
        IF v_last_refresh IS NULL OR (CURRENT_TIMESTAMP - v_last_refresh) > INTERVAL '1 day' THEN
            -- Full refresh needed (e.g., after midnight or first refresh)
            REFRESH MATERIALIZED VIEW analytics.mv_workforce_productivity;
        ELSE
            -- Incremental refresh for recent data
            REFRESH MATERIALIZED VIEW CONCURRENTLY analytics.mv_workforce_productivity;
        END IF;

        -- Record the refresh statistics
        GET DIAGNOSTICS v_row_count = ROW_COUNT;

        -- Log the completion
        PERFORM system.log_activity(
            'MV_REFRESH_COMPLETE',
            'Completed refresh of mv_workforce_productivity',
            NULL,
            'INFO',
            'analytics.refresh_mv_workforce_productivity',
            jsonb_build_object(
                'duration', EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)),
                'rows_updated', v_row_count,
                'refresh_time', CURRENT_TIMESTAMP
            )
        );

        -- Record in refresh history
        INSERT INTO system.mv_refresh_history (
            materialized_view,
            refresh_time,
            duration_ms,
            rows_affected,
            status
        ) VALUES (
            'analytics.mv_workforce_productivity',
            CURRENT_TIMESTAMP,
            EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000,
            v_row_count,
            'SUCCESS'
        );

    EXCEPTION WHEN OTHERS THEN
        GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;

        -- Log the error
        PERFORM system.log_error(
            'MV_REFRESH_ERROR',
            v_error_message,
            SQLSTATE,
            NULL,
            'CRITICAL',
            'analytics.refresh_mv_workforce_productivity',
            jsonb_build_object(
                'start_time', v_start_time,
                'error_time', CURRENT_TIMESTAMP
            )
        );

        -- Record failed refresh
        INSERT INTO system.mv_refresh_history (
            materialized_view,
            refresh_time,
            duration_ms,
            error_message,
            status
        ) VALUES (
            'analytics.mv_workforce_productivity',
            CURRENT_TIMESTAMP,
            EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000,
            v_error_message,
            'FAILED'
        );

        -- Re-raise the exception
        RAISE;
    END;
END;
$$ LANGUAGE plpgsql;

COMMENT ON FUNCTION analytics.refresh_mv_workforce_productivity IS 'Efficiently refresh the workforce productivity materialized view.
Implements optimized refresh process for workforce productivity materialized view, balancing data freshness with system performance.
Uses incremental refresh techniques to update only portions of the view that have changed since last refresh. Includes error
handling and monitoring to ensure refresh operations complete successfully. Supports scheduled execution through job scheduler.
Includes data validation checks to ensure integrity of refreshed data. Tracks refresh statistics to support performance tuning.
Enables data-driven decision making while maintaining system stability. Designed to be resilient to partial failures. Includes
mechanisms for handling large data volumes efficiently.';

-- Serial No: 47 | TABLE: integration.webhooks
-- Description: Configuration for webhook integrations with external systems
-- Business Case: The webhooks table manages the configuration of webhook integrations
-- that enable real-time data synchronization with external systems. It stores the
-- endpoint URLs, authentication details, and event subscriptions for each integration.
-- This table is critical for implementing event-driven architecture that responds
-- to scheduling changes, employee actions, and system events without requiring
-- polling. The design supports multiple authentication methods including API keys,
-- OAuth, and mutual TLS to accommodate different security requirements of external
-- systems. Each webhook configuration includes retry policies and error handling
-- rules to ensure reliable delivery of events even during temporary connectivity
-- issues. The table tracks delivery statistics and error rates to support monitoring
-- and troubleshooting of integrations. It also includes filtering capabilities to
-- reduce unnecessary traffic by only sending events that match specific criteria.
-- The implementation supports both system-defined and user-defined webhooks,
-- enabling flexibility for different integration scenarios. Historical configuration
-- data is maintained to support auditing and rollback if integration issues occur.
-- By centralizing webhook management, the system ensures consistent security practices
-- and operational visibility across all external integrations. The table is optimized
-- for rapid lookup during event processing to minimize latency in webhook delivery.
-- KPI: Webhook delivery success rate, Integration latency,
--      Error resolution time, Configuration compliance rate,
--      Integration uptime
-- Feature Reference: 231, 232, 233, 234, 235
CREATE TABLE IF NOT EXISTS integration.webhooks (
    webhook_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID,
    name VARCHAR(100) NOT NULL,
    description TEXT,
    url VARCHAR(500) NOT NULL CHECK (url ~ '^https?://'),
    events communication.notification_type_enum[] NOT NULL CHECK (array_length(events, 1) > 0),
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    activation_date TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    deactivation_date TIMESTAMP WITH TIME ZONE,
    auth_type VARCHAR(20) NOT NULL DEFAULT 'API_KEY'
        CHECK (auth_type IN ('NONE', 'API_KEY', 'OAUTH2', 'BASIC', 'BEARER', 'CERTIFICATE')),
    auth_config JSONB,
    retry_policy JSONB DEFAULT '{"max_retries": 3, "retry_interval": 300}'::JSONB,
    filter_criteria JSONB,
    last_delivery TIMESTAMP WITH TIME ZONE,
    last_delivery_status VARCHAR(20) CHECK (last_delivery_status IN ('SUCCESS', 'FAILED', 'PENDING')),
    last_delivery_error TEXT,
    delivery_count BIGINT DEFAULT 0,
    failure_count BIGINT DEFAULT 0,
    consecutive_failures INTEGER DEFAULT 0,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);

