-- Create function to process message queue
CREATE OR REPLACE FUNCTION communication.process_message_queue(
    p_batch_size INTEGER DEFAULT 100
)
RETURNS TABLE(
    processed_count INTEGER,
    failed_count INTEGER,
    log TEXT
) AS $$
DECLARE
    v_message RECORD;
    v_channel communication.channel_type_enum;
    v_processed INTEGER := 0;
    v_failed INTEGER := 0;
    v_log TEXT := '';
BEGIN
    FOR v_message IN 
        SELECT * FROM communication.message_queues
        WHERE status = 'QUEUED'
          AND (scheduled_for <= CURRENT_TIMESTAMP OR scheduled_for IS NULL)
          AND (expires_at IS NULL OR expires_at > CURRENT_TIMESTAMP)
        ORDER BY 
            CASE priority 
                WHEN 'CRITICAL' THEN 1
                WHEN 'URGENT' THEN 2
                WHEN 'HIGH' THEN 3
                WHEN 'MEDIUM' THEN 4
                WHEN 'LOW' THEN 5
            END,
            scheduled_for ASC
        LIMIT p_batch_size
        FOR UPDATE SKIP LOCKED
    LOOP
        BEGIN
            -- Update status to PROCESSING
            UPDATE communication.message_queues
            SET status = 'PROCESSING',
                processed_at = CURRENT_TIMESTAMP,
                updated_at = CURRENT_TIMESTAMP
            WHERE message_id = v_message.message_id;
            
            -- Process each channel
            FOREACH v_channel IN ARRAY v_message.channels
            LOOP
                INSERT INTO communication.message_delivery_log (
                    message_id, channel, attempt_number, 
                    attempted_at, channel_status
                ) VALUES (
                    v_message.message_id, v_channel, v_message.retry_count + 1,
                    CURRENT_TIMESTAMP, 'PENDING'
                );
                
                -- Actual delivery logic would go here
                -- This is where you'd integrate with email/SMS/push providers
            END LOOP;
            
            -- Mark as delivered (simplified - in reality would wait for callbacks)
            UPDATE communication.message_queues
            SET status = 'DELIVERED',
                delivered_at = CURRENT_TIMESTAMP,
                updated_at = CURRENT_TIMESTAMP
            WHERE message_id = v_message.message_id;
            
            v_processed := v_processed + 1;
            v_log := v_log || 'Processed message ' || v_message.message_id || E'\n';
            
        EXCEPTION WHEN OTHERS THEN
            -- Handle failure
            UPDATE communication.message_queues
            SET retry_count = retry_count + 1,
                last_attempt_at = CURRENT_TIMESTAMP,
                last_error = SQLERRM,
                status = CASE 
                    WHEN retry_count + 1 >= max_retries THEN 'FAILED'
                    ELSE 'QUEUED'
                END,
                updated_at = CURRENT_TIMESTAMP
            WHERE message_id = v_message.message_id;
            
            v_failed := v_failed + 1;
            v_log := v_log || 'Failed message ' || v_message.message_id || ': ' || SQLERRM || E'\n';
        END;
    END LOOP;
    
    RETURN QUERY SELECT v_processed, v_failed, v_log;
END;
$$ LANGUAGE plpgsql;

----####
-- Fix the cleanup_old_messages function (corrected LIMIT syntax)
CREATE OR REPLACE FUNCTION communication.cleanup_old_messages(
    p_days_old INTEGER DEFAULT 30,
    p_batch_size INTEGER DEFAULT 1000
)
RETURNS INTEGER AS $$
DECLARE
    v_deleted INTEGER;
BEGIN
    -- Use a subquery with LIMIT to control batch size
    DELETE FROM communication.message_queues
    WHERE message_id IN (
        SELECT message_id
        FROM communication.message_queues
        WHERE status IN ('DELIVERED', 'FAILED', 'CANCELLED', 'EXPIRED')
          AND created_at < CURRENT_DATE - (p_days_old || ' days')::INTERVAL
        LIMIT p_batch_size
    );
    
    GET DIAGNOSTICS v_deleted = ROW_COUNT;
    RETURN v_deleted;
END;
$$ LANGUAGE plpgsql;

-- Alternative simpler version if you don't need batch control
CREATE OR REPLACE FUNCTION communication.cleanup_old_messages_simple(
    p_days_old INTEGER DEFAULT 30
)
RETURNS INTEGER AS $$
DECLARE
    v_deleted INTEGER;
BEGIN
    -- Simple delete without LIMIT
    DELETE FROM communication.message_queues
    WHERE status IN ('DELIVERED', 'FAILED', 'CANCELLED', 'EXPIRED')
      AND created_at < CURRENT_DATE - (p_days_old || ' days')::INTERVAL;
    
    GET DIAGNOSTICS v_deleted = ROW_COUNT;
    RETURN v_deleted;
END;
$$ LANGUAGE plpgsql;

-- Alternative with CTE for better performance on large tables
CREATE OR REPLACE FUNCTION communication.cleanup_old_messages_optimized(
    p_days_old INTEGER DEFAULT 30,
    p_batch_size INTEGER DEFAULT 1000
)
RETURNS INTEGER AS $$
DECLARE
    v_deleted INTEGER;
BEGIN
    WITH deleted AS (
        DELETE FROM communication.message_queues
        WHERE message_id IN (
            SELECT message_id
            FROM communication.message_queues
            WHERE status IN ('DELIVERED', 'FAILED', 'CANCELLED', 'EXPIRED')
              AND created_at < CURRENT_DATE - (p_days_old || ' days')::INTERVAL
            LIMIT p_batch_size
        )
        RETURNING message_id
    )
    SELECT COUNT(*) INTO v_deleted FROM deleted;
    
    RETURN v_deleted;
END;
$$ LANGUAGE plpgsql;

-- Example of how to use the function:
-- SELECT communication.cleanup_old_messages(30, 1000); -- Deletes up to 1000 messages older than 30 days
-- SELECT communication.cleanup_old_messages_simple(30); -- Deletes all messages older than 30 days

-- Create view for message queue monitoring (FIXED: With proper syntax)
CREATE OR REPLACE VIEW communication.vw_message_queue_monitor AS
SELECT 
    status,
    COUNT(*) AS message_count,
    MIN(created_at) AS oldest_message,
    MAX(created_at) AS newest_message,
    COUNT(DISTINCT recipient_id) AS unique_recipients,
    COUNT(DISTINCT message_type) AS message_types,
    COUNT(*) FILTER (WHERE priority IN ('CRITICAL'::communication.message_priority_enum, 'URGENT'::communication.message_priority_enum)) AS urgent_messages,
    COUNT(*) FILTER (WHERE expires_at < CURRENT_TIMESTAMP) AS expired_messages,
    -- Add average age for queued messages
    AVG(EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - created_at))/3600) FILTER (WHERE status = 'QUEUED') AS avg_hours_queued,
    -- Add counts by priority
    COUNT(*) FILTER (WHERE priority = 'CRITICAL'::communication.message_priority_enum) AS critical_count,
    COUNT(*) FILTER (WHERE priority = 'HIGH'::communication.message_priority_enum) AS high_count,
    COUNT(*) FILTER (WHERE priority = 'MEDIUM'::communication.message_priority_enum) AS medium_count,
    COUNT(*) FILTER (WHERE priority = 'LOW'::communication.message_priority_enum) AS low_count
FROM communication.message_queues
GROUP BY status;

-- Create a separate view for detailed queue analysis
CREATE OR REPLACE VIEW communication.vw_queue_depth_analysis AS
WITH priority_stats AS (
    SELECT 
        priority,
        COUNT(*) AS total_count,
        COUNT(*) FILTER (WHERE status = 'QUEUED') AS queued_count,
        COUNT(*) FILTER (WHERE status = 'PROCESSING') AS processing_count,
        COUNT(*) FILTER (WHERE status = 'FAILED') AS failed_count,
        AVG(EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - created_at))/60) FILTER (WHERE status = 'QUEUED') AS avg_minutes_queued,
        MAX(EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - created_at))/60) FILTER (WHERE status = 'QUEUED') AS max_minutes_queued
    FROM communication.message_queues
    GROUP BY priority
)
SELECT 
    priority::TEXT,
    total_count,
    queued_count,
    processing_count,
    failed_count,
    ROUND(avg_minutes_queued::NUMERIC, 2) AS avg_minutes_queued,
    ROUND(max_minutes_queued::NUMERIC, 2) AS max_minutes_queued,
    CASE 
        WHEN queued_count > 0 AND avg_minutes_queued > 60 THEN 'CRITICAL'
        WHEN queued_count > 0 AND avg_minutes_queued > 30 THEN 'WARNING'
        WHEN queued_count > 0 THEN 'NORMAL'
        ELSE 'IDLE'
    END AS queue_health
FROM priority_stats
ORDER BY 
    CASE priority
        WHEN 'CRITICAL' THEN 1
        WHEN 'URGENT' THEN 2
        WHEN 'HIGH' THEN 3
        WHEN 'MEDIUM' THEN 4
        WHEN 'LOW' THEN 5
    END;

-- Create a view for channel effectiveness analysis
CREATE OR REPLACE VIEW communication.vw_channel_effectiveness AS
SELECT 
    dl.channel,
    dl.channel_status,
    COUNT(*) AS attempt_count,
    COUNT(DISTINCT dl.message_id) AS unique_messages,
    AVG(EXTRACT(EPOCH FROM (dl.completed_at - dl.attempted_at))/60) FILTER (WHERE dl.completed_at IS NOT NULL) AS avg_completion_minutes,
    COUNT(*) FILTER (WHERE dl.channel_status = 'FAILED') AS failed_count,
    COUNT(*) FILTER (WHERE dl.channel_status = 'BOUNCED') AS bounced_count,
    COUNT(*) FILTER (WHERE dl.channel_status = 'DELIVERED') AS delivered_count,
    COUNT(*) FILTER (WHERE dl.channel_status = 'READ') AS read_count,
    COUNT(*) FILTER (WHERE dl.channel_status = 'CLICKED') AS clicked_count,
    ROUND(100.0 * COUNT(*) FILTER (WHERE dl.channel_status = 'DELIVERED') / NULLIF(COUNT(*), 0), 2) AS delivery_rate,
    ROUND(100.0 * COUNT(*) FILTER (WHERE dl.channel_status = 'READ') / NULLIF(COUNT(*) FILTER (WHERE dl.channel_status = 'DELIVERED'), 0), 2) AS read_rate,
    ROUND(100.0 * COUNT(*) FILTER (WHERE dl.channel_status = 'CLICKED') / NULLIF(COUNT(*) FILTER (WHERE dl.channel_status = 'READ'), 0), 2) AS click_through_rate
FROM communication.message_delivery_log dl
WHERE dl.attempted_at > CURRENT_DATE - INTERVAL '30 days'
GROUP BY dl.channel, dl.channel_status;

-- -- Grant permissions on new views
-- GRANT SELECT ON communication.vw_message_queue_monitor TO monitoring_role;
-- GRANT SELECT ON communication.vw_queue_depth_analysis TO monitoring_role;
-- GRANT SELECT ON communication.vw_channel_effectiveness TO reporting_role;



-- Create a separate view for age metrics (where calculations are allowed)
CREATE OR REPLACE VIEW communication.vw_message_age_metrics AS
SELECT 
    message_id,
    status,
    priority,
    created_at,
    EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - created_at)) AS age_seconds,
    CASE 
        WHEN status = 'QUEUED' AND created_at < CURRENT_TIMESTAMP - INTERVAL '1 hour' THEN 'STALE'
        WHEN status = 'QUEUED' AND created_at < CURRENT_TIMESTAMP - INTERVAL '15 minutes' THEN 'AGING'
        ELSE 'NORMAL'
    END AS age_category
FROM communication.message_queues
WHERE status IN ('QUEUED', 'PROCESSING', 'FAILED');



-- Serial No: 48 | TABLE: communication.message_queues
-- Description: Queue for asynchronous message processing and delivery
-- Business Case: The message_queues table serves as the central message broker for
-- all asynchronous communication within the workforce scheduling system. It manages
-- the delivery of notifications, alerts, and other time-sensitive messages to
-- employees and managers through multiple channels (email, SMS, in-app). The table
-- supports priority-based message processing to ensure critical communications
-- are delivered promptly while less urgent messages are handled during off-peak
-- periods. Each message includes retry logic and delivery tracking to ensure
-- reliable communication even during system outages or external service failures.
-- The design accommodates multiple message templates and personalization variables
-- to support targeted, relevant communications. Comprehensive delivery statistics
-- are tracked to monitor channel effectiveness and identify delivery issues.
-- The queue supports both real-time and scheduled message delivery, enabling
-- time-zone aware notifications that reach recipients at appropriate times.
-- Message content is encrypted at rest to protect sensitive information, and
-- delivery logs are maintained for compliance and audit purposes. The table is
-- optimized for high-throughput processing during peak notification periods,
-- such as schedule publication or emergency alerts. By centralizing message
-- management, the system ensures consistent communication practices while
-- providing the flexibility needed for different communication scenarios.
-- KPI: Message delivery success rate, Delivery latency,
--      Channel effectiveness rate, Retry success rate,
--      Notification-related support requests
-- Feature Reference: 236, 237, 238, 239, 240
CREATE TABLE IF NOT EXISTS communication.message_queues (
    message_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    recipient_id UUID NOT NULL,
    sender_id UUID NOT NULL,
    message_type communication.notification_type_enum NOT NULL,
    subject VARCHAR(255) NOT NULL,
    body TEXT NOT NULL,
    channels communication.channel_type_enum[] NOT NULL DEFAULT '{EMAIL}'::communication.channel_type_enum[],
    priority INTEGER NOT NULL DEFAULT 5 CHECK (priority BETWEEN 1 AND 10),
    scheduled_for TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    processed_at TIMESTAMP WITH TIME ZONE,
    delivered_at TIMESTAMP WITH TIME ZONE,
    status VARCHAR(20) NOT NULL DEFAULT 'QUEUED'
        CHECK (status IN ('QUEUED', 'PROCESSING', 'DELIVERED', 'FAILED', 'CANCELLED')),
    retry_count INTEGER NOT NULL DEFAULT 0,
    max_retries INTEGER NOT NULL DEFAULT 3,
    last_error TEXT,
    delivery_metadata JSONB,
    template_id UUID REFERENCES communication.message_templates(template_id),
    variables JSONB,
    is_encrypted BOOLEAN NOT NULL DEFAULT TRUE,
    encryption_key_id UUID,
    expiration TIMESTAMP WITH TIME ZONE,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_message_queues_recipient ON communication.message_queues(recipient_id);
CREATE INDEX IF NOT EXISTS idx_message_queues_sender ON communication.message_queues(sender_id);
CREATE INDEX IF NOT EXISTS idx_message_queues_type ON communication.message_queues(message_type);
CREATE INDEX IF NOT EXISTS idx_message_queues_status ON communication.message_queues(status);
CREATE INDEX IF NOT EXISTS idx_message_queues_scheduled ON communication.message_queues(scheduled_for)
    WHERE status = 'QUEUED';
CREATE INDEX IF NOT EXISTS idx_message_queues_priority ON communication.message_queues(priority DESC);
CREATE INDEX IF NOT EXISTS idx_message_queues_template ON communication.message_queues(template_id)
    WHERE template_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_message_queues_channels ON communication.message_queues USING GIN(channels);

-- Add triggers for audit columns
CREATE TRIGGER trg_message_queues_updated_at
BEFORE UPDATE ON communication.message_queues
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();



-- Serial No: 49 | PROCEDURE: communication.process_message_queue
-- Purpose: Process messages in the communication queue for delivery
-- Business Case: This procedure implements the message processing engine that delivers
-- communications to employees and managers through various channels. It processes
-- messages in priority order, ensuring critical notifications like schedule changes
-- and compliance alerts are delivered promptly. The procedure handles channel-specific
-- delivery requirements, including email formatting, SMS character limits, and
-- in-app notification rendering. It implements sophisticated retry logic for failed
-- deliveries, with escalating retry intervals and fallback channels when primary
-- methods fail. Comprehensive delivery tracking captures success/failure status,
-- delivery timestamps, and channel-specific metadata for analytics and troubleshooting.
-- The procedure includes rate limiting to prevent overwhelming external services
-- and to comply with service provider restrictions. It also enforces message content
-- policies to prevent spam and ensure compliance with communication regulations.
-- For time-sensitive messages, the procedure considers recipient time zones to
-- deliver notifications at appropriate times. The implementation processes messages
-- in batches to optimize throughput while minimizing resource consumption. It
-- includes detailed error handling to ensure partial failures don't prevent
-- processing of other messages in the queue. By centralizing message delivery
-- logic, the procedure ensures consistent communication practices across all
-- notification types while providing the flexibility needed for different
-- communication scenarios.
-- KPI: Message delivery success rate, Average delivery latency,
--      Channel utilization rate, Retry success rate,
--      Message processing throughput
-- Feature Reference: 241, 242, 243, 244, 245
CREATE OR REPLACE PROCEDURE communication.process_message_queue(
    p_batch_size INTEGER DEFAULT 100,
    p_max_retries INTEGER DEFAULT 3
)
LANGUAGE plpgsql
AS $$
DECLARE
    v_message RECORD;
    v_delivery_status VARCHAR(20);
    v_error_message TEXT;
    v_channels communication.channel_type_enum[];
    v_channel communication.channel_type_enum;
    v_processed_count INTEGER := 0;
    v_success_count INTEGER := 0;
    v_failure_count INTEGER := 0;
BEGIN
    -- Log the start of queue processing
    PERFORM system.log_activity(
        'MESSAGE_QUEUE_PROCESSING_START',
        'Starting message queue processing',
        NULL,
        'INFO',
        'communication.process_message_queue',
        jsonb_build_object('batch_size', p_batch_size)
    );

    -- Process messages in priority order
    FOR v_message IN
        SELECT *
        FROM communication.message_queues
        WHERE status = 'QUEUED'
        AND scheduled_for <= CURRENT_TIMESTAMP
        AND (expiration IS NULL OR expiration > CURRENT_TIMESTAMP)
        ORDER BY priority DESC, created_at ASC
        LIMIT p_batch_size
        FOR UPDATE SKIP LOCKED
    LOOP
        BEGIN
            v_processed_count := v_processed_count + 1;
            v_channels := v_message.channels;

            -- Try each channel until successful delivery
            FOREACH v_channel IN ARRAY v_channels
            LOOP
                BEGIN
                    CASE v_channel
                        WHEN 'EMAIL' THEN
                            PERFORM communication.send_email(
                                v_message.recipient_id,
                                v_message.subject,
                                v_message.body
                            );
                        WHEN 'SMS' THEN
                            PERFORM communication.send_sms(
                                v_message.recipient_id,
                                v_message.subject || ': ' || v_message.body
                            );
                        WHEN 'IN_APP' THEN
                            PERFORM communication.send_in_app_notification(
                                v_message.recipient_id,
                                v_message.subject,
                                v_message.body,
                                v_message.message_type::VARCHAR
                            );
                        ELSE
                            RAISE EXCEPTION 'Unsupported channel: %', v_channel;
                    END CASE;

                    -- Update message status on successful delivery
                    UPDATE communication.message_queues
                    SET
                        status = 'DELIVERED',
                        delivered_at = CURRENT_TIMESTAMP,
                        delivery_metadata = jsonb_build_object(
                            'channel', v_channel,
                            'delivered_at', to_jsonb(CURRENT_TIMESTAMP)
                        ) || COALESCE(delivery_metadata, '{}'::JSONB),
                        updated_at = CURRENT_TIMESTAMP
                    WHERE message_id = v_message.message_id;

                    v_success_count := v_success_count + 1;
                    EXIT; -- Exit the channel loop on success

                EXCEPTION WHEN OTHERS THEN
                    GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;

                    -- Log delivery failure for this channel
                    PERFORM system.log_error(
                        'MESSAGE_DELIVERY_FAILURE',
                        v_error_message,
                        SQLSTATE,
                        v_message.sender_id,
                        'WARNING',
                        'communication.process_message_queue',
                        jsonb_build_object(
                            'message_id', v_message.message_id,
                            'channel', v_channel,
                            'recipient_id', v_message.recipient_id
                        )
                    );

                    -- Continue to next channel
                    CONTINUE;
                END;
            END LOOP;

            -- If all channels failed, handle retries
            IF NOT FOUND THEN
                IF v_message.retry_count < p_max_retries THEN
                    UPDATE communication.message_queues
                    SET
                        status = 'QUEUED',
                        retry_count = retry_count + 1,
                        scheduled_for = CURRENT_TIMESTAMP + (retry_count * INTERVAL '5 minutes'),
                        last_error = v_error_message,
                        updated_at = CURRENT_TIMESTAMP
                    WHERE message_id = v_message.message_id;
                ELSE
                    UPDATE communication.message_queues
                    SET
                        status = 'FAILED',
                        updated_at = CURRENT_TIMESTAMP
                    WHERE message_id = v_message.message_id;

                    v_failure_count := v_failure_count + 1;
                END IF;
            END IF;

        EXCEPTION WHEN OTHERS THEN
            -- Log unexpected processing error
            GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;

            PERFORM system.log_error(
                'MESSAGE_PROCESSING_ERROR',
                v_error_message,
                SQLSTATE,
                v_message.sender_id,
                'ERROR',
                'communication.process_message_queue',
                jsonb_build_object(
                    'message_id', v_message.message_id,
                    'recipient_id', v_message.recipient_id
                )
            );

            -- Mark message as failed to prevent infinite retries
            UPDATE communication.message_queues
            SET
                status = 'FAILED',
                last_error = 'Processing error: ' || v_error_message,
                updated_at = CURRENT_TIMESTAMP
            WHERE message_id = v_message.message_id;

            v_failure_count := v_failure_count + 1;
        END;
    END LOOP;

    -- Log completion of queue processing
    PERFORM system.log_activity(
        'MESSAGE_QUEUE_PROCESSING_COMPLETE',
        'Message queue processing completed',
        NULL,
        'INFO',
        'communication.process_message_queue',
        jsonb_build_object(
            'processed_count', v_processed_count,
            'success_count', v_success_count,
            'failure_count', v_failure_count
        )
    );

EXCEPTION WHEN OTHERS THEN
    -- Log critical error
    GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;

    PERFORM system.log_error(
        'MESSAGE_QUEUE_PROCESSING_ERROR',
        v_error_message,
        SQLSTATE,
        NULL,
        'CRITICAL',
        'communication.process_message_queue',
        jsonb_build_object('error_time', NOW())
    );
    RAISE;
END;
$$;

COMMENT ON PROCEDURE communication.process_message_queue IS 'Process messages in the communication queue for delivery.
Implements message processing engine that delivers communications to employees and managers through various channels. Processes
messages in priority order to ensure critical notifications are delivered promptly. Handles channel-specific delivery requirements.
Implements sophisticated retry logic with escalating retry intervals and fallback channels. Captures comprehensive delivery
tracking for analytics and troubleshooting. Includes rate limiting to prevent overwhelming external services. Enforces message
content policies to prevent spam. Considers recipient time zones for appropriate delivery timing. Processes messages in batches
to optimize throughput. Includes detailed error handling to ensure partial failures don''t prevent processing of other messages.
Centralizes message delivery logic for consistent communication practices.';


