-- Feature Reference: 276, 277, 278, 279, 280

-- OPTION 1: Drop and recreate the table (WARNING: This will delete all existing data)

-- DROP TABLE IF EXISTS communication.message_templates CASCADE;

CREATE TABLE IF NOT EXISTS communication.message_templates (
    template_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    template_code VARCHAR(50) UNIQUE NOT NULL CHECK (template_code ~ '^[A-Z0-9_]{3,50}$'),
    name VARCHAR(100) NOT NULL,
