    subject_template VARCHAR(255) NOT NULL,
    body_template TEXT NOT NULL,
    
    -- Channel configuration (fixed: using channel_type_enum instead of message_type)
    channel_type communication.channel_type_enum NOT NULL,
    
    -- Variable definitions
    variables JSONB DEFAULT '[]'::JSONB,
    
    -- Status and flags
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_system_template BOOLEAN NOT NULL DEFAULT FALSE,
    
    -- Version control
    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
    
    -- Approval workflow
    approval_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
        CHECK (approval_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'REJECTED')),
    approved_by UUID REFERENCES hr.employees(employee_id),
    approved_at TIMESTAMP WITH TIME ZONE,
    approval_notes TEXT,
    
    -- Localization
    localization_settings JSONB DEFAULT '{}'::JSONB,
    supported_languages TEXT[] DEFAULT '{en}'::TEXT[],
    
    -- Usage tracking
    usage_count INTEGER DEFAULT 0,
    last_used_at TIMESTAMP WITH TIME ZONE,
    last_used_by UUID REFERENCES hr.employees(employee_id),
    
    -- Business context
    context_type VARCHAR(50), -- e.g., 'SCHEDULE', 'SHIFT', 'LEAVE', 'COMPLIANCE'
    department_id UUID REFERENCES hr.departments(department_id),
    
    -- Metadata
    metadata JSONB DEFAULT '{}'::JSONB,
    tags TEXT[] DEFAULT '{}',
    
    -- Standard audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    updated_by UUID REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    CONSTRAINT chk_template_version CHECK (version_number ~ '^\d+\.\d+$')
);


-- OPTION 2: Alter existing table to add missing columns (preserves data)
DO $$
BEGIN
    -- Check if the table exists
    IF EXISTS (
        SELECT 1 
        FROM information_schema.tables 
        WHERE table_schema = 'communication' 
        AND table_name = 'message_templates'
    ) THEN
        -- Add channel_type column if it doesn't exist (using the enum)
        IF NOT EXISTS (
            SELECT 1 
            FROM information_schema.columns 
            WHERE table_schema = 'communication' 
              AND table_name = 'message_templates' 
              AND column_name = 'channel_type'
        ) THEN
            ALTER TABLE communication.message_templates 
            ADD COLUMN channel_type communication.channel_type_enum NOT NULL DEFAULT 'EMAIL';
            
            RAISE NOTICE 'Added channel_type column to message_templates';
        END IF;
        
        -- Add approval_notes column if it doesn't exist
        IF NOT EXISTS (
            SELECT 1 
            FROM information_schema.columns 
            WHERE table_schema = 'communication' 
              AND table_name = 'message_templates' 
              AND column_name = 'approval_notes'
        ) THEN
            ALTER TABLE communication.message_templates 
            ADD COLUMN approval_notes TEXT;
            
            RAISE NOTICE 'Added approval_notes column to message_templates';
        END IF;
        
        -- Add supported_languages column if it doesn't exist
        IF NOT EXISTS (
            SELECT 1 
            FROM information_schema.columns 
            WHERE table_schema = 'communication' 
              AND table_name = 'message_templates' 
              AND column_name = 'supported_languages'
        ) THEN
            ALTER TABLE communication.message_templates 
            ADD COLUMN supported_languages TEXT[] DEFAULT '{en}'::TEXT[];
            
            RAISE NOTICE 'Added supported_languages column to message_templates';
        END IF;
        
        -- Add last_used_by column if it doesn't exist
        IF NOT EXISTS (
            SELECT 1 
            FROM information_schema.columns 
            WHERE table_schema = 'communication' 
              AND table_name = 'message_templates' 
              AND column_name = 'last_used_by'
        ) THEN
            ALTER TABLE communication.message_templates 
            ADD COLUMN last_used_by UUID REFERENCES hr.employees(employee_id);
            
            RAISE NOTICE 'Added last_used_by column to message_templates';
        END IF;
        
        -- Add context_type column if it doesn't exist
        IF NOT EXISTS (
            SELECT 1 
            FROM information_schema.columns 
            WHERE table_schema = 'communication' 
              AND table_name = 'message_templates' 
              AND column_name = 'context_type'
        ) THEN
            ALTER TABLE communication.message_templates 
            ADD COLUMN context_type VARCHAR(50);
            
            RAISE NOTICE 'Added context_type column to message_templates';
        END IF;
        
        -- Add department_id column if it doesn't exist
        IF NOT EXISTS (
            SELECT 1 
            FROM information_schema.columns 
            WHERE table_schema = 'communication' 
              AND table_name = 'message_templates' 
              AND column_name = 'department_id'
        ) THEN
            ALTER TABLE communication.message_templates 
            ADD COLUMN department_id UUID REFERENCES hr.departments(department_id);
            
            RAISE NOTICE 'Added department_id column to message_templates';
        END IF;
        
        -- Add metadata column if it doesn't exist
        IF NOT EXISTS (
            SELECT 1 
            FROM information_schema.columns 
            WHERE table_schema = 'communication' 
              AND table_name = 'message_templates' 
              AND column_name = 'metadata'
        ) THEN
            ALTER TABLE communication.message_templates 
            ADD COLUMN metadata JSONB DEFAULT '{}'::JSONB;
            
            RAISE NOTICE 'Added metadata column to message_templates';
        END IF;
        
        -- Add tags column if it doesn't exist
        IF NOT EXISTS (
            SELECT 1 
            FROM information_schema.columns 
            WHERE table_schema = 'communication' 
              AND table_name = 'message_templates' 
              AND column_name = 'tags'
        ) THEN
            ALTER TABLE communication.message_templates 
            ADD COLUMN tags TEXT[] DEFAULT '{}';
            
            RAISE NOTICE 'Added tags column to message_templates';
        END IF;
        
        RAISE NOTICE 'Table communication.message_templates updated successfully';
    ELSE
        -- Create the table if it doesn't exist
        CREATE TABLE IF NOT EXISTS communication.message_templates (
            template_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
            template_code VARCHAR(50) UNIQUE NOT NULL CHECK (template_code ~ '^[A-Z0-9_]{3,50}$'),
            name VARCHAR(100) NOT NULL,
            description TEXT,
            
            -- Template content
            subject_template VARCHAR(255) NOT NULL,
            body_template TEXT NOT NULL,
            
            -- Channel configuration
            channel_type communication.channel_type_enum NOT NULL DEFAULT 'EMAIL',
            
            -- Variable definitions
            variables JSONB DEFAULT '[]'::JSONB,
            
            -- Status and flags
            is_active BOOLEAN NOT NULL DEFAULT TRUE,
            is_system_template BOOLEAN NOT NULL DEFAULT FALSE,
            
            -- Version control
            version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
            
            -- Approval workflow
            approval_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
                CHECK (approval_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'REJECTED')),
            approved_by UUID REFERENCES hr.employees(employee_id),
            approved_at TIMESTAMP WITH TIME ZONE,
            approval_notes TEXT,
            
            -- Localization
            localization_settings JSONB DEFAULT '{}'::JSONB,
            supported_languages TEXT[] DEFAULT '{en}'::TEXT[],
            
            -- Usage tracking
            usage_count INTEGER DEFAULT 0,
            last_used_at TIMESTAMP WITH TIME ZONE,
            last_used_by UUID REFERENCES hr.employees(employee_id),
            
            -- Business context
            context_type VARCHAR(50),
            department_id UUID REFERENCES hr.departments(department_id),
            
            -- Metadata
            metadata JSONB DEFAULT '{}'::JSONB,
            tags TEXT[] DEFAULT '{}',
            
            -- Standard audit columns
            created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
            updated_by UUID REFERENCES hr.employees(employee_id),
            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            
            CONSTRAINT chk_template_version CHECK (version_number ~ '^\d+\.\d+$')
        );
        
        RAISE NOTICE 'Created new table communication.message_templates';
    END IF;
END $$;

-- Add indexes for performance (with existence checks)
DO $$
BEGIN
    -- Index on is_active
    IF NOT EXISTS (
        SELECT 1 
        FROM pg_indexes 
        WHERE schemaname = 'communication' 
          AND tablename = 'message_templates' 
          AND indexname = 'idx_message_templates_active'
    ) THEN
        CREATE INDEX idx_message_templates_active ON communication.message_templates(is_active) WHERE is_active = TRUE;
    END IF;
    
    -- Index on channel_type
    IF NOT EXISTS (
        SELECT 1 
        FROM pg_indexes 
        WHERE schemaname = 'communication' 
          AND tablename = 'message_templates' 
          AND indexname = 'idx_message_templates_channel'
    ) THEN
        CREATE INDEX idx_message_templates_channel ON communication.message_templates(channel_type);
    END IF;
    
    -- Index on is_system_template
    IF NOT EXISTS (
        SELECT 1 
        FROM pg_indexes 
        WHERE schemaname = 'communication' 
          AND tablename = 'message_templates' 
          AND indexname = 'idx_message_templates_system'
    ) THEN
        CREATE INDEX idx_message_templates_system ON communication.message_templates(is_system_template);
    END IF;
    
    -- Index on approval_status
    IF NOT EXISTS (
        SELECT 1 
        FROM pg_indexes 
        WHERE schemaname = 'communication' 
          AND tablename = 'message_templates' 
          AND indexname = 'idx_message_templates_approval'
    ) THEN
        CREATE INDEX idx_message_templates_approval ON communication.message_templates(approval_status);
    END IF;
    
    -- Index on approved_by
    IF NOT EXISTS (
        SELECT 1 
        FROM pg_indexes 
        WHERE schemaname = 'communication' 
          AND tablename = 'message_templates' 
          AND indexname = 'idx_message_templates_approved'
    ) THEN
        CREATE INDEX idx_message_templates_approved ON communication.message_templates(approved_by)
            WHERE approved_by IS NOT NULL;
    END IF;
    
    -- GIN index on variables
    IF NOT EXISTS (
        SELECT 1 
        FROM pg_indexes 
        WHERE schemaname = 'communication' 
          AND tablename = 'message_templates' 
          AND indexname = 'idx_message_templates_variables'
    ) THEN
        CREATE INDEX idx_message_templates_variables ON communication.message_templates USING GIN(variables);
    END IF;
    
    -- GIN index on tags
    IF NOT EXISTS (
        SELECT 1 
        FROM pg_indexes 
        WHERE schemaname = 'communication' 
          AND tablename = 'message_templates' 
          AND indexname = 'idx_message_templates_tags'
    ) THEN
        CREATE INDEX idx_message_templates_tags ON communication.message_templates USING GIN(tags);
    END IF;
    
    -- Index on context_type
    IF NOT EXISTS (
        SELECT 1 
        FROM pg_indexes 
        WHERE schemaname = 'communication' 
          AND tablename = 'message_templates' 
          AND indexname = 'idx_message_templates_context'
    ) THEN
        CREATE INDEX idx_message_templates_context ON communication.message_templates(context_type)
            WHERE context_type IS NOT NULL;
    END IF;
    
    -- Index on department_id
    IF NOT EXISTS (
        SELECT 1 
        FROM pg_indexes 
        WHERE schemaname = 'communication' 
          AND tablename = 'message_templates' 
          AND indexname = 'idx_message_templates_department'
    ) THEN
        CREATE INDEX idx_message_templates_department ON communication.message_templates(department_id)
            WHERE department_id IS NOT NULL;
    END IF;
END $$;


-- Create a view for template usage analytics
CREATE OR REPLACE VIEW communication.vw_template_analytics AS
SELECT 
    mt.template_id,
    mt.template_code,
    mt.name,
    mt.channel_type,
    mt.is_active,
    mt.approval_status,
    mt.version_number,
    mt.usage_count,
    mt.last_used_at,
    COUNT(DISTINCT mq.message_id) AS total_messages_sent,
    COUNT(DISTINCT CASE WHEN mq.status = 'DELIVERED' THEN mq.message_id END) AS delivered_messages,
    COUNT(DISTINCT CASE WHEN mq.status = 'FAILED' THEN mq.message_id END) AS failed_messages,
    ROUND(100.0 * COUNT(DISTINCT CASE WHEN mq.status = 'DELIVERED' THEN mq.message_id END) / 
          NULLIF(COUNT(DISTINCT mq.message_id), 0), 2) AS delivery_rate,
    AVG(EXTRACT(EPOCH FROM (mq.delivered_at - mq.created_at))/60) FILTER (WHERE mq.delivered_at IS NOT NULL) AS avg_delivery_minutes
FROM communication.message_templates mt
LEFT JOIN communication.message_queues mq ON mt.template_id = mq.template_id
WHERE mq.created_at > CURRENT_DATE - INTERVAL '90 days' OR mq.created_at IS NULL
GROUP BY mt.template_id, mt.template_code, mt.name, mt.channel_type, 
         mt.is_active, mt.approval_status, mt.version_number, 
         mt.usage_count, mt.last_used_at;

COMMENT ON TABLE communication.message_templates IS 'Templates for standardized communication content.
Stores predefined message templates for consistent communication across the workforce scheduling system. Enables creation of
standardized notifications that maintain brand consistency and regulatory compliance. Includes placeholders for dynamic content
personalization. Supports multiple communication channels with channel-specific formatting. Templates undergo formal review and
approval workflows. Versioning allows tracking changes over time. Includes localization capabilities for multilingual communications.
Template usage analytics track effectiveness for continuous improvement. Enforces content policies to prevent inappropriate messaging.
Reduces time and effort required to create new communications while ensuring consistency. Accommodates organizational hierarchy
requirements for different templates by role and business unit.';

