    -- Serial No: 53 | TABLE: system.error_logs
    -- Description: Centralized error logging for system diagnostics and troubleshooting
    -- Business Case: The error_logs table serves as the central repository for all system errors
    -- and exceptions, providing comprehensive visibility into system health and stability. It
    -- captures detailed information about each error including the error code, message, stack
    -- trace, and contextual information about the operation that failed. This information is
    -- critical for diagnosing and resolving issues, particularly in complex distributed systems
    -- where errors may span multiple components. The table supports error categorization by
    -- severity, type, and source system, enabling prioritization of remediation efforts based
    -- on business impact. Historical error data is used to identify recurring issues and
    -- implement preventive measures. The implementation includes mechanisms for error
    -- deduplication to avoid alert fatigue from repeated occurrences of the same issue.
    -- Comprehensive context tracking helps identify patterns and correlations between seemingly
    -- unrelated errors. The table also supports integration with monitoring and alerting systems
    -- to trigger appropriate notifications based on error severity and frequency. By centralizing
    -- error logging, the system reduces mean time to resolution (MTTR) for issues and enables
    -- proactive identification of potential system failures before they impact users. The design
    -- accommodates high-volume error logging during peak periods while maintaining performance
    -- for operational systems. The table is optimized for rapid querying during incident response
    -- and root cause analysis, with appropriate indexing on error characteristics and timestamps.
    -- KPI: Error resolution time, Recurring error rate,
    --      System uptime, Mean time between failures (MTBF),
    --      Alert accuracy rate
    -- Feature Reference: 281, 282, 283, 284, 285
    CREATE TABLE IF NOT EXISTS system.error_logs (
        log_id BIGSERIAL PRIMARY KEY,
        error_code VARCHAR(50) NOT NULL,
        error_type VARCHAR(100) NOT NULL CHECK (error_type IN ('APPLICATION', 'DATABASE', 'NETWORK', 'AUTHENTICATION',
            'AUTHORIZATION', 'VALIDATION', 'INTEGRATION', 'SYSTEM', 'UNKNOWN')),
        error_category VARCHAR(100) NOT NULL CHECK (error_category IN ('CRITICAL', 'HIGH', 'MEDIUM', 'LOW', 'INFORMATIONAL')),
        error_message TEXT NOT NULL,
        error_details JSONB,
        stack_trace TEXT,
        inner_error TEXT,
        context_info JSONB,
        user_id UUID,
        ip_address INET,
        component VARCHAR(100) NOT NULL,
        occurred_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        resolved_at TIMESTAMP WITH TIME ZONE,
        resolution_notes TEXT,
        resolution_steps JSONB,
        is_resolved BOOLEAN NOT NULL DEFAULT FALSE,
        duplicate_count INTEGER NOT NULL DEFAULT 1 CHECK (duplicate_count >= 1),
        first_occurrence TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        last_occurrence TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        associated_alert_id UUID,
        created_by UUID NOT NULL,
        updated_by UUID,
        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

    -- Add indexes for performance
    CREATE INDEX IF NOT EXISTS idx_error_logs_code ON system.error_logs(error_code);
    CREATE INDEX IF NOT EXISTS idx_error_logs_type ON system.error_logs(error_type);
    CREATE INDEX IF NOT EXISTS idx_error_logs_category ON system.error_logs(error_category);
    CREATE INDEX IF NOT EXISTS idx_error_logs_occurred ON system.error_logs(occurred_at DESC);
    CREATE INDEX IF NOT EXISTS idx_error_logs_resolved ON system.error_logs(is_resolved) WHERE is_resolved = FALSE;
    CREATE INDEX IF NOT EXISTS idx_error_logs_component ON system.error_logs(component);
    CREATE INDEX IF NOT EXISTS idx_error_logs_user ON system.error_logs(user_id) WHERE user_id IS NOT NULL;
    CREATE INDEX IF NOT EXISTS idx_error_logs_details ON system.error_logs USING GIN(error_details);
    CREATE INDEX IF NOT EXISTS idx_error_logs_context ON system.error_logs USING GIN(context_info);

    -- Add triggers for audit columns
    CREATE TRIGGER trg_error_logs_updated_at
    BEFORE UPDATE ON system.error_logs
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

    COMMENT ON TABLE system.error_logs IS 'Centralized error logging for system diagnostics and troubleshooting.
    Serves as central repository for all system errors and exceptions, providing comprehensive visibility into system health.
    Captures detailed information about each error including error code, message, stack trace, and contextual information.
    Critical for diagnosing and resolving issues in complex distributed systems. Supports error categorization by severity,
    type, and source system for prioritization of remediation efforts. Historical error data used to identify recurring issues.
    Includes mechanisms for error deduplication to avoid alert fatigue. Comprehensive context tracking helps identify patterns
    and correlations. Supports integration with monitoring and alerting systems. Reduces mean time to resolution (MTTR) for
    issues. Enables proactive identification of potential system failures. Accommodates high-volume error logging while
    maintaining performance. Optimized for rapid querying during incident response and root cause analysis.';

    -- Serial No: 54 | TABLE: security.access_tokens
    -- Description: Secure token management for authentication and authorization
    -- Business Case: The access_tokens table manages all authentication tokens used for system access,
    -- providing secure session management and API authentication. It stores tokens using cryptographic
    -- hashing to protect against token leakage and unauthorized access. Each token record includes
    -- metadata about its scope, permissions, and expiration to enforce proper access controls. The
    -- table supports multiple token types including session tokens, API keys, and refresh tokens,
    -- each with appropriate security characteristics. Comprehensive audit logging tracks token
    -- creation, usage, and revocation to support security investigations and compliance reporting.
    -- The implementation includes mechanisms for token revocation and rotation to enhance security
    -- posture and respond to potential breaches. Token usage patterns are monitored to detect
    -- anomalous behavior that may indicate compromised accounts. The design accommodates high-volume
    -- token operations while maintaining performance for authentication-critical paths. For sensitive
    -- operations, the system supports short-lived tokens with limited scope to minimize potential
    -- damage from token compromise. The table also tracks client information to support device-based
    -- authentication policies and to provide context for security alerts. By centralizing token
    -- management, the system ensures consistent security practices across all authentication
    -- mechanisms while providing the flexibility needed for different integration scenarios. The
    -- table is optimized for rapid lookup during authentication operations, which are critical
    -- for system performance and user experience.
    -- KPI: Token security compliance rate, Unauthorized access attempts,
    --      Token leakage incidents, Authentication success rate,
    --      Session management efficiency
    -- Feature Reference: 286, 287, 288, 289, 290
    CREATE TABLE IF NOT EXISTS security.access_tokens (
        token_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
        user_id UUID NOT NULL REFERENCES hr.employees(employee_id) ON DELETE CASCADE,
        token_type VARCHAR(50) NOT NULL CHECK (token_type IN ('BEARER', 'JWT', 'API_KEY', 'REFRESH', 'SESSION', 'IMPERSONATION')),
        token_hash TEXT NOT NULL,
        token_identifier VARCHAR(255) UNIQUE,
        scopes TEXT[] NOT NULL DEFAULT '{}',
        permissions JSONB DEFAULT '{}'::JSONB,
        client_id VARCHAR(100),
        client_ip INET,
        client_user_agent TEXT,
        issued_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        expires_at TIMESTAMP WITH TIME ZONE NOT NULL,
        revoked_at TIMESTAMP WITH TIME ZONE,
        revocation_reason VARCHAR(100),
        last_used_at TIMESTAMP WITH TIME ZONE,
        usage_count INTEGER NOT NULL DEFAULT 0 CHECK (usage_count >= 0),
        is_revoked BOOLEAN NOT NULL DEFAULT FALSE,
        created_by UUID NOT NULL,
        updated_by UUID,
        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

    -- Add indexes for performance
    CREATE INDEX IF NOT EXISTS idx_access_tokens_user ON security.access_tokens(user_id);
    CREATE INDEX IF NOT EXISTS idx_access_tokens_type ON security.access_tokens(token_type);
    CREATE INDEX IF NOT EXISTS idx_access_tokens_expires ON security.access_tokens(expires_at)
        WHERE is_revoked = FALSE;
    CREATE INDEX IF NOT EXISTS idx_access_tokens_revoked ON security.access_tokens(is_revoked)
        WHERE is_revoked = TRUE;
    CREATE INDEX IF NOT EXISTS idx_access_tokens_client ON security.access_tokens(client_id);
    CREATE INDEX IF NOT EXISTS idx_access_tokens_identifier ON security.access_tokens(token_identifier)
        WHERE token_identifier IS NOT NULL;
    CREATE INDEX IF NOT EXISTS idx_access_tokens_scopes ON security.access_tokens USING GIN(scopes);
    CREATE INDEX IF NOT EXISTS idx_access_tokens_permissions ON security.access_tokens USING GIN(permissions);

    -- Add triggers for audit columns
    CREATE TRIGGER trg_access_tokens_updated_at
    BEFORE UPDATE ON security.access_tokens
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

    COMMENT ON TABLE security.access_tokens IS 'Secure token management for authentication and authorization.
    Manages all authentication tokens used for system access, providing secure session management and API authentication.
    Stores tokens using cryptographic hashing to protect against token leakage. Includes metadata about scope, permissions,
    and expiration to enforce access controls. Supports multiple token types with appropriate security characteristics.
    Comprehensive audit logging tracks token creation, usage, and revocation. Includes mechanisms for token revocation
    and rotation. Token usage patterns monitored to detect anomalous behavior. Accommodates high-volume token operations
    while maintaining performance. Supports short-lived tokens with limited scope for sensitive operations. Tracks client
    information for device-based authentication policies. Centralizes token management for consistent security practices.
    Optimized for rapid lookup during authentication operations.';



-- Serial No: 54 | TABLE: reporting.report_configurations
-- Description: Configuration and template definitions for all system reports
-- Business Case: The report_configurations table serves as the central repository for all report definitions
-- within the workforce scheduling system. It stores report templates, parameters, and formatting rules that
-- determine how data is presented to users across different modules. This table enables consistent report
-- generation across the application while allowing for customization based on user roles and requirements.
-- It supports multiple report types including operational reports for daily management, analytical reports
-- for trend analysis, and compliance reports for regulatory requirements. The configuration includes
-- security settings to ensure that reports only display data users are authorized to see, maintaining
-- data governance throughout the reporting process. Performance optimization settings allow for efficient
-- generation of large reports through configurable batch sizes and query optimization hints. The table
-- also tracks report usage statistics to identify popular reports and optimize system resources accordingly.
-- By centralizing report configurations, the system enables rapid development of new reports and consistent
-- modification of existing ones without code changes. The design accommodates multi-language support for
-- reports used in global organizations and different output formats (PDF, Excel, CSV, HTML) to meet
-- diverse user needs. Version tracking ensures that report changes are properly managed and can be
-- rolled back if necessary. This table is fundamental to the system's reporting capabilities, providing
-- the flexibility and control needed for comprehensive workforce analytics.
-- KPI: Report usage frequency, Report generation time,
--      Report configuration coverage, User satisfaction with reports,
--      Report maintenance efficiency
-- Feature Reference: 286, 287, 288, 289, 290
CREATE TABLE IF NOT EXISTS reporting.report_configurations (
    -- Primary identifiers
    report_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    report_code VARCHAR(50) UNIQUE NOT NULL CHECK (report_code ~ '^[A-Z0-9_]{3,50}$'),
    
    -- Basic information
    report_name VARCHAR(200) NOT NULL,
    report_description TEXT,
    report_category VARCHAR(50) NOT NULL 
        CHECK (report_category IN ('OPERATIONAL', 'ANALYTICAL', 'COMPLIANCE', 'EXECUTIVE', 'CUSTOM')),
    report_type VARCHAR(50) NOT NULL
        CHECK (report_type IN ('SCHEDULING', 'ATTENDANCE', 'COMPLIANCE', 'LABOR_COST', 'FORECAST', 'PERFORMANCE', 'CUSTOM')),
    
    -- Report source
    source_type VARCHAR(20) NOT NULL DEFAULT 'SQL'
        CHECK (source_type IN ('SQL', 'VIEW', 'FUNCTION', 'API', 'FILE')),
    source_definition TEXT NOT NULL, -- SQL query, view name, function call, etc.
    source_parameters JSONB DEFAULT '[]'::JSONB, -- Expected parameters
    
    -- Report structure
    columns_definition JSONB NOT NULL DEFAULT '[]'::JSONB, -- Column definitions with formatting
    grouping_config JSONB, -- Grouping and aggregation settings
    sorting_config JSONB, -- Default sorting
    filtering_config JSONB, -- Available filters
    
    -- Output formatting
    default_format VARCHAR(10) NOT NULL DEFAULT 'PDF'
        CHECK (default_format IN ('PDF', 'EXCEL', 'CSV', 'HTML', 'JSON', 'XML')),
    available_formats TEXT[] DEFAULT '{PDF,EXCEL,CSV}',
    page_orientation VARCHAR(10) DEFAULT 'PORTRAIT'
        CHECK (page_orientation IN ('PORTRAIT', 'LANDSCAPE')),
    page_size VARCHAR(20) DEFAULT 'A4',
    include_totals BOOLEAN DEFAULT TRUE,
    include_charts BOOLEAN DEFAULT FALSE,
    chart_config JSONB, -- Configuration for charts if include_charts = TRUE
    
    -- Template and styling
    template_id UUID, -- Reference to a template (can be self-referential or external)
    header_template TEXT,
    footer_template TEXT,
    stylesheet TEXT,
    logo_url VARCHAR(500),
    
    -- Security
    required_roles TEXT[] DEFAULT '{}', -- Roles that can access this report
    row_level_security BOOLEAN DEFAULT TRUE, -- Apply RLS based on user context
    data_masking_rules JSONB, -- Rules for masking sensitive data
    
    -- Performance settings
    cache_duration_minutes INTEGER DEFAULT 60,
    query_timeout_seconds INTEGER DEFAULT 120,
    max_rows INTEGER DEFAULT 10000,
    batch_size INTEGER DEFAULT 1000,
    use_materialized_data BOOLEAN DEFAULT FALSE,
    
    -- Parameters
    parameters_schema JSONB DEFAULT '[]'::JSONB, -- JSON Schema for parameter validation
    default_parameters JSONB DEFAULT '{}'::JSONB,
    
    -- Dependencies
    dependent_reports UUID[], -- Reports that depend on this one
    dependent_tables TEXT[], -- Tables this report depends on
    
    -- Version control
    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
    version_notes TEXT,
    parent_report_id UUID REFERENCES reporting.report_configurations(report_id),
    is_latest_version BOOLEAN DEFAULT TRUE,
    
    -- Status flags
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_system BOOLEAN DEFAULT FALSE,
    is_deprecated BOOLEAN DEFAULT FALSE,
    deprecated_date DATE,
    deprecated_by UUID REFERENCES hr.employees(employee_id),
    
    -- Usage tracking
    usage_count INTEGER DEFAULT 0,
    last_used_at TIMESTAMP WITH TIME ZONE,
    average_execution_time_ms INTEGER,
    
    -- Tags and categorization
    tags TEXT[] DEFAULT '{}',
    
    -- Flexible metadata
    metadata JSONB DEFAULT '{}'::JSONB,
    
    -- Standard audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    updated_by UUID REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- Check constraints
    CONSTRAINT chk_deprecated_consistency CHECK (
        (is_deprecated = TRUE AND deprecated_date IS NOT NULL) OR
        (is_deprecated = FALSE AND deprecated_date IS NULL)
    )
);

