-- Create function to update usage statistics
CREATE OR REPLACE FUNCTION reporting.update_report_usage()
RETURNS TRIGGER AS $$
BEGIN
    UPDATE reporting.report_configurations
    SET 
        usage_count = usage_count + 1,
        last_used_at = CURRENT_TIMESTAMP
    WHERE report_id = NEW.report_configuration_id;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

