    CREATE TYPE communication.channel_type_enum AS ENUM ('EMAIL', 'SMS', 'SLACK', 'TEAMS', 'WEBHOOK', 'PUSH');
EXCEPTION
    WHEN duplicate_object THEN NULL;
END $$;

-- Create function to calculate next run time
CREATE OR REPLACE FUNCTION reporting.calculate_next_run_time(
    p_schedule_type VARCHAR,
    p_schedule_cron VARCHAR,
    p_start_date DATE,
    p_end_date DATE,
    p_reference_date DATE DEFAULT CURRENT_DATE,
    p_timezone VARCHAR DEFAULT 'UTC'
)
RETURNS TIMESTAMP WITH TIME ZONE AS $$
DECLARE
    v_next_run TIMESTAMP WITH TIME ZONE;
    v_now TIMESTAMP WITH TIME ZONE;
BEGIN
    v_now := (p_reference_date::TIMESTAMP AT TIME ZONE p_timezone);
    
    IF p_schedule_type = 'RECURRING' AND p_schedule_cron IS NOT NULL THEN
        -- Simple cron parsing for common patterns
        CASE p_schedule_cron
            WHEN '0 0 * * *' THEN -- Daily at midnight
                v_next_run := date_trunc('day', v_now + INTERVAL '1 day');
            WHEN '0 9 * * *' THEN -- Daily at 9 AM
                v_next_run := date_trunc('hour', v_now + INTERVAL '1 day') + INTERVAL '9 hours';
            WHEN '0 0 * * 1' THEN -- Weekly on Monday
                v_next_run := date_trunc('week', v_now + INTERVAL '1 week');
            WHEN '0 0 1 * *' THEN -- Monthly on 1st
                v_next_run := date_trunc('month', v_now + INTERVAL '1 month');
            WHEN '0 */6 * * *' THEN -- Every 6 hours
                v_next_run := date_trunc('hour', v_now + INTERVAL '6 hours');
            ELSE
                -- Default to tomorrow if pattern not recognized
                v_next_run := date_trunc('day', v_now + INTERVAL '1 day');
        END CASE;
        
        -- Check against end date
        IF p_end_date IS NOT NULL AND v_next_run::DATE > p_end_date THEN
            v_next_run := NULL;
        END IF;
        
    ELSIF p_schedule_type = 'ONE_TIME' THEN
        -- One-time report
        v_next_run := p_start_date::TIMESTAMP AT TIME ZONE p_timezone;
        
        -- If start date is in the past, set to NULL
        IF v_next_run < v_now THEN
            v_next_run := NULL;
        END IF;
    ELSE
        v_next_run := NULL;
    END IF;
    
    RETURN v_next_run;
END;
$$ LANGUAGE plpgsql IMMUTABLE;

-- Serial No: 55 | TABLE: reporting.scheduled_reports (FIXED - removed references to report_configurations in indexes)
CREATE TABLE IF NOT EXISTS reporting.scheduled_reports (
    -- Primary identifiers
    scheduled_report_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    
    -- Report configuration
    report_configuration_id UUID NOT NULL,
    
    -- Schedule information
    schedule_name VARCHAR(200) NOT NULL,
    schedule_description TEXT,
    schedule_type VARCHAR(20) NOT NULL DEFAULT 'RECURRING'
        CHECK (schedule_type IN ('RECURRING', 'ONE_TIME', 'EVENT_TRIGGERED')),
    
    -- Cron expression
    schedule_cron VARCHAR(100),
    schedule_expression JSONB,
    
    -- Timezone handling
    timezone VARCHAR(50) NOT NULL DEFAULT 'UTC',
    
    -- Date range
    start_date DATE NOT NULL DEFAULT CURRENT_DATE,
    end_date DATE,
    
    -- Execution tracking
    next_run_time TIMESTAMP WITH TIME ZONE,
    last_run_time TIMESTAMP WITH TIME ZONE,
    last_run_status VARCHAR(20) CHECK (last_run_status IN ('SUCCESS', 'FAILED', 'RUNNING', 'SKIPPED', 'PARTIAL')),
    last_run_duration_ms INTEGER,
    last_run_message TEXT,
    last_error TEXT,
    
    -- Run counts
    total_runs INTEGER DEFAULT 0,
    successful_runs INTEGER DEFAULT 0,
    failed_runs INTEGER DEFAULT 0,
    
    -- Delivery configuration
    delivery_methods communication.channel_type_enum[] NOT NULL DEFAULT '{EMAIL}',
    recipients JSONB NOT NULL,
    
    -- Report parameters
    parameters JSONB DEFAULT '{}'::JSONB,
    
    -- Output configuration
    output_format VARCHAR(20) DEFAULT 'PDF'
        CHECK (output_format IN ('PDF', 'EXCEL', 'CSV', 'HTML', 'JSON', 'XML')),
    compression_enabled BOOLEAN DEFAULT FALSE,
    password_protected BOOLEAN DEFAULT FALSE,
    encryption_level VARCHAR(20) DEFAULT 'NONE'
        CHECK (encryption_level IN ('NONE', 'BASIC', 'AES-128', 'AES-256')),
    
    -- Dependencies
    dependent_report_ids UUID[],
    execution_order INTEGER DEFAULT 1,
    
    -- Notification settings
    notify_on_success BOOLEAN DEFAULT FALSE,
    notify_on_failure BOOLEAN DEFAULT TRUE,
    notify_on_skip BOOLEAN DEFAULT FALSE,
    
    -- Status flags
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_paused BOOLEAN DEFAULT FALSE,
    pause_reason TEXT,
    
    -- Priority (1 = highest, 10 = lowest)
    priority INTEGER DEFAULT 5 CHECK (priority BETWEEN 1 AND 10),
    
    -- Retry configuration
    max_retries INTEGER DEFAULT 3 CHECK (max_retries >= 0),
    retry_interval_minutes INTEGER DEFAULT 5,
    
    -- Resource limits
    timeout_minutes INTEGER DEFAULT 30,
    max_file_size_mb INTEGER DEFAULT 100,
    
    -- Tags for categorization
    tags TEXT[] DEFAULT '{}',
    
    -- Flexible metadata
    metadata JSONB DEFAULT '{}'::JSONB,
    
    -- Standard audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    updated_by UUID REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- Check constraints
    CONSTRAINT chk_schedule_dates CHECK (end_date IS NULL OR end_date >= start_date),
    CONSTRAINT chk_cron_format CHECK (
        schedule_cron IS NULL OR 
        schedule_cron ~ '^(\*|([0-9]|[1-5][0-9]?)|\*/([1-9][0-9]?)) (\*|([0-9]|1[0-9]|2[0-3])|\*/([1-9][0-9]?)) (\*|([1-9]|[12][0-9]|3[01])|\*/([1-9][0-9]?)) (\*|([1-9]|1[0-2])|\*/([1-9][0-9]?)) (\*|([0-6])|\*/([1-9][0-9]?))$'
    )
);

-- Add foreign key constraint
ALTER TABLE reporting.scheduled_reports 
    ADD CONSTRAINT fk_scheduled_reports_config 
    FOREIGN KEY (report_configuration_id) 
    REFERENCES reporting.report_configurations(report_id)
    ON DELETE CASCADE;

-- Create function to update next_run_time
CREATE OR REPLACE FUNCTION reporting.update_next_run_time()
RETURNS TRIGGER AS $$
BEGIN
    -- Calculate next run time based on schedule
    NEW.next_run_time := reporting.calculate_next_run_time(
        NEW.schedule_type,
        NEW.schedule_cron,
        NEW.start_date,
        NEW.end_date,
        CURRENT_DATE,
        NEW.timezone
    );
    
    -- Update run counts based on status
    IF TG_OP = 'UPDATE' AND NEW.last_run_status IS DISTINCT FROM OLD.last_run_status AND NEW.last_run_status IS NOT NULL THEN
        NEW.total_runs := COALESCE(OLD.total_runs, 0) + 1;
        
        IF NEW.last_run_status = 'SUCCESS' THEN
            NEW.successful_runs := COALESCE(OLD.successful_runs, 0) + 1;
        ELSIF NEW.last_run_status IN ('FAILED', 'PARTIAL') THEN
            NEW.failed_runs := COALESCE(OLD.failed_runs, 0) + 1;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

