-- Create view for due reports (now with report_configurations table)
CREATE OR REPLACE VIEW reporting.v_due_reports AS
SELECT 
    sr.scheduled_report_id,
    sr.schedule_name,
    sr.schedule_description,
    sr.schedule_type,
    sr.schedule_cron,
    sr.timezone,
    sr.start_date,
    sr.end_date,
    sr.next_run_time,
    sr.last_run_time,
    sr.last_run_status,
    sr.priority,
    sr.is_active,
    sr.is_paused,
    sr.parameters,
    sr.recipients,
    sr.delivery_methods,
    sr.output_format,
    rc.report_id,
    rc.report_code,
    rc.report_name,
    rc.report_category,
    rc.report_type,
    rc.source_type,
    rc.default_format,
    rc.query_timeout_seconds,
    rc.max_rows,
    EXTRACT(EPOCH FROM (sr.next_run_time - CURRENT_TIMESTAMP)) / 60 AS minutes_until_due,
    CASE 
        WHEN sr.next_run_time <= CURRENT_TIMESTAMP THEN 'OVERDUE'
        WHEN sr.next_run_time <= CURRENT_TIMESTAMP + INTERVAL '1 hour' THEN 'DUE_SOON'
        ELSE 'SCHEDULED'
    END AS due_status
FROM reporting.scheduled_reports sr
JOIN reporting.report_configurations rc ON sr.report_configuration_id = rc.report_id
WHERE sr.is_active = TRUE 
  AND sr.is_paused = FALSE
  AND sr.next_run_time IS NOT NULL
  AND (sr.end_date IS NULL OR sr.end_date >= CURRENT_DATE)
ORDER BY sr.priority, sr.next_run_time;

-- Create function to get due reports
CREATE OR REPLACE FUNCTION reporting.get_due_reports(
    p_max_count INTEGER DEFAULT 100,
    p_include_overdue BOOLEAN DEFAULT TRUE
)
RETURNS TABLE (
    scheduled_report_id UUID,
    report_configuration_id UUID,
    report_name VARCHAR,
    schedule_name VARCHAR,
    next_run_time TIMESTAMP WITH TIME ZONE,
    parameters JSONB,
    recipients JSONB,
    delivery_methods communication.channel_type_enum[],
    output_format VARCHAR,
    priority INTEGER,
    source_definition TEXT,
    query_timeout_seconds INTEGER,
    max_rows INTEGER
) AS $$
BEGIN
    RETURN QUERY
    SELECT 
        sr.scheduled_report_id,
        sr.report_configuration_id,
        rc.report_name,
        sr.schedule_name,
        sr.next_run_time,
        sr.parameters,
        sr.recipients,
        sr.delivery_methods,
        sr.output_format,
        sr.priority,
        rc.source_definition,
        rc.query_timeout_seconds,
        rc.max_rows
    FROM reporting.scheduled_reports sr
    JOIN reporting.report_configurations rc ON sr.report_configuration_id = rc.report_id
    WHERE sr.is_active = TRUE 
      AND sr.is_paused = FALSE
      AND sr.next_run_time IS NOT NULL
      AND (p_include_overdue OR sr.next_run_time <= CURRENT_TIMESTAMP + INTERVAL '5 minutes')
      AND (sr.end_date IS NULL OR sr.end_date >= CURRENT_DATE)
    ORDER BY 
        sr.priority,
        sr.next_run_time
    LIMIT p_max_count;
END;
$$ LANGUAGE plpgsql STABLE;

-- Create function to mark report as executed
CREATE OR REPLACE FUNCTION reporting.mark_report_executed(
    p_scheduled_report_id UUID,
    p_status VARCHAR,
    p_duration_ms INTEGER DEFAULT NULL,
    p_message TEXT DEFAULT NULL,
    p_error TEXT DEFAULT NULL
)
RETURNS VOID AS $$
DECLARE
    v_report_config_id UUID;
BEGIN
    -- Get the report configuration ID
    SELECT report_configuration_id INTO v_report_config_id
    FROM reporting.scheduled_reports
    WHERE scheduled_report_id = p_scheduled_report_id;
    
    -- Update scheduled report
    UPDATE reporting.scheduled_reports
    SET 
        last_run_time = CURRENT_TIMESTAMP,
        last_run_status = p_status,
        last_run_duration_ms = p_duration_ms,
        last_run_message = p_message,
        last_error = p_error,
        updated_at = CURRENT_TIMESTAMP
    WHERE scheduled_report_id = p_scheduled_report_id;
    
    -- Update report configuration usage stats
    IF v_report_config_id IS NOT NULL AND p_status = 'SUCCESS' THEN
        UPDATE reporting.report_configurations
        SET 
            usage_count = usage_count + 1,
            last_used_at = CURRENT_TIMESTAMP,
            average_execution_time_ms = (
                (COALESCE(average_execution_time_ms, 0) * 0.7) + (p_duration_ms * 0.3)
            )::INTEGER
        WHERE report_id = v_report_config_id;
    END IF;
END;
$$ LANGUAGE plpgsql;

