COMMENT ON TABLE reporting.report_configurations IS 'Configuration and template definitions for all system reports.
Central repository for all report definitions within the workforce scheduling system. Stores report templates, parameters,
and formatting rules for consistent report generation. Supports multiple report types including operational, analytical,
and compliance reports. Includes security settings for data governance. Performance optimization settings for efficient
report generation. Tracks usage statistics for popular reports. Enables rapid development of new reports without code changes.
Supports multi-language and multiple output formats. Version tracking for change management.';

COMMENT ON TABLE reporting.scheduled_reports IS 'Configuration and tracking of scheduled report execution.
Manages all scheduled reports within the workforce scheduling system, providing centralized mechanism for report automation.
Stores configuration details including report parameters, delivery schedule, and recipient information. Supports multiple
scheduling patterns from simple daily reports to complex calendar-based schedules. Includes security controls to ensure
recipients only receive authorized data. Comprehensive execution tracking captures report generation status and errors.';

    -- Serial No: 56 | TABLE: scheduling.schedule_locks
    -- Description: Management of schedule editing and modification restrictions
    -- Business Case: The schedule_locks table controls access to schedule modification during critical
    -- periods such as payroll processing, compliance reviews, or final schedule publication. It prevents
    -- unauthorized or conflicting changes to schedules that could disrupt business operations or create
    -- compliance issues. Each lock record specifies the schedule being locked, the user or process that
    -- created the lock, and the reason for the lock, providing clear auditability of schedule protection
    -- events. The implementation supports multiple lock types including manual locks initiated by users
    -- and automatic locks triggered by system processes, each with appropriate duration and scope.
    -- Comprehensive tracking of lock duration helps identify potential bottlenecks in the scheduling
    -- workflow where locks remain in place longer than necessary. The table also supports lock
    -- escalation procedures for situations where urgent changes are needed to locked schedules.
    -- For regulatory compliance, the system maintains historical lock records to demonstrate proper
    -- controls around schedule modification. The design accommodates different lock levels from full
    -- schedule locks to specific shift or employee restrictions, providing granular control over
    -- schedule modifications. Lock conflict detection prevents multiple conflicting locks on the
    -- same schedule elements. By centralizing schedule lock management, the system ensures consistent
    -- enforcement of schedule protection policies while providing the flexibility needed for different
    -- business scenarios. The table is optimized for rapid checking of lock status during schedule
    -- modification operations, which is critical for user experience during schedule creation and
    -- adjustment.
    -- KPI: Lock compliance rate, Unauthorized modification attempts,
    --      Schedule modification conflict rate, Lock resolution time,
    --      Payroll processing success rate
    -- Feature Reference: 296, 297, 298, 299, 300
    CREATE TABLE IF NOT EXISTS scheduling.schedule_locks (
        lock_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
        schedule_id UUID NOT NULL REFERENCES scheduling.schedules(schedule_id) ON DELETE CASCADE,
        locked_by UUID NOT NULL REFERENCES hr.employees(employee_id),
        locked_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        unlock_at TIMESTAMP WITH TIME ZONE,
        lock_duration INTERVAL GENERATED ALWAYS AS (
            CASE
                WHEN unlock_at IS NOT NULL
                    THEN unlock_at - locked_at
                ELSE NULL
            END
        ) STORED,
        lock_type VARCHAR(50) NOT NULL DEFAULT 'MANUAL'
            CHECK (lock_type IN ('MANUAL', 'AUTOMATIC', 'PAYROLL', 'APPROVAL', 'COMPLIANCE', 'AUDIT')),
        lock_reason TEXT NOT NULL,
        lock_level VARCHAR(20) NOT NULL DEFAULT 'FULL'
            CHECK (lock_level IN ('FULL', 'PARTIAL', 'READ_ONLY')),
        lock_scope JSONB,
        unlock_requested_by UUID REFERENCES hr.employees(employee_id),
        unlock_request_time TIMESTAMP WITH TIME ZONE,
        unlock_request_reason TEXT,
        created_by UUID NOT NULL,
        updated_by UUID,
        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

    -- Add indexes for performance
    CREATE INDEX IF NOT EXISTS idx_schedule_locks_schedule ON scheduling.schedule_locks(schedule_id);
    CREATE INDEX IF NOT EXISTS idx_schedule_locks_active ON scheduling.schedule_locks(unlock_at)
        WHERE unlock_at IS NULL;
    CREATE INDEX IF NOT EXISTS idx_schedule_locks_type ON scheduling.schedule_locks(lock_type);
    CREATE INDEX IF NOT EXISTS idx_schedule_locks_level ON scheduling.schedule_locks(lock_level);
    CREATE INDEX IF NOT EXISTS idx_schedule_locks_locked_by ON scheduling.schedule_locks(locked_by);
    CREATE INDEX IF NOT EXISTS idx_schedule_locks_requested ON scheduling.schedule_locks(unlock_requested_by)
        WHERE unlock_requested_by IS NOT NULL;
    CREATE INDEX IF NOT EXISTS idx_schedule_locks_scope ON scheduling.schedule_locks USING GIN(lock_scope);

    -- Add triggers for audit columns
    CREATE TRIGGER trg_schedule_locks_updated_at
    BEFORE UPDATE ON scheduling.schedule_locks
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

    COMMENT ON TABLE scheduling.schedule_locks IS 'Management of schedule editing and modification restrictions.
    Controls access to schedule modification during critical periods such as payroll processing or compliance reviews. Prevents
    unauthorized or conflicting changes to schedules that could disrupt operations. Specifies schedule being locked, user or
    process that created lock, and reason for lock. Supports multiple lock types including manual and automatic locks. Tracks
    lock duration to identify potential bottlenecks. Supports lock escalation procedures for urgent changes. Maintains historical
    lock records for regulatory compliance. Accommodates different lock levels from full schedule locks to specific restrictions.
    Lock conflict detection prevents multiple conflicting locks. Centralizes schedule lock management for consistent enforcement.
    Optimized for rapid checking of lock status during schedule modification operations.';

    -- Serial No: 57 | TABLE: system.sync_jobs
    -- Description: Configuration and tracking of data synchronization operations
    -- Business Case: The sync_jobs table manages all data synchronization operations between the
    -- workforce scheduling system and external systems, providing reliable integration with HRIS,
    -- payroll, point-of-sale, and other enterprise applications. It stores configuration details
    -- including source and target endpoints, synchronization direction, and data mapping rules
    -- to ensure accurate data exchange. The table supports multiple synchronization patterns from
    -- real-time event-driven updates to scheduled batch processing, accommodating different
    -- integration requirements. Each sync job includes comprehensive error handling and retry
    -- logic to ensure data consistency even during temporary connectivity issues or system
    -- outages. Historical synchronization data is tracked to monitor data latency and identify
    -- integration issues before they impact business operations. The implementation includes
    -- data transformation rules to handle format differences between systems while maintaining
    -- data integrity. For sensitive data, the system supports encryption and secure transfer
    -- protocols to comply with data protection regulations. The table also tracks synchronization
    -- metrics to measure integration health and performance, enabling proactive management of
    -- integration points. By centralizing synchronization management, the system reduces the
    -- complexity of maintaining multiple integrations while ensuring consistent data quality
    -- across the enterprise. The design accommodates both standard integrations with common
    -- enterprise systems and custom integrations with specialized applications. The table is
    -- optimized for rapid processing during synchronization operations, which often involve
    -- large data volumes and require timely completion to support business processes.
    -- KPI: Sync success rate, Data latency,
    --      Integration error rate, Sync job duration,
    --      Data consistency rate
    -- Feature Reference: 301, 302, 303, 304, 305
    CREATE TABLE IF NOT EXISTS system.sync_jobs (
        job_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
        job_name VARCHAR(100) NOT NULL,
        job_description TEXT,
        source_system VARCHAR(100) NOT NULL,
        source_endpoint TEXT,
        target_system VARCHAR(100) NOT NULL,
        target_endpoint TEXT,
        sync_direction VARCHAR(20) NOT NULL CHECK (sync_direction IN ('PUSH', 'PULL', 'BIDIRECTIONAL')),
        sync_type VARCHAR(50) NOT NULL CHECK (sync_type IN ('FULL', 'INCREMENTAL', 'DELTA', 'REAL_TIME', 'MANUAL')),
        sync_schedule VARCHAR(50),
        sync_parameters JSONB,
        transformation_rules JSONB,
        last_sync TIMESTAMP WITH TIME ZONE,
        next_sync TIMESTAMP WITH TIME ZONE,
        last_status VARCHAR(20) CHECK (last_status IN ('SUCCESS', 'FAILED', 'RUNNING', 'PENDING')),
        last_error TEXT,
        record_count INTEGER,
        error_count INTEGER,
        warning_count INTEGER,
        is_active BOOLEAN NOT NULL DEFAULT TRUE,
        created_by UUID NOT NULL,
        updated_by UUID,
        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

    -- Add indexes for performance
    CREATE INDEX IF NOT EXISTS idx_sync_jobs_source ON system.sync_jobs(source_system);
    CREATE INDEX IF NOT EXISTS idx_sync_jobs_target ON system.sync_jobs(target_system);
    CREATE INDEX IF NOT EXISTS idx_sync_jobs_schedule ON system.sync_jobs(next_sync)
        WHERE is_active = TRUE;
    CREATE INDEX IF NOT EXISTS idx_sync_jobs_status ON system.sync_jobs(last_status);
    CREATE INDEX IF NOT EXISTS idx_sync_jobs_active ON system.sync_jobs(is_active) WHERE is_active = TRUE;
    CREATE INDEX IF NOT EXISTS idx_sync_jobs_direction ON system.sync_jobs(sync_direction);
    CREATE INDEX IF NOT EXISTS idx_sync_jobs_parameters ON system.sync_jobs USING GIN(sync_parameters);
    CREATE INDEX IF NOT EXISTS idx_sync_jobs_rules ON system.sync_jobs USING GIN(transformation_rules);

    -- Add triggers for audit columns
    CREATE TRIGGER trg_sync_jobs_updated_at
    BEFORE UPDATE ON system.sync_jobs
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

    COMMENT ON TABLE system.sync_jobs IS 'Configuration and tracking of data synchronization operations.
    Manages all data synchronization operations between the workforce scheduling system and external systems. Stores configuration
    details including source and target endpoints, synchronization direction, and data mapping rules. Supports multiple
    synchronization patterns from real-time event-driven updates to scheduled batch processing. Includes comprehensive error
    handling and retry logic to ensure data consistency. Historical synchronization data tracked to monitor data latency.
    Includes data transformation rules to handle format differences. Supports encryption and secure transfer protocols for
    sensitive data. Tracks synchronization metrics to measure integration health. Reduces complexity of maintaining multiple
    integrations while ensuring consistent data quality. Accommodates both standard and custom integrations. Optimized for
    rapid processing during synchronization operations involving large data volumes.';

    -- Serial No: 58 | TABLE: customization.custom_fields
    -- Description: Dynamic field extensions for customizable data capture
    -- Business Case: The custom_fields table enables organizations to extend the standard data model
    -- with custom fields tailored to their specific business requirements without modifying the core
    -- schema. It supports flexible data capture for unique business processes, regulatory requirements,
    -- or industry-specific needs. Each custom field definition includes metadata about the field's
    -- data type, validation rules, and display properties to ensure proper integration with user
    -- interfaces. The implementation supports multiple field types including text, numeric, date,
    -- and reference fields, with appropriate storage and indexing strategies for each type.
    -- Comprehensive validation rules ensure data quality for custom fields, maintaining the same
    -- standards as core system fields. The table also tracks field usage patterns to identify
    -- underutilized fields that may be candidates for removal. For sensitive custom fields, the
    -- system enforces appropriate data protection measures based on field classification. Versioning
    -- of custom field definitions allows for tracking changes over time while maintaining historical
    -- data integrity. The design accommodates organizational hierarchy requirements, enabling
    -- different custom fields for different business units or locations while maintaining overall
    -- system consistency. By providing this extensibility mechanism, the system reduces the need
    -- for custom development and supports faster adaptation to changing business requirements. The
    -- table is optimized for efficient storage of custom field metadata while enabling rapid
    -- querying of field definitions during form rendering and data validation.
    -- KPI: Custom field usage rate, Field definition completeness,
    --      Customization compliance rate, Data quality for custom fields,
    --      Time to implement new business requirements
    -- Feature Reference: 306, 307, 308, 309, 310
    CREATE TABLE IF NOT EXISTS customization.custom_fields (
        field_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
        table_name VARCHAR(100) NOT NULL CHECK (table_name ~ '^[a-z_]+\.[a-z_]+$'),
        field_name VARCHAR(100) NOT NULL CHECK (field_name ~ '^[a-z][a-z0-9_]*$'),
        display_name VARCHAR(100) NOT NULL,
        field_type VARCHAR(50) NOT NULL CHECK (field_type IN ('TEXT', 'NUMBER', 'DECIMAL', 'INTEGER', 'DATE',
            'DATETIME', 'BOOLEAN', 'SELECT', 'MULTISELECT', 'JSON', 'REFERENCE', 'CALCULATED')),
        data_type VARCHAR(50),
        field_options JSONB,
        validation_rules JSONB,
        default_value TEXT,
        is_required BOOLEAN NOT NULL DEFAULT FALSE,
        is_visible BOOLEAN NOT NULL DEFAULT TRUE,
        is_editable BOOLEAN NOT NULL DEFAULT TRUE,
        sort_order INTEGER DEFAULT 0,
        field_group VARCHAR(50),
        help_text TEXT,
        data_classification VARCHAR(50) NOT NULL DEFAULT 'INTERNAL'
            CHECK (data_classification IN ('PUBLIC', 'INTERNAL', 'CONFIDENTIAL', 'RESTRICTED', 'HIGHLY_RESTRICTED')),
        version INTEGER NOT NULL DEFAULT 1 CHECK (version >= 1),
        is_active BOOLEAN NOT NULL DEFAULT TRUE,
        created_by UUID NOT NULL,
        updated_by UUID,
        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

    -- Add indexes for performance
    CREATE INDEX IF NOT EXISTS idx_custom_fields_table ON customization.custom_fields(table_name);
    CREATE INDEX IF NOT EXISTS idx_custom_fields_type ON customization.custom_fields(field_type);
    CREATE INDEX IF NOT EXISTS idx_custom_fields_required ON customization.custom_fields(is_required)
        WHERE is_required = TRUE;
    CREATE INDEX IF NOT EXISTS idx_custom_fields_active ON customization.custom_fields(is_active)
        WHERE is_active = TRUE;
    CREATE INDEX IF NOT EXISTS idx_custom_fields_classification ON customization.custom_fields(data_classification);
    CREATE INDEX IF NOT EXISTS idx_custom_fields_group ON customization.custom_fields(field_group)
        WHERE field_group IS NOT NULL;
    CREATE INDEX IF NOT EXISTS idx_custom_fields_options ON customization.custom_fields USING GIN(field_options);
    CREATE INDEX IF NOT EXISTS idx_custom_fields_rules ON customization.custom_fields USING GIN(validation_rules);

    -- Add triggers for audit columns
    CREATE TRIGGER trg_custom_fields_updated_at
    BEFORE UPDATE ON customization.custom_fields
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

    COMMENT ON TABLE customization.custom_fields IS 'Dynamic field extensions for customizable data capture.
    Enables organizations to extend the standard data model with custom fields tailored to specific business requirements.
    Supports flexible data capture for unique business processes, regulatory requirements, or industry-specific needs. Includes
    metadata about field''s data type, validation rules, and display properties. Supports multiple field types with appropriate
    storage and indexing. Comprehensive validation rules ensure data quality. Tracks field usage patterns to identify
    underutilized fields. Enforces data protection measures for sensitive custom fields. Versioning allows tracking changes
    while maintaining historical data integrity. Accommodates organizational hierarchy requirements for different business units.
    Reduces need for custom development and supports faster adaptation to changing business requirements. Optimized for efficient
    storage of custom field metadata while enabling rapid querying during form rendering.';




-- Create all necessary enum types
DO $$ BEGIN
    CREATE TYPE data_quality.metric_type_enum AS ENUM (
        'COMPLETENESS',      -- Null/empty percentage
        'UNIQUENESS',        -- Duplicate rate
        'CONSISTENCY',       -- Format/pattern compliance
        'ACCURACY',          -- Correct value percentage
        'TIMELINESS',        -- Freshness/update lag
        'VALIDITY',          -- Business rule compliance
        'INTEGRITY',         -- Referential integrity
        'PATTERN_MATCH',     -- Regex pattern compliance
        'RANGE_COMPLIANCE',  -- Value within expected range
        'DATA_TYPE_CHECK',   -- Correct data type
        'LENGTH_CHECK',      -- String length validation
        'CARDINALITY',       -- Distinct value count
        'FREQUENCY',         -- Value frequency distribution
        'OUTLIER_DETECTION', -- Statistical outliers
        'TREND_DEVIATION',   -- Deviation from trend
        'SEASONALITY',       -- Seasonal pattern compliance
        'CORRELATION',       -- Cross-column correlation
        'CONSISTENCY_ACROSS', -- Consistency across tables
        'FRESHNESS',         -- Data age/currency
        'VOLUME'             -- Record count/volume
    );
EXCEPTION
    WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
    CREATE TYPE data_quality.calculation_method_enum AS ENUM (
        'SQL_QUERY',
        'PYTHON_SCRIPT',
        'EXTERNAL_TOOL',
        'MANUAL',
        'R_SCRIPT',
        'JAVA_PROCESS',
        'API_CALL',
        'MACHINE_LEARNING'
    );
EXCEPTION
    WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
    CREATE TYPE data_quality.frequency_enum AS ENUM (
        'REALTIME',
        'HOURLY',
        'DAILY',
        'WEEKLY',
        'MONTHLY',
        'QUARTERLY',
        'YEARLY',
        'ON_DEMAND'
    );
EXCEPTION
    WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
    CREATE TYPE data_quality.granularity_enum AS ENUM (
        'HOURLY',
        'DAILY',
        'WEEKLY',
        'MONTHLY',
        'QUARTERLY',
        'YEARLY'
    );
EXCEPTION
    WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
    CREATE TYPE data_quality.data_source_enum AS ENUM (
        'SYSTEM_CALCULATED',
        'MANUAL_ENTRY',
        'SURVEY',
        'OBSERVATION',
        'EXTERNAL_SYSTEM',
        'IMPORTED_FILE',
        'USER_FEEDBACK',
        'THIRD_PARTY_API'
    );
EXCEPTION
    WHEN duplicate_object THEN NULL;
END $$;

-- Serial No: 59 | TABLE: data_governance.column_quality_metrics
-- Description: Statistical metrics for data quality assessment at the column level
-- Business Case: The column_quality_metrics table stores statistical metrics that quantify data
-- quality characteristics at the column level across the database. It captures metrics such as
-- null percentages, uniqueness rates, value distributions, and pattern compliance to provide
-- objective measurements of data health. These metrics are critical for identifying data quality
-- issues before they impact business operations or decision making. The table supports historical
-- tracking of quality metrics to identify trends and measure improvement over time. Each metric
-- record includes metadata about the calculation method, execution frequency, and target values
-- to support data quality goal setting and monitoring. The implementation includes mechanisms for
-- automated metric calculation through scheduled jobs, ensuring timely assessment of data quality.
-- For columns with defined data quality rules, the metrics are correlated with rule violations to
-- provide context for quality issues. The table also tracks remediation efforts and their impact
-- on quality metrics to demonstrate the value of data quality initiatives. By centralizing column
-- quality metrics, the system enables comprehensive data quality dashboards that provide visibility
-- into data health across the organization. The design accommodates different metric types and
-- calculation methods to support diverse data quality requirements. Historical metric data is
-- used to establish baselines and detect anomalies that may indicate underlying data issues. The
-- table is optimized for time-series analysis of quality metrics, supporting trend identification
-- and predictive data quality management.
-- KPI: Data completeness rate, Data uniqueness rate,
--      Pattern compliance rate, Data quality trend direction,
--      Data issue detection time
-- Feature Reference: 311, 312, 313, 314, 315
CREATE TABLE IF NOT EXISTS data_governance.column_quality_metrics (
    -- Primary identifiers
    metric_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    
    -- Target column identification
    schema_name VARCHAR(100) NOT NULL DEFAULT 'public',
    table_name VARCHAR(200) NOT NULL,
    column_name VARCHAR(200) NOT NULL,
    
    -- Metric classification
    metric_type data_quality.metric_type_enum NOT NULL,
    metric_subtype VARCHAR(100), -- More specific classification within the main type
    
    -- Calculation metadata
    calculation_method data_quality.calculation_method_enum NOT NULL DEFAULT 'SQL_QUERY',
    calculation_frequency data_quality.frequency_enum NOT NULL DEFAULT 'DAILY',
    calculation_version VARCHAR(20) DEFAULT '1.0',
    calculation_script TEXT, -- Store the actual calculation logic
    
    -- Metric values
    metric_value NUMERIC(15,6) NOT NULL,
    metric_value_raw TEXT, -- Raw value before transformation
    metric_value_formatted VARCHAR(255), -- Human-readable formatted value
    metric_unit VARCHAR(50), -- e.g., 'percentage', 'count', 'ratio'
    
    -- Thresholds and targets
    target_value NUMERIC(15,6),
    warning_threshold NUMERIC(15,6),
    failure_threshold NUMERIC(15,6),
    baseline_value NUMERIC(15,6), -- Historical baseline for comparison
    
    -- Statistical measures
    standard_deviation NUMERIC(15,6),
    variance NUMERIC(15,6),
    min_value NUMERIC(15,6),
    max_value NUMERIC(15,6),
    percentile_25 NUMERIC(15,6),
    percentile_50 NUMERIC(15,6), -- median
    percentile_75 NUMERIC(15,6),
    percentile_95 NUMERIC(15,6),
    percentile_99 NUMERIC(15,6),
    
    -- Sample information
    sample_size INTEGER,
    total_records INTEGER,
    sample_percentage NUMERIC(5,2), -- Percentage of total records sampled
    
    -- Execution tracking
    calculation_time TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    calculated_by UUID REFERENCES hr.employees(employee_id),
    calculation_duration_ms INTEGER CHECK (calculation_duration_ms >= 0),
    calculation_status VARCHAR(20) DEFAULT 'SUCCESS'
        CHECK (calculation_status IN ('SUCCESS', 'PARTIAL', 'FAILED', 'TIMEOUT')),
    error_message TEXT,
    
    -- Time granularity
    metric_granularity data_quality.granularity_enum NOT NULL DEFAULT 'DAILY',
    metric_date DATE NOT NULL DEFAULT CURRENT_DATE,
    metric_hour INTEGER CHECK (metric_hour BETWEEN 0 AND 23),
    metric_week INTEGER CHECK (metric_week BETWEEN 1 AND 53),
    metric_month INTEGER CHECK (metric_month BETWEEN 1 AND 12),
    metric_quarter INTEGER CHECK (metric_quarter BETWEEN 1 AND 4),
    metric_year INTEGER NOT NULL DEFAULT EXTRACT(YEAR FROM CURRENT_DATE),
    
    -- Business context
    related_shift_id UUID REFERENCES scheduling.shifts(shift_id),
    related_employee_id UUID REFERENCES hr.employees(employee_id),
    related_department_id UUID REFERENCES hr.departments(department_id),
    related_location_id UUID REFERENCES operations.locations(location_id),
    related_rule_id UUID REFERENCES data_quality.data_quality_rules(rule_id),
    related_process_id UUID, -- Could reference business_processes table
    
    -- Quality dimension scores
    completeness_score NUMERIC(5,2) CHECK (completeness_score BETWEEN 0 AND 100),
    accuracy_score NUMERIC(5,2) CHECK (accuracy_score BETWEEN 0 AND 100),
    consistency_score NUMERIC(5,2) CHECK (consistency_score BETWEEN 0 AND 100),
    timeliness_score NUMERIC(5,2) CHECK (timeliness_score BETWEEN 0 AND 100),
    overall_quality_score NUMERIC(5,2) CHECK (overall_quality_score BETWEEN 0 AND 100),
    
    -- Trend analysis
    trend_direction VARCHAR(10) CHECK (trend_direction IN ('IMPROVING', 'STABLE', 'DEGRADING', 'VOLATILE')),
    trend_percentage NUMERIC(10,2), -- Percentage change from previous period
    seasonally_adjusted_value NUMERIC(15,6),
    forecast_value NUMERIC(15,6),
    forecast_confidence NUMERIC(5,2) CHECK (forecast_confidence BETWEEN 0 AND 100),
    
    -- Anomaly detection
    is_anomaly BOOLEAN DEFAULT FALSE,
    anomaly_score NUMERIC(5,2) CHECK (anomaly_score BETWEEN 0 AND 100),
    anomaly_reason TEXT,
    
    -- Data quality issue linkage
    related_issue_ids UUID[], -- Links to data_quality_issues
    issue_count INTEGER DEFAULT 0,
    
    -- Remediation tracking
    remediation_required BOOLEAN DEFAULT FALSE,
    remediation_priority VARCHAR(20) CHECK (remediation_priority IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
    remediation_assigned_to UUID REFERENCES hr.employees(employee_id),
    remediation_deadline DATE,
    remediation_completed_at TIMESTAMP WITH TIME ZONE,
    remediation_notes TEXT,
    
    -- Data source
    data_source data_quality.data_source_enum NOT NULL DEFAULT 'SYSTEM_CALCULATED',
    source_system VARCHAR(100),
    
    -- Additional context
    context JSONB,
    tags TEXT[] DEFAULT '{}',
    notes TEXT,
    
    -- Quality metadata
    is_trusted BOOLEAN DEFAULT TRUE,
    confidence_level NUMERIC(5,2) DEFAULT 100 CHECK (confidence_level BETWEEN 0 AND 100),
    requires_review BOOLEAN DEFAULT FALSE,
    reviewed_by UUID REFERENCES hr.employees(employee_id),
    reviewed_at TIMESTAMP WITH TIME ZONE,
    
    -- Standard audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    updated_by UUID REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- Ensure valid date ranges
    CONSTRAINT chk_metric_date_consistency CHECK (
        (metric_granularity = 'HOURLY' AND metric_hour IS NOT NULL) OR
        (metric_granularity != 'HOURLY' AND metric_hour IS NULL)
    ),
    CONSTRAINT chk_metric_week_consistency CHECK (
        (metric_granularity = 'WEEKLY' AND metric_week IS NOT NULL) OR
        (metric_granularity != 'WEEKLY' AND metric_week IS NULL)
    ),
    CONSTRAINT chk_metric_month_consistency CHECK (
        (metric_granularity IN ('MONTHLY', 'QUARTERLY') AND metric_month IS NOT NULL) OR
        (metric_granularity NOT IN ('MONTHLY', 'QUARTERLY') AND metric_month IS NULL)
    )
);

-- Create a unique constraint to prevent duplicate metrics
CREATE UNIQUE INDEX IF NOT EXISTS uq_column_quality_metrics_unique 
    ON data_governance.column_quality_metrics(
        schema_name, table_name, column_name, metric_type, metric_granularity, metric_date, COALESCE(metric_hour, 0)
    );

