-- Create a function to calculate overall quality score
CREATE OR REPLACE FUNCTION data_governance.calculate_overall_quality_score()
RETURNS TRIGGER AS $$
BEGIN
    -- Calculate overall quality score as weighted average of dimension scores
    NEW.overall_quality_score := (
        COALESCE(NEW.completeness_score, 0) * 0.25 +
        COALESCE(NEW.accuracy_score, 0) * 0.30 +
        COALESCE(NEW.consistency_score, 0) * 0.20 +
        COALESCE(NEW.timeliness_score, 0) * 0.25
    );
    
    -- Determine trend direction based on comparison with previous period
    IF NEW.metric_value > OLD.metric_value + COALESCE(OLD.standard_deviation, 0) THEN
        NEW.trend_direction := 'IMPROVING';
    ELSIF NEW.metric_value < OLD.metric_value - COALESCE(OLD.standard_deviation, 0) THEN
        NEW.trend_direction := 'DEGRADING';
    ELSE
        NEW.trend_direction := 'STABLE';
    END IF;
    
    -- Calculate trend percentage
    IF OLD.metric_value IS NOT NULL AND OLD.metric_value != 0 THEN
        NEW.trend_percentage := ((NEW.metric_value - OLD.metric_value) / OLD.metric_value) * 100;
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- -- Create trigger for quality score calculation
-- DROP TRIGGER IF EXISTS trg_column_quality_metrics_score ON data_governance.column_quality_metrics;
-- CREATE TRIGGER trg_column_quality_metrics_score
--     BEFORE INSERT OR UPDATE OF completeness_score, accuracy_score, consistency_score, timeliness_score, metric_value
--     ON data_governance.column_quality_metrics
--     FOR EACH ROW
--     EXECUTE FUNCTION data_governance.calculate_overall_quality_score();

-- Create a view for quality dashboard
CREATE OR REPLACE VIEW data_governance.vw_quality_dashboard AS
SELECT 
    schema_name,
    table_name,
    column_name,
    metric_type,
    metric_granularity,
    metric_date,
    metric_value,
    target_value,
    CASE 
        WHEN metric_value >= target_value THEN 'MEETING_TARGET'
        WHEN metric_value >= warning_threshold THEN 'WARNING'
        WHEN metric_value >= failure_threshold THEN 'FAILING'
        ELSE 'CRITICAL'
    END AS status,
    overall_quality_score,
    trend_direction,
    trend_percentage,
    is_anomaly,
    anomaly_score,
    remediation_required,
    remediation_priority,
    created_at
FROM data_governance.column_quality_metrics
WHERE metric_date >= CURRENT_DATE - INTERVAL '90 days';

-- Create a function to get latest metrics for a column
CREATE OR REPLACE FUNCTION data_governance.get_latest_column_metrics(
    p_schema_name VARCHAR,
    p_table_name VARCHAR,
    p_column_name VARCHAR,
    p_days_back INTEGER DEFAULT 30
)
RETURNS TABLE (
    metric_date DATE,
    metric_type data_quality.metric_type_enum,
    metric_value NUMERIC,
    target_value NUMERIC,
    overall_quality_score NUMERIC,
    is_anomaly BOOLEAN
) AS $$
BEGIN
    RETURN QUERY
    SELECT 
        cqm.metric_date,
        cqm.metric_type,
        cqm.metric_value,
        cqm.target_value,
        cqm.overall_quality_score,
        cqm.is_anomaly
    FROM data_governance.column_quality_metrics cqm
    WHERE cqm.schema_name = p_schema_name
      AND cqm.table_name = p_table_name
      AND cqm.column_name = p_column_name
      AND cqm.metric_date >= CURRENT_DATE - (p_days_back || ' days')::INTERVAL
    ORDER BY cqm.metric_date DESC, cqm.metric_type;
END;
$$ LANGUAGE plpgsql STABLE;

COMMENT ON TABLE data_governance.column_quality_metrics IS 'Statistical metrics for data quality assessment at the column level.
Stores statistical metrics that quantify data quality characteristics at the column level. Captures metrics such as null
percentages, uniqueness rates, value distributions, and pattern compliance. Critical for identifying data quality issues
before they impact business operations. Supports historical tracking to identify trends and measure improvement. Includes
metadata about calculation method, execution frequency, and target values. Includes mechanisms for automated metric calculation.
Correlates metrics with rule violations for context. Tracks remediation efforts and impact on quality metrics. Enables
comprehensive data quality dashboards. Accommodates different metric types and calculation methods. Historical data used to
establish baselines and detect anomalies. Optimized for time-series analysis of quality metrics.';

