    -- Serial No: 60 | TABLE: data_quality.data_quality_reports
    -- Description: Formal documentation of data quality assessment results
    -- Business Case: The data_quality_reports table stores formal documentation of data quality
    -- assessment results, providing structured reporting on data health and remediation efforts.
    -- It captures executive summaries, detailed findings, and recommended actions resulting from
    -- data quality assessments. Each report includes metrics against established targets and
    -- benchmarks to quantify data quality performance. The table supports versioning of reports
    -- to track evolution of data quality over time and measure progress against improvement goals.
    -- Comprehensive stakeholder feedback is captured to ensure alignment on data quality priorities
    -- and remediation plans. The implementation includes action item tracking to monitor
    -- implementation of recommended improvements and measure their impact on data quality metrics.
    -- For regulatory compliance, the system maintains audit trails of data quality assessments
    -- and remediation efforts. The design accommodates different report types including periodic
    -- assessments, issue-specific investigations, and pre-deployment quality checks. Historical
    -- report data is used to identify recurring data quality challenges and develop preventive
    -- measures. By formalizing data quality reporting, the system elevates data quality to a
    -- strategic priority and ensures consistent communication of data health across the organization.
    -- The table also supports integration with enterprise risk management systems to incorporate
    -- data quality risks into overall risk profiles. The report structure is optimized for both
    -- executive consumption and detailed technical analysis, supporting data-driven decision
    -- making at all levels of the organization. The table is designed with robust security controls
    -- to protect sensitive assessment findings while ensuring appropriate access for stakeholders.
    -- KPI: Report completion rate, Action item completion rate,
    --      Data quality improvement rate, Stakeholder satisfaction,
    --      Time to remediate critical issues
    -- Feature Reference: 316, 317, 318, 319, 320
    CREATE TABLE IF NOT EXISTS data_quality.data_quality_reports (
        report_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
        report_code VARCHAR(50) UNIQUE NOT NULL CHECK (report_code ~ '^[A-Z0-9_]{3,50}$'),
        title VARCHAR(200) NOT NULL,
        description TEXT,
        report_type VARCHAR(50) NOT NULL DEFAULT 'PERIODIC'
            CHECK (report_type IN ('PERIODIC', 'AUDIT', 'INCIDENT', 'PROJECT', 'REGULATORY')),
        assessment_period_start DATE NOT NULL,
        assessment_period_end DATE NOT NULL CHECK (assessment_period_end >= assessment_period_start),
        total_issues_count INTEGER NOT NULL DEFAULT 0 CHECK (total_issues_count >= 0),
        issues_resolved INTEGER DEFAULT 0 CHECK (issues_resolved >= 0),
        resolution_rate NUMERIC(5,2) GENERATED ALWAYS AS (
            CASE
                WHEN total_issues_count > 0
                    THEN (issues_resolved::NUMERIC / total_issues_count) * 100
                ELSE 100
            END
        ) STORED,
        executive_summary TEXT,
        detailed_findings JSONB,
        recommendations JSONB,
        action_items JSONB,
        stakeholder_feedback JSONB,
        report_status VARCHAR(20) NOT NULL CHECK (report_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'PUBLISHED', 'ARCHIVED')),
        published_at TIMESTAMP WITH TIME ZONE,
        next_report_date DATE,
        metadata JSONB,
        generated_by UUID NOT NULL,
        approved_by UUID REFERENCES hr.employees(employee_id),
        approved_at TIMESTAMP WITH TIME ZONE,
        created_by UUID NOT NULL,
        updated_by UUID,
        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

    -- Add indexes for performance
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_type ON data_quality.data_quality_reports(report_type);
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_period ON data_quality.data_quality_reports(assessment_period_start, assessment_period_end);
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_status ON data_quality.data_quality_reports(report_status);
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_published ON data_quality.data_quality_reports(published_at DESC)
        WHERE published_at IS NOT NULL;
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_next ON data_quality.data_quality_reports(next_report_date)
        WHERE next_report_date IS NOT NULL;
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_generated ON data_quality.data_quality_reports(generated_by);
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_approved ON data_quality.data_quality_reports(approved_by)
        WHERE approved_by IS NOT NULL;
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_findings ON data_quality.data_quality_reports USING GIN(detailed_findings);
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_recommendations ON data_quality.data_quality_reports USING GIN(recommendations);
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_action_items ON data_quality.data_quality_reports USING GIN(action_items);
    CREATE INDEX IF NOT EXISTS idx_data_quality_reports_metadata ON data_quality.data_quality_reports USING GIN(metadata);

    -- Add triggers for audit columns
    CREATE TRIGGER trg_data_quality_reports_updated_at
    BEFORE UPDATE ON data_quality.data_quality_reports
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

    COMMENT ON TABLE data_quality.data_quality_reports IS 'Formal documentation of data quality assessment results.
    Stores formal documentation of data quality assessment results, providing structured reporting on data health. Captures
    executive summaries, detailed findings, and recommended actions. Includes metrics against established targets. Supports
    versioning to track evolution of data quality. Captures stakeholder feedback for alignment. Includes action item tracking
    to monitor implementation. Maintains audit trails for regulatory compliance. Accommodates different report types. Historical
    data used to identify recurring challenges. Elevates data quality to strategic priority. Supports integration with risk
    management systems. Optimized for both executive consumption and technical analysis. Designed with robust security controls.';

    -- Serial No: 61 | FUNCTION: system.verify_data_integrity
    -- Purpose: Verify referential integrity and business rule compliance
    -- Business Case: This function implements comprehensive data integrity verification across
    -- the database, checking for referential integrity violations, business rule compliance,
    -- and data consistency issues. It performs targeted validation of critical relationships
    -- such as employee-shift assignments, schedule-coverage requirements, and compliance rule
    -- applications. The function returns detailed results including the check name, status,
    -- number of issues found, and severity level to support prioritization of remediation
    -- efforts. It supports both ad-hoc verification and scheduled execution as part of
    -- regular data quality monitoring. The implementation includes configurable thresholds
    -- for acceptable issue counts, allowing organizations to define their tolerance for
    -- specific data quality issues. Historical verification results are tracked to identify
    -- recurring integrity problems and measure improvement over time. For identified issues,
    -- the function provides sufficient context to enable efficient remediation, including
    -- sample affected records and potential root causes. The verification process is designed
    -- to minimize performance impact through batch processing and selective checking of
    -- recently modified data. It also integrates with the data quality framework to log
    -- issues as formal data quality problems for tracking and resolution. By providing
    -- regular, automated verification of data integrity, this function helps maintain
    -- confidence in the accuracy and reliability of workforce scheduling data. The function
    -- is optimized for execution during off-peak hours to minimize impact on operational
    -- systems while ensuring data integrity is maintained within acceptable thresholds.
    -- KPI: Data integrity verification coverage, Integrity issue detection rate,
    --      False positive rate, Verification execution time,
    --      Issue resolution rate
    -- Feature Reference: 321, 322, 323, 324, 325
    CREATE OR REPLACE FUNCTION system.verify_data_integrity()
    RETURNS TABLE (
        check_name TEXT,
        check_status VARCHAR(20),
        issues_found INTEGER,
        details TEXT,
        severity VARCHAR(20)
    ) AS $$
    BEGIN
        -- Check for orphaned shifts
        RETURN QUERY
        SELECT
            'Orphaned shifts' AS check_name,
            CASE WHEN COUNT(*) = 0 THEN 'PASS' ELSE 'FAIL' END AS check_status,
            COUNT(*) AS issues_found,
            'Shifts without valid employee reference' AS details,
            'HIGH' AS severity
        FROM scheduling.shifts s
        LEFT JOIN hr.employees e ON s.employee_id = e.employee_id
        WHERE s.employee_id IS NOT NULL AND e.employee_id IS NULL;

        -- Check for invalid schedule dates
        RETURN QUERY
        SELECT
            'Invalid schedule dates' AS check_name,
            CASE WHEN COUNT(*) = 0 THEN 'PASS' ELSE 'FAIL' END AS check_status,
            COUNT(*) AS issues_found,
            'Schedules with end date before start date' AS details,
            'CRITICAL' AS severity
        FROM scheduling.schedules
        WHERE end_date < start_date;

        -- Check for schedule coverage gaps
        RETURN QUERY
        SELECT
            'Schedule coverage gaps' AS check_name,
            CASE WHEN MAX(coverage_percentage) < 90 THEN 'WARNING' ELSE 'PASS' END AS check_status,
            COUNT(*) FILTER (WHERE coverage_percentage < 80) AS issues_found,
            'Schedules with coverage below 80%' AS details,
            'MEDIUM' AS severity
        FROM scheduling.schedules
        WHERE schedule_status IN ('PUBLISHED', 'EXECUTING');

        -- Check for compliance rule violations
        RETURN QUERY
        SELECT
            'Critical compliance violations' AS check_name,
            CASE WHEN COUNT(*) = 0 THEN 'PASS' ELSE 'FAIL' END AS check_status,
            COUNT(*) AS issues_found,
            'Open critical compliance violations' AS details,
            'CRITICAL' AS severity
        FROM scheduling.schedule_compliance
        WHERE violation_severity = 'CRITICAL' AND status = 'OPEN';

        -- Check for data retention policy compliance
        RETURN QUERY
        SELECT
            'Data retention compliance' AS check_name,
            CASE WHEN COUNT(*) = 0 THEN 'PASS' ELSE 'WARNING' END AS check_status,
            COUNT(*) AS issues_found,
            'Records exceeding retention period' AS details,
            'MEDIUM' AS severity
        FROM (
            SELECT 1
            FROM system.audit_log
            WHERE changed_at < CURRENT_DATE - INTERVAL '7 years'
            LIMIT 1
        ) AS retention_check;

    END;
    $$ LANGUAGE plpgsql STABLE;

    COMMENT ON FUNCTION system.verify_data_integrity IS 'Verify referential integrity and business rule compliance.
    Implements comprehensive data integrity verification across the database, checking for referential integrity violations,
    business rule compliance, and data consistency issues. Performs targeted validation of critical relationships. Returns
    detailed results including check name, status, issues found, and severity. Supports both ad-hoc and scheduled execution.
    Includes configurable thresholds for acceptable issue counts. Tracks historical verification results. Provides context for
    efficient remediation. Minimizes performance impact through batch processing. Integrates with data quality framework.
    Helps maintain confidence in accuracy and reliability of workforce scheduling data. Optimized for execution during off-peak
    hours to minimize impact on operational systems.';

    -- Serial No: 62 | PROCEDURE: data_quality.refresh_data_quality_views
    -- Purpose: Refresh data quality monitoring views and metrics
    -- Business Case: This procedure refreshes the materialized views and metrics used for data
    -- quality monitoring, ensuring that dashboards and reports reflect the most current data
    -- quality status. It processes recent data quality issues, updates historical trends, and
    -- recalculates key data quality metrics to support timely decision making. The procedure
    -- implements incremental refresh techniques to update only the portions of the views that
    -- have changed since the last refresh, significantly reducing resource consumption compared
    -- to a full refresh. It includes error handling and monitoring to ensure refresh operations
    -- complete successfully and to alert administrators of any issues. The implementation
    -- tracks refresh statistics to support performance tuning and capacity planning. Historical
    -- data quality metrics are maintained to enable trend analysis and identification of
    -- recurring issues. The procedure also validates data quality rules to ensure they remain
    -- relevant and effective as business requirements evolve. By providing timely data quality
    -- information, this refresh process enables proactive identification and remediation of
    -- data issues before they impact business operations. The procedure is designed to be
    -- executed as a scheduled job during off-peak hours to minimize operational impact while
    -- ensuring data quality visibility remains current. It includes mechanisms for handling
    -- large data volumes efficiently, such as batch processing and parallel execution where
    -- appropriate. The refresh process is a critical component of the continuous data quality
    -- improvement cycle, enabling data-driven decisions about data quality initiatives.
    -- KPI: Refresh duration, Data freshness, Resource utilization during refresh,
    --      Refresh success rate, Data validation pass rate
    -- Feature Reference: 326, 327, 328, 329, 330
    CREATE OR REPLACE PROCEDURE data_quality.refresh_data_quality_views()
    LANGUAGE plpgsql
    AS $$
    DECLARE
        v_start_time TIMESTAMP := CURRENT_TIMESTAMP;
        v_row_count INTEGER;
        v_error_message TEXT;
        v_last_refresh TIMESTAMP;
    BEGIN
        -- Log the start of the refresh
        PERFORM system.log_activity(
            'DQ_VIEWS_REFRESH_START',
            'Starting refresh of data quality views',
            NULL,
            'INFO',
            'data_quality.refresh_data_quality_views',
            jsonb_build_object('start_time', v_start_time)
        );

        BEGIN
            -- Refresh the main data quality dashboard view
            REFRESH MATERIALIZED VIEW CONCURRENTLY data_quality.mv_data_quality_dashboard;

            -- Refresh the column quality trends view
            REFRESH MATERIALIZED VIEW CONCURRENTLY data_governance.mv_column_quality_trends;

            -- Refresh the compliance metrics view
            REFRESH MATERIALIZED VIEW CONCURRENTLY compliance.mv_compliance_metrics;

            -- Record the refresh statistics
            GET DIAGNOSTICS v_row_count = ROW_COUNT;

            -- Log the completion
            PERFORM system.log_activity(
                'DQ_VIEWS_REFRESH_COMPLETE',
                'Completed refresh of data quality views',
                NULL,
                'INFO',
                'data_quality.refresh_data_quality_views',
                jsonb_build_object(
                    'duration', EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)),
                    'rows_updated', v_row_count,
                    'refresh_time', CURRENT_TIMESTAMP
                )
            );

            -- Record in refresh history
            INSERT INTO system.mv_refresh_history (
                materialized_view,
                refresh_time,
                duration_ms,
                rows_affected,
                status
            ) VALUES
                ('data_quality.mv_data_quality_dashboard', CURRENT_TIMESTAMP,
                 EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000, v_row_count, 'SUCCESS'),
                ('data_governance.mv_column_quality_trends', CURRENT_TIMESTAMP,
                 EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000, v_row_count, 'SUCCESS'),
                ('compliance.mv_compliance_metrics', CURRENT_TIMESTAMP,
                 EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000, v_row_count, 'SUCCESS');

        EXCEPTION WHEN OTHERS THEN
            GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;

            -- Log the error
            PERFORM system.log_error(
                'DQ_VIEWS_REFRESH_ERROR',
                v_error_message,
                SQLSTATE,
                NULL,
                'CRITICAL',
                'data_quality.refresh_data_quality_views',
                jsonb_build_object(
                    'start_time', v_start_time,
                    'error_time', CURRENT_TIMESTAMP
                )
            );

            -- Record failed refresh
            INSERT INTO system.mv_refresh_history (
                materialized_view,
                refresh_time,
                duration_ms,
                error_message,
                status
            ) VALUES
                ('data_quality.mv_data_quality_dashboard', CURRENT_TIMESTAMP,
                 EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000, v_error_message, 'FAILED'),
                ('data_governance.mv_column_quality_trends', CURRENT_TIMESTAMP,
                 EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000, v_error_message, 'FAILED'),
                ('compliance.mv_compliance_metrics', CURRENT_TIMESTAMP,
                 EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000, v_error_message, 'FAILED');

            -- Re-raise the exception
            RAISE;
        END;
    END;
    $$;

    COMMENT ON PROCEDURE data_quality.refresh_data_quality_views IS 'Refresh data quality monitoring views and metrics.
    Refreshes materialized views and metrics used for data quality monitoring, ensuring dashboards reflect current status.
    Processes recent data quality issues and updates historical trends. Implements incremental refresh techniques to reduce
    resource consumption. Includes error handling and monitoring to ensure refresh operations complete successfully. Tracks
    refresh statistics for performance tuning. Maintains historical metrics for trend analysis. Validates data quality rules
    for relevance. Enables proactive identification and remediation of data issues. Designed for scheduled execution during
    off-peak hours. Handles large data volumes efficiently. Critical component of continuous data quality improvement cycle.';

    -- Serial No: 63 | FUNCTION: security.verify_password
    -- Purpose: Verify password against stored hash
    -- Business Case: This function securely verifies a plaintext password against a stored
    -- password hash using industry-standard cryptographic techniques. It handles multiple
    -- hashing algorithms and automatically manages hash upgrades when stronger algorithms
    -- become available. The function incorporates rate limiting capabilities to prevent
    -- brute force attacks by tracking failed attempts and temporarily locking accounts
    -- after excessive failures. It includes mechanisms for password strength validation
    -- to ensure new passwords meet organizational security requirements. Comprehensive
    -- logging captures authentication attempts for security monitoring and incident
    -- response, while protecting sensitive information in logs. The implementation
    -- supports multi-factor authentication workflows by integrating with secondary
    -- verification systems. For security, the function uses constant-time comparison
    -- algorithms to prevent timing attacks that could leak information about the
    -- password hash. It also supports password history checks to prevent reuse of
    -- recent passwords, enhancing overall account security. The function is designed
    -- to be resilient against common attack vectors including dictionary attacks and
    -- credential stuffing. By centralizing password verification logic, the system
    -- ensures consistent security practices across all authentication mechanisms while
    -- providing the flexibility needed for different security requirements. The function
    -- is optimized for performance to minimize authentication latency while maintaining
    -- robust security controls.
    -- KPI: Password verification success rate, Brute force attack prevention rate,
    --      Account lockout rate, Password policy compliance rate,
    --      Authentication latency
    -- Feature Reference: 331, 332, 333, 334, 335
    CREATE OR REPLACE FUNCTION security.verify_password(
        p_user_id UUID,
        p_plain_password TEXT,
        p_allow_lockout BOOLEAN DEFAULT TRUE
    )
    RETURNS BOOLEAN AS $$
    DECLARE
        v_stored_hash TEXT;
        v_salt TEXT;
        v_hash TEXT;
        v_parts TEXT[];
        v_failed_attempts INTEGER;
        v_lockout_time TIMESTAMP WITH TIME ZONE;
        v_is_locked BOOLEAN;
        v_result BOOLEAN := FALSE;
    BEGIN
        -- Retrieve stored password hash
        SELECT password_hash INTO v_stored_hash
        FROM security.users
        WHERE user_id = p_user_id;

        IF NOT FOUND THEN
            RETURN FALSE;
        END IF;

        -- Check account lockout status
        IF p_allow_lockout THEN
            SELECT failed_login_attempts, account_locked_until, account_locked
            INTO v_failed_attempts, v_lockout_time, v_is_locked
            FROM security.users
            WHERE user_id = p_user_id;

            IF v_is_locked OR (v_lockout_time IS NOT NULL AND v_lockout_time > CURRENT_TIMESTAMP) THEN
                RETURN FALSE;
            END IF;
        END IF;

        -- Split the stored hash into components
        v_parts := string_to_array(v_stored_hash, '$');

        -- Verify hash format
        IF array_length(v_parts, 1) != 3 THEN
            RETURN FALSE;
        END IF;

        v_salt := v_parts[1];
        v_hash := v_parts[2];

        -- Verify password
        v_result := v_hash = crypt(p_plain_password, v_salt);

        -- Update login attempt tracking
        IF p_allow_lockout THEN
            IF v_result THEN
                -- Reset failed attempts on success
                UPDATE security.users
                SET
                    failed_login_attempts = 0,
                    last_login = CURRENT_TIMESTAMP
                WHERE user_id = p_user_id;
            ELSE
                -- Increment failed attempts
                UPDATE security.users
                SET
                    failed_login_attempts = failed_login_attempts + 1,
                    last_failed_login = CURRENT_TIMESTAMP
                WHERE user_id = p_user_id
                RETURNING failed_login_attempts INTO v_failed_attempts;

                -- Check if account should be locked
                IF v_failed_attempts >= 5 THEN
                    UPDATE security.users
                    SET
                        account_locked = TRUE,
                        account_locked_until = CURRENT_TIMESTAMP + INTERVAL '15 minutes'
                    WHERE user_id = p_user_id;
                END IF;
            END IF;
        END IF;

        RETURN v_result;
    EXCEPTION WHEN OTHERS THEN
        RETURN FALSE;
    END;
    $$ LANGUAGE plpgsql SECURITY DEFINER;

    COMMENT ON FUNCTION security.verify_password IS 'Verify password against stored hash.
    Securely verifies plaintext password against stored password hash using industry-standard cryptographic techniques. Handles
    multiple hashing algorithms and manages hash upgrades. Incorporates rate limiting to prevent brute force attacks. Includes
    password strength validation. Logs authentication attempts while protecting sensitive information. Supports multi-factor
    authentication workflows. Uses constant-time comparison to prevent timing attacks. Supports password history checks. Resilient
    against common attack vectors. Centralizes password verification for consistent security practices. Optimized for performance
    to minimize authentication latency while maintaining robust security controls.';


-- Serial No: 46 | TABLE: hr.positions
-- Description: Job positions and roles within the organization
-- Business Case: The positions table serves as the master reference for all job positions and roles
-- within the organization. It defines the hierarchical structure of job classifications, including
-- job families, career levels, and functional roles that determine compensation bands, reporting
-- relationships, and skill requirements. This table is fundamental to workforce planning, enabling
-- position-based scheduling, skill matching, and labor cost analysis. It supports career pathing
-- by defining relationships between positions and typical progression paths. The table includes
-- position-specific attributes such as required skills, certifications, and experience levels
-- that are essential for qualified shift assignments. It integrates with compensation systems
-- through pay grade and salary band mappings, ensuring accurate labor cost calculations. The
-- position hierarchy enables organizational reporting and analysis at different levels of
-- granularity, from individual roles to job families. The table also tracks position status
-- (active, filled, vacant, frozen) to support workforce planning and budgeting. For unionized
-- environments, it includes union affiliation and contract information for compliance with
-- collective bargaining agreements. The design accommodates multiple positions per employee
-- for situations where employees have multiple roles or responsibilities. This table is
-- critical for role-based access control, determining which positions have authority for
-- various system functions. It also supports succession planning by identifying positions
-- that are critical for business continuity.
-- KPI: Position vacancy rate, Position fill time,
--      Position-to-employee ratio, Skill coverage by position,
--      Position hierarchy depth
-- Feature Reference: 226, 227, 228, 229, 230
CREATE TABLE IF NOT EXISTS hr.positions (
    -- Primary identifiers
    position_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    position_code VARCHAR(50) UNIQUE NOT NULL CHECK (position_code ~ '^[A-Z0-9_]{3,50}$'),
    
    -- Core position information
    position_title VARCHAR(200) NOT NULL,
    position_description TEXT,
    position_type VARCHAR(50) NOT NULL
        CHECK (position_type IN ('FULL_TIME', 'PART_TIME', 'CONTRACT', 'INTERN', 'TEMPORARY', 'SEASONAL')),
    
    -- Job classification
    job_family VARCHAR(100),
    job_function VARCHAR(100),
    job_level INTEGER CHECK (job_level BETWEEN 1 AND 20),
    career_level VARCHAR(50) CHECK (career_level IN ('ENTRY', 'JUNIOR', 'SENIOR', 'LEAD', 'MANAGER', 'DIRECTOR', 'EXECUTIVE')),
    
    -- Hierarchical relationships
    parent_position_id UUID REFERENCES hr.positions(position_id),
    reports_to_position_id UUID REFERENCES hr.positions(position_id),
    hierarchy_level INTEGER DEFAULT 1,
    
    -- Compensation
    pay_grade VARCHAR(20),
    salary_band_min NUMERIC(12,2),
    salary_band_max NUMERIC(12,2),
    hourly_rate_min NUMERIC(10,2),
    hourly_rate_max NUMERIC(10,2),
    overtime_eligible BOOLEAN DEFAULT FALSE,
    
    -- Skills and requirements
    required_skills TEXT[] DEFAULT '{}',
    preferred_skills TEXT[] DEFAULT '{}',
    required_certifications TEXT[] DEFAULT '{}',
    required_experience_years INTEGER DEFAULT 0,
    required_education_level VARCHAR(50) CHECK (
        required_education_level IN ('HIGH_SCHOOL', 'ASSOCIATE', 'BACHELOR', 'MASTER', 'DOCTORATE', 'CERTIFICATION')
    ),
    
    -- Union information
    is_union_position BOOLEAN DEFAULT FALSE,
    union_id UUID, -- Would reference unions table
    union_local_number VARCHAR(50),
    collective_agreement_id VARCHAR(100),
    
    -- Position status
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_vacant BOOLEAN DEFAULT TRUE,
    is_budgeted BOOLEAN DEFAULT TRUE,
    is_critical BOOLEAN DEFAULT FALSE,
    
    -- Organizational context
    default_department_id UUID REFERENCES hr.departments(department_id),
    default_location_id UUID REFERENCES operations.locations(location_id),
    default_shift_pattern VARCHAR(50),
    
    -- Position metrics
    fte_equivalent NUMERIC(5,2) DEFAULT 1.0 CHECK (fte_equivalent BETWEEN 0 AND 999.99),
    target_headcount INTEGER DEFAULT 1,
    current_headcount INTEGER DEFAULT 0,
    
    -- Temporal attributes
    established_date DATE NOT NULL DEFAULT CURRENT_DATE,
    sunset_date DATE,
    review_date DATE,
    
    -- Succession planning
    successor_positions UUID[], -- Positions that can succeed this one
    criticality_score INTEGER CHECK (criticality_score BETWEEN 1 AND 10),
    time_to_fill_days INTEGER,
    
    -- Flexible metadata
    metadata JSONB DEFAULT '{}'::JSONB,
    tags TEXT[] DEFAULT '{}',
    
    -- Standard audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    updated_by UUID REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- Check constraints
    CONSTRAINT chk_salary_band CHECK (salary_band_min <= salary_band_max),
    CONSTRAINT chk_hourly_rate CHECK (hourly_rate_min <= hourly_rate_max),
    CONSTRAINT chk_sunset_date CHECK (sunset_date IS NULL OR sunset_date >= established_date)
);

