-- Create function to update hierarchy level
CREATE OR REPLACE FUNCTION hr.maintain_position_hierarchy()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.parent_position_id IS NULL THEN
        NEW.hierarchy_level = 1;
    ELSE
        SELECT hierarchy_level + 1 INTO NEW.hierarchy_level
        FROM hr.positions
        WHERE position_id = NEW.parent_position_id;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- DROP TRIGGER IF EXISTS trg_positions_hierarchy ON hr.positions;
-- CREATE TRIGGER trg_positions_hierarchy
--     BEFORE INSERT OR UPDATE OF parent_position_id ON hr.positions
--     FOR EACH ROW
--     EXECUTE FUNCTION hr.maintain_position_hierarchy();

-- Create view for position hierarchy
CREATE OR REPLACE VIEW hr.vw_position_hierarchy AS
WITH RECURSIVE position_tree AS (
    SELECT 
        position_id,
        position_code,
        position_title,
        parent_position_id,
        hierarchy_level,
        position_title::TEXT AS path,
        ARRAY[position_title::TEXT] AS path_array,
        1 AS tree_depth
    FROM hr.positions
    WHERE parent_position_id IS NULL AND is_active = TRUE
    
    UNION ALL
    
    SELECT 
        c.position_id,
        c.position_code,
        c.position_title,
        c.parent_position_id,
        c.hierarchy_level,
        (pt.path || ' -> ' || c.position_title::TEXT)::TEXT,
        pt.path_array || ARRAY[c.position_title::TEXT],
        pt.tree_depth + 1
    FROM hr.positions c
    INNER JOIN position_tree pt ON c.parent_position_id = pt.position_id
    WHERE c.is_active = TRUE
)
SELECT * FROM position_tree;

