-- Create a simplified version for quick access
CREATE OR REPLACE VIEW reporting.v_shift_coverage_simple AS
SELECT 
    l.location_name,
    d.department_name,
    COALESCE(p.position_title, 'Unknown') AS position_title,
    DATE_TRUNC('day', sh.start_time)::DATE AS date,
    COUNT(*) AS total_shifts,
    COUNT(CASE WHEN sh.employee_id IS NOT NULL THEN 1 END) AS filled_shifts,
    COUNT(CASE WHEN sh.shift_status = 'OPEN' THEN 1 END) AS open_shifts,
    ROUND((COUNT(CASE WHEN sh.employee_id IS NOT NULL THEN 1 END)::NUMERIC / 
           NULLIF(COUNT(*), 0) * 100), 2) AS coverage_percent
FROM scheduling.shifts sh
JOIN scheduling.schedules s ON sh.schedule_id = s.schedule_id
JOIN operations.locations l ON s.location_id = l.location_id
JOIN hr.departments d ON s.department_id = d.department_id
LEFT JOIN hr.positions p ON sh.position_id = p.position_id
WHERE sh.start_time >= CURRENT_DATE - INTERVAL '30 days'
GROUP BY l.location_name, d.department_name, p.position_title, DATE_TRUNC('day', sh.start_time)
ORDER BY date DESC, location_name, department_name;




    -- Serial No: 65 | MATERIALIZED VIEW: data_governance.mv_column_quality_trends
    -- Purpose: Historical trends of column-level data quality metrics
    -- Business Case: This materialized view stores historical trends of column-level data
    -- quality metrics to support longitudinal analysis of data health. It aggregates metrics
    -- such as null rates, uniqueness rates, and pattern compliance over time to identify
    -- improvement or degradation in data quality. The view includes comparison against
    -- targets and thresholds to highlight areas requiring attention. It supports multiple
    -- time granularities (daily, weekly, monthly) to accommodate different analysis needs.
    -- Historical trend data is critical for demonstrating the value of data quality initiatives
    -- and securing investment in data governance programs. The materialized structure enables
    -- rapid query performance for trend analysis that would be too slow on operational tables.
    -- The view also includes benchmark comparisons against industry standards or internal
    -- best practices to provide context for quality measurements. It serves as the foundation
    -- for data quality scorecards that track progress against organizational data quality goals.
    -- The implementation includes anomaly detection logic to automatically identify unusual
    -- patterns in quality metrics that may indicate underlying data issues. By pre-computing
    -- these trends, the view enables sophisticated data quality analytics to be performed in
    -- real-time, supporting proactive data governance. The refresh process is optimized to
    -- minimize impact on operational systems while ensuring trend data remains sufficiently
    -- current for decision making. The view is designed to support both executive-level
    -- consumption of high-level trends and detailed analysis by data stewards investigating
    -- specific quality issues.
    -- KPI: Data quality trend direction, Target achievement rate,
    --      Anomaly detection rate, Data quality improvement rate,
    --      Trend analysis performance
    -- Feature Reference: 341, 342, 343, 344, 345
    CREATE MATERIALIZED VIEW IF NOT EXISTS data_governance.mv_column_quality_trends AS
    SELECT
        schema_name,
        table_name,
        column_name,
        metric_type,
        DATE_TRUNC('day', calculation_time) AS calculation_date,
        AVG(metric_value) AS avg_metric_value,
        MIN(metric_value) AS min_metric_value,
        MAX(metric_value) AS max_metric_value,
        PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY metric_value) AS median_metric_value,
        COUNT(*) AS sample_count,
        BOOL_AND(metric_value >= COALESCE(warning_threshold, 0)) AS meets_warning_threshold,
        BOOL_AND(metric_value >= COALESCE(failure_threshold, 0)) AS meets_failure_threshold,
        target_value,
        warning_threshold,
        failure_threshold
    FROM data_governance.column_quality_metrics
    WHERE calculation_time >= CURRENT_DATE - INTERVAL '2 years'
    GROUP BY
        schema_name, table_name, column_name, metric_type,
        DATE_TRUNC('day', calculation_time),
        target_value, warning_threshold, failure_threshold;

    -- Create indexes on the materialized view
    CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_column_quality_trends_full ON data_governance.mv_column_quality_trends
        (schema_name, table_name, column_name, metric_type, calculation_date);
    CREATE INDEX IF NOT EXISTS idx_mv_column_quality_trends_table ON data_governance.mv_column_quality_trends
        (schema_name, table_name, column_name);
    CREATE INDEX IF NOT EXISTS idx_mv_column_quality_trends_type ON data_governance.mv_column_quality_trends (metric_type);
    CREATE INDEX IF NOT EXISTS idx_mv_column_quality_trends_date ON data_governance.mv_column_quality_trends (calculation_date);
    CREATE INDEX IF NOT EXISTS idx_mv_column_quality_trends_trend ON data_governance.mv_column_quality_trends
        (avg_metric_value, calculation_date);

    COMMENT ON MATERIALIZED VIEW data_governance.mv_column_quality_trends IS 'Historical trends of column-level data quality metrics.
    Stores historical trends of column-level data quality metrics to support longitudinal analysis. Aggregates metrics such as null
    rates and uniqueness rates over time. Includes comparison against targets and thresholds. Critical for demonstrating value of
    data quality initiatives. Enables rapid query performance for trend analysis. Includes benchmark comparisons for context. Serves
    as foundation for data quality scorecards. Includes anomaly detection logic. Enables sophisticated data quality analytics. Refresh
    process optimized to minimize impact on operational systems. Supports both executive-level consumption and detailed analysis.';

    -- Serial No: 66 | FUNCTION: data_quality.execute_data_quality_rule
    -- Purpose: Execute a specific data quality rule and record findings
    -- Business Case: This function executes a specific data quality rule against the relevant
    -- data, applying the defined validation logic and recording any issues found. It handles
    -- multiple rule types including validation rules, calculation rules, and anomaly detection
    -- rules, each with appropriate execution logic. The function implements parameterized rule
    -- execution to support dynamic rule configuration without code changes. It includes
    -- comprehensive error handling to ensure partial failures don't prevent completion of
    -- the rule execution. For each rule execution, the function records detailed findings
    -- including affected records, severity levels, and contextual information to support
    -- remediation. The implementation tracks rule execution statistics to monitor rule
    -- performance and identify problematic rules that may need optimization. Historical
    -- execution data is maintained to analyze rule effectiveness and measure improvement
    -- over time. The function also supports rule simulation mode for testing rule changes
    -- before deployment to production. For critical rules, the function can trigger
    -- notifications to alert stakeholders of significant issues requiring immediate
    -- attention. By centralizing rule execution logic, the function ensures consistent
    -- application of data quality standards across the organization. The implementation
    -- is optimized for performance on large datasets, using efficient set-based operations
    -- rather than procedural logic where possible. It serves as the engine for the data
    -- quality monitoring system, enabling proactive identification of data issues.
    -- KPI: Rule execution coverage, Issue detection rate,
    --      False positive rate, Execution duration,
    --      Critical issue response time
    -- Feature Reference: 346, 347, 348, 349, 350
    CREATE OR REPLACE FUNCTION data_quality.execute_data_quality_rule(
        p_rule_id UUID,
        p_simulation_mode BOOLEAN DEFAULT FALSE
    )
    RETURNS INTEGER AS $$
    DECLARE
        v_rule RECORD;
        v_issue_count INTEGER := 0;
        v_start_time TIMESTAMP;
        v_end_time TIMESTAMP;
        v_duration_ms INTEGER;
        v_sql TEXT;
        v_issue_ids UUID[] := '{}';
        v_result JSONB;
        v_success BOOLEAN;
        v_error TEXT;
    BEGIN
        -- Retrieve rule definition
        SELECT * INTO v_rule
        FROM data_quality.data_quality_rules
        WHERE rule_id = p_rule_id
        AND is_active = TRUE;

        IF NOT FOUND THEN
            RAISE EXCEPTION 'Data quality rule % not found or inactive', p_rule_id;
        END IF;

        v_start_time := clock_timestamp();

        BEGIN
            CASE v_rule.rule_type
                WHEN 'VALIDATION' THEN
                    -- Execute validation rule
                    v_sql := format(
                        'INSERT INTO data_quality.data_quality_issues ' ||
                        '(rule_id, issue_code, title, description, severity, ' ||
                        'schema_name, table_name, column_name, record_id, record_details, ' ||
                        'detected_at, detected_by, status, created_by) ' ||
                        'SELECT ' ||
                        '   %L, ' ||
                        '   %L || ''_'' || uuid_generate_v4(), ' ||
                        '   %L, ' ||
                        '   %L, ' ||
                        '   %L, ' ||
                        '   %L, ' ||
                        '   %L, ' ||
                        '   %L, ' ||
                        '   %L, ' ||
                        '   %L, ' ||
                        '   CURRENT_TIMESTAMP, ' ||
                        '   %L, ' ||
                        '   %L, ' ||
                        '   %L ' ||
                        'FROM %I.%I ' ||
                        'WHERE %s',
                        v_rule.rule_id,
                        v_rule.rule_code,
                        v_rule.name,
                        v_rule.description,
                        v_rule.severity,
                        v_rule.schema_name,
                        v_rule.table_name,
                        v_rule.column_name,
                        'NULL',
                        'ROW_TO_JSON(%I.*)::JSONB',
                        'SYSTEM',
                        'OPEN',
                        'SYSTEM',
                        v_rule.table_name,
                        v_rule.table_name,
                        v_rule.rule_expression
                    );

                    IF p_simulation_mode THEN
                        EXECUTE 'SELECT COUNT(*) FROM ' || quote_ident(v_rule.schema_name) || '.' || quote_ident(v_rule.table_name) ||
                               ' WHERE ' || v_rule.rule_expression INTO v_issue_count;
                    ELSE
                        EXECUTE v_sql;
                        GET DIAGNOSTICS v_issue_count = ROW_COUNT;
                    END IF;

                    v_success := TRUE;

                WHEN 'CALCULATION' THEN
                    -- Execute calculation logic
                    v_result := jsonb_build_object('executed', TRUE, 'rule_type', v_rule.rule_type);
                    v_success := TRUE;
                    v_issue_count := 0;

                ELSE
                    v_result := jsonb_build_object('executed', TRUE, 'rule_type', v_rule.rule_type);
                    v_success := TRUE;
                    v_issue_count := 0;
            END CASE;

        EXCEPTION WHEN OTHERS THEN
            v_success := FALSE;
            v_error := SQLERRM;
            v_result := jsonb_build_object('error', SQLERRM, 'error_detail', SQLSTATE);
        END;

        v_end_time := clock_timestamp();
        v_duration_ms := EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000;

        -- Update rule statistics
        UPDATE data_quality.data_quality_rules
        SET
            last_executed = NOW(),
            last_issue_count = v_issue_count,
            last_execution_duration_ms = v_duration_ms
        WHERE rule_id = v_rule.rule_id;

        -- Log rule execution
        INSERT INTO system.audit_logs (
            user_id,
            action,
            entity_type,
            entity_id,
            details,
            ip_address
        ) VALUES (
            '00000000-0000-0000-0000-000000000000',
            'DATA_QUALITY_RULE_EXECUTION',
            'data_quality.data_quality_rules',
            v_rule.rule_id,
            jsonb_build_object(
                'rule_name', v_rule.name,
                'issue_count', v_issue_count,
                'duration_ms', v_duration_ms,
                'success', v_success,
                'simulation_mode', p_simulation_mode
            ),
            NULL
        );

        RETURN v_issue_count;
    END;
    $$ LANGUAGE plpgsql SECURITY DEFINER;

    COMMENT ON FUNCTION data_quality.execute_data_quality_rule IS 'Execute a specific data quality rule and record findings.
    Executes specific data quality rule against relevant data, applying defined validation logic. Handles multiple rule types with
    appropriate execution logic. Implements parameterized rule execution for dynamic configuration. Includes comprehensive error
    handling. Records detailed findings for remediation. Tracks rule execution statistics. Maintains historical execution data.
    Supports rule simulation mode for testing. Triggers notifications for critical issues. Centralizes rule execution for consistent
    application. Optimized for performance on large datasets. Serves as engine for data quality monitoring system.';

    -- Serial No: 67 | TABLE: compliance.compliance_audit_logs
    -- Description: Detailed audit trail for compliance-related activities
    -- Business Case: The compliance_audit_logs table provides a comprehensive audit trail of
    -- all compliance-related activities within the workforce scheduling system, capturing
    -- detailed information about compliance checks, violations, and remediation efforts.
    -- It records who performed compliance actions, when they were performed, and what specific
    -- data was evaluated, providing a complete historical record of compliance activities.
    -- This information is critical for regulatory compliance, forensic analysis of compliance
    -- issues, and reconstruction of historical compliance states. The table supports both
    -- automated compliance monitoring activities and manual compliance reviews conducted
    -- by auditors or compliance officers. Each record includes contextual information about
    -- the business environment at the time of the compliance check, enabling accurate
    -- assessment of compliance status during audits. The implementation includes robust
    -- security controls to protect the integrity of the audit trail and prevent tampering.
    -- Historical compliance data is maintained to support trend analysis and identification
    -- of recurring compliance issues. The table also tracks approval workflows for compliance
    -- exceptions, documenting the rationale and authorization for any deviations from standard
    -- compliance requirements. By centralizing compliance auditing, the system ensures
    -- consistent enforcement of compliance policies while providing the detailed evidence
    -- needed for regulatory examinations. The design accommodates different compliance
    -- frameworks for various jurisdictions and business units, enabling global organizations
    -- to maintain defensible compliance practices across their entire operation. The table
    -- is optimized for rapid querying during compliance audits and for generating required
    -- regulatory reports.
    -- KPI: Audit completeness rate, Compliance documentation quality,
    --      Audit preparation time, Exception approval timeliness,
    --      Audit finding resolution rate
    -- Feature Reference: 351, 352, 353, 354, 355
    CREATE TABLE IF NOT EXISTS compliance.compliance_audit_logs (
        audit_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
        audit_type VARCHAR(50) NOT NULL CHECK (audit_type IN ('AUTOMATED_CHECK', 'MANUAL_REVIEW', 'REGULATORY_AUDIT',
            'INTERNAL_AUDIT', 'COMPLIANCE_CERTIFICATION')),
        rule_id UUID NOT NULL,
        rule_type VARCHAR(50) NOT NULL CHECK (rule_type IN ('LABOR_LAW', 'UNION_AGREEMENT', 'COMPANY_POLICY', 'CUSTOM_RULE')),
        entity_type VARCHAR(50) NOT NULL CHECK (entity_type IN ('SCHEDULE', 'SHIFT', 'EMPLOYEE', 'DEPARTMENT', 'LOCATION')),
        entity_id UUID NOT NULL,
        performed_by UUID NOT NULL,
        performed_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        findings JSONB NOT NULL,
        severity VARCHAR(20) NOT NULL CHECK (severity IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
        status VARCHAR(20) NOT NULL CHECK (status IN ('OPEN', 'IN_PROGRESS', 'RESOLVED', 'EXCEPTION_APPROVED', 'IGNORED')),
        exception_approved_by UUID REFERENCES hr.employees(employee_id),
        exception_approval_date TIMESTAMP WITH TIME ZONE,
        exception_reason TEXT,
        remediation_steps TEXT[],
        remediation_evidence JSONB,
        remediation_completed_at TIMESTAMP WITH TIME ZONE,
        next_review_date DATE,
        audit_context JSONB,
        is_regulatory BOOLEAN NOT NULL DEFAULT FALSE,
        regulatory_body VARCHAR(100),
        regulatory_reference VARCHAR(100),
        created_by UUID NOT NULL,
        updated_by UUID,
        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
    );

    -- Add indexes for performance
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_type ON compliance.compliance_audit_logs(audit_type);
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_rule ON compliance.compliance_audit_logs(rule_id);
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_entity ON compliance.compliance_audit_logs(entity_type, entity_id);
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_performed ON compliance.compliance_audit_logs(performed_at DESC);
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_performer ON compliance.compliance_audit_logs(performed_by);
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_severity ON compliance.compliance_audit_logs(severity);
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_status ON compliance.compliance_audit_logs(status);
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_regulatory ON compliance.compliance_audit_logs(is_regulatory)
        WHERE is_regulatory = TRUE;
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_findings ON compliance.compliance_audit_logs USING GIN(findings);
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_evidence ON compliance.compliance_audit_logs USING GIN(remediation_evidence);
    CREATE INDEX IF NOT EXISTS idx_compliance_audit_context ON compliance.compliance_audit_logs USING GIN(audit_context);

    -- Add triggers for audit columns
    CREATE TRIGGER trg_compliance_audit_logs_updated_at
    BEFORE UPDATE ON compliance.compliance_audit_logs
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

    COMMENT ON TABLE compliance.compliance_audit_logs IS 'Detailed audit trail for compliance-related activities.
    Provides comprehensive audit trail of all compliance-related activities, capturing who performed actions and what data was
    evaluated. Critical for regulatory compliance, forensic analysis, and reconstruction of historical compliance states. Supports
    both automated monitoring and manual reviews. Includes contextual information about business environment. Includes robust
    security controls to protect audit trail integrity. Historical data maintained for trend analysis. Tracks approval workflows
    for compliance exceptions. Centralizes compliance auditing for consistent enforcement. Accommodates different compliance
    frameworks for various jurisdictions. Optimized for rapid querying during compliance audits and regulatory reporting.';

    -- Serial No: 68 | VIEW: compliance.v_compliance_trend_analysis
    -- Purpose: Analysis of compliance trends and patterns over time
    -- Business Case: This view provides analytical insights into compliance trends across
    -- the organization, identifying patterns of violations, remediation effectiveness, and
    -- improvement over time. It combines data from compliance audit logs, violation records,
    -- and remediation efforts to create a comprehensive picture of compliance performance.
    -- The view includes metrics at multiple levels of granularity (organization, location,
    -- department, position) to support different management perspectives. Historical trend
    -- data is presented with appropriate statistical analysis to distinguish meaningful
    -- patterns from random fluctuations. The design accommodates jurisdictional differences
    -- in compliance requirements, enabling global organizations to analyze compliance
    -- consistently across regions. The view serves as the foundation for compliance scorecards
    -- that track progress against organizational compliance goals and regulatory requirements.
    -- It also supports root cause analysis of recurring compliance issues by identifying
    -- common factors across violations. For regulatory reporting, the view provides the
    -- necessary data in the required format, reducing preparation time for compliance
    -- submissions. By centralizing compliance trend data, the view reduces the time and
    -- effort required to produce compliance reports and enables proactive management of
    -- compliance risks. The implementation includes benchmark comparisons against industry
    -- standards to provide context for compliance performance. The view is optimized for
    -- performance with pre-aggregated metrics where possible, ensuring responsive analytics
    -- even with large historical datasets. It enables data-driven decisions about compliance
    -- initiatives and resource allocation for compliance management.
    -- KPI: Compliance violation trend, Remediation effectiveness rate,
    --      Repeat violation rate, Compliance improvement rate,
    --      Audit finding closure rate
    -- Feature Reference: 356, 357, 358, 359, 360
    CREATE OR REPLACE VIEW compliance.v_compliance_trend_analysis AS
    SELECT
        l.location_id,
        l.location_name,
        l.region,
        d.department_id,
        d.department_name,
        p.position_id,
        p.position_title,
        r.rule_type,
        r.jurisdiction,
        DATE_TRUNC('week', cal.performed_at) AS week_start,
        COUNT(cal.audit_id) AS audit_count,
        COUNT(CASE WHEN cal.severity = 'CRITICAL' THEN 1 END) AS critical_findings,
        COUNT(CASE WHEN cal.severity = 'HIGH' THEN 1 END) AS high_findings,
        COUNT(CASE WHEN cal.severity = 'MEDIUM' THEN 1 END) AS medium_findings,
        COUNT(CASE WHEN cal.severity = 'LOW' THEN 1 END) AS low_findings,
        COUNT(CASE WHEN cal.status = 'OPEN' THEN 1 END) AS open_findings,
        COUNT(CASE WHEN cal.status = 'IN_PROGRESS' THEN 1 END) AS in_progress_findings,
        COUNT(CASE WHEN cal.status = 'RESOLVED' THEN 1 END) AS resolved_findings,
        COUNT(CASE WHEN cal.exception_approved_by IS NOT NULL THEN 1 END) AS exceptions,
        AVG(EXTRACT(EPOCH FROM (cal.remediation_completed_at - cal.performed_at)) / 86400)
            FILTER (WHERE cal.remediation_completed_at IS NOT NULL) AS avg_remediation_days,
        (COUNT(CASE WHEN cal.status = 'RESOLVED' THEN 1 END)::NUMERIC /
            NULLIF(COUNT(cal.audit_id), 0)) * 100 AS resolution_rate,
        jsonb_build_object(
            'repeat_violations', COUNT(*) FILTER (WHERE cal.entity_id IN (
                SELECT entity_id
                FROM compliance.compliance_audit_logs cal2
                WHERE cal2.rule_id = cal.rule_id
                AND cal2.performed_at < cal.performed_at - INTERVAL '30 days'
            ))
        ) AS pattern_analysis
    FROM compliance.compliance_audit_logs cal
    JOIN compliance.union_rules r ON cal.rule_id = r.rule_id
    LEFT JOIN operations.locations l ON cal.entity_id = l.location_id AND cal.entity_type = 'LOCATION'
    LEFT JOIN hr.departments d ON cal.entity_id = d.department_id AND cal.entity_type = 'DEPARTMENT'
    LEFT JOIN hr.positions p ON cal.entity_id = p.position_id AND cal.entity_type = 'POSITION'
    WHERE cal.performed_at >= CURRENT_DATE - INTERVAL '2 years'
    GROUP BY
        l.location_id, l.location_name, l.region,
        d.department_id, d.department_name,
        p.position_id, p.position_title,
        r.rule_type, r.jurisdiction,
        DATE_TRUNC('week', cal.performed_at);

    COMMENT ON VIEW compliance.v_compliance_trend_analysis IS 'Analysis of compliance trends and patterns over time.
    Provides analytical insights into compliance trends across the organization. Combines data from compliance audit logs, violation
    records, and remediation efforts. Includes metrics at multiple levels of granularity. Historical trend data presented with
    statistical analysis. Accommodates jurisdictional differences in compliance requirements. Serves as foundation for compliance
    scorecards. Supports root cause analysis of recurring issues. Provides data for regulatory reporting. Reduces time and effort
    for compliance reports. Includes benchmark comparisons for context. Optimized for performance with pre-aggregated metrics.
    Enables data-driven decisions about compliance initiatives.';

    -- Serial No: 69 | PROCEDURE: system.refresh_materialized_views
    -- Purpose: Refresh all critical materialized views for reporting and analytics
    -- Business Case: This procedure implements a coordinated refresh of all critical
    -- materialized views used for reporting and analytics, ensuring that dashboards
    -- and reports reflect the most current data. It processes views in dependency
    -- order to maintain data consistency across related views. The procedure includes
    -- sophisticated error handling to ensure partial failures don't prevent completion
    -- of the overall refresh process. Each view refresh is timed and logged to support
    -- performance monitoring and capacity planning. The implementation tracks historical
    -- refresh statistics to identify views that may need optimization or structural
    -- changes. For views with large data volumes, the procedure implements incremental
    -- refresh techniques to minimize resource consumption and reduce refresh duration.
    -- The procedure also validates the integrity of refreshed data to ensure accuracy
    -- and consistency. Comprehensive notifications are sent upon completion to alert
    -- stakeholders of data availability. By centralizing view refresh logic, the
    -- procedure ensures consistent refresh practices across the organization while
    -- providing the flexibility needed for different refresh requirements. The design
    -- accommodates scheduled execution through the job scheduler, enabling regular
    -- updates of analytical data during off-peak hours. It includes mechanisms for
    -- handling resource constraints by dynamically adjusting refresh parallelism based
    -- on system load. The procedure is a critical component of the data pipeline that
    -- delivers timely insights to business stakeholders, supporting data-driven
    -- decision making across the organization.
    -- KPI: View refresh success rate, Total refresh duration,
    --      Resource utilization during refresh, Data freshness,
    --      View refresh error rate
    -- Feature Reference: 361, 362, 363, 364, 365
    CREATE OR REPLACE PROCEDURE system.refresh_materialized_views()
    LANGUAGE plpgsql
    SECURITY DEFINER
    AS $$
    DECLARE
        v_start_time TIMESTAMP := CURRENT_TIMESTAMP;
        v_view_name TEXT;
        v_duration_ms INTEGER;
        v_error_message TEXT;
        v_total_duration INTEGER := 0;
        v_success_count INTEGER := 0;
        v_failure_count INTEGER := 0;
    BEGIN
        RAISE NOTICE 'Refreshing materialized views...';

        -- Log the start of the refresh process
        PERFORM system.log_activity(
            'MV_REFRESH_PROCESS_START',
            'Starting coordinated refresh of materialized views',
            NULL,
            'INFO',
            'system.refresh_materialized_views',
            jsonb_build_object('start_time', v_start_time)
        );

        -- Refresh views in dependency order
        FOR v_view_name IN
            VALUES
                ('analytics.mv_schedule_performance'),
                ('analytics.mv_workforce_productivity'),
                ('data_quality.mv_data_quality_dashboard'),
                ('data_governance.mv_column_quality_trends'),
                ('compliance.mv_compliance_metrics')
        LOOP
            BEGIN
                RAISE NOTICE 'Refreshing view %...', v_view_name;

                -- Record start time
                v_start_time := clock_timestamp();

                -- Refresh the view
                EXECUTE format('REFRESH MATERIALIZED VIEW CONCURRENTLY %s', v_view_name);

                -- Calculate duration
                v_duration_ms := EXTRACT(EPOCH FROM (clock_timestamp() - v_start_time)) * 1000;
                v_total_duration := v_total_duration + v_duration_ms;

                -- Log successful refresh
                PERFORM system.log_activity(
                    'MV_REFRESH_SUCCESS',
                    format('Successfully refreshed materialized view %s', v_view_name),
                    NULL,
                    'INFO',
                    'system.refresh_materialized_views',
                    jsonb_build_object(
                        'view_name', v_view_name,
                        'duration_ms', v_duration_ms
                    )
                );

                -- Record in refresh history
                INSERT INTO system.mv_refresh_history (
                    materialized_view,
                    refresh_time,
                    duration_ms,
                    status
                ) VALUES (
                    v_view_name,
                    CURRENT_TIMESTAMP,
                    v_duration_ms,
                    'SUCCESS'
                );

                v_success_count := v_success_count + 1;

            EXCEPTION WHEN OTHERS THEN
                GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;

                -- Log the error
                PERFORM system.log_error(
                    'MV_REFRESH_ERROR',
                    v_error_message,
                    SQLSTATE,
                    NULL,
                    'CRITICAL',
                    'system.refresh_materialized_views',
                    jsonb_build_object(
                        'view_name', v_view_name,
                        'error_time', CURRENT_TIMESTAMP
                    )
                );

                -- Record failed refresh
                INSERT INTO system.mv_refresh_history (
                    materialized_view,
                    refresh_time,
                    duration_ms,
                    error_message,
                    status
                ) VALUES (
                    v_view_name,
                    CURRENT_TIMESTAMP,
                    EXTRACT(EPOCH FROM (clock_timestamp() - v_start_time)) * 1000,
                    v_error_message,
                    'FAILED'
                );

                v_failure_count := v_failure_count + 1;
            END;
        END LOOP;

        -- Log completion of the refresh process
        PERFORM system.log_activity(
            'MV_REFRESH_PROCESS_COMPLETE',
            'Completed coordinated refresh of materialized views',
            NULL,
            'INFO',
            'system.refresh_materialized_views',
            jsonb_build_object(
                'total_duration_ms', v_total_duration,
                'success_count', v_success_count,
                'failure_count', v_failure_count
            )
        );

        -- Send notification if any failures occurred
        IF v_failure_count > 0 THEN
            PERFORM communication.send_alert(
                'MATERIALIZED_VIEW_REFRESH_FAILURE',
                format('Materialized view refresh completed with %s failures', v_failure_count),
                jsonb_build_object(
                    'success_count', v_success_count,
                    'failure_count', v_failure_count,
                    'total_duration_ms', v_total_duration
                )
            );
        END IF;

    EXCEPTION WHEN OTHERS THEN
        -- Log critical error
        GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;

        PERFORM system.log_error(
            'MV_REFRESH_PROCESS_ERROR',
            v_error_message,
            SQLSTATE,
            NULL,
            'CRITICAL',
            'system.refresh_materialized_views',
            jsonb_build_object('error_time', CURRENT_TIMESTAMP)
        );

        -- Send critical alert
        PERFORM communication.send_alert(
            'MATERIALIZED_VIEW_REFRESH_CRITICAL_ERROR',
            'Materialized view refresh process failed with critical error',
            jsonb_build_object('error_message', v_error_message)
        );

        RAISE;
    END;
    $$;

    COMMENT ON PROCEDURE system.refresh_materialized_views IS 'Refresh all critical materialized views for reporting and analytics.
    Implements coordinated refresh of all critical materialized views, ensuring dashboards reflect current data. Processes views in
    dependency order to maintain data consistency. Includes sophisticated error handling to ensure partial failures don''t prevent
    completion. Times and logs each view refresh for performance monitoring. Tracks historical refresh statistics for optimization.
    Implements incremental refresh techniques for large data volumes. Validates integrity of refreshed data. Sends comprehensive
    notifications upon completion. Centralizes view refresh logic for consistent practices. Accommodates scheduled execution during
    off-peak hours. Handles resource constraints by adjusting refresh parallelism. Critical component of data pipeline for timely
    insights and data-driven decision making.';

  -- Serial No: 70 | TABLE: system.audit_logs
-- Description: Comprehensive audit trail system with detailed context
-- Business Case: The audit_logs table serves as the central repository for all audit-relevant
-- activities within the workforce scheduling system, providing complete visibility into
-- system operations and data changes. It captures detailed information about each action
-- including the actor, action performed, affected entities, and contextual information
-- about the operational environment. This information is critical for security monitoring,
-- compliance reporting, and forensic analysis in the event of security incidents. The
-- table supports multiple audit categories (scheduling, attendance, compliance, security,
-- system) to enable targeted analysis of specific operational areas. Comprehensive tracking
-- of data changes includes both previous and new states to support change analysis and
-- historical reconstruction. The implementation includes mechanisms for audit log protection
-- to prevent tampering and ensure the integrity of the audit trail. Historical audit data
-- is maintained for the required retention period to meet regulatory requirements. The
-- design accommodates high-volume audit logging during peak operational periods while
-- maintaining performance for business-critical operations. For sensitive operations, the
-- system captures additional context such as IP address and user agent to support security
-- investigations. By centralizing audit logging, the system reduces the complexity of
-- maintaining multiple audit trails while ensuring consistent coverage across all system
-- components. The table is optimized for rapid querying during security investigations
-- and compliance audits, with appropriate indexing on key audit dimensions. It serves as
-- the foundation for audit dashboards that provide real-time visibility into system
-- activity and potential security threats.
-- KPI: Audit coverage completeness, Audit log integrity,
--      Incident investigation time, Compliance audit success rate,
--      Audit data retention compliance
-- Feature Reference: 366, 367, 368, 369, 370
CREATE TABLE IF NOT EXISTS system.audit_logs (
    log_id BIGSERIAL PRIMARY KEY,
    log_uuid UUID DEFAULT uuid_generate_v4() UNIQUE,
    user_id UUID,
    user_role VARCHAR(50),
    user_location_id UUID,
    action VARCHAR(100) NOT NULL,
    action_category VARCHAR(50) NOT NULL CHECK (action_category IN ('SCHEDULING', 'ATTENDANCE', 'COMPLIANCE',
        'SECURITY', 'SYSTEM', 'INTEGRATION', 'REPORTING', 'ADMINISTRATION')),
    action_subcategory VARCHAR(50),
    entity_type VARCHAR(100),
    entity_id UUID,
    entity_name VARCHAR(255),
    previous_state JSONB,
    new_state JSONB,
    changed_fields TEXT[],
    ip_address INET,
    user_agent TEXT,
    client_application VARCHAR(100),
    session_id UUID,
    is_sensitive BOOLEAN NOT NULL DEFAULT FALSE,
    security_level VARCHAR(20) NOT NULL DEFAULT 'STANDARD'
        CHECK (security_level IN ('STANDARD', 'SENSITIVE', 'CONFIDENTIAL', 'SECRET')),
    occurred_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    processed_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    -- Fix: Use timestamp with time zone casting which is immutable
    date_created DATE GENERATED ALWAYS AS ((occurred_at AT TIME ZONE 'UTC')::DATE) STORED,
    hour_created INTEGER GENERATED ALWAYS AS (EXTRACT(HOUR FROM (occurred_at AT TIME ZONE 'UTC'))) STORED,
    CONSTRAINT fk_user FOREIGN KEY (user_id) REFERENCES hr.employees(employee_id) ON DELETE SET NULL,
    CONSTRAINT fk_user_location FOREIGN KEY (user_location_id) REFERENCES operations.locations(location_id) ON DELETE SET NULL
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_audit_logs_user ON system.audit_logs(user_id) WHERE user_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_audit_logs_action ON system.audit_logs(action_category, action);
CREATE INDEX IF NOT EXISTS idx_audit_logs_entity ON system.audit_logs(entity_type, entity_id)
    WHERE entity_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_audit_logs_time ON system.audit_logs(occurred_at DESC);
CREATE INDEX IF NOT EXISTS idx_audit_logs_sensitive ON system.audit_logs(is_sensitive) WHERE is_sensitive = TRUE;
CREATE INDEX IF NOT EXISTS idx_audit_logs_security ON system.audit_logs(security_level);
CREATE INDEX IF NOT EXISTS idx_audit_logs_ip ON system.audit_logs(ip_address) WHERE ip_address IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_audit_logs_session ON system.audit_logs(session_id) WHERE session_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_audit_logs_date ON system.audit_logs(date_created);
CREATE INDEX IF NOT EXISTS idx_audit_logs_hour ON system.audit_logs(hour_created);
CREATE INDEX IF NOT EXISTS idx_audit_logs_previous ON system.audit_logs USING GIN(previous_state)
    WHERE previous_state IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_audit_logs_new ON system.audit_logs USING GIN(new_state)
    WHERE new_state IS NOT NULL;

COMMENT ON TABLE system.audit_logs IS 'Comprehensive audit trail system with detailed context.
Serves as central repository for all audit-relevant activities, providing complete visibility into system operations. Captures
detailed information about each action including actor, action performed, and affected entities. Critical for security monitoring,
compliance reporting, and forensic analysis. Supports multiple audit categories for targeted analysis. Tracks data changes with
previous and new states. Includes mechanisms for audit log protection to prevent tampering. Maintains historical audit data for
regulatory requirements. Accommodates high-volume audit logging while maintaining performance. Captures additional context for
sensitive operations. Centralizes audit logging to reduce complexity while ensuring consistent coverage. Optimized for rapid
querying during security investigations and compliance audits. Serves as foundation for audit dashboards with real-time visibility.';

