    -- KPI: Metric standardization rate, Data quality assessment consistency,
    --      Scorecard completeness, Framework alignment rate,
    --      Metric adoption rate
    -- Feature Reference: 386, 387, 388, 389, 390
    DO $$BEGIN
        IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'metric_type_enum') THEN
            CREATE TYPE data_quality.metric_type_enum AS ENUM (
                'COMPLETENESS',           -- Percentage of required values that are present
                'ACCURACY',               -- Degree to which data correctly represents real-world values
                'CONSISTENCY',            -- Uniformity of data across systems and over time
                'TIMELINESS',             -- Availability of data within required timeframes
                'VALIDITY',               -- Conformance to defined business rules and formats
                'UNIQUENESS',             -- Absence of duplicate records
                'INTEGRITY',              -- Referential integrity and relationship consistency
                'DUPlication_RATE',       -- Rate of duplicate records
                'FORMAT_COMPLIANCE',      -- Adherence to defined data formats
                'RANGE_COMPLIANCE',       -- Values within expected ranges
                'REFERENCE_INTEGRITY',    -- Validity of reference data relationships
                'BUSINESS_RULE_COMPLIANCE' -- Adherence to specific business rules
            );
        END IF;
    END$$;
    COMMENT ON TYPE data_quality.metric_type_enum IS 'Defines types of data quality metrics for standardized measurement.
