    -- BRIN index for time-series audit data
    -- Serial No: 75 | INDEX: idx_audit_logs_date
    -- Purpose: Optimizes range queries on audit log dates
    -- Business Case: This BRIN (Block Range INdex) index is specifically designed for
    -- time-series data like audit logs, where values are naturally ordered by time.
    -- It provides excellent performance for range queries on large datasets while
    -- consuming significantly less storage space than traditional B-tree indexes.
    -- The index works by storing summary information about ranges of pages in the
    -- table, making it highly efficient for queries that filter by date ranges -
    -- the most common access pattern for audit log data. It is particularly valuable
    -- for historical analysis and compliance reporting queries that span extended
    -- time periods. The BRIN index structure also has lower maintenance overhead
    -- for bulk data loading operations, which is important for audit data that is
    -- frequently written in large batches. This indexing strategy ensures that
    -- audit-related queries remain efficient even as historical data accumulates
    -- over time, which is critical for meeting regulatory requirements for data
    -- retention and access. The index is optimized for the specific access patterns
    -- of audit data, where queries typically focus on recent data but must also
    -- support historical investigations spanning multiple years.
    -- KPI: Audit query performance, Historical query response time,
    --      Storage efficiency, Index maintenance overhead,
    --      Compliance reporting speed
    -- Feature Reference: 391, 392, 393, 394, 395
    CREATE INDEX IF NOT EXISTS idx_audit_logs_date ON system.audit_logs USING BRIN (occurred_at);

