    -- all changes to specific fields or values across different entity types.
    -- The design is particularly valuable for compliance and security investigations
    -- that require reconstructing historical data states or identifying specific
    -- change patterns. The GIN index structure is specifically designed for
    -- semi-structured JSON data, allowing flexible querying without requiring
    -- predefined schema constraints. This index is critical for maintaining
    -- responsive user interfaces during audit analysis, when users frequently
    -- need to drill down into specific changes or compare different versions
    -- of data. The implementation includes appropriate configuration parameters
    -- to balance index size with query performance for the specific characteristics
    -- of audit state data.
    -- KPI: Change tracking query performance, Audit analysis speed,
    --      Historical reconstruction time, Complex filter success rate,
    --      Index storage efficiency
    -- Feature Reference: 396, 397, 398, 399, 400
    CREATE INDEX IF NOT EXISTS idx_audit_logs_previous ON system.audit_logs USING GIN(previous_state)
        WHERE previous_state IS NOT NULL;


 -- Create the traffic_data table without the foreign key first
CREATE TABLE IF NOT EXISTS analytics.traffic_data (
    traffic_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    location_id UUID NOT NULL REFERENCES operations.locations(location_id) ON DELETE CASCADE,
    department_id UUID REFERENCES hr.departments(department_id) ON DELETE SET NULL,
    date DATE NOT NULL,
    hour_of_day INTEGER NOT NULL CHECK (hour_of_day BETWEEN 0 AND 23),
    traffic_count INTEGER NOT NULL CHECK (traffic_count >= 0),
    traffic_source VARCHAR(50) NOT NULL CHECK (traffic_source IN ('POS', 'SENSOR', 'MOBILE_APP', 'MANUAL', 'ESTIMATED')),
    data_confidence NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (data_confidence BETWEEN 0.00 AND 1.00),
    dwell_time_minutes NUMERIC(6,2) CHECK (dwell_time_minutes >= 0),
    conversion_rate NUMERIC(5,2) CHECK (conversion_rate BETWEEN 0.00 AND 100.00),
    is_peak_hour BOOLEAN NOT NULL DEFAULT FALSE,
    special_event_id UUID,
    weather_condition VARCHAR(50),
    temperature NUMERIC(5,2),
    precipitation NUMERIC(5,2),
    notes TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Then add the foreign key constraint conditionally
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_tables WHERE schemaname = 'external' AND tablename = 'local_events') THEN
        ALTER TABLE analytics.traffic_data 
        ADD CONSTRAINT fk_traffic_data_special_event 
        FOREIGN KEY (special_event_id) 
        REFERENCES external.local_events(event_id) 
        ON DELETE SET NULL;
    END IF;
END $$;



CREATE TABLE IF NOT EXISTS external.local_events (
    event_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    event_name VARCHAR(255) NOT NULL,
    event_date DATE NOT NULL,
    start_time TIME,
    end_time TIME,
    location_id UUID REFERENCES operations.locations(location_id),
    event_type VARCHAR(100),
    expected_attendance INTEGER,
    description TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Then create the traffic_data table (with the foreign key)
CREATE TABLE IF NOT EXISTS analytics.traffic_data (
    traffic_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    location_id UUID NOT NULL REFERENCES operations.locations(location_id) ON DELETE CASCADE,
    department_id UUID REFERENCES hr.departments(department_id) ON DELETE SET NULL,
    date DATE NOT NULL,
    hour_of_day INTEGER NOT NULL CHECK (hour_of_day BETWEEN 0 AND 23),
    traffic_count INTEGER NOT NULL CHECK (traffic_count >= 0),
    traffic_source VARCHAR(50) NOT NULL CHECK (traffic_source IN ('POS', 'SENSOR', 'MOBILE_APP', 'MANUAL', 'ESTIMATED')),
    data_confidence NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (data_confidence BETWEEN 0.00 AND 1.00),
    dwell_time_minutes NUMERIC(6,2) CHECK (dwell_time_minutes >= 0),
    conversion_rate NUMERIC(5,2) CHECK (conversion_rate BETWEEN 0.00 AND 100.00),
    is_peak_hour BOOLEAN NOT NULL DEFAULT FALSE,
    -- Now this foreign key will work
    special_event_id UUID REFERENCES external.local_events(event_id) ON DELETE SET NULL,
    weather_condition VARCHAR(50),
    temperature NUMERIC(5,2),
    precipitation NUMERIC(5,2),
    notes TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Serial No: 78 | TABLE: external.local_events
-- Description: Calendar of local events impacting business operations and staffing needs
-- Business Case: The local_events table maintains a comprehensive calendar of local events that impact business operations
-- and staffing requirements, such as festivals, sporting events, concerts, and construction projects. This information is
-- critical for proactive workforce planning, allowing organizations to anticipate fluctuations in customer traffic and
-- adjust staffing levels accordingly. The table supports multiple event types with different impact profiles, enabling
-- nuanced scheduling adjustments based on event characteristics. Each event record includes details about expected
-- attendance, duration, proximity to business locations, and historical impact data to inform scheduling decisions.
-- The implementation includes mechanisms for event impact scoring, allowing scheduling algorithms to prioritize events
-- with the greatest expected impact on operations. Historical event data is maintained to support predictive modeling
-- of event impacts based on past occurrences. The table also tracks event status changes (planned, confirmed, canceled)
-- to enable timely adjustments to staffing plans. For multi-location businesses, the system supports varying event
-- impacts across different locations based on proximity and relevance. The design accommodates both regularly scheduled
-- events (e.g., weekly farmers markets) and one-time events through flexible recurrence patterns. By centralizing event
-- information, the system enables consistent handling of event-based scheduling adjustments across the organization
-- while providing the flexibility needed for location-specific considerations. The table is optimized for rapid querying
-- during schedule creation to identify relevant upcoming events that should influence staffing decisions.
-- KPI: Event impact prediction accuracy, Staffing adjustment timeliness,
--      Event data completeness, Event-based scheduling effectiveness,
--      Event data quality score
