-- Now add constraints (these will fail if data violates them, so we add them separately)
DO $$
BEGIN
    -- Add primary key constraint if not exists
    IF NOT EXISTS (SELECT 1 FROM information_schema.table_constraints 
                   WHERE constraint_schema = 'external' 
                   AND table_name = 'local_events' 
                   AND constraint_type = 'PRIMARY KEY') THEN
        ALTER TABLE external.local_events ADD PRIMARY KEY (event_id);
        RAISE NOTICE 'Added primary key constraint';
    END IF;
    
    -- Add check constraints
    BEGIN
        ALTER TABLE external.local_events ADD CONSTRAINT chk_end_date_after_start_date 
        CHECK (end_date >= start_date);
        RAISE NOTICE 'Added date range constraint';
    EXCEPTION WHEN duplicate_object THEN
        RAISE NOTICE 'Date range constraint already exists';
    END;
    
    BEGIN
        ALTER TABLE external.local_events ADD CONSTRAINT chk_event_type 
        CHECK (event_type IN ('CONCERT', 'SPORTING_EVENT', 'FESTIVAL', 'CONFERENCE',
            'HOLIDAY', 'PARADE', 'STREET_FAIR', 'POLITICAL_EVENT', 'CONSTRUCTION', 
            'TRANSPORT_DISRUPTION', 'WEATHER_EVENT', 'COMMUNITY_EVENT'));
        RAISE NOTICE 'Added event_type constraint';
    EXCEPTION WHEN duplicate_object THEN
        RAISE NOTICE 'Event_type constraint already exists';
    END;
    
    BEGIN
        ALTER TABLE external.local_events ADD CONSTRAINT chk_event_status 
        CHECK (event_status IN ('PLANNED', 'CONFIRMED', 'CANCELLED', 'RESCHEDULED', 'COMPLETED'));
        RAISE NOTICE 'Added event_status constraint';
    EXCEPTION WHEN duplicate_object THEN
        RAISE NOTICE 'Event_status constraint already exists';
    END;
    
    -- Add foreign key constraints
    BEGIN
        ALTER TABLE external.local_events ADD CONSTRAINT fk_local_events_location 
        FOREIGN KEY (location_id) REFERENCES operations.locations(location_id);
        RAISE NOTICE 'Added location foreign key constraint';
    EXCEPTION WHEN duplicate_object THEN
        RAISE NOTICE 'Location foreign key constraint already exists';
    END;
    
END $$;

