        -- Serial No: 85 | TABLE: hr.attendance_records
        -- Description: Detailed employee attendance and time tracking data
        -- Business Case: The attendance_records table captures detailed time and attendance data for all employees,
        -- providing the foundation for accurate payroll processing and schedule adherence analysis. It records
        -- clock-in and clock-out times, breaks, and other attendance events with precise timestamps and location
        -- information. The table supports multiple time capture methods including biometric scanners, mobile apps,
        -- and manual entry, accommodating different business requirements and locations. Each record includes
        -- metadata about the data source, verification status, and any exceptions to standard attendance patterns.
        -- The implementation includes robust validation rules to detect common time theft patterns and attendance
        -- anomalies that may indicate schedule adherence issues. Historical attendance data is versioned to support
        -- trend analysis and performance evaluation over time. For compliance purposes, the system tracks the
        -- approval status of attendance records and maintains audit trails of all modifications. The table
        -- integrates with the scheduling system to compare planned versus actual attendance, enabling analysis
        -- of schedule adherence and identification of chronic tardiness or absenteeism. The design accommodates
        -- different attendance policies across departments and locations through flexible configuration options.
        -- By centralizing attendance data, the organization can ensure accurate payroll processing while gaining
        -- insights into workforce patterns that inform future scheduling decisions. The table is optimized for
        -- high-volume time capture operations, ensuring reliable performance during peak clock-in/clock-out periods.
        -- KPI: Attendance data accuracy rate, Schedule adherence rate,
        --      Time theft detection rate, Payroll processing accuracy,
        --      Attendance anomaly resolution time
        -- Feature Reference: 441, 442, 443, 444, 445
       CREATE TABLE IF NOT EXISTS hr.attendance_records (
    attendance_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    employee_id UUID NOT NULL REFERENCES hr.employees(employee_id) ON DELETE CASCADE,
    schedule_id UUID REFERENCES scheduling.schedules(schedule_id),
    shift_id UUID REFERENCES scheduling.shifts(shift_id),
    clock_in_time TIMESTAMP WITH TIME ZONE NOT NULL,
    clock_out_time TIMESTAMP WITH TIME ZONE,
    break_start_time TIMESTAMP WITH TIME ZONE,
    break_end_time TIMESTAMP WITH TIME ZONE,
    actual_work_hours NUMERIC(6,2) GENERATED ALWAYS AS (
        CASE
            WHEN clock_out_time IS NOT NULL AND clock_in_time IS NOT NULL
                THEN EXTRACT(EPOCH FROM (clock_out_time - clock_in_time -
                    COALESCE((break_end_time - break_start_time), INTERVAL '0'))) / 3600
            ELSE 0
        END
    ) STORED,
    scheduled_work_hours NUMERIC(6,2),
    attendance_status VARCHAR(50) NOT NULL DEFAULT 'SCHEDULED'
        CHECK (attendance_status IN ('SCHEDULED', 'PRESENT', 'ABSENT', 'TARDY', 'EARLY_LEAVE', 'ON_LEAVE', 'HOLIDAY')),
    time_capture_method VARCHAR(50) NOT NULL
        CHECK (time_capture_method IN ('BIOMETRIC', 'MOBILE_APP', 'WEB', 'MANUAL', 'AUTOMATED', 'KIOSK')),
    location_id UUID REFERENCES operations.locations(location_id),
    verification_status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
        CHECK (verification_status IN ('PENDING', 'VERIFIED', 'NEEDS_REVIEW', 'REJECTED')),
    verification_notes TEXT,
    verified_by UUID REFERENCES hr.employees(employee_id),
    verified_at TIMESTAMP WITH TIME ZONE,
    is_billable BOOLEAN NOT NULL DEFAULT TRUE,
    pay_rate_multiplier NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (pay_rate_multiplier >= 0.50 AND pay_rate_multiplier <= 3.00),
    exception_type VARCHAR(50) CHECK (exception_type IN ('SICK_LEAVE', 'VACATION', 'PERSONAL', 'HOLIDAY', 'TRAINING', 'OTHER')),
    exception_notes TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

