        -- robust validation rules to detect common payroll errors before they impact employee payments.
        -- Historical payroll data is maintained to support trend analysis, tax reporting, and compliance
        -- verification. For audit purposes, the system tracks all modifications to payroll records with
        -- detailed audit trails of who made changes and why. The table integrates with the time and
        -- attendance system to ensure payroll calculations align with actual worked hours and schedule
        -- assignments. The design accommodates complex payroll scenarios including multi-state taxation,
        -- union-specific rules, and industry-specific compensation structures. By centralizing payroll
        -- data, the organization can ensure accurate and timely employee payments while maintaining
        -- compliance with tax regulations and labor laws. The table is optimized for rapid processing
        -- during payroll runs, which often involve complex calculations across large employee populations.
        -- KPI: Payroll accuracy rate, Payroll processing time,
        --      Payroll error rate, Tax compliance rate,
        --      Payroll audit success rate
        -- Feature Reference: 446, 447, 448, 449, 450
       -- Create the table without generated columns
CREATE TABLE IF NOT EXISTS finance.payroll_records (
    payroll_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    employee_id UUID NOT NULL REFERENCES hr.employees(employee_id) ON DELETE CASCADE,
    pay_period_start DATE NOT NULL,
    pay_period_end DATE NOT NULL CHECK (pay_period_end >= pay_period_start),
    pay_date DATE NOT NULL,
    pay_frequency VARCHAR(20) NOT NULL CHECK (pay_frequency IN ('WEEKLY', 'BIWEEKLY', 'SEMIMONTHLY', 'MONTHLY')),
    regular_hours NUMERIC(6,2) DEFAULT 0.00 CHECK (regular_hours >= 0),
    overtime_hours NUMERIC(6,2) DEFAULT 0.00 CHECK (overtime_hours >= 0),
    regular_pay NUMERIC(10,2) DEFAULT 0.00 CHECK (regular_pay >= 0),
    overtime_pay NUMERIC(10,2) DEFAULT 0.00 CHECK (overtime_pay >= 0),
    bonus_pay NUMERIC(10,2) DEFAULT 0.00 CHECK (bonus_pay >= 0),
    other_earnings NUMERIC(10,2) DEFAULT 0.00,
    gross_pay NUMERIC(10,2) DEFAULT 0.00 CHECK (gross_pay >= 0),
    federal_tax NUMERIC(10,2) DEFAULT 0.00 CHECK (federal_tax >= 0),
    state_tax NUMERIC(10,2) DEFAULT 0.00 CHECK (state_tax >= 0),
    local_tax NUMERIC(10,2) DEFAULT 0.00 CHECK (local_tax >= 0),
    social_security NUMERIC(10,2) DEFAULT 0.00 CHECK (social_security >= 0),
    medicare NUMERIC(10,2) DEFAULT 0.00 CHECK (medicare >= 0),
    other_deductions NUMERIC(10,2) DEFAULT 0.00 CHECK (other_deductions >= 0),
    net_pay NUMERIC(10,2) DEFAULT 0.00 CHECK (net_pay >= 0),
    tax_jurisdiction VARCHAR(100) NOT NULL,
    calculation_rules_version VARCHAR(20) NOT NULL,
    status VARCHAR(20) NOT NULL DEFAULT 'CALCULATED'
        CHECK (status IN ('CALCULATED', 'VERIFIED', 'PROCESSED', 'PAID', 'REVERSED', 'ERROR')),
    payment_method VARCHAR(20) CHECK (payment_method IN ('DIRECT_DEPOSIT', 'CHECK', 'CASH')),
    direct_deposit_account VARCHAR(50),
    payroll_run_id UUID NOT NULL,
    processed_by UUID REFERENCES hr.employees(employee_id),
    processed_at TIMESTAMP WITH TIME ZONE,
    reversal_reason TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Create a trigger function to calculate gross_pay and net_pay
CREATE OR REPLACE FUNCTION calculate_payroll_amounts()
RETURNS TRIGGER AS $$
BEGIN
    NEW.gross_pay := NEW.regular_pay + NEW.overtime_pay + NEW.bonus_pay + NEW.other_earnings;
    NEW.net_pay := NEW.gross_pay - (NEW.federal_tax + NEW.state_tax + NEW.local_tax + 
                                    NEW.social_security + NEW.medicare + NEW.other_deductions);
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger
CREATE TRIGGER trg_calculate_payroll_amounts
BEFORE INSERT OR UPDATE OF regular_pay, overtime_pay, bonus_pay, other_earnings,
                          federal_tax, state_tax, local_tax, social_security, medicare, other_deductions
ON finance.payroll_records
FOR EACH ROW
EXECUTE FUNCTION calculate_payroll_amounts();

        -- Serial No: 87 | TABLE: scheduling.schedule_templates
        -- Description: Reusable schedule patterns with version control and validation
        -- Business Case: The schedule_templates table provides a centralized repository for schedule patterns
        -- that can be reused across multiple scheduling periods, ensuring consistency in scheduling practices
        -- while reducing the time and effort required to create new schedules. It captures proven scheduling
        -- approaches that meet business requirements and compliance constraints, allowing organizations to
        -- leverage historical knowledge in future scheduling efforts. The table supports versioning of templates
        -- to track evolution of scheduling patterns over time and enables A/B testing of different template
        -- approaches. Each template includes metadata about its performance, usage statistics, and compliance
        -- status to support data-driven selection of the most effective templates for specific contexts. The
        -- implementation includes validation rules to ensure templates adhere to business rules and regulatory
        -- requirements before deployment. Historical template data is maintained to support retrospective
        -- analysis of template effectiveness and identify opportunities for improvement. For compliance
        -- purposes, the system tracks the approval status of templates and maintains audit trails of all
        -- modifications. The table integrates with the scheduling engine to enable seamless application of
        -- templates to new scheduling periods. The design accommodates complex template structures including
        -- conditional rules that adapt to changing business conditions. By centralizing template management,
        -- the organization can preserve institutional knowledge about effective scheduling approaches while
        -- enabling rapid response to recurring business patterns. The table is optimized for rapid lookup
        -- during schedule creation, which is critical for user experience in the scheduling interface.
        -- KPI: Template usage rate, Template effectiveness score,
        --      Time saved through template usage, Template adaptation frequency,
        --      Template compliance rate
        -- Feature Reference: 451, 452, 453, 454, 455
        CREATE TABLE IF NOT EXISTS scheduling.schedule_templates (
            template_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
            template_code VARCHAR(50) UNIQUE NOT NULL CHECK (template_code ~ '^[A-Z0-9_]{5,50}$'),
            name VARCHAR(200) NOT NULL,
            description TEXT,
            location_id UUID REFERENCES operations.locations(location_id),
            department_id UUID REFERENCES hr.departments(department_id),
            position_id UUID REFERENCES hr.positions(position_id),
            template_type VARCHAR(50) NOT NULL DEFAULT 'STANDARD'
                CHECK (template_type IN ('STANDARD', 'SEASONAL', 'EVENT_BASED', 'CUSTOM')),
            recurrence_pattern VARCHAR(50) NOT NULL DEFAULT 'WEEKLY'
                CHECK (recurrence_pattern IN ('DAILY', 'WEEKLY', 'BIWEEKLY', 'MONTHLY', 'CUSTOM')),
            recurrence_details JSONB,
            effective_start_date DATE NOT NULL,
            effective_end_date DATE,
            pattern JSONB NOT NULL,
            is_active BOOLEAN NOT NULL DEFAULT TRUE,
            is_default BOOLEAN NOT NULL DEFAULT FALSE,
            priority INTEGER DEFAULT 0 CHECK (priority BETWEEN -10 AND 10),
            version INTEGER NOT NULL DEFAULT 1 CHECK (version >= 1),
            based_on_template_id UUID REFERENCES scheduling.schedule_templates(template_id),
            validated_by UUID REFERENCES hr.employees(employee_id),
            validated_at TIMESTAMP WITH TIME ZONE,
            validation_results JSONB,
            usage_count INTEGER NOT NULL DEFAULT 0,
            performance_score NUMERIC(5,2) CHECK (performance_score BETWEEN 0.00 AND 100.00),
            compliance_score NUMERIC(5,2) CHECK (compliance_score BETWEEN 0.00 AND 100.00),
            created_by UUID NOT NULL,
            updated_by UUID,
            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            metadata JSONB,

            -- Constraints
            CONSTRAINT chk_template_dates CHECK (effective_end_date IS NULL OR effective_end_date >= effective_start_date),
            CONSTRAINT chk_pattern_structure CHECK (
                jsonb_typeof(pattern) = 'object'
                AND pattern ? 'shifts'
                AND jsonb_typeof(pattern->'shifts') = 'array'
            )
        );

        -- Add indexes for performance
        CREATE INDEX IF NOT EXISTS idx_schedule_templates_location ON scheduling.schedule_templates(location_id) WHERE location_id IS NOT NULL;
        CREATE INDEX IF NOT EXISTS idx_schedule_templates_department ON scheduling.schedule_templates(department_id) WHERE department_id IS NOT NULL;
        CREATE INDEX IF NOT EXISTS idx_schedule_templates_position ON scheduling.schedule_templates(position_id) WHERE position_id IS NOT NULL;
        CREATE INDEX IF NOT EXISTS idx_schedule_templates_type ON scheduling.schedule_templates(template_type);
        CREATE INDEX IF NOT EXISTS idx_schedule_templates_active ON scheduling.schedule_templates(is_active) WHERE is_active = TRUE;
        CREATE INDEX IF NOT EXISTS idx_schedule_templates_default ON scheduling.schedule_templates(is_default) WHERE is_default = TRUE;
        CREATE INDEX IF NOT EXISTS idx_schedule_templates_based_on ON scheduling.schedule_templates(based_on_template_id);
     
        CREATE INDEX IF NOT EXISTS idx_schedule_templates_metadata ON scheduling.schedule_templates USING GIN(metadata);

        -- Add triggers for audit columns
        CREATE TRIGGER trg_schedule_templates_updated_at
        BEFORE UPDATE ON scheduling.schedule_templates
        FOR EACH ROW
        EXECUTE FUNCTION update_updated_at_column();

        COMMENT ON TABLE scheduling.schedule_templates IS 'Reusable schedule patterns with version control and validation.
        Provides centralized repository for schedule patterns that can be reused across multiple scheduling periods. Ensures
        consistency in scheduling practices while reducing time to create new schedules. Captures proven scheduling approaches
        that meet business requirements. Supports versioning to track evolution of patterns. Enables A/B testing of different
        approaches. Includes metadata about performance and compliance status. Includes validation rules to ensure adherence to
        business rules. Historical data maintained for retrospective analysis. Tracks approval status and audit trails. Integrates
        with scheduling engine for seamless application. Accommodates complex template structures with conditional rules.
        Centralizes template management to preserve institutional knowledge. Optimized for rapid lookup during schedule creation.';

        -- Serial No: 88 | TABLE: scheduling.schedule_history
        -- Description: Comprehensive historical record of schedule changes and versions
        -- Business Case: The schedule_history table maintains a complete historical record of all changes made to
        -- schedules, providing an audit trail for compliance, dispute resolution, and performance analysis. It
        -- captures both metadata changes (such as schedule status and approval information) and detailed shift
        -- assignment changes, enabling reconstruction of schedule states at any point in time. The table supports
        -- versioning of schedules with clear identification of who made changes and when, critical for
        -- accountability and regulatory compliance. Each historical record includes contextual information about
        -- the business environment at the time of the change, enabling accurate assessment of scheduling
        -- decisions during audits. The implementation includes robust security controls to protect the integrity
        -- of the historical record and prevent tampering. Historical schedule data is maintained for the required
        -- retention period to meet regulatory requirements and support trend analysis. For performance reasons,
        -- the system implements differential storage of changes rather than full copies of schedules, optimizing
        -- storage efficiency while maintaining complete historical information. The table also tracks the
        -- business rationale for significant changes to support audit inquiries and process improvement
        -- initiatives. By centralizing schedule history, the organization can ensure consistent tracking of
        -- schedule evolution across all locations and business units. The table is optimized for rapid querying
        -- during audit investigations and for generating required regulatory reports.
        -- KPI: Audit completeness rate, Historical data integrity,
        --      Dispute resolution time, Compliance audit success rate,
        --      Historical query performance
        -- Feature Reference: 456, 457, 458, 459, 460
        CREATE TABLE IF NOT EXISTS scheduling.schedule_history (
            history_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
            schedule_id UUID NOT NULL REFERENCES scheduling.schedules(schedule_id) ON DELETE CASCADE,
            version_number INTEGER NOT NULL,
            change_type VARCHAR(50) NOT NULL CHECK (change_type IN ('CREATION', 'MODIFICATION', 'APPROVAL', 'PUBLICATION', 'ARCHIVAL')),
            changed_by UUID NOT NULL REFERENCES hr.employees(employee_id),
            changed_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            change_reason TEXT,
            schedule_status scheduling.schedule_status_enum,
            start_date DATE,
            end_date DATE,
            location_id UUID,
            department_id UUID,
            template_id UUID,
            optimization_level VARCHAR(50),
            constraint_violation_count INTEGER,
            coverage_percentage NUMERIC(5,2),
            labor_cost_estimate NUMERIC(12,2),
            actual_labor_cost NUMERIC(12,2),
            performance_score NUMERIC(5,2),
            notes TEXT,
            approval_chain JSONB,
            published_at TIMESTAMP WITH TIME ZONE,
            archived_at TIMESTAMP WITH TIME ZONE,
            is_active BOOLEAN,
            change_details JSONB NOT NULL,
            created_by UUID NOT NULL,
            updated_by UUID,
            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
        );

        -- Add indexes for performance
        CREATE INDEX IF NOT EXISTS idx_schedule_history_schedule ON scheduling.schedule_history(schedule_id);
        CREATE INDEX IF NOT EXISTS idx_schedule_history_version ON scheduling.schedule_history(schedule_id, version_number DESC);
        CREATE INDEX IF NOT EXISTS idx_schedule_history_type ON scheduling.schedule_history(change_type);
        CREATE INDEX IF NOT EXISTS idx_schedule_history_changed ON scheduling.schedule_history(changed_at DESC);
        CREATE INDEX IF NOT EXISTS idx_schedule_history_by ON scheduling.schedule_history(changed_by);
        CREATE INDEX IF NOT EXISTS idx_schedule_history_status ON scheduling.schedule_history(schedule_status);
        CREATE INDEX IF NOT EXISTS idx_schedule_history_details ON scheduling.schedule_history USING GIN(change_details);

        -- Add triggers for audit columns
        CREATE TRIGGER trg_schedule_history_updated_at
        BEFORE UPDATE ON scheduling.schedule_history
        FOR EACH ROW
        EXECUTE FUNCTION update_updated_at_column();

        COMMENT ON TABLE scheduling.schedule_history IS 'Comprehensive historical record of schedule changes and versions.
        Maintains complete historical record of all changes made to schedules, providing audit trail for compliance and dispute
        resolution. Captures both metadata changes and detailed shift assignment changes. Supports versioning with identification
        of who made changes and when. Includes contextual information about business environment. Includes robust security controls
        to protect historical record. Historical data maintained for required retention period. Implements differential storage for
        storage efficiency. Tracks business rationale for significant changes. Centralizes schedule history for consistent tracking.
        Optimized for rapid querying during audit investigations.';

        -- Serial No: 89 | TABLE: analytics.performance_metrics
        -- Description: Employee and team performance measurement data
        -- Business Case: The performance_metrics table captures quantitative and qualitative performance data for
        -- employees and teams, providing insights that inform scheduling decisions and workforce development.
        -- It records key performance indicators such as productivity metrics, quality scores, customer satisfaction,
        -- and attendance records, enabling data-driven scheduling that considers both business needs and employee
        -- capabilities. The table supports multiple measurement methodologies including automated system metrics,
        -- manager evaluations, and customer feedback, accommodating different roles and business units. Each
        -- metric includes metadata about its calculation method, time period, and confidence level to ensure
        -- appropriate interpretation. The implementation includes historical tracking of performance trends to
        -- identify improvement areas and recognize high performers. For scheduling purposes, the system calculates
        -- performance scores that can be used as inputs to optimization algorithms, helping to match employees
        -- with shifts where they perform best. The table also tracks development goals and progress to support
        -- career planning and skill development. By centralizing performance data, the organization can ensure
        -- consistent evaluation criteria while providing the flexibility needed for role-specific assessments.
        -- The design accommodates different performance review cycles and rating scales across the organization.
        -- The table is optimized for rapid querying during schedule optimization, which often considers performance
        -- data when making shift assignment decisions.
        -- KPI: Performance measurement accuracy, Performance data completeness,
        --      Performance trend identification rate, Development goal achievement rate,
        --      Performance-based scheduling effectiveness
        -- Feature Reference: 461, 462, 463, 464, 465
        -- First create the teams table
CREATE TABLE IF NOT EXISTS hr.teams (
    team_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    team_name VARCHAR(100) NOT NULL,
    team_code VARCHAR(50) UNIQUE NOT NULL,
    description TEXT,
    department_id UUID REFERENCES hr.departments(department_id),
    manager_id UUID REFERENCES hr.employees(employee_id),
    location_id UUID REFERENCES operations.locations(location_id),
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Add indexes for teams table
CREATE INDEX IF NOT EXISTS idx_teams_name ON hr.teams(team_name);
CREATE INDEX IF NOT EXISTS idx_teams_code ON hr.teams(team_code);
CREATE INDEX IF NOT EXISTS idx_teams_department ON hr.teams(department_id) WHERE department_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_teams_manager ON hr.teams(manager_id) WHERE manager_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_teams_location ON hr.teams(location_id) WHERE location_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_teams_active ON hr.teams(is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_teams_metadata ON hr.teams USING GIN(metadata);

-- Add trigger for audit columns
CREATE TRIGGER trg_teams_updated_at
BEFORE UPDATE ON hr.teams
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE hr.teams IS 'Teams within the organization.
Stores information about employee teams, including team structure, management, and departmental associations.
Supports scheduling and performance tracking at the team level.';

-- Now create the performance_metrics table
CREATE TABLE IF NOT EXISTS analytics.performance_metrics (
    metric_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    employee_id UUID REFERENCES hr.employees(employee_id),
    team_id UUID REFERENCES hr.teams(team_id),
    metric_type VARCHAR(50) NOT NULL CHECK (metric_type IN ('PRODUCTIVITY', 'QUALITY', 'ATTENDANCE', 'CUSTOMER_SATISFACTION',
        'SAFETY', 'TRAINING', 'ENGAGEMENT', 'SKILL_PROFICIENCY')),
    metric_name VARCHAR(100) NOT NULL,
    metric_value NUMERIC(10,2) NOT NULL,
    value_unit VARCHAR(50) NOT NULL,
    calculation_method VARCHAR(100) NOT NULL,
    measurement_period_start DATE NOT NULL,
    measurement_period_end DATE NOT NULL CHECK (measurement_period_end >= measurement_period_start),
    data_source VARCHAR(100) NOT NULL,
    data_quality_score NUMERIC(5,2) CHECK (data_quality_score >= 0 AND data_quality_score <= 100),
    confidence_level VARCHAR(20) NOT NULL DEFAULT 'HIGH'
        CHECK (confidence_level IN ('LOW', 'MEDIUM', 'HIGH')),
    reviewer_id UUID REFERENCES hr.employees(employee_id),
    review_date DATE,
    comments TEXT,
    development_goals JSONB,
    development_progress JSONB,
    is_current BOOLEAN NOT NULL DEFAULT TRUE,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB,
    -- Ensure at least one of employee_id or team_id is provided
    CONSTRAINT check_performance_subject CHECK (
        (employee_id IS NOT NULL) OR (team_id IS NOT NULL)
    )
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_performance_metrics_employee ON analytics.performance_metrics(employee_id) WHERE employee_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_performance_metrics_team ON analytics.performance_metrics(team_id) WHERE team_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_performance_metrics_type ON analytics.performance_metrics(metric_type);
CREATE INDEX IF NOT EXISTS idx_performance_metrics_period ON analytics.performance_metrics(measurement_period_start, measurement_period_end);
CREATE INDEX IF NOT EXISTS idx_performance_metrics_current ON analytics.performance_metrics(is_current) WHERE is_current = TRUE;
CREATE INDEX IF NOT EXISTS idx_performance_metrics_reviewer ON analytics.performance_metrics(reviewer_id) WHERE reviewer_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_performance_metrics_value ON analytics.performance_metrics(metric_value);
CREATE INDEX IF NOT EXISTS idx_performance_metrics_quality ON analytics.performance_metrics(data_quality_score DESC);
CREATE INDEX IF NOT EXISTS idx_performance_metrics_metadata ON analytics.performance_metrics USING GIN(metadata);

-- Add triggers for audit columns
CREATE TRIGGER trg_performance_metrics_updated_at
BEFORE UPDATE ON analytics.performance_metrics
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE analytics.performance_metrics IS 'Employee and team performance measurement data.
Captures quantitative and qualitative performance data for employees and teams, informing scheduling decisions. Records
key performance indicators such as productivity metrics and customer satisfaction. Supports multiple measurement methodologies.
Includes metadata about calculation method and confidence level. Includes historical tracking of performance trends. Calculates
performance scores for optimization algorithms. Tracks development goals and progress. Centralizes performance data for
consistent evaluation. Accommodates different performance review cycles. Optimized for rapid querying during schedule
optimization.';

        -- Serial No: 90 | TABLE: analytics.forecasted_staffing
        -- Description: Predicted staffing requirements based on demand forecasting
        -- Business Case: The forecasted_staffing table stores predicted staffing requirements derived from business
        -- demand forecasts, historical patterns, and predictive analytics models. It provides the foundation for
        -- data-driven scheduling by translating anticipated customer traffic, transaction volumes, and service
        -- demands into specific staffing needs by role, time period, and location. The table captures both
        -- quantity and quality requirements, specifying not only how many staff are needed but also their
        -- required skills and experience levels. Historical forecast accuracy is tracked to continuously improve
        -- prediction models and build confidence in forecasting capabilities. The implementation includes
        -- confidence intervals for predictions to support risk-aware scheduling decisions that account for
        -- forecast uncertainty. For operational planning, the system stores multiple forecast scenarios
        -- (optimistic, pessimistic, baseline) to enable "what-if" analysis of different business conditions.
        -- The table integrates with scheduling templates to enable automated schedule generation that aligns
        -- with predicted staffing needs. The design accommodates seasonal patterns, special events, and
        -- external factors that influence staffing requirements. By centralizing forecasted staffing data,
        -- the organization can ensure schedules are built on accurate demand predictions rather than historical
        -- staffing levels or manager intuition. The table is optimized for rapid access during schedule
        -- generation, which requires timely staffing requirement data to create effective schedules.
        -- KPI: Forecast accuracy rate, Staffing alignment with forecast,
        --      Forecast update frequency, Impact of forecast errors on labor costs,
        --      Forecast confidence level
        -- Feature Reference: 466, 467, 468, 469, 470
        CREATE TABLE IF NOT EXISTS analytics.forecasted_staffing (
            forecast_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
            location_id UUID NOT NULL REFERENCES operations.locations(location_id),
            department_id UUID NOT NULL REFERENCES hr.departments(department_id),
            position_id UUID NOT NULL REFERENCES hr.positions(position_id),
            forecast_date DATE NOT NULL,
            time_period VARCHAR(20) NOT NULL CHECK (time_period IN ('HOURLY', 'DAILY', 'WEEKLY')),
            start_time TIMESTAMP WITH TIME ZONE NOT NULL,
            end_time TIMESTAMP WITH TIME ZONE NOT NULL CHECK (end_time > start_time),
            forecasted_staffing INTEGER NOT NULL CHECK (forecasted_staffing >= 0),
            forecast_method VARCHAR(50) NOT NULL,
            confidence_interval_low INTEGER,
            confidence_interval_high INTEGER,
            historical_staffing INTEGER,
            actual_staffing INTEGER,
            forecast_version VARCHAR(20) NOT NULL DEFAULT '1.0',
            outlier_reason TEXT,
            data_source VARCHAR(100) NOT NULL,
            refresh_frequency VARCHAR(50) CHECK (refresh_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY', 'MANUAL')),
            last_refreshed_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
            created_by UUID NOT NULL,
            updated_by UUID,
            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            metadata JSONB,

            -- Calculated fields
            variance_from_benchmark NUMERIC(15,4) GENERATED ALWAYS AS (
                CASE
                    WHEN historical_staffing IS NOT NULL AND historical_staffing > 0
                        THEN (forecasted_staffing::NUMERIC - historical_staffing) / historical_staffing * 100
                    ELSE NULL
                END
            ) STORED
        );

        -- Add indexes for performance
        CREATE INDEX IF NOT EXISTS idx_forecasted_staffing_location ON analytics.forecasted_staffing(location_id);
        CREATE INDEX IF NOT EXISTS idx_forecasted_staffing_department ON analytics.forecasted_staffing(department_id);
        CREATE INDEX IF NOT EXISTS idx_forecasted_staffing_position ON analytics.forecasted_staffing(position_id);
        CREATE INDEX IF NOT EXISTS idx_forecasted_staffing_date ON analytics.forecasted_staffing(forecast_date);
        CREATE INDEX IF NOT EXISTS idx_forecasted_staffing_time ON analytics.forecasted_staffing(start_time, end_time);
        CREATE INDEX IF NOT EXISTS idx_forecasted_staffing_method ON analytics.forecasted_staffing(forecast_method);
        CREATE INDEX IF NOT EXISTS idx_forecasted_staffing_version ON analytics.forecasted_staffing(forecast_id, forecast_version DESC);
        CREATE INDEX IF NOT EXISTS idx_forecasted_staffing_variance ON analytics.forecasted_staffing(variance_from_benchmark);
        CREATE INDEX IF NOT EXISTS idx_forecasted_staffing_metadata ON analytics.forecasted_staffing USING GIN(metadata);

        -- Add triggers for audit columns
        CREATE TRIGGER trg_forecasted_staffing_updated_at
        BEFORE UPDATE ON analytics.forecasted_staffing
        FOR EACH ROW
        EXECUTE FUNCTION update_updated_at_column();

        COMMENT ON TABLE analytics.forecasted_staffing IS 'Predicted staffing requirements based on demand forecasting.
        Stores predicted staffing requirements derived from business demand forecasts and predictive analytics. Provides foundation
        for data-driven scheduling by translating demand into specific staffing needs. Captures both quantity and quality requirements.
        Tracks historical forecast accuracy to improve prediction models. Includes confidence intervals for risk-aware decisions.
        Stores multiple forecast scenarios for "what-if" analysis. Integrates with scheduling templates for automated schedule
        generation. Accommodates seasonal patterns and special events. Centralizes forecasted staffing data for accurate schedule
        creation. Optimized for rapid access during schedule generation.';

        -- Serial No: 91 | TABLE: data_governance.data_profiles
        -- Description: Statistical data profiling results for quality assessment
        -- Business Case: The data_profiles table stores comprehensive statistical profiles of data across the
        -- database, providing objective measurements of data quality characteristics at the column level. It
        -- captures metrics such as null rates, uniqueness rates, value distributions, pattern compliance, and
        -- statistical outliers to support data quality assessment and trend analysis. These metrics are critical
        -- for identifying data quality issues before they impact business operations or decision making. The
        -- table supports historical tracking of quality metrics to identify trends and measure improvement
        -- over time. Each profile record includes metadata about the calculation method, execution frequency,
        -- and target values to support data quality goal setting and monitoring. The implementation includes
        -- mechanisms for automated profile calculation through scheduled jobs, ensuring timely assessment of
        -- data quality. For columns with defined data quality rules, the profiles are correlated with rule
        -- violations to provide context for quality issues. The table also tracks remediation efforts and
        -- their impact on quality metrics to demonstrate the value of data quality initiatives. By centralizing
        -- data profiling results, the system enables comprehensive data quality dashboards that provide
        -- visibility into data health across the organization. The design accommodates different metric types
        -- and calculation methods to support diverse data quality requirements. Historical profile data is
        -- used to establish baselines and detect anomalies that may indicate underlying data issues. The
        -- table is optimized for time-series analysis of quality metrics, supporting trend identification
        -- and predictive data quality management.
        -- KPI: Data completeness rate, Data uniqueness rate,
        --      Pattern compliance rate, Data quality trend direction,
        --      Data issue detection time
        -- Feature Reference: 471, 472, 473, 474, 475
        CREATE TABLE IF NOT EXISTS data_governance.data_profiles (
            profile_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
            schema_name VARCHAR(100) NOT NULL DEFAULT 'public',
            table_name VARCHAR(200) NOT NULL,
            column_name VARCHAR(200) NOT NULL,
            profile_date DATE NOT NULL DEFAULT CURRENT_DATE,
            total_count BIGINT NOT NULL CHECK (total_count >= 0),
            null_count BIGINT NOT NULL DEFAULT 0 CHECK (null_count >= 0),
            not_null_count BIGINT GENERATED ALWAYS AS (total_count - null_count) STORED,
            unique_count BIGINT,
            min_value TEXT,
            max_value TEXT,
            avg_value NUMERIC(20,4),
            median_value NUMERIC(20,4),
            std_dev NUMERIC(20,4),
            value_distribution JSONB,
            pattern_compliance_rate NUMERIC(5,2),
            outlier_count BIGINT,
            data_quality_score NUMERIC(5,2) CHECK (data_quality_score >= 0 AND data_quality_score <= 100),
            completeness_score NUMERIC(5,2) CHECK (completeness_score >= 0 AND completeness_score <= 100),
            validity_score NUMERIC(5,2) CHECK (validity_score >= 0 AND completeness_score <= 100),
            refresh_frequency VARCHAR(50) CHECK (refresh_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY', 'MANUAL')),
            last_refreshed_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
            created_by UUID NOT NULL,
            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
            updated_by UUID,
            updated_at TIMESTAMP WITH TIME ZONE,

            -- Constraints
            CONSTRAINT uq_table_column_date UNIQUE (schema_name, table_name, column_name, profile_date),
            CONSTRAINT fk_created_by FOREIGN KEY (created_by) REFERENCES hr.employees(employee_id) ON DELETE RESTRICT,
            CONSTRAINT chk_counts CHECK (null_count + not_null_count = total_count),
            CONSTRAINT chk_quality_scores CHECK (data_quality_score IS NULL OR
                (completeness_score IS NOT NULL AND validity_score IS NOT NULL))
        );

        -- Add indexes for performance
        CREATE INDEX IF NOT EXISTS idx_data_profiles_table ON data_governance.data_profiles(schema_name, table_name, column_name);
        CREATE INDEX IF NOT EXISTS idx_data_profiles_date ON data_governance.data_profiles(profile_date DESC);
        CREATE INDEX IF NOT EXISTS idx_data_profiles_quality ON data_governance.data_profiles(data_quality_score DESC);
        CREATE INDEX IF NOT EXISTS idx_data_profiles_completeness ON data_governance.data_profiles(completeness_score DESC);
        CREATE INDEX IF NOT EXISTS idx_data_profiles_validity ON data_governance.data_profiles(validity_score DESC);
        CREATE INDEX IF NOT EXISTS idx_data_profiles_nulls ON data_governance.data_profiles(null_count);
        CREATE INDEX IF NOT EXISTS idx_data_profiles_unique ON data_governance.data_profiles(unique_count);
        CREATE INDEX IF NOT EXISTS idx_data_profiles_distribution ON data_governance.data_profiles USING GIN(value_distribution);

        COMMENT ON TABLE data_governance.data_profiles IS 'Stores comprehensive data profiling statistics for data quality assessment and trend analysis.';

        -- Serial No: 92 | MATERIALIZED VIEW: data_governance.mv_column_quality_trends
        -- Purpose: Historical trends of column-level data quality metrics
        -- Business Case: This materialized view stores historical trends of column-level data quality metrics to
        -- support longitudinal analysis of data health. It aggregates metrics such as null rates, uniqueness rates,
        -- and pattern compliance over time to identify improvement or degradation in data quality. The view includes
        -- comparison against targets and thresholds to highlight areas requiring attention. It supports multiple
        -- time granularities (daily, weekly, monthly) to accommodate different analysis needs. Historical trend
        -- data is critical for demonstrating the value of data quality initiatives and securing investment in
        -- data governance programs. The materialized structure enables rapid query performance for trend analysis
        -- that would be too slow on operational tables. The view also includes benchmark comparisons against
        -- industry standards or internal best practices to provide context for quality measurements. It serves as
        -- the foundation for data quality scorecards that track progress against organizational data quality goals.
        -- The implementation includes anomaly detection logic to automatically identify unusual patterns in quality
        -- metrics that may indicate underlying data issues. By pre-computing these trends, the view enables
        -- sophisticated data quality analytics to be performed in real-time, supporting proactive data governance.
        -- The refresh process is optimized to minimize impact on operational systems while ensuring trend data
        -- remains sufficiently current for decision making. The view is designed to support both executive-level
        -- consumption of high-level trends and detailed analysis by data stewards investigating specific quality
        -- issues.
        -- KPI: Data quality trend direction, Target achievement rate,
        --      Anomaly detection rate, Data quality improvement rate,
        --      Trend analysis performance
        -- Feature Reference: 476, 477, 478, 479, 480
       CREATE MATERIALIZED VIEW IF NOT EXISTS data_governance.mv_column_quality_trends AS
SELECT
    schema_name,
    table_name,
    column_name,
    profile_date,
    data_quality_score,
    completeness_score,
    validity_score,
    null_percentage,
    LAG(data_quality_score) OVER (
        PARTITION BY schema_name, table_name, column_name
        ORDER BY profile_date
    ) as previous_quality_score,
    data_quality_score - LAG(data_quality_score) OVER (
        PARTITION BY schema_name, table_name, column_name
        ORDER BY profile_date
    ) as quality_score_change
FROM (
    SELECT
        schema_name,
        table_name,
        column_name,
        profile_date,  -- Added profile_date to the subquery SELECT
        data_quality_score,
        completeness_score,
        validity_score,
        (null_count::NUMERIC / NULLIF(total_count, 0)) * 100 as null_percentage
    FROM data_governance.data_profiles
    WHERE profile_date >= CURRENT_DATE - INTERVAL '2 years'
) as profile_data;

-- Create indexes on the materialized view
CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_column_quality_trends_full ON data_governance.mv_column_quality_trends
    (schema_name, table_name, column_name, profile_date);
CREATE INDEX IF NOT EXISTS idx_mv_column_quality_trends_table ON data_governance.mv_column_quality_trends
    (schema_name, table_name, column_name);
CREATE INDEX IF NOT EXISTS idx_mv_column_quality_trends_date ON data_governance.mv_column_quality_trends (profile_date);
CREATE INDEX IF NOT EXISTS idx_mv_column_quality_trends_trend ON data_governance.mv_column_quality_trends
    (quality_score_change DESC);

COMMENT ON MATERIALIZED VIEW data_governance.mv_column_quality_trends IS 'Historical trends of column-level data quality metrics.
Stores historical trends of column-level data quality metrics to support longitudinal analysis. Aggregates metrics such as null
rates and uniqueness rates over time. Includes comparison against targets and thresholds. Critical for demonstrating value of
data quality initiatives. Enables rapid query performance for trend analysis. Includes benchmark comparisons for context. Serves
as foundation for data quality scorecards. Includes anomaly detection logic. Enables sophisticated data quality analytics. Refresh
process optimized to minimize impact on operational systems. Supports both executive-level consumption and detailed analysis.';

        -- Serial No: 93 | TABLE: system.maintenance_jobs
        -- Description: Configuration and tracking of system maintenance operations
        -- Business Case: The maintenance_jobs table manages the scheduling and execution of background maintenance
        -- tasks that are critical for system health and performance. It provides a centralized repository for job
        -- definitions, schedules, and execution history, enabling consistent management of operational processes
        -- across the system. The table supports multiple job types including data archiving, index maintenance,
        -- statistics gathering, and custom business processes. Each job definition includes parameters for
        -- controlling execution behavior, retry logic, and resource allocation. The design accommodates
        -- dependencies between jobs to ensure proper execution order for complex maintenance workflows.
        -- Comprehensive tracking of job execution history enables performance analysis and troubleshooting of
        -- maintenance operations. The table also supports dynamic adjustment of job schedules based on system
        -- load and business priorities, optimizing resource utilization during maintenance windows. This
        -- functionality is essential for maintaining system performance and reliability, particularly in
        -- environments with large data volumes where maintenance operations can significantly impact
        -- availability. The implementation includes safeguards against job overlap and resource contention to
        -- prevent maintenance activities from interfering with operational workloads. By centralizing job
        -- management, the system ensures consistent execution of critical maintenance tasks while providing
        -- the flexibility needed for different operational requirements.
        -- KPI: Job execution success rate, Maintenance window utilization,
        --      System performance impact, Job completion time,
        --      Error resolution time
        -- Feature Reference: 481, 482, 483, 484, 485
        CREATE TABLE IF NOT EXISTS system.maintenance_jobs (
            job_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
            job_name VARCHAR(100) NOT NULL UNIQUE,
            job_type VARCHAR(50) NOT NULL CHECK (job_type IN ('DATA_ARCHIVE', 'INDEX_MAINTENANCE', 'STATISTICS_GATHERING',
                'DATA_REFRESH', 'CUSTOM', 'VACUUM_ANALYZE', 'DATA_PURGE', 'BACKUP', 'VALIDATION')),
            target_tables TEXT[],
            description TEXT,
            schedule_cron VARCHAR(50) NOT NULL,
            estimated_duration_minutes INTEGER NOT NULL CHECK (estimated_duration_minutes >= 0),
            max_duration_minutes INTEGER NOT NULL CHECK (max_duration_minutes >= estimated_duration_minutes),
            last_run_start TIMESTAMP WITH TIME ZONE,
            last_run_end TIMESTAMP WITH TIME ZONE,
            last_run_duration_minutes INTEGER GENERATED ALWAYS AS (
                CASE
                    WHEN last_run_start IS NOT NULL AND last_run_end IS NOT NULL
                        THEN EXTRACT(EPOCH FROM (last_run_end - last_run_start)) / 60
                    ELSE NULL
                END
            ) STORED,
            last_run_status VARCHAR(20) CHECK (last_run_status IN ('SUCCESS', 'FAILED', 'RUNNING', 'SKIPPED')),
            last_run_message TEXT,
            max_runtime INTERVAL DEFAULT INTERVAL '2 hours',
            retry_count INTEGER DEFAULT 0,
            max_retries INTEGER DEFAULT 3,
            retry_interval INTERVAL DEFAULT INTERVAL '5 minutes',
            is_active BOOLEAN NOT NULL DEFAULT TRUE,
            parameters JSONB,
            dependencies UUID[] DEFAULT '{}',
            resource_group VARCHAR(50),
            priority INTEGER DEFAULT 50 CHECK (priority BETWEEN 1 AND 100),
            created_by UUID NOT NULL,
            updated_by UUID,
            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
        );

        -- Add indexes for performance
        CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_schedule ON system.maintenance_jobs(schedule_cron);
        CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_status ON system.maintenance_jobs(last_run_status);
        CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_type ON system.maintenance_jobs(job_type);
        CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_active ON system.maintenance_jobs(is_active) WHERE is_active = TRUE;
        CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_dependencies ON system.maintenance_jobs USING GIN(dependencies);
        CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_parameters ON system.maintenance_jobs USING GIN(parameters);

        -- Add triggers for audit columns
        CREATE TRIGGER trg_maintenance_jobs_updated_at
        BEFORE UPDATE ON system.maintenance_jobs
        FOR EACH ROW
        EXECUTE FUNCTION update_updated_at_column();

        COMMENT ON TABLE system.maintenance_jobs IS 'Configuration and tracking of system maintenance operations.
        Manages scheduling and execution of background maintenance tasks critical for system health. Provides centralized repository
        for job definitions, schedules, and execution history. Supports multiple job types including data archiving and index maintenance.
        Includes parameters for execution behavior, retry logic, and resource allocation. Accommodates dependencies between jobs.
        Enables performance analysis and troubleshooting. Supports dynamic adjustment of schedules based on system load. Essential for
        maintaining system performance with large data volumes. Includes safeguards against job overlap and resource contention.
        Centralizes job management for consistent execution of critical tasks.';

       -- Serial No: 94 | TABLE: system.task_results
-- Description: Storage and management of task execution results
-- Business Case: The task_results table captures detailed results of background task executions, providing
-- visibility into task performance and outcomes. It stores both metadata about task execution (duration,
-- status, resource usage) and the actual results data produced by the task. The table supports multiple
-- task types including data processing jobs, report generation, and system maintenance operations. Each
-- result record includes contextual information about the operational environment during execution to
-- support troubleshooting of performance issues. Historical task data is maintained to identify trends
-- in task performance and detect degradation over time. The implementation includes mechanisms for
-- result retention management, automatically archiving or purging older results based on configurable
-- policies. For critical tasks, the system tracks execution metrics against service level objectives to
-- ensure tasks complete within acceptable timeframes. The table also supports result comparison across
-- executions to identify unexpected changes in task outputs. By centralizing task results, the organization
-- can ensure consistent monitoring of background operations while providing the data needed for capacity
-- planning and performance tuning. The design accommodates both structured result data (via JSONB storage)
-- and binary outputs (for reports and other artifacts). The table is optimized for rapid querying during
-- incident response and performance analysis, with appropriate indexing on key task characteristics.
-- KPI: Task execution success rate, Average task duration,
--      Resource utilization per task, SLA compliance rate,
--      Task failure resolution time
-- Feature Reference: 486, 487, 488, 489, 490
-- Serial No: 94 | TABLE: system.task_results
-- Description: Storage and management of task execution results
-- Business Case: The task_results table captures detailed results of background task executions, providing
-- visibility into task performance and outcomes. It stores both metadata about task execution (duration,
-- status, resource usage) and the actual results data produced by the task. The table supports multiple
-- task types including data processing jobs, report generation, and system maintenance operations. Each
-- result record includes contextual information about the operational environment during execution to
-- support troubleshooting of performance issues. Historical task data is maintained to identify trends
-- in task performance and detect degradation over time. The implementation includes mechanisms for
-- result retention management, automatically archiving or purging older results based on configurable
-- policies. For critical tasks, the system tracks execution metrics against service level objectives to
-- ensure tasks complete within acceptable timeframes. The table also supports result comparison across
-- executions to identify unexpected changes in task outputs. By centralizing task results, the organization
-- can ensure consistent monitoring of background operations while providing the data needed for capacity
-- planning and performance tuning. The design accommodates both structured result data (via JSONB storage)
-- and binary outputs (for reports and other artifacts). The table is optimized for rapid querying during
-- incident response and performance analysis, with appropriate indexing on key task characteristics.
-- KPI: Task execution success rate, Average task duration,
--      Resource utilization per task, SLA compliance rate,
--      Task failure resolution time
-- Feature Reference: 486, 487, 488, 489, 490
CREATE TABLE IF NOT EXISTS system.task_results (
    result_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    task_id UUID NOT NULL,
    task_name VARCHAR(100) NOT NULL,
    execution_id UUID NOT NULL,
    start_time TIMESTAMP WITH TIME ZONE NOT NULL,
    end_time TIMESTAMP WITH TIME ZONE NOT NULL,
    duration_ms INTEGER NOT NULL CHECK (duration_ms >= 0),
    status VARCHAR(20) NOT NULL CHECK (status IN ('SUCCESS', 'FAILED', 'RUNNING', 'CANCELLED')),
    error_message TEXT,
    result_summary JSONB,
    result_data BYTEA,
    result_size_kb INTEGER CHECK (result_size_kb >= 0),
    cpu_usage NUMERIC(5,2),
    memory_usage_mb INTEGER,
    rows_processed BIGINT,
    rows_affected BIGINT,
    error_category VARCHAR(50),
    affected_records_count INTEGER,
    server_hostname VARCHAR(100),
    retention_days INTEGER NOT NULL DEFAULT 90 CHECK (retention_days >= 0),
    -- Changed from GENERATED to regular column
    expiration_date DATE,
    is_archived BOOLEAN NOT NULL DEFAULT FALSE,
    security_level VARCHAR(20) NOT NULL DEFAULT 'INTERNAL'
        CHECK (security_level IN ('PUBLIC', 'INTERNAL', 'CONFIDENTIAL', 'RESTRICTED')),
    watermark_text TEXT,
    version INTEGER NOT NULL DEFAULT 1,
    metadata JSONB DEFAULT '{}'::JSONB,
    created_by UUID NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_by UUID,
    updated_at TIMESTAMP WITH TIME ZONE
);

-- Create a function to update expiration_date
CREATE OR REPLACE FUNCTION update_task_result_expiration()
RETURNS TRIGGER AS $$
BEGIN
    NEW.expiration_date := (NEW.start_time AT TIME ZONE 'UTC')::date + NEW.retention_days;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger to set expiration_date on insert and update
CREATE TRIGGER trg_task_results_expiration
    BEFORE INSERT OR UPDATE OF start_time, retention_days ON system.task_results
    FOR EACH ROW
    EXECUTE FUNCTION update_task_result_expiration();

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_task_results_task ON system.task_results(task_id);
CREATE INDEX IF NOT EXISTS idx_task_results_name ON system.task_results(task_name);
CREATE INDEX IF NOT EXISTS idx_task_results_time ON system.task_results(start_time DESC);
CREATE INDEX IF NOT EXISTS idx_task_results_status ON system.task_results(status);
CREATE INDEX IF NOT EXISTS idx_task_results_duration ON system.task_results(duration_ms);
CREATE INDEX IF NOT EXISTS idx_task_results_error ON system.task_results(error_category) WHERE error_category IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_task_results_metadata ON system.task_results USING GIN(metadata);

-- Add triggers for audit columns
CREATE TRIGGER trg_task_results_updated_at
BEFORE UPDATE ON system.task_results
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE system.task_results IS 'Storage and management of task execution results.
Captures detailed results of background task executions, providing visibility into task performance. Stores metadata and
actual results data. Supports multiple task types including data processing and report generation. Includes contextual
information for troubleshooting. Historical data maintained to identify performance trends. Includes mechanisms for result
retention management. Tracks execution metrics against service level objectives. Supports result comparison across executions.
Centralizes task results for consistent monitoring. Accommodates structured and binary outputs. Optimized for rapid querying
during incident response.';

        -- Serial No: 95 | PROCEDURE: system.archive_task_results
        -- Purpose: Archive and purge historical task results based on retention policies
        -- Business Case: This procedure implements the organization's data retention policies for task results by
        -- systematically identifying and processing records that have exceeded their retention period. It moves
        -- qualifying records to archive tables before permanent deletion, providing a recovery window for potentially
        -- valuable historical data. The procedure handles multiple retention categories with different timeframes,
        -- accommodating varying regulatory requirements across jurisdictions. The implementation processes data in
        -- batches to minimize performance impact and includes detailed logging of all actions for audit purposes.
        -- It also tracks statistics on data volume reduction to demonstrate the business value of retention policies.
        -- The procedure integrates with the organization's data classification system to apply appropriate handling
        -- for sensitive data during the retention process. For critical business data, it supports extended retention
        -- periods with proper justification and approval workflows. The procedure includes safeguards to prevent
        -- accidental deletion of active data and provides notifications before permanent deletion occurs. By
        -- automating data retention, the organization reduces legal risk, optimizes storage costs, and maintains
        -- system performance by managing data growth effectively. The procedure is designed to be executed as a
        -- scheduled job during off-peak hours to minimize operational impact while ensuring data governance
        -- requirements are met.
        -- KPI: Data volume reduction rate, Retention policy compliance rate,
        --      Storage cost savings, Data recovery success rate,
        --      Policy violation incidents
        -- Feature Reference: 491, 492, 493, 494, 495
        CREATE OR REPLACE PROCEDURE system.archive_task_results()
        LANGUAGE plpgsql
        SECURITY DEFINER
        AS $$
        DECLARE
            v_retention_days INTEGER := 90;
            v_archive_cutoff DATE := CURRENT_DATE - (v_retention_days * INTERVAL '1 day');
            v_archived_count INTEGER;
        BEGIN
            -- Log the start of the archiving process
            PERFORM system.log_activity(
                'TASK_RESULTS_ARCHIVE_START',
                'Starting task results archiving process',
                NULL,
                'INFO',
                'system.archive_task_results',
                jsonb_build_object('retention_cutoff', v_archive_cutoff)
            );

            BEGIN
                -- Create archive table if it doesn't exist
                CREATE TABLE IF NOT EXISTS system.task_results_archive (LIKE system.task_results INCLUDING ALL);

                -- Move old task results to archive
                WITH archived AS (
                    DELETE FROM system.task_results
                    WHERE expiration_date <= CURRENT_DATE
                    AND is_archived = FALSE
                    RETURNING *
                )
                INSERT INTO system.task_results_archive
                SELECT * FROM archived;

                GET DIAGNOSTICS v_archived_count = ROW_COUNT;

                -- Log successful archiving
                PERFORM system.log_activity(
                    'TASK_RESULTS_ARCHIVE_COMPLETE',
                    format('Archived %s task results older than %s', v_archived_count, v_archive_cutoff),
                    NULL,
                    'INFO',
                    'system.archive_task_results',
                    jsonb_build_object(
                        'retention_cutoff', v_archive_cutoff,
                        'archived_count', v_archived_count
                    )
                );

            EXCEPTION WHEN OTHERS THEN
                -- Log the error with detailed context
                PERFORM system.log_error(
                    'TASK_RESULTS_ARCHIVE_ERROR',
                    SQLERRM,
                    SQLSTATE,
                    NULL,
                    'CRITICAL',
                    'system.archive_task_results',
                    jsonb_build_object(
                        'retention_cutoff', v_archive_cutoff,
                        'error_time', NOW()
                    )
                );
                RAISE EXCEPTION 'Task results archiving process failed: %', SQLERRM;
            END;
        END;
        $$;

        COMMENT ON PROCEDURE system.archive_task_results IS 'Archive and purge historical task results based on retention policies.
        Implements data retention policies for task results by identifying and processing records exceeding retention period. Moves
        qualifying records to archive tables before permanent deletion. Handles multiple retention categories with different timeframes.
        Processes data in batches to minimize performance impact. Includes detailed logging for audit purposes. Tracks data volume
        reduction statistics. Integrates with data classification system. Supports extended retention periods with proper justification.
        Includes safeguards against accidental deletion. Provides notifications before permanent deletion. Automates data retention to
        reduce legal risk and optimize storage costs. Designed for scheduled execution during off-peak hours.';

        -- Serial No: 96 | PROCEDURE: system.validate_data_integrity
        -- Purpose: Comprehensive verification of database referential integrity and business rules
        -- Business Case: This procedure implements comprehensive data integrity verification across the database,
        -- checking for referential integrity violations, business rule compliance, and data consistency issues.
        -- It performs targeted validation of critical relationships such as employee-shift assignments, schedule-coverage
        -- requirements, and compliance rule applications. The procedure returns detailed results including the check
        -- name, status, number of issues found, and severity level to support prioritization of remediation efforts.
        -- It supports both ad-hoc verification and scheduled execution as part of regular data quality monitoring.
        -- The implementation includes configurable thresholds for acceptable issue counts, allowing organizations
        -- to define their tolerance for specific data quality issues. Historical verification results are tracked
        -- to identify recurring integrity problems and measure improvement over time. For identified issues, the
        -- procedure provides sufficient context to enable efficient remediation, including sample affected records
        -- and potential root causes. The verification process is designed to minimize performance impact through
        -- batch processing and selective checking of recently modified data. It also integrates with the data
        -- quality framework to log issues as formal data quality problems for tracking and resolution. By providing
        -- regular, automated verification of data integrity, this procedure helps maintain confidence in the accuracy
        -- and reliability of workforce scheduling data. The procedure is optimized for execution during off-peak
        -- hours to minimize impact on operational systems while ensuring data integrity is maintained within
        -- acceptable thresholds.
        -- KPI: Data integrity verification coverage, Integrity issue detection rate,
        --      False positive rate, Verification execution time,
        --      Issue resolution rate
        -- Feature Reference: 496, 497, 498, 499, 500
        CREATE OR REPLACE PROCEDURE system.validate_data_integrity()
        LANGUAGE plpgsql
        AS $$
        DECLARE
            v_result RECORD;
        BEGIN
            -- Log the start of the verification process
            PERFORM system.log_activity(
                'DATA_INTEGRITY_VERIFICATION_START',
                'Starting data integrity verification process',
                NULL,
                'INFO',
                'system.validate_data_integrity',
                jsonb_build_object('start_time', CURRENT_TIMESTAMP)
            );

            -- Check for orphaned shifts
            FOR v_result IN
                SELECT
                    'Orphaned shifts' AS check_name,
                    CASE WHEN COUNT(*) = 0 THEN 'PASS' ELSE 'FAIL' END AS check_status,
                    COUNT(*) AS issues_found,
                    'Shifts without valid employee reference' AS details,
                    'HIGH' AS severity
                FROM scheduling.shifts s
                LEFT JOIN hr.employees e ON s.employee_id = e.employee_id
                WHERE s.employee_id IS NOT NULL AND e.employee_id IS NULL
            LOOP
                INSERT INTO data_quality.data_quality_issues (
                    rule_id,
                    issue_code,
                    title,
                    description,
                    severity,
                    schema_name,
                    table_name,
                    column_name,
                    record_id,
                    record_details,
                    detected_at,
                    detected_by,
                    status,
                    created_by
                ) VALUES (
                    NULL,
                    'INTEGRITY_' || v_result.check_name,
                    v_result.check_name,
                    v_result.details,
                    v_result.severity,
                    'scheduling',
                    'shifts',
                    'employee_id',
                    NULL,
                    jsonb_build_object('issue_count', v_result.issues_found),
                    CURRENT_TIMESTAMP,
                    'SYSTEM',
                    CASE WHEN v_result.check_status = 'PASS' THEN 'RESOLVED' ELSE 'OPEN' END,
                    '00000000-0000-0000-0000-000000000000'
                );
            END LOOP;

            -- Check for invalid schedule dates
            FOR v_result IN
                SELECT
                    'Invalid schedule dates' AS check_name,
                    CASE WHEN COUNT(*) = 0 THEN 'PASS' ELSE 'FAIL' END AS check_status,
                    COUNT(*) AS issues_found,
                    'Schedules with end date before start date' AS details,
                    'CRITICAL' AS severity
                FROM scheduling.schedules
                WHERE end_date < start_date
            LOOP
                INSERT INTO data_quality.data_quality_issues (
                    rule_id,
                    issue_code,
                    title,
                    description,
                    severity,
                    schema_name,
                    table_name,
                    column_name,
                    record_id,
                    record_details,
                    detected_at,
                    detected_by,
                    status,
                    created_by
                ) VALUES (
                    NULL,
                    'INTEGRITY_' || v_result.check_name,
                    v_result.check_name,
                    v_result.details,
                    v_result.severity,
                    'scheduling',
                    'schedules',
                    'end_date',
                    NULL,
                    jsonb_build_object('issue_count', v_result.issues_found),
                    CURRENT_TIMESTAMP,
                    'SYSTEM',
                    CASE WHEN v_result.check_status = 'PASS' THEN 'RESOLVED' ELSE 'OPEN' END,
                    '00000000-0000-0000-0000-000000000000'
                );
            END LOOP;

            -- Check for schedule coverage gaps
            FOR v_result IN
                SELECT
                    'Schedule coverage gaps' AS check_name,
                    CASE WHEN MAX(coverage_percentage) < 90 THEN 'WARNING' ELSE 'PASS' END AS check_status,
                    COUNT(*) FILTER (WHERE coverage_percentage < 80) AS issues_found,
                    'Schedules with coverage below 80%' AS details,
                    'MEDIUM' AS severity
                FROM scheduling.schedules
                WHERE schedule_status IN ('PUBLISHED', 'EXECUTING')
            LOOP
                INSERT INTO data_quality.data_quality_issues (
                    rule_id,
                    issue_code,
                    title,
                    description,
                    severity,
                    schema_name,
                    table_name,
                    column_name,
                    record_id,
                    record_details,
                    detected_at,
                    detected_by,
                    status,
                    created_by
                ) VALUES (
                    NULL,
                    'INTEGRITY_' || v_result.check_name,
                    v_result.check_name,
                    v_result.details,
                    v_result.severity,
                    'scheduling',
                    'schedules',
                    'coverage_percentage',
                    NULL,
                    jsonb_build_object('issue_count', v_result.issues_found),
                    CURRENT_TIMESTAMP,
                    'SYSTEM',
                    CASE WHEN v_result.check_status = 'PASS' THEN 'RESOLVED' ELSE 'OPEN' END,
                    '00000000-0000-0000-0000-000000000000'
                );
            END LOOP;

            -- Log completion of the verification process
            PERFORM system.log_activity(
                'DATA_INTEGRITY_VERIFICATION_COMPLETE',
                'Completed data integrity verification process',
                NULL,
                'INFO',
                'system.validate_data_integrity',
                jsonb_build_object('completion_time', CURRENT_TIMESTAMP)
            );

        EXCEPTION WHEN OTHERS THEN
            -- Log critical error
            PERFORM system.log_error(
                'DATA_INTEGRITY_VERIFICATION_ERROR',
                SQLERRM,
                SQLSTATE,
                NULL,
                'CRITICAL',
                'system.validate_data_integrity',
                jsonb_build_object('error_time', NOW())
            );
            RAISE;
        END;
        $$;

        COMMENT ON PROCEDURE system.validate_data_integrity IS 'Comprehensive verification of database referential integrity and business rules.
        Implements comprehensive data integrity verification across the database. Checks for referential integrity violations and business
        rule compliance. Performs targeted validation of critical relationships. Returns detailed results for prioritization. Supports
        ad-hoc and scheduled execution. Includes configurable thresholds for issue tolerance. Tracks historical results for trend analysis.
        Provides context for efficient remediation. Minimizes performance impact through batch processing. Integrates with data quality
        framework. Helps maintain confidence in data accuracy. Optimized for off-peak execution to minimize operational impact.';

