-- across all system components. The table is optimized for rapid querying during security investigations
-- and user behavior analysis, with appropriate indexing on key activity dimensions. It serves as the
-- foundation for activity dashboards that provide real-time visibility into system usage and potential
-- security threats.
-- KPI: Activity log completeness, Security incident detection rate,
--      User behavior analysis accuracy, Incident investigation time,
--      Compliance audit success rate
-- Feature Reference: 501, 502, 503, 504, 505
CREATE TABLE IF NOT EXISTS security.user_activity_log (
    activity_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID NOT NULL REFERENCES hr.employees(employee_id) ON DELETE CASCADE,
    user_role VARCHAR(50),
    user_location_id UUID REFERENCES operations.locations(location_id) ON DELETE SET NULL,
    activity_category VARCHAR(50) NOT NULL CHECK (activity_category IN ('SCHEDULING', 'ATTENDANCE', 'COMPLIANCE',
        'SECURITY', 'SYSTEM', 'INTEGRATION', 'REPORTING', 'ADMINISTRATION')),
    activity_type VARCHAR(100) NOT NULL,
    activity_subcategory VARCHAR(50),
    target_entity_type VARCHAR(100),
    target_entity_id UUID,
    target_entity_name VARCHAR(255),
    activity_status VARCHAR(20) NOT NULL CHECK (activity_status IN ('SUCCESS', 'FAILURE', 'ATTEMPT')),
    activity_details JSONB,
    ip_address INET,
    user_agent TEXT,
    client_application VARCHAR(100),
    session_id UUID,
    is_sensitive BOOLEAN NOT NULL DEFAULT FALSE,
    security_level VARCHAR(20) NOT NULL DEFAULT 'STANDARD'
        CHECK (security_level IN ('STANDARD', 'SENSITIVE', 'CONFIDENTIAL', 'SECRET')),
    occurred_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    processed_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    -- FIXED: Use UTC for immutable date conversion
    date_created DATE GENERATED ALWAYS AS ((occurred_at AT TIME ZONE 'UTC')::date) STORED,
    hour_created INTEGER GENERATED ALWAYS AS (EXTRACT(HOUR FROM (occurred_at AT TIME ZONE 'UTC'))) STORED
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_user_activity_user ON security.user_activity_log(user_id);
CREATE INDEX IF NOT EXISTS idx_user_activity_category ON security.user_activity_log(activity_category, activity_type);
CREATE INDEX IF NOT EXISTS idx_user_activity_target ON security.user_activity_log(target_entity_type, target_entity_id)
    WHERE target_entity_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_user_activity_time ON security.user_activity_log(occurred_at DESC);
CREATE INDEX IF NOT EXISTS idx_user_activity_status ON security.user_activity_log(activity_status);
CREATE INDEX IF NOT EXISTS idx_user_activity_sensitive ON security.user_activity_log(is_sensitive) WHERE is_sensitive = TRUE;
CREATE INDEX IF NOT EXISTS idx_user_activity_security ON security.user_activity_log(security_level);
CREATE INDEX IF NOT EXISTS idx_user_activity_ip ON security.user_activity_log(ip_address) WHERE ip_address IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_user_activity_session ON security.user_activity_log(session_id) WHERE session_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_user_activity_date ON security.user_activity_log(date_created);
CREATE INDEX IF NOT EXISTS idx_user_activity_hour ON security.user_activity_log(hour_created);
CREATE INDEX IF NOT EXISTS idx_user_activity_details ON security.user_activity_log USING GIN(activity_details);

COMMENT ON TABLE security.user_activity_log IS 'Comprehensive tracking of user interactions with the system.
Captures detailed information about user interactions with the workforce scheduling system. Records significant actions with
contextual information. Critical for security monitoring and forensic investigations. Supports multiple activity categories.
Tracks successful and failed attempts for security analysis. Includes mechanisms for log protection. Historical data maintained
for regulatory requirements. Accommodates high-volume logging while maintaining performance. Captures additional context for
sensitive operations. Centralizes activity logging for consistent coverage. Optimized for rapid querying during investigations.
Serves as foundation for activity dashboards with real-time visibility.';

        -- Serial No: 98 | ENUM: communication.channel_type_enum
        -- Purpose: Defines communication channels for notifications and messages
        -- Business Case: This enumeration standardizes the communication channels used for sending notifications
        -- and messages within the workforce scheduling system. It provides a consistent set of channel options
        -- that can be reliably used across different modules and interfaces. The enumeration supports multiple
        -- communication methods including email, SMS, in-app notifications, and voice messages, accommodating
        -- different user preferences and operational requirements. It is critical for implementing targeted
        -- communication strategies based on message importance, user preferences, and delivery context. The
        -- channel types are designed to cover all common workforce communication scenarios while allowing for
        -- appropriate message handling based on channel characteristics. This standardization enables consistent
        -- user experience across the system and simplifies the implementation of communication features. The
        -- enumeration also supports future expansion as new communication channels become available, ensuring
        -- the system remains adaptable to evolving communication technologies. By providing this standardization,
        -- the enumeration enables meaningful aggregation and comparison of communication metrics across the
        -- enterprise, supporting data-driven decisions about communication channel effectiveness.
        -- KPI: Channel standardization rate, Communication consistency,
        --      Channel adoption rate, Channel performance metrics,
        --      User preference alignment rate
        -- Feature Reference: 506, 507, 508, 509, 510
        DO $$BEGIN
            IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'channel_type_enum') THEN
                CREATE TYPE communication.channel_type_enum AS ENUM (
                    'EMAIL',                -- Standard email communication
                    'SMS',                  -- Short Message Service (text messaging)
                    'IN_APP',               -- Notifications within the application
                    'VOICE_CALL',           -- Automated voice message
                    'PUSH_NOTIFICATION',    -- Mobile push notification
                    'WEBHOOK',              -- External system integration
                    'PRINTED',              -- Physical printed communication
                    'INTERNAL_MESSAGE'      -- System-to-system communication
                );
            END IF;
        END$$;
        COMMENT ON TYPE communication.channel_type_enum IS 'Defines communication channels for notifications and messages.
        EMAIL: Standard email communication; SMS: Short Message Service (text messaging); IN_APP: Notifications within the application;
        VOICE_CALL: Automated voice message; PUSH_NOTIFICATION: Mobile push notification; WEBHOOK: External system integration;
        PRINTED: Physical printed communication; INTERNAL_MESSAGE: System-to-system communication.';

        -- Serial No: 99 | ENUM: integration.webhook_event_enum
        -- Purpose: Defines event types for webhook integrations
        -- Business Case: This enumeration standardizes the event types that can trigger webhook integrations
        -- with external systems. It provides a consistent vocabulary for describing system events that may
        -- be of interest to external applications, ensuring reliable and predictable integration behavior.
        -- The enumeration covers common workforce scheduling events including schedule changes, shift assignments,
        -- time off requests, and compliance alerts. It is critical for implementing event-driven architecture
        -- that responds to system changes without requiring polling. The event types are designed to be
        -- granular enough to support targeted integrations while remaining manageable in scope. This
        -- standardization enables external systems to subscribe only to events that are relevant to their
        -- functionality, reducing unnecessary network traffic and processing overhead. The enumeration also
        -- supports future expansion as new integration scenarios emerge, ensuring the system remains adaptable
        -- to evolving integration requirements. By providing this standardization, the enumeration enables
        -- consistent handling of integration events across the organization and simplifies the implementation
        -- of new integrations. The event types are designed to align with common integration patterns in
        -- workforce management systems, facilitating interoperability with third-party applications.
        -- KPI: Integration standardization rate, Event delivery reliability,
        --      Integration development time, Event processing performance,
        --      Integration error rate
        -- Feature Reference: 511, 512, 513, 514, 515
        DO $$BEGIN
            IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'webhook_event_enum') THEN
                CREATE TYPE integration.webhook_event_enum AS ENUM (
                    'SCHEDULE_CREATED',     -- New schedule created
                    'SCHEDULE_UPDATED',     -- Schedule modified
                    'SCHEDULE_PUBLISHED',   -- Schedule published to employees
                    'SCHEDULE_LOCKED',      -- Schedule locked for modification
                    'SHIFT_ASSIGNED',       -- Shift assigned to employee
                    'SHIFT_UPDATED',        -- Shift details modified
                    'SHIFT_COVERED',        -- Shift coverage status changed
                    'SHIFT_SWAP_REQUESTED', -- Shift swap request created
                    'SHIFT_SWAP_APPROVED',  -- Shift swap request approved
                    'TIME_OFF_REQUESTED',   -- Time off request submitted
                    'TIME_OFF_APPROVED',    -- Time off request approved
                    'ATTENDANCE_RECORDED',  -- Attendance record created
                    'PAYROLL_PROCESSED',    -- Payroll run completed
                    'COMPLIANCE_ALERT',     -- Compliance violation detected
                    'SYSTEM_HEALTH_ALERT'   -- System performance or health issue
                );
            END IF;
        END$$;
        COMMENT ON TYPE integration.webhook_event_enum IS 'Defines event types for webhook integrations.
        SCHEDULE_CREATED: New schedule created; SCHEDULE_UPDATED: Schedule modified; SCHEDULE_PUBLISHED: Schedule published to employees;
        SCHEDULE_LOCKED: Schedule locked for modification; SHIFT_ASSIGNED: Shift assigned to employee; SHIFT_UPDATED: Shift details modified;
        SHIFT_COVERED: Shift coverage status changed; SHIFT_SWAP_REQUESTED: Shift swap request created; SHIFT_SWAP_APPROVED: Shift swap request approved;
        TIME_OFF_REQUESTED: Time off request submitted; TIME_OFF_APPROVED: Time off request approved; ATTENDANCE_RECORDED: Attendance record created;
        PAYROLL_PROCESSED: Payroll run completed; COMPLIANCE_ALERT: Compliance violation detected; SYSTEM_HEALTH_ALERT: System performance or health issue.';

        -- Serial No: 100 | VIEW: reporting.v_employee_engagement
        -- Purpose: Analysis of employee engagement metrics and scheduling impact
        -- Business Case: This view provides analytical insights into the relationship between scheduling practices
        -- and employee engagement metrics, supporting data-driven decisions to improve workforce satisfaction.
        -- It combines data from schedule assignments, shift preferences, attendance records, and performance
        -- metrics to identify patterns that correlate with higher or lower engagement. The view includes metrics
        -- at multiple levels of granularity (individual, team, department) to support different management
        -- perspectives. Historical trend data is presented with appropriate statistical analysis to distinguish
        -- meaningful patterns from random fluctuations. The design accommodates different engagement measurement
        -- methodologies across business units while providing a consistent analytical framework. The view serves
        -- as the foundation for engagement scorecards that track progress against organizational engagement goals.
        -- It also supports root cause analysis of engagement issues by identifying scheduling factors that may
        -- contribute to disengagement. For strategic planning, the view provides the necessary data to evaluate
        -- the potential impact of scheduling policy changes on workforce engagement. By centralizing engagement
        -- data, the view reduces the time and effort required to analyze scheduling impacts and enables proactive
        -- management of workforce satisfaction. The implementation includes benchmark comparisons against industry
        -- standards to provide context for engagement performance. The view is optimized for performance with
        -- pre-aggregated metrics where possible, ensuring responsive analytics even with large historical datasets.
        -- It enables data-driven decisions about scheduling practices that balance business needs with employee
        -- satisfaction.
        -- KPI: Schedule preference fulfillment rate, Employee satisfaction score,
        --      Turnover risk score, Absenteeism rate,
        --      Engagement trend direction
        -- Feature Reference: 516, 517, 518, 519, 520
        CREATE OR REPLACE VIEW reporting.v_employee_engagement AS
        SELECT
            e.employee_id,
            e.employee_code,
            e.first_name,
            e.last_name,
            p.position_title,
            d.department_name,
            l.location_name,
            AVG(CASE WHEN pm.metric_type = 'ENGAGEMENT' THEN pm.metric_value ELSE NULL END) AS engagement_score,
            AVG(CASE WHEN pm.metric_type = 'SATISFACTION' THEN pm.metric_value ELSE NULL END) AS satisfaction_score,
            COUNT(CASE WHEN ar.attendance_status = 'ABSENT' THEN 1 END) AS absenteeism_count,
            COUNT(CASE WHEN ar.attendance_status = 'TARDY' THEN 1 END) AS tardiness_count,
            COUNT(CASE WHEN ssr.status = 'COMPLETED' THEN 1 END) AS swap_requests_count,
            COUNT(CASE WHEN ssr.status = 'COMPLETED' AND ssr.swap_conditions IS NOT NULL THEN 1 END) AS conditional_swaps_count,
            COUNT(CASE WHEN sp.preference_type = 'PREFERRED' THEN 1 END) AS preferred_shifts_count,
            COUNT(CASE WHEN sp.preference_type = 'AVOID' THEN 1 END) AS avoided_shifts_count,
            COUNT(CASE WHEN s.shift_status = 'NO_SHOW' THEN 1 END) AS no_show_count,
            COUNT(CASE WHEN s.shift_status = 'EARLY_LEAVE' THEN 1 END) AS early_leave_count,
            COUNT(CASE WHEN s.shift_status = 'LATE_ARRIVAL' THEN 1 END) AS late_arrival_count,
            COUNT(CASE WHEN tor.request_type = 'VACATION' THEN 1 END) AS vacation_requests_count,
            COUNT(CASE WHEN tor.status = 'APPROVED' THEN 1 END) AS approved_time_off_count,
            COUNT(CASE WHEN tor.status = 'APPROVED' AND tor.request_type = 'VACATION' THEN 1 END) AS approved_vacation_count
        FROM hr.employees e
        JOIN hr.positions p ON e.position_id = p.position_id
        JOIN hr.departments d ON e.department_id = d.department_id
        JOIN operations.locations l ON e.location_id = l.location_id
        LEFT JOIN analytics.performance_metrics pm ON e.employee_id = pm.employee_id AND pm.is_current = TRUE
        LEFT JOIN hr.attendance_records ar ON e.employee_id = ar.employee_id AND ar.clock_in_time >= CURRENT_DATE - INTERVAL '90 days'
        LEFT JOIN scheduling.shift_swap_requests ssr ON e.employee_id = ssr.requesting_employee_id AND ssr.requested_at >= CURRENT_DATE - INTERVAL '90 days'
        LEFT JOIN scheduling.shift_preferences sp ON e.employee_id = sp.employee_id AND sp.start_date <= CURRENT_DATE AND (sp.end_date IS NULL OR sp.end_date >= CURRENT_DATE)
        LEFT JOIN scheduling.shifts s ON e.employee_id = s.employee_id AND s.start_time >= CURRENT_DATE - INTERVAL '90 days'
        LEFT JOIN hr.time_off_requests tor ON e.employee_id = tor.employee_id AND tor.start_date <= CURRENT_DATE + INTERVAL '90 days' AND (tor.end_date >= CURRENT_DATE OR tor.end_date IS NULL)
        GROUP BY e.employee_id, e.employee_code, e.first_name, e.last_name, p.position_title, d.department_name, l.location_name;

        COMMENT ON VIEW reporting.v_employee_engagement IS 'Analysis of employee engagement metrics and scheduling impact.
        Provides analytical insights into relationship between scheduling practices and employee engagement. Combines data from schedule
        assignments, shift preferences, attendance records, and performance metrics. Includes metrics at multiple levels of granularity.
        Historical trend data presented with statistical analysis. Accommodates different engagement measurement methodologies. Serves
        as foundation for engagement scorecards. Supports root cause analysis of engagement issues. Provides data for evaluating impact
        of scheduling policy changes. Reduces time and effort for analyzing scheduling impacts. Includes benchmark comparisons for context.
        Optimized for performance with pre-aggregated metrics. Enables data-driven decisions balancing business needs with employee satisfaction.';


            -- Serial No: 101 | TABLE: finance.budgets
            -- Description: Departmental and organizational budget planning and tracking
            -- Business Case: The budgets table serves as the central repository for financial planning and tracking
            -- within the workforce scheduling system, enabling organizations to align staffing decisions with
            -- financial constraints. It captures both historical and projected labor costs by department,
            -- location, and time period, providing the foundation for cost-aware scheduling. The table supports
            -- multiple budgeting methodologies including zero-based budgeting, incremental budgeting, and
            -- activity-based budgeting, accommodating different organizational approaches to financial planning.
            -- Each budget record includes metadata about its approval status, variance thresholds, and
            -- forecasting methodology to support proper governance of the budgeting process. The implementation
            -- includes robust tracking of actual versus budgeted labor costs, enabling early identification
            -- of potential overruns. Historical budget data is maintained to support trend analysis and
            -- improve future budget accuracy. For compliance purposes, the system tracks the approval status
            -- of budgets and maintains audit trails of all modifications. The table integrates with the
            -- scheduling engine to enable cost-aware scheduling that respects budget constraints while
            -- meeting operational requirements. The design accommodates complex budgeting scenarios including
            -- seasonal variations, special projects, and multi-year planning horizons. By centralizing
            -- budget information, the organization can ensure schedules are built within financial constraints
            -- while providing visibility into the financial impact of scheduling decisions. The table is
            -- optimized for rapid access during schedule optimization, which often considers budget data
            -- when making staffing decisions.
            -- KPI: Budget adherence rate, Forecast accuracy rate,
            --      Budget variance identification time, Budget approval timeliness,
            --      Cost-per-unit-of-output
            -- Feature Reference: 521, 522, 523, 524, 525
            CREATE TABLE IF NOT EXISTS finance.budgets (
                budget_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                budget_code VARCHAR(50) UNIQUE NOT NULL CHECK (budget_code ~ '^[A-Z0-9_]{3,50}$'),
                name VARCHAR(200) NOT NULL,
                description TEXT,
                location_id UUID REFERENCES operations.locations(location_id),
                department_id UUID REFERENCES hr.departments(department_id),
                position_id UUID REFERENCES hr.positions(position_id),
                budget_type VARCHAR(50) NOT NULL DEFAULT 'OPERATIONAL'
                    CHECK (budget_type IN ('OPERATIONAL', 'CAPITAL', 'PROJECT', 'DEPARTMENT', 'LOCATION', 'ENTERPRISE')),
                budget_period VARCHAR(20) NOT NULL DEFAULT 'MONTHLY'
                    CHECK (budget_period IN ('DAILY', 'WEEKLY', 'BIWEEKLY', 'MONTHLY', 'QUARTERLY', 'ANNUAL')),
                start_date DATE NOT NULL,
                end_date DATE NOT NULL CHECK (end_date >= start_date),
                amount NUMERIC(14,2) NOT NULL CHECK (amount >= 0),
                actual_amount NUMERIC(14,2) DEFAULT 0 CHECK (actual_amount >= 0),
                variance_threshold NUMERIC(5,2) NOT NULL DEFAULT 5.00
                    CHECK (variance_threshold BETWEEN 0.00 AND 100.00),
                variance_amount NUMERIC(14,2) GENERATED ALWAYS AS (actual_amount - amount) STORED,
                variance_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
                    CASE
                        WHEN amount > 0 THEN (actual_amount - amount) / amount * 100
                        ELSE 0
                    END
                ) STORED,
                budget_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
                    CHECK (budget_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'FINAL', 'ARCHIVED')),
                approval_chain JSONB,
                approved_by UUID REFERENCES hr.employees(employee_id),
                approved_at TIMESTAMP WITH TIME ZONE,
                forecast_method VARCHAR(50) NOT NULL DEFAULT 'HISTORICAL'
                    CHECK (forecast_method IN ('HISTORICAL', 'TREND_BASED', 'SEASONAL', 'MACHINE_LEARNING', 'MANUAL')),
                notes TEXT,
                created_by UUID NOT NULL,
                updated_by UUID,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_budgets_location ON finance.budgets(location_id) WHERE location_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_budgets_department ON finance.budgets(department_id) WHERE department_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_budgets_position ON finance.budgets(position_id) WHERE position_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_budgets_period ON finance.budgets(start_date, end_date);
            CREATE INDEX IF NOT EXISTS idx_budgets_type ON finance.budgets(budget_type);
            CREATE INDEX IF NOT EXISTS idx_budgets_status ON finance.budgets(budget_status);
            CREATE INDEX IF NOT EXISTS idx_budgets_variance ON finance.budgets(variance_percentage DESC);
            CREATE INDEX IF NOT EXISTS idx_budgets_metadata ON finance.budgets USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_budgets_updated_at
            BEFORE UPDATE ON finance.budgets
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

            COMMENT ON TABLE finance.budgets IS 'Departmental and organizational budget planning and tracking.
            Serves as central repository for financial planning and tracking within the workforce scheduling system. Enables alignment
            of staffing decisions with financial constraints. Captures historical and projected labor costs by department and location.
            Supports multiple budgeting methodologies including zero-based and activity-based budgeting. Includes metadata about approval
            status and variance thresholds. Tracks actual versus budgeted labor costs for early identification of overruns. Historical
            data maintained for trend analysis. Tracks approval status and audit trails for compliance. Integrates with scheduling engine
            for cost-aware scheduling. Accommodates complex budgeting scenarios including seasonal variations. Centralizes budget information
            for schedules within financial constraints. Optimized for rapid access during schedule optimization.';

            -- Serial No: 102 | TABLE: analytics.forecast_models
            -- Description: Configuration and metadata for demand forecasting models
            -- Business Case: The forecast_models table stores configuration details and metadata for all demand
            -- forecasting models used within the workforce scheduling system, providing a centralized repository
            -- for forecasting capabilities. It captures essential information about each model including its
            -- methodology, input features, performance metrics, and deployment status to ensure consistent
            -- application of forecasting techniques. The table supports multiple forecasting approaches
            -- including time series models, machine learning algorithms, and hybrid approaches, accommodating
            -- different business needs and data characteristics. Each model record includes metadata about
            -- its validation results, confidence intervals, and expected performance under various conditions
            -- to support appropriate model selection for specific forecasting scenarios. Historical model
            -- performance is tracked to identify opportunities for improvement and to build confidence in
            -- forecasting capabilities. The implementation includes versioning of models to track evolution
            -- over time and enable A/B testing of different forecasting approaches. For operational planning,
            -- the system stores model parameters and hyperparameters to ensure reproducibility of forecasting
            -- results. The table integrates with the scheduling engine to enable seamless application of
            -- forecasts to staffing decisions. The design accommodates seasonal patterns, special events,
            -- and external factors that influence demand forecasting. By centralizing forecast model
            -- information, the organization can ensure consistent and accurate demand predictions that
            -- inform effective workforce planning. The table is optimized for rapid lookup during forecast
            -- generation, which requires timely access to model configurations to produce accurate staffing
            -- requirements.
            -- KPI: Forecast accuracy rate, Model selection appropriateness,
            --      Forecast update frequency, Impact of forecast errors on labor costs,
            --      Model performance degradation rate
            -- Feature Reference: 526, 527, 528, 529, 530
            CREATE TABLE IF NOT EXISTS analytics.forecast_models (
                model_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                model_code VARCHAR(50) UNIQUE NOT NULL CHECK (model_code ~ '^[A-Z0-9_]{3,50}$'),
                name VARCHAR(200) NOT NULL,
                description TEXT,
                model_type VARCHAR(50) NOT NULL CHECK (model_type IN ('ARIMA', 'EXPONENTIAL_SMOOTHING', 'REGRESSION',
                    'RANDOM_FOREST', 'GRADIENT_BOOSTING', 'NEURAL_NETWORK', 'PROPHET', 'ENSEMBLE')),
                forecast_target VARCHAR(50) NOT NULL CHECK (forecast_target IN ('CUSTOMER_TRAFFIC', 'TRANSACTIONS',
                    'SALES', 'SERVICE_DEMAND', 'STAFFING_REQUIREMENTS')),
                location_id UUID REFERENCES operations.locations(location_id),
                department_id UUID REFERENCES hr.departments(department_id),
                position_id UUID REFERENCES hr.positions(position_id),
                input_features JSONB NOT NULL,
                model_parameters JSONB,
                hyperparameters JSONB,
                training_data_start DATE,
                training_data_end DATE,
                training_data_size INTEGER CHECK (training_data_size >= 0),
                validation_metrics JSONB,
                accuracy_metrics JSONB,
                confidence_interval NUMERIC(5,2) NOT NULL DEFAULT 95.00
                    CHECK (confidence_interval BETWEEN 50.00 AND 99.99),
                forecast_horizon VARCHAR(20) NOT NULL CHECK (forecast_horizon IN ('SHORT_TERM', 'MEDIUM_TERM', 'LONG_TERM')),
                refresh_frequency VARCHAR(20) NOT NULL CHECK (refresh_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY')),
                status VARCHAR(20) NOT NULL DEFAULT 'DEVELOPMENT'
                    CHECK (status IN ('DEVELOPMENT', 'TESTING', 'APPROVED', 'DEPLOYED', 'DEPRECATED')),
                version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                is_active BOOLEAN NOT NULL DEFAULT TRUE,
                created_by UUID NOT NULL,
                updated_by UUID,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_forecast_models_type ON analytics.forecast_models(model_type);
            CREATE INDEX IF NOT EXISTS idx_forecast_models_target ON analytics.forecast_models(forecast_target);
            CREATE INDEX IF NOT EXISTS idx_forecast_models_location ON analytics.forecast_models(location_id) WHERE location_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_forecast_models_department ON analytics.forecast_models(department_id) WHERE department_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_forecast_models_position ON analytics.forecast_models(position_id) WHERE position_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_forecast_models_status ON analytics.forecast_models(status);
            CREATE INDEX IF NOT EXISTS idx_forecast_models_active ON analytics.forecast_models(is_active) WHERE is_active = TRUE;
            CREATE INDEX IF NOT EXISTS idx_forecast_models_version ON analytics.forecast_models(model_id, version_number DESC);
            CREATE INDEX IF NOT EXISTS idx_forecast_models_features ON analytics.forecast_models USING GIN(input_features);
            CREATE INDEX IF NOT EXISTS idx_forecast_models_metadata ON analytics.forecast_models USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_forecast_models_updated_at
            BEFORE UPDATE ON analytics.forecast_models
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

            COMMENT ON TABLE analytics.forecast_models IS 'Configuration and metadata for demand forecasting models.
            Stores configuration details and metadata for all demand forecasting models used within the workforce scheduling system.
            Provides centralized repository for forecasting capabilities. Captures methodology, input features, and performance metrics.
            Supports multiple forecasting approaches including time series and machine learning models. Includes metadata about validation
            results and confidence intervals. Historical performance tracked for improvement opportunities. Includes versioning for
            evolution tracking and A/B testing. Stores model parameters for reproducibility. Integrates with scheduling engine for
            seamless application to staffing decisions. Accommodates seasonal patterns and special events. Centralizes forecast model
            information for consistent demand predictions. Optimized for rapid lookup during forecast generation.';




            -- Serial No: 104 | TABLE: hr.survey_templates
            -- Description: Standardized survey structures for consistent feedback collection
            -- Business Case: The survey_templates table provides a standardized framework for collecting employee
            -- feedback, ensuring consistency in how satisfaction and other workforce metrics are measured over
            -- time. It defines the structure, questions, and response options for different types of surveys,
            -- enabling meaningful comparison of results across time periods and organizational units. The
            -- table supports multiple survey types including scheduling satisfaction, work-life balance,
            -- and general engagement surveys, accommodating different feedback collection needs. Each template
            -- includes metadata about its purpose, target audience, and expected completion time to support
            -- appropriate deployment. The implementation includes versioning of templates to track changes
            -- over time while maintaining historical consistency in measurement. Historical template data
            -- is maintained to support retrospective analysis of survey methodology evolution. For compliance
            -- purposes, the system tracks the approval status of templates and maintains audit trails of all
            -- modifications. The table integrates with the survey distribution system to enable automated
            -- survey deployment based on scheduling events or time-based triggers. The design accommodates
            -- complex survey logic including conditional questions and branching paths based on previous
            -- responses. By centralizing survey templates, the organization can ensure consistent measurement
            -- of workforce metrics while providing the flexibility needed for different feedback scenarios.
            -- The table is optimized for rapid lookup during survey deployment, which is critical for timely
            -- feedback collection following scheduling events.
            -- KPI: Template usage rate, Survey consistency score,
            --      Feedback collection efficiency, Template adaptation frequency,
            --      Survey data quality score
            -- Feature Reference: 536, 537, 538, 539, 540
            CREATE TABLE IF NOT EXISTS hr.survey_templates (
                survey_template_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                template_code VARCHAR(50) UNIQUE NOT NULL CHECK (template_code ~ '^[A-Z0-9_]{5,50}$'),
                name VARCHAR(200) NOT NULL,
                description TEXT,
                survey_type VARCHAR(50) NOT NULL CHECK (survey_type IN ('SCHEDULING_SATISFACTION', 'WORK_LIFE_BALANCE',
                    'GENERAL_ENGAGEMENT', 'SHIFT_SWAP_SATISFACTION', 'MANAGER_FEEDBACK', 'ONBOARDING_FEEDBACK')),
                target_audience JSONB NOT NULL DEFAULT '{"all_employees": true}'::JSONB,
                expected_completion_time_minutes INTEGER NOT NULL CHECK (expected_completion_time_minutes > 0),
                is_active BOOLEAN NOT NULL DEFAULT TRUE,
                is_default BOOLEAN NOT NULL DEFAULT FALSE,
                version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                based_on_template_id UUID REFERENCES hr.survey_templates(survey_template_id),
                validated_by UUID REFERENCES hr.employees(employee_id),
                validated_at TIMESTAMP WITH TIME ZONE,
                validation_results JSONB,
                usage_count INTEGER NOT NULL DEFAULT 0,
                questions JSONB NOT NULL,
                response_options JSONB,
                scoring_rules JSONB,
                distribution_rules JSONB,
                created_by UUID NOT NULL,
                updated_by UUID,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB,

                -- Constraints
                CONSTRAINT chk_questions_structure CHECK (
                    jsonb_typeof(questions) = 'array'
                    AND jsonb_array_length(questions) > 0
                    AND NOT (questions @? '$[*] ? (@.question_text == "")')
                )
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_survey_templates_type ON hr.survey_templates(survey_type);
            CREATE INDEX IF NOT EXISTS idx_survey_templates_active ON hr.survey_templates(is_active) WHERE is_active = TRUE;
            CREATE INDEX IF NOT EXISTS idx_survey_templates_default ON hr.survey_templates(is_default) WHERE is_default = TRUE;
            CREATE INDEX IF NOT EXISTS idx_survey_templates_version ON hr.survey_templates(survey_template_id, version_number DESC);
            CREATE INDEX IF NOT EXISTS idx_survey_templates_based_on ON hr.survey_templates(based_on_template_id);
            CREATE INDEX IF NOT EXISTS idx_survey_templates_questions ON hr.survey_templates USING GIN(questions);
            CREATE INDEX IF NOT EXISTS idx_survey_templates_metadata ON hr.survey_templates USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_survey_templates_updated_at
            BEFORE UPDATE ON hr.survey_templates
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

            COMMENT ON TABLE hr.survey_templates IS 'Standardized survey structures for consistent feedback collection.
            Provides standardized framework for collecting employee feedback, ensuring consistency in measurement. Defines structure,
            questions, and response options for different survey types. Supports multiple survey types including satisfaction and
            engagement surveys. Includes metadata about purpose and target audience. Includes versioning to track changes over time.
            Historical data maintained for retrospective analysis. Tracks approval status and audit trails for compliance. Integrates
            with survey distribution system for automated deployment. Accommodates complex survey logic including conditional questions.
            Centralizes survey templates for consistent metric measurement. Optimized for rapid lookup during survey deployment.';



            -- Serial No: 103 | TABLE: hr.employee_surveys
            -- Description: Employee feedback and satisfaction measurement data
            -- Business Case: The employee_surveys table captures structured feedback from employees regarding
            -- their satisfaction with scheduling practices, work-life balance, and other workforce management
            -- factors. It provides valuable insights that inform scheduling policy improvements and help identify
            -- areas needing attention. The table supports multiple survey methodologies including periodic
            -- satisfaction surveys, pulse surveys, and post-schedule feedback requests, accommodating different
            -- feedback collection strategies. Each survey response includes metadata about the timing, context,
            -- and employee demographics to enable meaningful analysis of feedback patterns. The implementation
            -- includes robust validation rules to detect response bias and ensure data quality. Historical
            -- survey data is maintained to track satisfaction trends over time and measure the impact of
            -- scheduling changes. For compliance purposes, the system tracks the anonymity status of surveys
            -- and maintains appropriate privacy controls for sensitive feedback. The table integrates with the
            -- scheduling system to correlate feedback with specific scheduling practices and identify
            -- relationships between scheduling factors and employee satisfaction. The design accommodates
            -- both quantitative ratings and qualitative comments, providing a comprehensive view of employee
            -- sentiment. By centralizing survey data, the organization can ensure consistent analysis of
            -- employee feedback while maintaining appropriate privacy controls. The table is optimized for
            -- rapid querying during satisfaction analysis, which often involves identifying patterns across
            -- large employee populations.
            -- KPI: Survey response rate, Employee satisfaction score,
            --      Feedback implementation rate, Trend identification rate,
            --      Survey data quality score
            -- Feature Reference: 531, 532, 533, 534, 535
            CREATE TABLE IF NOT EXISTS hr.employee_surveys (
                survey_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                employee_id UUID REFERENCES hr.employees(employee_id),
                survey_template_id UUID NOT NULL REFERENCES hr.survey_templates(survey_template_id),
                survey_date DATE NOT NULL DEFAULT CURRENT_DATE,
                is_anonymous BOOLEAN NOT NULL DEFAULT FALSE,
                response_json JSONB NOT NULL,
                overall_score NUMERIC(4,2) CHECK (overall_score BETWEEN 1.0 AND 5.0),
                feedback_text TEXT,
                manager_id UUID REFERENCES hr.employees(employee_id),
                department_id UUID REFERENCES hr.departments(department_id),
                location_id UUID REFERENCES operations.locations(location_id),
                schedule_id UUID REFERENCES scheduling.schedules(schedule_id),
                shift_preferences_fulfilled BOOLEAN,
                preferred_shifts_count INTEGER DEFAULT 0,
                avoided_shifts_count INTEGER DEFAULT 0,
                response_quality_score NUMERIC(4,2) DEFAULT 1.0 CHECK (response_quality_score BETWEEN 0.0 AND 1.0),
                sentiment_score NUMERIC(4,2) CHECK (sentiment_score BETWEEN -1.0 AND 1.0),
                is_follow_up BOOLEAN NOT NULL DEFAULT FALSE,
                follow_up_date DATE,
                follow_up_response TEXT,
                created_by UUID NOT NULL,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_by UUID,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_employee_surveys_employee ON hr.employee_surveys(employee_id) WHERE employee_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_employee_surveys_template ON hr.employee_surveys(survey_template_id);
            CREATE INDEX IF NOT EXISTS idx_employee_surveys_date ON hr.employee_surveys(survey_date DESC);
            CREATE INDEX IF NOT EXISTS idx_employee_surveys_score ON hr.employee_surveys(overall_score);
            CREATE INDEX IF NOT EXISTS idx_employee_surveys_anonymous ON hr.employee_surveys(is_anonymous) WHERE is_anonymous = TRUE;
            CREATE INDEX IF NOT EXISTS idx_employee_surveys_department ON hr.employee_surveys(department_id) WHERE department_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_employee_surveys_location ON hr.employee_surveys(location_id) WHERE location_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_employee_surveys_schedule ON hr.employee_surveys(schedule_id) WHERE schedule_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_employee_surveys_response ON hr.employee_surveys USING GIN(response_json);
            CREATE INDEX IF NOT EXISTS idx_employee_surveys_metadata ON hr.employee_surveys USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_employee_surveys_updated_at
            BEFORE UPDATE ON hr.employee_surveys
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

            COMMENT ON TABLE hr.employee_surveys IS 'Employee feedback and satisfaction measurement data.
            Captures structured feedback from employees regarding satisfaction with scheduling practices. Provides insights for scheduling
            policy improvements. Supports multiple survey methodologies including periodic and pulse surveys. Includes metadata about timing
            and context for meaningful analysis. Includes validation rules to detect response bias. Historical data maintained for trend
            tracking. Tracks anonymity status and privacy controls for compliance. Integrates with scheduling system to correlate feedback
            with practices. Accommodates both quantitative ratings and qualitative comments. Centralizes survey data for consistent analysis.
            Optimized for rapid querying during satisfaction analysis.';


            -- Serial No: 105 | TABLE: analytics.model_performance
            -- Description: Historical performance metrics for forecasting and optimization models
            -- Business Case: The model_performance table stores historical performance metrics for all predictive
            -- models used within the workforce scheduling system, providing the foundation for model evaluation
            -- and improvement. It captures key performance indicators such as accuracy, precision, recall, and
            -- error rates across different time periods and business conditions. This information is critical
            -- for selecting the most appropriate models for specific forecasting scenarios and identifying
            -- opportunities for model improvement. The table supports multiple model types including demand
            -- forecasting, scheduling optimization, and employee preference prediction models, accommodating
            -- different evaluation metrics for each type. Each performance record includes metadata about the
            -- evaluation methodology, data used, and business context to ensure meaningful comparison of model
            -- performance. Historical performance data is versioned to track evolution of model effectiveness
            -- over time and measure the impact of model improvements. The implementation includes mechanisms
            -- for performance benchmarking against industry standards or internal targets to provide context
            -- for model evaluation. For operational planning, the system stores performance metrics by business
            -- segment to enable targeted model selection based on specific operational characteristics. The
            -- table integrates with the model management system to enable data-driven decisions about model
            -- deployment and retirement. The design accommodates different performance evaluation timeframes
            -- from short-term to long-term assessments. By centralizing model performance data, the organization
            -- can ensure consistent evaluation criteria while providing the flexibility needed for role-specific
            -- model assessments. The table is optimized for rapid querying during model selection, which often
            -- considers historical performance when choosing models for specific forecasting needs.
            -- KPI: Model accuracy trend, Model selection appropriateness,
            --      Performance degradation rate, Model improvement impact,
            --      Benchmark achievement rate
            -- Feature Reference: 541, 542, 543, 544, 545
            CREATE TABLE IF NOT EXISTS analytics.model_performance (
                performance_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                model_id UUID NOT NULL,
                model_type VARCHAR(50) NOT NULL CHECK (model_type IN ('DEMAND_FORECAST', 'SCHEDULING_OPTIMIZATION',
                    'PREFERENCE_PREDICTION', 'COMPLIANCE_PREDICTION', 'ATTENDANCE_PREDICTION')),
                evaluation_start_date DATE NOT NULL,
                evaluation_end_date DATE NOT NULL CHECK (evaluation_end_date >= evaluation_start_date),
                evaluation_method VARCHAR(50) NOT NULL CHECK (evaluation_method IN ('HOLDOUT', 'CROSS_VALIDATION',
                    'TIME_SERIES_SPLIT', 'BACKTESTING')),
                evaluation_frequency VARCHAR(20) NOT NULL CHECK (evaluation_frequency IN ('DAILY', 'WEEKLY', 'MONTHLY')),
                metrics JSONB NOT NULL,
                accuracy NUMERIC(5,2) CHECK (accuracy BETWEEN 0.00 AND 100.00),
                precision NUMERIC(5,2) CHECK (precision BETWEEN 0.00 AND 100.00),
                recall NUMERIC(5,2) CHECK (recall BETWEEN 0.00 AND 100.00),
                f1_score NUMERIC(5,2) CHECK (f1_score BETWEEN 0.00 AND 100.00),
                mean_absolute_error NUMERIC(10,4),
                root_mean_squared_error NUMERIC(10,4),
                business_impact JSONB,
                data_quality_score NUMERIC(5,2) CHECK (data_quality_score BETWEEN 0.00 AND 100.00),
                evaluation_notes TEXT,
                is_current BOOLEAN NOT NULL DEFAULT TRUE,
                created_by UUID NOT NULL,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_by UUID,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_model_performance_model ON analytics.model_performance(model_id);
            CREATE INDEX IF NOT EXISTS idx_model_performance_type ON analytics.model_performance(model_type);
            CREATE INDEX IF NOT EXISTS idx_model_performance_date ON analytics.model_performance(evaluation_start_date, evaluation_end_date);
            CREATE INDEX IF NOT EXISTS idx_model_performance_method ON analytics.model_performance(evaluation_method);
            CREATE INDEX IF NOT EXISTS idx_model_performance_current ON analytics.model_performance(is_current) WHERE is_current = TRUE;
            CREATE INDEX IF NOT EXISTS idx_model_performance_accuracy ON analytics.model_performance(accuracy DESC);
            CREATE INDEX IF NOT EXISTS idx_model_performance_metrics ON analytics.model_performance USING GIN(metrics);
            CREATE INDEX IF NOT EXISTS idx_model_performance_metadata ON analytics.model_performance USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_model_performance_updated_at
            BEFORE UPDATE ON analytics.model_performance
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

            COMMENT ON TABLE analytics.model_performance IS 'Historical performance metrics for forecasting and optimization models.
            Stores historical performance metrics for all predictive models used within the workforce scheduling system. Captures key
            performance indicators such as accuracy and error rates. Critical for selecting appropriate models and identifying improvements.
            Supports multiple model types with different evaluation metrics. Includes metadata about evaluation methodology and context.
            Historical data versioned to track evolution of effectiveness. Includes mechanisms for performance benchmarking. Stores metrics
            by business segment for targeted model selection. Integrates with model management system for data-driven decisions.
            Accommodates different evaluation timeframes. Centralizes performance data for consistent evaluation. Optimized for rapid
            querying during model selection.';


