 -- Serial No: 107 | TABLE: analytics.sales_data
            -- Description: Historical sales and transaction data for workforce planning
            -- Business Case: The sales_data table captures historical sales and transaction data from point-of-sale
            -- systems and other sales channels, providing critical input for workforce planning and scheduling.
            -- It records detailed information about sales volume, transaction counts, and customer traffic patterns
            -- at granular time intervals to support accurate demand forecasting. The table supports multiple sales
            -- channels including in-store, online, and mobile transactions, accommodating different business models.
            -- Each sales record includes metadata about the business context, such as promotions, holidays, and
            -- special events that may influence sales patterns. Historical sales data is versioned to support trend
            -- analysis and seasonal pattern identification. The implementation includes data quality metrics to
            -- indicate confidence levels for each sales measurement, enabling more informed forecasting decisions.
            -- For predictive scheduling, the table integrates with forecasting models to project future sales based
            -- on historical patterns, calendar events, and external factors. The design accommodates different sales
            -- measurement methodologies while providing a consistent interface for forecasting algorithms. The table
            -- is optimized for time-series analysis with appropriate indexing on temporal dimensions and location
            -- attributes. By centralizing sales data, the system enables data-driven scheduling that responds to
            -- actual sales patterns rather than relying solely on historical staffing levels or manager intuition.
            -- The implementation includes mechanisms for handling data gaps and anomalies to maintain forecasting
            -- accuracy during unusual business periods.
            -- KPI: Sales prediction accuracy, Staffing alignment with sales,
            --      Service level achievement, Sales per labor hour,
            --      Sales data quality score
            -- Feature Reference: 551, 552, 553, 554, 555
        CREATE TABLE IF NOT EXISTS analytics.sales_data (
    sales_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    location_id UUID NOT NULL REFERENCES operations.locations(location_id) ON DELETE CASCADE,
    sales_date DATE NOT NULL CHECK (sales_date >= DATE '2020-01-01'),
    sales_time TIME NOT NULL,
    sales_timestamp TIMESTAMP WITH TIME ZONE NOT NULL,
    sales_amount NUMERIC(12,2) NOT NULL CHECK (sales_amount >= 0),
    transaction_count INTEGER NOT NULL CHECK (transaction_count >= 0),
    average_transaction_value NUMERIC(10,2) GENERATED ALWAYS AS (
        CASE
            WHEN transaction_count > 0 THEN sales_amount / transaction_count
            ELSE 0
        END
    ) STORED,
    customer_count INTEGER,
    sales_channel VARCHAR(50) NOT NULL CHECK (sales_channel IN ('IN_STORE', 'ONLINE', 'MOBILE_APP', 'PHONE', 'KIOSK')),
    data_confidence NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (data_confidence BETWEEN 0.00 AND 1.00),
    promotion_id UUID,  -- Removed REFERENCES temporarily
    holiday_id UUID,    -- Removed REFERENCES temporarily
    special_event_id UUID,  -- Removed REFERENCES temporarily
    weather_condition VARCHAR(50),
    temperature NUMERIC(5,2),
    precipitation NUMERIC(5,2),
    notes TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Serial No: 201 | TABLE: external.promotions
-- Description: Master data repository for all promotional campaigns and marketing initiatives
-- Business Case: The promotions table serves as the central repository for all promotional activities
-- across the organization, providing critical context for analyzing sales patterns and workforce requirements.
-- It enables the forecasting system to account for promotion-driven demand spikes, ensuring accurate
-- staffing predictions during promotional periods. The table captures comprehensive promotion metadata
-- including type, duration, discount structure, and applicability rules across different channels and
-- locations. This granular promotion data allows the workforce planning system to distinguish between
-- organic sales patterns and promotion-induced variations, leading to more accurate scheduling models.
-- The table supports complex promotion hierarchies including stackable promotions and priority-based
-- application rules, enabling sophisticated what-if analysis for future campaign planning. By tracking
-- redemption limits and actual usage, the system can monitor promotion effectiveness and adjust future
-- workforce allocations based on historical promotion performance. The design accommodates various
-- promotion types including percentage discounts, fixed amount reductions, BOGO offers, and loyalty
-- rewards, with specific rules for each type. Location and channel applicability arrays enable targeted
-- promotions that drive traffic to specific stores or online platforms, allowing precise workforce
-- allocation based on expected customer response. The inclusion of promotion codes and external
-- references ensures integration with marketing systems and point-of-sale applications for consistent
-- promotion execution across all customer touchpoints. Historical tracking of promotion periods
-- supports retrospective analysis of promotion effectiveness and its impact on staffing efficiency
-- metrics like sales per labor hour.
-- KPI: Promotion lift analysis, Promotion-driven traffic percentage, 
--      Redemption rate by channel, ROI per promotion, Staffing efficiency during promotions
-- Feature Reference: 601, 602, 603, 604, 605

CREATE TABLE IF NOT EXISTS external.promotions (
    promotion_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    promotion_code VARCHAR(50) UNIQUE,  -- Business-facing promotion code
    promotion_name VARCHAR(200) NOT NULL,
    promotion_type VARCHAR(50) NOT NULL CHECK (promotion_type IN ('PERCENTAGE', 'FIXED_AMOUNT', 'BOGO', 'FREE_SHIPPING', 'LOYALTY', 'SEASONAL', 'CLEARANCE')),
    promotion_category VARCHAR(50) CHECK (promotion_category IN ('PRODUCT', 'CATEGORY', 'BASKET', 'CUSTOMER')),
    start_date DATE NOT NULL,
    end_date DATE NOT NULL,
    start_time TIME,  -- For time-specific promotions
    end_time TIME,    -- For time-specific promotions
    discount_percentage NUMERIC(5,2) CHECK (discount_percentage BETWEEN 0 AND 100),
    discount_amount NUMERIC(10,2) CHECK (discount_amount >= 0),
    minimum_purchase_amount NUMERIC(10,2) DEFAULT 0 CHECK (minimum_purchase_amount >= 0),
    applicable_locations TEXT[],  -- Array of location IDs if promotion is location-specific
    applicable_channels VARCHAR(50)[] DEFAULT ARRAY['IN_STORE', 'ONLINE']::VARCHAR(50)[],  -- Which channels promotion applies to
    max_redemptions INTEGER CHECK (max_redemptions > 0),  -- Overall cap
    redemptions_per_customer INTEGER,  -- Per-customer cap
    total_redemptions INTEGER DEFAULT 0 CHECK (total_redemptions >= 0),  -- Counter for usage
    is_active BOOLEAN DEFAULT true,
    is_stackable BOOLEAN DEFAULT false,  -- Can combine with other promotions
    priority INTEGER DEFAULT 0 CHECK (priority BETWEEN -100 AND 100),  -- Higher priority promotions applied first
    description TEXT,
    terms_conditions TEXT,
    created_by UUID,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB,
    
    -- Ensure valid date range
    CONSTRAINT chk_promotion_dates CHECK (end_date >= start_date),
    
    -- Ensure either percentage or amount is provided, not both
    CONSTRAINT chk_promotion_value CHECK (
        (discount_percentage IS NOT NULL AND discount_amount IS NULL) OR
        (discount_percentage IS NULL AND discount_amount IS NOT NULL)
    )
);


-- Serial No: 202 | TABLE: external.holidays
-- Description: Comprehensive holiday calendar with regional variations and business impact assessment
-- Business Case: The holidays table provides essential temporal context for workforce planning by
-- identifying days with significantly altered customer behavior patterns. Holidays fundamentally
-- change consumer shopping patterns, business operating hours, and staffing requirements, making
-- this table critical for accurate demand forecasting. The table captures holidays at multiple
-- geographic levels including federal, state, and local observances, enabling precise workforce
-- planning for locations in different regions. Holiday categorization by type (religious, cultural,
-- federal) allows the forecasting system to apply appropriate historical pattern matching based
-- on similar holiday types. The business impact ratings (HIGH/MEDIUM/LOW/NONE) provide a quick
-- reference for expected traffic and sales changes, directly feeding into staffing requirement
-- calculations. Expected traffic increase percentages enable quantitative forecasting adjustments,
-- while typical hours of operation in JSON format support schedule optimization for modified
-- business hours on holidays. The recurring holiday feature with pattern definitions (fixed date,
-- nth day of month, Easter-based) allows automatic future holiday generation for long-term
-- workforce planning. Alternate observance dates ensure accurate scheduling when holidays fall
-- on weekends and are observed on weekdays. The combination of holiday type and region allows
-- sophisticated analysis of how different holiday categories affect various store formats and
-- locations, improving prediction accuracy over time. Integration with sales_data enables
-- post-holiday analysis comparing actual versus expected traffic increases, refining future
-- forecasting models. School holiday tracking supports workforce planning in locations where
-- student traffic significantly impacts business volume.
-- KPI: Holiday forecast accuracy, Holiday traffic lift percentage, 
--      Staffing alignment with holiday demand, Post-holiday sales analysis
-- Feature Reference: 611, 612, 613, 614, 615

-- Create holidays table with comprehensive structure
CREATE TABLE IF NOT EXISTS external.holidays (
    holiday_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    holiday_name VARCHAR(200) NOT NULL,
    holiday_date DATE NOT NULL,
    holiday_type VARCHAR(50) NOT NULL CHECK (holiday_type IN ('FEDERAL', 'STATE', 'RELIGIOUS', 'CULTURAL', 'OBSERVANCE', 'CORPORATE', 'SCHOOL')),
    holiday_category VARCHAR(50) CHECK (holiday_category IN ('PUBLIC', 'BANKING', 'RETAIL', 'SCHOOL', 'CORPORATE')),
    is_federal BOOLEAN DEFAULT false,
    region VARCHAR(50),  -- For regional holidays
    country_code CHAR(2),  -- ISO country code
    state_code VARCHAR(3),  -- For state-level holidays
    is_recurring BOOLEAN DEFAULT false,  -- Holiday occurs every year
    recurring_pattern VARCHAR(20) CHECK (recurring_pattern IN ('FIXED_DATE', 'NTH_DAY_OF_MONTH', 'EASTER_BASED')),
    is_observed BOOLEAN DEFAULT true,  -- Whether holiday is observed (may affect business hours)
    alternate_observance_date DATE,  -- When holiday is actually observed if different
    business_impact VARCHAR(50) CHECK (business_impact IN ('HIGH', 'MEDIUM', 'LOW', 'NONE')),
    expected_traffic_increase NUMERIC(5,2),  -- Percentage
    expected_sales_increase NUMERIC(5,2),    -- Percentage
    typical_hours_of_operation JSONB,  -- Custom hours for this holiday
    description TEXT,
    notes TEXT,
    created_by UUID,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB,
    
    -- Ensure unique holiday for region and date
    CONSTRAINT unq_holiday_region_date UNIQUE (holiday_date, region, country_code)
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_promotions_dates ON external.promotions(start_date, end_date);
CREATE INDEX IF NOT EXISTS idx_promotions_type ON external.promotions(promotion_type);
CREATE INDEX IF NOT EXISTS idx_promotions_active ON external.promotions(is_active) WHERE is_active = true;
CREATE INDEX IF NOT EXISTS idx_promotions_code ON external.promotions(promotion_code) WHERE promotion_code IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_promotions_metadata ON external.promotions USING GIN(metadata);

CREATE INDEX IF NOT EXISTS idx_holidays_date ON external.holidays(holiday_date);
CREATE INDEX IF NOT EXISTS idx_holidays_type ON external.holidays(holiday_type);
CREATE INDEX IF NOT EXISTS idx_holidays_region ON external.holidays(region) WHERE region IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_holidays_federal ON external.holidays(is_federal) WHERE is_federal = true;
CREATE INDEX IF NOT EXISTS idx_holidays_metadata ON external.holidays USING GIN(metadata);

CREATE INDEX IF NOT EXISTS idx_events_dates ON external.local_events(start_date, end_date);
CREATE INDEX IF NOT EXISTS idx_events_type ON external.local_events(event_type);
CREATE INDEX IF NOT EXISTS idx_events_location ON external.local_events(location_id) WHERE location_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_events_attendance ON external.local_events(expected_attendance DESC);
CREATE INDEX IF NOT EXISTS idx_events_metadata ON external.local_events USING GIN(metadata);

-- Add triggers for audit columns
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$$ language 'plpgsql';

CREATE TRIGGER trg_promotions_updated_at
    BEFORE UPDATE ON external.promotions
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER trg_holidays_updated_at
    BEFORE UPDATE ON external.holidays
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER trg_events_updated_at
    BEFORE UPDATE ON external.local_events
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

-- Add table comments
COMMENT ON TABLE external.promotions IS 'Master data for all promotions and marketing campaigns';
COMMENT ON TABLE external.holidays IS 'Comprehensive holiday calendar with regional variations and business impact';
COMMENT ON TABLE external.local_events IS 'Local events that may impact business traffic and sales patterns';

