            COMMENT ON TABLE analytics.sales_data IS 'Historical sales and transaction data for workforce planning.
            Captures historical sales and transaction data from point-of-sale systems and other channels. Records sales volume, transaction
            counts, and customer traffic patterns at granular time intervals. Supports multiple sales channels including in-store and online.
            Includes metadata about business context such as promotions and holidays. Historical data versioned for trend analysis. Includes
            data quality metrics to indicate confidence levels. Integrates with forecasting models to project future sales. Accommodates
            different sales measurement methodologies. Optimized for time-series analysis with temporal indexing. Enables data-driven
            scheduling that responds to actual sales patterns. Includes mechanisms for handling data gaps and anomalies.';

            -- Serial No: 106 | VIEW: reporting.v_forecast_accuracy
            -- Purpose: Analysis of forecast accuracy and impact on scheduling decisions
            -- Business Case: This view provides analytical insights into the accuracy of demand forecasts and
            -- their impact on scheduling outcomes, supporting continuous improvement of forecasting capabilities.
            -- It combines data from forecasted staffing requirements, actual staffing levels, and business
            -- performance metrics to identify patterns of forecast error and their operational consequences.
            -- The view includes metrics at multiple levels of granularity (location, department, time period)
            -- to support different management perspectives. Historical trend data is presented with appropriate
            -- statistical analysis to distinguish meaningful patterns from random fluctuations. The design
            -- accommodates different forecasting methodologies and time horizons, enabling comparative
            -- analysis of forecast performance across different approaches. The view serves as the foundation
            -- for forecast accuracy scorecards that track progress against organizational forecasting goals.
            -- It also supports root cause analysis of forecast errors by identifying factors that contribute
            -- to inaccuracy, such as special events or external factors. For strategic planning, the view
            -- provides the necessary data to evaluate the potential impact of forecast improvements on
            -- business outcomes. By centralizing forecast accuracy data, the view reduces the time and effort
            -- required to analyze forecasting performance and enables proactive management of forecast quality.
            -- The implementation includes benchmark comparisons against industry standards to provide context
            -- for forecast performance. The view is optimized for performance with pre-aggregated metrics
            -- where possible, ensuring responsive analytics even with large historical datasets. It enables
            -- data-driven decisions about forecasting methodology improvements that balance accuracy with
            -- computational complexity.
            -- KPI: Forecast accuracy rate, Forecast error impact on labor costs,
            --      Forecast improvement rate, Forecast bias identification rate,
            --      Forecast trend direction
            -- Feature Reference: 546, 547, 548, 549, 550
            CREATE OR REPLACE VIEW reporting.v_forecast_accuracy AS
SELECT
    fs.location_id,
    l.location_name,
    fs.department_id,
    d.department_name,
    fs.position_id,
    p.position_title,
    fs.forecast_date,
    fs.time_period,
    fs.start_time,
    fs.end_time,
    fs.forecasted_staffing,
    fs.historical_staffing,
    fs.actual_staffing,
    fs.forecast_method,
    (fs.actual_staffing - fs.forecasted_staffing) AS staffing_difference,
    CASE
        WHEN fs.forecasted_staffing > 0
            THEN (fs.actual_staffing - fs.forecasted_staffing)::NUMERIC / fs.forecasted_staffing * 100
        ELSE 0
    END AS staffing_variance_percentage,
    td.traffic_count,
    td.dwell_time_minutes,
    td.conversion_rate,
    -- Comment out or modify these sales-related columns if the table doesn't exist
    -- sd.sales_amount,
    -- sd.transaction_count,
    -- sd.average_transaction_value,
    -- (sd.sales_amount / NULLIF(fs.actual_staffing, 0)) AS sales_per_staff,
    -- (sd.sales_amount / NULLIF(fs.forecasted_staffing, 0)) AS forecasted_sales_per_staff,
    -- (sd.sales_amount / NULLIF(fs.historical_staffing, 0)) AS historical_sales_per_staff,
    -- CASE
    --     WHEN fs.forecasted_staffing > 0 AND fs.historical_staffing > 0
    --         THEN (sd.sales_amount / fs.forecasted_staffing) - (sd.sales_amount / fs.historical_staffing)
    --     ELSE 0
    -- END AS sales_per_staff_improvement,
    -- CASE
    --     WHEN fs.forecasted_staffing > 0 AND fs.historical_staffing > 0
    --         THEN ((sd.sales_amount / fs.forecasted_staffing) - (sd.sales_amount / fs.historical_staffing))
    --             / (sd.sales_amount / fs.historical_staffing) * 100
    --     ELSE 0
    -- END AS sales_per_staff_improvement_percentage,
    NULL AS sales_amount,  -- Placeholder
    NULL AS transaction_count,  -- Placeholder
    NULL AS average_transaction_value,  -- Placeholder
    NULL AS sales_per_staff,  -- Placeholder
    NULL AS forecasted_sales_per_staff,  -- Placeholder
    NULL AS historical_sales_per_staff,  -- Placeholder
    NULL AS sales_per_staff_improvement,  -- Placeholder
    NULL AS sales_per_staff_improvement_percentage  -- Placeholder
FROM analytics.forecasted_staffing fs
JOIN operations.locations l ON fs.location_id = l.location_id
JOIN hr.departments d ON fs.department_id = d.department_id
JOIN hr.positions p ON fs.position_id = p.position_id
LEFT JOIN analytics.traffic_data td
    ON l.location_id = td.location_id
    AND fs.forecast_date = td.date
    AND EXTRACT(HOUR FROM fs.start_time) = td.hour_of_day
-- LEFT JOIN analytics.sales_data sd
--     ON l.location_id = sd.location_id
--     AND fs.forecast_date = sd.sales_date
--     AND EXTRACT(HOUR FROM fs.start_time) = EXTRACT(HOUR FROM sd.sales_time)
WHERE fs.forecast_date >= CURRENT_DATE - INTERVAL '180 days';

            COMMENT ON VIEW reporting.v_forecast_accuracy IS 'Analysis of forecast accuracy and impact on scheduling decisions.
            Provides analytical insights into accuracy of demand forecasts and impact on scheduling outcomes. Combines data from forecasted
            staffing, actual staffing, and business performance metrics. Includes metrics at multiple levels of granularity. Historical
            trend data presented with statistical analysis. Accommodates different forecasting methodologies and time horizons. Serves as
            foundation for forecast accuracy scorecards. Supports root cause analysis of forecast errors. Provides data for evaluating
            impact of forecast improvements. Reduces time and effort for analyzing forecasting performance. Includes benchmark comparisons
            for context. Optimized for performance with pre-aggregated metrics. Enables data-driven decisions about forecasting methodology
            improvements.';

           

