            -- Serial No: 110 | TABLE: analytics.shift_swap_analysis
            -- Description: Metrics and insights from historical shift swap data
            -- Business Case: The shift_swap_analysis table stores aggregated metrics and analytical insights
            -- derived from historical shift swap data, providing valuable information for improving scheduling
            -- practices and employee satisfaction. It captures patterns in swap requests, approval rates, and
            -- business impact to identify opportunities for process improvement. The table supports multiple
            -- analysis dimensions including time periods, departments, locations, and employee demographics,
            -- enabling targeted insights for different organizational units. Each analysis record includes
            -- metadata about the data sources, calculation methodology, and confidence level to ensure proper
            -- interpretation of results. The implementation includes historical tracking of key metrics to
            -- identify trends and measure the impact of process changes over time. For operational planning,
            -- the system stores analysis results at multiple granularities (daily, weekly, monthly) to support
            -- different planning horizons. The table integrates with the scheduling engine to enable data-driven
            -- improvements to the swap process that balance employee flexibility with business needs. The design
            -- accommodates different analysis methodologies while providing a consistent interface for decision
            -- makers. By centralizing swap analysis data, the organization can ensure consistent evaluation of
            -- swap process effectiveness while providing the flexibility needed for location-specific insights.
            -- The table is optimized for rapid querying during scheduling optimization, which often considers
            -- historical swap patterns when creating new schedules.
            -- KPI: Swap request completion rate, Average swap approval time,
            --      Employee satisfaction with swap process, Swap-related coverage gaps,
            --      Policy compliance rate for swaps
            -- Feature Reference: 566, 567, 568, 569, 570
            CREATE TABLE IF NOT EXISTS analytics.shift_swap_analysis (
                analysis_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                analysis_date DATE NOT NULL,
                time_period VARCHAR(20) NOT NULL CHECK (time_period IN ('DAILY', 'WEEKLY', 'MONTHLY', 'QUARTERLY')),
                location_id UUID REFERENCES operations.locations(location_id),
                department_id UUID REFERENCES hr.departments(department_id),
                position_id UUID REFERENCES hr.positions(position_id),
                total_requests INTEGER NOT NULL DEFAULT 0 CHECK (total_requests >= 0),
                approved_requests INTEGER NOT NULL DEFAULT 0 CHECK (approved_requests >= 0),
                rejected_requests INTEGER NOT NULL DEFAULT 0 CHECK (rejected_requests >= 0),
                completed_swaps INTEGER NOT NULL DEFAULT 0 CHECK (completed_swaps >= 0),
                average_approval_time INTERVAL,
                approval_rate NUMERIC(5,2) GENERATED ALWAYS AS (
                    CASE
                        WHEN total_requests > 0 THEN approved_requests::NUMERIC / total_requests * 100
                        ELSE 0
                    END
                ) STORED,
                completion_rate NUMERIC(5,2) GENERATED ALWAYS AS (
                    CASE
                        WHEN approved_requests > 0 THEN completed_swaps::NUMERIC / approved_requests * 100
                        ELSE 0
                    END
                ) STORED,
                average_shifts_per_swap NUMERIC(4,2),
                coverage_impact NUMERIC(5,2),
                compliance_impact NUMERIC(5,2),
                employee_satisfaction_score NUMERIC(5,2),
                top_reasons JSONB,
                top_positions JSONB,
                top_locations JSONB,
                analysis_method VARCHAR(50) NOT NULL DEFAULT 'HISTORICAL_TREND'
                    CHECK (analysis_method IN ('HISTORICAL_TREND', 'COMPARATIVE_ANALYSIS', 'PREDICTIVE_MODEL')),
                data_quality_score NUMERIC(5,2) CHECK (data_quality_score BETWEEN 0.00 AND 100.00),
                notes TEXT,
                created_by UUID NOT NULL,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_by UUID,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_shift_swap_analysis_date ON analytics.shift_swap_analysis(analysis_date, time_period);
            CREATE INDEX IF NOT EXISTS idx_shift_swap_analysis_location ON analytics.shift_swap_analysis(location_id)
                WHERE location_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_shift_swap_analysis_department ON analytics.shift_swap_analysis(department_id)
                WHERE department_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_shift_swap_analysis_position ON analytics.shift_swap_analysis(position_id)
                WHERE position_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_shift_swap_analysis_rates ON analytics.shift_swap_analysis(approval_rate, completion_rate);
            CREATE INDEX IF NOT EXISTS idx_shift_swap_analysis_impact ON analytics.shift_swap_analysis(coverage_impact, compliance_impact);
            CREATE INDEX IF NOT EXISTS idx_shift_swap_analysis_satisfaction ON analytics.shift_swap_analysis(employee_satisfaction_score);
            CREATE INDEX IF NOT EXISTS idx_shift_swap_analysis_metadata ON analytics.shift_swap_analysis USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_shift_swap_analysis_updated_at
            BEFORE UPDATE ON analytics.shift_swap_analysis
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

            COMMENT ON TABLE analytics.shift_swap_analysis IS 'Metrics and insights from historical shift swap data.
            Stores aggregated metrics and analytical insights derived from historical shift swap data. Captures patterns in swap requests
            and approval rates. Supports multiple analysis dimensions including time periods and organizational units. Includes metadata
            about data sources and calculation methodology. Historical tracking of key metrics to identify trends. Stores analysis results
            at multiple granularities. Integrates with scheduling engine for data-driven improvements. Accommodates different analysis
            methodologies. Centralizes swap analysis data for consistent evaluation. Optimized for rapid querying during scheduling
            optimization.';

            -- Serial No: 111 | TABLE: hr.employee_preferences
            -- Description: Comprehensive employee preferences for scheduling and work conditions
            -- Business Case: The employee_preferences table captures a wide range of employee preferences beyond
            -- just shift availability, including work conditions, communication preferences, and career development
            -- interests. It provides a holistic view of employee preferences that can inform scheduling decisions
            -- and workforce management practices. The table supports multiple preference categories with different
            -- importance levels, enabling nuanced consideration of preferences during scheduling. Each preference
            -- record includes metadata about its effective dates, priority, and approval status to support proper
            -- workflow handling. The implementation accommodates complex preference scenarios such as conditional
            -- preferences that apply only under specific circumstances. Preference data is versioned to track
            -- changes over time, which is important for understanding historical scheduling patterns and resolving
            -- disputes. The table is optimized for rapid querying during schedule generation, which involves
            -- evaluating preference constraints for potentially hundreds of employees simultaneously. Historical
            -- preference data is used to identify patterns and improve the scheduling algorithm's ability to predict
            -- employee preferences. For compliance purposes, the system tracks the approval status of preferences
            -- that may conflict with business requirements or labor regulations. By centralizing preference
            -- management, the system enables more effective communication between employees and managers about
            -- scheduling expectations while providing the data needed for optimization algorithms to create schedules
            -- that balance business and employee needs.
            -- KPI: Preference fulfillment rate, Schedule satisfaction score,
            --      Preference update frequency, Preference data completeness,
            --      Scheduling conflict rate
            -- Feature Reference: 571, 572, 573, 574, 575
            CREATE TABLE IF NOT EXISTS hr.employee_preferences (
                preference_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                employee_id UUID NOT NULL REFERENCES hr.employees(employee_id) ON DELETE CASCADE,
                preference_category VARCHAR(50) NOT NULL CHECK (preference_category IN ('SHIFT_AVAILABILITY', 'WORK_CONDITIONS',
                    'COMMUNICATION', 'CAREER_DEVELOPMENT', 'BENEFITS', 'TRAINING', 'TEAM_PREFERENCES')),
                preference_type VARCHAR(50) NOT NULL,
                preference_value TEXT NOT NULL,
                effective_start_date DATE NOT NULL DEFAULT CURRENT_DATE,
                effective_end_date DATE,
                priority INTEGER DEFAULT 0 CHECK (priority BETWEEN -10 AND 10),
                is_approved BOOLEAN NOT NULL DEFAULT FALSE,
                approval_notes TEXT,
                approved_by UUID REFERENCES hr.employees(employee_id),
                approval_date TIMESTAMP WITH TIME ZONE,
                source_system VARCHAR(50) NOT NULL DEFAULT 'EMPLOYEE_SELF_SERVICE'
                    CHECK (source_system IN ('EMPLOYEE_SELF_SERVICE', 'MANAGER', 'HR_SYSTEM', 'IMPORTED')),
                notes TEXT,
                version INTEGER NOT NULL DEFAULT 1 CHECK (version >= 1),
                created_by UUID NOT NULL,
                updated_by UUID,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_employee_preferences_employee ON hr.employee_preferences(employee_id);
            CREATE INDEX IF NOT EXISTS idx_employee_preferences_category ON hr.employee_preferences(preference_category);
            CREATE INDEX IF NOT EXISTS idx_employee_preferences_type ON hr.employee_preferences(preference_type);
            CREATE INDEX IF NOT EXISTS idx_employee_preferences_dates ON hr.employee_preferences(effective_start_date, effective_end_date);
            CREATE INDEX IF NOT EXISTS idx_employee_preferences_priority ON hr.employee_preferences(priority DESC);
            CREATE INDEX IF NOT EXISTS idx_employee_preferences_approved ON hr.employee_preferences(is_approved) WHERE is_approved = FALSE;
            CREATE INDEX IF NOT EXISTS idx_employee_preferences_metadata ON hr.employee_preferences USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_employee_preferences_updated_at
            BEFORE UPDATE ON hr.employee_preferences
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

            COMMENT ON TABLE hr.employee_preferences IS 'Comprehensive employee preferences for scheduling and work conditions.
            Captures a wide range of employee preferences beyond just shift availability. Provides holistic view of preferences that
            inform scheduling decisions. Supports multiple preference categories with different importance levels. Includes metadata
            about effective dates and priority. Accommodates complex preference scenarios such as conditional preferences. Preference
            data versioned to track changes over time. Optimized for rapid querying during schedule generation. Historical data used
            to identify patterns and improve scheduling algorithms. Tracks approval status for compliance purposes. Centralizes preference
            management for effective communication between employees and managers.';

            -- Serial No: 112 | TABLE: analytics.attendance_patterns
            -- Description: Historical analysis of attendance patterns and trends
            -- Business Case: The attendance_patterns table stores aggregated metrics and analytical insights
            -- derived from historical attendance data, providing valuable information for improving scheduling
            -- practices and identifying potential issues. It captures patterns in attendance, tardiness, and
            -- absenteeism across different time periods, departments, and employee demographics, enabling
            -- targeted interventions. The table supports multiple analysis dimensions including time periods,
            -- locations, and organizational units, facilitating comprehensive understanding of attendance
            -- behavior. Each pattern record includes metadata about the data sources, calculation methodology,
            -- and statistical significance to ensure proper interpretation of results. The implementation
            -- includes historical tracking of key metrics to identify trends and measure the impact of
            -- scheduling changes over time. For operational planning, the system stores pattern data at
            -- multiple granularities (daily, weekly, monthly) to support different planning horizons. The
            -- table integrates with the scheduling engine to enable data-driven scheduling that accounts
            -- for historical attendance patterns and reduces the risk of coverage gaps. The design accommodates
            -- different analysis methodologies while providing a consistent interface for decision makers.
            -- By centralizing attendance pattern data, the organization can ensure consistent evaluation of
            -- attendance trends while providing the flexibility needed for location-specific insights. The
            -- table is optimized for rapid querying during scheduling optimization, which often considers
            -- historical attendance patterns when creating new schedules.
            -- KPI: Attendance pattern prediction accuracy, Schedule adherence rate,
            --      Absenteeism rate, Attendance anomaly detection rate,
            --      Attendance trend direction
            -- Feature Reference: 576, 577, 578, 579, 580
            CREATE TABLE IF NOT EXISTS analytics.attendance_patterns (
                pattern_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                analysis_date DATE NOT NULL,
                time_period VARCHAR(20) NOT NULL CHECK (time_period IN ('DAILY', 'WEEKLY', 'MONTHLY', 'QUARTERLY')),
                location_id UUID REFERENCES operations.locations(location_id),
                department_id UUID REFERENCES hr.departments(department_id),
                position_id UUID REFERENCES hr.positions(position_id),
                employee_id UUID REFERENCES hr.employees(employee_id),
                total_days INTEGER NOT NULL DEFAULT 0 CHECK (total_days > 0),
                present_days INTEGER NOT NULL DEFAULT 0 CHECK (present_days >= 0),
                absent_days INTEGER NOT NULL DEFAULT 0 CHECK (absent_days >= 0),
                tardy_days INTEGER NOT NULL DEFAULT 0 CHECK (tardy_days >= 0),
                early_departure_days INTEGER NOT NULL DEFAULT 0 CHECK (early_departure_days >= 0),
                attendance_rate NUMERIC(5,2) GENERATED ALWAYS AS (present_days::NUMERIC / total_days * 100) STORED,
                absenteeism_rate NUMERIC(5,2) GENERATED ALWAYS AS (absent_days::NUMERIC / total_days * 100) STORED,
                tardiness_rate NUMERIC(5,2) GENERATED ALWAYS AS (tardy_days::NUMERIC / total_days * 100) STORED,
                early_departure_rate NUMERIC(5,2) GENERATED ALWAYS AS (early_departure_days::NUMERIC / total_days * 100) STORED,
                pattern_type VARCHAR(50) NOT NULL CHECK (pattern_type IN ('CONSISTENT', 'SEASONAL', 'RANDOM', 'TRENDING')),
                pattern_strength NUMERIC(5,2) CHECK (pattern_strength BETWEEN 0.00 AND 100.00),
                predicted_absenteeism_rate NUMERIC(5,2),
                confidence_interval NUMERIC(5,2),
                top_absence_reasons JSONB,
                top_tardiness_reasons JSONB,
                analysis_method VARCHAR(50) NOT NULL DEFAULT 'HISTORICAL_TREND'
                    CHECK (analysis_method IN ('HISTORICAL_TREND', 'SEASONAL_DECOMPOSITION', 'MACHINE_LEARNING')),
                data_quality_score NUMERIC(5,2) CHECK (data_quality_score BETWEEN 0.00 AND 100.00),
                notes TEXT,
                created_by UUID NOT NULL,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_by UUID,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_attendance_patterns_date ON analytics.attendance_patterns(analysis_date, time_period);
            CREATE INDEX IF NOT EXISTS idx_attendance_patterns_location ON analytics.attendance_patterns(location_id)
                WHERE location_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_attendance_patterns_department ON analytics.attendance_patterns(department_id)
                WHERE department_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_attendance_patterns_position ON analytics.attendance_patterns(position_id)
                WHERE position_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_attendance_patterns_employee ON analytics.attendance_patterns(employee_id)
                WHERE employee_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_attendance_patterns_rates ON analytics.attendance_patterns(attendance_rate, absenteeism_rate);
            CREATE INDEX IF NOT EXISTS idx_attendance_patterns_tardiness ON analytics.attendance_patterns(tardiness_rate, early_departure_rate);
            CREATE INDEX IF NOT EXISTS idx_attendance_patterns_metadata ON analytics.attendance_patterns USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_attendance_patterns_updated_at
            BEFORE UPDATE ON analytics.attendance_patterns
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

