                title VARCHAR(200) NOT NULL,
                description TEXT NOT NULL,
                agreement_type VARCHAR(50) NOT NULL CHECK (agreement_type IN ('NATIONAL', 'REGIONAL', 'LOCAL', 'COMPANY_WIDE')),
                jurisdiction VARCHAR(100) NOT NULL,
                country_code VARCHAR(10) NOT NULL,
                region VARCHAR(50),
                city VARCHAR(50),
                effective_date DATE NOT NULL,
                expiration_date DATE,
                union_name VARCHAR(100) NOT NULL,
                legal_reference VARCHAR(200),
                covered_employees UUID[] NOT NULL,
                covered_positions UUID[],
                covered_locations UUID[],
                covered_departments UUID[],
                agreement_content TEXT NOT NULL,
                agreement_summary TEXT,
                key_provisions JSONB NOT NULL,
                enforcement_level VARCHAR(50) NOT NULL DEFAULT 'MANDATORY'
                    CHECK (enforcement_level IN ('MANDATORY', 'PREFERRED', 'INFORMATIONAL')),
                severity VARCHAR(20) NOT NULL DEFAULT 'HIGH'
                    CHECK (severity IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
                is_active BOOLEAN NOT NULL DEFAULT TRUE,
                version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                based_on_agreement_id UUID REFERENCES compliance.union_agreements(agreement_id),
                created_by UUID NOT NULL,
                updated_by UUID,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_union_agreements_type ON compliance.union_agreements(agreement_type);
            CREATE INDEX IF NOT EXISTS idx_union_agreements_jurisdiction ON compliance.union_agreements(jurisdiction);
            CREATE INDEX IF NOT EXISTS idx_union_agreements_effective ON compliance.union_agreements(effective_date, expiration_date);
            CREATE INDEX IF NOT EXISTS idx_union_agreements_active ON compliance.union_agreements(is_active) WHERE is_active = TRUE;
            CREATE INDEX IF NOT EXISTS idx_union_agreements_severity ON compliance.union_agreements(severity);
            CREATE INDEX IF NOT EXISTS idx_union_agreements_version ON compliance.union_agreements(agreement_id, version_number DESC);
            CREATE INDEX IF NOT EXISTS idx_union_agreements_based_on ON compliance.union_agreements(based_on_agreement_id);
            CREATE INDEX IF NOT EXISTS idx_union_agreements_employees ON compliance.union_agreements USING GIN(covered_employees);
            CREATE INDEX IF NOT EXISTS idx_union_agreements_positions ON compliance.union_agreements USING GIN(covered_positions);
            CREATE INDEX IF NOT EXISTS idx_union_agreements_locations ON compliance.union_agreements USING GIN(covered_locations);
            CREATE INDEX IF NOT EXISTS idx_union_agreements_departments ON compliance.union_agreements USING GIN(covered_departments);
            CREATE INDEX IF NOT EXISTS idx_union_agreements_metadata ON compliance.union_agreements USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_union_agreements_updated_at
            BEFORE UPDATE ON compliance.union_agreements
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

            COMMENT ON TABLE compliance.union_agreements IS 'Collective bargaining agreements and union contracts.
            Serves as central repository for all collective bargaining agreements applicable to the workforce. Captures detailed provisions
            around working hours, overtime, and other employment conditions. Supports hierarchical organization from national to local levels.
            Includes metadata about effective dates and covered employee groups. Accommodates complex agreement structures through standard
            rule types and custom expressions. Historical versions maintained for compliance verification. Tracks agreement updates and
            implementation deadlines. Supports translation into multiple languages. Centralizes agreement information for consistent compliance.
            Optimized for rapid querying during compliance checks.';

            -- Serial No: 114 | TABLE: compliance.union_rules
            -- Description: Specific rules derived from union agreements for compliance checking
            -- Business Case: The union_rules table stores specific compliance rules derived from collective bargaining
            -- agreements, providing the foundation for automated compliance checking within the scheduling system.
            -- It captures individual provisions from union contracts in a structured format that can be evaluated
            -- against schedule data. The table supports multiple rule types including time-based rules, seniority
            -- rules, and workload distribution rules, accommodating the diverse requirements found in union contracts.
            -- Each rule includes metadata about its source agreement, effective dates, and enforcement priority to
            -- support proper implementation. The implementation includes validation rules to ensure rules are
            -- correctly formulated and can be reliably evaluated. Historical rule versions are maintained to support
            -- compliance verification for past scheduling decisions. For operational efficiency, the system stores
            -- rule evaluation results to avoid redundant calculations during scheduling. The table integrates with
            -- the scheduling engine to enable real-time compliance validation during schedule creation and modification.
            -- The design accommodates complex rule logic through a combination of standard rule templates and custom
            -- expressions, enabling precise representation of contractual requirements. By centralizing union rules,
            -- the organization can ensure consistent application of contractual requirements across all locations
            -- while reducing the risk of labor disputes due to inconsistent rule application. The table is optimized
            -- for rapid querying during compliance checks, which is critical for real-time scheduling validation
            -- and preventing contractual violations before schedules are published.
            -- KPI: Rule coverage completeness, Rule evaluation accuracy,
            --      Compliance violation detection rate, Rule implementation time,
            --      Audit success rate
            -- Feature Reference: 586, 587, 588, 589, 590
            CREATE TABLE IF NOT EXISTS compliance.union_rules (
                rule_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                rule_code VARCHAR(50) UNIQUE NOT NULL CHECK (rule_code ~ '^[A-Z0-9_]{3,50}$'),
                title VARCHAR(200) NOT NULL,
                description TEXT NOT NULL,
                rule_type VARCHAR(50) NOT NULL CHECK (rule_type IN ('TIME_BASED', 'SENIORITY', 'WORKLOAD', 'REST_PERIOD',
                    'OVERTIME', 'PREFERENCE', 'ROTATION', 'OTHER')),
                agreement_id UUID NOT NULL REFERENCES compliance.union_agreements(agreement_id),
                effective_date DATE NOT NULL,
                expiration_date DATE,
                rule_expression TEXT NOT NULL,
                rule_parameters JSONB,
                severity VARCHAR(20) NOT NULL DEFAULT 'HIGH'
                    CHECK (severity IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
                enforcement_level VARCHAR(50) NOT NULL DEFAULT 'MANDATORY'
                    CHECK (enforcement_level IN ('MANDATORY', 'PREFERRED', 'INFORMATIONAL')),
                is_active BOOLEAN NOT NULL DEFAULT TRUE,
                version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                based_on_rule_id UUID REFERENCES compliance.union_rules(rule_id),
                validated_by UUID REFERENCES hr.employees(employee_id),
                validated_at TIMESTAMP WITH TIME ZONE,
                validation_results JSONB,
                usage_count INTEGER NOT NULL DEFAULT 0,
                created_by UUID NOT NULL,
                updated_by UUID,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB,

                -- Constraints
                CONSTRAINT chk_rule_expression CHECK (LENGTH(TRIM(rule_expression)) > 0)
            );

           

           

