            -- Serial No: 115 | TABLE: scheduling.schedule_compliance
            -- Description: Tracking of compliance violations and remediation efforts
            -- Business Case: The schedule_compliance table provides comprehensive tracking of compliance violations
            -- related to workforce schedules, capturing detailed information about each violation including its
            -- severity, root cause, and remediation status. It records violations against labor laws, union
            -- agreements, company policies, and other regulatory requirements to ensure proper oversight of
            -- scheduling practices. The table supports multiple violation types with different resolution
            -- workflows, enabling appropriate handling of critical versus minor issues. Each violation record
            -- includes contextual information about the business environment at the time of the violation,
            -- enabling accurate assessment during audits. The implementation includes robust tracking of
            -- remediation efforts with timestamps and responsible parties to support accountability and
            -- timely resolution. Historical violation data is maintained to identify recurring issues and
            -- measure improvement over time. For regulatory compliance, the system tracks approval workflows
            -- for exceptions to standard compliance requirements, documenting the rationale and authorization
            -- for any deviations. By centralizing compliance tracking, the system ensures consistent enforcement
            -- of compliance policies while providing the detailed evidence needed for regulatory examinations.
            -- The design accommodates different compliance frameworks for various jurisdictions and business
            -- units, enabling global organizations to maintain defensible compliance practices across their
            -- entire operation. The table is optimized for rapid querying during compliance audits and for
            -- generating required regulatory reports.
            -- KPI: Violation resolution rate, Time to resolve critical violations,
            --      Repeat violation rate, Compliance improvement rate,
            --      Audit finding closure rate
            -- Feature Reference: 591, 592, 593, 594, 595
            CREATE TABLE IF NOT EXISTS scheduling.schedule_compliance (
                compliance_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                schedule_id UUID NOT NULL REFERENCES scheduling.schedules(schedule_id) ON DELETE CASCADE,
                rule_id UUID NOT NULL,
                rule_type VARCHAR(50) NOT NULL CHECK (rule_type IN ('LABOR_LAW', 'UNION_AGREEMENT', 'COMPANY_POLICY', 'CUSTOM_RULE')),
                entity_type VARCHAR(50) NOT NULL CHECK (entity_type IN ('SCHEDULE', 'SHIFT', 'EMPLOYEE', 'DEPARTMENT', 'LOCATION')),
                entity_id UUID NOT NULL,
                violation_severity VARCHAR(20) NOT NULL CHECK (violation_severity IN ('CRITICAL', 'HIGH', 'MEDIUM', 'LOW')),
                violation_description TEXT NOT NULL,
                detected_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                detected_by UUID NOT NULL REFERENCES hr.employees(employee_id),
                status VARCHAR(20) NOT NULL DEFAULT 'OPEN'
                    CHECK (status IN ('OPEN', 'IN_PROGRESS', 'RESOLVED', 'EXCEPTION_APPROVED', 'IGNORED')),
                resolution_notes TEXT,
                resolved_at TIMESTAMP WITH TIME ZONE,
                resolved_by UUID REFERENCES hr.employees(employee_id),
                exception_approved_by UUID REFERENCES hr.employees(employee_id),
                exception_approval_date TIMESTAMP WITH TIME ZONE,
                exception_reason TEXT,
                remediation_steps TEXT[],
                remediation_evidence JSONB,
                remediation_completed_at TIMESTAMP WITH TIME ZONE,
                next_review_date DATE,
                audit_context JSONB,
                is_regulatory BOOLEAN NOT NULL DEFAULT FALSE,
                regulatory_body VARCHAR(100),
                regulatory_reference VARCHAR(100),
                created_by UUID NOT NULL,
                updated_by UUID,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

           

            COMMENT ON TABLE scheduling.schedule_compliance IS 'Tracking of compliance violations and remediation efforts.
            Provides comprehensive tracking of compliance violations related to workforce schedules. Records violations against labor laws,
            union agreements, and company policies. Supports multiple violation types with different resolution workflows. Includes contextual
            information for accurate assessment during audits. Tracks remediation efforts with timestamps and responsible parties. Historical
            data maintained to identify recurring issues. Tracks approval workflows for exceptions to standard requirements. Centralizes
            compliance tracking for consistent enforcement. Accommodates different compliance frameworks for various jurisdictions. Optimized
