            -- Serial No: 116 | TABLE: scheduling.shift_coverage
            -- Description: Historical and projected shift coverage metrics
            -- Business Case: The shift_coverage table stores historical and projected metrics related to shift
            -- coverage, providing critical insights for workforce planning and scheduling optimization. It captures
            -- data on coverage gaps, overstaffing, and skill-based coverage to ensure schedules meet operational
            -- requirements while optimizing labor costs. The table supports multiple coverage dimensions including
            -- time periods, locations, departments, and skill requirements, enabling comprehensive analysis of
            -- coverage patterns. Each coverage record includes metadata about the calculation methodology, data
            -- sources, and confidence level to ensure proper interpretation of results. The implementation
            -- includes historical tracking of coverage metrics to identify trends and measure the impact of
            -- scheduling changes over time. For operational planning, the system stores coverage data at multiple
            -- granularities (hourly, daily, weekly) to support different planning horizons. The table integrates
            -- with the scheduling engine to enable real-time coverage validation during schedule creation and
            -- modification. The design accommodates different coverage requirements for various business units
            -- and operational contexts, providing a flexible framework for coverage analysis. By centralizing
            -- coverage data, the organization can ensure consistent evaluation of coverage metrics while
            -- providing the flexibility needed for location-specific requirements. The table is optimized for
            -- rapid querying during schedule optimization, which often involves evaluating coverage constraints
            -- for potentially hundreds of shifts simultaneously.
            -- KPI: Coverage gap rate, Overstaffing rate,
            --      Skill gap identification rate, Coverage trend direction,
            --      Impact of coverage issues on business metrics
            -- Feature Reference: 596, 597, 598, 599, 600
            CREATE TABLE IF NOT EXISTS scheduling.shift_coverage (
                coverage_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                coverage_date DATE NOT NULL,
                time_period VARCHAR(20) NOT NULL CHECK (time_period IN ('HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
                start_time TIMESTAMP WITH TIME ZONE NOT NULL,
                end_time TIMESTAMP WITH TIME ZONE NOT NULL CHECK (end_time > start_time),
                location_id UUID NOT NULL REFERENCES operations.locations(location_id),
                department_id UUID NOT NULL REFERENCES hr.departments(department_id),
                position_id UUID NOT NULL REFERENCES hr.positions(position_id),
                required_staffing INTEGER NOT NULL CHECK (required_staffing >= 0),
                projected_staffing INTEGER NOT NULL CHECK (projected_staffing >= 0),
                actual_staffing INTEGER CHECK (actual_staffing >= 0),
                coverage_gap INTEGER GENERATED ALWAYS AS (required_staffing - projected_staffing) STORED,
                coverage_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
                    CASE
                        WHEN required_staffing > 0 THEN projected_staffing::NUMERIC / required_staffing * 100
                        ELSE 100
                    END
                ) STORED,
                skill_coverage JSONB,
                coverage_type VARCHAR(50) NOT NULL CHECK (coverage_type IN ('MINIMUM', 'OPTIMAL', 'PEAK', 'CUSTOM')),
                coverage_source VARCHAR(50) NOT NULL CHECK (coverage_source IN ('FORECAST', 'HISTORICAL', 'MANUAL', 'RULE_BASED')),
                data_confidence NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (data_confidence BETWEEN 0.00 AND 1.00),
                notes TEXT,
                created_by UUID NOT NULL,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_by UUID,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_shift_coverage_date ON scheduling.shift_coverage(coverage_date, time_period);
            CREATE INDEX IF NOT EXISTS idx_shift_coverage_time ON scheduling.shift_coverage(start_time, end_time);
            CREATE INDEX IF NOT EXISTS idx_shift_coverage_location ON scheduling.shift_coverage(location_id);
            CREATE INDEX IF NOT EXISTS idx_shift_coverage_department ON scheduling.shift_coverage(department_id);
            CREATE INDEX IF NOT EXISTS idx_shift_coverage_position ON scheduling.shift_coverage(position_id);
            CREATE INDEX IF NOT EXISTS idx_shift_coverage_gap ON scheduling.shift_coverage(coverage_gap);
            CREATE INDEX IF NOT EXISTS idx_shift_coverage_percentage ON scheduling.shift_coverage(coverage_percentage);
            CREATE INDEX IF NOT EXISTS idx_shift_coverage_type ON scheduling.shift_coverage(coverage_type);
            CREATE INDEX IF NOT EXISTS idx_shift_coverage_source ON scheduling.shift_coverage(coverage_source);
            CREATE INDEX IF NOT EXISTS idx_shift_coverage_metadata ON scheduling.shift_coverage USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_shift_coverage_updated_at
            BEFORE UPDATE ON scheduling.shift_coverage
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

            COMMENT ON TABLE scheduling.shift_coverage IS 'Historical and projected shift coverage metrics.
            Stores historical and projected metrics related to shift coverage. Captures data on coverage gaps, overstaffing, and skill-based
            coverage. Supports multiple coverage dimensions including time periods and skill requirements. Includes metadata about calculation
            methodology and confidence level. Historical tracking of coverage metrics to identify trends. Stores coverage data at multiple
            granularities. Integrates with scheduling engine for real-time coverage validation. Accommodates different coverage requirements
            for various business units. Centralizes coverage data for consistent evaluation. Optimized for rapid querying during schedule
            optimization.';

            -- Serial No: 117 | VIEW: reporting.v_schedule_compliance_dashboard
            -- Purpose: Executive view for monitoring schedule compliance across the organization
            -- Business Case: This view provides a comprehensive executive overview of schedule compliance across
            -- the organization, highlighting critical violations, trends, and remediation efforts. It combines
            -- data from compliance violations, audit logs, and remediation tracking to provide a holistic view
            -- of compliance status. The view includes metrics at multiple levels of granularity (organization,
            -- location, department) to support different management perspectives. Historical trend data is
            -- presented with appropriate statistical analysis to distinguish meaningful patterns from random
            -- fluctuations. The design accommodates jurisdictional differences in compliance requirements,
            -- enabling global organizations to monitor compliance consistently across regions. The view serves
            -- as the foundation for compliance scorecards that track progress against organizational compliance
            -- goals and regulatory requirements. It also supports root cause analysis of recurring compliance
            -- issues by identifying common factors across violations. For regulatory reporting, the view provides
            -- the necessary data in the required format, reducing preparation time for compliance submissions.
            -- By centralizing compliance data in this view, the system reduces the time and effort required to
            -- produce compliance reports and enables proactive management of compliance risks. The implementation
            -- includes benchmark comparisons against industry standards to provide context for compliance
            -- performance. The view is optimized for performance with pre-aggregated metrics where possible,
            -- ensuring responsive analytics even with large historical datasets. It enables data-driven decisions
            -- about compliance initiatives and resource allocation for compliance management.
            -- KPI: Compliance violation rate, Time to resolve violations,
            --      Critical violation count, Compliance remediation success rate,
            --      Audit readiness score
            -- Feature Reference: 601, 602, 603, 604, 605
            CREATE OR REPLACE VIEW reporting.v_schedule_compliance_dashboard AS
            SELECT
                l.location_id,
                l.location_name,
                l.region,
                d.department_id,
                d.department_name,
                p.position_id,
                p.position_title,
                r.rule_type,
                r.jurisdiction,
                DATE_TRUNC('week', sc.detected_at) AS week_start,
                COUNT(sc.compliance_id) AS violation_count,
                COUNT(CASE WHEN sc.violation_severity = 'CRITICAL' THEN 1 END) AS critical_violations,
                COUNT(CASE WHEN sc.violation_severity = 'HIGH' THEN 1 END) AS high_violations,
                COUNT(CASE WHEN sc.violation_severity = 'MEDIUM' THEN 1 END) AS medium_violations,
                COUNT(CASE WHEN sc.violation_severity = 'LOW' THEN 1 END) AS low_violations,
                COUNT(CASE WHEN sc.status = 'OPEN' THEN 1 END) AS open_violations,
                COUNT(CASE WHEN sc.status = 'IN_PROGRESS' THEN 1 END) AS in_progress_violations,
                COUNT(CASE WHEN sc.status = 'RESOLVED' THEN 1 END) AS resolved_violations,
                COUNT(CASE WHEN sc.exception_approved_by IS NOT NULL THEN 1 END) AS exceptions,
                AVG(EXTRACT(EPOCH FROM (sc.resolved_at - sc.detected_at)) / 86400)
                    FILTER (WHERE sc.resolved_at IS NOT NULL) AS avg_resolution_days,
                (COUNT(CASE WHEN sc.status = 'RESOLVED' THEN 1 END)::NUMERIC /
                    NULLIF(COUNT(sc.compliance_id), 0)) * 100 AS resolution_rate,
                jsonb_build_object(
                    'repeat_violations', COUNT(*) FILTER (WHERE sc.entity_id IN (
                        SELECT entity_id
                        FROM scheduling.schedule_compliance sc2
                        WHERE sc2.rule_id = sc.rule_id
                        AND sc2.detected_at < sc.detected_at - INTERVAL '30 days'
                    ))
                ) AS pattern_analysis
            FROM scheduling.schedule_compliance sc
            JOIN compliance.union_rules r ON sc.rule_id = r.rule_id
            JOIN operations.locations l ON sc.entity_id = l.location_id AND sc.entity_type = 'LOCATION'
            JOIN hr.departments d ON sc.entity_id = d.department_id AND sc.entity_type = 'DEPARTMENT'
            JOIN hr.positions p ON sc.entity_id = p.position_id AND sc.entity_type = 'POSITION'
            WHERE sc.detected_at >= CURRENT_DATE - INTERVAL '2 years'
            GROUP BY
                l.location_id, l.location_name, l.region,
                d.department_id, d.department_name,
                p.position_id, p.position_title,
