            -- Serial No: 120 | TABLE: scheduling.schedule_generation_history
            -- Description: Detailed tracking of schedule generation processes and outcomes
            -- Business Case: The schedule_generation_history table maintains a comprehensive record of all schedule
            -- generation processes, providing visibility into the performance and outcomes of scheduling algorithms.
            -- It captures detailed information about each generation attempt including input parameters, execution
            -- time, constraint violations, and optimization metrics. This information is critical for diagnosing
            -- scheduling issues, optimizing algorithm performance, and ensuring consistent schedule quality. The
            -- table supports multiple generation methods including manual, automated, and AI-driven approaches,
            -- accommodating different scheduling workflows. Each record includes metadata about the business
            -- context during generation to enable accurate assessment of scheduling decisions. Historical
            -- generation data is maintained to identify trends in algorithm performance and measure the impact
            -- of configuration changes over time. For compliance purposes, the system tracks the approval status
            -- of generated schedules and maintains audit trails of all modifications. The table integrates with
            -- the scheduling engine to enable continuous improvement of scheduling algorithms based on historical
            -- performance. The design accommodates complex scheduling scenarios with multiple constraints and
            -- optimization objectives, providing detailed insights into trade-offs made during schedule generation.
            -- By centralizing generation history, the organization can ensure consistent evaluation of scheduling
            -- performance while providing the data needed for algorithm refinement. The table is optimized for
            -- rapid querying during performance analysis, which often involves comparing multiple generation runs
            -- to identify improvement opportunities.
            -- KPI: Schedule generation success rate, Generation time,
            --      Constraint violation rate, Optimization score improvement,
            --      Schedule quality consistency
            -- Feature Reference: 616, 617, 618, 619, 620
            CREATE TABLE IF NOT EXISTS scheduling.schedule_generation_history (
                generation_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                schedule_id UUID REFERENCES scheduling.schedules(schedule_id),
                generation_request_id UUID NOT NULL,
                requestor_id UUID NOT NULL REFERENCES hr.employees(employee_id),
                request_time TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                start_time TIMESTAMP WITH TIME ZONE NOT NULL,
                end_time TIMESTAMP WITH TIME ZONE NOT NULL,
                duration_ms INTEGER NOT NULL CHECK (duration_ms >= 0),
                status VARCHAR(20) NOT NULL CHECK (status IN ('SUCCESS', 'PARTIAL_SUCCESS', 'FAILURE')),
                error_message TEXT,
                parameters JSONB NOT NULL,
                constraint_violation_count INTEGER NOT NULL DEFAULT 0,
                constraint_violations JSONB,
                optimization_score NUMERIC(5,2) CHECK (optimization_score BETWEEN 0.00 AND 100.00),
                coverage_percentage NUMERIC(5,2) CHECK (coverage_percentage BETWEEN 0.00 AND 100.00),
                labor_cost_estimate NUMERIC(12,2),
                shift_count INTEGER NOT NULL DEFAULT 0,
                employee_count INTEGER NOT NULL DEFAULT 0,
                preference_fulfillment_rate NUMERIC(5,2) CHECK (preference_fulfillment_rate BETWEEN 0.00 AND 100.00),
                algorithm_version VARCHAR(20) NOT NULL,
                algorithm_parameters JSONB,
                input_data_quality_score NUMERIC(5,2) CHECK (input_data_quality_score BETWEEN 0.00 AND 100.00),
                notes TEXT,
                created_by UUID NOT NULL,
                created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_by UUID,
                updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                metadata JSONB
            );

            -- Add indexes for performance
            CREATE INDEX IF NOT EXISTS idx_schedule_generation_request ON scheduling.schedule_generation_history(generation_request_id);
            CREATE INDEX IF NOT EXISTS idx_schedule_generation_requestor ON scheduling.schedule_generation_history(requestor_id);
            CREATE INDEX IF NOT EXISTS idx_schedule_generation_time ON scheduling.schedule_generation_history(start_time, end_time);
            CREATE INDEX IF NOT EXISTS idx_schedule_generation_status ON scheduling.schedule_generation_history(status);
            CREATE INDEX IF NOT EXISTS idx_schedule_generation_duration ON scheduling.schedule_generation_history(duration_ms);
            CREATE INDEX IF NOT EXISTS idx_schedule_generation_score ON scheduling.schedule_generation_history(optimization_score DESC);
            CREATE INDEX IF NOT EXISTS idx_schedule_generation_coverage ON scheduling.schedule_generation_history(coverage_percentage DESC);
            CREATE INDEX IF NOT EXISTS idx_schedule_generation_parameters ON scheduling.schedule_generation_history USING GIN(parameters);
            CREATE INDEX IF NOT EXISTS idx_schedule_generation_metadata ON scheduling.schedule_generation_history USING GIN(metadata);

            -- Add triggers for audit columns
            CREATE TRIGGER trg_schedule_generation_history_updated_at
            BEFORE UPDATE ON scheduling.schedule_generation_history
            FOR EACH ROW
            EXECUTE FUNCTION update_updated_at_column();

