            audit trails for compliance. Integrates with scheduling engine for continuous improvement. Accommodates complex scheduling
            scenarios with multiple constraints. Centralizes generation history for consistent evaluation. Optimized for rapid querying
            during performance analysis.';




                -- Serial No: 121 | TABLE: analytics.skill_coverage_analysis
                -- Description: Historical and projected skill-based coverage metrics
                -- Business Case: The skill_coverage_analysis table stores historical and projected metrics related to
                -- skill-based shift coverage, providing critical insights for workforce planning and scheduling optimization.
                -- It captures data on skill gaps, over-qualification, and skill-based coverage to ensure schedules meet
                -- operational requirements while optimizing labor costs. The table supports multiple skill coverage
                -- dimensions including time periods, locations, departments, and specific skill requirements, enabling
                -- comprehensive analysis of skill coverage patterns. Each coverage record includes metadata about the
                -- calculation methodology, data sources, and confidence level to ensure proper interpretation of results.
                -- The implementation includes historical tracking of skill coverage metrics to identify trends and
                -- measure the impact of scheduling changes over time. For operational planning, the system stores
                -- coverage data at multiple granularities (hourly, daily, weekly) to support different planning horizons.
                -- The table integrates with the scheduling engine to enable real-time skill coverage validation during
                -- schedule creation and modification. The design accommodates different skill coverage requirements for
                -- various business units and operational contexts, providing a flexible framework for skill coverage
                -- analysis. By centralizing skill coverage data, the organization can ensure consistent evaluation of
                -- skill coverage metrics while providing the flexibility needed for location-specific requirements.
                -- The table is optimized for rapid querying during schedule optimization, which often involves evaluating
                -- skill coverage constraints for potentially hundreds of shifts simultaneously.
                -- KPI: Skill coverage rate, Certification compliance rate,
                --      Skill gap identification rate, Development goal achievement rate,
                --      Skill-based scheduling effectiveness
                -- Feature Reference: 621, 622, 623, 624, 625
                CREATE TABLE IF NOT EXISTS analytics.skill_coverage_analysis (
                    analysis_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    analysis_date DATE NOT NULL,
                    time_period VARCHAR(20) NOT NULL CHECK (time_period IN ('HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
                    start_time TIMESTAMP WITH TIME ZONE NOT NULL,
                    end_time TIMESTAMP WITH TIME ZONE NOT NULL CHECK (end_time > start_time),
                    location_id UUID NOT NULL REFERENCES operations.locations(location_id),
                    department_id UUID NOT NULL REFERENCES hr.departments(department_id),
                    position_id UUID NOT NULL REFERENCES hr.positions(position_id),
                    skill_id UUID NOT NULL REFERENCES hr.skills(skill_id),
                    required_count INTEGER NOT NULL CHECK (required_count >= 0),
                    available_count INTEGER NOT NULL CHECK (available_count >= 0),
                    covered_count INTEGER NOT NULL CHECK (covered_count >= 0),
                    coverage_gap INTEGER GENERATED ALWAYS AS (required_count - covered_count) STORED,
                    coverage_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
                        CASE
                            WHEN required_count > 0 THEN covered_count::NUMERIC / required_count * 100
                            ELSE 100
                        END
                    ) STORED,
                    minimum_proficiency_required INTEGER NOT NULL CHECK (minimum_proficiency_required BETWEEN 1 AND 5),
                    average_proficiency NUMERIC(4,2) CHECK (average_proficiency BETWEEN 1.0 AND 5.0),
                    certification_required BOOLEAN NOT NULL DEFAULT FALSE,
                    certification_compliance_rate NUMERIC(5,2) CHECK (certification_compliance_rate BETWEEN 0.00 AND 100.00),
                    coverage_type VARCHAR(50) NOT NULL CHECK (coverage_type IN ('MINIMUM', 'OPTIMAL', 'PEAK', 'CUSTOM')),
                    coverage_source VARCHAR(50) NOT NULL CHECK (coverage_source IN ('FORECAST', 'HISTORICAL', 'MANUAL', 'RULE_BASED')),
                    data_confidence NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (data_confidence BETWEEN 0.00 AND 1.00),
                    notes TEXT,
                    created_by UUID NOT NULL,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_by UUID,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_date ON analytics.skill_coverage_analysis(analysis_date, time_period);
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_time ON analytics.skill_coverage_analysis(start_time, end_time);
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_location ON analytics.skill_coverage_analysis(location_id);
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_department ON analytics.skill_coverage_analysis(department_id);
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_position ON analytics.skill_coverage_analysis(position_id);
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_skill ON analytics.skill_coverage_analysis(skill_id);
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_gap ON analytics.skill_coverage_analysis(coverage_gap);
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_percentage ON analytics.skill_coverage_analysis(coverage_percentage);
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_type ON analytics.skill_coverage_analysis(coverage_type);
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_source ON analytics.skill_coverage_analysis(coverage_source);
                CREATE INDEX IF NOT EXISTS idx_skill_coverage_analysis_metadata ON analytics.skill_coverage_analysis USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_skill_coverage_analysis_updated_at
                BEFORE UPDATE ON analytics.skill_coverage_analysis
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE analytics.skill_coverage_analysis IS 'Historical and projected skill-based coverage metrics.
