                    WHERE employee_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_shift_swap_patterns_rates ON scheduling.shift_swap_patterns(approval_rate, completion_rate);
                CREATE INDEX IF NOT EXISTS idx_shift_swap_patterns_impact ON scheduling.shift_swap_patterns(coverage_impact, compliance_impact);
                CREATE INDEX IF NOT EXISTS idx_shift_swap_patterns_satisfaction ON scheduling.shift_swap_patterns(employee_satisfaction_score);
                CREATE INDEX IF NOT EXISTS idx_shift_swap_patterns_metadata ON scheduling.shift_swap_patterns USING GIN(metadata);

                -- Add triggers for audit columns
