                -- Feature Reference: 636, 637, 638, 639, 640
                CREATE TABLE IF NOT EXISTS analytics.schedule_quality_metrics (
                    metric_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    schedule_id UUID NOT NULL REFERENCES scheduling.schedules(schedule_id),
                    metric_date DATE NOT NULL,
                    time_period VARCHAR(20) NOT NULL CHECK (time_period IN ('DAILY', 'WEEKLY', 'MONTHLY', 'QUARTERLY')),
                    location_id UUID NOT NULL REFERENCES operations.locations(location_id),
                    department_id UUID NOT NULL REFERENCES hr.departments(department_id),
                    position_id UUID NOT NULL REFERENCES hr.positions(position_id),
                    coverage_accuracy NUMERIC(5,2) CHECK (coverage_accuracy BETWEEN 0.00 AND 100.00),
                    employee_satisfaction NUMERIC(5,2) CHECK (employee_satisfaction BETWEEN 0.00 AND 100.00),
                    schedule_adherence NUMERIC(5,2) CHECK (schedule_adherence BETWEEN 0.00 AND 100.00),
                    preference_fulfillment_rate NUMERIC(5,2) CHECK (preference_fulfillment_rate BETWEEN 0.00 AND 100.00),
                    compliance_rate NUMERIC(5,2) CHECK (compliance_rate BETWEEN 0.00 AND 100.00),
                    labor_cost_efficiency NUMERIC(5,2) CHECK (labor_cost_efficiency BETWEEN 0.00 AND 100.00),
                    schedule_stability NUMERIC(5,2) CHECK (schedule_stability BETWEEN 0.00 AND 100.00),
                    quality_score NUMERIC(5,2) GENERATED ALWAYS AS (
                        (COALESCE(coverage_accuracy, 0) * 0.2) +
                        (COALESCE(employee_satisfaction, 0) * 0.2) +
                        (COALESCE(schedule_adherence, 0) * 0.15) +
                        (COALESCE(preference_fulfillment_rate, 0) * 0.15) +
                        (COALESCE(compliance_rate, 0) * 0.15) +
                        (COALESCE(labor_cost_efficiency, 0) * 0.1) +
                        (COALESCE(schedule_stability, 0) * 0.05)
                    ) STORED,
                    metric_source VARCHAR(50) NOT NULL CHECK (metric_source IN ('SYSTEM', 'SURVEY', 'OBSERVATION', 'MANAGER_ASSESSMENT')),
                    data_confidence NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (data_confidence BETWEEN 0.00 AND 1.00),
                    notes TEXT,
                    created_by UUID NOT NULL,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_by UUID,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_schedule_quality_metrics_schedule ON analytics.schedule_quality_metrics(schedule_id);
                CREATE INDEX IF NOT EXISTS idx_schedule_quality_metrics_date ON analytics.schedule_quality_metrics(metric_date, time_period);
                CREATE INDEX IF NOT EXISTS idx_schedule_quality_metrics_location ON analytics.schedule_quality_metrics(location_id);
                CREATE INDEX IF NOT EXISTS idx_schedule_quality_metrics_department ON analytics.schedule_quality_metrics(department_id);
                CREATE INDEX IF NOT EXISTS idx_schedule_quality_metrics_position ON analytics.schedule_quality_metrics(position_id);
                CREATE INDEX IF NOT EXISTS idx_schedule_quality_metrics_score ON analytics.schedule_quality_metrics(quality_score);
                CREATE INDEX IF NOT EXISTS idx_schedule_quality_metrics_coverage ON analytics.schedule_quality_metrics(coverage_accuracy);
                CREATE INDEX IF NOT EXISTS idx_schedule_quality_metrics_satisfaction ON analytics.schedule_quality_metrics(employee_satisfaction);
                CREATE INDEX IF NOT EXISTS idx_schedule_quality_metrics_source ON analytics.schedule_quality_metrics(metric_source);
                CREATE INDEX IF NOT EXISTS idx_schedule_quality_metrics_metadata ON analytics.schedule_quality_metrics USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_schedule_quality_metrics_updated_at
                BEFORE UPDATE ON analytics.schedule_quality_metrics
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE analytics.schedule_quality_metrics IS 'Historical and projected schedule quality metrics.
                Stores historical and projected metrics related to schedule quality. Captures data on schedule adherence, employee satisfaction,
                and coverage accuracy. Supports multiple quality measurement methodologies. Includes metadata about data sources and calculation
                methodology. Historical tracking of quality metrics to identify trends. Stores quality data at multiple granularities. Integrates
                with scheduling engine for continuous improvement. Accommodates different quality benchmarks for various business units.
                Centralizes schedule quality data for consistent evaluation. Optimized for rapid querying during schedule optimization.';

