                CREATE TABLE IF NOT EXISTS analytics.performance_benchmarks (
                    benchmark_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    benchmark_code VARCHAR(50) UNIQUE NOT NULL CHECK (benchmark_code ~ '^[A-Z0-9_]{5,50}$'),
                    name VARCHAR(200) NOT NULL,
                    description TEXT,
                    metric_name VARCHAR(100) NOT NULL CHECK (metric_name IN ('LABOR_COST_PER_TRANSACTION', 'SCHEDULE_ADHERENCE_RATE',
                        'EMPLOYEE_SATISFACTION_SCORE', 'COVERAGE_ACCURACY_RATE', 'ABSENTEEISM_RATE', 'TURNOVER_RATE',
                        'PREFERENCE_FULFILLMENT_RATE', 'COMPLIANCE_RATE')),
                    location_id UUID REFERENCES operations.locations(location_id),
                    department_id UUID REFERENCES hr.departments(department_id),
                    position_id UUID REFERENCES hr.positions(position_id),
                    benchmark_type VARCHAR(50) NOT NULL DEFAULT 'MINIMUM'
                        CHECK (benchmark_type IN ('MINIMUM', 'TARGET', 'STRETCH', 'INDUSTRY', 'CUSTOM')),
                    target_value NUMERIC(10,4) NOT NULL,
                    acceptable_range_low NUMERIC(10,4),
                    acceptable_range_high NUMERIC(10,4),
                    priority INTEGER DEFAULT 0 CHECK (priority BETWEEN -10 AND 10),
                    effective_start_date DATE NOT NULL DEFAULT CURRENT_DATE,
                    effective_end_date DATE,
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    is_default BOOLEAN NOT NULL DEFAULT FALSE,
                    version INTEGER NOT NULL DEFAULT 1 CHECK (version >= 1),
                    based_on_benchmark_id UUID REFERENCES analytics.performance_benchmarks(benchmark_id),
                    validated_by UUID REFERENCES hr.employees(employee_id),
                    validated_at TIMESTAMP WITH TIME ZONE,
                    validation_results JSONB,
                    usage_count INTEGER NOT NULL DEFAULT 0,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB,

                    -- Constraints
                    CONSTRAINT chk_benchmark_dates CHECK (effective_end_date IS NULL OR effective_end_date >= effective_start_date),
                    CONSTRAINT chk_benchmark_ranges CHECK (
                        (acceptable_range_low IS NULL AND acceptable_range_high IS NULL) OR
                        (acceptable_range_low IS NOT NULL AND acceptable_range_high IS NOT NULL AND acceptable_range_high >= acceptable_range_low)
                    )
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_performance_benchmarks_metric ON analytics.performance_benchmarks(metric_name);
                CREATE INDEX IF NOT EXISTS idx_performance_benchmarks_location ON analytics.performance_benchmarks(location_id)
