                CREATE INDEX IF NOT EXISTS idx_performance_benchmarks_department ON analytics.performance_benchmarks(department_id)
                    WHERE department_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_performance_benchmarks_position ON analytics.performance_benchmarks(position_id)
                    WHERE position_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_performance_benchmarks_type ON analytics.performance_benchmarks(benchmark_type);
                CREATE INDEX IF NOT EXISTS idx_performance_benchmarks_active ON analytics.performance_benchmarks(is_active)
                    WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_performance_benchmarks_default ON analytics.performance_benchmarks(is_default)
                    WHERE is_default = TRUE;
                CREATE INDEX IF NOT EXISTS idx_performance_benchmarks_version ON analytics.performance_benchmarks(benchmark_id, version DESC);
                CREATE INDEX IF NOT EXISTS idx_performance_benchmarks_based_on ON analytics.performance_benchmarks(based_on_benchmark_id);
                CREATE INDEX IF NOT EXISTS idx_performance_benchmarks_metadata ON analytics.performance_benchmarks USING GIN(metadata);

