                -- Serial No: 129 | TABLE: scheduling.schedule_optimization
                -- Description: Configuration and results of schedule optimization processes
                -- Business Case: The schedule_optimization table stores configuration details and results of schedule
                -- optimization processes, providing visibility into the performance and outcomes of scheduling algorithms.
                -- It captures detailed information about each optimization attempt including input parameters, execution
                -- time, constraint violations, and optimization metrics. This information is critical for diagnosing
                -- scheduling issues, optimizing algorithm performance, and ensuring consistent schedule quality. The
                -- table supports multiple optimization methods including manual, automated, and AI-driven approaches,
                -- accommodating different scheduling workflows. Each record includes metadata about the business
                -- context during optimization to enable accurate assessment of scheduling decisions. Historical
                -- optimization data is maintained to identify trends in algorithm performance and measure the impact
                -- of configuration changes over time. For compliance purposes, the system tracks the approval status
                -- of optimized schedules and maintains audit trails of all modifications. The table integrates with
                -- the scheduling engine to enable continuous improvement of scheduling algorithms based on historical
                -- performance. The design accommodates complex scheduling scenarios with multiple constraints and
                -- optimization objectives, providing detailed insights into trade-offs made during schedule optimization.
                -- By centralizing optimization history, the organization can ensure consistent evaluation of scheduling
                -- performance while providing the data needed for algorithm refinement. The table is optimized for
                -- rapid querying during performance analysis, which often involves comparing multiple optimization runs
                -- to identify improvement opportunities.
                -- KPI: Optimization success rate, Optimization time,
                --      Constraint violation rate, Optimization score improvement,
                --      Schedule quality consistency
                -- Feature Reference: 661, 662, 663, 664, 665
                CREATE TABLE IF NOT EXISTS scheduling.schedule_optimization (
                    optimization_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    schedule_id UUID REFERENCES scheduling.schedules(schedule_id),
                    optimization_request_id UUID NOT NULL,
                    requestor_id UUID NOT NULL REFERENCES hr.employees(employee_id),
                    request_time TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    start_time TIMESTAMP WITH TIME ZONE NOT NULL,
                    end_time TIMESTAMP WITH TIME ZONE NOT NULL,
                    duration_ms INTEGER NOT NULL CHECK (duration_ms >= 0),
                    status VARCHAR(20) NOT NULL CHECK (status IN ('SUCCESS', 'PARTIAL_SUCCESS', 'FAILURE')),
                    error_message TEXT,
                    parameters JSONB NOT NULL,
                    constraint_violation_count INTEGER NOT NULL DEFAULT 0,
                    constraint_violations JSONB,
                    optimization_score NUMERIC(5,2) CHECK (optimization_score BETWEEN 0.00 AND 100.00),
                    coverage_percentage NUMERIC(5,2) CHECK (coverage_percentage BETWEEN 0.00 AND 100.00),
                    labor_cost_estimate NUMERIC(12,2),
                    shift_count INTEGER NOT NULL DEFAULT 0,
