                    last_delivery_status VARCHAR(20) CHECK (last_delivery_status IN ('SUCCESS', 'FAILED', 'PENDING')),
                    last_delivery_response TEXT,
                    delivery_statistics JSONB DEFAULT '{"success_count": 0, "failure_count": 0, "average_latency_ms": 0}'::JSONB,
                    created_by UUID NOT NULL,
                    updated_by UUID,
