                -- Serial No: 132 | TABLE: integration.webhook_deliveries
                -- Description: Detailed tracking of webhook delivery attempts and results
                -- Business Case: The webhook_deliveries table maintains a comprehensive record of all webhook delivery
                -- attempts, providing visibility into integration performance and reliability. It captures detailed
                -- information about each delivery attempt including request payload, response, and timing metrics to
                -- support troubleshooting of integration issues. This information is critical for diagnosing delivery
                -- failures, optimizing integration performance, and ensuring reliable event delivery. The table supports
                -- multiple delivery statuses including success, failure, and pending states, accommodating different
                -- integration scenarios. Each delivery record includes metadata about the event type, webhook
                -- configuration, and retry context to enable accurate assessment of delivery outcomes. Historical
                -- delivery data is maintained to identify patterns in delivery success and measure the impact of
                -- configuration changes over time. For operational efficiency, the system tracks retry attempts to
                -- avoid redundant processing and enable targeted troubleshooting. The table integrates with the event
                -- notification system to enable real-time monitoring of delivery status and automated retry
                -- processing. The design accommodates complex delivery scenarios with multiple retry attempts and
                -- varying response patterns, providing detailed insights into integration behavior. By centralizing
                -- delivery tracking, the organization can ensure consistent evaluation of integration performance
                -- while providing the data needed for integration improvement. The table is optimized for rapid
                -- querying during incident response, which often involves identifying delivery issues across multiple
                -- webhook endpoints and time periods.
                -- KPI: Delivery success rate, Average delivery latency,
                --      Retry success rate, Integration error resolution time,
                --      Delivery failure root cause identification rate
                -- Feature Reference: 676, 677, 678, 679, 680
                CREATE TABLE IF NOT EXISTS integration.webhook_deliveries (
                    delivery_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    webhook_id UUID NOT NULL REFERENCES integration.webhooks(webhook_id) ON DELETE CASCADE,
                    event_type integration.webhook_event_enum NOT NULL,
                    event_id UUID NOT NULL,
                    event_payload JSONB NOT NULL,
                    attempt_number INTEGER NOT NULL DEFAULT 1 CHECK (attempt_number >= 1),
                    request_timestamp TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    response_timestamp TIMESTAMP WITH TIME ZONE,
                    duration_ms INTEGER GENERATED ALWAYS AS (
                        CASE
                            WHEN response_timestamp IS NOT NULL
                                THEN EXTRACT(EPOCH FROM (response_timestamp - request_timestamp)) * 1000
                            ELSE NULL
                        END
                    ) STORED,
                    status VARCHAR(20) NOT NULL CHECK (status IN ('SUCCESS', 'FAILED', 'PENDING')),
                    http_status_code INTEGER,
                    response_payload TEXT,
                    error_message TEXT,
                    retry_context JSONB,
                    created_by UUID NOT NULL,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_by UUID,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_webhook ON integration.webhook_deliveries(webhook_id);
                CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_event ON integration.webhook_deliveries(event_type, event_id);
                CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_status ON integration.webhook_deliveries(status);
                CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_timestamp ON integration.webhook_deliveries(request_timestamp DESC);
                CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_duration ON integration.webhook_deliveries(duration_ms);
                CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_http_status ON integration.webhook_deliveries(http_status_code);
                CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_metadata ON integration.webhook_deliveries USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_webhook_deliveries_updated_at
                BEFORE UPDATE ON integration.webhook_deliveries
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

