                CREATE INDEX IF NOT EXISTS idx_api_keys_type ON security.api_keys(key_type);
                CREATE INDEX IF NOT EXISTS idx_api_keys_expires ON security.api_keys(expires_at) WHERE is_revoked = FALSE;
                CREATE INDEX IF NOT EXISTS idx_api_keys_revoked ON security.api_keys(is_revoked) WHERE is_revoked = TRUE;
                CREATE INDEX IF NOT EXISTS idx_api_keys_client ON security.api_keys(client_id);
                CREATE INDEX IF NOT EXISTS idx_api_keys_prefix ON security.api_keys(key_prefix);
                CREATE INDEX IF NOT EXISTS idx_api_keys_scopes ON security.api_keys USING GIN(scopes);
