                CREATE TABLE IF NOT EXISTS communication.message_delivery_logs (
                    delivery_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    message_id UUID NOT NULL REFERENCES communication.message_queues(message_id) ON DELETE CASCADE,
                    channel_type communication.channel_type_enum NOT NULL,
                    delivery_attempt INTEGER NOT NULL DEFAULT 1 CHECK (delivery_attempt >= 1),
                    attempt_timestamp TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    response_timestamp TIMESTAMP WITH TIME ZONE,
                    duration_ms INTEGER GENERATED ALWAYS AS (
                        CASE
                            WHEN response_timestamp IS NOT NULL
                                THEN EXTRACT(EPOCH FROM (response_timestamp - attempt_timestamp)) * 1000
                            ELSE NULL
                        END
                    ) STORED,
                    status VARCHAR(20) NOT NULL CHECK (status IN ('SUCCESS', 'FAILED', 'PENDING')),
                    external_status_code VARCHAR(50),
                    external_response TEXT,
                    error_message TEXT,
                    delivery_metadata JSONB,
                    created_by UUID NOT NULL,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_by UUID,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

