                CREATE INDEX IF NOT EXISTS idx_message_delivery_logs_channel ON communication.message_delivery_logs(channel_type);
                CREATE INDEX IF NOT EXISTS idx_message_delivery_logs_status ON communication.message_delivery_logs(status);
                CREATE INDEX IF NOT EXISTS idx_message_delivery_logs_timestamp ON communication.message_delivery_logs(attempt_timestamp DESC);
                CREATE INDEX IF NOT EXISTS idx_message_delivery_logs_duration ON communication.message_delivery_logs(duration_ms);
                CREATE INDEX IF NOT EXISTS idx_message_delivery_logs_external ON communication.message_delivery_logs(external_status_code);
