                -- Serial No: 142 | TABLE: data_governance.data_lineage
                -- Description: Tracking of data flow and transformation across the system
                -- Business Case: The data_lineage table maintains a comprehensive record of data flow and
                -- transformation across the workforce scheduling system, providing visibility into how data moves
                -- from source to destination. It captures detailed information about data transformations,
                -- calculations, and business rules applied at each step to support data quality assessment and
                -- troubleshooting. This information is critical for understanding data provenance, diagnosing data
                -- quality issues, and ensuring regulatory compliance with data handling requirements. The table
                -- supports multiple lineage types including technical lineage (system-to-system data flow) and
                -- business lineage (business rule application), accommodating different analysis needs. Each lineage
                -- record includes metadata about the data elements involved, transformation logic, and timing to
                -- enable accurate reconstruction of data history. Historical lineage data is maintained to identify
                -- changes in data processing patterns and measure the impact of system changes over time. For
                -- operational efficiency, the system tracks data quality metrics at each transformation step to
                -- enable targeted quality improvement. The table integrates with the data catalog to provide
                -- context for data elements and their relationships. The design accommodates complex data flows
                -- with multiple transformation steps and branching paths, providing detailed insights into data
                -- processing. By centralizing data lineage tracking, the organization can ensure consistent
                -- understanding of data flow while providing the flexibility needed for different analysis scenarios.
                -- The table is optimized for rapid querying during data quality investigations, which often involves
                -- tracing data issues through multiple transformation steps.
                -- KPI: Data lineage completeness, Data quality impact identification rate,
                --      Lineage query performance, Data traceability rate,
                --      Impact of data changes
                -- Feature Reference: 726, 727, 728, 729, 730
                CREATE TABLE IF NOT EXISTS data_governance.data_lineage (
                    lineage_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    source_system VARCHAR(100) NOT NULL,
                    source_table VARCHAR(200) NOT NULL,
                    source_column VARCHAR(100) NOT NULL,
                    transformation_rule TEXT NOT NULL,
                    transformation_type VARCHAR(50) NOT NULL CHECK (transformation_type IN ('CALCULATION', 'AGGREGATION',
                        'JOIN', 'FILTER', 'LOOKUP', 'ENRICHMENT', 'VALIDATION')),
                    target_system VARCHAR(100) NOT NULL,
                    target_table VARCHAR(200) NOT NULL,
                    target_column VARCHAR(100) NOT NULL,
                    process_id UUID,
                    process_name VARCHAR(200),
                    execution_time TIMESTAMP WITH TIME ZONE NOT NULL,
                    data_quality_metrics JSONB,
                    row_count BIGINT NOT NULL CHECK (row_count >= 0),
                    lineage_type VARCHAR(50) NOT NULL CHECK (lineage_type IN ('TECHNICAL', 'BUSINESS', 'OPERATIONAL')),
                    lineage_level VARCHAR(50) NOT NULL CHECK (lineage_level IN ('COLUMN', 'TABLE', 'PROCESS', 'SYSTEM')),
                    created_by UUID NOT NULL,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_by UUID,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_lineage_source ON data_governance.data_lineage(source_system, source_table, source_column);
                CREATE INDEX IF NOT EXISTS idx_data_lineage_target ON data_governance.data_lineage(target_system, target_table, target_column);
                CREATE INDEX IF NOT EXISTS idx_data_lineage_transformation ON data_governance.data_lineage(transformation_type);
                CREATE INDEX IF NOT EXISTS idx_data_lineage_process ON data_governance.data_lineage(process_id, process_name);
                CREATE INDEX IF NOT EXISTS idx_data_lineage_time ON data_governance.data_lineage(execution_time DESC);
                CREATE INDEX IF NOT EXISTS idx_data_lineage_type ON data_governance.data_lineage(lineage_type, lineage_level);
                CREATE INDEX IF NOT EXISTS idx_data_lineage_quality ON data_governance.data_lineage USING GIN(data_quality_metrics);
                CREATE INDEX IF NOT EXISTS idx_data_lineage_metadata ON data_governance.data_lineage USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_lineage_updated_at
                BEFORE UPDATE ON data_governance.data_lineage
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_lineage IS 'Tracking of data flow and transformation across the system.
                Maintains comprehensive record of data flow and transformation across the workforce scheduling system. Captures detailed
                information about data transformations and business rules. Critical for understanding data provenance and diagnosing issues.
                Supports multiple lineage types including technical and business lineage. Includes metadata about data elements and timing.
                Historical lineage data maintained to identify changes in processing patterns. Tracks data quality metrics at each step.
                Integrates with data catalog for context. Accommodates complex data flows with multiple transformation steps. Centralizes
                data lineage tracking for consistent understanding. Optimized for rapid querying during data quality investigations.';

                -- Serial No: 143 | TABLE: data_governance.data_catalog
                -- Description: Centralized catalog of data assets with metadata and business context
                -- Business Case: The data_catalog table serves as the central repository for all data assets across
                -- the workforce scheduling system, providing comprehensive metadata and business context for each
                -- data element. It captures essential information including data definitions, business rules, data
                -- quality metrics, and ownership to ensure consistent understanding and usage of data across the
                -- organization. The table supports multiple asset types including tables, columns, reports, and
                -- metrics, accommodating different data elements across the system. Each catalog record includes
                -- metadata about data classification, sensitivity, and usage patterns to support data governance
                -- and compliance requirements. The implementation includes robust versioning of catalog entries to
                -- track changes over time while maintaining historical context for data elements. Historical usage
                -- data is maintained to identify popular data assets and underutilized elements that may be
                -- candidates for deprecation. For operational efficiency, the system tracks data quality metrics
                -- with each catalog entry to enable proactive identification of data issues. The table integrates
                -- with the data lineage system to provide context about how data elements are transformed and used
                -- across the organization. The design accommodates different metadata requirements for various data
                -- types while providing a consistent interface for data discovery. By centralizing data cataloging,
                -- the organization can ensure consistent data understanding while providing the flexibility needed
                -- for different business units and analysis scenarios. The table is optimized for rapid querying
                -- during data discovery, which is critical for user experience when searching for relevant data
                -- assets.
                -- KPI: Catalog coverage completeness, Data discovery time,
                --      Metadata quality score, Data asset utilization rate,
                --      Data governance compliance rate
                -- Feature Reference: 731, 732, 733, 734, 735
                CREATE TABLE IF NOT EXISTS data_governance.data_catalog (
                    asset_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    asset_type VARCHAR(50) NOT NULL CHECK (asset_type IN ('TABLE', 'COLUMN', 'REPORT', 'METRIC', 'DASHBOARD', 'VIEW')),
                    asset_name VARCHAR(200) NOT NULL,
                    asset_path VARCHAR(500) NOT NULL,
                    schema_name VARCHAR(100),
                    table_name VARCHAR(200),
                    column_name VARCHAR(200),
                    display_name VARCHAR(200) NOT NULL,
                    description TEXT NOT NULL,
                    business_definition TEXT,
                    technical_definition TEXT,
                    data_type VARCHAR(50),
                    data_format VARCHAR(50),
                    data_classification VARCHAR(50) NOT NULL CHECK (data_classification IN ('PUBLIC', 'INTERNAL', 'CONFIDENTIAL',
                        'RESTRICTED', 'HIGHLY_RESTRICTED')),
                    sensitivity_level VARCHAR(50) NOT NULL CHECK (sensitivity_level IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
                    owner_id UUID REFERENCES hr.employees(employee_id),
                    steward_id UUID REFERENCES hr.employees(employee_id),
                    data_quality_metrics JSONB,
                    usage_statistics JSONB DEFAULT '{"access_count": 0, "unique_users": 0, "last_accessed": null}'::JSONB,
                    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_catalog_type ON data_governance.data_catalog(asset_type);
                CREATE INDEX IF NOT EXISTS idx_data_catalog_path ON data_governance.data_catalog(asset_path);
                CREATE INDEX IF NOT EXISTS idx_data_catalog_schema ON data_governance.data_catalog(schema_name)
                    WHERE schema_name IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_catalog_table ON data_governance.data_catalog(table_name)
                    WHERE table_name IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_catalog_column ON data_governance.data_catalog(column_name)
                    WHERE column_name IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_catalog_classification ON data_governance.data_catalog(data_classification);
                CREATE INDEX IF NOT EXISTS idx_data_catalog_sensitivity ON data_governance.data_catalog(sensitivity_level);
                CREATE INDEX IF NOT EXISTS idx_data_catalog_owner ON data_governance.data_catalog(owner_id)
                    WHERE owner_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_catalog_steward ON data_governance.data_catalog(steward_id)
                    WHERE steward_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_catalog_quality ON data_governance.data_catalog USING GIN(data_quality_metrics);
                CREATE INDEX IF NOT EXISTS idx_data_catalog_usage ON data_governance.data_catalog USING GIN(usage_statistics);
                CREATE INDEX IF NOT EXISTS idx_data_catalog_metadata ON data_governance.data_catalog USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_catalog_updated_at
                BEFORE UPDATE ON data_governance.data_catalog
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_catalog IS 'Centralized catalog of data assets with metadata and business context.
                Serves as central repository for all data assets across the workforce scheduling system. Captures data definitions, business
                rules, and quality metrics. Supports multiple asset types including tables and reports. Includes metadata about classification
                and sensitivity. Includes versioning to track changes over time. Historical usage data maintained to identify popular assets.
                Tracks data quality metrics for proactive issue identification. Integrates with data lineage system for context. Accommodates
                different metadata requirements for various data types. Centralizes data cataloging for consistent understanding. Optimized
                for rapid querying during data discovery.';

                -- Serial No: 144 | TABLE: data_governance.data_quality_dashboards
                -- Description: Configuration of data quality monitoring dashboards and reports
                -- Business Case: The data_quality_dashboards table stores configuration details for data quality
                -- monitoring dashboards and reports, providing a centralized repository for data quality visibility.
                -- It captures essential information including dashboard purpose, data sources, visualizations, and
                -- alerting rules to ensure consistent monitoring of data health across the organization. The table
                -- supports versioning of dashboard configurations to track changes over time and maintain historical
                -- monitoring standards. Each configuration includes security controls to ensure dashboards only access
                -- data the user is authorized to see, maintaining data governance throughout the monitoring process.
                -- Comprehensive usage statistics are tracked to identify effective monitoring approaches and
                -- underutilized configurations that may be candidates for deprecation. The implementation includes
                -- performance metrics to monitor dashboard load times and optimize slow-performing monitoring views.
                -- For proactive monitoring, the system stores alerting thresholds and notification rules to enable
                -- timely identification of data quality issues. The table also tracks user feedback to support
                -- continuous improvement of monitoring content and design. By centralizing monitoring configurations,
                -- the system reduces the time and effort required to create new monitoring views while ensuring
                -- consistency in data quality assessment. The design accommodates both operational monitoring needed
                -- for daily data management and strategic monitoring for executive oversight of data governance. The
                -- table is optimized for rapid lookup during monitoring view rendering and for historical analysis
                -- of monitoring effectiveness, supporting continuous improvement of the data quality program.
                -- KPI: Monitoring coverage completeness, Alert accuracy rate,
                --      Dashboard load time, Issue detection time,
                --      Data quality trend direction
                -- Feature Reference: 736, 737, 738, 739, 740
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_dashboards (
                    dashboard_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    dashboard_code VARCHAR(50) UNIQUE NOT NULL CHECK (dashboard_code ~ '^[A-Z0-9_]{3,50}$'),
                    name VARCHAR(200) NOT NULL,
                    description TEXT,
                    dashboard_type VARCHAR(50) NOT NULL CHECK (dashboard_type IN ('REAL_TIME', 'DAILY', 'WEEKLY', 'EXECUTIVE')),
                    category VARCHAR(50) NOT NULL CHECK (category IN ('COMPLETENESS', 'ACCURACY', 'CONSISTENCY', 'TIMELINESS', 'VALIDITY')),
                    data_sources VARCHAR(200)[] NOT NULL,
                    visualizations JSONB NOT NULL,
                    alert_rules JSONB,
                    refresh_frequency VARCHAR(20) NOT NULL DEFAULT 'HOURLY'
                        CHECK (refresh_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
                    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                    approval_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
                        CHECK (approval_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'REJECTED', 'DEPRECATED')),
                    approved_by UUID REFERENCES hr.employees(employee_id),
                    approved_at TIMESTAMP WITH TIME ZONE,
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_quality_dashboards_active ON data_governance.data_quality_dashboards(is_active)
                    WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_dashboards_type ON data_governance.data_quality_dashboards(dashboard_type);
                CREATE INDEX IF NOT EXISTS idx_data_quality_dashboards_category ON data_governance.data_quality_dashboards(category);
                CREATE INDEX IF NOT EXISTS idx_data_quality_dashboards_approval ON data_governance.data_quality_dashboards(approval_status);
                CREATE INDEX IF NOT EXISTS idx_data_quality_dashboards_approved ON data_governance.data_quality_dashboards(approved_by)
                    WHERE approved_by IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_quality_dashboards_visualizations ON data_governance.data_quality_dashboards
                    USING GIN(visualizations);
                CREATE INDEX IF NOT EXISTS idx_data_quality_dashboards_alerts ON data_governance.data_quality_dashboards
                    USING GIN(alert_rules);
                CREATE INDEX IF NOT EXISTS idx_data_quality_dashboards_metadata ON data_governance.data_quality_dashboards
                    USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_quality_dashboards_updated_at
                BEFORE UPDATE ON data_governance.data_quality_dashboards
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_quality_dashboards IS 'Configuration of data quality monitoring dashboards and reports.
                Stores configuration details for data quality monitoring dashboards. Captures dashboard purpose, data sources, and alerting rules.
                Supports versioning of dashboard configurations. Includes security controls to ensure authorized data access. Tracks usage
                statistics to identify effective monitoring approaches. Includes performance metrics to monitor load times. Stores alerting
                thresholds for timely issue identification. Tracks user feedback for continuous improvement. Reduces time and effort required
                to create new monitoring views. Accommodates both operational and strategic monitoring. Optimized for rapid lookup during
                monitoring view rendering.';

                -- Serial No: 145 | TABLE: data_governance.data_quality_rules
                -- Description: Business rules for data quality validation and monitoring
                -- Business Case: The data_quality_rules table defines the business rules used to validate and
                -- monitor data quality across the workforce scheduling system. It captures both technical
                -- validation rules (e.g., null checks, format validation) and business logic rules (e.g.,
                -- schedule coverage thresholds, compliance requirements). Each rule includes metadata about
                -- its severity, frequency of execution, and expected error rates. The table supports multiple
                -- rule types including validation, calculation, and anomaly detection rules, enabling
                -- comprehensive data quality assessment. Rules can be linked to specific business processes
                -- and KPIs to ensure data quality aligns with business objectives. The implementation
                -- includes mechanisms for rule versioning and approval workflows to maintain governance
                -- over data quality standards. The table also tracks rule effectiveness metrics to support
                -- continuous improvement of data quality practices. By centralizing data quality rules,
                -- the system ensures consistent application of data standards across all modules and
                -- provides a foundation for data-driven decision making. The design accommodates evolving
                -- business requirements through flexible rule expressions and parameters.
                -- KPI: Rule coverage completeness, Data issue detection rate,
                --      False positive rate, Rule execution success rate,
                --      Data quality trend improvement
                -- Feature Reference: 741, 742, 743, 744, 745
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_rules (
                    rule_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    rule_code VARCHAR(50) UNIQUE NOT NULL CHECK (rule_code ~ '^[A-Z0-9_]{3,50}$'),
                    name VARCHAR(200) NOT NULL,
                    description TEXT NOT NULL,
                    rule_type VARCHAR(50) NOT NULL CHECK (rule_type IN ('VALIDATION', 'CALCULATION', 'ANOMALY_DETECTION', 'BUSINESS_RULE')),
                    schema_name VARCHAR(50) NOT NULL,
                    table_name VARCHAR(50) NOT NULL,
                    column_name VARCHAR(50),
                    rule_expression TEXT NOT NULL,
                    rule_parameters JSONB,
                    severity VARCHAR(20) NOT NULL DEFAULT 'MEDIUM'
                        CHECK (severity IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
                    execution_frequency VARCHAR(20) NOT NULL DEFAULT 'DAILY'
                        CHECK (execution_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
                    expected_error_rate NUMERIC(5,2) DEFAULT 0.00
                        CHECK (expected_error_rate BETWEEN 0.00 AND 100.00),
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                    approval_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
                        CHECK (approval_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'REJECTED')),
                    approved_by UUID REFERENCES hr.employees(employee_id),
                    approved_at TIMESTAMP WITH TIME ZONE,
                    last_executed TIMESTAMP WITH TIME ZONE,
                    last_issue_count INTEGER DEFAULT 0,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_quality_rules_type ON data_governance.data_quality_rules(rule_type);
                CREATE INDEX IF NOT EXISTS idx_data_quality_rules_target ON data_governance.data_quality_rules(schema_name, table_name, column_name);
                CREATE INDEX IF NOT EXISTS idx_data_quality_rules_severity ON data_governance.data_quality_rules(severity);
                CREATE INDEX IF NOT EXISTS idx_data_quality_rules_active ON data_governance.data_quality_rules(is_active)
                    WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_rules_approval ON data_governance.data_quality_rules(approval_status);
                CREATE INDEX IF NOT EXISTS idx_data_quality_rules_executed ON data_governance.data_quality_rules(last_executed DESC);
                CREATE INDEX IF NOT EXISTS idx_data_quality_rules_parameters ON data_governance.data_quality_rules USING GIN(rule_parameters);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_quality_rules_updated_at
                BEFORE UPDATE ON data_governance.data_quality_rules
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_quality_rules IS 'Business rules for data quality validation and monitoring.
                Defines business rules used to validate and monitor data quality across the workforce scheduling system. Captures technical
                validation rules and business logic rules. Includes metadata about severity, execution frequency, and expected error rates.
                Supports multiple rule types including validation and anomaly detection rules. Rules linked to specific business processes
                and KPIs. Includes mechanisms for rule versioning and approval workflows. Tracks rule effectiveness metrics for continuous
                improvement. Centralizes data quality rules to ensure consistent application of data standards. Accommodates evolving business
                requirements through flexible rule expressions and parameters.';

                -- Serial No: 146 | TABLE: data_governance.data_quality_issues
                -- Description: Tracking of data quality issues and remediation
                -- Business Case: The data_quality_issues table captures all data quality issues identified through
                -- automated rule execution and manual reporting. It serves as the central tracking system for
                -- data quality incidents, providing end-to-end visibility into issue detection, analysis, and
                -- resolution. Each record includes detailed information about the affected data, the root cause
                -- of the issue, and the remediation steps taken. The table supports workflow management for
                -- data quality issues, including assignment to responsible parties and tracking of resolution
                -- timelines. It integrates with the broader issue management system to ensure proper prioritization
                -- and escalation of critical data issues. The design accommodates different issue types and
                -- severities, enabling appropriate handling based on business impact. Historical issue data
                -- is used to identify recurring data quality problems and drive preventive measures. The table
                -- also tracks the business impact of data quality issues to support cost-benefit analysis of
                -- data quality improvements. By maintaining this comprehensive issue tracking system, the
                -- organization can demonstrate continuous improvement in data quality and meet regulatory
                -- requirements for data governance. The data structure is optimized for rapid querying during
                -- incident response and trend analysis.
