                --      Business impact of data issues
                -- Feature Reference: 746, 747, 748, 749, 750
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_issues (
                    issue_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
