                    WHERE record_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_quality_issues_details ON data_governance.data_quality_issues USING GIN(record_details);
                CREATE INDEX IF NOT EXISTS idx_data_quality_issues_impact ON data_governance.data_quality_issues USING GIN(business_impact);
                CREATE INDEX IF NOT EXISTS idx_data_quality_issues_resolution ON data_governance.data_quality_issues
