                COMMENT ON TABLE data_governance.data_quality_issues IS 'Tracking of data quality issues and remediation.
                Captures all data quality issues identified through automated rule execution and manual reporting. Serves as central tracking
                system for data quality incidents. Includes detailed information about affected data and root cause. Supports workflow management
                for issue resolution. Integrates with broader issue management system for prioritization. Accommodates different issue types
                and severities. Historical issue data used to identify recurring problems. Tracks business impact for cost-benefit analysis.
                Demonstrates continuous improvement in data quality. Optimized for rapid querying during incident response and trend analysis.';

                -- Serial No: 147 | TABLE: data_governance.data_quality_metrics
                -- Description: Historical metrics for data quality assessment and trend analysis
                -- Business Case: The data_quality_metrics table stores historical data quality metrics for
                -- comprehensive assessment and trend analysis across the workforce scheduling system. It captures
                -- key quality indicators such as completeness rates, accuracy scores, and consistency metrics
                -- at regular intervals to support ongoing quality monitoring. This information is critical for
                -- identifying data quality issues before they impact business operations or decision making.
                -- The table supports multiple metric types including completeness, accuracy, consistency,
                -- timeliness, and validity, enabling holistic assessment of data health. Historical metric
                -- data is versioned to track changes over time and measure improvement against quality goals.
                -- Each metric record includes metadata about the calculation method, execution frequency, and
                -- target values to support data quality goal setting and monitoring. The implementation
                -- includes mechanisms for automated metric calculation through scheduled jobs, ensuring timely
                -- assessment of data quality. For metrics with defined targets, the table stores variance
                -- calculations to highlight areas requiring attention. Historical metric data is used to
                -- establish baselines and detect anomalies that may indicate underlying data issues. By
                -- centralizing data quality metrics, the system enables comprehensive data quality dashboards
                -- that provide visibility into data health across the organization. The table is optimized for
                -- time-series analysis of quality metrics, supporting trend identification and predictive
                -- data quality management.
                -- KPI: Data completeness rate, Data accuracy rate,
                --      Data consistency rate, Data quality trend direction,
                --      Data issue detection time
                -- Feature Reference: 751, 752, 753, 754, 755
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_metrics (
                    metric_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    schema_name VARCHAR(100) NOT NULL DEFAULT 'public',
                    table_name VARCHAR(200) NOT NULL,
                    column_name VARCHAR(200),
                    metric_type data_quality.metric_type_enum NOT NULL,
                    calculation_method VARCHAR(100) NOT NULL CHECK (calculation_method IN ('SQL_QUERY', 'PYTHON_SCRIPT',
                        'EXTERNAL_TOOL', 'MANUAL')),
                    calculation_frequency VARCHAR(20) NOT NULL CHECK (calculation_frequency IN ('REALTIME', 'HOURLY',
                        'DAILY', 'WEEKLY', 'MONTHLY', 'ON_DEMAND')),
                    metric_value NUMERIC(15,6) NOT NULL,
                    metric_value_raw TEXT,
                    target_value NUMERIC(15,6),
                    warning_threshold NUMERIC(15,6),
                    failure_threshold NUMERIC(15,6),
                    calculation_time TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    calculated_by UUID,
                    calculation_duration_ms INTEGER CHECK (calculation_duration_ms >= 0),
                    metric_granularity VARCHAR(20) NOT NULL DEFAULT 'DAILY'
                        CHECK (metric_granularity IN ('HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY', 'QUARTERLY', 'YEARLY')),
                    related_shift_id UUID,
                    related_employee_id UUID,
                    related_department_id UUID,
                    context JSONB CHECK (context IS NULL OR (jsonb_typeof(context) = 'object' AND
                        NOT context ? 'sensitive_data')),
                    data_source VARCHAR(50) NOT NULL DEFAULT 'SYSTEM_CALCULATED'
                        CHECK (data_source IN ('SYSTEM_CALCULATED', 'MANUAL_ENTRY', 'SURVEY', 'OBSERVATION', 'EXTERNAL_SYSTEM')),
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_quality_metrics_table ON data_governance.data_quality_metrics(schema_name, table_name, column_name);
                CREATE INDEX IF NOT EXISTS idx_data_quality_metrics_type ON data_governance.data_quality_metrics(metric_type);
                CREATE INDEX IF NOT EXISTS idx_data_quality_metrics_time ON data_governance.data_quality_metrics(calculation_time DESC);
                CREATE INDEX IF NOT EXISTS idx_data_quality_metrics_granularity ON data_governance.data_quality_metrics(metric_granularity);
                CREATE INDEX IF NOT EXISTS idx_data_quality_metrics_shift ON data_governance.data_quality_metrics(related_shift_id)
                    WHERE related_shift_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_quality_metrics_employee ON data_governance.data_quality_metrics(related_employee_id)
                    WHERE related_employee_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_quality_metrics_department ON data_governance.data_quality_metrics(related_department_id)
                    WHERE related_department_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_quality_metrics_context ON data_governance.data_quality_metrics USING GIN(context);

