                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_quality_metrics IS 'Historical metrics for data quality assessment and trend analysis.
                Stores historical data quality metrics for comprehensive assessment. Captures key quality indicators such as completeness rates
                and accuracy scores. Critical for identifying data quality issues before they impact business operations. Supports multiple
                metric types including completeness, accuracy, and consistency. Historical data versioned to track changes over time. Includes
                metadata about calculation method and target values. Includes mechanisms for automated metric calculation. Stores variance
                calculations for metrics with defined targets. Used to establish baselines and detect anomalies. Centralizes data quality metrics
                for comprehensive data quality dashboards. Optimized for time-series analysis of quality metrics.';

                -- Serial No: 148 | MATERIALIZED VIEW: data_governance.mv_data_quality_dashboard
                -- Purpose: Real-time data quality monitoring dashboard with key metrics
                -- Business Case: This materialized view provides a real-time snapshot of data quality health across
                -- the organization, serving as the foundation for data quality monitoring dashboards. It aggregates
                -- key quality metrics including completeness rates, accuracy scores, and consistency metrics to
                -- provide a comprehensive view of data health. The view includes comparison against targets and
                -- thresholds to highlight areas requiring attention. It supports multiple time granularities
                -- (daily, weekly, monthly) to accommodate different analysis needs. Historical trend data is
                -- presented with appropriate statistical analysis to distinguish meaningful patterns from random
                -- fluctuations. The materialized structure enables rapid query performance for monitoring that
                -- would be too slow on operational tables. The view also includes benchmark comparisons against
                -- industry standards or internal best practices to provide context for quality measurements. It
                -- serves as the foundation for data quality scorecards that track progress against organizational
                -- data quality goals. The implementation includes anomaly detection logic to automatically
                -- identify unusual patterns in quality metrics that may indicate underlying data issues. By
                -- pre-computing these metrics, the view enables sophisticated data quality analytics to be
                -- performed in real-time, supporting proactive data governance. The refresh process is optimized
                -- to minimize impact on operational systems while ensuring quality data remains sufficiently
                -- current for decision making. The view is designed with robust security controls to protect
                -- sensitive quality metrics while ensuring appropriate access for stakeholders.
                -- KPI: Data quality trend direction, Target achievement rate,
                --      Anomaly detection rate, Data quality improvement rate,
                --      Trend analysis performance
                -- Feature Reference: 756, 757, 758, 759, 760
                CREATE MATERIALIZED VIEW IF NOT EXISTS data_governance.mv_data_quality_dashboard AS
                SELECT
                    schema_name,
                    table_name,
                    column_name,
                    metric_type,
                    DATE_TRUNC('day', calculation_time) AS calculation_date,
                    AVG(metric_value) AS avg_metric_value,
                    MIN(metric_value) AS min_metric_value,
                    MAX(metric_value) AS max_metric_value,
                    PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY metric_value) AS median_metric_value,
                    COUNT(*) AS sample_count,
                    BOOL_AND(metric_value >= COALESCE(warning_threshold, 0)) AS meets_warning_threshold,
                    BOOL_AND(metric_value >= COALESCE(failure_threshold, 0)) AS meets_failure_threshold,
                    target_value,
                    warning_threshold,
                    failure_threshold,
                    (SELECT AVG(metric_value)
                     FROM data_governance.data_quality_metrics m2
                     WHERE m2.schema_name = m1.schema_name
                     AND m2.table_name = m1.table_name
                     AND m2.column_name = m1.column_name
                     AND m2.metric_type = m1.metric_type
                     AND calculation_time >= CURRENT_DATE - INTERVAL '7 days'
                     AND calculation_time < CURRENT_DATE) AS previous_week_avg,
                    CASE
                        WHEN (SELECT AVG(metric_value)
                              FROM data_governance.data_quality_metrics m2
                              WHERE m2.schema_name = m1.schema_name
                              AND m2.table_name = m1.table_name
                              AND m2.column_name = m1.column_name
                              AND m2.metric_type = m1.metric_type
                              AND calculation_time >= CURRENT_DATE - INTERVAL '7 days'
                              AND calculation_time < CURRENT_DATE) > 0
                            THEN (AVG(metric_value) - (SELECT AVG(metric_value)
                                                      FROM data_governance.data_quality_metrics m2
                                                      WHERE m2.schema_name = m1.schema_name
                                                      AND m2.table_name = m1.table_name
                                                      AND m2.column_name = m1.column_name
                                                      AND m2.metric_type = m1.metric_type
                                                      AND calculation_time >= CURRENT_DATE - INTERVAL '7 days'
                                                      AND calculation_time < CURRENT_DATE))
                                 / (SELECT AVG(metric_value)
                                    FROM data_governance.data_quality_metrics m2
                                    WHERE m2.schema_name = m1.schema_name
                                    AND m2.table_name = m1.table_name
                                    AND m2.column_name = m1.column_name
                                    AND m2.metric_type = m1.metric_type
                                    AND calculation_time >= CURRENT_DATE - INTERVAL '7 days'
                                    AND calculation_time < CURRENT_DATE) * 100
                        ELSE NULL
                    END AS week_over_week_change
                FROM data_governance.data_quality_metrics m1
                WHERE calculation_time >= CURRENT_DATE - INTERVAL '30 days'
                GROUP BY
                    schema_name, table_name, column_name, metric_type,
                    DATE_TRUNC('day', calculation_time),
                    target_value, warning_threshold, failure_threshold;

                -- Create indexes on the materialized view
                CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_data_quality_dashboard_full ON data_governance.mv_data_quality_dashboard
                    (schema_name, table_name, column_name, metric_type, calculation_date);
                CREATE INDEX IF NOT EXISTS idx_mv_data_quality_dashboard_table ON data_governance.mv_data_quality_dashboard
                    (schema_name, table_name, column_name);
                CREATE INDEX IF NOT EXISTS idx_mv_data_quality_dashboard_type ON data_governance.mv_data_quality_dashboard (metric_type);
                CREATE INDEX IF NOT EXISTS idx_mv_data_quality_dashboard_date ON data_governance.mv_data_quality_dashboard (calculation_date);
                CREATE INDEX IF NOT EXISTS idx_mv_data_quality_dashboard_trend ON data_governance.mv_data_quality_dashboard
                    (avg_metric_value, calculation_date);

                COMMENT ON MATERIALIZED VIEW data_governance.mv_data_quality_dashboard IS 'Real-time data quality monitoring dashboard with key metrics.
                Provides real-time snapshot of data quality health across the organization. Aggregates key quality metrics including completeness
                rates and accuracy scores. Includes comparison against targets and thresholds. Supports multiple time granularities for analysis.
                Historical trend data presented with statistical analysis. Enables rapid query performance for monitoring. Includes benchmark
                comparisons for context. Serves as foundation for data quality scorecards. Includes anomaly detection logic. Enables sophisticated
                data quality analytics in real-time. Refresh process optimized to minimize impact on operational systems. Designed with robust
                security controls for sensitive quality metrics.';

                -- Serial No: 149 | TABLE: system.maintenance_jobs
                -- Description: Configuration and tracking of system maintenance operations
                -- Business Case: The maintenance_jobs table manages the scheduling and execution of background maintenance
                -- tasks that are critical for system health and performance. It provides a centralized repository for job
                -- definitions, schedules, and execution history, enabling consistent management of operational processes
                -- across the system. The table supports multiple job types including data archiving, index maintenance,
                -- statistics gathering, and custom business processes. Each job definition includes parameters for
                -- controlling execution behavior, retry logic, and resource allocation. The design accommodates
                -- dependencies between jobs to ensure proper execution order for complex maintenance workflows.
                -- Comprehensive tracking of job execution history enables performance analysis and troubleshooting of
                -- maintenance operations. The table also supports dynamic adjustment of job schedules based on system
                -- load and business priorities, optimizing resource utilization during maintenance windows. This
                -- functionality is essential for maintaining system performance and reliability, particularly in
                -- environments with large data volumes where maintenance operations can significantly impact
                -- availability. The implementation includes safeguards against job overlap and resource contention to
                -- prevent maintenance activities from interfering with operational workloads. By centralizing job
                -- management, the system ensures consistent execution of critical maintenance tasks while providing
                -- the flexibility needed for different operational requirements.
                -- KPI: Job execution success rate, Maintenance window utilization,
                --      System performance impact, Job completion time,
                --      Error resolution time
                -- Feature Reference: 761, 762, 763, 764, 765
                CREATE TABLE IF NOT EXISTS system.maintenance_jobs (
                    job_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    job_name VARCHAR(100) NOT NULL UNIQUE,
                    job_type VARCHAR(50) NOT NULL CHECK (job_type IN ('DATA_ARCHIVE', 'INDEX_MAINTENANCE', 'STATISTICS_GATHERING',
                        'DATA_REFRESH', 'CUSTOM', 'VACUUM_ANALYZE', 'DATA_PURGE', 'BACKUP', 'VALIDATION')),
                    target_tables TEXT[],
                    description TEXT,
                    schedule_cron VARCHAR(50) NOT NULL,
                    estimated_duration_minutes INTEGER NOT NULL CHECK (estimated_duration_minutes >= 0),
                    max_duration_minutes INTEGER NOT NULL CHECK (max_duration_minutes >= estimated_duration_minutes),
                    last_run_start TIMESTAMP WITH TIME ZONE,
                    last_run_end TIMESTAMP WITH TIME ZONE,
                    last_run_duration_minutes INTEGER GENERATED ALWAYS AS (
                        CASE
                            WHEN last_run_start IS NOT NULL AND last_run_end IS NOT NULL
                                THEN EXTRACT(EPOCH FROM (last_run_end - last_run_start)) / 60
                            ELSE NULL
                        END
                    ) STORED,
                    last_run_status VARCHAR(20) CHECK (last_run_status IN ('SUCCESS', 'FAILED', 'RUNNING', 'SKIPPED')),
                    last_run_message TEXT,
                    max_runtime INTERVAL DEFAULT INTERVAL '2 hours',
                    retry_count INTEGER DEFAULT 0,
                    max_retries INTEGER DEFAULT 3,
                    retry_interval INTERVAL DEFAULT INTERVAL '5 minutes',
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    parameters JSONB,
                    dependencies UUID[] DEFAULT '{}',
                    resource_group VARCHAR(50),
                    priority INTEGER DEFAULT 50 CHECK (priority BETWEEN 1 AND 100),
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
                );

               

                COMMENT ON TABLE system.maintenance_jobs IS 'Configuration and tracking of system maintenance operations.
                Manages scheduling and execution of background maintenance tasks critical for system health. Provides centralized repository
                for job definitions, schedules, and execution history. Supports multiple job types including data archiving and index maintenance.
                Includes parameters for execution behavior, retry logic, and resource allocation. Accommodates dependencies between jobs.
                Enables performance analysis and troubleshooting. Supports dynamic adjustment of schedules based on system load. Essential for
                maintaining system performance with large data volumes. Includes safeguards against job overlap and resource contention.
                Centralizes job management for consistent execution of critical tasks.';

                -- Serial No: 150 | TABLE: system.task_results
                -- Description: Storage and management of task execution results
                -- Business Case: The task_results table captures detailed results of background task executions, providing
                -- visibility into task performance and outcomes. It stores both metadata about task execution (duration,
                -- status, resource usage) and the actual results data produced by the task. The table supports multiple
                -- task types including data processing jobs, report generation, and system maintenance operations. Each
                -- result record includes contextual information about the operational environment during execution to
                -- support troubleshooting of performance issues. Historical task data is maintained to identify trends
                -- in task performance and detect degradation over time. The implementation includes mechanisms for
                -- result retention management, automatically archiving or purging older results based on configurable
                -- policies. For critical tasks, the system tracks execution metrics against service level objectives to
                -- ensure tasks complete within acceptable timeframes. The table also supports result comparison across
                -- executions to identify unexpected changes in task outputs. By centralizing task results, the organization
                -- can ensure consistent monitoring of background operations while providing the data needed for capacity
                -- planning and performance tuning. The design accommodates both structured result data (via JSONB storage)
                -- and binary outputs (for reports and other artifacts). The table is optimized for rapid querying during
                -- incident response and performance analysis, with appropriate indexing on key task characteristics.
                -- KPI: Task execution success rate, Average task duration,
                --      Resource utilization per task, SLA compliance rate,
                --      Task failure resolution time
                -- Feature Reference: 766, 767, 768, 769, 770
                CREATE TABLE IF NOT EXISTS system.task_results (
                    result_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    task_id UUID NOT NULL,
                    task_name VARCHAR(100) NOT NULL,
                    execution_id UUID NOT NULL,
                    start_time TIMESTAMP WITH TIME ZONE NOT NULL,
                    end_time TIMESTAMP WITH TIME ZONE NOT NULL,
                    duration_ms INTEGER NOT NULL CHECK (duration_ms >= 0),
                    status VARCHAR(20) NOT NULL CHECK (status IN ('SUCCESS', 'FAILED', 'RUNNING', 'CANCELLED')),
                    error_message TEXT,
                    result_summary JSONB,
                    result_data BYTEA,
                    result_size_kb INTEGER CHECK (result_size_kb >= 0),
                    cpu_usage NUMERIC(5,2),
                    memory_usage_mb INTEGER,
                    rows_processed BIGINT,
                    rows_affected BIGINT,
                    error_category VARCHAR(50),
                    affected_records_count INTEGER,
                    server_hostname VARCHAR(100),
                    retention_days INTEGER NOT NULL DEFAULT 90 CHECK (retention_days >= 0),
                    expiration_date DATE GENERATED ALWAYS AS (DATE(start_time) + retention_days) STORED,
                    is_archived BOOLEAN NOT NULL DEFAULT FALSE,
                    security_level VARCHAR(20) NOT NULL DEFAULT 'INTERNAL'
                        CHECK (security_level IN ('PUBLIC', 'INTERNAL', 'CONFIDENTIAL', 'RESTRICTED')),
                    watermark_text TEXT,
                    version INTEGER NOT NULL DEFAULT 1,
                    metadata JSONB DEFAULT '{}'::JSONB,
                    created_by UUID NOT NULL,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
                    updated_by UUID,
                    updated_at TIMESTAMP WITH TIME ZONE
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_task_results_task ON system.task_results(task_id);
                CREATE INDEX IF NOT EXISTS idx_task_results_name ON system.task_results(task_name);


                -- Serial No: 151 | TABLE: data_governance.data_quality_alerts
                -- Description: Configuration and tracking of data quality alerts and notifications
                -- Business Case: The data_quality_alerts table manages the configuration and tracking of data quality
                -- alerts across the workforce scheduling system, enabling proactive identification and remediation of
                -- data issues. It captures essential information about alert conditions, notification rules, and
                -- escalation procedures to ensure timely response to data quality problems. The table supports
                -- multiple alert types including threshold-based alerts, anomaly detection alerts, and trend-based
                -- alerts, accommodating different data quality monitoring scenarios. Each alert configuration
                -- includes metadata about its severity, notification channels, and business impact to support
                -- appropriate response prioritization. The implementation includes robust tracking of alert history
                -- to identify patterns in data quality issues and measure the effectiveness of remediation efforts.
                -- Historical alert data is maintained to support root cause analysis and continuous improvement of
                -- data quality practices. For operational efficiency, the system tracks alert resolution times and
                -- outcomes to enable measurement of data quality team performance. The table integrates with the
                -- notification system to enable automated alert delivery through multiple channels including email,
                -- SMS, and in-app notifications. The design accommodates complex alert scenarios with multi-level
                -- escalation paths and conditional notification rules, providing detailed insights into data quality
                -- performance. By centralizing alert management, the organization can ensure consistent response to
                -- data quality issues while providing the flexibility needed for different business contexts. The
                -- table is optimized for rapid querying during incident response, which often involves identifying
                -- recurring alert patterns across multiple data domains.
                -- KPI: Alert resolution time, False positive rate,
                --      Alert accuracy rate, Data issue detection time,
                --      Business impact reduction rate
                -- Feature Reference: 771, 772, 773, 774, 775
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_alerts (
                    alert_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    alert_code VARCHAR(50) UNIQUE NOT NULL CHECK (alert_code ~ '^[A-Z0-9_]{3,50}$'),
                    name VARCHAR(200) NOT NULL,
                    description TEXT,
                    alert_type VARCHAR(50) NOT NULL CHECK (alert_type IN ('THRESHOLD', 'ANOMALY', 'TREND', 'COMPARISON', 'VALIDATION_RULE')),
                    rule_id UUID REFERENCES data_governance.data_quality_rules(rule_id),
                    metric_id UUID REFERENCES data_governance.data_quality_metrics(metric_id),
                    threshold_value NUMERIC(15,6),
                    threshold_type VARCHAR(20) NOT NULL CHECK (threshold_type IN ('ABSOLUTE', 'PERCENTAGE', 'STANDARD_DEVIATION')),
                    alert_condition VARCHAR(50) NOT NULL CHECK (alert_condition IN ('GREATER_THAN', 'LESS_THAN', 'EQUAL_TO', 'NOT_EQUAL_TO', 'OUTSIDE_RANGE')),
                    alert_frequency VARCHAR(20) NOT NULL DEFAULT 'HOURLY'
                        CHECK (alert_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
                    notification_channels VARCHAR(50)[] NOT NULL DEFAULT '{"EMAIL"}'
                        CHECK (array_length(notification_channels, 1) > 0),
                    notification_recipients UUID[],
                    escalation_rules JSONB,
                    severity VARCHAR(20) NOT NULL DEFAULT 'MEDIUM'
                        CHECK (severity IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
                    business_impact JSONB,
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    is_muted BOOLEAN NOT NULL DEFAULT FALSE,
                    mute_until TIMESTAMP WITH TIME ZONE,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_quality_alerts_rule ON data_governance.data_quality_alerts(rule_id)
                    WHERE rule_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_quality_alerts_metric ON data_governance.data_quality_alerts(metric_id)
                    WHERE metric_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_quality_alerts_type ON data_governance.data_quality_alerts(alert_type);
                CREATE INDEX IF NOT EXISTS idx_data_quality_alerts_severity ON data_governance.data_quality_alerts(severity);
                CREATE INDEX IF NOT EXISTS idx_data_quality_alerts_active ON data_governance.data_quality_alerts(is_active)
                    WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_alerts_muted ON data_governance.data_quality_alerts(is_muted)
                    WHERE is_muted = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_alerts_recipients ON data_governance.data_quality_alerts
                    USING GIN(notification_recipients);
                CREATE INDEX IF NOT EXISTS idx_data_quality_alerts_metadata ON data_governance.data_quality_alerts USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_quality_alerts_updated_at
                BEFORE UPDATE ON data_governance.data_quality_alerts
                FOR EACH ROW
