                --      Data quality improvement rate
                -- Feature Reference: 781, 782, 783, 784, 785
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_scorecards (
                    scorecard_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    scorecard_code VARCHAR(50) UNIQUE NOT NULL CHECK (scorecard_code ~ '^[A-Z0-9_]{5,50}$'),
                    name VARCHAR(200) NOT NULL,
                    description TEXT,
                    scorecard_type VARCHAR(50) NOT NULL CHECK (scorecard_type IN ('EXECUTIVE', 'OPERATIONAL', 'COMPLIANCE', 'DEPARTMENTAL', 'CUSTOM')),
                    scope JSONB NOT NULL DEFAULT '{"organization_wide": true}'::JSONB,
                    metrics JSONB NOT NULL,
                    metric_weights JSONB NOT NULL,
                    target_values JSONB NOT NULL,
                    calculation_method VARCHAR(50) NOT NULL DEFAULT 'WEIGHTED_AVERAGE'
                        CHECK (calculation_method IN ('WEIGHTED_AVERAGE', 'THRESHOLD_BASED', 'CUSTOM_FORMULA')),
                    refresh_frequency VARCHAR(20) NOT NULL DEFAULT 'DAILY'
                        CHECK (refresh_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
                    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    is_default BOOLEAN NOT NULL DEFAULT FALSE,
                    based_on_scorecard_id UUID REFERENCES data_governance.data_quality_scorecards(scorecard_id),
                    validated_by UUID REFERENCES hr.employees(employee_id),
                    validated_at TIMESTAMP WITH TIME ZONE,
                    validation_results JSONB,
                    usage_count INTEGER NOT NULL DEFAULT 0,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB,

                    -- Constraints
                    CONSTRAINT chk_metrics_structure CHECK (
                        jsonb_typeof(metrics) = 'object'
                        AND metrics != '{}'::JSONB
                    ),
                    CONSTRAINT chk_weights_structure CHECK (
                        jsonb_typeof(metric_weights) = 'object'
                        AND metric_weights != '{}'::JSONB
                    )
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecards_type ON data_governance.data_quality_scorecards(scorecard_type);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecards_active ON data_governance.data_quality_scorecards(is_active)
                    WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecards_default ON data_governance.data_quality_scorecards(is_default)
                    WHERE is_default = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecards_version ON data_governance.data_quality_scorecards(scorecard_id, version_number DESC);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecards_based_on ON data_governance.data_quality_scorecards(based_on_scorecard_id);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecards_metrics ON data_governance.data_quality_scorecards USING GIN(metrics);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecards_weights ON data_governance.data_quality_scorecards USING GIN(metric_weights);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecards_targets ON data_governance.data_quality_scorecards USING GIN(target_values);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecards_metadata ON data_governance.data_quality_scorecards USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_quality_scorecards_updated_at
                BEFORE UPDATE ON data_governance.data_quality_scorecards
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_quality_scorecards IS 'Configuration of data quality scorecards for organizational reporting.
                Stores configuration details for data quality scorecards used in organizational reporting. Captures composition including metrics
                and weightings. Supports multiple scorecard types including executive and operational reports. Includes metadata about scope and
                frequency. Includes versioning to track changes over time. Historical data maintained for retrospective analysis. Tracks approval
                status and audit trails for compliance. Integrates with data quality metrics system for automatic calculation. Accommodates
                different scorecard methodologies. Centralizes scorecard configuration for consistent evaluation. Optimized for rapid lookup
                during scorecard generation.';

                -- Serial No: 154 | TABLE: data_governance.data_quality_scorecard_results
                -- Description: Historical results of data quality scorecard calculations
                -- Business Case: The data_quality_scorecard_results table stores historical results of data quality
                -- scorecard calculations, providing a longitudinal view of data quality performance across the
                -- organization. It captures the calculated scores, metric values, and trend indicators for each
                -- scorecard evaluation period, enabling trend analysis and performance measurement. This information
                -- is critical for identifying data quality improvement opportunities and measuring the impact of
                -- data governance initiatives over time. The table supports multiple evaluation periods including
                -- daily, weekly, and monthly, accommodating different reporting requirements. Each result record
                -- includes metadata about the calculation methodology, data sources, and confidence level to ensure
                -- proper interpretation of results. Historical result data is versioned to track changes in scorecard
                -- configurations while maintaining historical consistency in measurement. For operational planning,
                -- the system stores results at multiple granularities (organization-wide, departmental, system-level)
                -- to support different management perspectives. The table integrates with the scorecard configuration
                -- system to enable automatic recalculation of historical results when scorecard configurations change.
                -- The design accommodates different scorecard methodologies while providing a consistent interface
                -- for trend analysis. By centralizing scorecard results, the organization can ensure consistent
                -- evaluation of data quality performance while providing the flexibility needed for different
                -- reporting requirements. The table is optimized for time-series analysis of scorecard results,
                -- supporting trend identification and predictive data quality management.
                -- KPI: Data quality trend direction, Scorecard target achievement rate,
                --      Data quality improvement rate, Scorecard variance identification rate,
                --      Data quality benchmark achievement rate
                -- Feature Reference: 786, 787, 788, 789, 790
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_scorecard_results (
                    result_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    scorecard_id UUID NOT NULL REFERENCES data_governance.data_quality_scorecards(scorecard_id),
                    evaluation_date DATE NOT NULL,
                    time_period VARCHAR(20) NOT NULL CHECK (time_period IN ('DAILY', 'WEEKLY', 'MONTHLY', 'QUARTERLY', 'YEARLY')),
                    scope_type VARCHAR(50) NOT NULL CHECK (scope_type IN ('ORGANIZATION', 'DEPARTMENT', 'SYSTEM', 'TABLE', 'COLUMN')),
                    scope_id UUID,
                    scope_name VARCHAR(200),
                    overall_score NUMERIC(5,2) CHECK (overall_score BETWEEN 0.00 AND 100.00),
                    metric_scores JSONB NOT NULL,
                    trend_indicator VARCHAR(20) NOT NULL CHECK (trend_indicator IN ('IMPROVING', 'STABLE', 'DEGRADING', 'NEW_BASELINE')),
                    trend_value NUMERIC(5,2),
                    data_quality_level VARCHAR(20) NOT NULL CHECK (data_quality_level IN ('EXCELLENT', 'GOOD', 'FAIR', 'POOR', 'CRITICAL')),
                    calculation_method VARCHAR(50) NOT NULL,
                    calculation_metadata JSONB,
                    data_source VARCHAR(100) NOT NULL,
                    data_confidence NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (data_confidence BETWEEN 0.00 AND 1.00),
                    notes TEXT,
                    created_by UUID NOT NULL,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_by UUID,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecard_results_scorecard ON data_governance.data_quality_scorecard_results(scorecard_id);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecard_results_date ON data_governance.data_quality_scorecard_results(evaluation_date, time_period);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecard_results_scope ON data_governance.data_quality_scorecard_results(scope_type, scope_id);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecard_results_score ON data_governance.data_quality_scorecard_results(overall_score);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecard_results_trend ON data_governance.data_quality_scorecard_results(trend_indicator);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecard_results_level ON data_governance.data_quality_scorecard_results(data_quality_level);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecard_results_metrics ON data_governance.data_quality_scorecard_results USING GIN(metric_scores);
                CREATE INDEX IF NOT EXISTS idx_data_quality_scorecard_results_metadata ON data_governance.data_quality_scorecard_results USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_quality_scorecard_results_updated_at
                BEFORE UPDATE ON data_governance.data_quality_scorecard_results
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_quality_scorecard_results IS 'Historical results of data quality scorecard calculations.
                Stores historical results of data quality scorecard calculations. Captures calculated scores and metric values for evaluation
                periods. Critical for identifying improvement opportunities and measuring impact of initiatives. Supports multiple evaluation
                periods including daily and weekly. Includes metadata about calculation methodology and confidence level. Historical data
                versioned to track changes in configurations. Stores results at multiple granularities for different management perspectives.
                Integrates with scorecard configuration system for automatic recalculation. Accommodates different scorecard methodologies.
                Centralizes scorecard results for consistent evaluation. Optimized for time-series analysis of results.';

                -- Serial No: 155 | TABLE: data_governance.data_stewardship
                -- Description: Assignment of data stewardship responsibilities across the organization
                -- Business Case: The data_stewardship table manages the assignment of data stewardship
                -- responsibilities across the workforce scheduling system, ensuring clear accountability for
                -- data quality and governance. It captures the relationship between data assets and their
                -- stewards, including the scope of responsibilities and stewardship duration. The table
                -- supports multiple stewardship types including data domain stewards, process stewards, and
                -- system stewards, accommodating different governance models. Each stewardship record includes
                -- metadata about the steward's responsibilities, escalation paths, and approval status to
                -- support proper governance of data assets. The implementation includes robust tracking of
                -- stewardship history to identify changes in responsibility over time and support audit
                -- requirements. Historical stewardship data is maintained to support retrospective analysis
                -- of data quality issues and their resolution. For operational efficiency, the system tracks
                -- response times to data quality issues to enable measurement of steward performance. The
                -- table integrates with the data catalog to provide context for data assets and their
                -- stewardship requirements. The design accommodates complex stewardship scenarios with
                -- hierarchical responsibilities and shared stewardship arrangements, providing detailed
                -- insights into data governance structure. By centralizing stewardship assignments, the
                -- organization can ensure consistent data governance practices while providing the flexibility
                -- needed for different business units and data domains. The table is optimized for rapid
                -- querying during data issue resolution, which often involves identifying the appropriate
                -- data steward for a specific data asset.
                -- KPI: Stewardship coverage completeness, Issue resolution time,
                --      Steward response rate, Data quality improvement rate,
                --      Stewardship compliance rate
                -- Feature Reference: 791, 792, 793, 794, 795
                CREATE TABLE IF NOT EXISTS data_governance.data_stewardship (
                    stewardship_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    asset_type VARCHAR(50) NOT NULL CHECK (asset_type IN ('TABLE', 'COLUMN', 'REPORT', 'METRIC', 'DASHBOARD', 'VIEW')),
                    asset_id UUID NOT NULL,
                    asset_path VARCHAR(500) NOT NULL,
                    steward_id UUID NOT NULL REFERENCES hr.employees(employee_id),
                    steward_role VARCHAR(50) NOT NULL CHECK (steward_role IN ('PRIMARY', 'SECONDARY', 'BACKUP')),
                    responsibility_scope JSONB NOT NULL,
                    effective_start_date DATE NOT NULL DEFAULT CURRENT_DATE,
                    effective_end_date DATE,
                    escalation_path UUID[],
                    approval_status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
                        CHECK (approval_status IN ('PENDING', 'APPROVED', 'REJECTED', 'REVOKED')),
                    approved_by UUID REFERENCES hr.employees(employee_id),
                    approved_at TIMESTAMP WITH TIME ZONE,
                    stewardship_type VARCHAR(50) NOT NULL CHECK (stewardship_type IN ('DOMAIN', 'PROCESS', 'SYSTEM', 'PROJECT')),
                    business_unit_id UUID REFERENCES hr.departments(department_id),
                    location_id UUID REFERENCES operations.locations(location_id),
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_asset ON data_governance.data_stewardship(asset_type, asset_id);
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_path ON data_governance.data_stewardship(asset_path);
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_steward ON data_governance.data_stewardship(steward_id);
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_role ON data_governance.data_stewardship(steward_role);
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_dates ON data_governance.data_stewardship(effective_start_date, effective_end_date);
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_status ON data_governance.data_stewardship(approval_status);
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_type ON data_governance.data_stewardship(stewardship_type);
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_business ON data_governance.data_stewardship(business_unit_id);
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_location ON data_governance.data_stewardship(location_id);
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_escalation ON data_governance.data_stewardship USING GIN(escalation_path);
                CREATE INDEX IF NOT EXISTS idx_data_stewardship_metadata ON data_governance.data_stewardship USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_stewardship_updated_at
                BEFORE UPDATE ON data_governance.data_stewardship
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_stewardship IS 'Assignment of data stewardship responsibilities across the organization.
                Manages assignment of data stewardship responsibilities. Captures relationship between data assets and their stewards. Supports
                multiple stewardship types including data domain and process stewards. Includes metadata about responsibilities and escalation
                paths. Tracks stewardship history for audit requirements. Historical data maintained for retrospective analysis. Tracks response
                times for steward performance measurement. Integrates with data catalog for context. Accommodates complex stewardship scenarios
                with hierarchical responsibilities. Centralizes stewardship assignments for consistent governance. Optimized for rapid querying
                during data issue resolution.';

                -- Serial No: 156 | TABLE: data_governance.data_governance_policies
                -- Description: Central repository for data governance policies and standards
                -- Business Case: The data_governance_policies table serves as the central repository for all
                -- data governance policies and standards across the workforce scheduling system, ensuring
                -- consistent application of data management practices. It captures the full text of policies,
                -- their scope, and implementation requirements to provide clear guidance for data handling.
                -- The table supports multiple policy types including data classification, data quality, data
                -- security, and data retention policies, accommodating different governance domains. Each
                -- policy record includes metadata about its effective dates, jurisdiction, and enforcement
                -- status to support proper governance of data practices. The implementation includes robust
                -- versioning of policies to track changes over time while maintaining historical compliance
                -- requirements. Historical policy data is maintained to support audit requirements and track
                -- changes to governance standards over time. For operational efficiency, the system tracks
                -- policy compliance metrics to enable measurement of governance effectiveness. The table
                -- integrates with the data catalog to provide context for policy application to specific
                -- data assets. The design accommodates complex policy scenarios with jurisdiction-specific
                -- requirements and tiered implementation levels, providing detailed insights into governance
                -- compliance. By centralizing policy management, the organization can ensure consistent
                -- application of data governance practices while providing the flexibility needed for different
                -- regulatory environments. The table is optimized for rapid querying during compliance audits,
                -- which often involves verifying policy application across multiple data types and jurisdictions.
                -- KPI: Policy coverage completeness, Policy compliance rate,
                --      Policy implementation time, Audit success rate,
                --      Policy update frequency
                -- Feature Reference: 796, 797, 798, 799, 800
                CREATE TABLE IF NOT EXISTS data_governance.data_governance_policies (
                    policy_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    policy_code VARCHAR(50) UNIQUE NOT NULL CHECK (policy_code ~ '^[A-Z0-9_]{3,50}$'),
                    name VARCHAR(200) NOT NULL,
                    description TEXT,
                    policy_type VARCHAR(50) NOT NULL CHECK (policy_type IN ('CLASSIFICATION', 'QUALITY', 'SECURITY', 'RETENTION', 'PRIVACY', 'USAGE')),
                    policy_category VARCHAR(50) NOT NULL CHECK (policy_category IN ('REGULATORY', 'COMPLIANCE', 'BUSINESS', 'TECHNICAL')),
                    policy_text TEXT NOT NULL,
                    policy_summary TEXT,
                    scope JSONB NOT NULL,
                    effective_date DATE NOT NULL DEFAULT CURRENT_DATE,
                    expiration_date DATE,
                    jurisdiction VARCHAR(100),
                    country_code VARCHAR(10),
                    enforcement_level VARCHAR(50) NOT NULL DEFAULT 'MANDATORY'
                        CHECK (enforcement_level IN ('MANDATORY', 'RECOMMENDED', 'INFORMATIONAL')),
                    compliance_standards VARCHAR(100)[],
                    approval_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
                        CHECK (approval_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'REJECTED', 'RETIRED')),
                    approved_by UUID REFERENCES hr.employees(employee_id),
                    approved_at TIMESTAMP WITH TIME ZONE,
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_governance_policies_type ON data_governance.data_governance_policies(policy_type);
                CREATE INDEX IF NOT EXISTS idx_data_governance_policies_category ON data_governance.data_governance_policies(policy_category);
                CREATE INDEX IF NOT EXISTS idx_data_governance_policies_effective ON data_governance.data_governance_policies(effective_date, expiration_date);
                CREATE INDEX IF NOT EXISTS idx_data_governance_policies_jurisdiction ON data_governance.data_governance_policies(jurisdiction);
                CREATE INDEX IF NOT EXISTS idx_data_governance_policies_country ON data_governance.data_governance_policies(country_code);
                CREATE INDEX IF NOT EXISTS idx_data_governance_policies_status ON data_governance.data_governance_policies(approval_status);
                CREATE INDEX IF NOT EXISTS idx_data_governance_policies_active ON data_governance.data_governance_policies(is_active)
                    WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_governance_policies_standards ON data_governance.data_governance_policies
                    USING GIN(compliance_standards);
                CREATE INDEX IF NOT EXISTS idx_data_governance_policies_metadata ON data_governance.data_governance_policies USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_governance_policies_updated_at
                BEFORE UPDATE ON data_governance.data_governance_policies
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_governance_policies IS 'Central repository for data governance policies and standards.
                Serves as central repository for all data governance policies and standards. Captures full text of policies and implementation
                requirements. Supports multiple policy types including classification and quality policies. Includes metadata about effective
                dates and jurisdiction. Includes versioning to track changes over time. Historical data maintained for audit requirements.
                Tracks compliance metrics for governance effectiveness. Integrates with data catalog for policy application context.
                Accommodates complex policy scenarios with jurisdiction-specific requirements. Centralizes policy management for consistent
                application. Optimized for rapid querying during compliance audits.';

                -- Serial No: 157 | TABLE: data_governance.policy_compliance
                -- Description: Tracking of policy compliance assessments and remediation
                -- Business Case: The policy_compliance table maintains a comprehensive record of all policy
                -- compliance assessments, providing visibility into governance adherence across the organization.
                -- It captures detailed information about each assessment including scope, methodology, results,
                -- and remediation efforts to support continuous improvement of data governance practices. This
                -- information is critical for demonstrating regulatory compliance, identifying governance gaps,
                -- and prioritizing remediation efforts. The table supports multiple assessment types including
                -- internal audits, regulatory examinations, and self-assessments, accommodating different
                -- compliance verification methods. Each compliance record includes metadata about the assessment
                -- context, responsible parties, and verification evidence to enable accurate assessment during
                -- audits. Historical compliance data is maintained to identify trends in governance adherence
                -- and measure the impact of remediation efforts over time. For regulatory compliance, the system
                -- tracks approval workflows for exceptions to standard governance requirements, documenting the
                -- rationale and authorization for any deviations. By centralizing compliance tracking, the
                -- organization can ensure consistent enforcement of governance policies while providing the
                -- detailed evidence needed for regulatory examinations. The design accommodates different
                -- compliance frameworks for various jurisdictions and business units, enabling global
                -- organizations to maintain defensible governance practices across their entire operation. The
                -- table is optimized for rapid querying during compliance audits and for generating required
                -- regulatory reports.
                -- KPI: Compliance rate, Time to resolve critical violations,
                --      Repeat violation rate, Compliance improvement rate,
                --      Audit finding closure rate
                -- Feature Reference: 801, 802, 803, 804, 805
                CREATE TABLE IF NOT EXISTS data_governance.policy_compliance (
                    compliance_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    policy_id UUID NOT NULL REFERENCES data_governance.data_governance_policies(policy_id),
                    assessment_type VARCHAR(50) NOT NULL CHECK (assessment_type IN ('INTERNAL_AUDIT', 'REGULATORY_EXAMINATION',
                        'SELF_ASSESSMENT', 'THIRD_PARTY_AUDIT', 'AUTOMATED_SCAN')),
                    assessment_date DATE NOT NULL,
                    assessment_scope JSONB NOT NULL,
                    assessment_method VARCHAR(50) NOT NULL CHECK (assessment_method IN ('DOCUMENT_REVIEW', 'INTERVIEW', 'TESTING',
                        'AUTOMATED_SCAN', 'OBSERVATION')),
                    assessor_id UUID NOT NULL REFERENCES hr.employees(employee_id),
                    findings JSONB NOT NULL,
                    compliance_score NUMERIC(5,2) CHECK (compliance_score BETWEEN 0.00 AND 100.00),
                    non_compliance_count INTEGER NOT NULL DEFAULT 0,
                    critical_findings_count INTEGER NOT NULL DEFAULT 0,
                    status VARCHAR(20) NOT NULL DEFAULT 'OPEN'
                        CHECK (status IN ('OPEN', 'IN_PROGRESS', 'RESOLVED', 'EXCEPTION_APPROVED', 'IGNORED')),
                    remediation_plan JSONB,
                    remediation_deadline DATE,
                    remediation_completed_date DATE,
                    verification_evidence JSONB,
                    exception_approved_by UUID REFERENCES hr.employees(employee_id),
                    exception_approval_date TIMESTAMP WITH TIME ZONE,
                    exception_reason TEXT,
                    next_assessment_date DATE,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_policy_compliance_policy ON data_governance.policy_compliance(policy_id);
                CREATE INDEX IF NOT EXISTS idx_policy_compliance_type ON data_governance.policy_compliance(assessment_type);
                CREATE INDEX IF NOT EXISTS idx_policy_compliance_date ON data_governance.policy_compliance(assessment_date DESC);
                CREATE INDEX IF NOT EXISTS idx_policy_compliance_assessor ON data_governance.policy_compliance(assessor_id);
                CREATE INDEX IF NOT EXISTS idx_policy_compliance_score ON data_governance.policy_compliance(compliance_score);
                CREATE INDEX IF NOT EXISTS idx_policy_compliance_status ON data_governance.policy_compliance(status);
                CREATE INDEX IF NOT EXISTS idx_policy_compliance_findings ON data_governance.policy_compliance(non_compliance_count);
                CREATE INDEX IF NOT EXISTS idx_policy_compliance_critical ON data_governance.policy_compliance(critical_findings_count);
                CREATE INDEX IF NOT EXISTS idx_policy_compliance_exception ON data_governance.policy_compliance(exception_approved_by)
                    WHERE exception_approved_by IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_policy_compliance_metadata ON data_governance.policy_compliance USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_policy_compliance_updated_at
                BEFORE UPDATE ON data_governance.policy_compliance
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.policy_compliance IS 'Tracking of policy compliance assessments and remediation.
                Maintains comprehensive record of all policy compliance assessments. Captures detailed information about each assessment.
                Critical for demonstrating regulatory compliance and identifying governance gaps. Supports multiple assessment types including
                internal audits and regulatory examinations. Includes metadata about assessment context and verification evidence. Historical
                data maintained to identify trends in governance adherence. Tracks approval workflows for exceptions to standard requirements.
                Centralizes compliance tracking for consistent enforcement. Accommodates different compliance frameworks for various jurisdictions.
                Optimized for rapid querying during compliance audits and regulatory reporting.';

                -- Serial No: 158 | TABLE: system.system_health_metrics
                -- Description: Historical system performance and health metrics
                -- Business Case: The system_health_metrics table stores historical performance metrics for monitoring
                -- the health and performance of the workforce scheduling system. It captures key indicators such as
                -- response times, error rates, resource utilization, and throughput to support proactive system
                -- management. This information is critical for identifying performance bottlenecks before they impact
                -- users, planning capacity requirements, and ensuring service level agreement compliance. The table
                -- supports multiple metric types including database performance, application server metrics, and
                -- integration health indicators, enabling comprehensive system monitoring. Historical metric data is
                -- versioned to track changes over time and measure improvement against performance goals. Each metric
                -- record includes metadata about the collection method, environment, and confidence level to ensure
                -- proper interpretation of results. The implementation includes mechanisms for automated metric
                -- collection through scheduled jobs, ensuring timely assessment of system health. For metrics with
                -- defined targets, the table stores variance calculations to highlight areas requiring attention.
                -- Historical metric data is used to establish baselines and detect anomalies that may indicate
                -- underlying system issues. By centralizing system health metrics, the organization can ensure
                -- comprehensive monitoring that provides visibility into system performance across all components.
                -- The table is optimized for time-series analysis of performance metrics, supporting trend
                -- identification and predictive system management.
                -- KPI: System uptime, Average response time,
                --      Error rate, Resource utilization,
                --      Performance trend direction
                -- Feature Reference: 806, 807, 808, 809, 810
                CREATE TABLE IF NOT EXISTS system.system_health_metrics (
                    metric_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    metric_type VARCHAR(50) NOT NULL CHECK (metric_type IN ('RESPONSE_TIME', 'ERROR_RATE', 'CPU_USAGE',
                        'MEMORY_USAGE', 'DISK_IO', 'NETWORK_LATENCY', 'DATABASE_CONNECTIONS', 'QUEUE_LENGTH')),
                    component_name VARCHAR(100) NOT NULL,
                    environment VARCHAR(50) NOT NULL CHECK (environment IN ('PRODUCTION', 'STAGING', 'TEST', 'DEVELOPMENT')),
                    instance_id VARCHAR(100),
                    metric_value NUMERIC(15,6) NOT NULL,
                    unit_of_measure VARCHAR(50) NOT NULL,
                    collection_time TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    collection_interval VARCHAR(20) NOT NULL DEFAULT 'MINUTE'
                        CHECK (collection_interval IN ('SECOND', 'MINUTE', 'HOUR', 'DAY')),
                    target_value NUMERIC(15,6),
                    warning_threshold NUMERIC(15,6),
                    failure_threshold NUMERIC(15,6),
                    calculation_method VARCHAR(100) NOT NULL DEFAULT 'DIRECT_MEASUREMENT'
                        CHECK (calculation_method IN ('DIRECT_MEASUREMENT', 'AVERAGE', 'PEAK', 'PERCENTILE', 'COUNT')),
                    related_transaction_id UUID,
                    related_error_code VARCHAR(50),
                    context JSONB,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_system_health_metrics_type ON system.system_health_metrics(metric_type);
                CREATE INDEX IF NOT EXISTS idx_system_health_metrics_component ON system.system_health_metrics(component_name);
                CREATE INDEX IF NOT EXISTS idx_system_health_metrics_environment ON system.system_health_metrics(environment);
                CREATE INDEX IF NOT EXISTS idx_system_health_metrics_time ON system.system_health_metrics(collection_time DESC);
                CREATE INDEX IF NOT EXISTS idx_system_health_metrics_interval ON system.system_health_metrics(collection_interval);
                CREATE INDEX IF NOT EXISTS idx_system_health_metrics_transaction ON system.system_health_metrics(related_transaction_id)
                    WHERE related_transaction_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_system_health_metrics_error ON system.system_health_metrics(related_error_code)
                    WHERE related_error_code IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_system_health_metrics_context ON system.system_health_metrics USING GIN(context);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_system_health_metrics_updated_at
                BEFORE UPDATE ON system.system_health_metrics
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE system.system_health_metrics IS 'Historical system performance and health metrics.
                Stores historical performance metrics for monitoring system health. Captures key indicators such as response times and error
                rates. Critical for identifying performance bottlenecks before they impact users. Supports multiple metric types including
                database and application server metrics. Historical data versioned to track changes over time. Includes metadata about collection
                method and environment. Includes mechanisms for automated metric collection. Stores variance calculations for metrics with
                defined targets. Used to establish baselines and detect anomalies. Centralizes system health metrics for comprehensive monitoring.
                Optimized for time-series analysis of performance metrics.';

                -- Serial No: 159 | MATERIALIZED VIEW: system.mv_system_health_dashboard
                -- Purpose: Real-time system health monitoring dashboard with key metrics
                -- Business Case: This materialized view provides a real-time snapshot of system health across the
                -- organization, serving as the foundation for system monitoring dashboards. It aggregates key
                -- performance metrics including response times, error rates, and resource utilization to provide
                -- a comprehensive view of system health. The view includes comparison against targets and
                -- thresholds to highlight areas requiring attention. It supports multiple time granularities
                -- (minute, hour, day) to accommodate different analysis needs. Historical trend data is presented
                -- with appropriate statistical analysis to distinguish meaningful patterns from random fluctuations.
                -- The materialized structure enables rapid query performance for monitoring that would be too slow
                -- on operational tables. The view also includes benchmark comparisons against historical performance
                -- to provide context for current metrics. It serves as the foundation for system health scorecards
                -- that track progress against service level objectives. The implementation includes anomaly
                -- detection logic to automatically identify unusual patterns in performance metrics that may
                -- indicate underlying system issues. By pre-computing these metrics, the view enables sophisticated
                -- system health analytics to be performed in real-time, supporting proactive system management. The
                -- refresh process is optimized to minimize impact on operational systems while ensuring health data
                -- remains sufficiently current for decision making. The view is designed with robust security
                -- controls to protect sensitive system metrics while ensuring appropriate access for stakeholders.
                -- KPI: System health trend direction, SLA compliance rate,
                --      Anomaly detection rate, System performance improvement rate,
                --      Trend analysis performance
                -- Feature Reference: 811, 812, 813, 814, 815
                CREATE MATERIALIZED VIEW IF NOT EXISTS system.mv_system_health_dashboard AS
                SELECT
                    component_name,
                    environment,
                    instance_id,
                    metric_type,
                    DATE_TRUNC('hour', collection_time) AS hour_bucket,
                    AVG(metric_value) AS avg_metric_value,
                    MIN(metric_value) AS min_metric_value,
                    MAX(metric_value) AS max_metric_value,
                    PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY metric_value) AS median_metric_value,
                    COUNT(*) AS sample_count,
                    BOOL_AND(metric_value <= COALESCE(warning_threshold, metric_value)) AS meets_warning_threshold,
                    BOOL_AND(metric_value <= COALESCE(failure_threshold, metric_value)) AS meets_failure_threshold,
                    target_value,
                    warning_threshold,
                    failure_threshold,
                    (SELECT AVG(metric_value)
                     FROM system.system_health_metrics m2
                     WHERE m2.component_name = m1.component_name
                     AND m2.environment = m1.environment
                     AND m2.metric_type = m1.metric_type
                     AND collection_time >= CURRENT_TIMESTAMP - INTERVAL '24 hours'
                     AND collection_time < CURRENT_TIMESTAMP - INTERVAL '1 hour') AS previous_hour_avg,
                    CASE
                        WHEN (SELECT AVG(metric_value)
                              FROM system.system_health_metrics m2
                              WHERE m2.component_name = m1.component_name
                              AND m2.environment = m1.environment
                              AND m2.metric_type = m1.metric_type
                              AND collection_time >= CURRENT_TIMESTAMP - INTERVAL '24 hours'
                              AND collection_time < CURRENT_TIMESTAMP - INTERVAL '1 hour') > 0
                            THEN (AVG(metric_value) - (SELECT AVG(metric_value)
                                                      FROM system.system_health_metrics m2
                                                      WHERE m2.component_name = m1.component_name
                                                      AND m2.environment = m1.environment
                                                      AND m2.metric_type = m1.metric_type
                                                      AND collection_time >= CURRENT_TIMESTAMP - INTERVAL '24 hours'
                                                      AND collection_time < CURRENT_TIMESTAMP - INTERVAL '1 hour'))
                                 / (SELECT AVG(metric_value)
                                    FROM system.system_health_metrics m2
                                    WHERE m2.component_name = m1.component_name
                                    AND m2.environment = m1.environment
                                    AND m2.metric_type = m1.metric_type
                                    AND collection_time >= CURRENT_TIMESTAMP - INTERVAL '24 hours'
                                    AND collection_time < CURRENT_TIMESTAMP - INTERVAL '1 hour') * 100
                        ELSE NULL
                    END AS hour_over_hour_change
                FROM system.system_health_metrics m1
                WHERE collection_time >= CURRENT_TIMESTAMP - INTERVAL '7 days'
                GROUP BY
                    component_name, environment, instance_id, metric_type,
                    DATE_TRUNC('hour', collection_time),
                    target_value, warning_threshold, failure_threshold;

                -- Create indexes on the materialized view
                CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_full ON system.mv_system_health_dashboard
                    (component_name, environment, instance_id, metric_type, hour_bucket);
                CREATE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_component ON system.mv_system_health_dashboard (component_name);
                CREATE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_environment ON system.mv_system_health_dashboard (environment);
                CREATE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_type ON system.mv_system_health_dashboard (metric_type);
                CREATE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_hour ON system.mv_system_health_dashboard (hour_bucket);
                CREATE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_trend ON system.mv_system_health_dashboard
                    (avg_metric_value, hour_bucket);

                COMMENT ON MATERIALIZED VIEW system.mv_system_health_dashboard IS 'Real-time system health monitoring dashboard with key metrics.
                Provides real-time snapshot of system health across the organization. Aggregates key performance metrics including response times
                and error rates. Includes comparison against targets and thresholds. Supports multiple time granularities for analysis. Historical
                trend data presented with statistical analysis. Enables rapid query performance for monitoring. Includes benchmark comparisons
                for context. Serves as foundation for system health scorecards. Includes anomaly detection logic. Enables sophisticated system
                health analytics in real-time. Refresh process optimized to minimize impact on operational systems. Designed with robust security
                controls for sensitive system metrics.';

                -- Serial No: 160 | TABLE: system.error_logs
                -- Description: Comprehensive logging of system errors and exceptions
                -- Business Case: The error_logs table captures detailed information about system errors and
                -- exceptions, providing critical visibility into application stability and reliability. It records
                -- each error occurrence with comprehensive context including stack traces, error codes, and
                -- environmental information to support effective troubleshooting and root cause analysis. The
                -- table supports multiple error severity levels, enabling appropriate prioritization of issues
                -- based on business impact. Each error record includes metadata about the user, session, and
                -- business process context to enable accurate assessment of impact and frequency. Historical
                -- error data is maintained to identify recurring issues and measure the effectiveness of
                -- remediation efforts over time. For operational efficiency, the system tracks error frequency
                -- and patterns to enable proactive identification of systemic issues before they impact users.
                -- The table integrates with monitoring systems to enable automated alerting for critical errors
                -- and facilitate rapid response. The design accommodates complex error scenarios with nested
                -- exceptions and correlated errors across multiple components, providing detailed insights into
                -- system behavior. By centralizing error logging, the organization can ensure consistent
                -- troubleshooting practices while providing the data needed for continuous improvement of
                -- application stability. The table is optimized for rapid querying during incident response,
                -- which often involves identifying error patterns across multiple time periods and system
                -- components.
                -- KPI: Error resolution time, Recurrence rate of errors,
                --      Error severity distribution, Mean time to recovery,
                --      Business impact of errors
                -- Feature Reference: 816, 817, 818, 819, 820
                CREATE TABLE IF NOT EXISTS system.error_logs (
                    log_id BIGSERIAL PRIMARY KEY,
                    log_uuid UUID NOT NULL DEFAULT uuid_generate_v4() UNIQUE,
                    -- Error Identification
                    error_code VARCHAR(50) NOT NULL,
                    error_type VARCHAR(100) NOT NULL CHECK (error_type IN ('APPLICATION', 'DATABASE', 'NETWORK',
                        'AUTHENTICATION', 'AUTHORIZATION', 'VALIDATION', 'INTEGRATION', 'SYSTEM', 'UNKNOWN')),
                    error_category VARCHAR(100) NOT NULL CHECK (error_category IN ('CRITICAL', 'HIGH', 'MEDIUM', 'LOW', 'INFORMATIONAL')),
                    -- Error Details
                    error_message TEXT NOT NULL,
                    error_details JSONB,
                    stack_trace TEXT,
                    inner_error TEXT, -- For nested exceptions
                    -- Context Information
                    user_id UUID,
                    session_id UUID,
                    request_id UUID,
                    client_ip INET,
                    client_user_agent TEXT,
                    business_process VARCHAR(100),
                    business_entity_type VARCHAR(100),
                    business_entity_id UUID,
                    -- Timing and Frequency
                    occurred_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    occurrence_count INTEGER NOT NULL DEFAULT 1,
                    first_occurred_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    last_occurred_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    -- Resolution Information
                    resolved_at TIMESTAMP WITH TIME ZONE,
                    resolved_by UUID REFERENCES hr.employees(employee_id),
                    resolution_notes TEXT,
                    resolution_steps JSONB,
                    is_resolved BOOLEAN NOT NULL DEFAULT FALSE,
                    -- Metadata
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_error_logs_code ON system.error_logs(error_code);
                CREATE INDEX IF NOT EXISTS idx_error_logs_type ON system.error_logs(error_type);
                CREATE INDEX IF NOT EXISTS idx_error_logs_category ON system.error_logs(error_category);
                CREATE INDEX IF NOT EXISTS idx_error_logs_time ON system.error_logs(occurred_at DESC);
                CREATE INDEX IF NOT EXISTS idx_error_logs_user ON system.error_logs(user_id) WHERE user_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_error_logs_session ON system.error_logs(session_id) WHERE session_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_error_logs_entity ON system.error_logs(business_entity_type, business_entity_id)
                    WHERE business_entity_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_error_logs_resolved ON system.error_logs(is_resolved) WHERE is_resolved = TRUE;
                CREATE INDEX IF NOT EXISTS idx_error_logs_unresolved ON system.error_logs(is_resolved) WHERE is_resolved = FALSE;
                CREATE INDEX IF NOT EXISTS idx_error_logs_details ON system.error_logs USING GIN(error_details);
                CREATE INDEX IF NOT EXISTS idx_error_logs_metadata ON system.error_logs USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_error_logs_updated_at
                BEFORE UPDATE ON system.error_logs
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE system.error_logs IS 'Comprehensive logging of system errors and exceptions.
                Captures detailed information about system errors and exceptions. Records each error occurrence with comprehensive context.
                Supports multiple error severity levels for appropriate prioritization. Includes metadata about user and business process context.
                Historical error data maintained to identify recurring issues. Tracks error frequency for proactive identification. Integrates
                with monitoring systems for automated alerting. Accommodates complex error scenarios with nested exceptions. Centralizes error
                logging for consistent troubleshooting. Optimized for rapid querying during incident response.';

