                    name VARCHAR(200) NOT NULL,
                    description TEXT,
                    policy_type VARCHAR(50) NOT NULL CHECK (policy_type IN ('ROLE_BASED', 'ATTRIBUTE_BASED', 'CONTEXT_AWARE',
                        'HIERARCHICAL', 'TIME_BASED', 'LOCATION_BASED')),
                    policy_category VARCHAR(50) NOT NULL CHECK (policy_category IN ('DATA_ACCESS', 'FUNCTIONAL_ACCESS',
                        'PRIVILEGED_ACCESS', 'COMPLIANCE')),
                    policy_expression TEXT NOT NULL,
                    policy_parameters JSONB,
                    target_resources JSONB NOT NULL,
                    required_conditions JSONB,
                    permitted_actions VARCHAR(50)[],
                    priority INTEGER NOT NULL DEFAULT 100 CHECK (priority BETWEEN 1 AND 1000),
                    effective_start_date DATE NOT NULL DEFAULT CURRENT_DATE,
                    effective_end_date DATE,
                    enforcement_level VARCHAR(50) NOT NULL DEFAULT 'MANDATORY'
                        CHECK (enforcement_level IN ('MANDATORY', 'RECOMMENDED', 'INFORMATIONAL')),
                    approval_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
                        CHECK (approval_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'REJECTED', 'RETIRED')),
                    approved_by UUID REFERENCES hr.employees(employee_id),
                    approved_at TIMESTAMP WITH TIME ZONE,
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB,

                    -- Constraints
                    CONSTRAINT chk_policy_expression CHECK (LENGTH(TRIM(policy_expression)) > 0),
                    CONSTRAINT chk_permitted_actions CHECK (array_length(permitted_actions, 1) > 0)
                );

