                CREATE INDEX IF NOT EXISTS idx_vulnerability_management_deadline ON security.vulnerability_management(remediation_deadline);
                CREATE INDEX IF NOT EXISTS idx_vulnerability_management_completed ON security.vulnerability_management(remediation_completed_at)
                    WHERE remediation_completed_at IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_vulnerability_management_impact ON security.vulnerability_management
                    USING GIN(business_impact);
                CREATE INDEX IF NOT EXISTS idx_vulnerability_management_components ON security.vulnerability_management
                    USING GIN(affected_components);
                CREATE INDEX IF NOT EXISTS idx_vulnerability_management_metadata ON security.vulnerability_management USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_vulnerability_management_updated_at
                BEFORE UPDATE ON security.vulnerability_management
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE security.vulnerability_management IS 'Tracking of system vulnerabilities and remediation efforts.
                Provides comprehensive tracking of security vulnerabilities. Captures detailed information about each vulnerability. Supports
                multiple vulnerability sources including automated scans and manual assessments. Includes metadata about CVSS score and business
                impact. Tracks remediation progress with milestones and deadlines. Historical data maintained to identify vulnerability patterns.
                Tracks required documentation for regulatory reporting. Integrates with patch management systems for end-to-end tracking.
                Accommodates complex vulnerability scenarios with multiple affected components. Centralizes vulnerability tracking for consistent
                risk management. Optimized for rapid querying during risk assessment.';

                -- Serial No: 176 | TABLE: security.compliance_standards
                -- Description: Repository of compliance standards and regulatory requirements
                -- Business Case: The compliance_standards table serves as the central repository for all
                -- compliance standards and regulatory requirements applicable to the workforce scheduling
                -- system, ensuring consistent understanding and implementation of compliance obligations. It
                -- captures detailed requirements from various regulatory frameworks including GDPR, HIPAA,
                -- PCI-DSS, and industry-specific standards, providing a comprehensive view of compliance
                -- landscape. The table supports hierarchical organization of requirements from high-level
                -- principles to specific controls, ensuring proper application of the most specific applicable
                -- requirement. Each standard record includes metadata about its jurisdiction, effective dates,
                -- and enforcement priority to support appropriate implementation in security controls. The
                -- design accommodates complex regulatory structures through a combination of standard rule
                -- types and custom expression capabilities, enabling precise representation of nuanced
                -- regulatory requirements. Historical versions of standards are maintained to support
                -- compliance verification for past system configurations. The table also tracks regulatory
                -- updates and implementation deadlines to ensure timely adaptation of security practices. For
                -- multinational organizations, the system supports translation of regulations into multiple
                -- languages while maintaining the legal accuracy of requirements. By centralizing compliance
                -- standards, the organization can ensure consistent compliance across all locations while
                -- reducing the risk of legal violations due to outdated or misinterpreted regulations. The
                -- table is optimized for rapid querying during compliance assessments, which is critical for
                -- timely identification of compliance gaps and implementation of necessary controls.
                -- KPI: Regulatory compliance rate, Standard update implementation time,
                --      Compliance gap resolution time, Regulatory coverage completeness,
                --      Audit success rate
                -- Feature Reference: 896, 897, 898, 899, 900
                CREATE TABLE IF NOT EXISTS security.compliance_standards (
                    standard_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    standard_code VARCHAR(50) UNIQUE NOT NULL CHECK (standard_code ~ '^[A-Z0-9_]{3,50}$'),
                    title VARCHAR(200) NOT NULL,
                    description TEXT NOT NULL,
                    standard_type VARCHAR(50) NOT NULL CHECK (standard_type IN ('REGULATORY', 'INDUSTRY_STANDARD', 'INTERNAL_POLICY')),
                    jurisdiction VARCHAR(100) NOT NULL,
                    country_code VARCHAR(10) NOT NULL,
                    region VARCHAR(50),
                    city VARCHAR(50),
                    effective_date DATE NOT NULL,
                    expiration_date DATE,
                    regulatory_body VARCHAR(100) NOT NULL,
                    legal_reference VARCHAR(200),
                    applies_to_employees VARCHAR(50)[] NOT NULL DEFAULT '{ALL}'
                        CHECK (array_length(applies_to_employees, 1) > 0),
                    applies_to_positions UUID[],
                    applies_to_locations UUID[],
                    applies_to_departments UUID[],
                    standard_expression TEXT NOT NULL,
                    standard_parameters JSONB,
                    enforcement_level VARCHAR(50) NOT NULL DEFAULT 'MANDATORY'
                        CHECK (enforcement_level IN ('MANDATORY', 'PREFERRED', 'INFORMATIONAL')),
                    severity VARCHAR(20) NOT NULL DEFAULT 'HIGH'
                        CHECK (severity IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                    based_on_standard_id UUID REFERENCES security.compliance_standards(standard_id),
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_compliance_standards_type ON security.compliance_standards(standard_type);
                CREATE INDEX IF NOT EXISTS idx_compliance_standards_jurisdiction ON security.compliance_standards(jurisdiction);
                CREATE INDEX IF NOT EXISTS idx_compliance_standards_effective ON security.compliance_standards(effective_date, expiration_date);
                CREATE INDEX IF NOT EXISTS idx_compliance_standards_active ON security.compliance_standards(is_active) WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_compliance_standards_severity ON security.compliance_standards(severity);
                CREATE INDEX IF NOT EXISTS idx_compliance_standards_version ON security.compliance_standards(standard_id, version_number DESC);
                CREATE INDEX IF NOT EXISTS idx_compliance_standards_based_on ON security.compliance_standards(based_on_standard_id);
                CREATE INDEX IF NOT EXISTS idx_compliance_standards_parameters ON security.compliance_standards USING GIN(standard_parameters);
                CREATE INDEX IF NOT EXISTS idx_compliance_standards_metadata ON security.compliance_standards USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_compliance_standards_updated_at
                BEFORE UPDATE ON security.compliance_standards
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE security.compliance_standards IS 'Repository of compliance standards and regulatory requirements.
                Serves as central repository for all compliance standards and regulatory requirements. Captures detailed requirements from
                various regulatory frameworks. Supports hierarchical organization of requirements. Includes metadata about jurisdiction and
                effective dates. Accommodates complex regulatory structures through standard rule types. Historical versions maintained for
                compliance verification. Tracks regulatory updates and implementation deadlines. Supports translation into multiple languages.
                Centralizes compliance standards for consistent implementation. Optimized for rapid querying during compliance assessments.';

                -- Serial No: 178 | TABLE: security.security_controls
                -- Description: Repository of security controls and their implementation status
                -- Business Case: The security_controls table serves as the central repository for all security
                -- controls implemented or planned within the workforce scheduling system, providing a structured
                -- approach to security management. It captures detailed information about each control including
                -- its purpose, implementation status, and effectiveness metrics to support security program
                -- management. The table supports multiple control frameworks including NIST, ISO 27001, and
                -- internal security standards, accommodating different organizational requirements. Each control
                -- record includes metadata about its category, maturity level, and ownership to enable effective
                -- governance of security practices. The implementation includes robust tracking of control
                -- implementation history to identify changes in security posture over time and support audit
                -- requirements. Historical control data is maintained to support retrospective analysis of
                -- security effectiveness and its relationship to security incidents. For operational efficiency,
                -- the system tracks control maturity metrics to enable measurement of security program maturity
                -- and identify areas for improvement. The table integrates with the risk management system to
                -- enable automatic calculation of risk reduction based on control implementation. The design
                -- accommodates complex control structures with dependencies between controls, providing detailed
                -- insights into security posture. By centralizing security control management, the organization
                -- can ensure consistent application of security practices while providing the flexibility needed
                -- for different business contexts. The table is optimized for rapid querying during security
                -- assessments and compliance audits.
                -- KPI: Control implementation rate, Control maturity level,
                --      Control effectiveness rate, Control coverage completeness,
                --      Security program maturity
                -- Feature Reference: 906, 907, 908, 909, 910
                CREATE TABLE IF NOT EXISTS security.security_controls (
                    control_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    control_code VARCHAR(50) UNIQUE NOT NULL CHECK (control_code ~ '^[A-Z0-9_]{3,50}$'),
                    name VARCHAR(100) NOT NULL,
                    description TEXT,
                    framework VARCHAR(50) NOT NULL CHECK (framework IN ('NIST', 'ISO_27001', 'CIS', 'PCI_DSS', 'GDPR', 'INTERNAL')),
                    category VARCHAR(50) NOT NULL,
                    sub_category VARCHAR(50),
                    control_type VARCHAR(50) NOT NULL CHECK (control_type IN ('PREVENTIVE', 'DETECTIVE', 'CORRECTIVE', 'COMPENSATING')),
                    implementation_status VARCHAR(20) NOT NULL DEFAULT 'PLANNED'
                        CHECK (implementation_status IN ('PLANNED', 'IN_PROGRESS', 'IMPLEMENTED', 'TESTED', 'DEPRECATED')),
                    implementation_level VARCHAR(20) NOT NULL DEFAULT 'BASIC'
                        CHECK (implementation_level IN ('NONE', 'BASIC', 'GOOD', 'ADVANCED')),
                    maturity_level INTEGER NOT NULL DEFAULT 1 CHECK (maturity_level BETWEEN 1 AND 5),
                    owner_id UUID REFERENCES hr.employees(employee_id),
                    steward_id UUID REFERENCES hr.employees(employee_id),
                    dependencies UUID[],
                    effectiveness_metrics JSONB,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_security_controls_framework ON security.security_controls(framework);
                CREATE INDEX IF NOT EXISTS idx_security_controls_category ON security.security_controls(category);
                CREATE INDEX IF NOT EXISTS idx_security_controls_subcategory ON security.security_controls(sub_category);
                CREATE INDEX IF NOT EXISTS idx_security_controls_type ON security.security_controls(control_type);
                CREATE INDEX IF NOT EXISTS idx_security_controls_status ON security.security_controls(implementation_status);
                CREATE INDEX IF NOT EXISTS idx_security_controls_level ON security.security_controls(implementation_level);
                CREATE INDEX IF NOT EXISTS idx_security_controls_maturity ON security.security_controls(maturity_level);
                CREATE INDEX IF NOT EXISTS idx_security_controls_owner ON security.security_controls(owner_id) WHERE owner_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_security_controls_steward ON security.security_controls(steward_id)
                    WHERE steward_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_security_controls_dependencies ON security.security_controls USING GIN(dependencies);
                CREATE INDEX IF NOT EXISTS idx_security_controls_metrics ON security.security_controls USING GIN(effectiveness_metrics);
                CREATE INDEX IF NOT EXISTS idx_security_controls_metadata ON security.security_controls USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_security_controls_updated_at
                BEFORE UPDATE ON security.security_controls
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE security.security_controls IS 'Repository of security controls and their implementation status.
                Serves as central repository for all security controls implemented or planned. Captures detailed information about each control.
                Supports multiple control frameworks including NIST and ISO 27001. Includes metadata about category, maturity, and ownership.
                Tracks implementation history for audit requirements. Historical data maintained for retrospective analysis. Tracks maturity
                metrics for security program measurement. Integrates with risk management system for risk reduction calculation. Accommodates
                complex control structures with dependencies. Centralizes security control management for consistent security practices.
                Optimized for rapid querying during security assessments and compliance audits.';

				
                -- Serial No: 177 | TABLE: security.compliance_mappings
                -- Description: Mapping of security controls to compliance requirements
                -- Business Case: The compliance_mappings table provides detailed mappings between security
                -- controls implemented in the workforce scheduling system and specific compliance requirements,
                -- enabling effective compliance management and reporting. It captures the relationship between
                -- technical and procedural controls and regulatory requirements to demonstrate how compliance
                -- obligations are met. The table supports multiple mapping types including direct mappings,
                -- compensating controls, and inherited controls, accommodating different compliance scenarios.
                -- Each mapping record includes metadata about the implementation status, evidence location, and
                -- verification method to support audit requirements. The implementation includes robust tracking
                -- of mapping history to identify changes in control implementation over time and support audit
                -- requirements. Historical mapping data is maintained to support retrospective analysis of
                -- compliance posture and its relationship to security incidents. For operational efficiency,
                -- the system tracks compliance coverage metrics to enable measurement of compliance completeness
                -- across different regulatory frameworks. The table integrates with the compliance standards
                -- repository to enable automatic calculation of compliance scores based on control implementation.
                -- The design accommodates complex compliance scenarios with multiple requirements mapped to
                -- single controls and vice versa, providing detailed insights into compliance posture. By
                -- centralizing compliance mappings, the organization can ensure consistent demonstration of
                -- compliance across all regulatory frameworks while providing the detailed evidence needed for
                -- compliance audits. The table is optimized for rapid querying during compliance reporting,
                -- which is critical for timely submission of compliance documentation.
                -- KPI: Compliance coverage rate, Control implementation completeness,
                --      Evidence availability rate, Audit preparation time,
                --      Compliance gap identification rate
                -- Feature Reference: 901, 902, 903, 904, 905
                CREATE TABLE IF NOT EXISTS security.compliance_mappings (
                    mapping_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    standard_id UUID NOT NULL REFERENCES security.compliance_standards(standard_id),
                    control_id UUID NOT NULL REFERENCES security.security_controls(control_id),
                    mapping_type VARCHAR(50) NOT NULL DEFAULT 'DIRECT'
                        CHECK (mapping_type IN ('DIRECT', 'COMPENSATING', 'INHERITED', 'PARTIAL')),
                    implementation_status VARCHAR(20) NOT NULL DEFAULT 'PLANNED'
                        CHECK (implementation_status IN ('PLANNED', 'IN_PROGRESS', 'IMPLEMENTED', 'TESTED', 'VERIFIED')),
                    implementation_details TEXT,
                    evidence_location TEXT,
                    verification_method VARCHAR(50) NOT NULL CHECK (verification_method IN ('DOCUMENT_REVIEW', 'TESTING',
                        'OBSERVATION', 'SYSTEM_CHECK', 'THIRD_PARTY_AUDIT')),
                    verification_date DATE,
                    verification_results JSONB,
                    exception_requested BOOLEAN NOT NULL DEFAULT FALSE,
                    exception_reason TEXT,
                    exception_approval JSONB,
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_compliance_mappings_standard ON security.compliance_mappings(standard_id);
                CREATE INDEX IF NOT EXISTS idx_compliance_mappings_control ON security.compliance_mappings(control_id);
                CREATE INDEX IF NOT EXISTS idx_compliance_mappings_type ON security.compliance_mappings(mapping_type);
                CREATE INDEX IF NOT EXISTS idx_compliance_mappings_status ON security.compliance_mappings(implementation_status);
                CREATE INDEX IF NOT EXISTS idx_compliance_mappings_verified ON security.compliance_mappings(verification_date)
                    WHERE verification_date IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_compliance_mappings_exception ON security.compliance_mappings(exception_requested)
                    WHERE exception_requested = TRUE;
                CREATE INDEX IF NOT EXISTS idx_compliance_mappings_active ON security.compliance_mappings(is_active)
                    WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_compliance_mappings_results ON security.compliance_mappings USING GIN(verification_results);
                CREATE INDEX IF NOT EXISTS idx_compliance_mappings_metadata ON security.compliance_mappings USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_compliance_mappings_updated_at
                BEFORE UPDATE ON security.compliance_mappings
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE security.compliance_mappings IS 'Mapping of security controls to compliance requirements.
                Provides detailed mappings between security controls and compliance requirements. Captures relationship between controls and
                regulatory requirements. Supports multiple mapping types including direct and compensating controls. Includes metadata about
                implementation status and evidence location. Tracks mapping history for audit requirements. Historical data maintained for
                retrospective analysis. Tracks compliance coverage metrics for completeness measurement. Integrates with compliance standards
                repository for score calculation. Accommodates complex compliance scenarios with multiple requirements mapped to controls.
                Centralizes compliance mappings for consistent demonstration of compliance. Optimized for rapid querying during compliance
                reporting.';


                -- Serial No: 179 | TABLE: security.risk_register
                -- Description: Central repository for identified security risks and mitigation plans
                -- Business Case: The risk_register table serves as the central repository for all identified
                -- security risks within the workforce scheduling system, providing a structured approach to risk
                -- management. It captures detailed information about each risk including likelihood, impact,
                -- residual risk level, and mitigation plans to support informed risk decision-making. The table
                -- supports multiple risk sources including vulnerability assessments, threat modeling, and
                -- business impact analysis, accommodating different risk identification methods. Each risk record
                -- includes metadata about the risk owner, assessment date, and review schedule to enable proper
                -- governance of risk management activities. The implementation includes robust tracking of risk
                -- treatment progress with milestones and deadlines to ensure timely mitigation of security risks.
                -- Historical risk data is maintained to identify patterns in risk types and measure the
                -- effectiveness of risk management practices over time. For compliance purposes, the system
                -- tracks all required documentation for regulatory reporting of security risks and their
                -- treatment status. The table integrates with the vulnerability management system to enable
                -- end-to-end tracking of risk identification through mitigation. The design accommodates complex
                -- risk scenarios with interdependent risks and multiple mitigation options, providing detailed
                -- insights into the organization's risk posture. By centralizing risk management, the organization
                -- can ensure consistent risk assessment and treatment while providing the detailed evidence
                -- needed for compliance audits and executive reporting. The table is optimized for rapid querying
                -- during risk assessment meetings, which is critical for timely identification and treatment of
                -- security risks.
                -- KPI: Risk treatment time, Critical risk count,
                --      Risk recurrence rate, Risk acceptance rate,
                --      Risk reduction rate
                -- Feature Reference: 911, 912, 913, 914, 915
                CREATE TABLE IF NOT EXISTS security.risk_register (
                    risk_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    risk_code VARCHAR(50) UNIQUE NOT NULL CHECK (risk_code ~ '^[A-Z0-9_]{3,50}$'),
                    title VARCHAR(200) NOT NULL,
                    description TEXT NOT NULL,
                    risk_source VARCHAR(50) NOT NULL CHECK (risk_source IN ('VULNERABILITY_SCAN', 'THREAT_MODELING',
                        'BUSINESS_IMPACT_ANALYSIS', 'AUDIT_FINDING', 'REGULATORY_FINDING', 'INCIDENT_ANALYSIS')),
                    risk_category VARCHAR(50) NOT NULL CHECK (risk_category IN ('TECHNICAL', 'PROCESS', 'HUMAN', 'COMPLIANCE', 'STRATEGIC')),
                    likelihood VARCHAR(20) NOT NULL CHECK (likelihood IN ('VERY_LOW', 'LOW', 'MEDIUM', 'HIGH', 'VERY_HIGH')),
                    impact VARCHAR(20) NOT NULL CHECK (impact IN ('VERY_LOW', 'LOW', 'MEDIUM', 'HIGH', 'VERY_HIGH')),
                    inherent_risk_level VARCHAR(20) NOT NULL CHECK (inherent_risk_level IN ('VERY_LOW', 'LOW', 'MEDIUM', 'HIGH', 'VERY_HIGH')),
                    residual_risk_level VARCHAR(20) NOT NULL CHECK (residual_risk_level IN ('VERY_LOW', 'LOW', 'MEDIUM', 'HIGH', 'VERY_HIGH')),
                    risk_score NUMERIC(4,2) NOT NULL CHECK (risk_score BETWEEN 0.0 AND 25.0),
                    status VARCHAR(20) NOT NULL DEFAULT 'IDENTIFIED'
                        CHECK (status IN ('IDENTIFIED', 'ANALYZING', 'ACCEPTED', 'MITIGATING', 'MONITORING', 'RESOLVED')),
                    identified_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    identified_by UUID REFERENCES hr.employees(employee_id),
                    risk_owner UUID NOT NULL REFERENCES hr.employees(employee_id),
                    risk_steward UUID REFERENCES hr.employees(employee_id),
                    business_unit_id UUID NOT NULL REFERENCES hr.departments(department_id),
                    affected_assets JSONB NOT NULL,
                    mitigation_plan TEXT NOT NULL,
                    mitigation_steps JSONB NOT NULL,
                    mitigation_deadline DATE NOT NULL,
                    mitigation_started_at TIMESTAMP WITH TIME ZONE,
                    mitigation_completed_at TIMESTAMP WITH TIME ZONE,
                    verification_method VARCHAR(50) NOT NULL,
                    verification_evidence TEXT,
                    risk_acceptance JSONB,
                    next_review_date DATE NOT NULL,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_risk_register_source ON security.risk_register(risk_source);
                CREATE INDEX IF NOT EXISTS idx_risk_register_category ON security.risk_register(risk_category);
                CREATE INDEX IF NOT EXISTS idx_risk_register_level ON security.risk_register(inherent_risk_level, residual_risk_level);
                CREATE INDEX IF NOT EXISTS idx_risk_register_score ON security.risk_register(risk_score DESC);
                CREATE INDEX IF NOT EXISTS idx_risk_register_status ON security.risk_register(status);
                CREATE INDEX IF NOT EXISTS idx_risk_register_identified ON security.risk_register(identified_at DESC);
                CREATE INDEX IF NOT EXISTS idx_risk_register_deadline ON security.risk_register(mitigation_deadline);
                CREATE INDEX IF NOT EXISTS idx_risk_register_completed ON security.risk_register(mitigation_completed_at)
                    WHERE mitigation_completed_at IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_risk_register_owner ON security.risk_register(risk_owner);
                CREATE INDEX IF NOT EXISTS idx_risk_register_unit ON security.risk_register(business_unit_id);
                CREATE INDEX IF NOT EXISTS idx_risk_register_assets ON security.risk_register USING GIN(affected_assets);
                CREATE INDEX IF NOT EXISTS idx_risk_register_metadata ON security.risk_register USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_risk_register_updated_at
                BEFORE UPDATE ON security.risk_register
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE security.risk_register IS 'Central repository for identified security risks and mitigation plans.
                Serves as central repository for all identified security risks. Captures detailed information about each risk. Supports multiple
                risk sources including vulnerability assessments and threat modeling. Includes metadata about risk owner and business unit.
                Tracks risk treatment progress with milestones and deadlines. Historical data maintained to identify risk patterns. Tracks
                required documentation for regulatory reporting. Integrates with vulnerability management system for end-to-end tracking.
                Accommodates complex risk scenarios with interdependent risks. Centralizes risk management for consistent assessment. Optimized
                for rapid querying during risk assessment meetings.';



                -- Serial No: 180 | TABLE: security.threat_intelligence
                -- Description: Repository of threat intelligence data for proactive security
                -- Business Case: The threat_intelligence table serves as the central repository for threat
                -- intelligence data, enabling proactive security management through early awareness of emerging
                -- threats. It captures detailed information about threat actors, attack patterns, indicators of
                -- compromise (IOCs), and mitigation recommendations to support threat detection and prevention.
                -- The table supports multiple intelligence sources including commercial feeds, open-source
                -- intelligence, and internal incident data, accommodating different intelligence gathering
                -- methods. Each intelligence record includes metadata about the confidence level, relevance, and
                -- timeliness to enable appropriate prioritization of threats. The implementation includes robust
                -- tracking of intelligence history to identify evolving threat patterns and measure the
                -- effectiveness of threat intelligence over time. Historical intelligence data is maintained to
                -- support retrospective analysis of threat landscape changes and their relationship to security
                -- incidents. For operational efficiency, the system tracks intelligence utilization metrics to
                -- enable measurement of threat intelligence value and identify opportunities for improvement.
                -- The table integrates with security monitoring systems to enable automated correlation of
                -- intelligence with security events and facilitate rapid response to potential threats. The
                -- design accommodates complex threat scenarios with multiple indicators and evolving attack
                -- patterns, providing detailed insights into the threat landscape. By centralizing threat
                -- intelligence, the organization can ensure consistent threat awareness across security teams
                -- while providing the detailed context needed for effective threat detection and response. The
                -- table is optimized for rapid querying during security monitoring, which is critical for timely
                -- identification and mitigation of emerging threats.
                -- KPI: Threat detection rate, Intelligence utilization rate,
                --      Threat response time, False positive rate,
                --      Threat intelligence coverage
                -- Feature Reference: 916, 917, 918, 919, 920
                CREATE TABLE IF NOT EXISTS security.threat_intelligence (
                    intelligence_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
