                    title VARCHAR(200) NOT NULL,
                    description TEXT NOT NULL,
                    intelligence_type VARCHAR(50) NOT NULL CHECK (intelligence_type IN ('INDICATOR', 'TTP', 'CAMPAIGN',
                        'THREAT_ACTOR', 'VULNERABILITY', 'MALWARE')),
