                        'THIRD_PARTY_REPORT', 'GOVERNMENT_ALERT')),
                    confidence_level VARCHAR(20) NOT NULL CHECK (confidence_level IN ('VERY_LOW', 'LOW', 'MEDIUM', 'HIGH', 'VERY_HIGH')),
                    relevance_level VARCHAR(20) NOT NULL CHECK (relevance_level IN ('VERY_LOW', 'LOW', 'MEDIUM', 'HIGH', 'VERY_HIGH')),
                    timeliness VARCHAR(20) NOT NULL CHECK (timeliness IN ('REAL_TIME', 'CURRENT', 'HISTORICAL')),
                    observed_from TIMESTAMP WITH TIME ZONE NOT NULL,
                    observed_to TIMESTAMP WITH TIME ZONE,
                    iocs JSONB NOT NULL,
                    tactics_techniques JSONB NOT NULL,
                    affected_industries VARCHAR(100)[],
                    affected_technologies VARCHAR(100)[],
                    mitigation_recommendations TEXT NOT NULL,
                    severity VARCHAR(20) NOT NULL CHECK (severity IN ('CRITICAL', 'HIGH', 'MEDIUM', 'LOW')),
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
