                CREATE INDEX IF NOT EXISTS idx_threat_intelligence_source ON security.threat_intelligence(source);
                CREATE INDEX IF NOT EXISTS idx_threat_intelligence_severity ON security.threat_intelligence(severity);
                CREATE INDEX IF NOT EXISTS idx_threat_intelligence_observed ON security.threat_intelligence(observed_from DESC);
                CREATE INDEX IF NOT EXISTS idx_threat_intelligence_industries ON security.threat_intelligence USING GIN(affected_industries);
                CREATE INDEX IF NOT EXISTS idx_threat_intelligence_technologies ON security.threat_intelligence USING GIN(affected_technologies);
                CREATE INDEX IF NOT EXISTS idx_threat_intelligence_metadata ON security.threat_intelligence USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_threat_intelligence_updated_at
                BEFORE UPDATE ON security.threat_intelligence
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE security.threat_intelligence IS 'Repository of threat intelligence data for proactive security.
                Serves as central repository for threat intelligence data. Captures detailed information about threat actors and attack patterns.
                Supports multiple intelligence sources including commercial feeds and open-source intelligence. Includes metadata about confidence
                level and relevance. Tracks intelligence history for threat pattern identification. Historical data maintained for retrospective
                analysis. Tracks utilization metrics for value measurement. Integrates with security monitoring systems for automated correlation.
                Accommodates complex threat scenarios with multiple indicators. Centralizes threat intelligence for consistent awareness. Optimized
                for rapid querying during security monitoring.';




                -- Serial No: 181 | TABLE: data_governance.data_profiles
                -- Description: Comprehensive data profiling statistics for quality assessment
                -- Business Case: The data_profiles table stores comprehensive data profiling statistics that
                -- enable detailed analysis of data quality characteristics across the workforce scheduling
                -- system. It captures key metrics such as null rates, uniqueness, value distributions, and
                -- statistical properties to support data quality assessment and trend analysis. This information
                -- is critical for identifying data quality issues, understanding data characteristics, and
                -- measuring improvement against data quality goals. The table supports multiple profiling
                -- dimensions including column-level statistics, value distributions, and pattern analysis,
                -- enabling holistic assessment of data health. Historical profile data is versioned to track
                -- changes over time and measure improvement against quality goals. Each profile record includes
                -- metadata about the collection method, execution frequency, and confidence level to ensure
                -- proper interpretation of results. The implementation includes mechanisms for automated profile
                -- collection through scheduled jobs, ensuring timely assessment of data quality. For metrics
                -- with defined targets, the table stores variance calculations to highlight areas requiring
                -- attention. Historical profile data is used to establish baselines and detect anomalies that
                -- may indicate underlying data issues. By centralizing data profiling results, the organization
                -- can ensure comprehensive data quality assessment that provides visibility into data health
                -- across all components. The table is optimized for time-series analysis of profiling metrics,
                -- supporting trend identification and predictive data quality management.
                -- KPI: Data completeness rate, Data uniqueness rate,
                --      Pattern consistency rate, Data profile coverage,
                --      Data issue detection time
                -- Feature Reference: 921, 922, 923, 924, 925
                CREATE TABLE IF NOT EXISTS data_governance.data_profiles (
                    profile_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    schema_name VARCHAR(100) NOT NULL,
                    table_name VARCHAR(200) NOT NULL,
                    column_name VARCHAR(100) NOT NULL,
                    profile_date DATE NOT NULL DEFAULT CURRENT_DATE,
                    null_count INTEGER NOT NULL DEFAULT 0 CHECK (null_count >= 0),
                    not_null_count INTEGER NOT NULL DEFAULT 0 CHECK (not_null_count >= 0),
                    total_count INTEGER NOT NULL DEFAULT 0 CHECK (total_count >= 0),
                    null_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
                        CASE
                            WHEN total_count > 0 THEN (null_count::NUMERIC / total_count * 100.0)
                            ELSE 0
                        END
                    ) STORED,
                    unique_count INTEGER NOT NULL DEFAULT 0 CHECK (unique_count >= 0),
                    distinct_count INTEGER NOT NULL DEFAULT 0 CHECK (distinct_count >= 0),
                    duplicate_count INTEGER NOT NULL DEFAULT 0 CHECK (duplicate_count >= 0),
                    duplicate_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
                        CASE
                            WHEN total_count > 0 THEN (duplicate_count::NUMERIC / total_count * 100.0)
                            ELSE 0
                        END
                    ) STORED,
                    min_value TEXT,
                    max_value TEXT,
                    average_length INTEGER,
                    median_value TEXT,
                    mode_value TEXT,
                    standard_deviation NUMERIC(15,6),
                    value_distribution JSONB,
                    pattern_analysis JSONB,
                    data_quality_score NUMERIC(5,2) CHECK (data_quality_score BETWEEN 0.00 AND 100.00),
                    completeness_score NUMERIC(5,2) CHECK (completeness_score BETWEEN 0.00 AND 100.00),
                    validity_score NUMERIC(5,2) CHECK (validity_score BETWEEN 0.00 AND 100.00),
                    collection_method VARCHAR(50) NOT NULL DEFAULT 'AUTOMATED'
                        CHECK (collection_method IN ('AUTOMATED', 'MANUAL', 'SAMPLED')),
                    sample_size INTEGER,
                    sample_percentage NUMERIC(5,2) CHECK (sample_percentage BETWEEN 0.00 AND 100.00),
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,

                    -- Constraints
                    CONSTRAINT uq_table_column_date UNIQUE (schema_name, table_name, column_name, profile_date),
                    CONSTRAINT chk_counts CHECK (null_count + not_null_count = total_count),
                    CONSTRAINT chk_quality_scores CHECK (
                        data_quality_score IS NULL OR
                        (completeness_score IS NOT NULL AND validity_score IS NOT NULL)
                    )
                );

                


                COMMENT ON TABLE data_governance.data_profiles IS 'Comprehensive data profiling statistics for data quality assessment and trend analysis.
                Stores comprehensive data profiling statistics that enable detailed analysis of data quality characteristics. Captures key metrics
                such as null rates, uniqueness, and value distributions. Critical for identifying data quality issues and understanding data
                characteristics. Supports multiple profiling dimensions including column-level statistics and pattern analysis. Historical profile
                data versioned to track changes over time. Includes metadata about collection method and confidence level. Includes mechanisms
                for automated profile collection. Stores variance calculations for metrics with defined targets. Used to establish baselines and
                detect anomalies. Centralizes data profiling results for comprehensive data quality assessment. Optimized for time-series analysis
                of profiling metrics.';

                -- Serial No: 182 | TABLE: data_governance.data_quality_monitoring
                -- Description: Configuration of data quality monitoring schedules and parameters
                -- Business Case: The data_quality_monitoring table manages the configuration of data quality
                -- monitoring schedules and parameters across the workforce scheduling system, ensuring timely
