                -- scope, and execution parameters to support consistent data quality evaluation. The table
                -- supports multiple monitoring types including real-time monitoring, scheduled batch monitoring,
                -- and on-demand monitoring, accommodating different data quality requirements. Each monitoring
                -- configuration includes metadata about its priority, resource allocation, and failure handling
                -- to support proper governance of data quality processes. The implementation includes robust
                -- validation rules to ensure monitoring configurations are correctly formulated and can be
                -- reliably executed. Historical configuration data is maintained to identify patterns in
                -- monitoring effectiveness and measure the impact of configuration changes over time. For
                -- operational efficiency, the system tracks monitoring execution metrics to enable measurement
                -- of monitoring effectiveness and identify opportunities for optimization. The table integrates
                -- with the data quality rules system to enable automatic application of monitoring rules based
                -- on configuration parameters. The design accommodates complex monitoring scenarios with
                -- dependencies between monitoring jobs and conditional execution rules, providing detailed
                -- insights into data quality monitoring effectiveness. By centralizing monitoring configuration,
                -- the organization can ensure consistent data quality assessment practices while providing the
                -- flexibility needed for different business contexts. The table is optimized for rapid querying
                -- during monitoring execution, which is critical for timely identification of data quality issues.
                -- KPI: Monitoring coverage completeness, Monitoring execution success rate,
                --      Data issue detection time, Monitoring configuration completeness,
                --      Monitoring optimization rate
                -- Feature Reference: 926, 927, 928, 929, 930
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_monitoring (
                    monitoring_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    monitoring_code VARCHAR(50) UNIQUE NOT NULL CHECK (monitoring_code ~ '^[A-Z0-9_]{3,50}$'),
                    name VARCHAR(200) NOT NULL,
                    description TEXT,
                    monitoring_type VARCHAR(50) NOT NULL CHECK (monitoring_type IN ('REAL_TIME', 'SCHEDULED', 'ON_DEMAND', 'EVENT_TRIGGERED')),
                    schedule_cron VARCHAR(50),
                    target_tables TEXT[] NOT NULL,
                    target_columns TEXT[],
                    rules_to_apply UUID[],
                    execution_parameters JSONB DEFAULT '{}'::JSONB,
                    priority INTEGER NOT NULL DEFAULT 50 CHECK (priority BETWEEN 1 AND 100),
                    resource_allocation JSONB DEFAULT '{"max_workers": 1, "timeout_minutes": 30}'::JSONB,
                    failure_handling JSONB DEFAULT '{"retry_count": 2, "retry_interval_minutes": 5, "escalation_rules": []}'::JSONB,
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    last_execution TIMESTAMP WITH TIME ZONE,
                    last_execution_status VARCHAR(20) CHECK (last_execution_status IN ('SUCCESS', 'FAILED', 'RUNNING', 'SKIPPED')),
                    last_execution_duration_ms INTEGER,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_type ON data_governance.data_quality_monitoring(monitoring_type);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_active ON data_governance.data_quality_monitoring(is_active)
                    WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_schedule ON data_governance.data_quality_monitoring(schedule_cron)
                    WHERE schedule_cron IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_tables ON data_governance.data_quality_monitoring
                    USING GIN(target_tables);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_columns ON data_governance.data_quality_monitoring
                    USING GIN(target_columns);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_rules ON data_governance.data_quality_monitoring
                    USING GIN(rules_to_apply);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_status ON data_governance.data_quality_monitoring(last_execution_status);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_execution ON data_governance.data_quality_monitoring(last_execution DESC);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_metadata ON data_governance.data_quality_monitoring USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_quality_monitoring_updated_at
                BEFORE UPDATE ON data_governance.data_quality_monitoring
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_quality_monitoring IS 'Configuration of data quality monitoring schedules and parameters.
                Manages configuration of data quality monitoring schedules and parameters. Captures monitoring frequency, scope, and execution
                parameters. Supports multiple monitoring types including real-time and scheduled monitoring. Includes metadata about priority
                and resource allocation. Includes validation rules to ensure correct configuration. Historical data maintained to identify
                patterns in monitoring effectiveness. Tracks execution metrics for optimization. Integrates with data quality rules system for
                automatic application. Accommodates complex monitoring scenarios with dependencies. Centralizes monitoring configuration for
                consistent data quality assessment. Optimized for rapid querying during monitoring execution.';

                -- Serial No: 183 | TABLE: data_governance.data_quality_monitoring_history
                -- Description: Historical execution records for data quality monitoring jobs
                -- Business Case: The data_quality_monitoring_history table maintains a comprehensive record of
                -- all data quality monitoring job executions, providing visibility into monitoring performance
                -- and effectiveness. It captures detailed information about each execution including start and
                -- end times, resource usage, and results to support performance analysis and troubleshooting.
                -- This information is critical for diagnosing monitoring failures, optimizing monitoring
                -- performance, and ensuring timely detection of data quality issues. The table supports multiple
                -- execution statuses including success, failure, and running states, accommodating different
                -- monitoring scenarios. Each execution record includes metadata about the monitoring
                -- configuration, execution context, and outcome to enable accurate assessment of monitoring
                -- effectiveness. Historical execution data is maintained to identify trends in monitoring
                -- performance and measure the impact of configuration changes over time. For operational
                -- efficiency, the system tracks execution duration and resource utilization to enable capacity
                -- planning for monitoring operations. The table integrates with the data quality metrics system
                -- to enable correlation of monitoring results with actual data quality metrics. The design
                -- accommodates complex monitoring scenarios with multi-step processes and conditional execution
                -- paths, providing detailed insights into monitoring behavior. By centralizing execution
                -- history, the organization can ensure consistent evaluation of monitoring effectiveness while
                -- providing the data needed for continuous improvement of monitoring practices. The table is
                -- optimized for rapid querying during performance analysis, which often involves comparing
                -- multiple execution runs to identify improvement opportunities.
                -- KPI: Monitoring execution success rate, Execution duration,
                --      Resource utilization, Data issue detection time,
                --      Monitoring optimization rate
                -- Feature Reference: 931, 932, 933, 934, 935
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_monitoring_history (
                    history_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    monitoring_id UUID NOT NULL REFERENCES data_governance.data_quality_monitoring(monitoring_id),
                    execution_id UUID NOT NULL,
                    start_time TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    end_time TIMESTAMP WITH TIME ZONE,
                    duration_ms INTEGER GENERATED ALWAYS AS (
                        CASE
                            WHEN end_time IS NOT NULL
                                THEN EXTRACT(EPOCH FROM (end_time - start_time)) * 1000
                            ELSE NULL
                        END
                    ) STORED,
                    status VARCHAR(20) NOT NULL CHECK (status IN ('SUCCESS', 'FAILED', 'RUNNING', 'SKIPPED')),
                    error_message TEXT,
                    resource_usage JSONB DEFAULT '{"cpu_usage": 0.0, "memory_usage_mb": 0, "rows_processed": 0}'::JSONB,
                    metrics_collected INTEGER NOT NULL DEFAULT 0,
                    issues_detected INTEGER NOT NULL DEFAULT 0,
                    execution_parameters JSONB,
                    created_by UUID NOT NULL,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_by UUID,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

