                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_history_monitoring ON data_governance.data_quality_monitoring_history(monitoring_id);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_history_execution ON data_governance.data_quality_monitoring_history(execution_id);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_history_time ON data_governance.data_quality_monitoring_history(start_time DESC);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_history_status ON data_governance.data_quality_monitoring_history(status);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_history_duration ON data_governance.data_quality_monitoring_history(duration_ms);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_history_issues ON data_governance.data_quality_monitoring_history(issues_detected);
                CREATE INDEX IF NOT EXISTS idx_data_quality_monitoring_history_metadata ON data_governance.data_quality_monitoring_history USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_quality_monitoring_history_updated_at
                BEFORE UPDATE ON data_governance.data_quality_monitoring_history
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_quality_monitoring_history IS 'Historical execution records for data quality monitoring jobs.
