                    metric_type VARCHAR(50) NOT NULL CHECK (metric_type IN ('DELIVERY_RATE', 'OPEN_RATE', 'CLICK_RATE',
                        'RESPONSE_RATE', 'ENGAGEMENT_SCORE', 'AWARENESS_SCORE')),
                    calculation_method VARCHAR(100) NOT NULL CHECK (calculation_method IN ('SYSTEM_CALCULATED', 'MANUAL_ENTRY',
                        'SURVEY', 'OBSERVATION')),
                    calculation_time TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metric_value NUMERIC(5,2) NOT NULL CHECK (metric_value BETWEEN 0.00 AND 100.00),
                    target_value NUMERIC(5,2) CHECK (target_value BETWEEN 0.00 AND 100.00),
                    warning_threshold NUMERIC(5,2) CHECK (warning_threshold BETWEEN 0.00 AND 100.00),
                    failure_threshold NUMERIC(5,2) CHECK (failure_threshold BETWEEN 0.00 AND 100.00),
                    audience_segment JSONB,
                    channel VARCHAR(50),
                    context JSONB,
                    created_by UUID NOT NULL,
                    updated_by UUID,
