                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_metrics_name ON data_governance.data_quality_communication_campaign_metrics(metric_name);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_metrics_time ON data_governance.data_quality_communication_campaign_metrics(measurement_time DESC);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_metrics_value ON data_governance.data_quality_communication_campaign_metrics(metric_value);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_metrics_segment ON data_governance.data_quality_communication_campaign_metrics
