                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_benchmarks_value ON data_governance.data_quality_communication_campaign_benchmarks(benchmark_value);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_benchmarks_validity ON data_governance.data_quality_communication_campaign_benchmarks(data_collection_date, data_validity_period);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_benchmarks_confidence ON data_governance.data_quality_communication_campaign_benchmarks(confidence_level);
