                -- Serial No: 198 | TABLE: data_governance.data_quality_communication_campaign_goals
                -- Description: Configuration of goals for data quality communication campaigns
                -- Business Case: The data_quality_communication_campaign_goals table stores configuration
                -- details for goals used to evaluate data quality communication campaign effectiveness against
                -- organizational objectives. It captures target values, acceptable ranges, and priority levels
                -- for key performance indicators across different business units and time periods. The table
                -- supports multiple goal types including minimum requirements, stretch goals, and industry
                -- comparisons, enabling nuanced goal setting and performance evaluation. Each goal configuration
                -- includes metadata about its effective dates, priority, and approval status to support proper
                -- workflow handling. The implementation accommodates complex goal scenarios such as conditional
                -- goals that apply only under specific business conditions. Goal data is versioned to track
                -- changes over time, which is important for understanding historical performance against
                -- evolving goals. The table is optimized for rapid querying during performance evaluation,
                -- which involves comparing actual performance against configured goals for potentially
                -- hundreds of metrics simultaneously. Historical goal data is used to identify patterns and
                -- improve the goal-setting process. For compliance purposes, the system tracks the approval
                -- status of goals that may conflict with business requirements or regulatory standards. By
                -- centralizing goal configuration, the system enables more effective communication between
                -- leadership and operational teams about performance expectations while providing the data
                -- needed for performance management systems. The table is optimized for rapid querying during
                -- performance evaluation, which is critical for timely feedback on communication campaign
                -- effectiveness.
                -- KPI: Goal configuration completeness, Performance goal achievement rate,
                --      Goal update frequency, Goal data completeness,
                --      Performance gap closure rate
                -- Feature Reference: 1006, 1007, 1008, 1009, 1010
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_communication_campaign_goals (
                    goal_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    goal_code VARCHAR(50) UNIQUE NOT NULL CHECK (goal_code ~ '^[A-Z0-9_]{5,50}$'),
                    name VARCHAR(200) NOT NULL,
                    description TEXT,
                    metric_name VARCHAR(100) NOT NULL CHECK (metric_name IN ('ENGAGEMENT_RATE', 'AWARENESS_IMPROVEMENT_RATE',
                        'BEHAVIOR_CHANGE_RATE', 'CAMPAIGN_REACH_RATE', 'CAMPAIGN_ROI')),
                    campaign_id UUID REFERENCES data_governance.data_quality_communication_campaigns(campaign_id),
                    activity_id UUID REFERENCES data_governance.data_quality_communication_campaign_activities(activity_id),
                    goal_type VARCHAR(50) NOT NULL DEFAULT 'MINIMUM'
                        CHECK (goal_type IN ('MINIMUM', 'TARGET', 'STRETCH', 'INDUSTRY', 'CUSTOM')),
                    target_value NUMERIC(10,4) NOT NULL,
                    acceptable_range_low NUMERIC(10,4),
                    acceptable_range_high NUMERIC(10,4),
                    priority INTEGER DEFAULT 0 CHECK (priority BETWEEN -10 AND 10),
                    effective_start_date DATE NOT NULL DEFAULT CURRENT_DATE,
                    effective_end_date DATE,
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    is_default BOOLEAN NOT NULL DEFAULT FALSE,
                    version INTEGER NOT NULL DEFAULT 1 CHECK (version >= 1),
                    based_on_goal_id UUID REFERENCES data_governance.data_quality_communication_campaign_goals(goal_id),
                    validated_by UUID REFERENCES hr.employees(employee_id),
                    validated_at TIMESTAMP WITH TIME ZONE,
                    validation_results JSONB,
                    usage_count INTEGER NOT NULL DEFAULT 0,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB,

                    -- Constraints
                    CONSTRAINT chk_goal_dates CHECK (effective_end_date IS NULL OR effective_end_date >= effective_start_date),
                    CONSTRAINT chk_goal_ranges CHECK (
                        (acceptable_range_low IS NULL AND acceptable_range_high IS NULL) OR
                        (acceptable_range_low IS NOT NULL AND acceptable_range_high IS NOT NULL AND acceptable_range_high >= acceptable_range_low)
                    )
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_goals_metric ON data_governance.data_quality_communication_campaign_goals(metric_name);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_goals_campaign ON data_governance.data_quality_communication_campaign_goals(campaign_id)
                    WHERE campaign_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_goals_activity ON data_governance.data_quality_communication_campaign_goals(activity_id)
                    WHERE activity_id IS NOT NULL;
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_goals_type ON data_governance.data_quality_communication_campaign_goals(goal_type);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_goals_active ON data_governance.data_quality_communication_campaign_goals(is_active)
                    WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_goals_default ON data_governance.data_quality_communication_campaign_goals(is_default)
                    WHERE is_default = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_goals_version ON data_governance.data_quality_communication_campaign_goals(goal_id, version DESC);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_goals_based_on ON data_governance.data_quality_communication_campaign_goals(based_on_goal_id);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_goals_metadata ON data_governance.data_quality_communication_campaign_goals
                    USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_quality_communication_campaign_goals_updated_at
                BEFORE UPDATE ON data_governance.data_quality_communication_campaign_goals
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_quality_communication_campaign_goals IS 'Configuration of goals for data quality communication campaigns.
                Stores configuration details for goals used to evaluate communication campaign effectiveness. Captures target values, acceptable
                ranges, and priority levels for key performance indicators. Supports multiple goal types including minimum requirements and
                stretch goals. Includes metadata about effective dates and priority. Accommodates complex goal scenarios such as conditional
                goals. Goal data versioned to track changes over time. Optimized for rapid querying during performance evaluation. Historical
                data used to identify patterns and improve goal-setting. Tracks approval status for compliance purposes. Centralizes goal
                configuration for effective communication about performance expectations. Optimized for rapid querying during performance
                evaluation.';

                -- Serial No: 199 | TABLE: data_governance.data_quality_communication_campaign_scorecards
                -- Description: Configuration of scorecards for data quality communication campaign reporting
                -- Business Case: The data_quality_communication_campaign_scorecards table stores configuration
                -- details for scorecards used in organizational reporting of data quality communication campaign
                -- performance. It captures the composition of scorecards including the metrics, weightings, and
                -- targets used to evaluate campaign performance. The table supports multiple scorecard types
                -- including executive dashboards, operational reports, and compliance monitoring views, enabling
                -- tailored reporting for different audiences. Each scorecard configuration includes metadata
                -- about its scope, frequency, and approval status to support proper governance of communication
                -- reporting. The implementation includes versioning of scorecards to track changes over time
                -- while maintaining historical consistency in measurement. Historical scorecard data is
                -- maintained to support retrospective analysis of communication performance trends. For
                -- compliance purposes, the system tracks the approval status of scorecards and maintains audit
                -- trails of all modifications. The table integrates with the campaign metrics system to enable
                -- automatic calculation of scorecard results based on current communication metrics. The design
                -- accommodates different scorecard methodologies while providing a consistent interface for
                -- decision makers. By centralizing scorecard configuration, the organization can ensure
                -- consistent evaluation of communication performance while providing the flexibility needed for
                -- different reporting requirements. The table is optimized for rapid lookup during scorecard
                -- generation, which is critical for timely delivery of communication performance reports.
                -- KPI: Scorecard coverage completeness, Communication performance trend,
                --      Scorecard update frequency, Scorecard data completeness,
                --      Communication improvement rate
                -- Feature Reference: 1011, 1012, 1013, 1014, 1015
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_communication_campaign_scorecards (
                    scorecard_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    scorecard_code VARCHAR(50) UNIQUE NOT NULL CHECK (scorecard_code ~ '^[A-Z0-9_]{5,50}$'),
                    name VARCHAR(200) NOT NULL,
                    description TEXT,
                    scorecard_type VARCHAR(50) NOT NULL CHECK (scorecard_type IN ('EXECUTIVE', 'OPERATIONAL', 'COMPLIANCE', 'DEPARTMENTAL', 'CUSTOM')),
                    scope JSONB NOT NULL DEFAULT '{"organization_wide": true}'::JSONB,
                    metrics JSONB NOT NULL,
                    metric_weights JSONB NOT NULL,
                    target_values JSONB NOT NULL,
                    calculation_method VARCHAR(50) NOT NULL DEFAULT 'WEIGHTED_AVERAGE'
                        CHECK (calculation_method IN ('WEIGHTED_AVERAGE', 'THRESHOLD_BASED', 'CUSTOM_FORMULA')),
                    refresh_frequency VARCHAR(20) NOT NULL DEFAULT 'DAILY'
                        CHECK (refresh_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
                    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    is_default BOOLEAN NOT NULL DEFAULT FALSE,
                    based_on_scorecard_id UUID REFERENCES data_governance.data_quality_communication_campaign_scorecards(scorecard_id),
                    validated_by UUID REFERENCES hr.employees(employee_id),
                    validated_at TIMESTAMP WITH TIME ZONE,
                    validation_results JSONB,
                    usage_count INTEGER NOT NULL DEFAULT 0,
                    created_by UUID NOT NULL,
                    updated_by UUID,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB,

                    -- Constraints
                    CONSTRAINT chk_metrics_structure CHECK (
                        jsonb_typeof(metrics) = 'object'
                        AND metrics != '{}'::JSONB
                    ),
                    CONSTRAINT chk_weights_structure CHECK (
                        jsonb_typeof(metric_weights) = 'object'
                        AND metric_weights != '{}'::JSONB
                    )
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecards_type ON data_governance.data_quality_communication_campaign_scorecards(scorecard_type);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecards_active ON data_governance.data_quality_communication_campaign_scorecards(is_active)
                    WHERE is_active = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecards_default ON data_governance.data_quality_communication_campaign_scorecards(is_default)
                    WHERE is_default = TRUE;
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecards_version ON data_governance.data_quality_communication_campaign_scorecards(scorecard_id, version_number DESC);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecards_based_on ON data_governance.data_quality_communication_campaign_scorecards(based_on_scorecard_id);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecards_metrics ON data_governance.data_quality_communication_campaign_scorecards
                    USING GIN(metrics);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecards_weights ON data_governance.data_quality_communication_campaign_scorecards
                    USING GIN(metric_weights);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecards_targets ON data_governance.data_quality_communication_campaign_scorecards
                    USING GIN(target_values);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecards_metadata ON data_governance.data_quality_communication_campaign_scorecards
                    USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_quality_communication_campaign_scorecards_updated_at
                BEFORE UPDATE ON data_governance.data_quality_communication_campaign_scorecards
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_quality_communication_campaign_scorecards IS 'Configuration of scorecards for data quality communication campaign reporting.
                Stores configuration details for scorecards used in communication campaign reporting. Captures composition including metrics
                and weightings. Supports multiple scorecard types including executive and operational reports. Includes metadata about scope and
                frequency. Includes versioning to track changes over time. Historical data maintained for retrospective analysis. Tracks approval
                status and audit trails for compliance. Integrates with campaign metrics system for automatic calculation. Accommodates different
                scorecard methodologies. Centralizes scorecard configuration for consistent evaluation. Optimized for rapid lookup during
                scorecard generation.';

                -- Serial No: 200 | TABLE: data_governance.data_quality_communication_campaign_scorecard_results
                -- Description: Historical results of data quality communication campaign scorecard calculations
                -- Business Case: The data_quality_communication_campaign_scorecard_results table stores
                -- historical results of data quality communication campaign scorecard calculations, providing a
                -- longitudinal view of communication performance across the organization. It captures the
                -- calculated scores, metric values, and trend indicators for each scorecard evaluation period,
                -- enabling trend analysis and performance measurement. This information is critical for
                -- identifying communication improvement opportunities and measuring the impact of communication
                -- initiatives over time. The table supports multiple evaluation periods including daily, weekly,
                -- and monthly, accommodating different reporting requirements. Each result record includes
                -- metadata about the calculation methodology, data sources, and confidence level to ensure
                -- proper interpretation of results. Historical result data is versioned to track changes in
                -- scorecard configurations while maintaining historical consistency in measurement. For
                -- operational planning, the system stores results at multiple granularities (organization-wide,
                -- departmental, campaign-specific) to support different management perspectives. The table
                -- integrates with the scorecard configuration system to enable automatic recalculation of
                -- historical results when scorecard configurations change. The design accommodates different
                -- scorecard methodologies while providing a consistent interface for trend analysis. By
                -- centralizing scorecard results, the organization can ensure consistent evaluation of
                -- communication performance while providing the flexibility needed for different reporting
                -- requirements. The table is optimized for time-series analysis of scorecard results,
                -- supporting trend identification and predictive communication management.
                -- KPI: Communication trend direction, Scorecard target achievement rate,
                --      Communication improvement rate, Scorecard variance identification rate,
                --      Communication benchmark achievement rate
                -- Feature Reference: 1016, 1017, 1018, 1019, 1020
                CREATE TABLE IF NOT EXISTS data_governance.data_quality_communication_campaign_scorecard_results (
                    result_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                    scorecard_id UUID NOT NULL REFERENCES data_governance.data_quality_communication_campaign_scorecards(scorecard_id),
                    evaluation_date DATE NOT NULL,
                    time_period VARCHAR(20) NOT NULL CHECK (time_period IN ('DAILY', 'WEEKLY', 'MONTHLY', 'QUARTERLY', 'YEARLY')),
                    scope_type VARCHAR(50) NOT NULL CHECK (scope_type IN ('ORGANIZATION', 'DEPARTMENT', 'CAMPAIGN', 'ACTIVITY')),
                    scope_id UUID,
                    scope_name VARCHAR(200),
                    overall_score NUMERIC(5,2) CHECK (overall_score BETWEEN 0.00 AND 100.00),
                    metric_scores JSONB NOT NULL,
                    trend_indicator VARCHAR(20) NOT NULL CHECK (trend_indicator IN ('IMPROVING', 'STABLE', 'DEGRADING', 'NEW_BASELINE')),
                    trend_value NUMERIC(5,2),
                    communication_level VARCHAR(20) NOT NULL CHECK (communication_level IN ('EXCELLENT', 'GOOD', 'FAIR', 'POOR', 'CRITICAL')),
                    calculation_method VARCHAR(50) NOT NULL,
                    calculation_metadata JSONB,
                    data_source VARCHAR(100) NOT NULL,
                    data_confidence NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (data_confidence BETWEEN 0.00 AND 1.00),
                    notes TEXT,
                    created_by UUID NOT NULL,
                    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_by UUID,
                    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    metadata JSONB
                );

                -- Add indexes for performance
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecard_results_scorecard ON data_governance.data_quality_communication_campaign_scorecard_results(scorecard_id);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecard_results_date ON data_governance.data_quality_communication_campaign_scorecard_results(evaluation_date, time_period);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecard_results_scope ON data_governance.data_quality_communication_campaign_scorecard_results(scope_type, scope_id);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecard_results_score ON data_governance.data_quality_communication_campaign_scorecard_results(overall_score);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecard_results_trend ON data_governance.data_quality_communication_campaign_scorecard_results(trend_indicator);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecard_results_level ON data_governance.data_quality_communication_campaign_scorecard_results(communication_level);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecard_results_metrics ON data_governance.data_quality_communication_campaign_scorecard_results
                    USING GIN(metric_scores);
                CREATE INDEX IF NOT EXISTS idx_data_quality_communication_campaign_scorecard_results_metadata ON data_governance.data_quality_communication_campaign_scorecard_results
                    USING GIN(metadata);

                -- Add triggers for audit columns
                CREATE TRIGGER trg_data_quality_communication_campaign_scorecard_results_updated_at
                BEFORE UPDATE ON data_governance.data_quality_communication_campaign_scorecard_results
                FOR EACH ROW
                EXECUTE FUNCTION update_updated_at_column();

                COMMENT ON TABLE data_governance.data_quality_communication_campaign_scorecard_results IS 'Historical results of data quality communication campaign scorecard calculations.
                Stores historical results of communication campaign scorecard calculations. Captures calculated scores and metric values for evaluation
                periods. Critical for identifying improvement opportunities and measuring impact of initiatives. Supports multiple evaluation
                periods including daily and weekly. Includes metadata about calculation methodology and confidence level. Historical data
                versioned to track changes in configurations. Stores results at multiple granularities for different management perspectives.
                Integrates with scorecard configuration system for automatic recalculation. Accommodates different scorecard methodologies.
                Centralizes scorecard results for consistent evaluation. Optimized for time-series analysis of results.';


                    -- Serial No: 201 | TABLE: system.maintenance_jobs
                    -- Description: Configuration and tracking of system maintenance operations
                    -- Business Case: The maintenance_jobs table manages the scheduling and execution of background maintenance
                    -- tasks that are critical for system health and performance. It provides a centralized repository for job
                    -- definitions, schedules, and execution history, enabling consistent management of operational processes
                    -- across the system. The table supports multiple job types including data archiving, index maintenance,
                    -- statistics gathering, and custom business processes. Each job definition includes parameters for
                    -- controlling execution behavior, retry logic, and resource allocation. The design accommodates
                    -- dependencies between jobs to ensure proper execution order for complex maintenance workflows.
                    -- Comprehensive tracking of job execution history enables performance analysis and troubleshooting of
                    -- maintenance operations. The table also supports dynamic adjustment of job schedules based on system
                    -- load and business priorities, optimizing resource utilization during maintenance windows. This
                    -- functionality is essential for maintaining system performance and reliability, particularly in
                    -- environments with large data volumes where maintenance operations can significantly impact
                    -- availability. The implementation includes safeguards against job overlap and resource contention to
                    -- prevent maintenance activities from interfering with operational workloads. By centralizing job
                    -- management, the system ensures consistent execution of critical maintenance tasks while providing
                    -- the flexibility needed for different operational requirements.
                    -- KPI: Job execution success rate, Maintenance window utilization,
                    --      System performance impact, Job completion time,
                    --      Error resolution time
                    -- Feature Reference: 1021, 1022, 1023, 1024, 1025
                    CREATE TABLE IF NOT EXISTS system.maintenance_jobs (
                        job_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                        job_name VARCHAR(100) NOT NULL UNIQUE,
                        job_type VARCHAR(50) NOT NULL CHECK (job_type IN ('DATA_ARCHIVE', 'INDEX_MAINTENANCE', 'STATISTICS_GATHERING',
                            'DATA_REFRESH', 'CUSTOM', 'VACUUM_ANALYZE', 'DATA_PURGE', 'BACKUP', 'VALIDATION')),
                        target_tables TEXT[],
                        description TEXT,
                        schedule_cron VARCHAR(50) NOT NULL,
                        estimated_duration_minutes INTEGER NOT NULL CHECK (estimated_duration_minutes >= 0),
                        max_duration_minutes INTEGER NOT NULL CHECK (max_duration_minutes >= estimated_duration_minutes),
                        last_run_start TIMESTAMP WITH TIME ZONE,
                        last_run_end TIMESTAMP WITH TIME ZONE,
                        last_run_duration_minutes INTEGER GENERATED ALWAYS AS (
                            CASE
                                WHEN last_run_start IS NOT NULL AND last_run_end IS NOT NULL
                                    THEN EXTRACT(EPOCH FROM (last_run_end - last_run_start)) / 60
                                ELSE NULL
                            END
                        ) STORED,
                        last_run_status VARCHAR(20) CHECK (last_run_status IN ('SUCCESS', 'FAILED', 'RUNNING', 'SKIPPED')),
                        last_run_message TEXT,
                        max_runtime INTERVAL DEFAULT INTERVAL '2 hours',
                        retry_count INTEGER DEFAULT 0,
                        max_retries INTEGER DEFAULT 3,
                        retry_interval INTERVAL DEFAULT INTERVAL '5 minutes',
                        is_active BOOLEAN NOT NULL DEFAULT TRUE,
                        parameters JSONB,
                        dependencies UUID[] DEFAULT '{}',
                        resource_group VARCHAR(50),
                        priority INTEGER DEFAULT 50 CHECK (priority BETWEEN 1 AND 100),
                        created_by UUID NOT NULL,
                        updated_by UUID,
                        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
                    );

                    -- Add indexes for performance
                    CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_schedule ON system.maintenance_jobs(schedule_cron);
                    CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_status ON system.maintenance_jobs(last_run_status);
                    CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_type ON system.maintenance_jobs(job_type);
                    CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_active ON system.maintenance_jobs(is_active) WHERE is_active = TRUE;
                    CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_dependencies ON system.maintenance_jobs USING GIN(dependencies);
                    CREATE INDEX IF NOT EXISTS idx_maintenance_jobs_parameters ON system.maintenance_jobs USING GIN(parameters);

                    -- Add triggers for audit columns
                    CREATE TRIGGER trg_maintenance_jobs_updated_at
                    BEFORE UPDATE ON system.maintenance_jobs
                    FOR EACH ROW
                    EXECUTE FUNCTION update_updated_at_column();

                    COMMENT ON TABLE system.maintenance_jobs IS 'Configuration and tracking of system maintenance operations.
                    Manages scheduling and execution of background maintenance tasks critical for system health. Provides centralized repository
                    for job definitions, schedules, and execution history. Supports multiple job types including data archiving and index maintenance.
                    Includes parameters for execution behavior, retry logic, and resource allocation. Accommodates dependencies between jobs.
                    Enables performance analysis and troubleshooting. Supports dynamic adjustment of schedules based on system load. Essential for
                    maintaining system performance with large data volumes. Includes safeguards against job overlap and resource contention.
                    Centralizes job management for consistent execution of critical tasks.';

                    -- Serial No: 202 | TABLE: system.task_results
                    -- Description: Storage and management of task execution results
                    -- Business Case: The task_results table captures detailed results of background task executions, providing
                    -- visibility into task performance and outcomes. It stores both metadata about task execution (duration,
                    -- status, resource usage) and the actual results data produced by the task. The table supports multiple
                    -- task types including data processing jobs, report generation, and system maintenance operations. Each
                    -- result record includes contextual information about the operational environment during execution to
                    -- support troubleshooting of performance issues. Historical task data is maintained to identify trends
                    -- in task performance and detect degradation over time. The implementation includes mechanisms for
                    -- result retention management, automatically archiving or purging older results based on configurable
                    -- policies. For critical tasks, the system tracks execution metrics against service level objectives to
                    -- ensure tasks complete within acceptable timeframes. The table also supports result comparison across
                    -- executions to identify unexpected changes in task outputs. By centralizing task results, the organization
                    -- can ensure consistent monitoring of background operations while providing the data needed for capacity
                    -- planning and performance tuning. The design accommodates both structured result data (via JSONB storage)
                    -- and binary outputs (for reports and other artifacts). The table is optimized for rapid querying during
                    -- incident response and performance analysis, with appropriate indexing on key task characteristics.
                    -- KPI: Task execution success rate, Average task duration,
                    --      Resource utilization per task, SLA compliance rate,
                    --      Task failure resolution time
                    -- Feature Reference: 1026, 1027, 1028, 1029, 1030
                    CREATE TABLE IF NOT EXISTS system.task_results (
                        result_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                        task_id UUID NOT NULL,
                        task_name VARCHAR(100) NOT NULL,
                        execution_id UUID NOT NULL,
                        start_time TIMESTAMP WITH TIME ZONE NOT NULL,
                        end_time TIMESTAMP WITH TIME ZONE NOT NULL,
                        duration_ms INTEGER NOT NULL CHECK (duration_ms >= 0),
                        status VARCHAR(20) NOT NULL CHECK (status IN ('SUCCESS', 'FAILED', 'RUNNING', 'CANCELLED')),
                        error_message TEXT,
                        result_summary JSONB,
                        result_data BYTEA,
                        result_size_kb INTEGER CHECK (result_size_kb >= 0),
                        cpu_usage NUMERIC(5,2),
                        memory_usage_mb INTEGER,
                        rows_processed BIGINT,
                        rows_affected BIGINT,
                        error_category VARCHAR(50),
                        affected_records_count INTEGER,
                        server_hostname VARCHAR(100),
                        retention_days INTEGER NOT NULL DEFAULT 90 CHECK (retention_days >= 0),
                        expiration_date DATE GENERATED ALWAYS AS (DATE(start_time) + retention_days) STORED,
                        is_archived BOOLEAN NOT NULL DEFAULT FALSE,
                        security_level VARCHAR(20) NOT NULL DEFAULT 'INTERNAL'
                            CHECK (security_level IN ('PUBLIC', 'INTERNAL', 'CONFIDENTIAL', 'RESTRICTED')),
                        watermark_text TEXT,
                        version INTEGER NOT NULL DEFAULT 1,
                        metadata JSONB DEFAULT '{}'::JSONB,
                        created_by UUID NOT NULL,
                        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
                        updated_by UUID,
                        updated_at TIMESTAMP WITH TIME ZONE
                    );

                    -- Add indexes for performance
                    CREATE INDEX IF NOT EXISTS idx_task_results_task ON system.task_results(task_id);
                    CREATE INDEX IF NOT EXISTS idx_task_results_name ON system.task_results(task_name);
                    CREATE INDEX IF NOT EXISTS idx_task_results_time ON system.task_results(start_time DESC, end_time DESC);
