                        user_id UUID,
                        session_id UUID,
                        request_id UUID,
                        client_ip INET,
                        client_user_agent TEXT,
                        business_process VARCHAR(100),
                        business_entity_type VARCHAR(100),
                        business_entity_id UUID,
                        -- Timing and Frequency
                        occurred_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        occurrence_count INTEGER NOT NULL DEFAULT 1,
                        first_occurred_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        last_occurred_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        -- Resolution Information
                        resolved_at TIMESTAMP WITH TIME ZONE,
                        resolved_by UUID REFERENCES hr.employees(employee_id),
                        resolution_notes TEXT,
                        resolution_steps JSONB,
                        is_resolved BOOLEAN NOT NULL DEFAULT FALSE,
