                    CREATE INDEX IF NOT EXISTS idx_error_logs_time ON system.error_logs(occurred_at DESC);
                    CREATE INDEX IF NOT EXISTS idx_error_logs_user ON system.error_logs(user_id) WHERE user_id IS NOT NULL;
                    CREATE INDEX IF NOT EXISTS idx_error_logs_session ON system.error_logs(session_id) WHERE session_id IS NOT NULL;
                    CREATE INDEX IF NOT EXISTS idx_error_logs_entity ON system.error_logs(business_entity_type, business_entity_id)
