                    CREATE INDEX IF NOT EXISTS idx_error_logs_unresolved ON system.error_logs(is_resolved) WHERE is_resolved = FALSE;
                    CREATE INDEX IF NOT EXISTS idx_error_logs_details ON system.error_logs USING GIN(error_details);
