                    -- Serial No: 206 | TABLE: system.export_jobs
                    -- Description: Tracking of data export requests and results
                    -- Business Case: The export_jobs table manages all data export requests initiated by users or
                    -- system processes, providing visibility into export activity and results. It captures detailed
                    -- information about each export including requested format, filters, and security classification
                    -- to support compliance with data handling policies. The table supports multiple export types
                    -- including user-initiated exports, scheduled reports, and API-driven exports, accommodating
                    -- different business needs. Each export record includes metadata about the data sensitivity,
                    -- retention requirements, and delivery method to ensure proper handling of exported data. The
                    -- implementation includes robust tracking of export status, completion time, and download
                    -- statistics to support audit requirements and measure performance. Historical export data is
                    -- maintained to identify patterns in export behavior and measure the impact of security policies
                    -- over time. For compliance purposes, the system tracks access to exported data and enforces
                    -- appropriate retention policies. The table integrates with the data classification system to
                    -- enable automatic application of security controls based on the sensitivity of exported data.
                    -- The design accommodates complex export scenarios with large data volumes and multiple
                    -- delivery channels, providing detailed insights into data export practices. By centralizing
                    -- export tracking, the organization can ensure consistent application of data security practices
                    -- while providing the detailed evidence needed for compliance audits. The table is optimized
                    -- for rapid querying during security investigations, which is critical for timely identification
                    -- of potential data exposure incidents.
                    -- KPI: Export compliance rate, Export completion time,
                    --      Data exposure incidents, Export request approval rate,
                    --      Compliance audit success rate
                    -- Feature Reference: 1046, 1047, 1048, 1049, 1050
                    CREATE TABLE IF NOT EXISTS system.export_jobs (
                        export_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                        request_id UUID NOT NULL,
                        user_id UUID NOT NULL REFERENCES hr.employees(employee_id),
                        export_type VARCHAR(50) NOT NULL CHECK (export_type IN ('USER_REQUEST', 'SCHEDULED_REPORT', 'API_EXPORT', 'AUDIT_EXPORT')),
                        export_format VARCHAR(50) NOT NULL CHECK (export_format IN ('CSV', 'XLSX', 'PDF', 'JSON', 'XML')),
                        data_classification VARCHAR(50) NOT NULL CHECK (data_classification IN ('PUBLIC', 'INTERNAL', 'CONFIDENTIAL', 'RESTRICTED', 'HIGHLY_RESTRICTED')),
                        requested_filters JSONB NOT NULL,
                        requested_columns TEXT[],
                        record_count INTEGER NOT NULL CHECK (record_count >= 0),
                        file_size_bytes BIGINT NOT NULL CHECK (file_size_bytes >= 0),
                        file_path TEXT,
                        status VARCHAR(20) NOT NULL DEFAULT 'REQUESTED'
                            CHECK (status IN ('REQUESTED', 'PROCESSING', 'COMPLETED', 'FAILED', 'CANCELLED', 'EXPIRED')),
                        requested_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        started_at TIMESTAMP WITH TIME ZONE,
                        completed_at TIMESTAMP WITH TIME ZONE,
                        duration_ms INTEGER GENERATED ALWAYS AS (
                            CASE
                                WHEN completed_at IS NOT NULL AND started_at IS NOT NULL
                                    THEN EXTRACT(EPOCH FROM (completed_at - started_at)) * 1000
                                ELSE NULL
                            END
                        ) STORED,
                        download_count INTEGER NOT NULL DEFAULT 0,
                        last_downloaded_at TIMESTAMP WITH TIME ZONE,
                        expiry_time TIMESTAMP WITH TIME ZONE,
                        access_token UUID,
                        download_token UUID,
                        is_encrypted BOOLEAN NOT NULL DEFAULT TRUE,
                        encryption_method VARCHAR(50),
                        retention_days INTEGER NOT NULL DEFAULT 7,
                        created_by UUID NOT NULL,
                        updated_by UUID,
                        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        metadata JSONB
                    );

                    


                    COMMENT ON TABLE system.export_jobs IS 'Tracking of data export requests and results.
