                        target_value NUMERIC(15,6),
                        warning_threshold NUMERIC(15,6),
                        failure_threshold NUMERIC(15,6),
                        calculation_method VARCHAR(100) NOT NULL DEFAULT 'DIRECT_MEASUREMENT'
                            CHECK (calculation_method IN ('DIRECT_MEASUREMENT', 'AVERAGE', 'PEAK', 'PERCENTILE', 'COUNT')),
                        related_transaction_id UUID,
                        related_error_code VARCHAR(50),
                        context JSONB,
                        created_by UUID NOT NULL,
                        updated_by UUID,
                        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
                    );

                    -- Add indexes for performance
                    CREATE INDEX IF NOT EXISTS idx_system_health_metrics_type ON system.system_health_metrics(metric_type);
                    CREATE INDEX IF NOT EXISTS idx_system_health_metrics_component ON system.system_health_metrics(component_name);
                    CREATE INDEX IF NOT EXISTS idx_system_health_metrics_environment ON system.system_health_metrics(environment);
                    CREATE INDEX IF NOT EXISTS idx_system_health_metrics_time ON system.system_health_metrics(collection_time DESC);
                    CREATE INDEX IF NOT EXISTS idx_system_health_metrics_interval ON system.system_health_metrics(collection_interval);
                    CREATE INDEX IF NOT EXISTS idx_system_health_metrics_transaction ON system.system_health_metrics(related_transaction_id)
                        WHERE related_transaction_id IS NOT NULL;
                    CREATE INDEX IF NOT EXISTS idx_system_health_metrics_error ON system.system_health_metrics(related_error_code)
                        WHERE related_error_code IS NOT NULL;
                    CREATE INDEX IF NOT EXISTS idx_system_health_metrics_context ON system.system_health_metrics USING GIN(context);

                    -- Add triggers for audit columns
                    CREATE TRIGGER trg_system_health_metrics_updated_at
                    BEFORE UPDATE ON system.system_health_metrics
                    FOR EACH ROW
                    EXECUTE FUNCTION update_updated_at_column();

                    COMMENT ON TABLE system.system_health_metrics IS 'Historical system performance and health metrics.
                    Stores historical performance metrics for monitoring system health. Captures key indicators such as response times and error
                    rates. Critical for identifying performance bottlenecks before they impact users. Supports multiple metric types including
                    database and application server metrics. Historical data versioned to track changes over time. Includes metadata about collection
                    method and environment. Includes mechanisms for automated metric collection. Stores variance calculations for metrics with
                    defined targets. Used to establish baselines and detect anomalies. Centralizes system health metrics for comprehensive monitoring.
                    Optimized for time-series analysis of performance metrics.';

                    -- Serial No: 209 | MATERIALIZED VIEW: system.mv_system_health_dashboard
                    -- Purpose: Real-time system health monitoring dashboard with key metrics
                    -- Business Case: This materialized view provides a real-time snapshot of system health across the
                    -- organization, serving as the foundation for system monitoring dashboards. It aggregates key
                    -- performance metrics including response times, error rates, and resource utilization to provide
                    -- a comprehensive view of system health. The view includes comparison against targets and
                    -- thresholds to highlight areas requiring attention. It supports multiple time granularities
                    -- (minute, hour, day) to accommodate different analysis needs. Historical trend data is presented
                    -- with appropriate statistical analysis to distinguish meaningful patterns from random fluctuations.
                    -- The materialized structure enables rapid query performance for monitoring that would be too slow
                    -- on operational tables. The view also includes benchmark comparisons against historical performance
                    -- to provide context for current metrics. It serves as the foundation for system health scorecards
                    -- that track progress against service level objectives. The implementation includes anomaly
                    -- detection logic to automatically identify unusual patterns in performance metrics that may
                    -- indicate underlying system issues. By pre-computing these metrics, the view enables sophisticated
                    -- system health analytics to be performed in real-time, supporting proactive system management. The
                    -- refresh process is optimized to minimize impact on operational systems while ensuring health data
                    -- remains sufficiently current for decision making. The view is designed with robust security
                    -- controls to protect sensitive system metrics while ensuring appropriate access for stakeholders.
                    -- KPI: System health trend direction, SLA compliance rate,
                    --      Anomaly detection rate, System performance improvement rate,
                    --      Trend analysis performance
                    -- Feature Reference: 1061, 1062, 1063, 1064, 1065
                    CREATE MATERIALIZED VIEW IF NOT EXISTS system.mv_system_health_dashboard AS
                    SELECT
                        component_name,
                        environment,
                        instance_id,
                        metric_type,
                        DATE_TRUNC('hour', collection_time) AS hour_bucket,
                        AVG(metric_value) AS avg_metric_value,
                        MIN(metric_value) AS min_metric_value,
                        MAX(metric_value) AS max_metric_value,
                        PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY metric_value) AS median_metric_value,
                        COUNT(*) AS sample_count,
                        BOOL_AND(metric_value <= COALESCE(warning_threshold, metric_value)) AS meets_warning_threshold,
                        BOOL_AND(metric_value <= COALESCE(failure_threshold, metric_value)) AS meets_failure_threshold,
                        target_value,
                        warning_threshold,
                        failure_threshold,
                        (SELECT AVG(metric_value)
                         FROM system.system_health_metrics m2
                         WHERE m2.component_name = m1.component_name
                         AND m2.environment = m1.environment
                         AND m2.metric_type = m1.metric_type
                         AND collection_time >= CURRENT_TIMESTAMP - INTERVAL '24 hours'
                         AND collection_time < CURRENT_TIMESTAMP - INTERVAL '1 hour') AS previous_hour_avg,
                        CASE
                            WHEN (SELECT AVG(metric_value)
                                  FROM system.system_health_metrics m2
                                  WHERE m2.component_name = m1.component_name
                                  AND m2.environment = m1.environment
                                  AND m2.metric_type = m1.metric_type
                                  AND collection_time >= CURRENT_TIMESTAMP - INTERVAL '24 hours'
                                  AND collection_time < CURRENT_TIMESTAMP - INTERVAL '1 hour') > 0
                                THEN (AVG(metric_value) - (SELECT AVG(metric_value)
                                                          FROM system.system_health_metrics m2
                                                          WHERE m2.component_name = m1.component_name
                                                          AND m2.environment = m1.environment
                                                          AND m2.metric_type = m1.metric_type
                                                          AND collection_time >= CURRENT_TIMESTAMP - INTERVAL '24 hours'
                                                          AND collection_time < CURRENT_TIMESTAMP - INTERVAL '1 hour'))
                                     / (SELECT AVG(metric_value)
                                        FROM system.system_health_metrics m2
                                        WHERE m2.component_name = m1.component_name
                                        AND m2.environment = m1.environment
                                        AND m2.metric_type = m1.metric_type
                                        AND collection_time >= CURRENT_TIMESTAMP - INTERVAL '24 hours'
                                        AND collection_time < CURRENT_TIMESTAMP - INTERVAL '1 hour') * 100
                            ELSE NULL
                        END AS hour_over_hour_change
                    FROM system.system_health_metrics m1
                    WHERE collection_time >= CURRENT_TIMESTAMP - INTERVAL '7 days'
                    GROUP BY
                        component_name, environment, instance_id, metric_type,
                        DATE_TRUNC('hour', collection_time),
                        target_value, warning_threshold, failure_threshold;

                    -- Create indexes on the materialized view
                    CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_full ON system.mv_system_health_dashboard
                        (component_name, environment, instance_id, metric_type, hour_bucket);
                    CREATE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_component ON system.mv_system_health_dashboard (component_name);
                    CREATE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_environment ON system.mv_system_health_dashboard (environment);
                    CREATE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_type ON system.mv_system_health_dashboard (metric_type);
                    CREATE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_hour ON system.mv_system_health_dashboard (hour_bucket);
                    CREATE INDEX IF NOT EXISTS idx_mv_system_health_dashboard_trend ON system.mv_system_health_dashboard
                        (avg_metric_value, hour_bucket);

                    COMMENT ON MATERIALIZED VIEW system.mv_system_health_dashboard IS 'Real-time system health monitoring dashboard with key metrics.
                    Provides real-time snapshot of system health across the organization. Aggregates key performance metrics including response times
                    and error rates. Includes comparison against targets and thresholds. Supports multiple time granularities for analysis. Historical
                    trend data presented with statistical analysis. Enables rapid query performance for monitoring. Includes benchmark comparisons
                    for context. Serves as foundation for system health scorecards. Includes anomaly detection logic. Enables sophisticated system
                    health analytics in real-time. Refresh process optimized to minimize impact on operational systems. Designed with robust security
                    controls for sensitive system metrics.';

                    -- Serial No: 210 | TABLE: system.export_templates
                    -- Description: Configuration of export templates for common data exports
                    -- Business Case: The export_templates table stores configuration details for export templates
                    -- used across the workforce scheduling system, enabling consistent data export practices. It
                    -- captures the complete definition of export specifications including data sources, filters,
                    -- formatting rules, and security requirements to ensure consistent export behavior. The table
                    -- supports multiple template types including standard reports, custom exports, and compliance
                    -- exports, accommodating different business needs. Each template record includes metadata about
                    -- its purpose, security classification, and usage patterns to support effective template design.
                    -- The implementation includes versioning of templates to track changes over time while
                    -- maintaining historical export configurations. Historical template data is maintained to
                    -- support audit requirements and track changes to export standards over time. For operational
                    -- efficiency, the system tracks template usage metrics to enable identification of unused or
                    -- redundant templates. The table integrates with the data classification system to ensure
                    -- appropriate security controls are applied to exported data. The design accommodates complex
                    -- export structures with hierarchical relationships between template components, providing
                    -- detailed insights into export configuration. By centralizing export template management, the
                    -- organization can ensure consistent application of export practices while providing the
                    -- flexibility needed for different business contexts. The table is optimized for rapid querying
                    -- during export configuration and execution, which is critical for timely delivery of export
                    -- requests.
                    -- KPI: Template coverage completeness, Export consistency rate,
                    --      Template utilization rate, Export configuration efficiency,
                    --      Export management effectiveness
                    -- Feature Reference: 1066, 1067, 1068, 1069, 1070
                    CREATE TABLE IF NOT EXISTS system.export_templates (
                        template_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                        template_code VARCHAR(50) UNIQUE NOT NULL CHECK (template_code ~ '^[A-Z0-9_]{3,50}$'),
                        name VARCHAR(100) NOT NULL,
                        description TEXT,
                        template_type VARCHAR(50) NOT NULL CHECK (template_type IN ('STANDARD_REPORT', 'CUSTOM_EXPORT', 'COMPLIANCE_EXPORT', 'AUDIT_EXPORT', 'SCHEDULED_REPORT')),
                        data_source VARCHAR(100) NOT NULL,
                        filters JSONB NOT NULL,
                        columns JSONB NOT NULL,
                        sort_order JSONB,
                        formatting_rules JSONB,
                        export_format VARCHAR(50) NOT NULL CHECK (export_format IN ('CSV', 'XLSX', 'PDF', 'JSON', 'XML')),
                        data_classification VARCHAR(50) NOT NULL CHECK (data_classification IN ('PUBLIC', 'INTERNAL', 'CONFIDENTIAL', 'RESTRICTED', 'HIGHLY_RESTRICTED')),
                        security_requirements JSONB,
                        is_active BOOLEAN NOT NULL DEFAULT TRUE,
                        is_system_template BOOLEAN NOT NULL DEFAULT FALSE,
                        version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                        approval_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
                            CHECK (approval_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'REJECTED', 'RETIRED')),
                        approved_by UUID REFERENCES hr.employees(employee_id),
                        approved_at TIMESTAMP WITH TIME ZONE,
                        created_by UUID NOT NULL,
                        updated_by UUID,
                        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        metadata JSONB
                    );

                    -- Add indexes for performance
                    CREATE INDEX IF NOT EXISTS idx_export_templates_type ON system.export_templates(template_type);
                    CREATE INDEX IF NOT EXISTS idx_export_templates_active ON system.export_templates(is_active) WHERE is_active = TRUE;
                    CREATE INDEX IF NOT EXISTS idx_export_templates_system ON system.export_templates(is_system_template)
                        WHERE is_system_template = TRUE;
                    CREATE INDEX IF NOT EXISTS idx_export_templates_classification ON system.export_templates(data_classification);
                    CREATE INDEX IF NOT EXISTS idx_export_templates_status ON system.export_templates(approval_status);
                    CREATE INDEX IF NOT EXISTS idx_export_templates_version ON system.export_templates(template_id, version_number DESC);
                    CREATE INDEX IF NOT EXISTS idx_export_templates_approved ON system.export_templates(approved_by)
                        WHERE approved_by IS NOT NULL;
                    CREATE INDEX IF NOT EXISTS idx_export_templates_filters ON system.export_templates USING GIN(filters);
                    CREATE INDEX IF NOT EXISTS idx_export_templates_columns ON system.export_templates USING GIN(columns);
                    CREATE INDEX IF NOT EXISTS idx_export_templates_metadata ON system.export_templates USING GIN(metadata);

                    -- Add triggers for audit columns
                    CREATE TRIGGER trg_export_templates_updated_at
                    BEFORE UPDATE ON system.export_templates
                    FOR EACH ROW
                    EXECUTE FUNCTION update_updated_at_column();

                    COMMENT ON TABLE system.export_templates IS 'Configuration of export templates for common data exports.
                    Stores configuration details for export templates used across the system. Captures complete definition of export specifications.
                    Supports multiple template types including standard reports and compliance exports. Includes metadata about purpose and security
                    classification. Includes versioning to track changes over time. Historical data maintained for audit requirements. Tracks usage
                    metrics for identification of unused templates. Integrates with data classification system for security controls. Accommodates
                    complex export structures with hierarchical relationships. Centralizes export template management for consistent practices.
                    Optimized for rapid querying during export configuration and execution.';



-- Serial No: 211 | TABLE: system.export_schedules
-- Description: Configuration of scheduled export jobs
-- Business Case: The export_schedules table manages the scheduling of recurring export jobs,
-- providing visibility into scheduled data delivery processes. It captures detailed information
-- about each scheduled export including timing, recipients, and delivery methods to support
-- consistent data distribution practices. The table supports multiple schedule types including
-- daily, weekly, and custom interval schedules, accommodating different business requirements.
-- Each schedule record includes metadata about the export template, data sensitivity, and
-- retention requirements to ensure proper handling of exported data. The implementation includes
-- robust tracking of schedule execution history to identify failures and measure reliability.
-- Historical schedule data is maintained to support audit requirements and track changes to
-- scheduled exports over time. For compliance purposes, the system tracks approval workflows
-- for sensitive scheduled exports to document the rationale and authorization for data
-- distribution. The table integrates with the notification system to enable automated delivery
-- of exported data through multiple channels including email and secure file transfer. The
-- design accommodates complex scheduling scenarios with dependencies between scheduled exports
-- and conditional delivery rules, providing detailed insights into data distribution practices.
-- By centralizing schedule management, the organization can ensure consistent delivery of data
-- while providing the detailed evidence needed for compliance audits. The table is optimized
-- for rapid querying during schedule management, which is critical for timely adjustments to
-- scheduled data distribution processes.
-- KPI: Schedule reliability rate, Data delivery timeliness,
--      Schedule coverage completeness, Delivery method compliance rate,
--      Audit success rate
-- Feature Reference: 1071, 1072, 1073, 1074, 1075
CREATE TABLE IF NOT EXISTS system.export_schedules (
    schedule_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    schedule_name VARCHAR(100) NOT NULL,
    description TEXT,
    schedule_type VARCHAR(50) NOT NULL CHECK (schedule_type IN ('DAILY', 'WEEKLY', 'MONTHLY', 'CUSTOM_INTERVAL', 'EVENT_BASED')),
    schedule_cron VARCHAR(50),
    schedule_expression JSONB,
    timezone VARCHAR(50) NOT NULL DEFAULT 'UTC',
    start_date DATE NOT NULL DEFAULT CURRENT_DATE,
    end_date DATE,
    next_run_time TIMESTAMP WITH TIME ZONE, -- Removed GENERATED, will be managed by application/job scheduler
    export_template_id UUID NOT NULL REFERENCES system.export_templates(template_id),
    delivery_methods VARCHAR(50)[] NOT NULL DEFAULT '{"EMAIL"}'
        CHECK (array_length(delivery_methods, 1) > 0),
    recipients JSONB NOT NULL,
    delivery_options JSONB,
    data_retention_days INTEGER NOT NULL DEFAULT 7 CHECK (data_retention_days >= 0),
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_encrypted BOOLEAN NOT NULL DEFAULT TRUE,
    last_run_time TIMESTAMP WITH TIME ZONE,
    last_run_status VARCHAR(20) CHECK (last_run_status IN ('SUCCESS', 'FAILED', 'SKIPPED')),
    last_run_message TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_export_schedules_type ON system.export_schedules(schedule_type);
CREATE INDEX IF NOT EXISTS idx_export_schedules_active ON system.export_schedules(is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_export_schedules_template ON system.export_schedules(export_template_id);
CREATE INDEX IF NOT EXISTS idx_export_schedules_next_run ON system.export_schedules(next_run_time);
CREATE INDEX IF NOT EXISTS idx_export_schedules_last_run ON system.export_schedules(last_run_time DESC);
CREATE INDEX IF NOT EXISTS idx_export_schedules_status ON system.export_schedules(last_run_status);
CREATE INDEX IF NOT EXISTS idx_export_schedules_recipients ON system.export_schedules USING GIN(recipients);
CREATE INDEX IF NOT EXISTS idx_export_schedules_metadata ON system.export_schedules USING GIN(metadata);

-- Add triggers for audit columns
CREATE TRIGGER trg_export_schedules_updated_at
BEFORE UPDATE ON system.export_schedules
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE system.export_schedules IS 'Configuration of scheduled export jobs.
Manages scheduling of recurring export jobs. Captures detailed information about each scheduled export.
Supports multiple schedule types including daily and weekly schedules. Includes metadata about export template and data sensitivity.
Tracks schedule execution history for reliability measurement. Historical data maintained for audit requirements.
Tracks approval workflows for sensitive exports. Integrates with notification system for automated delivery.
Accommodates complex scheduling scenarios with dependencies. Centralizes schedule management for consistent data delivery.
Optimized for rapid querying during schedule management.';




                    -- Serial No: 212 | TABLE: system.export_delivery_logs
                    -- Description: Tracking of export delivery attempts and results
                    -- Business Case: The export_delivery_logs table maintains a comprehensive record of all export
                    -- delivery attempts, providing visibility into the reliability and security of data distribution
                    -- processes. It captures detailed information about each delivery attempt including request
                    -- payload, response, and timing metrics to support troubleshooting of delivery issues. This
                    -- information is critical for diagnosing delivery failures, optimizing delivery performance,
                    -- and ensuring reliable data distribution. The table supports multiple delivery statuses
                    -- including success, failure, and pending states, accommodating different delivery scenarios.
                    -- Each delivery record includes metadata about the export job, delivery method, and retry
                    -- context to enable accurate assessment of delivery outcomes. Historical delivery data is
                    -- maintained to identify patterns in delivery success and measure the impact of configuration
                    -- changes over time. For operational efficiency, the system tracks retry attempts to avoid
                    -- redundant processing and enable targeted troubleshooting. The table integrates with the
                    -- delivery system to enable real-time monitoring of delivery status and automated retry
                    -- processing. The design accommodates complex delivery scenarios with multiple delivery
                    -- channels and varying response patterns, providing detailed insights into delivery behavior.
                    -- By centralizing delivery tracking, the organization can ensure consistent evaluation of
                    -- delivery performance while providing the data needed for delivery improvement. The table is
                    -- optimized for rapid querying during incident response, which often involves identifying
                    -- delivery issues across multiple export jobs and time periods.
                    -- KPI: Delivery success rate, Average delivery latency,
                    --      Retry success rate, Delivery error resolution time,
                    --      Delivery failure root cause identification rate
                    -- Feature Reference: 1076, 1077, 1078, 1079, 1080
                    CREATE TABLE IF NOT EXISTS system.export_delivery_logs (
                        delivery_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                        export_id UUID NOT NULL REFERENCES system.export_jobs(export_id) ON DELETE CASCADE,
                        schedule_id UUID REFERENCES system.export_schedules(schedule_id) ON DELETE SET NULL,
                        delivery_method VARCHAR(50) NOT NULL CHECK (delivery_method IN ('EMAIL', 'SFTP', 'API', 'SHAREPOINT', 'SECURE_PORTAL')),
                        attempt_number INTEGER NOT NULL DEFAULT 1 CHECK (attempt_number >= 1),
                        request_timestamp TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        response_timestamp TIMESTAMP WITH TIME ZONE,
                        duration_ms INTEGER GENERATED ALWAYS AS (
                            CASE
                                WHEN response_timestamp IS NOT NULL
                                    THEN EXTRACT(EPOCH FROM (response_timestamp - request_timestamp)) * 1000
                                ELSE NULL
                            END
                        ) STORED,
                        status VARCHAR(20) NOT NULL CHECK (status IN ('SUCCESS', 'FAILED', 'PENDING')),
                        http_status_code INTEGER,
                        response_payload TEXT,
                        error_message TEXT,
                        retry_context JSONB,
                        delivery_details JSONB,
                        created_by UUID NOT NULL,
                        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        updated_by UUID,
                        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        metadata JSONB
                    );

                    -- Add indexes for performance
                    CREATE INDEX IF NOT EXISTS idx_export_delivery_logs_export ON system.export_delivery_logs(export_id);
                    CREATE INDEX IF NOT EXISTS idx_export_delivery_logs_schedule ON system.export_delivery_logs(schedule_id)
                        WHERE schedule_id IS NOT NULL;
                    CREATE INDEX IF NOT EXISTS idx_export_delivery_logs_method ON system.export_delivery_logs(delivery_method);
                    CREATE INDEX IF NOT EXISTS idx_export_delivery_logs_status ON system.export_delivery_logs(status);
                    CREATE INDEX IF NOT EXISTS idx_export_delivery_logs_timestamp ON system.export_delivery_logs(request_timestamp DESC);
                    CREATE INDEX IF NOT EXISTS idx_export_delivery_logs_duration ON system.export_delivery_logs(duration_ms);
                    CREATE INDEX IF NOT EXISTS idx_export_delivery_logs_http_status ON system.export_delivery_logs(http_status_code);
                    CREATE INDEX IF NOT EXISTS idx_export_delivery_logs_metadata ON system.export_delivery_logs USING GIN(metadata);

                    -- Add triggers for audit columns
                    CREATE TRIGGER trg_export_delivery_logs_updated_at
                    BEFORE UPDATE ON system.export_delivery_logs
                    FOR EACH ROW
                    EXECUTE FUNCTION update_updated_at_column();

                    COMMENT ON TABLE system.export_delivery_logs IS 'Tracking of export delivery attempts and results.
                    Maintains comprehensive record of all export delivery attempts. Captures detailed information about each delivery attempt.
                    Critical for diagnosing delivery failures and optimizing delivery performance. Supports multiple delivery statuses. Includes
                    metadata about delivery method and retry context. Historical delivery data maintained to identify patterns. Tracks retry
                    attempts for targeted troubleshooting. Integrates with delivery system for real-time monitoring. Accommodates complex delivery
                    scenarios with multiple channels. Centralizes delivery tracking for consistent evaluation. Optimized for rapid querying during
                    incident response.';

                    -- Serial No: 213 | TABLE: system.data_retention_policies
