                        compliance_standards VARCHAR(100)[],
                        approval_status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
                            CHECK (approval_status IN ('PENDING', 'APPROVED', 'REJECTED')),
                        approved_by UUID REFERENCES hr.employees(employee_id),
                        approved_at TIMESTAMP WITH TIME ZONE,
                        created_by UUID NOT NULL,
                        updated_by UUID,
                        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        metadata JSONB
                    );

                  
                    COMMENT ON TABLE system.data_retention_policies IS 'Configuration of data retention policies by data type and sensitivity.
                    Stores configuration details for data retention policies across the organization. Captures retention periods and deletion
                    procedures for different data types. Supports multiple retention categories including regulatory requirements. Includes metadata
                    about effective dates and jurisdiction. Includes validation rules to ensure compliance with regulatory requirements. Historical
                    policy data maintained for audit requirements. Stores policy execution metrics for monitoring compliance. Integrates with data
                    classification system for automated application. Accommodates complex retention scenarios with jurisdiction-specific rules.
                    Centralizes retention policy management for consistent application. Optimized for rapid querying during compliance audits.';

                    -- Serial No: 214 | TABLE: system.data_retention_enforcement
                    -- Description: Tracking of data retention policy execution and compliance
                    -- Business Case: The data_retention_enforcement table maintains a comprehensive record of all data
                    -- retention policy executions, providing visibility into compliance with data lifecycle management
                    -- requirements. It captures detailed information about each retention action including data affected,
                    -- execution timing, and verification results to support audit requirements. This information is
                    -- critical for demonstrating compliance with regulatory requirements and internal data governance
                    -- policies. The table supports multiple enforcement actions including data archival, anonymization,
                    -- and permanent deletion, accommodating different retention policy requirements. Each enforcement
                    -- record includes metadata about the policy applied, execution context, and verification status to
                    -- enable accurate assessment of compliance outcomes. Historical enforcement data is maintained to
                    -- identify patterns in execution success and measure the impact of policy changes over time. For
                    -- operational efficiency, the system tracks resource utilization during enforcement actions to
