                    -- KPI: Retention execution success rate, Policy compliance rate,
                    --      Enforcement time, Audit success rate,
                    --      Data volume reduction rate
                    -- Feature Reference: 1086, 1087, 1088, 1089, 1090
                    CREATE TABLE IF NOT EXISTS system.data_retention_enforcement (
                        enforcement_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                        policy_id UUID NOT NULL REFERENCES system.data_retention_policies(policy_id),
                        enforcement_type VARCHAR(50) NOT NULL CHECK (enforcement_type IN ('ARCHIVE', 'ANONYMIZE', 'DELETE', 'VERIFY')),
                        enforcement_started_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        enforcement_completed_at TIMESTAMP WITH TIME ZONE,
                        duration_ms INTEGER GENERATED ALWAYS AS (
                            CASE
                                WHEN enforcement_completed_at IS NOT NULL
                                    THEN EXTRACT(EPOCH FROM (enforcement_completed_at - enforcement_started_at)) * 1000
                                ELSE NULL
                            END
                        ) STORED,
                        status VARCHAR(20) NOT NULL CHECK (status IN ('PENDING', 'IN_PROGRESS', 'COMPLETED', 'FAILED')),
                        error_message TEXT,
                        data_category VARCHAR(50) NOT NULL,
                        data_sensitivity VARCHAR(50) NOT NULL,
                        jurisdiction VARCHAR(100),
                        country_code VARCHAR(10),
                        records_processed BIGINT NOT NULL DEFAULT 0 CHECK (records_processed >= 0),
                        records_affected BIGINT NOT NULL DEFAULT 0 CHECK (records_affected >= 0),
                        storage_reclaimed_mb NUMERIC(15,2) DEFAULT 0.00 CHECK (storage_reclaimed_mb >= 0.00),
                        verification_results JSONB,
                        created_by UUID NOT NULL,
                        created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        updated_by UUID,
                        updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                        metadata JSONB
                    );

                    
                    COMMENT ON TABLE system.data_retention_enforcement IS 'Tracking of data retention policy execution and compliance.
                    Maintains comprehensive record of all data retention policy executions. Captures detailed information about each retention
