                            user_id UUID NOT NULL REFERENCES hr.employees(employee_id),
                            import_type VARCHAR(50) NOT NULL CHECK (import_type IN ('USER_REQUEST', 'SCHEDULED_IMPORT', 'API_IMPORT', 'AUDIT_IMPORT')),
                            import_format VARCHAR(50) NOT NULL CHECK (import_format IN ('CSV', 'XLSX', 'JSON', 'XML', 'FIXED_WIDTH')),
                            data_classification VARCHAR(50) NOT NULL CHECK (data_classification IN ('PUBLIC', 'INTERNAL', 'CONFIDENTIAL', 'RESTRICTED', 'HIGHLY_RESTRICTED')),
                            source_location VARCHAR(500) NOT NULL,
                            file_path TEXT,
                            file_size_bytes BIGINT NOT NULL CHECK (file_size_bytes >= 0),
                            record_count INTEGER NOT NULL CHECK (record_count >= 0),
                            validation_status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
                                CHECK (validation_status IN ('PENDING', 'VALIDATING', 'VALID', 'INVALID')),
                            validation_errors JSONB,
                            processing_status VARCHAR(20) NOT NULL DEFAULT 'REQUESTED'
                                CHECK (processing_status IN ('REQUESTED', 'PROCESSING', 'COMPLETED', 'FAILED', 'CANCELLED')),
                            requested_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            started_at TIMESTAMP WITH TIME ZONE,
                            completed_at TIMESTAMP WITH TIME ZONE,
                            duration_ms INTEGER GENERATED ALWAYS AS (
                                CASE
                                    WHEN completed_at IS NOT NULL AND started_at IS NOT NULL
                                        THEN EXTRACT(EPOCH FROM (completed_at - started_at)) * 1000
                                    ELSE NULL
                                END
                            ) STORED,
                            records_imported INTEGER NOT NULL DEFAULT 0,
                            records_rejected INTEGER NOT NULL DEFAULT 0,
                            rejection_details JSONB,
                            is_encrypted BOOLEAN NOT NULL DEFAULT TRUE,
                            encryption_method VARCHAR(50),
                            created_by UUID NOT NULL,
