                        CREATE INDEX IF NOT EXISTS idx_import_jobs_format ON system.import_jobs(import_format);
                        CREATE INDEX IF NOT EXISTS idx_import_jobs_classification ON system.import_jobs(data_classification);
                        CREATE INDEX IF NOT EXISTS idx_import_jobs_validation ON system.import_jobs(validation_status);
                        CREATE INDEX IF NOT EXISTS idx_import_jobs_processing ON system.import_jobs(processing_status);
                        CREATE INDEX IF NOT EXISTS idx_import_jobs_requested ON system.import_jobs(requested_at DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_jobs_completed ON system.import_jobs(completed_at DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_jobs_errors ON system.import_jobs(validation_errors)
                            WHERE validation_errors IS NOT NULL;
                        CREATE INDEX IF NOT EXISTS idx_import_jobs_metadata ON system.import_jobs USING GIN(metadata);

                        -- Add triggers for audit columns
