-- Serial No: 218 | TABLE: system.import_schedules
-- Description: Configuration of scheduled import jobs
-- Business Case: The import_schedules table manages the scheduling of recurring import jobs,
-- providing visibility into scheduled data ingestion processes. It captures detailed information
-- about each scheduled import including timing, sources, and validation requirements to support
-- consistent data ingestion practices. The table supports multiple schedule types including
-- daily, weekly, and custom interval schedules, accommodating different business requirements.
-- Each schedule record includes metadata about the import template, data sensitivity, and
-- validation rules to ensure proper handling of imported data. The implementation includes
-- robust tracking of schedule execution history to identify failures and measure reliability.
-- Historical schedule data is maintained to support audit requirements and track changes to
-- scheduled imports over time. For compliance purposes, the system tracks approval workflows
-- for sensitive scheduled imports to document the rationale and authorization for data
-- ingestion. The table integrates with the notification system to enable automated alerts for
-- import failures and status updates. The design accommodates complex scheduling scenarios with
-- dependencies between scheduled imports and conditional processing rules, providing detailed
-- insights into data ingestion practices. By centralizing schedule management, the organization
-- can ensure consistent ingestion of data while providing the detailed evidence needed for
-- compliance audits. The table is optimized for rapid querying during schedule management,
-- which is critical for timely adjustments to scheduled data ingestion processes.
-- KPI: Schedule reliability rate, Data ingestion timeliness,
--      Schedule coverage completeness, Import method compliance rate,
--      Audit success rate
-- Feature Reference: 1106, 1107, 1108, 1109, 1110
CREATE TABLE IF NOT EXISTS system.import_schedules (
    schedule_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    schedule_name VARCHAR(100) NOT NULL,
    description TEXT,
    schedule_type VARCHAR(50) NOT NULL CHECK (schedule_type IN ('DAILY', 'WEEKLY', 'MONTHLY', 'CUSTOM_INTERVAL', 'EVENT_BASED')),
    schedule_cron VARCHAR(50),
    schedule_expression JSONB,
    timezone VARCHAR(50) NOT NULL DEFAULT 'UTC',
    start_date DATE NOT NULL DEFAULT CURRENT_DATE,
    end_date DATE,
    next_run_time TIMESTAMP WITH TIME ZONE, -- Removed GENERATED, will be managed by application/job scheduler
    import_template_id UUID NOT NULL REFERENCES system.import_templates(template_id),
    source_location VARCHAR(500) NOT NULL,
    validation_required BOOLEAN NOT NULL DEFAULT TRUE,
    processing_rules JSONB,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    last_run_time TIMESTAMP WITH TIME ZONE,
    last_run_status VARCHAR(20) CHECK (last_run_status IN ('SUCCESS', 'FAILED', 'SKIPPED')),
    last_run_message TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_import_schedules_type ON system.import_schedules(schedule_type);
CREATE INDEX IF NOT EXISTS idx_import_schedules_active ON system.import_schedules(is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_import_schedules_template ON system.import_schedules(import_template_id);
CREATE INDEX IF NOT EXISTS idx_import_schedules_next_run ON system.import_schedules(next_run_time);
CREATE INDEX IF NOT EXISTS idx_import_schedules_last_run ON system.import_schedules(last_run_time DESC);
CREATE INDEX IF NOT EXISTS idx_import_schedules_status ON system.import_schedules(last_run_status);
CREATE INDEX IF NOT EXISTS idx_import_schedules_metadata ON system.import_schedules USING GIN(metadata);

-- Add triggers for audit columns
CREATE TRIGGER trg_import_schedules_updated_at
BEFORE UPDATE ON system.import_schedules
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE system.import_schedules IS 'Configuration of scheduled import jobs.
Manages scheduling of recurring import jobs. Captures detailed information about each scheduled import.
