                        CREATE INDEX IF NOT EXISTS idx_import_remediation_actions_risk ON system.import_remediation_actions(risk_level);
                        CREATE INDEX IF NOT EXISTS idx_import_remediation_actions_status ON system.import_remediation_actions(approval_status);
                        CREATE INDEX IF NOT EXISTS idx_import_remediation_actions_version ON system.import_remediation_actions(action_id, version_number DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_remediation_actions_approved ON system.import_remediation_actions(approved_by)
