                        -- Serial No: 223 | TABLE: system.import_profiles
                        -- Description: Profiling of data sources for import preparation
                        -- Business Case: The import_profiles table stores profiling statistics for data sources used
                        -- in import processes, enabling data quality assessment and preparation. It captures key metrics
                        -- such as null rates, uniqueness, value distributions, and statistical properties to support
                        -- data quality assessment before import. This information is critical for identifying potential
                        -- data quality issues before they impact import processes, understanding source data
                        -- characteristics, and planning appropriate validation rules. The table supports multiple
                        -- profiling dimensions including column-level statistics, value distributions, and pattern
                        -- analysis, enabling holistic assessment of source data health. Historical profile data is
                        -- versioned to track changes over time and measure improvement against quality goals. Each
                        -- profile record includes metadata about the source system, collection method, and confidence
                        -- level to ensure proper interpretation of results. The implementation includes mechanisms for
                        -- automated profile collection through scheduled jobs, ensuring timely assessment of source
                        -- data quality. For metrics with defined targets, the table stores variance calculations to
                        -- highlight areas requiring attention. Historical profile data is used to establish baselines
                        -- and detect anomalies that may indicate underlying data issues in source systems. By
                        -- centralizing source data profiling results, the organization can ensure comprehensive data
                        -- quality assessment that provides visibility into source data health across all systems. The
                        -- table is optimized for time-series analysis of profiling metrics, supporting trend
                        -- identification and predictive data quality management.
                        -- KPI: Source data completeness rate, Source data uniqueness rate,
                        --      Pattern consistency rate, Profile coverage,
                        --      Data issue detection time
                        -- Feature Reference: 1131, 1132, 1133, 1134, 1135
                        CREATE TABLE IF NOT EXISTS system.import_profiles (
                            profile_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                            source_system VARCHAR(100) NOT NULL,
                            table_name VARCHAR(200) NOT NULL,
                            column_name VARCHAR(100) NOT NULL,
                            profile_date DATE NOT NULL DEFAULT CURRENT_DATE,
                            null_count INTEGER NOT NULL DEFAULT 0 CHECK (null_count >= 0),
                            not_null_count INTEGER NOT NULL DEFAULT 0 CHECK (not_null_count >= 0),
                            total_count INTEGER NOT NULL DEFAULT 0 CHECK (total_count >= 0),
                            null_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
                                CASE
                                    WHEN total_count > 0 THEN (null_count::NUMERIC / total_count * 100.0)
                                    ELSE 0
                                END
                            ) STORED,
                            unique_count INTEGER NOT NULL DEFAULT 0 CHECK (unique_count >= 0),
                            distinct_count INTEGER NOT NULL DEFAULT 0 CHECK (distinct_count >= 0),
                            duplicate_count INTEGER NOT NULL DEFAULT 0 CHECK (duplicate_count >= 0),
                            duplicate_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
                                CASE
                                    WHEN total_count > 0 THEN (duplicate_count::NUMERIC / total_count * 100.0)
                                    ELSE 0
                                END
                            ) STORED,
                            min_value TEXT,
                            max_value TEXT,
                            average_length INTEGER,
                            median_value TEXT,
                            mode_value TEXT,
                            standard_deviation NUMERIC(15,6),
                            value_distribution JSONB,
                            pattern_analysis JSONB,
                            data_quality_score NUMERIC(5,2) CHECK (data_quality_score BETWEEN 0.00 AND 100.00),
                            completeness_score NUMERIC(5,2) CHECK (completeness_score BETWEEN 0.00 AND 100.00),
                            validity_score NUMERIC(5,2) CHECK (validity_score BETWEEN 0.00 AND 100.00),
                            collection_method VARCHAR(50) NOT NULL DEFAULT 'AUTOMATED'
                                CHECK (collection_method IN ('AUTOMATED', 'MANUAL', 'SAMPLED')),
                            sample_size INTEGER,
                            sample_percentage NUMERIC(5,2) CHECK (sample_percentage BETWEEN 0.00 AND 100.00),
                            created_by UUID NOT NULL,
                            updated_by UUID,
                            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,

                            -- Constraints
                            CONSTRAINT uq_source_table_column_date UNIQUE (source_system, table_name, column_name, profile_date),
                            CONSTRAINT chk_counts CHECK (null_count + not_null_count = total_count),
                            CONSTRAINT chk_quality_scores CHECK (
                                data_quality_score IS NULL OR
                                (completeness_score IS NOT NULL AND validity_score IS NOT NULL)
                            )
                        );

                        -- Add indexes for performance
                        CREATE INDEX IF NOT EXISTS idx_import_profiles_source ON system.import_profiles(source_system, table_name, column_name);
                        CREATE INDEX IF NOT EXISTS idx_import_profiles_date ON system.import_profiles(profile_date DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_profiles_quality ON system.import_profiles(data_quality_score DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_profiles_completeness ON system.import_profiles(completeness_score DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_profiles_validity ON system.import_profiles(validity_score DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_profiles_null ON system.import_profiles(null_percentage DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_profiles_duplicate ON system.import_profiles(duplicate_percentage DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_profiles_distribution ON system.import_profiles USING GIN(value_distribution);
                        CREATE INDEX IF NOT EXISTS idx_import_profiles_pattern ON system.import_profiles USING GIN(pattern_analysis);

                        -- Add triggers for audit columns
                        CREATE TRIGGER trg_import_profiles_updated_at
                        BEFORE UPDATE ON system.import_profiles
                        FOR EACH ROW
                        EXECUTE FUNCTION update_updated_at_column();

                        COMMENT ON TABLE system.import_profiles IS 'Profiling of data sources for import preparation.
                        Stores profiling statistics for data sources used in import processes. Captures key metrics such as null rates and uniqueness.
                        Critical for identifying data quality issues before import processes. Supports multiple profiling dimensions including column-level
                        statistics. Historical profile data versioned to track changes over time. Includes metadata about source system and collection
                        method. Includes mechanisms for automated profile collection. Stores variance calculations for metrics with defined targets. Used
                        to establish baselines and detect anomalies. Centralizes source data profiling for comprehensive data quality assessment. Optimized
                        for time-series analysis of profiling metrics.';
-- Serial No: 224 | TABLE: system.import_mapping_templates
-- Description: Configuration of data mapping templates for imports
-- Business Case: The import_mapping_templates table stores configuration details for data
-- mapping templates used during import processes, enabling consistent data transformation
-- between source and target systems. It captures the complete definition of mapping
-- specifications including field mappings, transformation rules, and data type conversions to
-- ensure consistent mapping behavior. The table supports multiple template types including
-- standard mappings, custom mappings, and compliance mappings, accommodating different business
-- needs. Each template record includes metadata about its purpose, source and target systems,
-- and usage patterns to support effective template design. The implementation includes
-- versioning of templates to track changes over time while maintaining historical mapping
-- configurations. Historical template data is maintained to support audit requirements and
-- track changes to mapping standards over time. For operational efficiency, the system tracks
-- template usage metrics to enable identification of unused or redundant templates. The table
-- integrates with the data dictionary to ensure proper data type handling during
-- transformations. The design accommodates complex mapping scenarios with hierarchical
-- relationships between template components, providing detailed insights into mapping
-- configuration. By centralizing mapping template management, the organization can ensure
-- consistent application of data transformation practices while providing the flexibility
-- needed for different business contexts. The table is optimized for rapid querying during
-- import processing, which is critical for timely transformation of imported data.
-- KPI: Template coverage completeness, Mapping consistency rate,
--      Template utilization rate, Mapping configuration efficiency,
--      Mapping management effectiveness
-- Feature Reference: 1136, 1137, 1138, 1139, 1140
CREATE TABLE IF NOT EXISTS system.import_mapping_templates (
    template_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    template_code VARCHAR(50) UNIQUE NOT NULL CHECK (template_code ~ '^[A-Z0-9_]{3,50}$'),
    name VARCHAR(100) NOT NULL,
    description TEXT,
    template_type VARCHAR(50) NOT NULL CHECK (template_type IN ('STANDARD', 'CUSTOM', 'COMPLIANCE', 'AUDIT', 'SCHEDULED')),
    source_system VARCHAR(100) NOT NULL,
    source_format VARCHAR(50) NOT NULL CHECK (source_format IN ('CSV', 'XLSX', 'JSON', 'XML', 'FIXED_WIDTH')),
    target_system VARCHAR(100) NOT NULL,
    target_table VARCHAR(100) NOT NULL,
    mappings JSONB NOT NULL,
    transformation_rules JSONB,
    data_type_conversions JSONB,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_system_template BOOLEAN NOT NULL DEFAULT FALSE,
    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
    approval_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
        CHECK (approval_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'REJECTED', 'RETIRED')),
    approved_by UUID REFERENCES hr.employees(employee_id),
    approved_at TIMESTAMP WITH TIME ZONE,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Add indexes for performance
CREATE INDEX IF NOT EXISTS idx_import_mapping_templates_type ON system.import_mapping_templates(template_type);
CREATE INDEX IF NOT EXISTS idx_import_mapping_templates_active ON system.import_mapping_templates(is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_import_mapping_templates_system ON system.import_mapping_templates(is_system_template)
    WHERE is_system_template = TRUE;
CREATE INDEX IF NOT EXISTS idx_import_mapping_templates_source ON system.import_mapping_templates(source_system);
CREATE INDEX IF NOT EXISTS idx_import_mapping_templates_target ON system.import_mapping_templates(target_system, target_table);
CREATE INDEX IF NOT EXISTS idx_import_mapping_templates_status ON system.import_mapping_templates(approval_status);
CREATE INDEX IF NOT EXISTS idx_import_mapping_templates_version ON system.import_mapping_templates(template_id, version_number DESC);
CREATE INDEX IF NOT EXISTS idx_import_mapping_templates_approved ON system.import_mapping_templates(approved_by)
    WHERE approved_by IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_import_mapping_templates_mappings ON system.import_mapping_templates USING GIN(mappings);
CREATE INDEX IF NOT EXISTS idx_import_mapping_templates_metadata ON system.import_mapping_templates USING GIN(metadata);

-- Add triggers for audit columns
CREATE TRIGGER trg_import_mapping_templates_updated_at
BEFORE UPDATE ON system.import_mapping_templates
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE system.import_mapping_templates IS 'Configuration of data mapping templates for imports.
Stores configuration details for data mapping templates used during import processes. Captures complete definition of mapping specifications.
Supports multiple template types including standard, custom, and compliance mappings. Includes metadata about purpose, source and target systems.
Includes versioning of templates to track changes over time while maintaining historical mapping configurations. Historical template data is
maintained to support audit requirements and track changes to mapping standards over time. For operational efficiency, the system tracks
template usage metrics to enable identification of unused or redundant templates. The table integrates with the data dictionary to ensure
proper data type handling during transformations. The design accommodates complex mapping scenarios with hierarchical relationships between
template components, providing detailed insights into mapping configuration. By centralizing mapping template management, the organization can
ensure consistent application of data transformation practices while providing the flexibility needed for different business contexts. The
table is optimized for rapid querying during import processing, which is critical for timely transformation of imported data.';

                        -- Serial No: 225 | TABLE: system.import_mapping_history
                        -- Description: Tracking of data mappings applied during import processes
                        -- Business Case: The import_mapping_history table maintains a comprehensive record of all data
                        -- mappings applied during import processes, providing visibility into data transformation
                        -- activities. It captures detailed information about each mapping including source and target
                        -- fields, transformation rules applied, and execution results to support data quality
                        -- assessment. This information is critical for diagnosing mapping issues, optimizing
                        -- transformation performance, and ensuring accurate data transfer between systems. The table
                        -- supports multiple mapping statuses including success, warning, and failure, accommodating
                        -- different transformation scenarios. Each mapping record includes metadata about the import
                        -- job, mapping template, and business context to enable accurate assessment of transformation
                        -- outcomes. Historical mapping data is maintained to identify trends in mapping performance and
                        -- measure the impact of template changes over time. For operational efficiency, the system
                        -- tracks transformation duration and error rates to enable capacity planning for import
                        -- operations. The table integrates with the data quality system to enable correlation of
                        -- mapping results with actual data quality metrics. The design accommodates complex mapping
                        -- scenarios with multi-step transformations and conditional execution paths, providing detailed
                        -- insights into transformation behavior. By centralizing mapping history, the organization can
                        -- ensure consistent evaluation of transformation effectiveness while providing the data needed
                        -- for continuous improvement of import processes. The table is optimized for rapid querying
                        -- during performance analysis, which often involves comparing multiple mapping runs to identify
                        -- improvement opportunities.
                        -- KPI: Mapping execution success rate, Transformation duration,
                        --      Resource utilization, Data quality after transformation,
                        --      Mapping optimization rate
                        -- Feature Reference: 1141, 1142, 1143, 1144, 1145
                        CREATE TABLE IF NOT EXISTS system.import_mapping_history (
                            history_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                            import_id UUID NOT NULL REFERENCES system.import_jobs(import_id),
                            template_id UUID REFERENCES system.import_mapping_templates(template_id),
                            source_field VARCHAR(100) NOT NULL,
                            target_field VARCHAR(100) NOT NULL,
                            transformation_rule TEXT,
                            records_processed INTEGER NOT NULL DEFAULT 0,
                            records_transformed INTEGER NOT NULL DEFAULT 0,
                            records_errored INTEGER NOT NULL DEFAULT 0,
                            error_details JSONB,
                            execution_status VARCHAR(20) NOT NULL CHECK (execution_status IN ('SUCCESS', 'WARNING', 'FAILURE')),
                            started_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            completed_at TIMESTAMP WITH TIME ZONE,
                            duration_ms INTEGER GENERATED ALWAYS AS (
                                CASE
                                    WHEN completed_at IS NOT NULL
                                        THEN EXTRACT(EPOCH FROM (completed_at - started_at)) * 1000
                                    ELSE NULL
                                END
                            ) STORED,
                            created_by UUID NOT NULL,
                            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            updated_by UUID,
                            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            metadata JSONB
                        );

                        -- Add indexes for performance
                        CREATE INDEX IF NOT EXISTS idx_import_mapping_history_import ON system.import_mapping_history(import_id);
                        CREATE INDEX IF NOT EXISTS idx_import_mapping_history_template ON system.import_mapping_history(template_id)
                            WHERE template_id IS NOT NULL;
                        CREATE INDEX IF NOT EXISTS idx_import_mapping_history_status ON system.import_mapping_history(execution_status);
                        CREATE INDEX IF NOT EXISTS idx_import_mapping_history_source ON system.import_mapping_history(source_field);
                        CREATE INDEX IF NOT EXISTS idx_import_mapping_history_target ON system.import_mapping_history(target_field);
                        CREATE INDEX IF NOT EXISTS idx_import_mapping_history_time ON system.import_mapping_history(started_at DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_mapping_history_duration ON system.import_mapping_history(duration_ms);
                        CREATE INDEX IF NOT EXISTS idx_import_mapping_history_errors ON system.import_mapping_history(records_errored);
                        CREATE INDEX IF NOT EXISTS idx_import_mapping_history_metadata ON system.import_mapping_history USING GIN(metadata);

                        -- Add triggers for audit columns
                        CREATE TRIGGER trg_import_mapping_history_updated_at
                        BEFORE UPDATE ON system.import_mapping_history
                        FOR EACH ROW
                        EXECUTE FUNCTION update_updated_at_column();

                        COMMENT ON TABLE system.import_mapping_history IS 'Tracking of data mappings applied during import processes.
                        Maintains comprehensive record of all data mappings applied during imports. Captures detailed information about each mapping.
                        Critical for diagnosing mapping issues and optimizing performance. Supports multiple mapping statuses including success and failure.
                        Includes metadata about import job and mapping template. Historical data maintained to identify mapping performance trends.
                        Tracks transformation duration and error rates. Integrates with data quality system for correlation. Accommodates complex
                        mapping scenarios with multi-step transformations. Centralizes mapping history for consistent evaluation. Optimized for rapid
                        querying during performance analysis.';

                        -- Serial No: 226 | TABLE: system.import_data_lineage
                        -- Description: Tracking of data lineage for imported data
                        -- Business Case: The import_data_lineage table maintains a comprehensive record of data lineage
                        -- for imported data, providing visibility into data origin, transformations, and usage. It
                        -- captures detailed information about each data element including source system, transformation
                        -- history, and downstream usage to support data governance and compliance requirements. The
                        -- table supports multiple lineage types including operational lineage, technical lineage, and
                        -- business lineage, accommodating different data governance needs. Each lineage record includes
                        -- metadata about the data sensitivity, retention requirements, and business context to ensure
                        -- proper handling of lineage information. Historical lineage data is maintained to identify
                        -- patterns in data flow and measure the impact of data changes over time. For compliance
                        -- purposes, the system tracks the complete data journey from source to consumption, enabling
                        -- accurate impact analysis for regulatory requirements. The table integrates with the data
                        -- catalog to provide context for data elements and their lineage relationships. The design
                        -- accommodates complex lineage scenarios with multiple transformations and branching data
                        -- flows, providing detailed insights into data movement across the organization. By centralizing
                        -- data lineage tracking, the organization can ensure consistent data governance practices while
                        -- providing the detailed evidence needed for compliance audits and impact analysis. The table
                        -- is optimized for rapid querying during impact analysis, which is critical for timely
                        -- responses to regulatory inquiries and change management requests.
                        -- KPI: Lineage coverage completeness, Lineage accuracy rate,
                        --      Data impact analysis time, Compliance audit success rate,
                        --      Data lineage data quality
                        -- Feature Reference: 1146, 1147, 1148, 1149, 1150
                        CREATE TABLE IF NOT EXISTS system.import_data_lineage (
                            lineage_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                            source_system VARCHAR(100) NOT NULL,
                            source_table VARCHAR(200) NOT NULL,
                            source_column VARCHAR(100) NOT NULL,
                            target_system VARCHAR(100) NOT NULL,
                            target_table VARCHAR(200) NOT NULL,
                            target_column VARCHAR(100) NOT NULL,
                            lineage_type VARCHAR(50) NOT NULL CHECK (lineage_type IN ('OPERATIONAL', 'TECHNICAL', 'BUSINESS')),
                            transformation_rules JSONB,
                            transformation_history JSONB,
                            import_job_id UUID REFERENCES system.import_jobs(import_id),
                            data_classification VARCHAR(50) NOT NULL CHECK (data_classification IN ('PUBLIC', 'INTERNAL', 'CONFIDENTIAL', 'RESTRICTED', 'HIGHLY_RESTRICTED')),
                            business_context JSONB,
                            effective_start_date TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            effective_end_date TIMESTAMP WITH TIME ZONE,
                            is_active BOOLEAN NOT NULL DEFAULT TRUE,
                            created_by UUID NOT NULL,
                            updated_by UUID,
                            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            metadata JSONB
                        );

                        -- Add indexes for performance
                        CREATE INDEX IF NOT EXISTS idx_import_data_lineage_source ON system.import_data_lineage(source_system, source_table, source_column);
                        CREATE INDEX IF NOT EXISTS idx_import_data_lineage_target ON system.import_data_lineage(target_system, target_table, target_column);
                        CREATE INDEX IF NOT EXISTS idx_import_data_lineage_type ON system.import_data_lineage(lineage_type);
                        CREATE INDEX IF NOT EXISTS idx_import_data_lineage_import ON system.import_data_lineage(import_job_id)
                            WHERE import_job_id IS NOT NULL;
                        CREATE INDEX IF NOT EXISTS idx_import_data_lineage_classification ON system.import_data_lineage(data_classification);
                        CREATE INDEX IF NOT EXISTS idx_import_data_lineage_active ON system.import_data_lineage(is_active) WHERE is_active = TRUE;
                        CREATE INDEX IF NOT EXISTS idx_import_data_lineage_dates ON system.import_data_lineage(effective_start_date, effective_end_date);
                        CREATE INDEX IF NOT EXISTS idx_import_data_lineage_metadata ON system.import_data_lineage USING GIN(metadata);

                        -- Add triggers for audit columns
                        CREATE TRIGGER trg_import_data_lineage_updated_at
                        BEFORE UPDATE ON system.import_data_lineage
                        FOR EACH ROW
                        EXECUTE FUNCTION update_updated_at_column();

                        COMMENT ON TABLE system.import_data_lineage IS 'Tracking of data lineage for imported data.
                        Maintains comprehensive record of data lineage for imported data. Captures detailed information about data origin and
                        transformations. Supports multiple lineage types including operational and business lineage. Includes metadata about data
                        sensitivity and business context. Historical data maintained to identify data flow patterns. Tracks complete data journey for
                        compliance. Integrates with data catalog for context. Accommodates complex lineage scenarios with multiple transformations.
                        Centralizes data lineage tracking for consistent governance. Optimized for rapid querying during impact analysis.';

                        -- Serial No: 227 | TABLE: system.import_data_quality_metrics
                        -- Description: Historical metrics for imported data quality assessment
                        -- Business Case: The import_data_quality_metrics table stores historical data quality metrics
                        -- for imported data, providing critical insights for data governance and quality management. It
                        -- captures key quality indicators such as completeness rates, accuracy scores, and consistency
                        -- metrics at regular intervals to support ongoing quality monitoring. This information is
                        -- critical for identifying data quality issues before they impact business operations or
                        -- decision making. The table supports multiple metric types including completeness, accuracy,
                        -- consistency, timeliness, and validity, enabling holistic assessment of data health. Historical
                        -- metric data is versioned to track changes over time and measure improvement against quality
                        -- goals. Each metric record includes metadata about the calculation method, execution frequency,
                        -- and target values to support data quality goal setting and monitoring. The implementation
                        -- includes mechanisms for automated metric calculation through scheduled jobs, ensuring timely
                        -- assessment of data quality. For metrics with defined targets, the table stores variance
                        -- calculations to highlight areas requiring attention. Historical metric data is used to
                        -- establish baselines and detect anomalies that may indicate underlying data issues. By
                        -- centralizing data quality metrics, the system enables comprehensive data quality dashboards
                        -- that provide visibility into data health across the organization. The table is optimized for
                        -- time-series analysis of quality metrics, supporting trend identification and predictive data
                        -- quality management.
                        -- KPI: Data completeness rate, Data accuracy rate,
                        --      Data consistency rate, Data quality trend direction,
                        --      Data issue detection time
                        -- Feature Reference: 1151, 1152, 1153, 1154, 1155
                        CREATE TABLE IF NOT EXISTS system.import_data_quality_metrics (
                            metric_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                            source_system VARCHAR(100) NOT NULL,
                            source_table VARCHAR(200) NOT NULL,
                            source_column VARCHAR(200),
                            metric_type VARCHAR(50) NOT NULL CHECK (metric_type IN ('COMPLETENESS', 'ACCURACY', 'CONSISTENCY',
                                'TIMELINESS', 'VALIDITY', 'DUPLICACY', 'UNIQUENESS')),
                            calculation_method VARCHAR(100) NOT NULL CHECK (calculation_method IN ('SQL_QUERY', 'PYTHON_SCRIPT',
                                'EXTERNAL_TOOL', 'MANUAL')),
                            calculation_frequency VARCHAR(20) NOT NULL CHECK (calculation_frequency IN ('REALTIME', 'HOURLY',
                                'DAILY', 'WEEKLY', 'MONTHLY', 'ON_DEMAND')),
                            metric_value NUMERIC(15,6) NOT NULL,
                            metric_value_raw TEXT,
                            target_value NUMERIC(15,6),
                            warning_threshold NUMERIC(15,6),
                            failure_threshold NUMERIC(15,6),
                            calculation_time TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            calculated_by UUID,
                            calculation_duration_ms INTEGER CHECK (calculation_duration_ms >= 0),
                            metric_granularity VARCHAR(20) NOT NULL DEFAULT 'DAILY'
                                CHECK (metric_granularity IN ('HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY', 'QUARTERLY', 'YEARLY')),
                            related_import_id UUID REFERENCES system.import_jobs(import_id),
                            context JSONB,
                            data_source VARCHAR(50) NOT NULL DEFAULT 'SYSTEM_CALCULATED'
                                CHECK (data_source IN ('SYSTEM_CALCULATED', 'MANUAL_ENTRY', 'SURVEY', 'OBSERVATION', 'EXTERNAL_SYSTEM')),
                            created_by UUID NOT NULL,
                            updated_by UUID,
                            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
                        );

                        -- Add indexes for performance
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_metrics_source ON system.import_data_quality_metrics(source_system, source_table, source_column);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_metrics_type ON system.import_data_quality_metrics(metric_type);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_metrics_time ON system.import_data_quality_metrics(calculation_time DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_metrics_granularity ON system.import_data_quality_metrics(metric_granularity);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_metrics_import ON system.import_data_quality_metrics(related_import_id)
                            WHERE related_import_id IS NOT NULL;
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_metrics_context ON system.import_data_quality_metrics USING GIN(context);

                        -- Add triggers for audit columns
                        CREATE TRIGGER trg_import_data_quality_metrics_updated_at
                        BEFORE UPDATE ON system.import_data_quality_metrics
                        FOR EACH ROW
                        EXECUTE FUNCTION update_updated_at_column();

                        COMMENT ON TABLE system.import_data_quality_metrics IS 'Historical metrics for imported data quality assessment and trend analysis.
                        Stores historical data quality metrics for comprehensive assessment. Captures key quality indicators such as completeness rates
                        and accuracy scores. Critical for identifying data quality issues before they impact business operations. Supports multiple
                        metric types including completeness, accuracy, and consistency. Historical data versioned to track changes over time. Includes
                        metadata about calculation method and target values. Includes mechanisms for automated metric calculation. Stores variance
                        calculations for metrics with defined targets. Used to establish baselines and detect anomalies. Centralizes data quality metrics
                        for comprehensive data quality dashboards. Optimized for time-series analysis of quality metrics.';

                        -- Serial No: 228 | MATERIALIZED VIEW: system.mv_import_data_quality_dashboard
                        -- Purpose: Real-time data quality monitoring dashboard for imported data
                        -- Business Case: This materialized view provides a real-time snapshot of data quality health for
                        -- imported data across the organization, serving as the foundation for data quality monitoring
                        -- dashboards. It aggregates key quality metrics including completeness rates, accuracy scores,
                        -- and consistency metrics to provide a comprehensive view of data health. The view includes
                        -- comparison against targets and thresholds to highlight areas requiring attention. It supports
                        -- multiple time granularities (daily, weekly, monthly) to accommodate different analysis needs.
                        -- Historical trend data is presented with appropriate statistical analysis to distinguish
                        -- meaningful patterns from random fluctuations. The materialized structure enables rapid query
                        -- performance for monitoring that would be too slow on operational tables. The view also
                        -- includes benchmark comparisons against industry standards or internal best practices to
                        -- provide context for quality measurements. It serves as the foundation for data quality
                        -- scorecards that track progress against organizational data quality goals. The implementation
                        -- includes anomaly detection logic to automatically identify unusual patterns in quality metrics
                        -- that may indicate underlying data issues. By pre-computing these metrics, the view enables
                        -- sophisticated data quality analytics to be performed in real-time, supporting proactive data
                        -- governance. The refresh process is optimized to minimize impact on operational systems while
                        -- ensuring quality data remains sufficiently current for decision making. The view is designed
                        -- with robust security controls to protect sensitive quality metrics while ensuring appropriate
                        -- access for stakeholders.
                        -- KPI: Data quality trend direction, Target achievement rate,
                        --      Anomaly detection rate, Data quality improvement rate,
                        --      Trend analysis performance
                        -- Feature Reference: 1156, 1157, 1158, 1159, 1160
                        CREATE MATERIALIZED VIEW IF NOT EXISTS system.mv_import_data_quality_dashboard AS
                        SELECT
                            source_system,
                            source_table,
                            source_column,
                            metric_type,
                            DATE_TRUNC('day', calculation_time) AS calculation_date,
                            AVG(metric_value) AS avg_metric_value,
                            MIN(metric_value) AS min_metric_value,
                            MAX(metric_value) AS max_metric_value,
                            PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY metric_value) AS median_metric_value,
                            COUNT(*) AS sample_count,
                            BOOL_AND(metric_value >= COALESCE(warning_threshold, 0)) AS meets_warning_threshold,
                            BOOL_AND(metric_value >= COALESCE(failure_threshold, 0)) AS meets_failure_threshold,
                            target_value,
                            warning_threshold,
                            failure_threshold,
                            (SELECT AVG(metric_value)
                             FROM system.import_data_quality_metrics m2
                             WHERE m2.source_system = m1.source_system
                             AND m2.source_table = m1.source_table
                             AND m2.source_column = m1.source_column
                             AND m2.metric_type = m1.metric_type
                             AND calculation_time >= CURRENT_DATE - INTERVAL '7 days'
                             AND calculation_time < CURRENT_DATE) AS previous_week_avg,
                            CASE
                                WHEN (SELECT AVG(metric_value)
                                      FROM system.import_data_quality_metrics m2
                                      WHERE m2.source_system = m1.source_system
                                      AND m2.source_table = m1.source_table
                                      AND m2.source_column = m1.source_column
                                      AND m2.metric_type = m1.metric_type
                                      AND calculation_time >= CURRENT_DATE - INTERVAL '7 days'
                                      AND calculation_time < CURRENT_DATE) > 0
                                    THEN (AVG(metric_value) - (SELECT AVG(metric_value)
                                                              FROM system.import_data_quality_metrics m2
                                                              WHERE m2.source_system = m1.source_system
                                                              AND m2.source_table = m1.source_table
                                                              AND m2.source_column = m1.source_column
                                                              AND m2.metric_type = m1.metric_type
                                                              AND calculation_time >= CURRENT_DATE - INTERVAL '7 days'
                                                              AND calculation_time < CURRENT_DATE))
                                         / (SELECT AVG(metric_value)
                                            FROM system.import_data_quality_metrics m2
                                            WHERE m2.source_system = m1.source_system
                                            AND m2.source_table = m1.source_table
                                            AND m2.source_column = m1.source_column
                                            AND m2.metric_type = m1.metric_type
                                            AND calculation_time >= CURRENT_DATE - INTERVAL '7 days'
                                            AND calculation_time < CURRENT_DATE) * 100
                                ELSE NULL
                            END AS week_over_week_change
                        FROM system.import_data_quality_metrics m1
                        WHERE calculation_time >= CURRENT_DATE - INTERVAL '30 days'
                        GROUP BY
                            source_system, source_table, source_column, metric_type,
                            DATE_TRUNC('day', calculation_time),
                            target_value, warning_threshold, failure_threshold;

                        -- Create indexes on the materialized view
                        CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_import_data_quality_dashboard_full ON system.mv_import_data_quality_dashboard
                            (source_system, source_table, source_column, metric_type, calculation_date);
                        CREATE INDEX IF NOT EXISTS idx_mv_import_data_quality_dashboard_table ON system.mv_import_data_quality_dashboard
                            (source_system, source_table, source_column);
                        CREATE INDEX IF NOT EXISTS idx_mv_import_data_quality_dashboard_type ON system.mv_import_data_quality_dashboard (metric_type);
                        CREATE INDEX IF NOT EXISTS idx_mv_import_data_quality_dashboard_date ON system.mv_import_data_quality_dashboard (calculation_date);
                        CREATE INDEX IF NOT EXISTS idx_mv_import_data_quality_dashboard_trend ON system.mv_import_data_quality_dashboard
                            (avg_metric_value, calculation_date);

                        COMMENT ON MATERIALIZED VIEW system.mv_import_data_quality_dashboard IS 'Real-time data quality monitoring dashboard for imported data.
                        Provides real-time snapshot of data quality health for imported data across the organization. Aggregates key quality metrics including completeness
                        rates and accuracy scores. Includes comparison against targets and thresholds. Supports multiple time granularities for analysis.
                        Historical trend data presented with statistical analysis. Enables rapid query performance for monitoring. Includes benchmark
                        comparisons for context. Serves as foundation for data quality scorecards. Includes anomaly detection logic. Enables sophisticated
                        data quality analytics in real-time. Refresh process optimized to minimize impact on operational systems. Designed with robust
                        security controls for sensitive quality metrics.';

                        -- Serial No: 229 | TABLE: system.import_data_quality_scorecards
                        -- Description: Configuration of data quality scorecards for imported data
                        -- Business Case: The import_data_quality_scorecards table stores configuration details for data
                        -- quality scorecards used in organizational reporting of imported data quality performance. It
                        -- captures the composition of scorecards including the metrics, weightings, and targets used to
                        -- evaluate data quality performance. The table supports multiple scorecard types including
                        -- executive dashboards, operational reports, and compliance monitoring views, enabling tailored
                        -- reporting for different audiences. Each scorecard configuration includes metadata about its
                        -- scope, frequency, and approval status to support proper governance of data quality reporting.
                        -- The implementation includes versioning of scorecards to track changes over time while
                        -- maintaining historical consistency in measurement. Historical scorecard data is maintained to
                        -- support retrospective analysis of data quality performance trends. For compliance purposes,
                        -- the system tracks the approval status of scorecards and maintains audit trails of all
                        -- modifications. The table integrates with the data quality metrics system to enable automatic
                        -- calculation of scorecard results based on current quality metrics. The design accommodates
                        -- different scorecard methodologies while providing a consistent interface for decision makers.
                        -- By centralizing scorecard configuration, the organization can ensure consistent evaluation of
                        -- data quality performance while providing the flexibility needed for different reporting
                        -- requirements. The table is optimized for rapid lookup during scorecard generation, which is
                        -- critical for timely delivery of data quality performance reports.
                        -- KPI: Scorecard coverage completeness, Data quality performance trend,
                        --      Scorecard update frequency, Scorecard data completeness,
                        --      Data quality improvement rate
                        -- Feature Reference: 1161, 1162, 1163, 1164, 1165
                        CREATE TABLE IF NOT EXISTS system.import_data_quality_scorecards (
                            scorecard_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                            scorecard_code VARCHAR(50) UNIQUE NOT NULL CHECK (scorecard_code ~ '^[A-Z0-9_]{5,50}$'),
                            name VARCHAR(200) NOT NULL,
                            description TEXT,
                            scorecard_type VARCHAR(50) NOT NULL CHECK (scorecard_type IN ('EXECUTIVE', 'OPERATIONAL', 'COMPLIANCE', 'DEPARTMENTAL', 'CUSTOM')),
                            scope JSONB NOT NULL DEFAULT '{"organization_wide": true}'::JSONB,
                            metrics JSONB NOT NULL,
                            metric_weights JSONB NOT NULL,
                            target_values JSONB NOT NULL,
                            calculation_method VARCHAR(50) NOT NULL DEFAULT 'WEIGHTED_AVERAGE'
                                CHECK (calculation_method IN ('WEIGHTED_AVERAGE', 'THRESHOLD_BASED', 'CUSTOM_FORMULA')),
                            refresh_frequency VARCHAR(20) NOT NULL DEFAULT 'DAILY'
                                CHECK (refresh_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
                            version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
                            is_active BOOLEAN NOT NULL DEFAULT TRUE,
                            is_default BOOLEAN NOT NULL DEFAULT FALSE,
                            based_on_scorecard_id UUID REFERENCES system.import_data_quality_scorecards(scorecard_id),
                            validated_by UUID REFERENCES hr.employees(employee_id),
                            validated_at TIMESTAMP WITH TIME ZONE,
                            validation_results JSONB,
                            usage_count INTEGER NOT NULL DEFAULT 0,
                            created_by UUID NOT NULL,
                            updated_by UUID,
                            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            metadata JSONB,

                            -- Constraints
                            CONSTRAINT chk_metrics_structure CHECK (
                                jsonb_typeof(metrics) = 'object'
                                AND metrics != '{}'::JSONB
                            ),
                            CONSTRAINT chk_weights_structure CHECK (
                                jsonb_typeof(metric_weights) = 'object'
                                AND metric_weights != '{}'::JSONB
                            )
                        );

                        -- Add indexes for performance
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecards_type ON system.import_data_quality_scorecards(scorecard_type);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecards_active ON system.import_data_quality_scorecards(is_active)
                            WHERE is_active = TRUE;
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecards_default ON system.import_data_quality_scorecards(is_default)
                            WHERE is_default = TRUE;
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecards_version ON system.import_data_quality_scorecards(scorecard_id, version_number DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecards_based_on ON system.import_data_quality_scorecards(based_on_scorecard_id);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecards_metrics ON system.import_data_quality_scorecards USING GIN(metrics);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecards_weights ON system.import_data_quality_scorecards USING GIN(metric_weights);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecards_targets ON system.import_data_quality_scorecards USING GIN(target_values);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecards_metadata ON system.import_data_quality_scorecards USING GIN(metadata);

                        -- Add triggers for audit columns
                        CREATE TRIGGER trg_import_data_quality_scorecards_updated_at
                        BEFORE UPDATE ON system.import_data_quality_scorecards
                        FOR EACH ROW
                        EXECUTE FUNCTION update_updated_at_column();

                        COMMENT ON TABLE system.import_data_quality_scorecards IS 'Configuration of data quality scorecards for imported data.
                        Stores configuration details for data quality scorecards used in organizational reporting. Captures composition including metrics
                        and weightings. Supports multiple scorecard types including executive and operational reports. Includes metadata about scope and
                        frequency. Includes versioning to track changes over time. Historical data maintained for retrospective analysis. Tracks approval
                        status and audit trails for compliance. Integrates with data quality metrics system for automatic calculation. Accommodates
                        different scorecard methodologies. Centralizes scorecard configuration for consistent evaluation. Optimized for rapid lookup
                        during scorecard generation.';

                        -- Serial No: 230 | TABLE: system.import_data_quality_scorecard_results
                        -- Description: Historical results of data quality scorecard calculations for imported data
                        -- Business Case: The import_data_quality_scorecard_results table stores historical results of
                        -- data quality scorecard calculations for imported data, providing a longitudinal view of data
                        -- quality performance across the organization. It captures the calculated scores, metric values,
                        -- and trend indicators for each scorecard evaluation period, enabling trend analysis and
                        -- performance measurement. This information is critical for identifying data quality improvement
                        -- opportunities and measuring the impact of data governance initiatives over time. The table
                        -- supports multiple evaluation periods including daily, weekly, and monthly, accommodating
                        -- different reporting requirements. Each result record includes metadata about the calculation
                        -- methodology, data sources, and confidence level to ensure proper interpretation of results.
                        -- Historical result data is versioned to track changes in scorecard configurations while
                        -- maintaining historical consistency in measurement. For operational planning, the system stores
                        -- results at multiple granularities (organization-wide, departmental, system-level) to support
                        -- different management perspectives. The table integrates with the scorecard configuration
                        -- system to enable automatic recalculation of historical results when scorecard configurations
                        -- change. The design accommodates different scorecard methodologies while providing a consistent
                        -- interface for trend analysis. By centralizing scorecard results, the organization can ensure
                        -- consistent evaluation of data quality performance while providing the flexibility needed for
                        -- different reporting requirements. The table is optimized for time-series analysis of scorecard
                        -- results, supporting trend identification and predictive data quality management.
                        -- KPI: Data quality trend direction, Scorecard target achievement rate,
                        --      Data quality improvement rate, Scorecard variance identification rate,
                        --      Data quality benchmark achievement rate
                        -- Feature Reference: 1166, 1167, 1168, 1169, 1170
                        CREATE TABLE IF NOT EXISTS system.import_data_quality_scorecard_results (
                            result_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                            scorecard_id UUID NOT NULL REFERENCES system.import_data_quality_scorecards(scorecard_id),
                            evaluation_date DATE NOT NULL,
                            time_period VARCHAR(20) NOT NULL CHECK (time_period IN ('DAILY', 'WEEKLY', 'MONTHLY', 'QUARTERLY', 'YEARLY')),
                            scope_type VARCHAR(50) NOT NULL CHECK (scope_type IN ('ORGANIZATION', 'DEPARTMENT', 'SYSTEM', 'TABLE', 'COLUMN')),
                            scope_id UUID,
                            scope_name VARCHAR(200),
                            overall_score NUMERIC(5,2) CHECK (overall_score BETWEEN 0.00 AND 100.00),
                            metric_scores JSONB NOT NULL,
                            trend_indicator VARCHAR(20) NOT NULL CHECK (trend_indicator IN ('IMPROVING', 'STABLE', 'DEGRADING', 'NEW_BASELINE')),
                            trend_value NUMERIC(5,2),
                            data_quality_level VARCHAR(20) NOT NULL CHECK (data_quality_level IN ('EXCELLENT', 'GOOD', 'FAIR', 'POOR', 'CRITICAL')),
                            calculation_method VARCHAR(50) NOT NULL,
                            calculation_metadata JSONB,
                            data_source VARCHAR(100) NOT NULL,
                            data_confidence NUMERIC(4,2) NOT NULL DEFAULT 1.00 CHECK (data_confidence BETWEEN 0.00 AND 1.00),
                            notes TEXT,
                            created_by UUID NOT NULL,
                            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            updated_by UUID,
                            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            metadata JSONB
                        );

                        -- Add indexes for performance
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecard_results_scorecard ON system.import_data_quality_scorecard_results(scorecard_id);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecard_results_date ON system.import_data_quality_scorecard_results(evaluation_date, time_period);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecard_results_scope ON system.import_data_quality_scorecard_results(scope_type, scope_id);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecard_results_score ON system.import_data_quality_scorecard_results(overall_score);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_scorecard_results_trend ON system.import_data_quality_scorecard_results(trend_indicator);
