                        -- Serial No: 231 | TABLE: system.import_data_quality_alerts
                        -- Description: Configuration and tracking of data quality alerts for imported data
                        -- Business Case: The import_data_quality_alerts table manages the configuration and tracking of
                        -- data quality alerts across the workforce scheduling system for imported data, enabling
                        -- proactive identification and remediation of data issues. It captures essential information
                        -- about alert conditions, notification rules, and escalation procedures to ensure timely
                        -- response to data quality problems. The table supports multiple alert types including
                        -- threshold-based alerts, anomaly detection alerts, and trend-based alerts, accommodating
                        -- different data quality monitoring scenarios. Each alert configuration includes metadata about
                        -- its severity, notification channels, and business impact to support appropriate response
                        -- prioritization. The implementation includes robust tracking of alert history to identify
                        -- patterns in data quality issues and measure the effectiveness of remediation efforts.
                        -- Historical alert data is maintained to support root cause analysis and continuous
                        -- improvement of data quality practices. For operational efficiency, the system tracks alert
                        -- resolution times and outcomes to enable measurement of data quality team performance. The
                        -- table integrates with the notification system to enable automated alert delivery through
                        -- multiple channels including email, SMS, and in-app notifications. The design accommodates
                        -- complex alert scenarios with multi-level escalation paths and conditional notification rules,
                        -- providing detailed insights into data quality performance. By centralizing alert management,
                        -- the organization can ensure consistent response to data quality issues while providing the
                        -- flexibility needed for different business contexts. The table is optimized for rapid querying
                        -- during incident response, which often involves identifying recurring alert patterns across
                        -- multiple data domains.
                        -- KPI: Alert resolution time, False positive rate,
                        --      Alert accuracy rate, Data issue detection time,
                        --      Business impact reduction rate
                        -- Feature Reference: 1171, 1172, 1173, 1174, 1175
                        CREATE TABLE IF NOT EXISTS system.import_data_quality_alerts (
                            alert_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
                            alert_code VARCHAR(50) UNIQUE NOT NULL CHECK (alert_code ~ '^[A-Z0-9_]{3,50}$'),
                            name VARCHAR(200) NOT NULL,
                            description TEXT,
                            alert_type VARCHAR(50) NOT NULL CHECK (alert_type IN ('THRESHOLD', 'ANOMALY', 'TREND', 'COMPARISON', 'VALIDATION_RULE')),
                            metric_id UUID REFERENCES system.import_data_quality_metrics(metric_id),
                            threshold_value NUMERIC(15,6),
                            threshold_type VARCHAR(20) NOT NULL CHECK (threshold_type IN ('ABSOLUTE', 'PERCENTAGE', 'STANDARD_DEVIATION')),
                            alert_condition VARCHAR(50) NOT NULL CHECK (alert_condition IN ('GREATER_THAN', 'LESS_THAN', 'EQUAL_TO', 'NOT_EQUAL_TO', 'OUTSIDE_RANGE')),
                            alert_frequency VARCHAR(20) NOT NULL DEFAULT 'HOURLY'
                                CHECK (alert_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
                            notification_channels VARCHAR(50)[] NOT NULL DEFAULT '{"EMAIL"}'
                                CHECK (array_length(notification_channels, 1) > 0),
                            notification_recipients UUID[],
                            escalation_rules JSONB,
                            severity VARCHAR(20) NOT NULL DEFAULT 'MEDIUM'
                                CHECK (severity IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
                            business_impact JSONB,
                            is_active BOOLEAN NOT NULL DEFAULT TRUE,
                            is_muted BOOLEAN NOT NULL DEFAULT FALSE,
                            mute_until TIMESTAMP WITH TIME ZONE,
                            created_by UUID NOT NULL,
                            updated_by UUID,
                            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            metadata JSONB
                        );

                        -- Add indexes for performance
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_alerts_metric ON system.import_data_quality_alerts(metric_id)
                            WHERE metric_id IS NOT NULL;
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_alerts_type ON system.import_data_quality_alerts(alert_type);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_alerts_severity ON system.import_data_quality_alerts(severity);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_alerts_active ON system.import_data_quality_alerts(is_active)
                            WHERE is_active = TRUE;
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_alerts_muted ON system.import_data_quality_alerts(is_muted)
                            WHERE is_muted = TRUE;
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_alerts_recipients ON system.import_data_quality_alerts
                            USING GIN(notification_recipients);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_alerts_metadata ON system.import_data_quality_alerts USING GIN(metadata);

