                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_alert_history_time ON system.import_data_quality_alert_history(triggered_at DESC);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_alert_history_status ON system.import_data_quality_alert_history(status);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_alert_history_ack ON system.import_data_quality_alert_history(acknowledged_at)
