                            record_id UUID,
                            record_details JSONB,
                            detected_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            detected_by UUID REFERENCES hr.employees(employee_id),
                            status VARCHAR(20) NOT NULL DEFAULT 'OPEN'
                                CHECK (status IN ('OPEN', 'IN_PROGRESS', 'RESOLVED', 'ESCALATED', 'DUPLICATE', 'FALSE_POSITIVE', 'WONT_FIX')),
                            assigned_to UUID REFERENCES hr.employees(employee_id),
                            resolution_notes TEXT,
                            resolved_at TIMESTAMP WITH TIME ZONE,
                            resolution_steps JSONB,
                            business_impact JSONB,
                            recurrence_count INTEGER NOT NULL DEFAULT 1,
                            recurrence_pattern VARCHAR(100),
                            created_by UUID NOT NULL,
                            updated_by UUID,
                            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
                            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
