                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_communication_feedback_department ON system.import_data_quality_communication_feedback(department_id)
                            WHERE department_id IS NOT NULL;
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_communication_feedback_location ON system.import_data_quality_communication_feedback(location_id)
                            WHERE location_id IS NOT NULL;
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_communication_feedback_response ON system.import_data_quality_communication_feedback
                            USING GIN(response_json);
                        CREATE INDEX IF NOT EXISTS idx_import_data_quality_communication_feedback_metadata ON system.import_data_quality_communication_feedback
