-- Enable necessary PostgreSQL extensions
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
COMMENT ON EXTENSION "uuid-ossp" IS 'Generates universally unique identifiers (UUIDs) for distributed systems';

CREATE EXTENSION IF NOT EXISTS "pgcrypto";
COMMENT ON EXTENSION "pgcrypto" IS 'Cryptographic functions for secure data storage';

CREATE EXTENSION IF NOT EXISTS "btree_gist";
COMMENT ON EXTENSION "btree_gist" IS 'Supports GiST indexes on scalar data types for exclusion constraints';

CREATE EXTENSION IF NOT EXISTS "tablefunc";
COMMENT ON EXTENSION "tablefunc" IS 'Table functions including crosstab for pivot operations';

CREATE EXTENSION IF NOT EXISTS "timescaledb" CASCADE;
COMMENT ON EXTENSION "timescaledb" IS 'Time-series database extension for temporal data optimization';

-- 2. ENUMERATED TYPES
-- ============================================

-- Enum: Schedule status lifecycle
CREATE TYPE scheduling.schedule_status AS ENUM (
    'DRAFT',
    'PENDING_REVIEW',
    'PENDING_APPROVAL',
    'APPROVED',
    'PUBLISHED',
    'ACTIVE',
    'COMPLETED',
    'ARCHIVED',
    'CANCELLED'
);
COMMENT ON TYPE scheduling.schedule_status IS 'Defines the complete lifecycle of a schedule from creation to archival';

-- Enum: Shift types with detailed categories
CREATE TYPE scheduling.shift_category AS ENUM (
    'REGULAR',
    'OVERTIME',
    'DOUBLE',
    'HOLIDAY',
    'WEEKEND',
    'TRAINING',
    'MEETING',
    'ON_CALL',
    'STAND_BY',
    'BREAK',
    'MEAL',
    'EVENT',
    'EMERGENCY',
    'MAINTENANCE',
    'ADMINISTRATIVE'
);
COMMENT ON TYPE scheduling.shift_category IS 'Comprehensive shift type classification for accurate reporting and compliance';

-- Enum: Assignment status with workflow states
CREATE TYPE scheduling.assignment_status AS ENUM (
    'TENTATIVE',
    'ASSIGNED',
    'CONFIRMED',
    'CHECKED_IN',
    'IN_PROGRESS',
    'COMPLETED',
    'CANCELLED',
    'NO_SHOW',
    'LATE',
    'LEFT_EARLY',
    'EXCUSED_ABSENCE'
);
COMMENT ON TYPE scheduling.assignment_status IS 'Tracks the complete workflow of shift assignments from tentative to completion';

-- Enum: Approval workflow with escalation levels
CREATE TYPE scheduling.approval_workflow AS ENUM (
    'SUPERVISOR',
    'MANAGER',
    'DIRECTOR',
    'HR',
    'OPERATIONS',
    'FINANCE',
    'EXECUTIVE'
);
COMMENT ON TYPE scheduling.approval_workflow IS 'Defines hierarchical approval levels for schedule management';

-- Enum: Coverage priority levels
CREATE TYPE scheduling.coverage_priority AS ENUM (
    'CRITICAL',
    'HIGH',
    'MEDIUM',
    'LOW',
    'OPTIONAL'
);
COMMENT ON TYPE scheduling.coverage_priority IS 'Prioritizes coverage requirements based on operational criticality';

-- Enum: Compliance violation severity
CREATE TYPE scheduling.violation_severity AS ENUM (
    'MINOR',
    'MODERATE',
    'MAJOR',
    'CRITICAL',
    'COMPLIANCE_BREACH'
);
COMMENT ON TYPE scheduling.violation_severity IS 'Classifies compliance violations based on impact and regulatory implications';

-- Enum: Exception request types
CREATE TYPE scheduling.exception_type AS ENUM (
    'TIME_OFF_REQUEST',
    'SHIFT_SWAP_REQUEST',
    'SHIFT_DROP_REQUEST',
    'SHIFT_PICKUP_REQUEST',
    'SCHEDULE_MODIFICATION',
    'COVERAGE_REQUEST',
    'OVERTIME_REQUEST',
    'UNDERTIME_REQUEST',
    'FLEX_TIME_REQUEST',
    'REMOTE_WORK_REQUEST'
);
COMMENT ON TYPE scheduling.exception_type IS 'Categorizes schedule exception requests for proper routing and processing';

