-- Table 1: scheduling.schedules
-- Serial No: SCH-001
-- Description: Master table for schedule definitions with lifecycle management
-- Business Case: This table serves as the central repository for all scheduling periods,
-- enabling organizations to plan workforce allocation across departments, locations,
-- and timeframes. It supports complex scheduling scenarios including rotating shifts,
-- project-based scheduling, and seasonal variations. The table facilitates strategic
-- workforce planning by providing visibility into labor distribution, helping optimize
-- staffing costs while maintaining service levels and compliance requirements.
-- KPIs: 1. Schedule completion rate, 2. Schedule adherence percentage,
-- 3. Average schedule creation time, 4. Schedule revision frequency,
-- 5. Departmental schedule coverage ratio
-- Feature Reference: F-SCH-001, F-SCH-002, F-SCH-005, F-APP-001, F-REP-001

CREATE TABLE IF NOT EXISTS scheduling.schedules (
    schedule_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL, -- Multi-tenancy support
    schedule_code VARCHAR(50) UNIQUE NOT NULL,
    schedule_name VARCHAR(200) NOT NULL,
    schedule_version INTEGER NOT NULL DEFAULT 1,
    description TEXT,
    schedule_period_type scheduling.schedule_status NOT NULL,

    -- Temporal attributes
    planning_start_date DATE NOT NULL,
    planning_end_date DATE NOT NULL,
    execution_start_date DATE,
    execution_end_date DATE,
    effective_start_date DATE NOT NULL,
    effective_end_date DATE NOT NULL,

    -- Organizational context
    department_id UUID NOT NULL REFERENCES hr.departments(department_id),
    location_id UUID NOT NULL REFERENCES operations.locations(location_id),
    project_id UUID REFERENCES projects.master(project_id),

    -- Configuration
    is_recurring BOOLEAN NOT NULL DEFAULT FALSE,
    recurrence_pattern JSONB,
    allow_self_scheduling BOOLEAN NOT NULL DEFAULT FALSE,
    max_self_schedule_hours INTEGER DEFAULT 40,
    require_shift_confirmation BOOLEAN NOT NULL DEFAULT TRUE,
    confirmation_deadline_hours INTEGER DEFAULT 24,

    -- Status management
    status scheduling.schedule_status NOT NULL DEFAULT 'DRAFT',
    published_at TIMESTAMPTZ,
    locked_at TIMESTAMPTZ,
    archived_at TIMESTAMPTZ,

    -- Approval tracking
    current_approval_level INTEGER DEFAULT 1,
    next_approver_id UUID REFERENCES hr.employees(employee_id),

    -- Audit and version control
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    version_created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    previous_version_id UUID REFERENCES scheduling.schedules(schedule_id),

    -- Performance metrics
    total_planned_hours NUMERIC(10,2) DEFAULT 0,
    total_approved_hours NUMERIC(10,2) DEFAULT 0,
    total_worked_hours NUMERIC(10,2) DEFAULT 0,
    schedule_utilization_rate NUMERIC(5,2) DEFAULT 0,

    -- Metadata and extensibility
    tags TEXT[],
    custom_attributes JSONB,
    metadata JSONB,

    -- Constraints
    CONSTRAINT valid_date_range CHECK (effective_end_date >= effective_start_date),
    CONSTRAINT valid_planning_range CHECK (planning_end_date >= planning_start_date),
    CONSTRAINT valid_execution_range CHECK (
        execution_end_date >= execution_start_date OR
        (execution_start_date IS NULL AND execution_end_date IS NULL)
    ),
    CONSTRAINT check_schedule_code_format CHECK (schedule_code ~ '^SCH-[A-Z0-9]{3}-[0-9]{6}$'),
    CONSTRAINT max_self_schedule_hours_limit CHECK (max_self_schedule_hours BETWEEN 0 AND 80)
);

-- Indexes for schedules table
CREATE INDEX IF NOT EXISTS idx_schedules_tenant_department
ON scheduling.schedules(tenant_id, department_id);

CREATE INDEX IF NOT EXISTS idx_schedules_status_dates
ON scheduling.schedules(status, effective_start_date, effective_end_date);

CREATE INDEX IF NOT EXISTS idx_schedules_created_by_dates
ON scheduling.schedules(created_by, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_schedules_custom_attributes
ON scheduling.schedules USING GIN(custom_attributes);

CREATE INDEX IF NOT EXISTS idx_schedules_tags
ON scheduling.schedules USING GIN(tags);

-- Comments for schedules table
COMMENT ON TABLE scheduling.schedules IS 'Master schedule definitions with comprehensive lifecycle management';
COMMENT ON COLUMN scheduling.schedules.schedule_id IS 'Unique identifier for the schedule';
COMMENT ON COLUMN scheduling.schedules.tenant_id IS 'Multi-tenancy isolation identifier';
COMMENT ON COLUMN scheduling.schedules.schedule_code IS 'Business-readable schedule identifier (format: SCH-DEP-YYYYMM)';
COMMENT ON COLUMN scheduling.schedules.schedule_version IS 'Version number for schedule revisions';
COMMENT ON COLUMN scheduling.schedules.schedule_period_type IS 'Type of scheduling period (weekly, bi-weekly, monthly, custom)';
COMMENT ON COLUMN scheduling.schedules.planning_start_date IS 'Date when schedule planning begins';
COMMENT ON COLUMN scheduling.schedules.planning_end_date IS 'Date when schedule planning ends';
COMMENT ON COLUMN scheduling.schedules.effective_start_date IS 'Date when schedule becomes active';
COMMENT ON COLUMN scheduling.schedules.effective_end_date IS 'Date when schedule expires';
COMMENT ON COLUMN scheduling.schedules.is_recurring IS 'Indicates if schedule repeats according to pattern';
COMMENT ON COLUMN scheduling.schedules.allow_self_scheduling IS 'Allows employees to self-select shifts';
COMMENT ON COLUMN scheduling.schedules.schedule_utilization_rate IS 'Percentage of scheduled hours actually worked';

-- Table 2: scheduling.shifts
-- Serial No: SCH-002
-- Description: Individual shift definitions within schedules
-- Business Case: This table defines specific work shifts including timing, location,
-- position requirements, and staffing levels. It enables precise workforce allocation
-- by capturing shift-level details such as skill requirements, coverage needs, and
-- operational constraints. The table supports complex scheduling scenarios including
-- split shifts, overlapping coverage, and multi-position assignments. Real-time
-- coverage tracking helps managers identify gaps and optimize staffing decisions.
-- KPIs: 1. Shift coverage percentage, 2. Shift fill rate, 3. Average shift duration,
-- 4. Overtime shift percentage, 5. Shift cancellation rate
-- Feature Reference: F-SCH-003, F-SCH-004, F-COV-001, F-ANA-002, F-REP-002

CREATE TABLE IF NOT EXISTS scheduling.shifts (
    shift_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL,
    schedule_id UUID NOT NULL REFERENCES scheduling.schedules(schedule_id),
    shift_code VARCHAR(50) UNIQUE NOT NULL,

    -- Temporal attributes
    shift_date DATE NOT NULL,
    planned_start_time TIMESTAMPTZ NOT NULL,
    planned_end_time TIMESTAMPTZ NOT NULL,
    actual_start_time TIMESTAMPTZ,
    actual_end_time TIMESTAMPTZ,
    check_in_time TIMESTAMPTZ,
    check_out_time TIMESTAMPTZ,

    -- Operational context
    location_id UUID NOT NULL REFERENCES operations.locations(location_id),
    department_id UUID NOT NULL REFERENCES hr.departments(department_id),
    position_id UUID NOT NULL REFERENCES hr.positions(position_id),
    cost_center_id UUID REFERENCES finance.cost_centers(cost_center_id),

    -- Staffing requirements
    required_employee_count INTEGER NOT NULL DEFAULT 1,
    minimum_employee_count INTEGER NOT NULL DEFAULT 1,
    maximum_employee_count INTEGER,
    required_skill_level INTEGER CHECK (required_skill_level BETWEEN 1 AND 5),
    certification_required BOOL DEFAULT FALSE,

    -- Current staffing status
    assigned_employee_count INTEGER NOT NULL DEFAULT 0,
    confirmed_employee_count INTEGER NOT NULL DEFAULT 0,
    checked_in_employee_count INTEGER NOT NULL DEFAULT 0,

    -- Computed columns
    coverage_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
        CASE
            WHEN required_employee_count > 0
            THEN (assigned_employee_count::NUMERIC / required_employee_count * 100.0)
            ELSE 100.0
        END
    ) STORED,

    fill_rate_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
        CASE
            WHEN required_employee_count > 0
            THEN (confirmed_employee_count::NUMERIC / required_employee_count * 100.0)
            ELSE 100.0
        END
    ) STORED,

    -- Shift characteristics
    shift_category scheduling.shift_category NOT NULL DEFAULT 'REGULAR',
    is_overtime_eligible BOOLEAN NOT NULL DEFAULT FALSE,
    is_break_included BOOLEAN NOT NULL DEFAULT TRUE,
    break_duration_minutes INTEGER DEFAULT 30,
    is_meal_provided BOOLEAN DEFAULT FALSE,

    -- Financial attributes
    base_pay_rate NUMERIC(10,2),
    overtime_multiplier NUMERIC(3,2) DEFAULT 1.5,
    shift_differential NUMERIC(5,2) DEFAULT 0.00,

    -- Status and visibility
    is_open_for_bidding BOOLEAN NOT NULL DEFAULT FALSE,
    is_mandatory BOOLEAN NOT NULL DEFAULT FALSE,
    is_floating_shift BOOLEAN NOT NULL DEFAULT FALSE,
    shift_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
        CHECK (shift_status IN ('DRAFT', 'PUBLISHED', 'ACTIVE', 'IN_PROGRESS', 'COMPLETED', 'CANCELLED')),

    -- Operational constraints
    minimum_rest_hours_before INTEGER DEFAULT 10,
    maximum_consecutive_shifts INTEGER DEFAULT 5,

    -- Audit fields
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,

    -- Notes and metadata
    operational_notes TEXT,
    safety_notes TEXT,
    equipment_requirements TEXT[],
    custom_attributes JSONB,
    metadata JSONB,

    -- Constraints
    CONSTRAINT valid_shift_duration CHECK (planned_end_time > planned_start_time),
    CONSTRAINT valid_employee_counts CHECK (
        minimum_employee_count <= required_employee_count AND
        (maximum_employee_count IS NULL OR required_employee_count <= maximum_employee_count)
    ),
    CONSTRAINT valid_assigned_count CHECK (assigned_employee_count >= 0),
    CONSTRAINT check_shift_code_format CHECK (shift_code ~ '^SHF-[A-Z0-9]{3}-[0-9]{8}$'),
    CONSTRAINT valid_break_duration CHECK (break_duration_minutes BETWEEN 0 AND 120)
);

-- Indexes for shifts table
CREATE INDEX IF NOT EXISTS idx_shifts_schedule_date
ON scheduling.shifts(schedule_id, shift_date);

CREATE INDEX IF NOT EXISTS idx_shifts_location_time
ON scheduling.shifts(location_id, planned_start_time, planned_end_time);

CREATE INDEX IF NOT EXISTS idx_shifts_category_status
ON scheduling.shifts(shift_category, shift_status);

CREATE INDEX IF NOT EXISTS idx_shifts_coverage
ON scheduling.shifts(shift_date, department_id, coverage_percentage);

CREATE INDEX IF NOT EXISTS idx_shifts_fill_rate
ON scheduling.shifts(shift_date, location_id, fill_rate_percentage);

CREATE INDEX IF NOT EXISTS idx_shifts_operational_range
ON scheduling.shifts USING gist (
    tsrange(planned_start_time, planned_end_time)
);

-- Comments for shifts table
COMMENT ON TABLE scheduling.shifts IS 'Individual shift definitions with comprehensive operational details';
COMMENT ON COLUMN scheduling.shifts.shift_code IS 'Unique business identifier for shift (format: SHF-LOC-YYYYMMDD)';
COMMENT ON COLUMN scheduling.shifts.planned_start_time IS 'Scheduled start time with timezone';
COMMENT ON COLUMN scheduling.shifts.planned_end_time IS 'Scheduled end time with timezone';
COMMENT ON COLUMN scheduling.shifts.coverage_percentage IS 'Percentage of required positions currently assigned';
COMMENT ON COLUMN scheduling.shifts.fill_rate_percentage IS 'Percentage of required positions confirmed by employees';
COMMENT ON COLUMN scheduling.shifts.is_open_for_bidding IS 'Shift available for employee self-selection';

-- Table 3: scheduling.shift_assignments
-- Serial No: SCH-003
-- Description: Tracks employee assignments to specific shifts
-- Business Case: This table manages the relationship between employees and their
-- assigned shifts, providing a complete audit trail of assignment decisions.
-- It supports complex workforce management scenarios including shift swaps,
-- substitutions, and multi-employee assignments. The table enables tracking of
-- actual vs. planned work hours, supports attendance validation, and provides
-- data for labor cost allocation and productivity analysis across projects and
-- cost centers.
-- KPIs: 1. Assignment confirmation rate, 2. Shift swap success rate,
-- 3. Substitution fill time, 4. Assignment compliance score,
-- 5. Employee schedule satisfaction index
-- Feature Reference: F-ASS-001, F-ASS-002, F-ASS-003, F-APP-002, F-REP-003

CREATE TABLE IF NOT EXISTS scheduling.shift_assignments (
    assignment_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL,
    shift_id UUID NOT NULL REFERENCES scheduling.shifts(shift_id),
    employee_id UUID NOT NULL REFERENCES hr.employees(employee_id),

    -- Assignment details
    assignment_type scheduling.assignment_status NOT NULL DEFAULT 'ASSIGNED',
    assignment_reason VARCHAR(50) CHECK (assignment_reason IN (
        'REGULAR', 'OVERTIME', 'CALL_IN', 'SUBSTITUTE', 'TRAINING',
        'PROJECT', 'EMERGENCY', 'VOLUNTARY', 'MANDATORY', 'BID_WIN'
    )),
    assignment_source VARCHAR(20) NOT NULL DEFAULT 'MANAGER'
        CHECK (assignment_source IN ('MANAGER', 'SELF', 'SYSTEM', 'AUTOMATED', 'PEER')),

    -- Status tracking
    assignment_status scheduling.assignment_status NOT NULL DEFAULT 'TENTATIVE',
    status_changed_at TIMESTAMPTZ,
    status_changed_by UUID REFERENCES hr.employees(employee_id),

    -- Time tracking
    scheduled_start_time TIMESTAMPTZ NOT NULL,
    scheduled_end_time TIMESTAMPTZ NOT NULL,
    actual_start_time TIMESTAMPTZ,
    actual_end_time TIMESTAMPTZ,
    break_start_time TIMESTAMPTZ,
    break_end_time TIMESTAMPTZ,

    -- Duration calculations
    scheduled_duration_minutes INTEGER GENERATED ALWAYS AS (
        EXTRACT(EPOCH FROM (scheduled_end_time - scheduled_start_time)) / 60
    ) STORED,
    actual_duration_minutes INTEGER GENERATED ALWAYS AS (
        CASE
            WHEN actual_start_time IS NOT NULL AND actual_end_time IS NOT NULL
            THEN EXTRACT(EPOCH FROM (actual_end_time - actual_start_time)) / 60
            ELSE NULL
        END
    ) STORED,
    break_duration_minutes INTEGER GENERATED ALWAYS AS (
        CASE
            WHEN break_start_time IS NOT NULL AND break_end_time IS NOT NULL
            THEN EXTRACT(EPOCH FROM (break_end_time - break_start_time)) / 60
            ELSE 0
        END
    ) STORED,
    productive_duration_minutes INTEGER GENERATED ALWAYS AS (
        CASE
            WHEN actual_duration_minutes IS NOT NULL
            THEN actual_duration_minutes - break_duration_minutes
            ELSE NULL
        END
    ) STORED,

    -- Approval workflow
    approval_required BOOLEAN NOT NULL DEFAULT TRUE,
    approved_by UUID REFERENCES hr.employees(employee_id),
    approved_at TIMESTAMPTZ,
    approval_level scheduling.approval_workflow,
    approval_notes TEXT,

    -- Performance metrics
    punctuality_score INTEGER CHECK (punctuality_score BETWEEN 1 AND 5),
    attendance_score INTEGER CHECK (attendance_score BETWEEN 1 AND 5),
    productivity_score NUMERIC(5,2),

    -- Financial tracking
    applied_pay_rate NUMERIC(10,2) NOT NULL,
    overtime_hours NUMERIC(5,2) DEFAULT 0,
    shift_differential_hours NUMERIC(5,2) DEFAULT 0,
    special_allowance NUMERIC(10,2) DEFAULT 0,

    -- Substitution tracking
    is_substitution BOOLEAN NOT NULL DEFAULT FALSE,
    original_employee_id UUID REFERENCES hr.employees(employee_id),
    substitution_reason TEXT,

    -- Audit trail
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,

    -- Employee feedback
    employee_acknowledged BOOLEAN DEFAULT FALSE,
    acknowledged_at TIMESTAMPTZ,
    employee_notes TEXT,

    -- System tracking
    last_reminder_sent_at TIMESTAMPTZ,
    reminder_count INTEGER DEFAULT 0,

    -- Metadata
    custom_attributes JSONB,
    metadata JSONB,

    -- Constraints
    CONSTRAINT valid_actual_times CHECK (
        (actual_start_time IS NULL AND actual_end_time IS NULL) OR
        (actual_start_time IS NOT NULL AND actual_end_time IS NOT NULL AND actual_end_time >= actual_start_time)
    ),
    CONSTRAINT valid_break_times CHECK (
        (break_start_time IS NULL AND break_end_time IS NULL) OR
        (break_start_time IS NOT NULL AND break_end_time IS NOT NULL AND break_end_time >= break_start_time)
    ),
    CONSTRAINT check_productive_duration CHECK (productive_duration_minutes >= 0),
    CONSTRAINT unique_shift_employee_assignment UNIQUE(shift_id, employee_id)
        DEFERRABLE INITIALLY DEFERRED
);

-- Indexes for shift_assignments table
CREATE INDEX IF NOT EXISTS idx_assignments_employee_status
ON scheduling.shift_assignments(employee_id, assignment_status, scheduled_start_time);

CREATE INDEX IF NOT EXISTS idx_assignments_shift_status
ON scheduling.shift_assignments(shift_id, assignment_status);

CREATE INDEX IF NOT EXISTS idx_assignments_date_range
ON scheduling.shift_assignments(
    date(scheduled_start_time),
    date(scheduled_end_time)
);

CREATE INDEX IF NOT EXISTS idx_assignments_approval
ON scheduling.shift_assignments(approved_by, approved_at DESC);

CREATE INDEX IF NOT EXISTS idx_assignments_productivity
ON scheduling.shift_assignments(employee_id, productive_duration_minutes DESC);

CREATE INDEX IF NOT EXISTS idx_assignments_substitution
ON scheduling.shift_assignments(original_employee_id, is_substitution);

-- Comments for shift_assignments table
COMMENT ON TABLE scheduling.shift_assignments IS 'Tracks employee assignments to shifts with comprehensive time and performance data';
COMMENT ON COLUMN scheduling.shift_assignments.assignment_type IS 'Type of assignment (regular, overtime, substitute, etc.)';
COMMENT ON COLUMN scheduling.shift_assignments.assignment_source IS 'Source of the assignment (manager, self, system)';
COMMENT ON COLUMN scheduling.shift_assignments.productive_duration_minutes IS 'Actual working minutes excluding breaks';
COMMENT ON COLUMN scheduling.shift_assignments.punctuality_score IS 'Score for arriving on time (1-5 scale)';
COMMENT ON COLUMN scheduling.shift_assignments.is_substitution IS 'Indicates if this is a substitution assignment';


-- Table 4: scheduling.schedule_templates
CREATE TABLE IF NOT EXISTS scheduling.schedule_templates (
    template_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL,
    template_name VARCHAR(200) NOT NULL,
    template_code VARCHAR(50) UNIQUE NOT NULL,
    description TEXT,
    department_id UUID REFERENCES hr.departments(department_id),
    location_id UUID REFERENCES operations.locations(location_id),
    template_type VARCHAR(20) NOT NULL CHECK (template_type IN ('WEEKLY', 'BIWEEKLY', 'MONTHLY', 'QUARTERLY', 'ANNUAL')),
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_system_template BOOLEAN DEFAULT FALSE,
    usage_count INTEGER DEFAULT 0,
    last_used_at TIMESTAMPTZ,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB,
    CONSTRAINT check_template_code_format CHECK (template_code ~ '^TMP-[A-Z0-9]{3}-[0-9]{6}$')
);

-- Table 5: scheduling.schedule_template_details
CREATE TABLE IF NOT EXISTS scheduling.schedule_template_details (
    detail_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    template_id UUID NOT NULL REFERENCES scheduling.schedule_templates(template_id),
    day_of_week INTEGER NOT NULL CHECK (day_of_week BETWEEN 0 AND 6),
    week_number INTEGER CHECK (week_number BETWEEN 1 AND 52),
    start_time TIME NOT NULL,
    end_time TIME NOT NULL,
    position_id UUID NOT NULL,
    required_count INTEGER NOT NULL DEFAULT 1,
    skill_level_required INTEGER,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(template_id, day_of_week, week_number, start_time, position_id)
);

-- Table 6: scheduling.availability
CREATE TABLE IF NOT EXISTS scheduling.availability (
    availability_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL,
    employee_id UUID NOT NULL,
    day_of_week INTEGER NOT NULL CHECK (day_of_week BETWEEN 0 AND 6),
    start_time TIME,
    end_time TIME,
    is_available BOOLEAN NOT NULL DEFAULT TRUE,
    availability_type VARCHAR(20) NOT NULL CHECK (availability_type IN ('REGULAR', 'TEMPORARY', 'PREFERRED', 'BLOCKED')),
    priority_level INTEGER CHECK (priority_level BETWEEN 1 AND 3),
    start_date DATE,
    end_date DATE,
    reason_code VARCHAR(50),
    approved_by UUID,
    approved_at TIMESTAMPTZ,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Table 7: scheduling.shift_preferences
CREATE TABLE IF NOT EXISTS scheduling.shift_preferences (
    preference_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL,
    employee_id UUID NOT NULL,
    preference_type VARCHAR(20) NOT NULL CHECK (preference_type IN ('SHIFT_TIME', 'SHIFT_TYPE', 'LOCATION', 'TEAM', 'DAY_OFF')),
    preference_value VARCHAR(100) NOT NULL,
    preference_level INTEGER NOT NULL CHECK (preference_level BETWEEN 1 AND 5),
    effective_start_date DATE NOT NULL,
    effective_end_date DATE,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    weight_factor NUMERIC(3,2) DEFAULT 1.0,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(employee_id, preference_type, preference_value)
);

-- Table 8: scheduling.coverage_requirements
CREATE TABLE IF NOT EXISTS scheduling.coverage_requirements (
    requirement_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL,
    department_id UUID NOT NULL,
    location_id UUID NOT NULL,
    position_id UUID NOT NULL,
    day_of_week INTEGER NOT NULL CHECK (day_of_week BETWEEN 0 AND 6),
    hour_of_day INTEGER NOT NULL CHECK (hour_of_day BETWEEN 0 AND 23),
    required_count INTEGER NOT NULL DEFAULT 1,
    minimum_experience_level INTEGER,
    priority_level scheduling.coverage_priority NOT NULL DEFAULT 'MEDIUM',
    effective_start_date DATE NOT NULL,
    effective_end_date DATE,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- Table 9: scheduling.schedule_compliance
CREATE TABLE IF NOT EXISTS scheduling.schedule_compliance (
    compliance_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL,
    schedule_id UUID NOT NULL,
    rule_id UUID NOT NULL,
    violation_severity scheduling.violation_severity NOT NULL,
    violation_description TEXT NOT NULL,
    violation_details JSONB,
    affected_employees UUID[],
    affected_shifts UUID[],
    detected_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    resolved BOOLEAN NOT NULL DEFAULT FALSE,
    resolved_by UUID,
    resolved_at TIMESTAMPTZ,
    resolution_notes TEXT,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Table 10: scheduling.schedule_exceptions
CREATE TABLE IF NOT EXISTS scheduling.schedule_exceptions (
    exception_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL,
    schedule_id UUID,
    shift_id UUID,
    employee_id UUID,
    exception_type scheduling.exception_type NOT NULL,
    exception_date DATE NOT NULL,
    description TEXT NOT NULL,
    status VARCHAR(20) NOT NULL DEFAULT 'PENDING',
    requested_by UUID NOT NULL,
    requested_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    approved_by UUID,
    approved_at TIMESTAMPTZ,
    rejection_reason TEXT,
    effective_date DATE,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB
);

-- Table 11: scheduling.schedule_approvals
CREATE TABLE IF NOT EXISTS scheduling.schedule_approvals (
    approval_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL,
    schedule_id UUID NOT NULL,
    approver_id UUID NOT NULL,
    approval_level INTEGER NOT NULL,
    required_action VARCHAR(50) NOT NULL CHECK (required_action IN ('REVIEW', 'APPROVE', 'SIGN_OFF')),
    status VARCHAR(20) NOT NULL DEFAULT 'PENDING',
    comments TEXT,
    acted_at TIMESTAMPTZ,
    next_reminder_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(schedule_id, approver_id, approval_level)
);

-- Table 12: scheduling.schedule_history
CREATE TABLE IF NOT EXISTS scheduling.schedule_history (
    history_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL,
    schedule_id UUID NOT NULL,
    version_number INTEGER NOT NULL,
    change_type VARCHAR(50) NOT NULL CHECK (change_type IN (
        'CREATED', 'UPDATED', 'PUBLISHED', 'ARCHIVED',
        'APPROVED', 'REJECTED', 'ROLLED_BACK', 'COPIED'
    )),
    changed_table VARCHAR(100),
    changed_record_id UUID,
    changed_columns TEXT[],
    old_values JSONB,
    new_values JSONB,
    change_reason TEXT,
    changed_by UUID NOT NULL,
    changed_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    ip_address INET,
    user_agent TEXT
);

-- 5. COMPREHENSIVE INDEXING STRATEGY
-- ============================================

-- Composite indexes for common query patterns
CREATE INDEX IF NOT EXISTS idx_schedules_tenant_status_date
ON scheduling.schedules(tenant_id, status, effective_start_date, effective_end_date);

CREATE INDEX IF NOT EXISTS idx_shifts_tenant_location_date
ON scheduling.shifts(tenant_id, location_id, shift_date, planned_start_time);

CREATE INDEX IF NOT EXISTS idx_assignments_tenant_employee_date
ON scheduling.shift_assignments(tenant_id, employee_id, date(scheduled_start_time));

CREATE INDEX IF NOT EXISTS idx_availability_tenant_employee
ON scheduling.availability(tenant_id, employee_id, day_of_week, is_available);

-- Partial indexes for frequent filters
CREATE INDEX IF NOT EXISTS idx_shifts_active_open
ON scheduling.shifts(shift_id)
WHERE shift_status IN ('PUBLISHED', 'ACTIVE') AND is_open_for_bidding = true;

CREATE INDEX IF NOT EXISTS idx_assignments_pending_approval
ON scheduling.shift_assignments(assignment_id)
WHERE approval_required = true AND approved_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_exceptions_pending
ON scheduling.schedule_exceptions(exception_id)
WHERE status = 'PENDING';

-- GIN indexes for JSON and array columns
CREATE INDEX IF NOT EXISTS idx_schedules_metadata_gin
ON scheduling.schedules USING GIN(metadata jsonb_path_ops);

CREATE INDEX IF NOT EXISTS idx_shifts_custom_attrs_gin
ON scheduling.shifts USING GIN(custom_attributes);

CREATE INDEX IF NOT EXISTS idx_compliance_violation_details
ON scheduling.schedule_compliance USING GIN(violation_details);

-- BRIN indexes for time-series data
CREATE INDEX IF NOT EXISTS idx_shifts_time_brin
ON scheduling.shifts USING BRIN(planned_start_time, planned_end_time);

CREATE INDEX IF NOT EXISTS idx_assignments_actual_times_brin
ON scheduling.shift_assignments USING BRIN(actual_start_time, actual_end_time);


