-- Serial No: SCH-003-A | TABLE: scheduling.shift_assignments
-- Description: Tracks employee assignments to specific shifts with comprehensive workflow management
-- Business Case: Manages employee-shift relationships with complete audit trail, supporting shift swaps, 
--              substitutions, and multi-employee assignments. Enables tracking of actual vs. planned work hours,
--              attendance validation, and labor cost allocation.
-- KPI: Assignment confirmation rate, Shift fill rate, Last-minute cancellation rate, Overtime assignment percentage
-- Feature Reference: F-ASS-001, F-ASS-002, F-ASS-003, F-APP-002, F-REP-003

CREATE TABLE IF NOT EXISTS scheduling.shift_assignments (
    -- Primary identifiers
    assignment_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id UUID NOT NULL DEFAULT '11111111-1111-1111-1111-111111111111', -- Multi-tenancy support
    assignment_code VARCHAR(50) UNIQUE NOT NULL CHECK (assignment_code ~ '^ASG-[A-Z0-9]{3}-[0-9]{8}$'),
    
    -- Core relationships
    shift_id UUID NOT NULL REFERENCES scheduling.shifts(shift_id) ON DELETE CASCADE,
    employee_id UUID NOT NULL REFERENCES hr.employees(employee_id) ON DELETE CASCADE,
    
    -- Assignment details
    assignment_type VARCHAR(50) NOT NULL DEFAULT 'REGULAR' 
        CHECK (assignment_type IN ('REGULAR', 'OVERTIME', 'CALL_IN', 'SUBSTITUTE', 'TRAINING', 
                                   'PROJECT', 'EMERGENCY', 'VOLUNTARY', 'MANDATORY', 'BID_WIN', 'SWAP')),
    assignment_source VARCHAR(20) NOT NULL DEFAULT 'MANAGER'
        CHECK (assignment_source IN ('MANAGER', 'SELF', 'SYSTEM', 'AUTOMATED', 'PEER', 'API')),
    assignment_reason TEXT,
    
    -- Status tracking
    assignment_status VARCHAR(30) NOT NULL DEFAULT 'TENTATIVE'
        CHECK (assignment_status IN ('TENTATIVE', 'ASSIGNED', 'CONFIRMED', 'CHECKED_IN', 
                                     'IN_PROGRESS', 'COMPLETED', 'CANCELLED', 'NO_SHOW', 
                                     'LATE', 'LEFT_EARLY', 'EXCUSED_ABSENCE', 'PENDING_SWAP')),
    status_changed_at TIMESTAMP WITH TIME ZONE,
    status_changed_by UUID REFERENCES hr.employees(employee_id),
    
    -- Time tracking
    scheduled_start_time TIMESTAMP WITH TIME ZONE NOT NULL,
    scheduled_end_time TIMESTAMP WITH TIME ZONE NOT NULL,
    actual_start_time TIMESTAMP WITH TIME ZONE,
    actual_end_time TIMESTAMP WITH TIME ZONE,
    break_start_time TIMESTAMP WITH TIME ZONE,
    break_end_time TIMESTAMP WITH TIME ZONE,
    check_in_time TIMESTAMP WITH TIME ZONE,
    check_out_time TIMESTAMP WITH TIME ZONE,
    
    -- Approval workflow
    approval_required BOOLEAN NOT NULL DEFAULT TRUE,
    approval_level INTEGER DEFAULT 1,
    approved_by UUID REFERENCES hr.employees(employee_id),
    approved_at TIMESTAMP WITH TIME ZONE,
    approval_notes TEXT,
    
    -- Substitution tracking
    is_substitution BOOLEAN NOT NULL DEFAULT FALSE,
    original_employee_id UUID REFERENCES hr.employees(employee_id),
    substitution_reason TEXT,
    substitution_approved_by UUID REFERENCES hr.employees(employee_id),
    substitution_approved_at TIMESTAMP WITH TIME ZONE,
    
    -- Swap tracking
    swap_id UUID REFERENCES scheduling.shift_swap_requests(swap_request_id),
    is_swap BOOLEAN NOT NULL DEFAULT FALSE,
    
    -- Performance metrics (will be populated by application or triggers)
    punctuality_score INTEGER CHECK (punctuality_score BETWEEN 1 AND 5),
    attendance_score INTEGER CHECK (attendance_score BETWEEN 1 AND 5),
    productivity_score NUMERIC(3,1) CHECK (productivity_score BETWEEN 0 AND 5),
    supervisor_rating INTEGER CHECK (supervisor_rating BETWEEN 1 AND 5),
    supervisor_notes TEXT,
    rated_by UUID REFERENCES hr.employees(employee_id),
    rated_at TIMESTAMP WITH TIME ZONE,
    
    -- Financial tracking
    applied_pay_rate NUMERIC(10,2),
    overtime_hours NUMERIC(5,2) DEFAULT 0 CHECK (overtime_hours >= 0),
    overtime_multiplier NUMERIC(3,2) DEFAULT 1.5,
    shift_differential NUMERIC(5,2) DEFAULT 0,
    shift_differential_hours NUMERIC(5,2) DEFAULT 0,
    special_allowance NUMERIC(10,2) DEFAULT 0,
    
    -- Compliance tracking
    complies_with_labor_law BOOLEAN DEFAULT TRUE,
    compliance_notes TEXT,
    labor_law_exception_approved BOOLEAN DEFAULT FALSE,
    labor_law_exception_approved_by UUID REFERENCES hr.employees(employee_id),
    labor_law_exception_approved_at TIMESTAMP WITH TIME ZONE,
    
    -- Employee feedback
    employee_acknowledged BOOLEAN DEFAULT FALSE,
    acknowledged_at TIMESTAMP WITH TIME ZONE,
    employee_notes TEXT,
    employee_satisfaction_score INTEGER CHECK (employee_satisfaction_score BETWEEN 1 AND 5),
    
    -- System tracking
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    last_reminder_sent_at TIMESTAMP WITH TIME ZONE,
    reminder_count INTEGER DEFAULT 0 CHECK (reminder_count >= 0),
    version INTEGER NOT NULL DEFAULT 1,
    
    -- Metadata and extensibility
    tags TEXT[],
    custom_attributes JSONB,
    metadata JSONB,
    
    -- Constraints
    CONSTRAINT valid_actual_times CHECK (
        (actual_start_time IS NULL AND actual_end_time IS NULL) OR
        (actual_start_time IS NOT NULL AND actual_end_time IS NOT NULL AND actual_end_time >= actual_start_time)
    ),
    CONSTRAINT valid_break_times CHECK (
        (break_start_time IS NULL AND break_end_time IS NULL) OR
        (break_start_time IS NOT NULL AND break_end_time IS NOT NULL AND break_end_time >= break_start_time)
    ),
    CONSTRAINT valid_check_times CHECK (
        (check_in_time IS NULL OR (check_in_time >= scheduled_start_time - INTERVAL '2 hours')) AND
        (check_out_time IS NULL OR check_in_time IS NOT NULL)
    ),
    CONSTRAINT valid_assignment_dates CHECK (scheduled_end_time > scheduled_start_time),
    CONSTRAINT check_lateness_reason CHECK (
        (actual_start_time IS NULL OR actual_start_time <= scheduled_start_time + INTERVAL '1 minute') OR 
        (assignment_status IN ('LATE', 'LATE_ARRIVAL'))
    )
);

-- Create indexes for performance
CREATE INDEX IF NOT EXISTS idx_shift_assignments_employee 
ON scheduling.shift_assignments(employee_id, scheduled_start_time DESC);

CREATE INDEX IF NOT EXISTS idx_shift_assignments_shift 
ON scheduling.shift_assignments(shift_id);

CREATE INDEX IF NOT EXISTS idx_shift_assignments_status 
ON scheduling.shift_assignments(assignment_status, scheduled_start_time);

CREATE INDEX IF NOT EXISTS idx_shift_assignments_dates 
ON scheduling.shift_assignments(scheduled_start_time, scheduled_end_time);

CREATE INDEX IF NOT EXISTS idx_shift_assignments_approval 
ON scheduling.shift_assignments(approval_required, approved_at) 
WHERE approval_required = TRUE AND approved_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_shift_assignments_substitution 
ON scheduling.shift_assignments(original_employee_id, is_substitution) 
WHERE is_substitution = TRUE;

CREATE INDEX IF NOT EXISTS idx_shift_assignments_swap 
ON scheduling.shift_assignments(swap_id) 
WHERE swap_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_shift_assignments_compliance 
ON scheduling.shift_assignments(complies_with_labor_law) 
WHERE complies_with_labor_law = FALSE;

CREATE INDEX IF NOT EXISTS idx_shift_assignments_tenant 
ON scheduling.shift_assignments(tenant_id, scheduled_start_time);

-- Partial unique index to prevent duplicate active assignments
CREATE UNIQUE INDEX IF NOT EXISTS uq_shift_assignments_active 
ON scheduling.shift_assignments(shift_id, employee_id) 
WHERE assignment_status NOT IN ('CANCELLED', 'NO_SHOW', 'EXCUSED_ABSENCE');

-- GIN indexes for JSON and array columns
CREATE INDEX IF NOT EXISTS idx_shift_assignments_custom_attrs 
ON scheduling.shift_assignments USING GIN(custom_attributes);

CREATE INDEX IF NOT EXISTS idx_shift_assignments_tags 
ON scheduling.shift_assignments USING GIN(tags);

CREATE INDEX IF NOT EXISTS idx_shift_assignments_metadata 
ON scheduling.shift_assignments USING GIN(metadata);

-- BRIN index for time-series data
CREATE INDEX IF NOT EXISTS idx_shift_assignments_time_brin 
ON scheduling.shift_assignments USING BRIN(scheduled_start_time, scheduled_end_time);

-- Add triggers for audit columns
DROP TRIGGER IF EXISTS trg_shift_assignments_updated_at ON scheduling.shift_assignments;
CREATE TRIGGER trg_shift_assignments_updated_at
BEFORE UPDATE ON scheduling.shift_assignments
FOR EACH ROW
EXECUTE FUNCTION update_updated_at_column();

-- Add trigger for status change tracking
CREATE OR REPLACE FUNCTION scheduling.track_assignment_status_change()
RETURNS TRIGGER AS $$
BEGIN
    IF OLD.assignment_status IS DISTINCT FROM NEW.assignment_status THEN
        NEW.status_changed_at = CURRENT_TIMESTAMP;
        NEW.status_changed_by = NEW.updated_by;
        
        -- Insert into audit log
        INSERT INTO system.audit_logs (
            user_id,
            action,
            entity_type,
            entity_id,
            old_value,
            new_value,
            ip_address
        ) VALUES (
            NEW.updated_by,
            'STATUS_CHANGE',
            'shift_assignments',
            NEW.assignment_id,
            OLD.assignment_status,
            NEW.assignment_status,
            NULL
        );
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_shift_assignments_status_change ON scheduling.shift_assignments;
CREATE TRIGGER trg_shift_assignments_status_change
BEFORE UPDATE OF assignment_status ON scheduling.shift_assignments
FOR EACH ROW
EXECUTE FUNCTION scheduling.track_assignment_status_change();

-- Add trigger to validate assignment against shift capacity
CREATE OR REPLACE FUNCTION scheduling.validate_shift_capacity()
RETURNS TRIGGER AS $$
DECLARE
    v_current_assignments INTEGER;
    v_max_employees INTEGER;
BEGIN
    -- Get max employees from shift
    SELECT maximum_employee_count INTO v_max_employees
    FROM scheduling.shifts
    WHERE shift_id = NEW.shift_id;
    
    -- Count current assignments (excluding cancelled/no-show)
    SELECT COUNT(*) INTO v_current_assignments
    FROM scheduling.shift_assignments
    WHERE shift_id = NEW.shift_id
      AND assignment_status NOT IN ('CANCELLED', 'NO_SHOW', 'EXCUSED_ABSENCE');
    
    IF v_max_employees IS NOT NULL AND v_current_assignments >= v_max_employees THEN
        RAISE EXCEPTION 'Shift % has reached maximum capacity of % employees', 
                        NEW.shift_id, v_max_employees;
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_shift_assignments_capacity ON scheduling.shift_assignments;
CREATE TRIGGER trg_shift_assignments_capacity
BEFORE INSERT ON scheduling.shift_assignments
FOR EACH ROW
EXECUTE FUNCTION scheduling.validate_shift_capacity();

-- Add trigger to update shift statistics
CREATE OR REPLACE FUNCTION scheduling.update_shift_statistics()
RETURNS TRIGGER AS $$
BEGIN
    -- Update shift statistics based on assignment status
    IF TG_OP = 'INSERT' OR (TG_OP = 'UPDATE' AND OLD.assignment_status IS DISTINCT FROM NEW.assignment_status) THEN
        IF NEW.assignment_status IN ('CONFIRMED', 'ASSIGNED') THEN
            UPDATE scheduling.shifts 
            SET confirmed_employee_count = (
                SELECT COUNT(*) FROM scheduling.shift_assignments 
                WHERE shift_id = NEW.shift_id 
                AND assignment_status IN ('CONFIRMED', 'ASSIGNED')
            )
            WHERE shift_id = NEW.shift_id;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_shift_assignments_update_stats ON scheduling.shift_assignments;
CREATE TRIGGER trg_shift_assignments_update_stats
AFTER INSERT OR UPDATE OF assignment_status ON scheduling.shift_assignments
FOR EACH ROW
EXECUTE FUNCTION scheduling.update_shift_statistics();

-- Create a view for easy access to calculated fields
CREATE OR REPLACE VIEW scheduling.vw_shift_assignments_extended AS
SELECT 
    sa.*,
    -- Duration calculations
    EXTRACT(EPOCH FROM (sa.scheduled_end_time - sa.scheduled_start_time)) / 60 AS scheduled_duration_minutes,
    CASE 
        WHEN sa.actual_start_time IS NOT NULL AND sa.actual_end_time IS NOT NULL
        THEN EXTRACT(EPOCH FROM (sa.actual_end_time - sa.actual_start_time)) / 60
        ELSE NULL
    END AS actual_duration_minutes,
    CASE 
        WHEN sa.break_start_time IS NOT NULL AND sa.break_end_time IS NOT NULL
        THEN EXTRACT(EPOCH FROM (sa.break_end_time - sa.break_start_time)) / 60
        ELSE 0
    END AS break_duration_minutes,
    CASE 
        WHEN sa.actual_start_time IS NOT NULL AND sa.actual_end_time IS NOT NULL
        THEN (EXTRACT(EPOCH FROM (sa.actual_end_time - sa.actual_start_time)) / 60) - 
             COALESCE(EXTRACT(EPOCH FROM (sa.break_end_time - sa.break_start_time)) / 60, 0)
        ELSE NULL
    END AS productive_duration_minutes,
    CASE 
        WHEN sa.actual_start_time IS NOT NULL AND sa.actual_start_time > sa.scheduled_start_time
        THEN EXTRACT(EPOCH FROM (sa.actual_start_time - sa.scheduled_start_time)) / 60
        ELSE 0
    END AS lateness_minutes,
    CASE 
        WHEN sa.actual_end_time IS NOT NULL AND sa.actual_end_time < sa.scheduled_end_time
        THEN EXTRACT(EPOCH FROM (sa.scheduled_end_time - sa.actual_end_time)) / 60
        ELSE 0
    END AS early_departure_minutes,
    -- Pay calculations
    (EXTRACT(EPOCH FROM (COALESCE(sa.actual_end_time, sa.scheduled_end_time) - 
                          COALESCE(sa.actual_start_time, sa.scheduled_start_time)) / 3600 * 
     COALESCE(sa.applied_pay_rate, 0)) + 
     COALESCE(sa.overtime_hours * sa.applied_pay_rate * sa.overtime_multiplier, 0) + 
     COALESCE(sa.shift_differential_hours * sa.shift_differential, 0) + 
     COALESCE(sa.special_allowance, 0)) AS total_pay_calculated,
    -- Punctuality category
    CASE 
        WHEN sa.actual_start_time IS NULL THEN 'NO_SHOW'
        WHEN sa.actual_start_time <= sa.scheduled_start_time + INTERVAL '5 minutes' THEN 'ON_TIME'
        WHEN sa.actual_start_time <= sa.scheduled_start_time + INTERVAL '15 minutes' THEN 'SLIGHTLY_LATE'
        WHEN sa.actual_start_time <= sa.scheduled_start_time + INTERVAL '30 minutes' THEN 'LATE'
        ELSE 'VERY_LATE'
    END AS punctuality_category
FROM scheduling.shift_assignments sa;

COMMENT ON VIEW scheduling.vw_shift_assignments_extended IS 
'Extended view of shift assignments with calculated duration and pay fields';

-- Comments for the table and columns
COMMENT ON TABLE scheduling.shift_assignments IS 
'Tracks employee assignments to specific shifts with comprehensive workflow management, time tracking, and performance metrics';

COMMENT ON COLUMN scheduling.shift_assignments.assignment_id IS 'Unique identifier for the assignment (UUID)';
COMMENT ON COLUMN scheduling.shift_assignments.assignment_code IS 'Business-readable assignment code (format: ASG-DEP-YYYYMMDD-###)';
COMMENT ON COLUMN scheduling.shift_assignments.assignment_type IS 'Type of assignment (regular, overtime, substitute, etc.)';
COMMENT ON COLUMN scheduling.shift_assignments.assignment_source IS 'Source of the assignment (manager, self, system, etc.)';
COMMENT ON COLUMN scheduling.shift_assignments.assignment_status IS 'Current status in the assignment lifecycle';
COMMENT ON COLUMN scheduling.shift_assignments.is_substitution IS 'Indicates if this is a substitution for another employee';
COMMENT ON COLUMN scheduling.shift_assignments.is_swap IS 'Indicates if this assignment resulted from a shift swap';
COMMENT ON COLUMN scheduling.shift_assignments.complies_with_labor_law IS 'Whether this assignment complies with applicable labor laws';


