-- Serial No: V-001 | VIEW: scheduling.vw_employee_schedule
-- Purpose: Provides comprehensive employee schedule information with shift details and status
-- Business Case: This view consolidates schedule information for employees into a single, easy-to-query format, enabling employees and managers to view upcoming shifts, current assignments, and schedule history. It supports employee self-service portals, manager dashboards, and mobile applications by providing real-time schedule visibility. The view combines data from schedules, shifts, assignments, and employee information to present a complete picture of each employee's work schedule, including shift times, locations, positions, and current status. This centralized view reduces query complexity and ensures consistent data presentation across all user interfaces.
-- KPI: Schedule visibility rate, Self-service adoption rate, Data retrieval time
-- Feature Reference: F-SCH-001, F-UI-002, F-MOB-001
CREATE OR REPLACE VIEW scheduling.vw_employee_schedule AS
SELECT 
    e.employee_id,
    e.employee_code,
    e.first_name,
    e.last_name,
    e.preferred_name,
    s.schedule_id,
    s.schedule_code,

    sh.shift_id,
    sh.start_time AS planned_start_time,
    sh.end_time AS planned_end_time,
    sh.actual_start_time,
    sh.actual_end_time,
    EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600 AS planned_hours,
    CASE 
        WHEN sh.actual_end_time IS NOT NULL AND sh.actual_start_time IS NOT NULL 
        THEN EXTRACT(EPOCH FROM (sh.actual_end_time - sh.actual_start_time)) / 3600
        ELSE NULL
    END AS actual_hours,
    sh.shift_type AS shift_category,
    sh.shift_status,
    sh.shift_status AS assignment_status,
    sh.shift_type AS assignment_type,
    sh.created_by IS NOT NULL AS is_approved,
    l.location_name,
    l.location_code,
    l.address_line1,
    l.city,
    l.state,
    p.position_title,
    p.job_level,
    d.department_name,
    RANK() OVER (PARTITION BY e.employee_id ORDER BY sh.start_time ASC) AS shift_sequence,
    CASE 
        WHEN sh.start_time::DATE = CURRENT_DATE AND sh.start_time <= CURRENT_TIMESTAMP 
             AND (sh.actual_start_time IS NULL) THEN 'DUE'
        WHEN sh.start_time::DATE = CURRENT_DATE AND sh.start_time > CURRENT_TIMESTAMP THEN 'UPCOMING'
        WHEN sh.start_time::DATE > CURRENT_DATE THEN 'FUTURE'
        WHEN sh.start_time::DATE < CURRENT_DATE AND sh.actual_start_time IS NULL THEN 'MISSED'
        WHEN sh.actual_start_time IS NOT NULL AND sh.actual_end_time IS NULL THEN 'IN_PROGRESS'
        WHEN sh.actual_end_time IS NOT NULL THEN 'COMPLETED'
        ELSE 'UNKNOWN'
    END AS shift_status_category,
    EXTRACT(DOW FROM sh.start_time) AS day_of_week,
    EXTRACT(WEEK FROM sh.start_time) AS week_number,
    EXTRACT(MONTH FROM sh.start_time) AS month_number,
    EXTRACT(YEAR FROM sh.start_time) AS year_number
FROM hr.employees e
JOIN scheduling.shifts sh ON e.employee_id = sh.employee_id
JOIN scheduling.schedules s ON sh.schedule_id = s.schedule_id
JOIN operations.locations l ON sh.location_id = l.location_id
JOIN hr.positions p ON sh.position_id = p.position_id
JOIN hr.departments d ON sh.department_id = d.department_id
WHERE sh.shift_status NOT IN ('CANCELLED')
  AND sh.start_time >= CURRENT_DATE - INTERVAL '30 days';

COMMENT ON VIEW scheduling.vw_employee_schedule IS 
'Comprehensive employee schedule view with shift details, status categorization, and temporal attributes for filtering';



CREATE OR REPLACE VIEW scheduling.vw_employee_schedule01 AS
SELECT 
    e.employee_id,
    e.employee_code,
    e.first_name,
    e.last_name,
    e.preferred_name,
    s.schedule_id,
    s.schedule_code,
   
    sh.shift_id,

    sh.start_time AS planned_start_time,
    sh.end_time AS planned_end_time,
    sa.actual_start_time,
    sa.actual_end_time,
    EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600 AS planned_hours,
    CASE 
        WHEN sa.actual_end_time IS NOT NULL AND sa.actual_start_time IS NOT NULL 
        THEN EXTRACT(EPOCH FROM (sa.actual_end_time - sa.actual_start_time)) / 3600
        ELSE NULL
    END AS actual_hours,
    sh.shift_type AS shift_category,
    sh.shift_status,
    sa.assignment_status,
    sa.assignment_type,
    sa.approved_at IS NOT NULL AS is_approved,
    l.location_name,
    l.location_code,
    l.address_line1,
    l.city,
    l.state,
    p.position_title,
    p.job_level,
    d.department_name,
    RANK() OVER (PARTITION BY e.employee_id ORDER BY sh.start_time ASC) AS shift_sequence,
    CASE 
        WHEN sh.start_time::DATE = CURRENT_DATE AND sh.start_time <= CURRENT_TIMESTAMP 
             AND (sa.actual_start_time IS NULL) THEN 'DUE'
        WHEN sh.start_time::DATE = CURRENT_DATE AND sh.start_time > CURRENT_TIMESTAMP THEN 'UPCOMING'
        WHEN sh.start_time::DATE > CURRENT_DATE THEN 'FUTURE'
        WHEN sh.start_time::DATE < CURRENT_DATE AND sa.actual_start_time IS NULL THEN 'MISSED'
        WHEN sa.actual_start_time IS NOT NULL AND sa.actual_end_time IS NULL THEN 'IN_PROGRESS'
        WHEN sa.actual_end_time IS NOT NULL THEN 'COMPLETED'
        ELSE 'UNKNOWN'
    END AS shift_status_category,
    EXTRACT(DOW FROM sh.start_time) AS day_of_week,
    EXTRACT(WEEK FROM sh.start_time) AS week_number,
    EXTRACT(MONTH FROM sh.start_time) AS month_number,
    EXTRACT(YEAR FROM sh.start_time) AS year_number
FROM hr.employees e
JOIN scheduling.shift_assignments sa ON e.employee_id = sa.employee_id
JOIN scheduling.shifts sh ON sa.shift_id = sh.shift_id
JOIN scheduling.schedules s ON sh.schedule_id = s.schedule_id
JOIN operations.locations l ON sh.location_id = l.location_id
JOIN hr.positions p ON sh.position_id = p.position_id
JOIN hr.departments d ON sh.department_id = d.department_id
WHERE sa.assignment_status NOT IN ('CANCELLED', 'NO_SHOW')
  AND sh.start_time >= CURRENT_DATE - INTERVAL '30 days';

COMMENT ON VIEW scheduling.vw_employee_schedule IS 
'Comprehensive employee schedule view with shift details, status categorization, and temporal attributes for filtering';

-- Serial No: V-002 | VIEW: scheduling.vw_open_shifts
-- Purpose: Identifies all currently open shifts requiring assignment
-- Business Case: This view provides real-time visibility into unfilled shifts across the organization, enabling managers and employees to identify coverage gaps and self-assign to available shifts. It supports shift bidding systems, overtime management, and emergency coverage needs by highlighting shifts with critical staffing requirements. The view includes priority indicators based on coverage requirements, time remaining until shift start, and skill requirements to facilitate optimal assignment decisions.
-- KPI: Open shift fill rate, Time-to-fill open shifts, Coverage gap reduction
-- Feature Reference: F-COV-001, F-ASS-002, F-ALERT-001
CREATE OR REPLACE VIEW scheduling.vw_open_shifts AS
SELECT 
    sh.shift_id,
    sh.start_time::DATE AS shift_date,
    sh.start_time AS planned_start_time,
    sh.end_time AS planned_end_time,
    EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600 AS shift_duration_hours,
    sh.location_id,
    l.location_name,
    l.city,
    l.state,
    sh.department_id,
    d.department_name,
    sh.position_id,
    p.position_title,
    1 AS required_employee_count,
    CASE WHEN sh.employee_id IS NOT NULL THEN 1 ELSE 0 END AS assigned_employee_count,
    CASE WHEN sh.shift_status = 'CONFIRMED' THEN 1 ELSE 0 END AS confirmed_employee_count,
    1 - CASE WHEN sh.employee_id IS NOT NULL THEN 1 ELSE 0 END AS open_positions,
    CASE WHEN sh.employee_id IS NOT NULL THEN 100.0 ELSE 0.0 END AS coverage_percentage,
    CASE 
        WHEN sh.priority >= 5 THEN 'HIGH'
        WHEN sh.priority >= 0 THEN 'MEDIUM'
        ELSE 'LOW'
    END AS coverage_priority,
    sh.required_skill_level,
    sh.pay_rate_multiplier AS shift_differential,
    NULL AS base_pay_rate,
    CASE 
        WHEN sh.start_time - CURRENT_TIMESTAMP < INTERVAL '4 hours' THEN 'CRITICAL'
        WHEN sh.start_time - CURRENT_TIMESTAMP < INTERVAL '24 hours' THEN 'URGENT'
        WHEN sh.start_time - CURRENT_TIMESTAMP < INTERVAL '72 hours' THEN 'PRIORITY'
        ELSE 'STANDARD'
    END AS fill_priority,
    EXTRACT(HOUR FROM sh.start_time) AS start_hour,
    EXTRACT(DOW FROM sh.start_time) AS day_of_week,
    0 AS current_applicants
FROM scheduling.shifts sh
JOIN operations.locations l ON sh.location_id = l.location_id
JOIN hr.departments d ON sh.department_id = d.department_id
JOIN hr.positions p ON sh.position_id = p.position_id
WHERE sh.shift_status IN ('OPEN', 'ASSIGNED')
  AND sh.employee_id IS NULL
  AND sh.start_time > CURRENT_TIMESTAMP
  AND sh.start_time < CURRENT_TIMESTAMP + INTERVAL '14 days'
ORDER BY 
    CASE 
        WHEN sh.start_time - CURRENT_TIMESTAMP < INTERVAL '4 hours' THEN 1
        WHEN sh.start_time - CURRENT_TIMESTAMP < INTERVAL '24 hours' THEN 2
        WHEN sh.start_time - CURRENT_TIMESTAMP < INTERVAL '72 hours' THEN 3
        ELSE 4
    END;

COMMENT ON VIEW scheduling.vw_open_shifts IS 
'Real-time view of unfilled shifts with priority classification based on time remaining until shift start';


-- Serial No: V-003 | VIEW: scheduling.vw_shift_swap_opportunities
-- Purpose: Identifies potential shift swap matches between employees
-- Business Case: This view analyzes employee shift assignments and preferences to identify potential shift swap opportunities, facilitating employee-driven schedule flexibility while maintaining operational coverage. It matches employees who want to exchange shifts based on skills, qualifications, and shift compatibility. The view supports the shift swap request system by pre-calculating potential matches and providing recommendations to employees and managers.
-- KPI: Swap match rate, Employee satisfaction with flexibility, Manual intervention reduction
-- Feature Reference: F-SWAP-001, F-EMP-003, F-OPT-002

CREATE OR REPLACE VIEW scheduling.vw_shift_swap_opportunities AS
WITH employee_shifts AS (
    SELECT 
        sh.employee_id,
        sh.shift_id,
        sh.start_time::DATE AS shift_date,
        sh.start_time,
        sh.end_time,
        sh.position_id,
        sh.location_id,
        sh.department_id,
        sh.required_skill_level,
        ROW_NUMBER() OVER (PARTITION BY sh.employee_id ORDER BY sh.start_time) AS shift_rank
    FROM scheduling.shifts sh
    WHERE sh.employee_id IS NOT NULL
      AND sh.shift_status IN ('ASSIGNED', 'CONFIRMED')
      AND sh.start_time BETWEEN CURRENT_TIMESTAMP AND CURRENT_TIMESTAMP + INTERVAL '14 days'
),
employee_availability AS (
    SELECT 
        employee_id,
        day_of_week,
        start_time,
        end_time
    FROM scheduling.employee_availability
    WHERE is_approved = TRUE
      AND (end_date IS NULL OR end_date >= CURRENT_DATE)
)
SELECT 
    a.employee_id AS employee_a_id,
    a.shift_id AS shift_a_id,
    a.shift_date AS shift_a_date,
    a.start_time AS shift_a_start,
    b.employee_id AS employee_b_id,
    b.shift_id AS shift_b_id,
    b.shift_date AS shift_b_date,
    b.start_time AS shift_b_start,
    ABS(EXTRACT(EPOCH FROM (a.start_time - b.start_time)) / 3600) AS time_difference_hours,
    CASE 
        WHEN a.shift_date = b.shift_date THEN 'SAME_DAY'
        WHEN ABS(EXTRACT(EPOCH FROM (a.start_time - b.start_time)) / 86400) <= 1 THEN 'ADJACENT_DAY'
        ELSE 'DIFFERENT_DAY'
    END AS swap_timing,
    a.position_id,
    p.position_title,
    CASE 
        WHEN a.position_id = b.position_id THEN 'SAME_POSITION'
        ELSE 'DIFFERENT_POSITION'
    END AS position_match,
    a.location_id,
    l.location_name,
    CASE 
        WHEN a.location_id = b.location_id THEN 'SAME_LOCATION'
        ELSE 'DIFFERENT_LOCATION'
    END AS location_match,
    RANK() OVER (ORDER BY 
        CASE WHEN a.position_id = b.position_id THEN 1 ELSE 2 END,
        CASE WHEN a.location_id = b.location_id THEN 1 ELSE 2 END,
        ABS(EXTRACT(EPOCH FROM (a.start_time - b.start_time)))
    ) AS match_quality_rank
FROM employee_shifts a
JOIN employee_shifts b ON a.shift_date = b.shift_date
JOIN hr.positions p ON a.position_id = p.position_id
JOIN operations.locations l ON a.location_id = l.location_id
WHERE a.employee_id != b.employee_id
  AND a.shift_id != b.shift_id
  AND NOT EXISTS (
      SELECT 1 FROM scheduling.shift_swap_requests ssr
      WHERE (ssr.requesting_employee_id = a.employee_id 
             AND ssr.offering_shift_id = b.shift_id)
         OR (ssr.requesting_employee_id = b.employee_id 
             AND ssr.offering_shift_id = a.shift_id)
  )
  AND NOT EXISTS (
      SELECT 1 FROM scheduling.employee_availability av
      WHERE av.employee_id = a.employee_id
        AND av.day_of_week = EXTRACT(DOW FROM b.shift_date)
        AND av.is_approved = TRUE
        AND av.start_time <= b.start_time::TIME
        AND av.end_time >= b.end_time::TIME
  )
  AND NOT EXISTS (
      SELECT 1 FROM scheduling.employee_availability av
      WHERE av.employee_id = b.employee_id
        AND av.day_of_week = EXTRACT(DOW FROM a.shift_date)
        AND av.is_approved = TRUE
        AND av.start_time <= a.start_time::TIME
        AND av.end_time >= a.end_time::TIME
  );

COMMENT ON VIEW scheduling.vw_shift_swap_opportunities IS 
'Identifies potential shift swap matches between employees based on schedule compatibility and availability';

-- Serial No: V-004 | VIEW: scheduling.vw_department_coverage
-- Purpose: Provides departmental coverage analysis with skill-based metrics
-- Business Case: This view delivers comprehensive coverage analysis at the department level, enabling managers to assess staffing adequacy across different time periods and skill requirements. It combines shift data with employee skills and certifications to provide a nuanced view of coverage quality, not just quantity. The view supports strategic workforce planning by highlighting skill gaps, overstaffing, and understaffing patterns, enabling proactive recruitment and training initiatives.
-- KPI: Departmental coverage rate, Skill gap identification rate, Staffing optimization score
-- Feature Reference: F-ANA-002, F-PLAN-001, F-SKILL-003
CREATE OR REPLACE VIEW scheduling.vw_department_coverage AS
WITH time_slots AS (
    SELECT 
        generate_series(
            DATE_TRUNC('hour', CURRENT_TIMESTAMP),
            DATE_TRUNC('hour', CURRENT_TIMESTAMP + INTERVAL '7 days'),
            INTERVAL '1 hour'
        ) AS time_slot
),
actual_coverage AS (
    SELECT 
        sh.department_id,
        sh.location_id,
        sh.position_id,
        DATE_TRUNC('hour', sh.start_time) AS hour_slot,
        COUNT(DISTINCT sh.employee_id) AS employees_working,
        COUNT(DISTINCT CASE WHEN es.skill_id IS NOT NULL THEN sh.employee_id END) AS skilled_employees
    FROM scheduling.shifts sh
    LEFT JOIN hr.employee_skills es ON sh.employee_id = es.employee_id
    WHERE sh.shift_status IN ('ASSIGNED', 'CONFIRMED', 'IN_PROGRESS')
      AND sh.start_time >= CURRENT_TIMESTAMP
      AND sh.start_time < CURRENT_TIMESTAMP + INTERVAL '7 days'
    GROUP BY sh.department_id, sh.location_id, sh.position_id, DATE_TRUNC('hour', sh.start_time)
)
SELECT 
    ts.time_slot,
    ac.department_id,
    d.department_name,
    ac.location_id,
    l.location_name,
    ac.position_id,
    p.position_title,
    COALESCE(ac.employees_working, 0) AS employees_working,
    COALESCE(ac.skilled_employees, 0) AS skilled_employees,
    EXTRACT(DOW FROM ts.time_slot) AS day_of_week,
    EXTRACT(HOUR FROM ts.time_slot) AS hour_of_day,
    CURRENT_TIMESTAMP AS calculated_at
FROM time_slots ts
LEFT JOIN actual_coverage ac ON ac.hour_slot = ts.time_slot
LEFT JOIN hr.departments d ON ac.department_id = d.department_id
LEFT JOIN operations.locations l ON ac.location_id = l.location_id
LEFT JOIN hr.positions p ON ac.position_id = p.position_id
WHERE ac.department_id IS NOT NULL  -- Only show time slots that have actual coverage data
   OR ts.time_slot = DATE_TRUNC('hour', CURRENT_TIMESTAMP)  -- Include current hour even if no data
ORDER BY ts.time_slot;

COMMENT ON VIEW scheduling.vw_department_coverage IS 
'Hourly department coverage analysis showing employees working and skilled employees by time slot';

-- department coverage view 
CREATE OR REPLACE VIEW scheduling.vw_department_coverage AS
WITH time_slots AS (
    SELECT 
        generate_series(
            DATE_TRUNC('hour', CURRENT_TIMESTAMP),
            DATE_TRUNC('hour', CURRENT_TIMESTAMP + INTERVAL '7 days'),
            INTERVAL '1 hour'
        ) AS time_slot
),
all_departments AS (
    SELECT DISTINCT 
        sh.department_id,
        sh.location_id,
        sh.position_id
    FROM scheduling.shifts sh
    WHERE sh.start_time >= CURRENT_TIMESTAMP
      AND sh.start_time < CURRENT_TIMESTAMP + INTERVAL '7 days'
),
time_slot_departments AS (
    SELECT 
        ts.time_slot,
        ad.department_id,
        ad.location_id,
        ad.position_id
    FROM time_slots ts
    CROSS JOIN all_departments ad
),
actual_coverage AS (
    SELECT 
        sh.department_id,
        sh.location_id,
        sh.position_id,
        DATE_TRUNC('hour', sh.start_time) AS hour_slot,
        COUNT(DISTINCT sh.employee_id) AS employees_working,
        COUNT(DISTINCT CASE WHEN es.skill_id IS NOT NULL THEN sh.employee_id END) AS skilled_employees
    FROM scheduling.shifts sh
    LEFT JOIN hr.employee_skills es ON sh.employee_id = es.employee_id
    WHERE sh.shift_status IN ('ASSIGNED', 'CONFIRMED', 'IN_PROGRESS')
      AND sh.start_time >= CURRENT_TIMESTAMP
      AND sh.start_time < CURRENT_TIMESTAMP + INTERVAL '7 days'
    GROUP BY sh.department_id, sh.location_id, sh.position_id, DATE_TRUNC('hour', sh.start_time)
)
SELECT 
    tsd.time_slot,
    tsd.department_id,
    d.department_name,
    tsd.location_id,
    l.location_name,
    tsd.position_id,
    p.position_title,
    COALESCE(ac.employees_working, 0) AS employees_working,
    COALESCE(ac.skilled_employees, 0) AS skilled_employees,
    EXTRACT(DOW FROM tsd.time_slot) AS day_of_week,
    EXTRACT(HOUR FROM tsd.time_slot) AS hour_of_day,
    CURRENT_TIMESTAMP AS calculated_at
FROM time_slot_departments tsd
LEFT JOIN actual_coverage ac ON ac.department_id = tsd.department_id 
    AND ac.location_id = tsd.location_id 
    AND ac.position_id = tsd.position_id
    AND ac.hour_slot = tsd.time_slot
LEFT JOIN hr.departments d ON tsd.department_id = d.department_id
LEFT JOIN operations.locations l ON tsd.location_id = l.location_id
LEFT JOIN hr.positions p ON tsd.position_id = p.position_id
ORDER BY tsd.time_slot, d.department_name;

COMMENT ON VIEW scheduling.vw_department_coverage IS 
'Hourly department coverage analysis showing all departments and time slots with employee counts';


-- Analytics and Reporting Views
-- Serial No: V-005 | VIEW: analytics.vw_labor_cost_analysis
-- Purpose: Provides detailed labor cost analysis by department, position, and time period
-- Business Case: This view delivers comprehensive labor cost analytics, enabling finance and operations teams to track actual vs. budgeted labor costs, identify cost drivers, and optimize workforce spending. It integrates payroll data, shift assignments, and budget information to provide real-time visibility into labor costs across multiple dimensions. The view supports strategic decision-making around staffing levels, overtime management, and shift differential optimization.
-- KPI: Labor cost variance, Overtime percentage, Cost per productive hour
-- Feature Reference: F-FIN-001, F-BUDGET-002, F-ANA-003

CREATE OR REPLACE VIEW analytics.vw_labor_cost_analysis AS
WITH shift_costs AS (
    SELECT 
        sh.shift_id,
        sh.start_time::DATE AS shift_date,
        sh.department_id,
        sh.location_id,
        sh.position_id,
        sh.shift_type AS shift_category,
        EXTRACT(YEAR FROM sh.start_time) AS year,
        EXTRACT(MONTH FROM sh.start_time) AS month,
        EXTRACT(WEEK FROM sh.start_time) AS week,
        sh.employee_id,
        EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600 AS scheduled_hours,
        CASE 
            WHEN sh.actual_end_time IS NOT NULL AND sh.actual_start_time IS NOT NULL
            THEN EXTRACT(EPOCH FROM (sh.actual_end_time - sh.actual_start_time)) / 3600
            ELSE 0
        END AS actual_hours,
        CASE WHEN sh.shift_type = 'OVERTIME' THEN EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600 ELSE 0 END AS overtime_hours,
        sh.pay_rate_multiplier,
        COALESCE(e.hourly_rate, 15.00) AS employee_hourly_rate
    FROM scheduling.shifts sh
    LEFT JOIN hr.employees e ON sh.employee_id = e.employee_id
    WHERE sh.shift_status IN ('COMPLETED', 'IN_PROGRESS')
      AND sh.start_time >= CURRENT_DATE - INTERVAL '2 years'
)
SELECT 
    sc.year,
    sc.month,
    sc.week,
    sc.shift_date,
    sc.department_id,
    d.department_name,
    sc.location_id,
    l.location_name,
    sc.position_id,
    p.position_title,
    sc.shift_category,
    COUNT(DISTINCT sc.shift_id) AS total_shifts,
    COUNT(DISTINCT sc.employee_id) AS unique_employees,
    ROUND(SUM(sc.scheduled_hours), 2) AS total_scheduled_hours,
    ROUND(SUM(sc.actual_hours), 2) AS total_actual_hours,
    ROUND(SUM(sc.overtime_hours), 2) AS total_overtime_hours,
    ROUND((SUM(sc.overtime_hours) / NULLIF(SUM(sc.scheduled_hours), 0) * 100), 2) AS overtime_percentage,
    ROUND(SUM(sc.scheduled_hours * sc.employee_hourly_rate * sc.pay_rate_multiplier), 2) AS total_labor_cost,
    ROUND(AVG(sc.employee_hourly_rate), 2) AS avg_hourly_rate,
    ROUND(SUM(sc.scheduled_hours * sc.employee_hourly_rate * sc.pay_rate_multiplier) / 
          NULLIF(SUM(sc.scheduled_hours), 0), 2) AS avg_cost_per_hour,
    CURRENT_TIMESTAMP AS calculated_at
FROM shift_costs sc
LEFT JOIN hr.departments d ON sc.department_id = d.department_id
LEFT JOIN operations.locations l ON sc.location_id = l.location_id
LEFT JOIN hr.positions p ON sc.position_id = p.position_id
GROUP BY sc.year, sc.month, sc.week, sc.shift_date, sc.department_id, d.department_name,
         sc.location_id, l.location_name, sc.position_id, p.position_title, sc.shift_category
ORDER BY sc.year DESC, sc.month DESC, sc.week DESC;

COMMENT ON VIEW analytics.vw_labor_cost_analysis IS 
'Labor cost analytics with overtime tracking and cost-per-hour metrics based on actual shift data';

-- Serial No: V-006 | VIEW: analytics.vw_productivity_metrics
-- Purpose: Tracks employee and departmental productivity metrics over time
-- Business Case: This view provides comprehensive productivity analytics, enabling managers to identify high-performing employees and departments, optimize workforce allocation, and recognize improvement opportunities. It combines attendance data, shift assignments, and performance metrics to calculate key productivity indicators. The view supports performance management, incentive programs, and operational efficiency initiatives by providing objective, data-driven productivity measurements.
-- KPI: Productivity score, Attendance rate, Punctuality index
-- Feature Reference: F-PERF-001, F-ANA-004, F-REP-003
CREATE OR REPLACE VIEW analytics.vw_productivity_metrics AS
WITH attendance_base AS (
    SELECT 
        sh.employee_id,
        sh.shift_id,
        sh.start_time,
        sh.actual_start_time,
        sh.actual_end_time,
        sh.end_time,
        EXTRACT(EPOCH FROM (COALESCE(sh.actual_end_time, sh.end_time) - COALESCE(sh.actual_start_time, sh.start_time))) / 3600 AS hours_worked,
        sh.start_time::DATE AS shift_date,
        sh.department_id,
        sh.location_id,
        sh.position_id,
        EXTRACT(YEAR FROM sh.start_time) AS year,
        EXTRACT(MONTH FROM sh.start_time) AS month,
        EXTRACT(WEEK FROM sh.start_time) AS week
    FROM scheduling.shifts sh
    WHERE sh.employee_id IS NOT NULL
      AND sh.shift_status IN ('COMPLETED', 'IN_PROGRESS')
      AND sh.start_time >= CURRENT_DATE - INTERVAL '1 year'
),
employee_weekly AS (
    SELECT 
        employee_id,
        department_id,
        location_id,
        position_id,
        year,
        month,
        week,
        COUNT(DISTINCT shift_id) AS shifts_assigned,
        COUNT(DISTINCT CASE WHEN actual_start_time IS NOT NULL THEN shift_id END) AS shifts_attended,
        ROUND(SUM(hours_worked), 2) AS hours_worked,
        ROUND(AVG(CASE 
            WHEN actual_start_time IS NULL THEN 0
            WHEN actual_start_time <= start_time + INTERVAL '5 minutes' THEN 100 
            WHEN actual_start_time <= start_time + INTERVAL '15 minutes' THEN 80
            WHEN actual_start_time <= start_time + INTERVAL '30 minutes' THEN 60
            WHEN actual_start_time > start_time + INTERVAL '30 minutes' THEN 40
            ELSE 0 END), 2) AS punctuality_score
    FROM attendance_base
    GROUP BY employee_id, department_id, location_id, position_id, year, month, week
)
SELECT 
    ew.employee_id,
    e.employee_code,
    e.first_name,
    e.last_name,
    e.job_title,
    ew.department_id,
    d.department_name,
    ew.location_id,
    l.location_name,
    ew.position_id,
    p.position_title,
    ew.year,
    ew.month,
    ew.week,
    ew.shifts_assigned,
    ew.shifts_attended,
    ROUND((ew.shifts_attended::NUMERIC / NULLIF(ew.shifts_assigned, 0) * 100), 2) AS attendance_rate,
    ew.hours_worked,
    ew.punctuality_score,
    ROUND(AVG(ew.hours_worked) OVER (PARTITION BY ew.department_id, ew.year, ew.month), 2) AS dept_avg_hours,
    RANK() OVER (PARTITION BY ew.department_id, ew.year, ew.month ORDER BY ew.hours_worked DESC) AS hours_rank_in_dept
FROM employee_weekly ew
JOIN hr.employees e ON ew.employee_id = e.employee_id
LEFT JOIN hr.departments d ON ew.department_id = d.department_id
LEFT JOIN operations.locations l ON ew.location_id = l.location_id
LEFT JOIN hr.positions p ON ew.position_id = p.position_id
ORDER BY ew.year DESC, ew.month DESC, ew.week DESC;

COMMENT ON VIEW analytics.vw_productivity_metrics IS 
'Weekly employee productivity analytics with attendance rates and punctuality scores based on shift data';

-- Serial No: V-007 | VIEW: analytics.vw_forecast_accuracy
-- Purpose: Measures forecast accuracy against actual demand and staffing
-- Business Case: This view evaluates the accuracy of demand forecasts by comparing predicted staffing requirements with actual shift assignments and operational data. It provides critical feedback for improving forecasting models, optimizing staffing levels, and reducing labor costs. The view supports data-driven decision-making by highlighting forecast biases, seasonal patterns, and improvement opportunities.
-- KPI: Forecast accuracy percentage, Mean absolute percentage error (MAPE), Bias direction
-- Feature Reference: F-FORECAST-001, F-OPT-003, F-ANA-005
CREATE OR REPLACE VIEW analytics.vw_forecast_accuracy AS
WITH forecast_data AS (
    SELECT 
        fd.forecast_id,
        fd.location_id,
        fd.department_id,
        fd.position_id,
        fd.forecast_date,
        fd.time_period,
        fd.start_time,
        fd.end_time,
        fd.forecasted_staffing,
        fd.historical_staffing,
        fd.forecast_method,
        fd.confidence_interval_low,
        fd.confidence_interval_high,
        fd.forecast_version
    FROM analytics.forecasted_staffing fd
    WHERE fd.forecast_date >= CURRENT_DATE - INTERVAL '180 days'
),
actual_staffing AS (
    SELECT 
        sh.location_id,
        sh.department_id,
        sh.position_id,
        sh.start_time::DATE AS shift_date,
        DATE_TRUNC('hour', sh.start_time) AS hour_start,
        COUNT(DISTINCT sh.employee_id) AS actual_staff_count
    FROM scheduling.shifts sh
    WHERE sh.employee_id IS NOT NULL
      AND sh.shift_status IN ('ASSIGNED', 'CONFIRMED', 'IN_PROGRESS', 'COMPLETED')
      AND sh.start_time::DATE >= CURRENT_DATE - INTERVAL '180 days'
    GROUP BY sh.location_id, sh.department_id, sh.position_id, 
             sh.start_time::DATE, DATE_TRUNC('hour', sh.start_time)
),
traffic_actual AS (
    SELECT 
        td.location_id,
        td.date AS traffic_date,
        td.hour_of_day,
        td.traffic_count,
        td.dwell_time_minutes,
        td.conversion_rate
    FROM analytics.traffic_data td
    WHERE td.date >= CURRENT_DATE - INTERVAL '180 days'
)
SELECT 
    fd.location_id,
    l.location_name,
    fd.department_id,
    d.department_name,
    fd.position_id,
    p.position_title,
    fd.forecast_date,
    fd.time_period,
    fd.start_time,
    fd.end_time,
    fd.forecasted_staffing,
    COALESCE(ast.actual_staff_count, 0) AS actual_staffing,
    fd.historical_staffing,
    fd.forecasted_staffing - COALESCE(ast.actual_staff_count, 0) AS staffing_difference,
    ROUND(CASE 
        WHEN COALESCE(ast.actual_staff_count, 0) > 0 
        THEN ABS(fd.forecasted_staffing - COALESCE(ast.actual_staff_count, 0))::NUMERIC / 
             COALESCE(ast.actual_staff_count, 1) * 100
        ELSE NULL
    END, 2) AS absolute_percentage_error,
    ROUND(CASE 
        WHEN COALESCE(ast.actual_staff_count, 0) > 0 
        THEN (fd.forecasted_staffing - COALESCE(ast.actual_staff_count, 0))::NUMERIC / 
             COALESCE(ast.actual_staff_count, 1) * 100
        ELSE NULL
    END, 2) AS percentage_error,
    fd.forecast_method,
    fd.confidence_interval_low,
    fd.confidence_interval_high,
    CASE 
        WHEN ast.actual_staff_count IS NULL THEN 'NO_DATA'
        WHEN fd.forecasted_staffing > COALESCE(ast.actual_staff_count, 0) * 1.2 THEN 'OVER_FORECAST_HIGH'
        WHEN fd.forecasted_staffing > COALESCE(ast.actual_staff_count, 0) THEN 'OVER_FORECAST'
        WHEN fd.forecasted_staffing < COALESCE(ast.actual_staff_count, 0) * 0.8 THEN 'UNDER_FORECAST_HIGH'
        WHEN fd.forecasted_staffing < COALESCE(ast.actual_staff_count, 0) THEN 'UNDER_FORECAST'
        ELSE 'ACCURATE'
    END AS forecast_accuracy_category,
    tat.traffic_count,
    tat.dwell_time_minutes,
    tat.conversion_rate,
    ROUND(CASE 
        WHEN tat.traffic_count > 0 AND COALESCE(ast.actual_staff_count, 0) > 0
        THEN tat.traffic_count::NUMERIC / COALESCE(ast.actual_staff_count, 1)
        ELSE NULL
    END, 2) AS traffic_per_employee,
    ROUND(CASE 
        WHEN tat.traffic_count > 0 AND fd.forecasted_staffing > 0
        THEN tat.traffic_count::NUMERIC / fd.forecasted_staffing
        ELSE NULL
    END, 2) AS forecasted_traffic_per_employee
FROM forecast_data fd
JOIN operations.locations l ON fd.location_id = l.location_id
JOIN hr.departments d ON fd.department_id = d.department_id
JOIN hr.positions p ON fd.position_id = p.position_id
LEFT JOIN actual_staffing ast ON ast.location_id = fd.location_id
    AND ast.department_id = fd.department_id
    AND ast.position_id = fd.position_id
    AND ast.shift_date = fd.forecast_date
    AND ast.hour_start = fd.start_time
LEFT JOIN traffic_actual tat ON tat.location_id = fd.location_id
    AND tat.traffic_date = fd.forecast_date
    AND tat.hour_of_day = EXTRACT(HOUR FROM fd.start_time);

COMMENT ON VIEW analytics.vw_forecast_accuracy IS 
'Comprehensive forecast accuracy analysis comparing predicted vs. actual staffing with traffic correlation metrics';



-- Serial No: V-008 | VIEW: analytics.vw_turnover_risk (Fixed v2)
-- Purpose: Identifies employees at risk of turnover based on scheduling patterns and engagement metrics
-- Business Case: This view provides predictive insights into employee turnover risk by analyzing scheduling patterns, attendance behavior, shift preferences, and engagement metrics. It enables proactive retention strategies by identifying employees who may be dissatisfied or disengaged before they leave. The view supports HR initiatives, manager interventions, and workforce planning by highlighting at-risk employees and contributing factors.
-- KPI: Turnover risk score, Retention intervention rate, Voluntary turnover reduction
-- Feature Reference: F-HR-003, F-ANALYTICS-002, F-RETENTION-001

CREATE OR REPLACE VIEW analytics.vw_turnover_risk AS
WITH recent_attendance AS (
    SELECT 
        sa.employee_id,
        COUNT(DISTINCT sa.assignment_id) AS total_shifts_90d,
        COUNT(DISTINCT CASE WHEN sa.actual_start_time IS NULL THEN sa.assignment_id END) AS no_shows_90d,
        COUNT(DISTINCT CASE WHEN sa.assignment_status = 'LATE' THEN sa.assignment_id END) AS late_arrivals_90d,
        COUNT(DISTINCT CASE WHEN sa.assignment_status = 'LEFT_EARLY' THEN sa.assignment_id END) AS early_departures_90d,
        AVG(sa.punctuality_score) AS avg_punctuality_90d,
        AVG(sa.attendance_score) AS avg_attendance_90d,
        AVG(sa.productivity_score) AS avg_productivity_90d
    FROM scheduling.shift_assignments sa
    WHERE sa.scheduled_start_time >= CURRENT_DATE - INTERVAL '90 days'
    GROUP BY sa.employee_id
),
shift_preference_analysis AS (
    SELECT 
        sp.employee_id,
        -- Using priority as preference level (higher priority = more preferred)
        -- Priority range is -10 to 10
        COUNT(DISTINCT CASE WHEN sp.priority >= 5 AND a.shift_id IS NULL THEN 1 END) AS missed_preferred_shifts,
        COUNT(DISTINCT CASE WHEN sp.priority <= -5 AND a.shift_id IS NOT NULL THEN 1 END) AS assigned_unpreferred_shifts,
        COUNT(DISTINCT sp.preference_id) AS total_preferences
    FROM scheduling.shift_preferences sp
    LEFT JOIN scheduling.shift_assignments a ON a.employee_id = sp.employee_id
        AND a.scheduled_start_time >= CURRENT_DATE - INTERVAL '90 days'
    WHERE sp.is_approved = TRUE
      AND sp.start_date <= CURRENT_DATE
      AND (sp.end_date IS NULL OR sp.end_date >= CURRENT_DATE)
    GROUP BY sp.employee_id
),
time_off_patterns AS (
    SELECT 
        tor.employee_id,
        COUNT(DISTINCT tor.request_id) AS total_requests_90d,
        COUNT(DISTINCT CASE WHEN tor.status = 'REJECTED' THEN tor.request_id END) AS rejected_requests_90d,
        SUM(CASE WHEN tor.status = 'APPROVED' THEN tor.hours_requested ELSE 0 END) AS approved_time_off_hours_90d
    FROM hr.time_off_requests tor
    WHERE tor.requested_at >= CURRENT_DATE - INTERVAL '90 days'
    GROUP BY tor.employee_id
),
engagement_scores AS (
    SELECT 
        es.employee_id,
        AVG(es.overall_score) AS avg_engagement_score,
        COUNT(DISTINCT es.survey_id) AS survey_count_90d,
        AVG(es.sentiment_score) AS avg_sentiment_score
    FROM hr.employee_surveys es
    WHERE es.survey_date >= CURRENT_DATE - INTERVAL '180 days'
    GROUP BY es.employee_id
),
performance_trend AS (
    SELECT 
        pm.employee_id,
        AVG(pm.metric_value) FILTER (WHERE pm.metric_type = 'PRODUCTIVITY' 
            AND pm.measurement_period_end >= CURRENT_DATE - INTERVAL '30 days') AS recent_productivity,
        AVG(pm.metric_value) FILTER (WHERE pm.metric_type = 'PRODUCTIVITY' 
            AND pm.measurement_period_end BETWEEN CURRENT_DATE - INTERVAL '90 days' 
            AND CURRENT_DATE - INTERVAL '60 days') AS prior_productivity
    FROM analytics.performance_metrics pm
    WHERE pm.metric_type = 'PRODUCTIVITY'
    GROUP BY pm.employee_id
),
shift_swap_behavior AS (
    SELECT 
        requesting_employee_id AS employee_id,
        COUNT(*) AS total_swap_requests_90d,
        COUNT(CASE WHEN status = 'APPROVED' THEN 1 END) AS approved_swaps_90d,
        COUNT(CASE WHEN status = 'REJECTED' THEN 1 END) AS rejected_swaps_90d
    FROM scheduling.shift_swap_requests
    WHERE requested_at >= CURRENT_DATE - INTERVAL '90 days'
    GROUP BY requesting_employee_id
),
certification_status AS (
    SELECT 
        employee_id,
        COUNT(*) AS total_certifications,
        COUNT(CASE WHEN expiration_date < CURRENT_DATE + INTERVAL '30 days' THEN 1 END) AS expiring_soon,
        COUNT(CASE WHEN expiration_date < CURRENT_DATE THEN 1 END) AS expired
    FROM hr.employee_certifications
    WHERE is_active = TRUE
    GROUP BY employee_id
)
SELECT 
    e.employee_id,
    e.employee_code,
    e.first_name,
    e.last_name,
    e.job_title,
    e.hire_date,
    EXTRACT(YEAR FROM age(CURRENT_DATE, e.hire_date)) AS years_of_service,
    d.department_name,
    l.location_name,
    p.position_title,
    
    -- Attendance metrics
    COALESCE(ra.total_shifts_90d, 0) AS total_shifts_90d,
    COALESCE(ra.no_shows_90d, 0) AS no_shows_90d,
    COALESCE(ra.late_arrivals_90d, 0) AS late_arrivals_90d,
    COALESCE(ra.early_departures_90d, 0) AS early_departures_90d,
    COALESCE(ROUND((ra.no_shows_90d::NUMERIC / NULLIF(ra.total_shifts_90d, 0) * 100), 2), 0) AS no_show_percentage,
    COALESCE(ra.avg_punctuality_90d, 3.0) AS avg_punctuality,
    COALESCE(ra.avg_attendance_90d, 3.0) AS avg_attendance,
    COALESCE(ra.avg_productivity_90d, 3.0) AS avg_productivity,
    
    -- Preference metrics
    COALESCE(spa.missed_preferred_shifts, 0) AS missed_preferred_shifts,
    COALESCE(spa.assigned_unpreferred_shifts, 0) AS assigned_unpreferred_shifts,
    COALESCE(spa.total_preferences, 0) AS total_preferences,
    
    -- Time off metrics
    COALESCE(top.total_requests_90d, 0) AS time_off_requests_90d,
    COALESCE(top.rejected_requests_90d, 0) AS rejected_time_off_requests,
    COALESCE(top.approved_time_off_hours_90d, 0) AS approved_time_off_hours_90d,
    
    -- Engagement metrics
    COALESCE(es.avg_engagement_score, 3.0) AS avg_engagement_score,
    COALESCE(es.avg_sentiment_score, 0.0) AS avg_sentiment_score,
    COALESCE(es.survey_count_90d, 0) AS survey_count_90d,
    
    -- Performance trend
    COALESCE(pt.recent_productivity, 3.0) AS recent_productivity,
    COALESCE(pt.prior_productivity, 3.0) AS prior_productivity,
    ROUND(COALESCE(pt.recent_productivity, 3.0) - COALESCE(pt.prior_productivity, 3.0), 2) AS productivity_trend,
    
    -- Swap behavior
    COALESCE(ssb.total_swap_requests_90d, 0) AS total_swap_requests_90d,
    COALESCE(ssb.approved_swaps_90d, 0) AS approved_swaps_90d,
    COALESCE(ssb.rejected_swaps_90d, 0) AS rejected_swaps_90d,
    
    -- Certification status
    COALESCE(cs.total_certifications, 0) AS total_certifications,
    COALESCE(cs.expiring_soon, 0) AS certifications_expiring_soon,
    COALESCE(cs.expired, 0) AS certifications_expired,
    
    -- Calculate turnover risk score (0-100)
    ROUND((
        -- Attendance issues (max 30)
        LEAST(30, 
            (CASE WHEN COALESCE(ra.avg_attendance_90d, 3.0) < 2.5 THEN 15 ELSE 0 END) +
            (CASE WHEN COALESCE(ra.no_shows_90d, 0) > 2 THEN 10 ELSE 0 END) +
            (CASE WHEN COALESCE(ra.late_arrivals_90d, 0) > 5 THEN 5 ELSE 0 END)
        ) +
        
        -- Preference issues (max 20)
        LEAST(20,
            (CASE WHEN COALESCE(spa.missed_preferred_shifts, 0) > 3 THEN 10 ELSE 0 END) +
            (CASE WHEN COALESCE(spa.assigned_unpreferred_shifts, 0) > 5 THEN 10 ELSE 0 END)
        ) +
        
        -- Time off patterns (max 15)
        LEAST(15,
            (CASE WHEN COALESCE(top.rejected_requests_90d, 0) > 2 THEN 10 ELSE 0 END) +
            (CASE WHEN COALESCE(top.total_requests_90d, 0) > 5 THEN 5 ELSE 0 END)
        ) +
        
        -- Engagement issues (max 20)
        LEAST(20,
            (CASE WHEN COALESCE(es.avg_engagement_score, 3.0) < 2.5 THEN 15 ELSE 0 END) +
            (CASE WHEN COALESCE(es.survey_count_90d, 0) = 0 THEN 5 ELSE 0 END)
        ) +
        
        -- Performance decline (max 15)
        LEAST(15,
            (CASE WHEN COALESCE(pt.recent_productivity, 3.0) < COALESCE(pt.prior_productivity, 3.0) - 0.5 THEN 15 ELSE 0 END)
        ) +
        
        -- Swap behavior (max 10)
        LEAST(10,
            (CASE WHEN COALESCE(ssb.rejected_swaps_90d, 0) > 3 THEN 10 ELSE 0 END)
        ) +
        
        -- Certification issues (max 10)
        LEAST(10,
            (CASE WHEN COALESCE(cs.expired, 0) > 0 THEN 10 ELSE 0 END) +
            (CASE WHEN COALESCE(cs.expiring_soon, 0) > 2 THEN 5 ELSE 0 END)
        ) +
        
        -- Tenure factors (max 10)
        (CASE WHEN EXTRACT(YEAR FROM age(CURRENT_DATE, e.hire_date)) < 1 THEN 5 ELSE 0 END) +
        (CASE WHEN e.employment_status = 'PROBATION' THEN 5 ELSE 0 END)
        
    ), 2) AS turnover_risk_score,
    
    -- Risk category based on score
    CASE 
        WHEN (
            LEAST(30, (CASE WHEN COALESCE(ra.avg_attendance_90d, 3.0) < 2.5 THEN 15 ELSE 0 END) +
                      (CASE WHEN COALESCE(ra.no_shows_90d, 0) > 2 THEN 10 ELSE 0 END) +
                      (CASE WHEN COALESCE(ra.late_arrivals_90d, 0) > 5 THEN 5 ELSE 0 END)) +
            LEAST(20, (CASE WHEN COALESCE(spa.missed_preferred_shifts, 0) > 3 THEN 10 ELSE 0 END) +
                      (CASE WHEN COALESCE(spa.assigned_unpreferred_shifts, 0) > 5 THEN 10 ELSE 0 END)) +
            LEAST(15, (CASE WHEN COALESCE(top.rejected_requests_90d, 0) > 2 THEN 10 ELSE 0 END) +
                      (CASE WHEN COALESCE(top.total_requests_90d, 0) > 5 THEN 5 ELSE 0 END)) +
            LEAST(20, (CASE WHEN COALESCE(es.avg_engagement_score, 3.0) < 2.5 THEN 15 ELSE 0 END) +
                      (CASE WHEN COALESCE(es.survey_count_90d, 0) = 0 THEN 5 ELSE 0 END)) +
            LEAST(15, (CASE WHEN COALESCE(pt.recent_productivity, 3.0) < COALESCE(pt.prior_productivity, 3.0) - 0.5 THEN 15 ELSE 0 END)) +
            LEAST(10, (CASE WHEN COALESCE(ssb.rejected_swaps_90d, 0) > 3 THEN 10 ELSE 0 END)) +
            LEAST(10, (CASE WHEN COALESCE(cs.expired, 0) > 0 THEN 10 ELSE 0 END) +
                      (CASE WHEN COALESCE(cs.expiring_soon, 0) > 2 THEN 5 ELSE 0 END)) +
            (CASE WHEN EXTRACT(YEAR FROM age(CURRENT_DATE, e.hire_date)) < 1 THEN 5 ELSE 0 END) +
            (CASE WHEN e.employment_status = 'PROBATION' THEN 5 ELSE 0 END)
        ) >= 50 THEN 'HIGH'
        WHEN (
            LEAST(30, (CASE WHEN COALESCE(ra.avg_attendance_90d, 3.0) < 2.5 THEN 15 ELSE 0 END) +
                      (CASE WHEN COALESCE(ra.no_shows_90d, 0) > 2 THEN 10 ELSE 0 END) +
                      (CASE WHEN COALESCE(ra.late_arrivals_90d, 0) > 5 THEN 5 ELSE 0 END)) +
            LEAST(20, (CASE WHEN COALESCE(spa.missed_preferred_shifts, 0) > 3 THEN 10 ELSE 0 END) +
                      (CASE WHEN COALESCE(spa.assigned_unpreferred_shifts, 0) > 5 THEN 10 ELSE 0 END)) +
            LEAST(15, (CASE WHEN COALESCE(top.rejected_requests_90d, 0) > 2 THEN 10 ELSE 0 END) +
                      (CASE WHEN COALESCE(top.total_requests_90d, 0) > 5 THEN 5 ELSE 0 END)) +
            LEAST(20, (CASE WHEN COALESCE(es.avg_engagement_score, 3.0) < 2.5 THEN 15 ELSE 0 END) +
                      (CASE WHEN COALESCE(es.survey_count_90d, 0) = 0 THEN 5 ELSE 0 END)) +
            LEAST(15, (CASE WHEN COALESCE(pt.recent_productivity, 3.0) < COALESCE(pt.prior_productivity, 3.0) - 0.5 THEN 15 ELSE 0 END)) +
            LEAST(10, (CASE WHEN COALESCE(ssb.rejected_swaps_90d, 0) > 3 THEN 10 ELSE 0 END)) +
            LEAST(10, (CASE WHEN COALESCE(cs.expired, 0) > 0 THEN 10 ELSE 0 END) +
                      (CASE WHEN COALESCE(cs.expiring_soon, 0) > 2 THEN 5 ELSE 0 END)) +
            (CASE WHEN EXTRACT(YEAR FROM age(CURRENT_DATE, e.hire_date)) < 1 THEN 5 ELSE 0 END) +
            (CASE WHEN e.employment_status = 'PROBATION' THEN 5 ELSE 0 END)
        ) >= 30 THEN 'MEDIUM'
        ELSE 'LOW'
    END AS risk_category,
    
    -- Top risk factors (for quick identification)
    CASE 
        WHEN COALESCE(ra.avg_attendance_90d, 3.0) < 2.5 THEN 'Poor attendance'
        WHEN COALESCE(ra.no_shows_90d, 0) > 2 THEN 'Multiple no-shows'
        WHEN COALESCE(es.avg_engagement_score, 3.0) < 2.5 THEN 'Low engagement'
        WHEN COALESCE(pt.recent_productivity, 3.0) < COALESCE(pt.prior_productivity, 3.0) - 0.5 THEN 'Declining productivity'
        WHEN COALESCE(spa.missed_preferred_shifts, 0) > 3 THEN 'Unfulfilled preferences'
        WHEN COALESCE(top.rejected_requests_90d, 0) > 2 THEN 'Rejected time off'
        WHEN COALESCE(cs.expired, 0) > 0 THEN 'Expired certifications'
        WHEN EXTRACT(YEAR FROM age(CURRENT_DATE, e.hire_date)) < 1 THEN 'New hire'
        WHEN e.employment_status = 'PROBATION' THEN 'On probation'
        ELSE 'No primary factor'
    END AS primary_risk_factor,
    
    CURRENT_TIMESTAMP AS calculated_at
    
FROM hr.employees e
JOIN hr.departments d ON e.department_id = d.department_id
JOIN operations.locations l ON e.location_id = l.location_id
JOIN hr.positions p ON e.position_id = p.position_id
LEFT JOIN recent_attendance ra ON e.employee_id = ra.employee_id
LEFT JOIN shift_preference_analysis spa ON e.employee_id = spa.employee_id
LEFT JOIN time_off_patterns top ON e.employee_id = top.employee_id
LEFT JOIN engagement_scores es ON e.employee_id = es.employee_id
LEFT JOIN performance_trend pt ON e.employee_id = pt.employee_id
LEFT JOIN shift_swap_behavior ssb ON e.employee_id = ssb.employee_id
LEFT JOIN certification_status cs ON e.employee_id = cs.employee_id
WHERE e.employment_status IN ('ACTIVE', 'PROBATION')
ORDER BY turnover_risk_score DESC;

COMMENT ON VIEW analytics.vw_turnover_risk IS 
'Predictive turnover risk analysis combining attendance patterns, preference fulfillment, engagement scores, swap behavior, certification status, and performance trends';


-- Serial No: V-009 | VIEW: compliance.vw_labor_law_compliance (Fixed)
-- Purpose: Monitors schedule compliance with labor laws and regulations
-- Business Case: This view provides comprehensive monitoring of schedule compliance with applicable labor laws, including rest period requirements, maximum work hours, and overtime regulations. It automatically detects potential violations, calculates risk levels, and provides actionable insights for compliance management. The view supports audit preparation, risk mitigation, and proactive compliance by highlighting areas of concern before they become violations.
-- KPI: Compliance rate, Violation count by type, Remediation time
-- Feature Reference: F-COMP-001, F-AUDIT-002, F-RISK-001

CREATE OR REPLACE VIEW compliance.vw_labor_law_compliance AS
WITH employee_work_analysis AS (
    SELECT 
        sa.employee_id,
        sa.shift_id,
        sh.start_time::DATE AS shift_date,
        sh.start_time AS planned_start_time,
        sh.end_time AS planned_end_time,
        sh.actual_start_time,
        sh.actual_end_time,
        EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 60 AS scheduled_duration_minutes,
        CASE 
            WHEN sh.actual_start_time IS NOT NULL AND sh.actual_end_time IS NOT NULL
            THEN EXTRACT(EPOCH FROM (sh.actual_end_time - sh.actual_start_time)) / 60
            ELSE NULL
        END AS actual_duration_minutes,
        CASE 
            WHEN sh.actual_start_time IS NOT NULL AND sh.actual_end_time IS NOT NULL
            THEN (EXTRACT(EPOCH FROM (sh.actual_end_time - sh.actual_start_time)) / 60) - 
                 COALESCE(EXTRACT(EPOCH FROM (sa.break_end_time - sa.break_start_time)) / 60, 0)
            ELSE NULL
        END AS productive_duration_minutes,
        EXTRACT(EPOCH FROM (sh.start_time - LAG(sh.end_time) 
            OVER (PARTITION BY sa.employee_id ORDER BY sh.start_time))) / 3600 AS hours_since_previous_shift,
        COUNT(*) OVER (PARTITION BY sa.employee_id, sh.start_time::DATE) AS shifts_on_day,
        SUM(EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 60) OVER (PARTITION BY sa.employee_id, sh.start_time::DATE) / 60.0 AS daily_hours,
        SUM(EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 60) OVER (PARTITION BY sa.employee_id, DATE_TRUNC('week', sh.start_time)) / 60.0 AS weekly_hours
    FROM scheduling.shift_assignments sa
    JOIN scheduling.shifts sh ON sa.shift_id = sh.shift_id
    WHERE sa.assignment_status IN ('CONFIRMED', 'IN_PROGRESS', 'COMPLETED')
      AND sh.start_time >= CURRENT_DATE - INTERVAL '30 days'
),
employee_position_data AS (
    SELECT 
        e.employee_id,
        e.employee_code,
        e.first_name,
        e.last_name,
        e.position_id,
        p.job_level,
        p.overtime_eligible,
        p.position_title,
        e.department_id,
        d.department_name,
        e.location_id,
        l.location_name,
        l.country_code,
        l.region
    FROM hr.employees e
    JOIN hr.positions p ON e.position_id = p.position_id
    JOIN hr.departments d ON e.department_id = d.department_id
    JOIN operations.locations l ON e.location_id = l.location_id
)
SELECT 
    epd.employee_id,
    epd.employee_code,
    epd.first_name,
    epd.last_name,
    epd.position_title,
    epd.department_name,
    epd.location_name,
    epd.country_code,
    epd.region,
    ewa.shift_date,
    ewa.shifts_on_day,
    ROUND(ewa.daily_hours, 2) AS daily_hours,
    ROUND(ewa.weekly_hours, 2) AS weekly_hours,
    ROUND(ewa.hours_since_previous_shift, 2) AS hours_since_previous_shift,
    ROUND(ewa.actual_duration_minutes, 2) AS actual_duration_minutes,
    ROUND(ewa.productive_duration_minutes, 2) AS productive_duration_minutes,
    ll.law_id,
    ll.title AS law_title,
    ll.law_type,
    ll.jurisdiction,
    ll.severity AS law_severity,
    
    -- Determine violation type
    CASE 
        WHEN ewa.daily_hours > 12 THEN 'EXCEEDS_MAX_DAILY_HOURS'
        WHEN ewa.weekly_hours > 60 THEN 'EXCEEDS_MAX_WEEKLY_HOURS'
        WHEN ewa.hours_since_previous_shift < 8 AND ewa.hours_since_previous_shift > 0 THEN 'INSUFFICIENT_REST_PERIOD'
        WHEN ewa.shifts_on_day > 2 THEN 'EXCEEDS_MAX_SHIFTS_PER_DAY'
        WHEN ewa.actual_duration_minutes > 720 AND NOT epd.overtime_eligible THEN 'UNAUTHORIZED_OVERTIME'
        ELSE NULL
    END AS potential_violation_type,
    
    -- Calculate violation magnitude
    CASE 
        WHEN ewa.daily_hours > 12 THEN ROUND(ewa.daily_hours - 12, 2)
        WHEN ewa.weekly_hours > 60 THEN ROUND(ewa.weekly_hours - 60, 2)
        WHEN ewa.hours_since_previous_shift < 8 AND ewa.hours_since_previous_shift > 0 THEN ROUND(8 - ewa.hours_since_previous_shift, 2)
        WHEN ewa.shifts_on_day > 2 THEN ewa.shifts_on_day - 2
        ELSE 0
    END AS violation_magnitude,
    
    -- Calculate severity
    CASE 
        WHEN ewa.daily_hours > 12 THEN 'CRITICAL'
        WHEN ewa.weekly_hours > 60 THEN 'HIGH'
        WHEN ewa.hours_since_previous_shift < 8 AND ewa.hours_since_previous_shift > 4 THEN 'MEDIUM'
        WHEN ewa.hours_since_previous_shift < 4 AND ewa.hours_since_previous_shift > 0 THEN 'HIGH'
        WHEN ewa.shifts_on_day > 2 THEN 'MEDIUM'
        WHEN ewa.actual_duration_minutes > 720 AND NOT epd.overtime_eligible THEN 'MEDIUM'
        ELSE NULL
    END AS calculated_severity,
    
    -- Determine compliance status
    CASE 
        WHEN sc.compliance_id IS NOT NULL THEN 'DETECTED'
        WHEN ll.law_id IS NOT NULL AND 
            ((ewa.daily_hours > 12 AND ll.law_type = 'NATIONAL') OR
             (ewa.weekly_hours > 60 AND ll.law_type = 'NATIONAL')) THEN 'PENDING_REVIEW'
        WHEN (ewa.daily_hours > 8 OR ewa.weekly_hours > 40 OR ewa.hours_since_previous_shift < 8) 
             AND ll.law_id IS NULL THEN 'NEEDS_LAW_CHECK'
        ELSE 'COMPLIANT'
    END AS compliance_status,
    
    CURRENT_TIMESTAMP AS assessed_at
    
FROM employee_work_analysis ewa
JOIN employee_position_data epd ON ewa.employee_id = epd.employee_id
LEFT JOIN compliance.labor_laws ll ON ll.country_code = epd.country_code
    AND (ll.region IS NULL OR ll.region = epd.region)
    AND ll.is_active = TRUE
    AND ll.effective_date <= ewa.shift_date
    AND (ll.expiration_date IS NULL OR ll.expiration_date >= ewa.shift_date)
LEFT JOIN scheduling.schedule_compliance sc ON sc.schedule_id = ewa.shift_id
    AND sc.rule_id = ll.law_id
    AND sc.entity_id = ewa.employee_id
WHERE (ewa.daily_hours > 8 OR ewa.weekly_hours > 40 OR ewa.hours_since_previous_shift < 8)
ORDER BY ewa.shift_date DESC, calculated_severity DESC NULLS LAST;

COMMENT ON VIEW compliance.vw_labor_law_compliance IS 
'Comprehensive labor law compliance monitoring with automated violation detection and risk assessment';

-- ============================================================================
-- Table: scheduling.shift_requirements
-- Purpose: Defines required employee counts for shifts by position
-- Business Case: Enables accurate staffing requirements tracking for union 
--                compliance, seniority-based scheduling, and workload distribution
-- ============================================================================
-- Drop and recreate with correct UUID types
-- DROP TABLE IF EXISTS scheduling.shift_requirements CASCADE;

CREATE TABLE scheduling.shift_requirements (
    requirement_id      UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    shift_id            UUID NOT NULL,
    position_id         UUID NOT NULL,  -- FIXED: Changed from INTEGER to UUID
    required_count      INTEGER NOT NULL DEFAULT 1,
    minimum_count       INTEGER DEFAULT 0,
    maximum_count       INTEGER,
    shift_type          VARCHAR(50),
    effective_date      DATE NOT NULL DEFAULT CURRENT_DATE,
    expiration_date     DATE,
    is_active           BOOLEAN NOT NULL DEFAULT TRUE,
    created_by          UUID,           -- FIXED: Changed to UUID for consistency
    created_at          TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by          UUID,           -- FIXED: Changed to UUID for consistency
    updated_at          TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- Constraints
    CONSTRAINT chk_required_count_positive 
        CHECK (required_count > 0),
    CONSTRAINT chk_minimum_not_greater_than_required 
        CHECK (minimum_count <= required_count),
    CONSTRAINT chk_maximum_not_less_than_required 
        CHECK (maximum_count IS NULL OR maximum_count >= required_count),
    CONSTRAINT chk_dates_valid 
        CHECK (expiration_date IS NULL OR expiration_date >= effective_date)
);

-- Indexes
CREATE INDEX idx_shift_requirements_shift_id 
    ON scheduling.shift_requirements(shift_id);

CREATE INDEX idx_shift_requirements_position_id 
    ON scheduling.shift_requirements(position_id);

CREATE INDEX idx_shift_requirements_effective_date 
    ON scheduling.shift_requirements(effective_date);

CREATE INDEX idx_shift_requirements_active 
    ON scheduling.shift_requirements(is_active) 
    WHERE is_active = TRUE;

CREATE UNIQUE INDEX idx_shift_requirements_unique_active 
    ON scheduling.shift_requirements(shift_id, position_id, effective_date)
    WHERE is_active = TRUE;

-- Foreign Keys
ALTER TABLE scheduling.shift_requirements
    ADD CONSTRAINT fk_shift_requirements_shift
    FOREIGN KEY (shift_id) 
    REFERENCES scheduling.shifts(shift_id)
    ON DELETE CASCADE;

ALTER TABLE scheduling.shift_requirements
    ADD CONSTRAINT fk_shift_requirements_position
    FOREIGN KEY (position_id) 
    REFERENCES hr.positions(position_id)
    ON DELETE RESTRICT;

-- Trigger for updated_at
CREATE OR REPLACE FUNCTION scheduling.update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_shift_requirements_updated_at
    BEFORE UPDATE ON scheduling.shift_requirements
    FOR EACH ROW
    EXECUTE FUNCTION scheduling.update_updated_at_column();

COMMENT ON TABLE scheduling.shift_requirements IS 
'Stores required employee counts for shifts by position, supporting union compliance and staffing planning';

-- Serial No: V-010 | VIEW: compliance.vw_union_agreement_compliance (Fixed v8)
-- Purpose: Ensures scheduling practices comply with union agreements
-- Business Case: This view monitors compliance with collective bargaining agreements and union rules, including seniority-based scheduling, work distribution, and union-specific provisions. It provides real-time visibility into potential union agreement violations, enabling proactive resolution and reducing the risk of grievances. The view supports labor relations management by ensuring equitable treatment of union members and adherence to negotiated terms.
-- KPI: Union rule compliance rate, Seniority-based assignment accuracy, Grievance prevention rate
-- Feature Reference: F-UNION-001, F-COMP-002, F-LABOR-003

CREATE OR REPLACE VIEW compliance.vw_union_agreement_compliance AS
WITH employee_union_status AS (
    SELECT 
        e.employee_id,
        e.employee_code,
        e.first_name,
        e.last_name,
        e.hire_date,
        e.position_id,
        p.position_title,
        e.department_id,
        d.department_name,
        e.location_id,
        l.location_name,
        CASE 
            WHEN e.hire_date <= CURRENT_DATE - INTERVAL '5 years' THEN 'SENIOR'
            WHEN e.hire_date <= CURRENT_DATE - INTERVAL '2 years' THEN 'MID_LEVEL'
            ELSE 'JUNIOR'
        END AS seniority_level,
        RANK() OVER (PARTITION BY e.department_id, e.position_id ORDER BY e.hire_date ASC) AS seniority_rank_in_dept
    FROM hr.employees e
    JOIN hr.positions p ON e.position_id = p.position_id
    JOIN hr.departments d ON e.department_id = d.department_id
    JOIN operations.locations l ON e.location_id = l.location_id
    WHERE e.employment_status IN ('ACTIVE', 'PROBATION')
),
-- NEW: Calculate shift assignment counts from shift_assignments table
shift_assignment_counts AS (
    SELECT 
        shift_id,
        COUNT(*) AS total_assigned,
        COUNT(*) FILTER (WHERE assignment_status = 'CONFIRMED') AS confirmed_count,
        COUNT(*) FILTER (WHERE assignment_status = 'ASSIGNED') AS assigned_count
    FROM scheduling.shift_assignments
    WHERE assignment_status IN ('ASSIGNED', 'CONFIRMED')
    GROUP BY shift_id
),
shift_assignments_with_seniority AS (
    SELECT 
        sa.assignment_id,
        sa.shift_id,
        sa.employee_id,
        sa.assignment_type,
        sh.start_time::DATE AS shift_date,
        sh.start_time AS planned_start_time,
        sh.end_time AS planned_end_time,
        sh.position_id,
        sh.department_id,
        sh.location_id,
        -- FIXED: Get required_count from shift_requirements, fallback to calculated counts
        COALESCE(sr.required_count, sac.total_assigned, 1) AS required_employee_count,
        sac.assigned_count,
        sac.confirmed_count,
        eus.seniority_level,
        eus.seniority_rank_in_dept,
        RANK() OVER (PARTITION BY sh.shift_id ORDER BY eus.seniority_rank_in_dept) AS seniority_rank_for_shift,
        COUNT(*) OVER (PARTITION BY sh.shift_id) AS total_assigned_for_shift
    FROM scheduling.shift_assignments sa
    JOIN scheduling.shifts sh ON sa.shift_id = sh.shift_id
    JOIN employee_union_status eus ON sa.employee_id = eus.employee_id
    LEFT JOIN shift_assignment_counts sac ON sh.shift_id = sac.shift_id
    LEFT JOIN scheduling.shift_requirements sr ON sh.shift_id = sr.shift_id
        AND sr.position_id = sh.position_id
        AND sr.is_active = TRUE
        AND (sr.expiration_date IS NULL OR sr.expiration_date >= CURRENT_DATE)
    WHERE sa.assignment_status IN ('ASSIGNED', 'CONFIRMED')
      AND sh.start_time::DATE >= CURRENT_DATE - INTERVAL '60 days'
),
union_rules_analysis AS (
    SELECT 
        ur.rule_id,
        ur.title AS rule_title,
        ur.rule_type,
        ur.jurisdiction,
        ur.applies_to_positions,
        ur.applies_to_locations,
        ur.applies_to_departments,
        ur.rule_expression,
        ur.severity,
        ur.enforcement_level
    FROM compliance.union_rules ur
    WHERE ur.is_active = TRUE
      AND ur.effective_date <= CURRENT_DATE
      AND (ur.expiration_date IS NULL OR ur.expiration_date >= CURRENT_DATE)
),
eligible_employees_for_shift AS (
    SELECT 
        sh.shift_id,
        sh.start_time::DATE AS shift_date,
        sh.department_id,
        sh.location_id,
        sh.position_id,
        -- FIXED: Use COALESCE for required count
        COALESCE(sr.required_count, sac.total_assigned, 1) AS required_employee_count,
        eus.employee_id,
        eus.seniority_rank_in_dept,
        RANK() OVER (PARTITION BY sh.shift_id ORDER BY eus.seniority_rank_in_dept) AS eligible_rank
    FROM scheduling.shifts sh
    CROSS JOIN employee_union_status eus
    LEFT JOIN shift_assignment_counts sac ON sh.shift_id = sac.shift_id
    LEFT JOIN scheduling.shift_requirements sr ON sh.shift_id = sr.shift_id
        AND sr.position_id = sh.position_id
        AND sr.is_active = TRUE
        AND (sr.expiration_date IS NULL OR sr.expiration_date >= CURRENT_DATE)
    WHERE eus.department_id = sh.department_id
      AND eus.location_id = sh.location_id
      AND eus.position_id = sh.position_id
      AND sh.start_time::DATE >= CURRENT_DATE - INTERVAL '60 days'
      AND NOT EXISTS (
          SELECT 1 FROM scheduling.employee_availability ea
          WHERE ea.employee_id = eus.employee_id
            AND ea.day_of_week = EXTRACT(DOW FROM sh.start_time)
            AND ea.is_approved = TRUE
            AND ea.availability_type = 'UNAVAILABLE'
      )
),
shift_employee_counts AS (
    SELECT 
        shift_id,
        COUNT(*) AS total_assignments,
        COUNT(DISTINCT employee_id) AS unique_employees
    FROM scheduling.shift_assignments
    WHERE assignment_status NOT IN ('CANCELLED', 'NO_SHOW')
    GROUP BY shift_id
)
SELECT 
    sa.shift_id,
      sa.shift_date,
    sa.department_id,
    d.department_name,
    sa.location_id,
    l.location_name,
    sa.position_id,
    p.position_title,
    sa.required_employee_count AS positions_required,
    COALESCE(sec.total_assignments, 0) AS current_assignments,
    sa.employee_id,
    eus.employee_code,
    eus.first_name,
    eus.last_name,
    eus.seniority_level,
    eus.seniority_rank_in_dept,
    sa.seniority_rank_for_shift,
    
    -- Determine if this employee should have been considered for the shift based on seniority
    CASE 
        WHEN efs.eligible_rank <= sa.required_employee_count THEN 'SHOULD_BE_CONSIDERED'
        WHEN efs.eligible_rank > sa.required_employee_count THEN 'BEYOND_REQUIRED_COUNT'
        ELSE 'NOT_ELIGIBLE'
    END AS eligibility_status,
    
    -- Assignment status by seniority
    CASE 
        WHEN sa.seniority_rank_for_shift <= sa.required_employee_count THEN 'ASSIGNED_WITHIN_SENIORITY_RANGE'
        WHEN sa.seniority_rank_for_shift > sa.required_employee_count THEN 'ASSIGNED_BEYOND_SENIORITY_RANGE'
        ELSE 'ASSIGNED'
    END AS assignment_status_by_seniority,
    
    -- Check if any higher-seniority employee was available but not assigned
    CASE 
        WHEN EXISTS (
            SELECT 1 FROM eligible_employees_for_shift efs2
            WHERE efs2.shift_id = sa.shift_id
              AND efs2.eligible_rank <= sa.required_employee_count
              AND efs2.employee_id NOT IN (
                  SELECT employee_id FROM scheduling.shift_assignments sa2
                  WHERE sa2.shift_id = sa.shift_id
                    AND sa2.assignment_status IN ('ASSIGNED', 'CONFIRMED')
              )
        ) THEN 'HIGHER_SENIORITY_AVAILABLE'
        ELSE 'SENIORITY_RESPECTED'
    END AS seniority_compliance_check,
    
    ura.rule_id,
    ura.rule_title,
    ura.rule_type,
    ura.severity AS rule_severity,
    
    -- Determine compliance status
    CASE 
        WHEN ura.rule_type = 'SENIORITY' AND EXISTS (
            SELECT 1 FROM eligible_employees_for_shift efs2
            WHERE efs2.shift_id = sa.shift_id
              AND efs2.eligible_rank <= sa.required_employee_count
              AND efs2.employee_id NOT IN (
                  SELECT employee_id FROM scheduling.shift_assignments sa2
                  WHERE sa2.shift_id = sa.shift_id
                    AND sa2.assignment_status IN ('ASSIGNED', 'CONFIRMED')
              )
        ) THEN 'VIOLATION'
        WHEN ura.rule_type = 'SENIORITY' AND sa.seniority_rank_for_shift > sa.required_employee_count THEN 'EXCEPTION_REQUIRED'
        WHEN ura.rule_type = 'WORKLOAD' AND sa.assignment_type = 'OVERTIME' AND eus.seniority_level = 'JUNIOR' THEN 'PREFERRED'
        WHEN ura.rule_type = 'WORKLOAD' AND sa.assignment_type = 'OVERTIME' AND eus.seniority_level != 'JUNIOR' THEN 'REVIEW_REQUIRED'
        ELSE 'COMPLIANT'
    END AS compliance_status,
    
    CASE 
        WHEN sc.compliance_id IS NOT NULL THEN 'VIOLATION_LOGGED'
        ELSE 'NO_VIOLATION'
    END AS violation_logged_status,
    
    CURRENT_TIMESTAMP AS assessed_at
    
FROM shift_assignments_with_seniority sa
JOIN scheduling.shifts sh ON sa.shift_id = sh.shift_id
JOIN employee_union_status eus ON sa.employee_id = eus.employee_id
JOIN hr.departments d ON sa.department_id = d.department_id
JOIN operations.locations l ON sa.location_id = l.location_id
JOIN hr.positions p ON sa.position_id = p.position_id
LEFT JOIN eligible_employees_for_shift efs ON efs.shift_id = sa.shift_id AND efs.employee_id = sa.employee_id
LEFT JOIN shift_employee_counts sec ON sa.shift_id = sec.shift_id
LEFT JOIN union_rules_analysis ura ON (
    (ura.applies_to_positions IS NULL OR p.position_id = ANY(ura.applies_to_positions)) AND
    (ura.applies_to_locations IS NULL OR l.location_id = ANY(ura.applies_to_locations)) AND
    (ura.applies_to_departments IS NULL OR d.department_id = ANY(ura.applies_to_departments))
)
LEFT JOIN scheduling.schedule_compliance sc ON sc.schedule_id = sh.schedule_id
    AND sc.rule_id = ura.rule_id
    AND sc.entity_id = sa.employee_id
WHERE ura.rule_type IN ('SENIORITY', 'WORKLOAD') OR ura.rule_type IS NULL
ORDER BY sa.shift_date DESC, d.department_name, p.position_title, eus.seniority_rank_in_dept;

COMMENT ON VIEW compliance.vw_union_agreement_compliance IS 
'Union agreement compliance monitoring with seniority-based assignment validation and rule-specific violation detection';


ALTER TABLE scheduling.shifts 
ADD COLUMN minimum_employee_count INTEGER,
ADD COLUMN maximum_employee_count INTEGER;

COMMENT ON COLUMN scheduling.shifts.minimum_employee_count IS 'Minimum number of employees needed (optional)';
COMMENT ON COLUMN scheduling.shifts.maximum_employee_count IS 'Maximum number of employees allowed (optional)';

-- Add constraint to ensure min <= max if both are set
ALTER TABLE scheduling.shifts 
ADD CONSTRAINT chk_shift_employee_counts 
CHECK (
    (minimum_employee_count IS NULL OR maximum_employee_count IS NULL) OR
    (minimum_employee_count <= maximum_employee_count)
);

ALTER TABLE scheduling.shifts 
ADD COLUMN required_employee_count INTEGER NOT NULL DEFAULT 1 
CHECK (required_employee_count >= 0);

COMMENT ON COLUMN scheduling.shifts.required_employee_count IS 'Number of employees required for this shift';

ALTER TABLE scheduling.shifts 
ADD COLUMN shift_code VARCHAR(50) UNIQUE;

COMMENT ON COLUMN scheduling.shifts.shift_code IS 'Business-friendly shift code (e.g., SHF-001)';

-- Serial No: V-010 | VIEW: compliance.vw_union_agreement_compliance (Final with no shift_code)
-- Purpose: Ensures scheduling practices comply with union agreements
-- Business Case: This view monitors compliance with collective bargaining agreements and union rules,
-- including seniority-based scheduling, work distribution, and union-specific provisions.
-- It provides real-time visibility into potential union agreement violations, enabling proactive resolution
-- and reducing the risk of grievances. The view supports labor relations management by ensuring equitable
-- treatment of union members and adherence to negotiated terms.
-- KPI: Union rule compliance rate, Seniority-based assignment accuracy, Grievance prevention rate
-- Feature Reference: F-UNION-001, F-COMP-002, F-LABOR-003
-- Drop the existing view if it exists
DROP VIEW IF EXISTS compliance.vw_union_agreement_compliance;

-- Recreate the view with the corrected definition (no shift_code column)
CREATE OR REPLACE VIEW compliance.vw_union_agreement_compliance AS
WITH employee_union_status AS (
    SELECT 
        e.employee_id,
        e.employee_code,
        e.first_name,
        e.last_name,
        e.hire_date,
        e.position_id,
        p.position_title,
        e.department_id,
        d.department_name,
        e.location_id,
        l.location_name,
        CASE 
            WHEN e.hire_date <= CURRENT_DATE - INTERVAL '5 years' THEN 'SENIOR'
            WHEN e.hire_date <= CURRENT_DATE - INTERVAL '2 years' THEN 'MID_LEVEL'
            ELSE 'JUNIOR'
        END AS seniority_level,
        RANK() OVER (ORDER BY e.hire_date ASC) AS seniority_rank
    FROM hr.employees e
    JOIN hr.positions p ON e.position_id = p.position_id
    JOIN hr.departments d ON e.department_id = d.department_id
    JOIN operations.locations l ON e.location_id = l.location_id
    WHERE e.employment_status IN ('ACTIVE', 'PROBATION')
),
shift_assignments_with_seniority AS (
    SELECT 
        sa.assignment_id,
        sa.shift_id,
        sa.employee_id,
        sa.assignment_type,
        sh.start_time::DATE AS shift_date,
        sh.start_time AS planned_start_time,
        sh.end_time AS planned_end_time,
        sh.position_id,
        sh.department_id,
        sh.location_id,
        sh.required_employee_count,
        eus.seniority_level,
        eus.seniority_rank,
        RANK() OVER (PARTITION BY sh.shift_id ORDER BY eus.seniority_rank) AS seniority_rank_for_shift,
        COUNT(*) OVER (PARTITION BY sh.shift_id) AS total_assigned_for_shift
    FROM scheduling.shift_assignments sa
    JOIN scheduling.shifts sh ON sa.shift_id = sh.shift_id
    JOIN employee_union_status eus ON sa.employee_id = eus.employee_id
    WHERE sa.assignment_status IN ('ASSIGNED', 'CONFIRMED')
      AND sh.start_time::DATE >= CURRENT_DATE - INTERVAL '60 days'
),
union_rules_analysis AS (
    SELECT 
        ur.rule_id,
        ur.title AS rule_title,
        ur.rule_type,
        ur.jurisdiction,
        ur.applies_to_positions,
        ur.applies_to_locations,
        ur.applies_to_departments,
        ur.rule_expression,
        ur.severity,
        ur.enforcement_level
    FROM compliance.union_rules ur
    WHERE ur.is_active = TRUE
      AND ur.effective_date <= CURRENT_DATE
      AND (ur.expiration_date IS NULL OR ur.expiration_date >= CURRENT_DATE)
),
all_eligible_employees AS (
    SELECT 
        sh.shift_id,
        sh.start_time::DATE AS shift_date,
        sh.department_id,
        sh.location_id,
        sh.position_id,
        eus.employee_id,
        eus.seniority_rank,
        RANK() OVER (PARTITION BY sh.shift_id ORDER BY eus.seniority_rank) AS eligible_rank
    FROM scheduling.shifts sh
    CROSS JOIN employee_union_status eus
    WHERE eus.department_id = sh.department_id
      AND eus.location_id = sh.location_id
      AND eus.position_id = sh.position_id
      AND sh.start_time::DATE >= CURRENT_DATE - INTERVAL '60 days'
      AND NOT EXISTS (
          SELECT 1 FROM scheduling.employee_availability ea
          WHERE ea.employee_id = eus.employee_id
            AND ea.day_of_week = EXTRACT(DOW FROM sh.start_time)
            AND ea.is_approved = TRUE
            AND ea.availability_type = 'UNAVAILABLE'
      )
)
SELECT 
    sa.shift_id,
    sa.shift_date,
    sa.department_id,
    d.department_name,
    sa.location_id,
    l.location_name,
    sa.position_id,
    p.position_title,
    sa.required_employee_count AS positions_required,
    sa.total_assigned_for_shift AS current_assignments,
    sa.employee_id,
    eus.employee_code,
    eus.first_name,
    eus.last_name,
    eus.seniority_level,
    eus.seniority_rank,
    sa.seniority_rank_for_shift,
    CASE 
        WHEN sa.seniority_rank_for_shift <= sa.total_assigned_for_shift THEN 'ASSIGNED_WITHIN_SENIORITY_ORDER'
        WHEN sa.seniority_rank_for_shift > sa.total_assigned_for_shift THEN 'ASSIGNED_OUTSIDE_SENIORITY_ORDER'
        ELSE 'ASSIGNED'
    END AS assignment_status_by_seniority,
    CASE 
        WHEN EXISTS (
            SELECT 1 FROM all_eligible_employees aee
            WHERE aee.shift_id = sa.shift_id
              AND aee.eligible_rank <= sa.total_assigned_for_shift
              AND aee.employee_id NOT IN (
                  SELECT employee_id FROM scheduling.shift_assignments sa2
                  WHERE sa2.shift_id = sa.shift_id
                    AND sa2.assignment_status IN ('ASSIGNED', 'CONFIRMED')
              )
        ) THEN 'HIGHER_SENIORITY_AVAILABLE'
        ELSE 'SENIORITY_RESPECTED'
    END AS seniority_compliance_check,
    ura.rule_id,
    ura.rule_title,
    ura.rule_type,
    ura.severity AS rule_severity,
    CASE 
        WHEN ura.rule_type = 'SENIORITY' AND EXISTS (
            SELECT 1 FROM all_eligible_employees aee
            WHERE aee.shift_id = sa.shift_id
              AND aee.eligible_rank <= sa.total_assigned_for_shift
              AND aee.employee_id NOT IN (
                  SELECT employee_id FROM scheduling.shift_assignments sa2
                  WHERE sa2.shift_id = sa.shift_id
                    AND sa2.assignment_status IN ('ASSIGNED', 'CONFIRMED')
              )
        ) THEN 'POTENTIAL_VIOLATION'
        WHEN ura.rule_type = 'WORKLOAD' AND sa.assignment_type = 'OVERTIME' AND eus.seniority_level = 'JUNIOR' THEN 'PREFERRED_DISTRIBUTION'
        WHEN ura.rule_type = 'WORKLOAD' AND sa.assignment_type = 'OVERTIME' AND eus.seniority_level != 'JUNIOR' THEN 'REVIEW_REQUIRED'
        ELSE 'COMPLIANT'
    END AS compliance_status,
    CASE 
        WHEN sc.compliance_id IS NOT NULL THEN 'VIOLATION_LOGGED'
        ELSE 'NO_VIOLATION'
    END AS violation_logged_status,
    CURRENT_TIMESTAMP AS assessed_at
FROM shift_assignments_with_seniority sa
JOIN scheduling.shifts sh ON sa.shift_id = sh.shift_id
JOIN employee_union_status eus ON sa.employee_id = eus.employee_id
JOIN hr.departments d ON sa.department_id = d.department_id
JOIN operations.locations l ON sa.location_id = l.location_id
JOIN hr.positions p ON sa.position_id = p.position_id
LEFT JOIN union_rules_analysis ura ON (
    (ura.applies_to_positions IS NULL OR p.position_id = ANY(ura.applies_to_positions)) AND
    (ura.applies_to_locations IS NULL OR l.location_id = ANY(ura.applies_to_locations)) AND
    (ura.applies_to_departments IS NULL OR d.department_id = ANY(ura.applies_to_departments))
)
LEFT JOIN scheduling.schedule_compliance sc ON sc.schedule_id = sh.schedule_id
    AND sc.rule_id = ura.rule_id
    AND sc.entity_id = sa.employee_id
WHERE ura.rule_type IN ('SENIORITY', 'WORKLOAD')
ORDER BY sa.shift_date DESC, d.department_name, p.position_title, eus.seniority_rank;

COMMENT ON VIEW compliance.vw_union_agreement_compliance IS 
'Union agreement compliance monitoring with seniority-based assignment validation and rule-specific violation detection';



-- =============================================================================
-- DATABASE ROLE CREATION
-- =============================================================================
-- Purpose: Create all required database roles for the workforce scheduling system
-- Business Case: Proper role-based access control (RBAC) is essential for security
--          and compliance. These roles define access levels for different user types.
-- =============================================================================

-- Create roles if they don't exist (PostgreSQL 15+)
DO $$
BEGIN
    -- Reporting role - Read-only access to reports and analytics
    IF NOT EXISTS (SELECT FROM pg_catalog.pg_roles WHERE rolname = 'reporting_role') THEN
        CREATE ROLE reporting_role WITH LOGIN NOSUPERUSER NOCREATEDB NOCREATEROLE;
        RAISE NOTICE 'Created role: reporting_role';
    ELSE
        RAISE NOTICE 'Role reporting_role already exists';
    END IF;
    
    -- Manager role - Read access plus some write permissions for their department
    IF NOT EXISTS (SELECT FROM pg_catalog.pg_roles WHERE rolname = 'manager_role') THEN
        CREATE ROLE manager_role WITH LOGIN NOSUPERUSER NOCREATEDB NOCREATEROLE;
        RAISE NOTICE 'Created role: manager_role';
    ELSE
        RAISE NOTICE 'Role manager_role already exists';
    END IF;
    
    -- Admin role - Full administrative access
    IF NOT EXISTS (SELECT FROM pg_catalog.pg_roles WHERE rolname = 'admin_role') THEN
        CREATE ROLE admin_role WITH LOGIN NOSUPERUSER NOCREATEDB NOCREATEROLE;
        RAISE NOTICE 'Created role: admin_role';
    ELSE
        RAISE NOTICE 'Role admin_role already exists';
    END IF;
    
    -- Scheduler role - For automated scheduling processes
    IF NOT EXISTS (SELECT FROM pg_catalog.pg_roles WHERE rolname = 'scheduler_role') THEN
        CREATE ROLE scheduler_role WITH LOGIN NOSUPERUSER NOCREATEDB NOCREATEROLE;
        RAISE NOTICE 'Created role: scheduler_role';
    ELSE
        RAISE NOTICE 'Role scheduler_role already exists';
    END IF;
    
    -- HR role - Human resources specific access
    IF NOT EXISTS (SELECT FROM pg_catalog.pg_roles WHERE rolname = 'hr_role') THEN
        CREATE ROLE hr_role WITH LOGIN NOSUPERUSER NOCREATEDB NOCREATEROLE;
        RAISE NOTICE 'Created role: hr_role';
    ELSE
        RAISE NOTICE 'Role hr_role already exists';
    END IF;
    
    -- Finance role - Financial data access
    IF NOT EXISTS (SELECT FROM pg_catalog.pg_roles WHERE rolname = 'finance_role') THEN
        CREATE ROLE finance_role WITH LOGIN NOSUPERUSER NOCREATEDB NOCREATEROLE;
        RAISE NOTICE 'Created role: finance_role';
    ELSE
        RAISE NOTICE 'Role finance_role already exists';
    END IF;
END
$$;

-- Grant basic connection privileges
GRANT CONNECT ON DATABASE focuspguser TO reporting_role, manager_role, admin_role, scheduler_role, hr_role, finance_role;


-- =============================================================================
-- SCHEMA PERMISSIONS
-- =============================================================================

-- Create schema if not exists
CREATE SCHEMA IF NOT EXISTS performance;

-- Grant usage on schemas
GRANT USAGE ON SCHEMA scheduling TO reporting_role, manager_role, admin_role, scheduler_role, hr_role, finance_role;
GRANT USAGE ON SCHEMA hr TO reporting_role, manager_role, admin_role, scheduler_role, hr_role, finance_role;
GRANT USAGE ON SCHEMA operations TO reporting_role, manager_role, admin_role, scheduler_role, hr_role, finance_role;
GRANT USAGE ON SCHEMA analytics TO reporting_role, manager_role, admin_role, scheduler_role, hr_role, finance_role;
GRANT USAGE ON SCHEMA finance TO reporting_role, manager_role, admin_role, scheduler_role, hr_role, finance_role;
GRANT USAGE ON SCHEMA compliance TO reporting_role, manager_role, admin_role, scheduler_role, hr_role, finance_role;
GRANT USAGE ON SCHEMA performance TO reporting_role, manager_role, admin_role, scheduler_role, hr_role, finance_role;
GRANT USAGE ON SCHEMA system TO admin_role, scheduler_role;
GRANT USAGE ON SCHEMA security TO admin_role;
GRANT USAGE ON SCHEMA data_governance TO admin_role, reporting_role;

-- =============================================================================
-- Serial No: MV-011 | MATERIALIZED VIEW: performance.mv_schedule_efficiency
-- =============================================================================
-- Purpose: Measures schedule efficiency metrics including utilization, adherence, 
--          and cost effectiveness
-- Business Case: This materialized view provides comprehensive schedule efficiency 
--          metrics, enabling operations managers to optimize staffing levels, 
--          reduce labor costs, and improve productivity.
-- KPI: Schedule utilization rate, Labor efficiency ratio, Schedule adherence percentage
-- Feature Reference: F-PERF-002, F-OPT-001, F-ANA-006
-- Dependencies: scheduling.shifts, scheduling.shift_assignments, hr.employees, 
--               hr.departments, operations.locations, finance.budgets
-- Refresh Strategy: Daily refresh during off-peak hours
-- =============================================================================

-- Drop existing materialized view if exists
DROP MATERIALIZED VIEW IF EXISTS performance.mv_schedule_efficiency CASCADE;

-- Create the materialized view
CREATE MATERIALIZED VIEW performance.mv_schedule_efficiency AS
WITH shift_metrics AS (
    SELECT
        sh.shift_id,
        sh.schedule_id,
        sh.department_id,
        sh.location_id,
        sh.position_id,
        sh.start_time::DATE AS shift_date,
        sh.start_time AS planned_start_time,
        sh.end_time AS planned_end_time,
        EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600 
            AS planned_shift_hours,
        sh.shift_type AS shift_category,
        sh.shift_status,
        COALESCE(sh.required_employee_count, 1) AS required_employee_count
    FROM scheduling.shifts sh
    WHERE sh.start_time >= CURRENT_TIMESTAMP - INTERVAL '90 days'
),
assignment_metrics AS (
    SELECT
        sa.assignment_id,
        sa.shift_id,
        sa.employee_id,
        sa.assignment_status,
        sa.scheduled_start_time,
        sa.scheduled_end_time,
        sa.actual_start_time,
        sa.actual_end_time,
        sa.break_start_time,
        sa.break_end_time,
        EXTRACT(EPOCH FROM (sa.scheduled_end_time - sa.scheduled_start_time)) / 3600 
            AS scheduled_hours,
        CASE
            WHEN sa.actual_start_time IS NOT NULL AND sa.actual_end_time IS NOT NULL
            THEN EXTRACT(EPOCH FROM (sa.actual_end_time - sa.actual_start_time)) / 3600
            ELSE 0
        END AS actual_hours,
        CASE
            WHEN sa.actual_start_time IS NOT NULL 
            THEN EXTRACT(EPOCH FROM (sa.actual_start_time - sa.scheduled_start_time)) / 60
            ELSE 0
        END AS lateness_minutes,
        COALESCE(e.hourly_rate, 0) AS employee_hourly_rate,
        COALESCE(sa.applied_pay_rate, e.hourly_rate, 0) AS applied_pay_rate,
        COALESCE(sa.overtime_hours, 0) AS overtime_hours
    FROM scheduling.shift_assignments sa
    LEFT JOIN hr.employees e ON sa.employee_id = e.employee_id
    WHERE sa.scheduled_start_time >= CURRENT_TIMESTAMP - INTERVAL '90 days'
),
department_budgets AS (
    SELECT
        b.department_id,
        b.location_id,
        b.position_id,
        DATE_TRUNC('month', b.start_date) AS budget_month,
        SUM(b.amount) AS budgeted_amount,
        SUM(b.actual_amount) AS actual_amount
    FROM finance.budgets b
    WHERE b.budget_type IN ('OPERATIONAL', 'DEPARTMENT')
    AND b.start_date >= CURRENT_DATE - INTERVAL '90 days'
    GROUP BY b.department_id, b.location_id, b.position_id, 
             DATE_TRUNC('month', b.start_date)
)
SELECT
    sm.shift_date,
    DATE_TRUNC('week', sm.shift_date) AS week_start,
    DATE_TRUNC('month', sm.shift_date) AS month_start,
    sm.department_id,
    d.department_name,
    sm.location_id,
    l.location_name,
    sm.position_id,
    p.position_title,
    sm.shift_category,
    
    -- Shift Coverage Metrics
    COUNT(DISTINCT sm.shift_id) AS total_shifts,
    SUM(sm.required_employee_count) AS total_required_positions,
    COUNT(DISTINCT am.employee_id) AS unique_employees_assigned,
    COUNT(DISTINCT CASE WHEN am.assignment_status IN ('CONFIRMED', 'ASSIGNED') 
                        THEN am.shift_id END) AS filled_shifts,
    
    -- Coverage Percentage
    ROUND(
        COUNT(DISTINCT CASE WHEN am.assignment_status IN ('CONFIRMED', 'ASSIGNED') 
                            THEN am.shift_id END)::NUMERIC / 
        NULLIF(COUNT(DISTINCT sm.shift_id), 0) * 100, 2
    ) AS shift_fill_rate_percentage,
    
    -- Hours Metrics
    ROUND(SUM(sm.planned_shift_hours * sm.required_employee_count), 2) 
        AS total_planned_hours,
    ROUND(SUM(am.actual_hours), 2) AS total_actual_hours,
    ROUND(SUM(am.scheduled_hours), 2) AS total_scheduled_hours,
    
    -- Utilization Rate (Actual vs Planned)
    ROUND(
        SUM(am.actual_hours)::NUMERIC / 
        NULLIF(SUM(sm.planned_shift_hours * sm.required_employee_count), 0) * 100, 2
    ) AS schedule_utilization_rate,
    
    -- Adherence Metrics
    ROUND(AVG(CASE WHEN am.lateness_minutes <= 15 THEN 100 
                   WHEN am.lateness_minutes <= 30 THEN 80 
                   WHEN am.lateness_minutes <= 60 THEN 60 
                   ELSE 40 END), 2) AS adherence_score,
    ROUND(AVG(am.lateness_minutes), 2) AS avg_lateness_minutes,
    COUNT(DISTINCT CASE WHEN am.lateness_minutes > 15 THEN am.employee_id END) 
        AS late_employees_count,
    
    -- Overtime Metrics
    ROUND(SUM(am.overtime_hours), 2) AS total_overtime_hours,
    ROUND(
        SUM(am.overtime_hours)::NUMERIC / 
        NULLIF(SUM(am.actual_hours), 0) * 100, 2
    ) AS overtime_percentage,
    
    -- Cost Metrics
    ROUND(SUM(am.actual_hours * am.applied_pay_rate), 2) AS total_labor_cost,
    ROUND(SUM(am.overtime_hours * am.applied_pay_rate * 1.5), 2) AS overtime_cost,
    ROUND(
        SUM(am.actual_hours * am.applied_pay_rate)::NUMERIC / 
        NULLIF(SUM(am.actual_hours), 0), 2
    ) AS avg_cost_per_hour,
    
    -- Budget Comparison
    COALESCE(MAX(db.budgeted_amount), 0) AS monthly_budget,
    COALESCE(MAX(db.actual_amount), 0) AS monthly_actual,
    ROUND(
        (COALESCE(MAX(db.actual_amount), 0) - COALESCE(MAX(db.budgeted_amount), 0))::NUMERIC / 
        NULLIF(COALESCE(MAX(db.budgeted_amount), 1), 0) * 100, 2
    ) AS budget_variance_percentage,
    
    -- Efficiency Ratios
    ROUND(
        COUNT(DISTINCT am.employee_id)::NUMERIC / 
        NULLIF(SUM(sm.required_employee_count), 0), 2
    ) AS labor_efficiency_ratio,
    
    -- Status Distribution
    COUNT(DISTINCT CASE WHEN am.assignment_status = 'CONFIRMED' THEN am.assignment_id END) 
        AS confirmed_assignments,
    COUNT(DISTINCT CASE WHEN am.assignment_status = 'NO_SHOW' THEN am.assignment_id END) 
        AS no_show_count,
    COUNT(DISTINCT CASE WHEN am.assignment_status = 'CANCELLED' THEN am.assignment_id END) 
        AS cancelled_count,
    
    CURRENT_TIMESTAMP AS calculated_at
    
FROM shift_metrics sm
LEFT JOIN assignment_metrics am ON sm.shift_id = am.shift_id
LEFT JOIN hr.departments d ON sm.department_id = d.department_id
LEFT JOIN operations.locations l ON sm.location_id = l.location_id
LEFT JOIN hr.positions p ON sm.position_id = p.position_id
LEFT JOIN department_budgets db ON sm.department_id = db.department_id
    AND sm.location_id = db.location_id
    AND sm.position_id = db.position_id
    AND DATE_TRUNC('month', sm.shift_date) = db.budget_month
GROUP BY 
    sm.shift_date,
    DATE_TRUNC('week', sm.shift_date),
    DATE_TRUNC('month', sm.shift_date),
    sm.department_id,
    d.department_name,
    sm.location_id,
    l.location_name,
    sm.position_id,
    p.position_title,
    sm.shift_category
ORDER BY sm.shift_date DESC, d.department_name, l.location_name;

-- Create unique index for concurrent refresh
CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_schedule_efficiency_primary 
ON performance.mv_schedule_efficiency(shift_date, department_id, location_id, position_id, shift_category);

-- Create additional indexes for performance
CREATE INDEX IF NOT EXISTS idx_mv_schedule_efficiency_date 
ON performance.mv_schedule_efficiency(shift_date DESC);
CREATE INDEX IF NOT EXISTS idx_mv_schedule_efficiency_department 
ON performance.mv_schedule_efficiency(department_id);
CREATE INDEX IF NOT EXISTS idx_mv_schedule_efficiency_location 
ON performance.mv_schedule_efficiency(location_id);
CREATE INDEX IF NOT EXISTS idx_mv_schedule_efficiency_month 
ON performance.mv_schedule_efficiency(month_start);
CREATE INDEX IF NOT EXISTS idx_mv_schedule_efficiency_utilization 
ON performance.mv_schedule_efficiency(schedule_utilization_rate DESC);

-- Add comments
COMMENT ON MATERIALIZED VIEW performance.mv_schedule_efficiency IS 
'Comprehensive schedule efficiency metrics including utilization, adherence, and cost effectiveness. 
Refreshed daily during off-peak hours for optimal performance.';

COMMENT ON COLUMN performance.mv_schedule_efficiency.shift_date IS 'Date of the shift';
COMMENT ON COLUMN performance.mv_schedule_efficiency.schedule_utilization_rate IS 'Percentage of planned hours actually worked';
COMMENT ON COLUMN performance.mv_schedule_efficiency.adherence_score IS 'Average adherence score based on lateness (0-100)';
COMMENT ON COLUMN performance.mv_schedule_efficiency.labor_efficiency_ratio IS 'Ratio of employees to shifts';
COMMENT ON COLUMN performance.mv_schedule_efficiency.budget_variance_percentage IS 'Percentage variance from budgeted amount';



