-- =============================================================================
-- Serial No: MV-001 | MATERIALIZED VIEW: scheduling.mv_daily_coverage_summary
-- =============================================================================
-- Purpose: Pre-aggregated daily coverage metrics for fast reporting
-- Business Case: This materialized view provides pre-calculated daily coverage metrics, 
--                enabling rapid dashboard loading and real-time reporting without complex 
--                aggregations. It significantly improves query performance for operational 
--                dashboards and management reports by storing pre-aggregated coverage data. 
--                The view supports capacity planning, staffing optimization, and coverage 
--                analysis by providing instant access to key coverage indicators.
-- Refresh Strategy: Daily refresh during off-peak hours (e.g., 02:00 AM UTC)
-- KPI: Query performance improvement, Data freshness, Reporting latency reduction
-- Feature Reference: F-REP-004, F-PERF-004, F-OPT-004
-- =============================================================================

-- Drop existing materialized view if exists to ensure clean deployment
DROP MATERIALIZED VIEW IF EXISTS scheduling.mv_daily_coverage_summary CASCADE;

-- Create the materialized view
CREATE MATERIALIZED VIEW scheduling.mv_daily_coverage_summary AS
WITH shift_base AS (
    -- Base shift information with requirements
    -- NOTE: Using start_time::DATE instead of non-existent shift_date column
    SELECT
        sh.shift_id,
        sh.schedule_id,
        sh.start_time::DATE AS shift_date,  -- FIXED: Derived from start_time
        sh.start_time AS planned_start_time,
        sh.end_time AS planned_end_time,
        sh.department_id,
        sh.location_id,
        sh.position_id,
        sh.shift_type AS shift_category,  -- FIXED: Using shift_type column
        sh.shift_status,
        COALESCE(sh.required_employee_count, 1) AS required_employee_count
    FROM scheduling.shifts sh
    WHERE sh.shift_status NOT IN ('CANCELLED')
    -- Limit data range for performance if needed, currently open-ended for historical analysis
    -- AND sh.start_time >= CURRENT_TIMESTAMP - INTERVAL '2 years'
),
assignment_agg AS (
    -- Aggregate assignment statuses per shift
    SELECT
        sa.shift_id,
        COUNT(*) AS total_assignments,
        COUNT(DISTINCT sa.employee_id) AS unique_employees,
        COUNT(CASE WHEN sa.assignment_status IN ('CONFIRMED', 'ASSIGNED') THEN 1 END) AS filled_assignments,
        COUNT(CASE WHEN sa.assignment_status = 'CONFIRMED' THEN 1 END) AS confirmed_assignments,
        COUNT(CASE WHEN sa.assignment_status = 'TENTATIVE' THEN 1 END) AS tentative_assignments,
        COUNT(CASE WHEN sa.assignment_status IN ('CANCELLED', 'NO_SHOW') THEN 1 END) AS unavailable_assignments
    FROM scheduling.shift_assignments sa
    WHERE sa.assignment_status NOT IN ('CANCELLED')
    GROUP BY sa.shift_id
)
SELECT
    -- Dimension Keys
    sb.shift_date,
    DATE_TRUNC('week', sb.shift_date) AS week_start_date,
    DATE_TRUNC('month', sb.shift_date) AS month_start_date,
    sb.department_id,
    d.department_name,
    sb.location_id,
    l.location_name,
    l.city,
    l.state,
    sb.position_id,
    p.position_title,
    p.job_level,
    sb.shift_category,
    
    -- Shift Counts
    COUNT(DISTINCT sb.shift_id) AS total_shifts,
    
    -- Staffing Requirements
    SUM(sb.required_employee_count) AS total_required_positions,
    COALESCE(SUM(aa.total_assignments), 0) AS total_assigned_employees,
    COALESCE(SUM(aa.unique_employees), 0) AS unique_employees_scheduled,
    COALESCE(SUM(aa.filled_assignments), 0) AS total_filled_positions,
    COALESCE(SUM(aa.confirmed_assignments), 0) AS total_confirmed_positions,
    COALESCE(SUM(aa.tentative_assignments), 0) AS total_tentative_positions,
    
    -- Coverage Metrics
    ROUND(
        COALESCE(SUM(aa.filled_assignments), 0)::NUMERIC / 
        NULLIF(SUM(sb.required_employee_count), 0) * 100, 
    2) AS coverage_percentage,
    
    ROUND(
        COALESCE(SUM(aa.confirmed_assignments), 0)::NUMERIC / 
        NULLIF(SUM(sb.required_employee_count), 0) * 100, 
    2) AS confirmed_coverage_percentage,
    
    -- Gap Analysis
    SUM(sb.required_employee_count) - COALESCE(SUM(aa.filled_assignments), 0) AS staffing_gap,
    
    -- Status Breakdown (FIXED: Using valid shift_status_enum values only)
    COUNT(CASE WHEN sb.shift_status = 'OPEN' THEN 1 END) AS open_shifts,
    COUNT(CASE WHEN sb.shift_status = 'ASSIGNED' THEN 1 END) AS assigned_shifts,  -- FIXED: Was 'PUBLISHED'
    COUNT(CASE WHEN sb.shift_status = 'CONFIRMED' THEN 1 END) AS confirmed_shifts,
    COUNT(CASE WHEN sb.shift_status = 'IN_PROGRESS' THEN 1 END) AS in_progress_shifts,  -- FIXED: Was 'ACTIVE'
    COUNT(CASE WHEN sb.shift_status = 'COMPLETED' THEN 1 END) AS completed_shifts,
    COUNT(CASE WHEN sb.shift_status = 'HOLD' THEN 1 END) AS on_hold_shifts,
    COUNT(CASE WHEN sb.shift_status = 'PENDING_COVERAGE' THEN 1 END) AS pending_coverage_shifts,
    COUNT(CASE WHEN sb.shift_status = 'COVERED' THEN 1 END) AS covered_shifts,
    COUNT(CASE WHEN sb.shift_status = 'NO_SHOW' THEN 1 END) AS no_show_shifts,
    
    -- Time Metrics
    ROUND(SUM(EXTRACT(EPOCH FROM (sb.planned_end_time - sb.planned_start_time)) / 3600), 2) AS total_planned_hours,
    
    -- Data Freshness
    CURRENT_TIMESTAMP AS calculated_at,
    CURRENT_DATE AS snapshot_date
    
FROM shift_base sb
LEFT JOIN assignment_agg aa ON sb.shift_id = aa.shift_id
LEFT JOIN hr.departments d ON sb.department_id = d.department_id
LEFT JOIN operations.locations l ON sb.location_id = l.location_id
LEFT JOIN hr.positions p ON sb.position_id = p.position_id
GROUP BY
    sb.shift_date,
    DATE_TRUNC('week', sb.shift_date),
    DATE_TRUNC('month', sb.shift_date),
    sb.department_id,
    d.department_name,
    sb.location_id,
    l.location_name,
    l.city,
    l.state,
    sb.position_id,
    p.position_title,
    p.job_level,
    sb.shift_category
ORDER BY
    sb.shift_date DESC,
    d.department_name,
    l.location_name,
    p.position_title;

-- =============================================================================
-- INDEXES FOR PERFORMANCE AND REFRESH
-- =============================================================================

-- Unique index is REQUIRED for CONCURRENT refresh
CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_daily_coverage_summary_unique
ON scheduling.mv_daily_coverage_summary (
    shift_date, 
    department_id, 
    location_id, 
    position_id, 
    shift_category
);

-- Indexes for common query patterns (Dashboards, Reports)
CREATE INDEX IF NOT EXISTS idx_mv_daily_coverage_summary_date
ON scheduling.mv_daily_coverage_summary (shift_date DESC);

CREATE INDEX IF NOT EXISTS idx_mv_daily_coverage_summary_week
ON scheduling.mv_daily_coverage_summary (week_start_date DESC);

CREATE INDEX IF NOT EXISTS idx_mv_daily_coverage_summary_month
ON scheduling.mv_daily_coverage_summary (month_start_date DESC);

CREATE INDEX IF NOT EXISTS idx_mv_daily_coverage_summary_department
ON scheduling.mv_daily_coverage_summary (department_id, shift_date DESC);

CREATE INDEX IF NOT EXISTS idx_mv_daily_coverage_summary_location
ON scheduling.mv_daily_coverage_summary (location_id, shift_date DESC);

CREATE INDEX IF NOT EXISTS idx_mv_daily_coverage_summary_coverage
ON scheduling.mv_daily_coverage_summary (coverage_percentage ASC);

CREATE INDEX IF NOT EXISTS idx_mv_daily_coverage_summary_gap
ON scheduling.mv_daily_coverage_summary (staffing_gap DESC);

-- =============================================================================
-- COMMENTS AND DOCUMENTATION
-- =============================================================================

COMMENT ON MATERIALIZED VIEW scheduling.mv_daily_coverage_summary IS 
'Materialized view providing pre-aggregated daily coverage metrics for fast reporting and dashboarding. 
Includes staffing requirements, actual assignments, coverage percentages, and gap analysis grouped by 
department, location, and position. Supports concurrent refresh for zero-downtime updates.

KEY FIXES APPLIED:
- Uses start_time::DATE instead of non-existent shift_date column
- Uses shift_type column instead of shift_category
- Uses VALID shift_status_enum values only (OPEN, ASSIGNED, CONFIRMED, IN_PROGRESS, COMPLETED, etc.)
- Removed invalid values: PUBLISHED, ACTIVE (these are schedule_status_enum values)
- Compatible with actual scheduling.shifts table schema';

COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.shift_date IS 'Date of the shifts being summarized (derived from start_time)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.week_start_date IS 'ISO week start date for weekly aggregations';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.month_start_date IS 'Month start date for monthly aggregations';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.total_required_positions IS 'Sum of required employee counts across all shifts';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.total_filled_positions IS 'Count of assignments with status CONFIRMED or ASSIGNED';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.coverage_percentage IS 'Percentage of required positions that are filled (0-100)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.confirmed_coverage_percentage IS 'Percentage of required positions that are confirmed by employees';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.staffing_gap IS 'Difference between required positions and filled positions (negative means overstaffed)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.total_planned_hours IS 'Total scheduled hours for the day across all shifts';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.calculated_at IS 'Timestamp when the materialized view was last refreshed';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.snapshot_date IS 'Date when the data snapshot was taken';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.open_shifts IS 'Shifts with status OPEN (available for assignment)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.assigned_shifts IS 'Shifts with status ASSIGNED (employee assigned but not confirmed)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.confirmed_shifts IS 'Shifts with status CONFIRMED (employee confirmed)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.in_progress_shifts IS 'Shifts with status IN_PROGRESS (currently being worked)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.completed_shifts IS 'Shifts with status COMPLETED (finished)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.on_hold_shifts IS 'Shifts with status HOLD (awaiting approval or other action)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.pending_coverage_shifts IS 'Shifts needing coverage (employee called off)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.covered_shifts IS 'Shifts that have been covered by replacement';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.no_show_shifts IS 'Shifts where employee failed to show';

-- =============================================================================
-- REFRESH FUNCTION (Optional Helper)
-- =============================================================================
-- Helper function to refresh the view with logging
CREATE OR REPLACE FUNCTION scheduling.refresh_mv_daily_coverage_summary()
RETURNS TABLE (
    refresh_status VARCHAR(20),
    refresh_duration_ms INTEGER,
    rows_count BIGINT,
    error_message TEXT
) AS $$
DECLARE
    v_start_time TIMESTAMPTZ := CURRENT_TIMESTAMP;
    v_end_time TIMESTAMPTZ;
    v_row_count BIGINT;
    v_error_message TEXT;
    v_status VARCHAR(20) := 'SUCCESS';
BEGIN
    BEGIN
        -- Perform concurrent refresh to avoid locking
        REFRESH MATERIALIZED VIEW CONCURRENTLY scheduling.mv_daily_coverage_summary;
        
        -- Get row count
        SELECT COUNT(*) INTO v_row_count FROM scheduling.mv_daily_coverage_summary;
        
        v_end_time := CURRENT_TIMESTAMP;
        
        RETURN QUERY SELECT
            v_status,
            EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000::INTEGER,
            v_row_count,
            NULL::TEXT;
            
    EXCEPTION WHEN OTHERS THEN
        GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;
        v_status := 'FAILED';
        v_end_time := CURRENT_TIMESTAMP;
        
        RETURN QUERY SELECT
            v_status,
            EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000::INTEGER,
            0::BIGINT,
            v_error_message;
    END;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION scheduling.refresh_mv_daily_coverage_summary IS 
'Helper function to refresh the daily coverage summary materialized view concurrently with error handling and timing metrics.';

-- Grant permissions (Adjust roles as per your security model)
GRANT SELECT ON scheduling.mv_daily_coverage_summary TO reporting_role, manager_role, admin_role;
GRANT EXECUTE ON FUNCTION scheduling.refresh_mv_daily_coverage_summary TO admin_role, scheduler_role;

-- =============================================================================
-- VERIFICATION QUERY
-- =============================================================================
-- Example query to test the materialized view
SELECT 
    shift_date, 
    department_name, 
    location_name, 
    total_required_positions, 
    total_filled_positions, 
    coverage_percentage, 
    staffing_gap,
    open_shifts,
    assigned_shifts,
    confirmed_shifts,
    in_progress_shifts,
    completed_shifts
FROM scheduling.mv_daily_coverage_summary 
WHERE shift_date >= CURRENT_DATE - INTERVAL '7 days' 
ORDER BY shift_date DESC, coverage_percentage ASC 
LIMIT 20;


