COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.completed_shifts IS 'Shifts with status COMPLETED (finished)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.on_hold_shifts IS 'Shifts with status HOLD (awaiting approval or other action)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.pending_coverage_shifts IS 'Shifts needing coverage (employee called off)';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.covered_shifts IS 'Shifts that have been covered by replacement';
COMMENT ON COLUMN scheduling.mv_daily_coverage_summary.no_show_shifts IS 'Shifts where employee failed to show';

-- =============================================================================
-- REFRESH FUNCTION (Optional Helper)
-- =============================================================================
-- Helper function to refresh the view with logging
CREATE OR REPLACE FUNCTION scheduling.refresh_mv_daily_coverage_summary()
RETURNS TABLE (
    refresh_status VARCHAR(20),
    refresh_duration_ms INTEGER,
    rows_count BIGINT,
    error_message TEXT
) AS $$
DECLARE
    v_start_time TIMESTAMPTZ := CURRENT_TIMESTAMP;
    v_end_time TIMESTAMPTZ;
    v_row_count BIGINT;
    v_error_message TEXT;
    v_status VARCHAR(20) := 'SUCCESS';
BEGIN
    BEGIN
        -- Perform concurrent refresh to avoid locking
        REFRESH MATERIALIZED VIEW CONCURRENTLY scheduling.mv_daily_coverage_summary;
        
        -- Get row count
        SELECT COUNT(*) INTO v_row_count FROM scheduling.mv_daily_coverage_summary;
        
        v_end_time := CURRENT_TIMESTAMP;
        
        RETURN QUERY SELECT
            v_status,
            EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000::INTEGER,
            v_row_count,
            NULL::TEXT;
            
    EXCEPTION WHEN OTHERS THEN
        GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;
        v_status := 'FAILED';
        v_end_time := CURRENT_TIMESTAMP;
        
        RETURN QUERY SELECT
            v_status,
            EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000::INTEGER,
            0::BIGINT,
            v_error_message;
    END;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION scheduling.refresh_mv_daily_coverage_summary IS 
'Helper function to refresh the daily coverage summary materialized view concurrently with error handling and timing metrics.';

-- Grant permissions (Adjust roles as per your security model)
GRANT SELECT ON scheduling.mv_daily_coverage_summary TO reporting_role, manager_role, admin_role;
GRANT EXECUTE ON FUNCTION scheduling.refresh_mv_daily_coverage_summary TO admin_role, scheduler_role;

-- =============================================================================
-- VERIFICATION QUERY
-- =============================================================================
-- Example query to test the materialized view
SELECT 
    shift_date, 
    department_name, 
    location_name, 
    total_required_positions, 
    total_filled_positions, 
    coverage_percentage, 
    staffing_gap,
    open_shifts,
    assigned_shifts,
    confirmed_shifts,
    in_progress_shifts,
    completed_shifts
FROM scheduling.mv_daily_coverage_summary 
WHERE shift_date >= CURRENT_DATE - INTERVAL '7 days' 
ORDER BY shift_date DESC, coverage_percentage ASC 
LIMIT 20;



-- =============================================================================
-- 1. SHIFT STATUS ENUM (for individual shifts)
-- =============================================================================
-- Serial No: ENUM-001
-- Type: scheduling.shift_status_enum
-- Purpose: Defines the status of individual shifts within schedules
-- Business Case: This enumeration standardizes shift status tracking across the 
--                system, enabling consistent handling of shift assignments, 
--                coverage status, and operational states. It supports real-time 
--                visibility into shift coverage, facilitates automated gap 
--                detection, and enables status-based notifications.
-- KPI: Shift coverage rate, Time to fill open shifts, Shift swap completion rate,
--      Unfilled shift duration, Shift status transition efficiency
-- Feature Reference: F-SCH-006, F-SCH-007, F-SCH-008, F-SCH-009, F-SCH-010
-- =============================================================================

DO $$BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'shift_status_enum') THEN
        CREATE TYPE scheduling.shift_status_enum AS ENUM (
            'OPEN',              -- Shift is available for assignment
            'ASSIGNED',          -- Shift is assigned to an employee
            'CONFIRMED',         -- Employee has confirmed the shift
            'PENDING_COVERAGE',  -- Shift needs coverage (employee called off)
            'COVERED',           -- Shift has been covered by replacement
            'CANCELLED',         -- Shift was cancelled
            'HOLD',              -- Shift is on hold (e.g., awaiting approval)
            'IN_PROGRESS',       -- Shift is currently being worked
            'COMPLETED',         -- Shift has been completed
            'NO_SHOW',           -- Employee failed to show for shift
            'EARLY_LEAVE',       -- Employee left shift early
            'LATE_ARRIVAL'       -- Employee arrived late for shift
        );
        RAISE NOTICE 'Created enum type: scheduling.shift_status_enum';
    ELSE
        RAISE NOTICE 'Enum type scheduling.shift_status_enum already exists';
    END IF;
END$$;

COMMENT ON TYPE scheduling.shift_status_enum IS 
'Defines the status of individual shifts within schedules.
OPEN: Shift is available for assignment; 
ASSIGNED: Shift is assigned to an employee; 
CONFIRMED: Employee has confirmed the shift;
PENDING_COVERAGE: Shift needs coverage (employee called off); 
COVERED: Shift has been covered by replacement;
CANCELLED: Shift was cancelled; 
HOLD: Shift is on hold (e.g., awaiting approval); 
IN_PROGRESS: Shift is currently being worked;
COMPLETED: Shift has been completed; 
NO_SHOW: Employee failed to show for shift; 
EARLY_LEAVE: Employee left shift early;
LATE_ARRIVAL: Employee arrived late for shift.';

-- =============================================================================
-- 2. SCHEDULE STATUS ENUM (for schedules - NOT for shifts)
-- =============================================================================
-- Serial No: ENUM-002
-- Type: scheduling.schedule_status_enum
-- Purpose: Defines the lifecycle status of schedules for workflow management
-- Business Case: This enumeration provides a standardized set of status values 
--                that represent the various stages in a schedule's lifecycle, 
--                from creation through approval to execution and archiving. 
--                It enables consistent tracking of schedule progression, 
--                facilitates automated workflow transitions, and supports 
--                status-based reporting.
-- KPI: Schedule approval cycle time, Draft schedule abandonment rate, 
--      Schedule publication timeliness, Approval workflow efficiency, 
--      Schedule versioning frequency
-- Feature Reference: F-SCH-001, F-SCH-002, F-SCH-003, F-SCH-004, F-SCH-005
-- =============================================================================

DO $$BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'schedule_status_enum') THEN
        CREATE TYPE scheduling.schedule_status_enum AS ENUM (
            'DRAFT',               -- Schedule is being created or modified
            'PENDING_APPROVAL',    -- Schedule submitted for approval
            'APPROVED',            -- Schedule approved and ready for publication
            'PUBLISHED',           -- Schedule published to employees
            'EXECUTING',           -- Schedule is currently in effect
            'COMPLETED',           -- Schedule period has ended
            'ARCHIVED',            -- Schedule moved to long-term storage
            'CANCELLED',           -- Schedule was cancelled before execution
            'REVISION_REQUIRED'    -- Schedule needs changes before approval
        );
        RAISE NOTICE 'Created enum type: scheduling.schedule_status_enum';
    ELSE
        RAISE NOTICE 'Enum type scheduling.schedule_status_enum already exists';
    END IF;
END$$;

COMMENT ON TYPE scheduling.schedule_status_enum IS 
'Defines the lifecycle status of schedules for workflow management.
DRAFT: Schedule is being created or modified; 
PENDING_APPROVAL: Schedule submitted for approval;
APPROVED: Schedule approved and ready for publication; 
PUBLISHED: Schedule published to employees;
EXECUTING: Schedule is currently in effect; 
COMPLETED: Schedule period has ended;
ARCHIVED: Schedule moved to long-term storage; 
CANCELLED: Schedule was cancelled before execution;
REVISION_REQUIRED: Schedule needs changes before approval.';

