-- Check if enums were created successfully
SELECT 
    typname AS enum_name,
    nspname AS schema_name,
    pg_catalog.array_agg(enumlabel ORDER BY enumsortorder) AS enum_values
FROM pg_type
JOIN pg_enum ON pg_enum.enumtypid = pg_type.oid
JOIN pg_namespace ON pg_namespace.oid = pg_type.typnamespace
WHERE typname IN ('shift_status_enum', 'schedule_status_enum')
GROUP BY typname, nspname
ORDER BY schema_name, enum_name;

