-- =============================================================================
-- Serial No: MV-002 | MATERIALIZED VIEW: scheduling.mv_employee_compliance
-- =============================================================================
-- Purpose: Employee compliance and performance metrics aggregated monthly
-- Business Case: This materialized view provides pre-calculated employee compliance 
--              and performance metrics, enabling rapid performance reviews, 
--              compliance monitoring, and trend analysis. It significantly improves 
--              query performance for HR dashboards and manager reports by storing 
--              pre-aggregated compliance data. The view supports performance 
--              management, recognition programs, and compliance tracking by 
--              providing instant access to key employee indicators.
-- Refresh Strategy: Weekly refresh with daily incremental updates
-- KPI: Query performance improvement, Compliance trend visibility, Performance review efficiency
-- Feature Reference: F-COMP-003, F-HR-004, F-REP-005
-- Dependencies: hr.employees, scheduling.shift_assignments, scheduling.shifts, 
--               scheduling.schedule_compliance, analytics.performance_metrics, 
--               hr.employee_certifications, hr.time_off_requests, hr.departments, 
--               operations.locations
-- =============================================================================

-- Drop existing view if exists to ensure clean creation during deployment
DROP MATERIALIZED VIEW IF EXISTS scheduling.mv_employee_compliance CASCADE;

-- Create the materialized view
CREATE MATERIALIZED VIEW scheduling.mv_employee_compliance AS
WITH shift_activity AS (
    -- Aggregate shift assignment data per employee per month
    SELECT 
        sa.employee_id,
        e.department_id,
        e.location_id,
        DATE_TRUNC('month', sa.scheduled_start_time) AS compliance_month,
        COUNT(DISTINCT sa.assignment_id) AS total_shifts_assigned,
        COUNT(DISTINCT CASE 
            WHEN sa.assignment_status IN ('COMPLETED', 'CONFIRMED', 'IN_PROGRESS') 
            THEN sa.assignment_id 
        END) AS total_shifts_worked,
        COUNT(DISTINCT CASE 
            WHEN sa.assignment_status = 'NO_SHOW' 
            THEN sa.assignment_id 
        END) AS no_show_count,
        COUNT(DISTINCT CASE 
            WHEN sa.actual_start_time > sa.scheduled_start_time + INTERVAL '15 minutes' 
            THEN sa.assignment_id 
        END) AS late_arrival_count,
        ROUND(SUM(COALESCE(sa.overtime_hours, 0)), 2) AS total_overtime_hours,
        ROUND(AVG(COALESCE(sa.punctuality_score, 0)), 2) AS avg_punctuality_score,
        ROUND(AVG(COALESCE(sa.attendance_score, 0)), 2) AS avg_attendance_score
    FROM scheduling.shift_assignments sa
    JOIN hr.employees e ON sa.employee_id = e.employee_id
    WHERE sa.scheduled_start_time >= CURRENT_DATE - INTERVAL '12 months'
    GROUP BY sa.employee_id, e.department_id, e.location_id, DATE_TRUNC('month', sa.scheduled_start_time)
),
compliance_violations AS (
    -- Aggregate compliance violations per employee per month
    SELECT 
        sc.entity_id AS employee_id,
        e.department_id,
        e.location_id,
        DATE_TRUNC('month', sc.detected_at) AS compliance_month,
        COUNT(sc.compliance_id) AS total_violations,
        COUNT(CASE WHEN sc.violation_severity IN ('CRITICAL', 'HIGH') THEN 1 END) AS critical_violations,
        COUNT(CASE WHEN sc.status = 'RESOLVED' THEN 1 END) AS resolved_violations
    FROM scheduling.schedule_compliance sc
    JOIN hr.employees e ON sc.entity_id = e.employee_id
    WHERE sc.entity_type = 'EMPLOYEE'
    AND sc.detected_at >= CURRENT_DATE - INTERVAL '12 months'
    GROUP BY sc.entity_id, e.department_id, e.location_id, DATE_TRUNC('month', sc.detected_at)
),
performance_scores AS (
    -- Aggregate performance metrics per employee per month
    SELECT 
        pm.employee_id,
        e.department_id,
        e.location_id,
        DATE_TRUNC('month', pm.measurement_period_start) AS compliance_month,
        ROUND(AVG(CASE WHEN pm.metric_type = 'PRODUCTIVITY' THEN pm.metric_value END), 2) AS avg_productivity_score,
        ROUND(AVG(CASE WHEN pm.metric_type = 'QUALITY' THEN pm.metric_value END), 2) AS avg_quality_score,
        ROUND(AVG(CASE WHEN pm.metric_type = 'CUSTOMER_SATISFACTION' THEN pm.metric_value END), 2) AS avg_customer_satisfaction
    FROM analytics.performance_metrics pm
    JOIN hr.employees e ON pm.employee_id = e.employee_id
    WHERE pm.measurement_period_start >= CURRENT_DATE - INTERVAL '12 months'
    GROUP BY pm.employee_id, e.department_id, e.location_id, DATE_TRUNC('month', pm.measurement_period_start)
),
certification_status AS (
    -- Count certification issues per employee per month (snapshot at month end)
    SELECT 
        ec.employee_id,
        e.department_id,
        e.location_id,
        DATE_TRUNC('month', CURRENT_DATE) AS compliance_month,
        COUNT(CASE WHEN ec.expiration_date < CURRENT_DATE THEN 1 END) AS expired_certifications,
        COUNT(CASE WHEN ec.expiration_date BETWEEN CURRENT_DATE AND CURRENT_DATE + INTERVAL '30 days' THEN 1 END) AS expiring_soon_certifications
    FROM hr.employee_certifications ec
    JOIN hr.employees e ON ec.employee_id = e.employee_id
    WHERE ec.is_active = TRUE
    GROUP BY ec.employee_id, e.department_id, e.location_id
),
time_off_requests AS (
    -- Aggregate time off requests per employee per month
    SELECT 
        tor.employee_id,
        e.department_id,
        e.location_id,
        DATE_TRUNC('month', tor.requested_at) AS compliance_month,
        COUNT(tor.request_id) AS total_time_off_requests,
        COUNT(CASE WHEN tor.status = 'APPROVED' THEN 1 END) AS approved_time_off,
        COUNT(CASE WHEN tor.status = 'REJECTED' THEN 1 END) AS rejected_time_off
    FROM hr.time_off_requests tor
    JOIN hr.employees e ON tor.employee_id = e.employee_id
    WHERE tor.requested_at >= CURRENT_DATE - INTERVAL '12 months'
    GROUP BY tor.employee_id, e.department_id, e.location_id, DATE_TRUNC('month', tor.requested_at)
)
SELECT 
    -- Employee Identity
    e.employee_id,
    e.employee_code,
    e.first_name,
    e.last_name,
    e.job_title,
    e.employment_status,
    -- Organizational Context
    d.department_name,
    l.location_name,
    l.city,
    l.country,
    -- Time Period
    COALESCE(sa.compliance_month, cv.compliance_month, ps.compliance_month, tor.compliance_month) AS compliance_month,
    EXTRACT(YEAR FROM COALESCE(sa.compliance_month, cv.compliance_month, ps.compliance_month, tor.compliance_month)) AS compliance_year,
    EXTRACT(MONTH FROM COALESCE(sa.compliance_month, cv.compliance_month, ps.compliance_month, tor.compliance_month)) AS compliance_month_num,
    -- Shift Activity Metrics
    COALESCE(sa.total_shifts_assigned, 0) AS total_shifts_assigned,
    COALESCE(sa.total_shifts_worked, 0) AS total_shifts_worked,
    COALESCE(sa.no_show_count, 0) AS no_show_count,
    COALESCE(sa.late_arrival_count, 0) AS late_arrival_count,
    COALESCE(sa.total_overtime_hours, 0) AS total_overtime_hours,
    -- Calculated Attendance Metrics
    CASE 
        WHEN COALESCE(sa.total_shifts_assigned, 0) > 0 
        THEN ROUND((COALESCE(sa.total_shifts_worked, 0)::NUMERIC / sa.total_shifts_assigned * 100), 2)
        ELSE 100.00 
    END AS attendance_rate_percentage,
    -- Compliance Metrics
    COALESCE(cv.total_violations, 0) AS total_compliance_violations,
    COALESCE(cv.critical_violations, 0) AS critical_compliance_violations,
    COALESCE(cv.resolved_violations, 0) AS resolved_compliance_violations,
    CASE 
        WHEN COALESCE(cv.total_violations, 0) > 0 
        THEN ROUND((COALESCE(cv.resolved_violations, 0)::NUMERIC / cv.total_violations * 100), 2)
        ELSE 100.00 
    END AS violation_resolution_rate,
    -- Certification Metrics (Using latest available snapshot)
    COALESCE(cs.expired_certifications, 0) AS expired_certifications_count,
    COALESCE(cs.expiring_soon_certifications, 0) AS expiring_soon_certifications_count,
    -- Performance Metrics
    COALESCE(ps.avg_productivity_score, 0) AS avg_productivity_score,
    COALESCE(ps.avg_quality_score, 0) AS avg_quality_score,
    COALESCE(ps.avg_customer_satisfaction, 0) AS avg_customer_satisfaction_score,
    -- Time Off Metrics
    COALESCE(tor.total_time_off_requests, 0) AS total_time_off_requests,
    COALESCE(tor.approved_time_off, 0) AS approved_time_off_requests,
    COALESCE(tor.rejected_time_off, 0) AS rejected_time_off_requests,
    -- Composite Scores
    ROUND((
        (COALESCE(sa.avg_attendance_score, 0) * 0.3) +
        (COALESCE(sa.avg_punctuality_score, 0) * 0.2) +
        (COALESCE(ps.avg_productivity_score, 0) * 0.3) +
        (CASE WHEN COALESCE(cv.critical_violations, 0) > 0 THEN 0 ELSE 20 END)
    ), 2) AS overall_compliance_performance_score,
    -- Metadata
    CURRENT_TIMESTAMP AS calculated_at,
    CURRENT_DATE AS data_freshness_date  -- FIXED: Changed from "data freshness_date" to "data_freshness_date"
FROM hr.employees e
JOIN hr.departments d ON e.department_id = d.department_id
JOIN operations.locations l ON e.location_id = l.location_id
-- Join aggregated data sources
LEFT JOIN shift_activity sa ON e.employee_id = sa.employee_id 
    AND (sa.compliance_month IS NOT NULL)
LEFT JOIN compliance_violations cv ON e.employee_id = cv.employee_id 
    AND (sa.compliance_month = cv.compliance_month OR (sa.compliance_month IS NULL AND cv.compliance_month IS NOT NULL))
LEFT JOIN performance_scores ps ON e.employee_id = ps.employee_id 
    AND (COALESCE(sa.compliance_month, cv.compliance_month) = ps.compliance_month OR (sa.compliance_month IS NULL AND cv.compliance_month IS NULL AND ps.compliance_month IS NOT NULL))
LEFT JOIN certification_status cs ON e.employee_id = cs.employee_id
LEFT JOIN time_off_requests tor ON e.employee_id = tor.employee_id 
    AND (COALESCE(sa.compliance_month, cv.compliance_month, ps.compliance_month) = tor.compliance_month OR (sa.compliance_month IS NULL AND cv.compliance_month IS NULL AND ps.compliance_month IS NULL AND tor.compliance_month IS NOT NULL))
WHERE e.employment_status IN ('ACTIVE', 'PROBATION', 'ON_LEAVE')
ORDER BY compliance_month DESC, d.department_name, e.last_name;

-- =============================================================================
-- INDEXES FOR PERFORMANCE
-- =============================================================================
-- Unique index required for REFRESH CONCURRENTLY
CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_employee_compliance_unique 
ON scheduling.mv_employee_compliance(employee_id, compliance_month);

-- Common query filter indexes
CREATE INDEX IF NOT EXISTS idx_mv_employee_compliance_month 
ON scheduling.mv_employee_compliance(compliance_month DESC);

CREATE INDEX IF NOT EXISTS idx_mv_employee_compliance_employee 
ON scheduling.mv_employee_compliance(employee_id);

CREATE INDEX IF NOT EXISTS idx_mv_employee_compliance_department 
ON scheduling.mv_employee_compliance(department_name);

CREATE INDEX IF NOT EXISTS idx_mv_employee_compliance_location 
ON scheduling.mv_employee_compliance(location_name);

CREATE INDEX IF NOT EXISTS idx_mv_employee_compliance_violations 
ON scheduling.mv_employee_compliance(total_compliance_violations DESC);

CREATE INDEX IF NOT EXISTS idx_mv_employee_compliance_performance 
ON scheduling.mv_employee_compliance(overall_compliance_performance_score DESC);

-- =============================================================================
-- DOCUMENTATION COMMENTS
-- =============================================================================
COMMENT ON MATERIALIZED VIEW scheduling.mv_employee_compliance IS 
'Monthly aggregated employee compliance and performance metrics. Provides pre-calculated data for HR dashboards, 
performance reviews, and compliance monitoring. Includes shift activity, violations, certifications, performance scores, 
and time off requests. Refreshed weekly with daily incremental updates.';

COMMENT ON COLUMN scheduling.mv_employee_compliance.employee_id IS 'Unique identifier for the employee';
COMMENT ON COLUMN scheduling.mv_employee_compliance.compliance_month IS 'Month period for which metrics are aggregated';
COMMENT ON COLUMN scheduling.mv_employee_compliance.attendance_rate_percentage IS 'Percentage of assigned shifts actually worked';
COMMENT ON COLUMN scheduling.mv_employee_compliance.total_compliance_violations IS 'Total count of compliance violations detected in the month';
COMMENT ON COLUMN scheduling.mv_employee_compliance.critical_compliance_violations IS 'Count of high severity violations (Critical/High)';
COMMENT ON COLUMN scheduling.mv_employee_compliance.violation_resolution_rate IS 'Percentage of violations resolved within the month';
COMMENT ON COLUMN scheduling.mv_employee_compliance.expired_certifications_count IS 'Number of certifications expired as of month end';
COMMENT ON COLUMN scheduling.mv_employee_compliance.avg_productivity_score IS 'Average productivity metric value for the month';
COMMENT ON COLUMN scheduling.mv_employee_compliance.overall_compliance_performance_score IS 'Composite score (0-100) combining attendance, punctuality, performance, and compliance';
COMMENT ON COLUMN scheduling.mv_employee_compliance.calculated_at IS 'Timestamp when the materialized view was last refreshed';
COMMENT ON COLUMN scheduling.mv_employee_compliance.data_freshness_date IS 'Date indicating the freshness of the data in the view';

-- =============================================================================
-- REFRESH FUNCTION
-- =============================================================================
-- Serial No: FN-MV-002 | FUNCTION: scheduling.refresh_mv_employee_compliance
-- Purpose: Refreshes the employee compliance materialized view with logging
-- Business Case: Ensures data freshness for compliance reporting while maintaining 
--                system performance through controlled refresh operations.
-- =============================================================================
CREATE OR REPLACE FUNCTION scheduling.refresh_mv_employee_compliance(
    p_concurrent BOOLEAN DEFAULT TRUE,
    p_log_results BOOLEAN DEFAULT TRUE
)
RETURNS TABLE (
    refresh_status VARCHAR(20),
    refresh_duration_ms INTEGER,
    rows_affected INTEGER,
    error_message TEXT
) AS $$
DECLARE
    v_start_time TIMESTAMPTZ := CURRENT_TIMESTAMP;
    v_end_time TIMESTAMPTZ;
    v_row_count INTEGER;
    v_error_message TEXT;
    v_status VARCHAR(20) := 'SUCCESS';
BEGIN
    BEGIN
        -- Refresh the materialized view
        IF p_concurrent THEN
            EXECUTE 'REFRESH MATERIALIZED VIEW CONCURRENTLY scheduling.mv_employee_compliance';
        ELSE
            EXECUTE 'REFRESH MATERIALIZED VIEW scheduling.mv_employee_compliance';
        END IF;
        
        -- Get row count
        SELECT COUNT(*) INTO v_row_count FROM scheduling.mv_employee_compliance;
        
        -- Calculate duration
        v_end_time := CURRENT_TIMESTAMP;
        
        -- Log success if requested
        IF p_log_results THEN
            INSERT INTO system.mv_refresh_history (
                materialized_view,
                refresh_time,
                duration_ms,
                rows_affected,
                status
            ) VALUES (
                'scheduling.mv_employee_compliance',
                CURRENT_TIMESTAMP,
                EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000,
                v_row_count,
                'SUCCESS'
            );
        END IF;
        
        -- Return success
        RETURN QUERY SELECT 
            v_status, 
            EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000::INTEGER, 
            v_row_count, 
            NULL::TEXT;
            
    EXCEPTION WHEN OTHERS THEN
        GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;
        v_status := 'FAILED';
        v_end_time := CURRENT_TIMESTAMP;
        
        -- Log failure if requested
        IF p_log_results THEN
            INSERT INTO system.mv_refresh_history (
                materialized_view,
                refresh_time,
                duration_ms,
                error_message,
                status
            ) VALUES (
                'scheduling.mv_employee_compliance',
                CURRENT_TIMESTAMP,
                EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000,
                v_error_message,
                'FAILED'
            );
        END IF;
        
        -- Return failure
        RETURN QUERY SELECT 
            v_status, 
            EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000::INTEGER, 
            0, 
            v_error_message;
    END;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION scheduling.refresh_mv_employee_compliance IS 
'Refreshes the employee compliance materialized view with error handling and logging to system.mv_refresh_history';

