-- Grant SELECT to reporting and management roles
GRANT SELECT ON scheduling.mv_shift_pattern_analysis TO reporting_role;
GRANT SELECT ON scheduling.mv_shift_pattern_analysis TO manager_role;
GRANT SELECT ON scheduling.mv_shift_pattern_analysis TO admin_role;
GRANT SELECT ON scheduling.mv_shift_pattern_analysis TO finance_role;

-- Grant EXECUTE on refresh function to admin and scheduler roles
GRANT EXECUTE ON FUNCTION scheduling.refresh_mv_shift_pattern_analysis TO admin_role;
GRANT EXECUTE ON FUNCTION scheduling.refresh_mv_shift_pattern_analysis TO scheduler_role;

