-- =============================================================================
-- Serial No: ALT-001 | ALTER TABLE: scheduling.shifts (Add Temporal Columns)
-- =============================================================================
-- Purpose: Add persistent day_of_week and hour_of_day columns for performance
-- Business Case: Storing these derived values eliminates the need for repeated 
--              EXTRACT() function calls in queries, views, and materialized views.
--              This significantly improves query performance for scheduling 
--              optimization, reporting, and availability matching.
-- KPI: Query performance improvement, Index efficiency, Join speed
-- Feature Reference: F-SCH-006, F-OPT-005, F-REP-004
-- =============================================================================

-- 1. Add columns (nullable initially to allow ALTER TABLE without locking writes)
ALTER TABLE scheduling.shifts 
ADD COLUMN day_of_week INTEGER,
ADD COLUMN hour_of_day INTEGER;

-- 2. Populate existing data
-- Note: ISODOW returns 1-7 (Monday=1), matching employee_availability convention
UPDATE scheduling.shifts 
SET 
    day_of_week = EXTRACT(ISODOW FROM start_time)::INTEGER,
    hour_of_day = EXTRACT(HOUR FROM start_time)::INTEGER
WHERE day_of_week IS NULL OR hour_of_day IS NULL;

-- 3. Add NOT NULL constraints
ALTER TABLE scheduling.shifts 
ALTER COLUMN day_of_week SET NOT NULL,
ALTER COLUMN hour_of_day SET NOT NULL;

-- 4. Add CHECK constraints for data integrity
ALTER TABLE scheduling.shifts 
ADD CONSTRAINT chk_shifts_day_of_week CHECK (day_of_week BETWEEN 1 AND 7),
ADD CONSTRAINT chk_shifts_hour_of_day CHECK (hour_of_day BETWEEN 0 AND 23);

-- 5. Create indexes for performance (critical for joins with availability)
CREATE INDEX IF NOT EXISTS idx_shifts_day_of_week 
ON scheduling.shifts(day_of_week);

CREATE INDEX IF NOT EXISTS idx_shifts_hour_of_day 
ON scheduling.shifts(hour_of_day);

-- Composite index for common filtering patterns
CREATE INDEX IF NOT EXISTS idx_shifts_temporal 
ON scheduling.shifts(day_of_week, hour_of_day, start_time);

-- 6. Add column comments for documentation
COMMENT ON COLUMN scheduling.shifts.day_of_week IS 'Day of week (1=Monday, 7=Sunday) derived from start_time. Matches employee_availability convention.';
COMMENT ON COLUMN scheduling.shifts.hour_of_day IS 'Hour of day (0-23) derived from start_time. Used for shift pattern analysis.';

-- =============================================================================
-- Serial No: TRG-001 | TRIGGER: scheduling.shifts (Maintain Temporal Columns)
-- =============================================================================
-- Purpose: Automatically update day_of_week and hour_of_day when start_time changes
-- Business Case: Ensures data consistency between the timestamp and derived columns.
--              Prevents data drift if shifts are rescheduled via direct SQL updates.
-- =============================================================================

CREATE OR REPLACE FUNCTION scheduling.update_shift_temporal_columns()
RETURNS TRIGGER AS $$
BEGIN
    -- Only update if start_time actually changed
    IF OLD.start_time IS DISTINCT FROM NEW.start_time THEN
        NEW.day_of_week := EXTRACT(ISODOW FROM NEW.start_time)::INTEGER;
        NEW.hour_of_day := EXTRACT(HOUR FROM NEW.start_time)::INTEGER;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_shifts_update_temporal ON scheduling.shifts;
CREATE TRIGGER trg_shifts_update_temporal
BEFORE INSERT OR UPDATE OF start_time ON scheduling.shifts
FOR EACH ROW
EXECUTE FUNCTION scheduling.update_shift_temporal_columns();

COMMENT ON FUNCTION scheduling.update_shift_temporal_columns() IS 
'Automatically maintains day_of_week and hour_of_day columns when start_time changes';

-- =============================================================================
-- Serial No: MV-004 | MATERIALIZED VIEW: scheduling.mv_schedule_optimization_metrics
-- =============================================================================
-- Purpose: Pre-calculated metrics for schedule optimization algorithms
-- Business Case: This materialized view provides pre-calculated metrics that feed into 
--              schedule optimization algorithms, significantly improving the performance 
--              of automated scheduling systems. It aggregates historical data on employee 
--              preferences, shift coverage patterns, and scheduling constraints to enable 
--              intelligent, data-driven schedule generation. The view supports the 
--              scheduling engine by providing rapid access to optimization-relevant 
--              metrics without real-time calculations.
-- Refresh Strategy: Daily refresh with trigger-based updates for critical changes
-- KPI: Schedule generation time reduction, Optimization quality improvement, Algorithm performance
-- Feature Reference: F-OPT-005, F-AI-001, F-SCH-006
-- Dependencies: This view requires the following tables to exist:
--     scheduling.shifts
--     scheduling.shift_assignments
--     scheduling.shift_preferences
--     scheduling.employee_availability
--     scheduling.schedule_compliance
--     hr.employees
--     hr.departments
--     hr.positions
--     operations.locations
-- =============================================================================

DROP MATERIALIZED VIEW IF EXISTS scheduling.mv_schedule_optimization_metrics CASCADE;

CREATE MATERIALIZED VIEW scheduling.mv_schedule_optimization_metrics AS
WITH shift_history AS (
    -- Historical shift data with coverage status
    -- UPDATED: Using persistent columns instead of EXTRACT()
    SELECT 
        sh.shift_id,
        sh.department_id,
        sh.location_id,
        sh.position_id,
        sh.start_time::DATE AS shift_date,
        sh.day_of_week,  -- Now using persistent column
        sh.hour_of_day,  -- Now using persistent column
        sh.shift_type,
        sh.required_employee_count,
        sh.shift_status,
        CASE 
            WHEN sh.shift_status IN ('COMPLETED', 'IN_PROGRESS') THEN 1 
            ELSE 0 
        END AS was_filled
    FROM scheduling.shifts sh
    WHERE sh.start_time >= CURRENT_TIMESTAMP - INTERVAL '180 days'
),
assignment_history AS (
    -- Historical assignment performance data
    SELECT 
        sa.shift_id,
        sa.employee_id,
        sa.assignment_status,
        sa.assignment_type,
        sa.applied_pay_rate,
        sa.overtime_hours,
        COALESCE(sa.punctuality_score, 3.0) AS punctuality_score,
        COALESCE(sa.attendance_score, 3.0) AS attendance_score,
        COALESCE(sa.productivity_score, 3.0) AS productivity_score,
        CASE WHEN sa.assignment_status IN ('NO_SHOW', 'CANCELLED') THEN 1 ELSE 0 END AS is_failure,
        CASE WHEN sa.assignment_status = 'CONFIRMED' THEN 1 ELSE 0 END AS is_confirmed
    FROM scheduling.shift_assignments sa
    WHERE sa.scheduled_start_time >= CURRENT_TIMESTAMP - INTERVAL '180 days'
),
employee_preferences_agg AS (
    -- Aggregated employee preference data
    SELECT 
        sp.employee_id,
        sp.preference_type,
        AVG(sp.priority) AS avg_priority,
        COUNT(*) AS preference_count,
        COUNT(CASE WHEN sp.priority >= 5 THEN 1 END) AS positive_preference_count,
        COUNT(CASE WHEN sp.priority <= -5 THEN 1 END) AS negative_preference_count
    FROM scheduling.shift_preferences sp
    WHERE sp.is_approved = TRUE
    AND (sp.end_date IS NULL OR sp.end_date >= CURRENT_DATE)
    GROUP BY sp.employee_id, sp.preference_type
),
employee_availability_agg AS (
    -- Aggregated employee availability patterns
    SELECT 
        ea.employee_id,
        ea.day_of_week,
        COUNT(*) AS availability_slots,
        MAX(CASE WHEN ea.availability_type = 'UNAVAILABLE' THEN 1 ELSE 0 END) AS has_unavailable_slots
    FROM scheduling.employee_availability ea
    WHERE ea.is_approved = TRUE
    AND (ea.end_date IS NULL OR ea.end_date >= CURRENT_DATE)
    GROUP BY ea.employee_id, ea.day_of_week
),
compliance_history AS (
    -- Historical compliance violations per employee
    SELECT 
        sc.entity_id AS employee_id,
        COUNT(*) AS violation_count,
        AVG(CASE sc.violation_severity 
            WHEN 'CRITICAL' THEN 5 
            WHEN 'HIGH' THEN 4 
            WHEN 'MEDIUM' THEN 3 
            WHEN 'LOW' THEN 2 
            ELSE 1 
        END) AS avg_severity_score
    FROM scheduling.schedule_compliance sc
    WHERE sc.detected_at >= CURRENT_TIMESTAMP - INTERVAL '180 days'
    AND sc.entity_type = 'EMPLOYEE'
    GROUP BY sc.entity_id
),
coverage_difficulty AS (
    -- How hard is it to fill specific shift types/locations
    SELECT 
        sh.department_id,
        sh.location_id,
        sh.position_id,
        sh.day_of_week,
        sh.hour_of_day,
        sh.shift_type,
        COUNT(*) AS total_shifts,
        SUM(sh.was_filled) AS filled_shifts,
        ROUND((SUM(sh.was_filled)::NUMERIC / NULLIF(COUNT(*), 0)) * 100, 2) AS historical_fill_rate
    FROM shift_history sh
    GROUP BY sh.department_id, sh.location_id, sh.position_id, sh.day_of_week, sh.hour_of_day, sh.shift_type
)
SELECT 
    -- Dimension Keys
    ah.employee_id,
    e.employee_code,
    e.first_name,
    e.last_name,
    sh.department_id,
    d.department_name,
    sh.location_id,
    l.location_name,
    sh.position_id,
    p.position_title,
    sh.day_of_week,  -- Using persistent column
    sh.hour_of_day,  -- Using persistent column
    sh.shift_type,
    
    -- Employee Performance Metrics (Optimization Scores)
    ROUND(AVG(ah.punctuality_score), 2) AS avg_punctuality_score,
    ROUND(AVG(ah.attendance_score), 2) AS avg_attendance_score,
    ROUND(AVG(ah.productivity_score), 2) AS avg_productivity_score,
    ROUND((SUM(ah.is_confirmed)::NUMERIC / NULLIF(COUNT(*), 0)) * 100, 2) AS acceptance_rate,
    ROUND((SUM(ah.is_failure)::NUMERIC / NULLIF(COUNT(*), 0)) * 100, 2) AS failure_rate,
    
    -- Cost Metrics
    ROUND(AVG(ah.applied_pay_rate), 2) AS avg_hourly_rate,
    ROUND(SUM(ah.overtime_hours), 2) AS total_overtime_hours_180d,
    
    -- Preference & Availability Fit
    COALESCE(epa.avg_priority, 0) AS preference_priority_score,
    COALESCE(epa.positive_preference_count, 0) AS positive_preferences,
    COALESCE(epa.negative_preference_count, 0) AS negative_preferences,
    COALESCE(epa.preference_count, 0) AS total_preferences,
    COALESCE(eaa.availability_slots, 0) AS availability_slots_count,
    COALESCE(eaa.has_unavailable_slots, 0) AS has_conflicting_availability,
    
    -- Compliance Risk
    COALESCE(ch.violation_count, 0) AS compliance_violation_count,
    ROUND(COALESCE(ch.avg_severity_score, 0), 2) AS avg_compliance_severity,
    
    -- Shift Coverage Difficulty (Context for Optimization)
    cd.historical_fill_rate,
    cd.total_shifts AS shift_pattern_volume,
    
    -- Calculated Optimization Weights
    -- Higher score = Better candidate for this shift type
    ROUND((
        (COALESCE(AVG(ah.attendance_score), 3.0) * 2.0) + 
        (COALESCE(AVG(ah.punctuality_score), 3.0) * 1.5) + 
        (COALESCE(epa.avg_priority, 0) * 1.0) - 
        (COALESCE(ch.violation_count, 0) * 5.0) - 
        (COALESCE(eaa.has_unavailable_slots, 0) * 10.0)
    ), 2) AS optimization_candidate_score,
    
    -- Metadata
    CURRENT_TIMESTAMP AS calculated_at,
    COUNT(*) AS sample_size_assignments
FROM assignment_history ah
JOIN scheduling.shifts sh ON ah.shift_id = sh.shift_id
JOIN hr.employees e ON ah.employee_id = e.employee_id
JOIN hr.departments d ON sh.department_id = d.department_id
JOIN operations.locations l ON sh.location_id = l.location_id
JOIN hr.positions p ON sh.position_id = p.position_id
LEFT JOIN employee_preferences_agg epa ON ah.employee_id = epa.employee_id
-- UPDATED: Join now uses persistent column directly
LEFT JOIN employee_availability_agg eaa ON ah.employee_id = eaa.employee_id 
    AND eaa.day_of_week = sh.day_of_week
LEFT JOIN compliance_history ch ON ah.employee_id = ch.employee_id
LEFT JOIN coverage_difficulty cd ON 
    sh.department_id = cd.department_id AND 
    sh.location_id = cd.location_id AND 
    sh.position_id = cd.position_id AND 
    sh.day_of_week = cd.day_of_week AND 
    sh.hour_of_day = cd.hour_of_day AND
    sh.shift_type = cd.shift_type
WHERE e.employment_status = 'ACTIVE'
GROUP BY 
    ah.employee_id, e.employee_code, e.first_name, e.last_name,
    sh.department_id, d.department_name,
    sh.location_id, l.location_name,
    sh.position_id, p.position_title,
    sh.day_of_week, sh.hour_of_day, sh.shift_type,
    epa.avg_priority, epa.positive_preference_count, epa.negative_preference_count, epa.preference_count,
    eaa.availability_slots, eaa.has_unavailable_slots,
    ch.violation_count, ch.avg_severity_score,
    cd.historical_fill_rate, cd.total_shifts
WITH DATA;

