-- =============================================================================
-- Serial No: MV-005 | MATERIALIZED VIEW: compliance.mv_compliance_dashboard
-- =============================================================================
-- Purpose: Executive dashboard for compliance monitoring and reporting
-- Business Case: This materialized view provides a comprehensive compliance 
--   dashboard for executives and compliance officers, aggregating key compliance 
--   metrics across labor laws, union agreements, and company policies.
-- Refresh Strategy: Hourly refresh during business hours, daily overnight
-- KPI: Compliance visibility, Risk identification time, Audit preparation efficiency
-- Feature Reference: F-COMP-004, F-EXEC-001, F-AUDIT-003
-- =============================================================================
-- =============================================================================
-- Serial No: MV-005 | MATERIALIZED VIEW: compliance.mv_compliance_dashboard
-- =============================================================================
-- Purpose: Executive dashboard for compliance monitoring and reporting
-- Business Case: This materialized view provides a comprehensive compliance 
--   dashboard for executives and compliance officers, aggregating key compliance 
--   metrics across labor laws, union agreements, and company policies.
-- Refresh Strategy: Hourly refresh during business hours, daily overnight
-- KPI: Compliance visibility, Risk identification time, Audit preparation efficiency
-- Feature Reference: F-COMP-004, F-EXEC-001, F-AUDIT-003
-- =============================================================================
-- Add missing columns to scheduling.schedule_compliance
ALTER TABLE scheduling.schedule_compliance
ADD COLUMN IF NOT EXISTS is_regulatory BOOLEAN NOT NULL DEFAULT FALSE,
ADD COLUMN IF NOT EXISTS regulatory_body VARCHAR(100),
ADD COLUMN IF NOT EXISTS regulatory_reference VARCHAR(100);

-- Add comments for documentation
COMMENT ON COLUMN scheduling.schedule_compliance.is_regulatory IS 
'Indicates if this compliance violation is related to regulatory/labor law requirements';

COMMENT ON COLUMN scheduling.schedule_compliance.regulatory_body IS 
'Name of the regulatory body (e.g., Department of Labor, OSHA, NLRB)';

COMMENT ON COLUMN scheduling.schedule_compliance.regulatory_reference IS 
'Reference code or section of the regulation (e.g., FLSA Section 7, OSHA 1910)';

-- Create indexes for performance on new columns
CREATE INDEX IF NOT EXISTS idx_schedule_compliance_regulatory 
ON scheduling.schedule_compliance(is_regulatory) WHERE is_regulatory = TRUE;

CREATE INDEX IF NOT EXISTS idx_schedule_compliance_regulatory_body 
ON scheduling.schedule_compliance(regulatory_body) WHERE regulatory_body IS NOT NULL;

DROP MATERIALIZED VIEW IF EXISTS compliance.mv_compliance_dashboard CASCADE;

CREATE MATERIALIZED VIEW compliance.mv_compliance_dashboard AS
WITH compliance_summary AS (
    SELECT
        sc.schedule_id,
        sc.rule_id,
        sc.rule_type,
        sc.entity_type,
        sc.entity_id,
        sc.violation_severity,
        sc.status,
        sc.detected_at,
        sc.resolved_at,
        sc.resolved_by,
        sc.exception_approved_by,
        sc.is_regulatory,
        sc.regulatory_body,
        sc.regulatory_reference,
        CASE
            WHEN sc.resolved_at IS NOT NULL AND sc.detected_at IS NOT NULL
            THEN EXTRACT(EPOCH FROM (sc.resolved_at - sc.detected_at)) / 86400
            ELSE NULL
        END AS resolution_days,
        CASE
            WHEN sc.status != 'RESOLVED' AND sc.status != 'IGNORED' AND
                 sc.detected_at < CURRENT_TIMESTAMP - 
                 CASE sc.violation_severity
                     WHEN 'CRITICAL' THEN INTERVAL '7 days'
                     WHEN 'HIGH' THEN INTERVAL '14 days'
                     ELSE INTERVAL '30 days'
                 END
            THEN TRUE
            ELSE FALSE
        END AS is_overdue,
        CASE sc.violation_severity
            WHEN 'CRITICAL' THEN 100
            WHEN 'HIGH' THEN 75
            WHEN 'MEDIUM' THEN 50
            WHEN 'LOW' THEN 25
            ELSE 0
        END AS risk_score
    FROM scheduling.schedule_compliance sc
    WHERE sc.detected_at >= CURRENT_TIMESTAMP - INTERVAL '365 days'
),
violation_counts AS (
    SELECT
        violation_severity,
        status,
        COUNT(*) AS violation_count,
        SUM(risk_score) AS total_risk_score,
        COUNT(CASE WHEN is_overdue THEN 1 END) AS overdue_count,
        COUNT(CASE WHEN is_regulatory THEN 1 END) AS regulatory_count,
        AVG(resolution_days) AS avg_resolution_days
    FROM compliance_summary
    GROUP BY violation_severity, status
),
violation_by_type AS (
    SELECT
        rule_type,
        COUNT(*) AS violation_count,
        SUM(risk_score) AS total_risk_score,
        COUNT(CASE WHEN status = 'RESOLVED' THEN 1 END) AS resolved_count,
        COUNT(CASE WHEN status = 'OPEN' THEN 1 END) AS open_count,
        ROUND(
            COUNT(CASE WHEN status = 'RESOLVED' THEN 1 END)::NUMERIC / 
            NULLIF(COUNT(*), 0) * 100, 2
        ) AS resolution_rate
    FROM compliance_summary
    GROUP BY rule_type
),
violation_by_department AS (
    SELECT
        d.department_id,
        d.department_name,
        COUNT(cs.violation_severity) AS violation_count,
        SUM(cs.risk_score) AS total_risk_score,
        COUNT(CASE WHEN cs.violation_severity = 'CRITICAL' THEN 1 END) AS critical_count,
        COUNT(CASE WHEN cs.violation_severity = 'HIGH' THEN 1 END) AS high_count,
        COUNT(CASE WHEN cs.status = 'OPEN' THEN 1 END) AS open_violations,
        ROUND(
            COUNT(CASE WHEN cs.status = 'RESOLVED' THEN 1 END)::NUMERIC / 
            NULLIF(COUNT(cs.violation_severity), 0) * 100, 2
        ) AS resolution_rate
    FROM compliance_summary cs
    LEFT JOIN hr.departments d ON cs.entity_id = d.department_id 
        AND cs.entity_type = 'DEPARTMENT'
    GROUP BY d.department_id, d.department_name
),
violation_by_location AS (
    SELECT
        l.location_id,
        l.location_name,
        l.region,
        l.country_code,
        COUNT(cs.violation_severity) AS violation_count,
        SUM(cs.risk_score) AS total_risk_score,
        COUNT(CASE WHEN cs.violation_severity = 'CRITICAL' THEN 1 END) AS critical_count,
        COUNT(CASE WHEN cs.is_regulatory THEN 1 END) AS regulatory_count,
        ROUND(
            COUNT(CASE WHEN cs.status = 'RESOLVED' THEN 1 END)::NUMERIC / 
            NULLIF(COUNT(cs.violation_severity), 0) * 100, 2
        ) AS resolution_rate
    FROM compliance_summary cs
    LEFT JOIN operations.locations l ON cs.entity_id = l.location_id 
        AND cs.entity_type = 'LOCATION'
    GROUP BY l.location_id, l.location_name, l.region, l.country_code
),
violation_trends AS (
    SELECT
        DATE_TRUNC('week', detected_at) AS week_start,
        COUNT(*) AS violation_count,
        SUM(risk_score) AS total_risk_score,
        COUNT(CASE WHEN violation_severity IN ('CRITICAL', 'HIGH') THEN 1 END) AS high_severity_count,
        COUNT(CASE WHEN status = 'RESOLVED' THEN 1 END) AS resolved_count
    FROM compliance_summary
    WHERE detected_at >= CURRENT_TIMESTAMP - INTERVAL '12 weeks'
    GROUP BY DATE_TRUNC('week', detected_at)
),
regulatory_summary AS (
    SELECT
        regulatory_body,
        regulatory_reference,
        COUNT(*) AS violation_count,
        COUNT(CASE WHEN violation_severity = 'CRITICAL' THEN 1 END) AS critical_count,
        COUNT(CASE WHEN status = 'OPEN' THEN 1 END) AS open_count,
        COUNT(CASE WHEN status = 'RESOLVED' THEN 1 END) AS resolved_count,
        AVG(CASE WHEN resolved_at IS NOT NULL THEN resolution_days END) AS avg_resolution_days
    FROM compliance_summary
    WHERE is_regulatory = TRUE
    GROUP BY regulatory_body, regulatory_reference
),
audit_readiness AS (
    SELECT
        COUNT(CASE WHEN status = 'RESOLVED' THEN 1 END) AS resolved_violations,
        COUNT(CASE WHEN status = 'OPEN' AND violation_severity IN ('CRITICAL', 'HIGH') THEN 1 END) AS critical_open_violations,
        COUNT(CASE WHEN is_overdue THEN 1 END) AS overdue_violations,
        COUNT(*) AS total_violations,
        ROUND(
            COUNT(CASE WHEN status = 'RESOLVED' THEN 1 END)::NUMERIC / 
            NULLIF(COUNT(*), 0) * 100, 2
        ) AS overall_resolution_rate,
        ROUND(
            COUNT(CASE WHEN status != 'OPEN' THEN 1 END)::NUMERIC / 
            NULLIF(COUNT(*), 0) * 100, 2
        ) AS compliance_rate
    FROM compliance_summary
    WHERE detected_at >= CURRENT_TIMESTAMP - INTERVAL '90 days'
),
union_compliance AS (
    SELECT
        ur.rule_type,
        COUNT(cs.violation_severity) AS violation_count,
        COUNT(CASE WHEN cs.status = 'RESOLVED' THEN 1 END) AS resolved_count,
        COUNT(CASE WHEN cs.exception_approved_by IS NOT NULL THEN 1 END) AS exception_count,
        ROUND(
            COUNT(CASE WHEN cs.status = 'RESOLVED' THEN 1 END)::NUMERIC / 
            NULLIF(COUNT(cs.violation_severity), 0) * 100, 2
        ) AS resolution_rate
    FROM compliance_summary cs
    LEFT JOIN compliance.union_rules ur ON cs.rule_id = ur.rule_id
    WHERE cs.rule_type = 'UNION_AGREEMENT'
    GROUP BY ur.rule_type
)
SELECT
    -- Overall Summary Metrics
    (SELECT COUNT(*) FROM compliance_summary) AS total_violations_all_time,
    (SELECT COUNT(*) FROM compliance_summary WHERE detected_at >= CURRENT_TIMESTAMP - INTERVAL '30 days') AS violations_last_30_days,
    (SELECT COUNT(*) FROM compliance_summary WHERE detected_at >= CURRENT_TIMESTAMP - INTERVAL '90 days') AS violations_last_90_days,
    (SELECT COUNT(*) FROM compliance_summary WHERE detected_at >= CURRENT_TIMESTAMP - INTERVAL '365 days') AS violations_last_year,
    
    -- Severity Breakdown (Last 90 Days)
    (SELECT COALESCE(SUM(violation_count), 0) FROM violation_counts WHERE violation_severity = 'CRITICAL' AND status IN ('OPEN', 'IN_PROGRESS')) AS critical_open_violations,
    (SELECT COALESCE(SUM(violation_count), 0) FROM violation_counts WHERE violation_severity = 'HIGH' AND status IN ('OPEN', 'IN_PROGRESS')) AS high_open_violations,
    (SELECT COALESCE(SUM(violation_count), 0) FROM violation_counts WHERE violation_severity = 'MEDIUM' AND status IN ('OPEN', 'IN_PROGRESS')) AS medium_open_violations,
    (SELECT COALESCE(SUM(violation_count), 0) FROM violation_counts WHERE violation_severity = 'LOW' AND status IN ('OPEN', 'IN_PROGRESS')) AS low_open_violations,
    
    -- Resolution Metrics (Last 90 Days)
    (SELECT COALESCE(avg_resolution_days, 0) FROM violation_counts WHERE violation_severity = 'CRITICAL' AND status = 'RESOLVED') AS avg_critical_resolution_days,
    (SELECT COALESCE(avg_resolution_days, 0) FROM violation_counts WHERE violation_severity = 'HIGH' AND status = 'RESOLVED') AS avg_high_resolution_days,
    (SELECT COALESCE(overall_resolution_rate, 0) FROM audit_readiness) AS overall_resolution_rate,
    (SELECT COALESCE(compliance_rate, 0) FROM audit_readiness) AS compliance_rate_percentage,
    
    -- Risk Metrics
    (SELECT COALESCE(SUM(total_risk_score), 0) FROM violation_counts WHERE status IN ('OPEN', 'IN_PROGRESS')) AS total_open_risk_score,
    (SELECT COALESCE(SUM(overdue_count), 0) FROM violation_counts) AS total_overdue_violations,
    (SELECT COALESCE(SUM(regulatory_count), 0) FROM violation_counts) AS total_regulatory_violations,
    
    -- Violation by Type (Last 90 Days) - FIXED
    (SELECT jsonb_object_agg(rule_type, violation_count) FROM violation_by_type) AS violations_by_type_json,
    (SELECT jsonb_object_agg(rule_type, resolution_rate) FROM violation_by_type) AS resolution_rate_by_type_json,
    
    -- Top 5 Departments by Violations (Last 90 Days) - FIXED with subquery
    (SELECT jsonb_agg(jsonb_build_object(
        'department_id', department_id,
        'department_name', department_name,
        'violation_count', violation_count,
        'critical_count', critical_count,
        'resolution_rate', resolution_rate
    ))
    FROM (
        SELECT department_id, department_name, violation_count, critical_count, resolution_rate
        FROM violation_by_department
        ORDER BY violation_count DESC
        LIMIT 5
    ) t) AS top_departments_json,
    
    -- Top 5 Locations by Violations (Last 90 Days) - FIXED with subquery
    (SELECT jsonb_agg(jsonb_build_object(
        'location_id', location_id,
        'location_name', location_name,
        'region', region,
        'violation_count', violation_count,
        'critical_count', critical_count,
        'regulatory_count', regulatory_count,
        'resolution_rate', resolution_rate
    ))
    FROM (
        SELECT location_id, location_name, region, violation_count, critical_count, regulatory_count, resolution_rate
        FROM violation_by_location
        ORDER BY violation_count DESC
        LIMIT 5
    ) t) AS top_locations_json,
    
    -- Weekly Trends (Last 12 Weeks)
    (SELECT jsonb_agg(jsonb_build_object(
        'week_start', week_start,
        'violation_count', violation_count,
        'total_risk_score', total_risk_score,
        'high_severity_count', high_severity_count,
        'resolved_count', resolved_count
    ) ORDER BY week_start)
    FROM violation_trends) AS weekly_trends_json,
    
    -- Regulatory Summary - FIXED (removed extra parenthesis)
    (SELECT jsonb_agg(jsonb_build_object(
        'regulatory_body', regulatory_body,
        'regulatory_reference', regulatory_reference,
        'violation_count', violation_count,
        'critical_count', critical_count,
        'open_count', open_count,
        'resolved_count', resolved_count,
        'avg_resolution_days', avg_resolution_days
    ))
    FROM regulatory_summary) AS regulatory_summary_json,
    
    -- Union Compliance Metrics - FIXED (removed extra parenthesis)
    (SELECT jsonb_object_agg(rule_type, jsonb_build_object(
        'violation_count', violation_count,
        'resolved_count', resolved_count,
        'exception_count', exception_count,
        'resolution_rate', resolution_rate
    ))
    FROM union_compliance) AS union_compliance_json,
    
    -- Audit Readiness Score (0-100)
    ROUND(
        (SELECT COALESCE(compliance_rate, 0) FROM audit_readiness) * 0.4 +
        (SELECT COALESCE(overall_resolution_rate, 0) FROM audit_readiness) * 0.3 +
        (CASE 
            WHEN (SELECT COALESCE(critical_open_violations, 0) FROM audit_readiness) = 0 THEN 30
            WHEN (SELECT COALESCE(critical_open_violations, 0) FROM audit_readiness) <= 2 THEN 20
            WHEN (SELECT COALESCE(critical_open_violations, 0) FROM audit_readiness) <= 5 THEN 10
            ELSE 0
        END) +
        (CASE 
            WHEN (SELECT COALESCE(overdue_violations, 0) FROM audit_readiness) = 0 THEN 20
            WHEN (SELECT COALESCE(overdue_violations, 0) FROM audit_readiness) <= 5 THEN 10
            ELSE 0
        END), 2
    ) AS audit_readiness_score,
    
    -- Risk Category
    CASE
        WHEN (SELECT COALESCE(critical_open_violations, 0) FROM audit_readiness) > 5 
             OR (SELECT COALESCE(overdue_violations, 0) FROM audit_readiness) > 10 THEN 'CRITICAL'
        WHEN (SELECT COALESCE(critical_open_violations, 0) FROM audit_readiness) > 2 
             OR (SELECT COALESCE(overdue_violations, 0) FROM audit_readiness) > 5 THEN 'HIGH'
        WHEN (SELECT COALESCE(critical_open_violations, 0) FROM audit_readiness) > 0 
             OR (SELECT COALESCE(overdue_violations, 0) FROM audit_readiness) > 0 THEN 'MEDIUM'
        ELSE 'LOW'
    END AS overall_risk_category,
    
    -- Refresh Metadata
    CURRENT_TIMESTAMP AS calculated_at,
    CURRENT_DATE AS report_date,
    DATE_TRUNC('month', CURRENT_DATE) AS report_month,
    DATE_TRUNC('quarter', CURRENT_DATE) AS report_quarter,
    EXTRACT(YEAR FROM CURRENT_DATE) AS report_year
    
FROM compliance_summary
LIMIT 1;

-- Create unique index for concurrent refresh
CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_compliance_dashboard_primary
ON compliance.mv_compliance_dashboard(report_date);

-- Create additional indexes for performance
CREATE INDEX IF NOT EXISTS idx_mv_compliance_dashboard_calculated_at
ON compliance.mv_compliance_dashboard(calculated_at DESC);

CREATE INDEX IF NOT EXISTS idx_mv_compliance_dashboard_risk_category
ON compliance.mv_compliance_dashboard(overall_risk_category);

CREATE INDEX IF NOT EXISTS idx_mv_compliance_dashboard_audit_score
ON compliance.mv_compliance_dashboard(audit_readiness_score DESC);

-- Add comments for documentation
COMMENT ON MATERIALIZED VIEW compliance.mv_compliance_dashboard IS
'Executive dashboard for compliance monitoring and reporting. Aggregates key compliance metrics 
across labor laws, union agreements, and company policies. Enables real-time monitoring of compliance 
status, identification of high-risk areas, and tracking of remediation efforts.';

COMMENT ON COLUMN compliance.mv_compliance_dashboard.total_violations_all_time IS
'Total number of compliance violations detected in the system (all time)';

COMMENT ON COLUMN compliance.mv_compliance_dashboard.critical_open_violations IS
'Number of open CRITICAL severity violations requiring immediate attention';

COMMENT ON COLUMN compliance.mv_compliance_dashboard.overall_resolution_rate IS
'Percentage of violations that have been resolved (last 90 days)';

COMMENT ON COLUMN compliance.mv_compliance_dashboard.compliance_rate_percentage IS
'Overall compliance rate percentage (non-open violations / total violations)';

COMMENT ON COLUMN compliance.mv_compliance_dashboard.total_open_risk_score IS
'Aggregate risk score for all open violations (CRITICAL=100, HIGH=75, MEDIUM=50, LOW=25)';

COMMENT ON COLUMN compliance.mv_compliance_dashboard.top_departments_json IS
'JSON array of top 5 departments by violation count with metrics';

COMMENT ON COLUMN compliance.mv_compliance_dashboard.top_locations_json IS
'JSON array of top 5 locations by violation count with metrics';

COMMENT ON COLUMN compliance.mv_compliance_dashboard.audit_readiness_score IS
'Composite audit readiness score (0-100) based on resolution rate, critical violations, and overdue violations';

COMMENT ON COLUMN compliance.mv_compliance_dashboard.overall_risk_category IS
'Overall risk category (CRITICAL, HIGH, MEDIUM, LOW) based on violation severity and count';

-- =============================================================================
-- Serial No: MV-006 | MATERIALIZED VIEW: analytics.mv_workforce_productivity
-- =============================================================================
-- Purpose: Comprehensive workforce productivity analytics with historical trends
-- Business Case: This materialized view provides comprehensive workforce productivity 
--              analytics, enabling data-driven decisions about staffing levels, 
--              employee development, and operational efficiency. It aggregates 
--              productivity metrics across multiple dimensions including individual 
--              employees, teams, departments, and locations, with historical trend 
--              analysis for pattern identification. The view supports strategic 
--              workforce planning, performance management, and continuous improvement 
--              initiatives by providing instant access to key productivity indicators.
-- Refresh Strategy: Daily refresh with weekly full rebuild
-- KPI: Productivity trend visibility, Workforce optimization efficiency, 
--      Performance management effectiveness
-- Feature Reference: F-PROD-001, F-ANA-009, F-REP-006
-- Dependencies: scheduling.shift_assignments, scheduling.shifts, hr.employees, 
--               hr.departments, operations.locations, hr.positions, 
--               analytics.performance_metrics, system.mv_refresh_history
-- =============================================================================

-- Drop existing view if exists to ensure clean deployment
DROP MATERIALIZED VIEW IF EXISTS analytics.mv_workforce_productivity CASCADE;

-- Create the Materialized View
CREATE MATERIALIZED VIEW analytics.mv_workforce_productivity AS
WITH assignment_base AS (
    -- Base assignment data with time calculations
    SELECT 
        sa.assignment_id,
        sa.employee_id,
        sa.shift_id,
        sa.assignment_status,
        sa.scheduled_start_time,
        sa.scheduled_end_time,
        sa.actual_start_time,
        sa.actual_end_time,
        sa.break_start_time,
        sa.break_end_time,
        -- CALCULATE productive_duration_minutes from base columns
        COALESCE(
            EXTRACT(EPOCH FROM (
                COALESCE(sa.actual_end_time, sa.scheduled_end_time) - 
                COALESCE(sa.actual_start_time, sa.scheduled_start_time)
            )) / 60,
            EXTRACT(EPOCH FROM (sa.scheduled_end_time - sa.scheduled_start_time)) / 60
        ) - COALESCE(
            EXTRACT(EPOCH FROM (
                COALESCE(sa.break_end_time, sa.break_start_time) - 
                COALESCE(sa.break_start_time, sa.break_end_time)
            )) / 60,
            0
        ) AS productive_duration_minutes,
        -- Calculate scheduled minutes
        EXTRACT(EPOCH FROM (sa.scheduled_end_time - sa.scheduled_start_time)) / 60 AS scheduled_minutes,
        DATE_TRUNC('day', sa.scheduled_start_time)::DATE AS work_date,
        DATE_TRUNC('week', sa.scheduled_start_time)::DATE AS work_week,
        DATE_TRUNC('month', sa.scheduled_start_time)::DATE AS work_month,
        EXTRACT(YEAR FROM sa.scheduled_start_time) AS work_year,
        EXTRACT(MONTH FROM sa.scheduled_start_time) AS work_month_num,
        sh.department_id,
        sh.location_id,
        sh.position_id,
        -- FIXED: Use shift_type instead of shift_category
        sh.shift_type AS shift_category
    FROM scheduling.shift_assignments sa
    JOIN scheduling.shifts sh ON sa.shift_id = sh.shift_id
    WHERE sa.assignment_status IN ('CONFIRMED', 'COMPLETED', 'IN_PROGRESS', 'ASSIGNED')
    AND sa.scheduled_start_time >= CURRENT_DATE - INTERVAL '2 years'
),
employee_details AS (
    -- Enrich with employee hierarchy info
    SELECT 
        ab.*,
        e.employee_code,
        e.first_name,
        e.last_name,
        e.department_id AS emp_department_id,
        e.location_id AS emp_location_id,
        e.position_id AS emp_position_id,
        d.department_name,
        l.location_name,
        p.position_title
    FROM assignment_base ab
    JOIN hr.employees e ON ab.employee_id = e.employee_id
    LEFT JOIN hr.departments d ON e.department_id = d.department_id
    LEFT JOIN operations.locations l ON e.location_id = l.location_id
    LEFT JOIN hr.positions p ON e.position_id = p.position_id
    WHERE e.employment_status IN ('ACTIVE', 'PROBATION', 'ON_LEAVE')
),
performance_scores AS (
    -- Aggregate performance metrics from the analytics table
    SELECT 
        pm.employee_id,
        DATE_TRUNC('month', pm.measurement_period_start)::DATE AS metric_month,
        AVG(CASE WHEN pm.metric_type = 'PRODUCTIVITY' THEN pm.metric_value END) AS avg_productivity_score,
        AVG(CASE WHEN pm.metric_type = 'QUALITY' THEN pm.metric_value END) AS avg_quality_score,
        AVG(CASE WHEN pm.metric_type = 'ATTENDANCE' THEN pm.metric_value END) AS avg_attendance_score,
        COUNT(DISTINCT pm.metric_id) AS metric_count
    FROM analytics.performance_metrics pm
    WHERE pm.is_current = TRUE 
    AND pm.measurement_period_start >= CURRENT_DATE - INTERVAL '2 years'
    GROUP BY pm.employee_id, DATE_TRUNC('month', pm.measurement_period_start)::DATE
)
SELECT 
    -- Time Dimensions
    ed.work_date,
    ed.work_week,
    ed.work_month,
    ed.work_year,
    ed.work_month_num,
    
    -- Organizational Dimensions
    ed.department_id,
    ed.department_name,
    ed.location_id,
    ed.location_name,
    ed.position_id,
    ed.position_title,
    ed.shift_category,
    
    -- Employee Dimension
    ed.employee_id,
    ed.employee_code,
    ed.first_name,
    ed.last_name,
    
    -- Productivity Metrics
    COUNT(DISTINCT ed.assignment_id) AS total_assignments,
    COUNT(DISTINCT ed.shift_id) AS total_shifts,
    ROUND(SUM(ed.productive_duration_minutes) / 60.0, 2) AS total_productive_hours,
    ROUND(SUM(ed.scheduled_minutes) / 60.0, 2) AS total_scheduled_hours,
    ROUND(AVG(ed.productive_duration_minutes / NULLIF(ed.scheduled_minutes, 0)) * 100, 2) AS avg_efficiency_rate,
    
    -- Attendance/Adherence Metrics
    COUNT(CASE WHEN ed.actual_start_time IS NOT NULL THEN 1 END) AS shifts_worked,
    ROUND(AVG(CASE 
        WHEN ed.actual_start_time IS NULL THEN 0
        WHEN ed.actual_start_time <= ed.scheduled_start_time + INTERVAL '15 minutes' THEN 100
        WHEN ed.actual_start_time <= ed.scheduled_start_time + INTERVAL '30 minutes' THEN 80
        ELSE 60 
    END), 2) AS avg_punctuality_score,
    
    -- Performance Integration (Joined on Month)
    COALESCE(ps.avg_productivity_score, 0.0) AS monthly_productivity_score,
    COALESCE(ps.avg_quality_score, 0.0) AS monthly_quality_score,
    COALESCE(ps.avg_attendance_score, 0.0) AS monthly_attendance_score,
    COALESCE(ps.metric_count, 0) AS performance_metric_count,
    
    -- Calculated KPIs
    ROUND(
        (SUM(ed.productive_duration_minutes) / 60.0) / NULLIF(COUNT(DISTINCT ed.shift_id), 0), 
        2
    ) AS avg_hours_per_shift,
    
    -- Metadata
    CURRENT_TIMESTAMP AS calculated_at,
    COUNT(*) OVER (PARTITION BY ed.work_month) AS monthly_total_assignments_context
FROM employee_details ed
LEFT JOIN performance_scores ps 
    ON ed.employee_id = ps.employee_id 
    AND ed.work_month = ps.metric_month
GROUP BY 
    ed.work_date,
    ed.work_week,
    ed.work_month,
    ed.work_year,
    ed.work_month_num,
    ed.department_id,
    ed.department_name,
    ed.location_id,
    ed.location_name,
    ed.position_id,
    ed.position_title,
    ed.shift_category,
    ed.employee_id,
    ed.employee_code,
    ed.first_name,
    ed.last_name,
    ps.avg_productivity_score,
    ps.avg_quality_score,
    ps.avg_attendance_score,
    ps.metric_count
ORDER BY 
    ed.work_date DESC, 
    ed.department_name, 
    ed.employee_code;

