-- =============================================================================
-- DOCUMENTATION
-- =============================================================================

COMMENT ON MATERIALIZED VIEW analytics.mv_workforce_productivity IS 
'Comprehensive workforce productivity analytics with historical trends. Aggregates productivity metrics 
across employees, teams, departments, and locations. Supports strategic workforce planning and performance 
management. Refreshed daily with weekly full rebuild.';

COMMENT ON COLUMN analytics.mv_workforce_productivity.work_date IS 'Daily granularity for productivity tracking';
COMMENT ON COLUMN analytics.mv_workforce_productivity.work_week IS 'Weekly granularity for trend analysis';
COMMENT ON COLUMN analytics.mv_workforce_productivity.work_month IS 'Monthly granularity for reporting';
COMMENT ON COLUMN analytics.mv_workforce_productivity.total_productive_hours IS 'Sum of actual productive minutes converted to hours';
COMMENT ON COLUMN analytics.mv_workforce_productivity.avg_efficiency_rate IS 'Percentage of scheduled time that was productive';
COMMENT ON COLUMN analytics.mv_workforce_productivity.avg_punctuality_score IS 'Score 0-100 based on arrival time vs scheduled start';
COMMENT ON COLUMN analytics.mv_workforce_productivity.monthly_productivity_score IS 'Integrated score from analytics.performance_metrics table';
COMMENT ON COLUMN analytics.mv_workforce_productivity.avg_hours_per_shift IS 'Average productive hours per shift worked';

-- =============================================================================
-- REFRESH FUNCTION
-- =============================================================================
-- Implements the "Daily refresh with weekly full rebuild" strategy
-- =============================================================================
 DROP FUNCTION analytics.refresh_mv_workforce_productivity();
CREATE OR REPLACE FUNCTION analytics.refresh_mv_workforce_productivity()
RETURNS TABLE (
    refresh_status VARCHAR(20),
    refresh_duration_ms INTEGER,
    rows_affected INTEGER,
    error_message TEXT
) AS $$
DECLARE
    v_start_time TIMESTAMPTZ := CURRENT_TIMESTAMP;
    v_end_time TIMESTAMPTZ;
    v_row_count INTEGER;
    v_error_message TEXT;
    v_status VARCHAR(20) := 'SUCCESS';
    v_is_weekly_refresh BOOLEAN;
BEGIN
    -- Determine if this is a weekly full rebuild (e.g., every Sunday)
    -- Using EXTRACT(DOW FROM CURRENT_DATE) = 0 for Sunday
    v_is_weekly_refresh := (EXTRACT(DOW FROM CURRENT_DATE) = 0);
    
    BEGIN
        -- Execute refresh based on strategy
        IF v_is_weekly_refresh THEN
            -- Full rebuild on weekly cycle
            REFRESH MATERIALIZED VIEW analytics.mv_workforce_productivity;
        ELSE
            -- Concurrent refresh for daily updates (non-blocking)
            REFRESH MATERIALIZED VIEW CONCURRENTLY analytics.mv_workforce_productivity;
        END IF;
        
        -- Get row count
        SELECT COUNT(*) INTO v_row_count FROM analytics.mv_workforce_productivity;
        
        -- Calculate duration
        v_end_time := CURRENT_TIMESTAMP;
        
        -- Log to refresh history table (if exists)
        BEGIN
            INSERT INTO system.mv_refresh_history (
                materialized_view,
                refresh_time,
                duration_ms,
                rows_affected,
                status,
                refresh_type
            ) VALUES (
                'analytics.mv_workforce_productivity',
                CURRENT_TIMESTAMP,
                EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000,
                v_row_count,
                'SUCCESS',
                CASE WHEN v_is_weekly_refresh THEN 'FULL' ELSE 'CONCURRENT' END
            );
        EXCEPTION WHEN OTHERS THEN
            -- Ignore logging errors to prevent refresh failure
            NULL;
        END;
        
        -- Return success
        RETURN QUERY SELECT 
            v_status, 
            EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000::INTEGER, 
            v_row_count, 
            NULL::TEXT;
            
    EXCEPTION WHEN OTHERS THEN
        GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;
        v_status := 'FAILED';
        v_end_time := CURRENT_TIMESTAMP;
        
        -- Log failure
        BEGIN
            INSERT INTO system.mv_refresh_history (
                materialized_view,
                refresh_time,
                duration_ms,
                error_message,
                status,
                refresh_type
            ) VALUES (
                'analytics.mv_workforce_productivity',
                CURRENT_TIMESTAMP,
                EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000,
                v_error_message,
                'FAILED',
                CASE WHEN v_is_weekly_refresh THEN 'FULL' ELSE 'CONCURRENT' END
            );
        EXCEPTION WHEN OTHERS THEN
            NULL;
        END;
        
        -- Return failure
        RETURN QUERY SELECT 
            v_status, 
            EXTRACT(EPOCH FROM (v_end_time - v_start_time)) * 1000::INTEGER, 
            0, 
            v_error_message;
    END;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION analytics.refresh_mv_workforce_productivity IS 
'Refreshes the workforce productivity materialized view. Performs full rebuild on Sundays, concurrent refresh on other days. Logs results to system.mv_refresh_history.';

