-- =============================================================================
-- Serial No: CC-001 | TABLE: finance.cost_centers
-- =============================================================================
-- Purpose: Master table for organizational cost centers used in labor cost tracking
-- Business Case: This table serves as the central repository for all cost centers 
--   within the organization, enabling accurate labor cost allocation, budget 
--   tracking, and financial reporting. Cost centers are critical for assigning 
--   labor expenses to specific departments, projects, or operational units. 
--   This enables finance teams to track labor costs against budgets, analyze 
--   cost efficiency by department, and support accurate financial forecasting. 
--   The table supports hierarchical cost center structures for complex 
--   organizations and integrates with the general ledger for financial reporting.
-- KPI: Cost center coverage rate, Labor cost allocation accuracy, 
--      Budget variance tracking, Cost reporting timeliness
-- Feature Reference: F-FIN-001, F-FIN-002, F-BUDGET-001, F-REPORT-001
-- =============================================================================

-- Drop existing table if exists (for clean deployment)
DROP TABLE IF EXISTS finance.cost_centers CASCADE;

-- Create the cost_centers table
CREATE TABLE finance.cost_centers (
    -- Primary identifiers
    cost_center_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    cost_center_code VARCHAR(50) UNIQUE NOT NULL 
        CHECK (cost_center_code ~ '^[A-Z0-9_-]{3,50}$'),
    
    -- Core cost center information
    cost_center_name VARCHAR(200) NOT NULL,
    cost_center_description TEXT,
    cost_center_type VARCHAR(50) NOT NULL DEFAULT 'OPERATIONAL'
        CHECK (cost_center_type IN (
            'OPERATIONAL', 'CAPITAL', 'PROJECT', 'DEPARTMENT', 
            'LOCATION', 'DIVISION', 'ENTERPRISE', 'OVERHEAD'
        )),
    
    -- Hierarchical structure
    parent_cost_center_id UUID REFERENCES finance.cost_centers(cost_center_id),
    hierarchy_level INTEGER DEFAULT 1 CHECK (hierarchy_level >= 1),
    cost_center_path LTREE, -- For efficient hierarchical queries
    
    -- Organizational context
    department_id UUID REFERENCES hr.departments(department_id),
    location_id UUID REFERENCES operations.locations(location_id),
    project_id UUID, -- Would reference projects table if exists
    
    -- Financial attributes
    currency VARCHAR(3) DEFAULT 'USD',
    fiscal_year_start DATE,
    fiscal_year_end DATE,
    budget_amount NUMERIC(14,2) CHECK (budget_amount >= 0),
    actual_amount NUMERIC(14,2) DEFAULT 0 CHECK (actual_amount >= 0),
    
    -- Status and flags
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_billable BOOLEAN DEFAULT FALSE,
    is_profit_center BOOLEAN DEFAULT FALSE,
    is_overhead BOOLEAN DEFAULT FALSE,
    
    -- Management
    manager_id UUID REFERENCES hr.employees(employee_id),
    finance_contact_id UUID REFERENCES hr.employees(employee_id),
    
    -- General Ledger integration
    gl_account_code VARCHAR(50),
    gl_company_code VARCHAR(20),
    gl_segment_1 VARCHAR(50),
    gl_segment_2 VARCHAR(50),
    gl_segment_3 VARCHAR(50),
    
    -- Allocation rules
    allocation_method VARCHAR(50) DEFAULT 'DIRECT'
        CHECK (allocation_method IN (
            'DIRECT', 'STEP_DOWN', 'RECIPROCAL', 'ACTIVITY_BASED'
        )),
    allocation_percentage NUMERIC(5,2) DEFAULT 100.00 
        CHECK (allocation_percentage BETWEEN 0 AND 100),
    
    -- Effective dates
    effective_start_date DATE NOT NULL DEFAULT CURRENT_DATE,
    effective_end_date DATE,
    
    -- Audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    updated_by UUID REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- Flexible metadata
    metadata JSONB DEFAULT '{}'::JSONB,
    tags TEXT[] DEFAULT '{}',
    
    -- Constraints
    CONSTRAINT chk_cost_center_dates CHECK (
        effective_end_date IS NULL OR effective_end_date >= effective_start_date
    ),
    CONSTRAINT chk_parent_not_self CHECK (
        parent_cost_center_id IS NULL OR parent_cost_center_id != cost_center_id
    ),
    CONSTRAINT chk_budget_consistency CHECK (
        budget_amount IS NULL OR actual_amount IS NULL OR 
        budget_amount >= 0 AND actual_amount >= 0
    )
);

-- =============================================================================
-- INDEXES FOR PERFORMANCE OPTIMIZATION
-- =============================================================================

-- Primary lookup indexes
CREATE INDEX IF NOT EXISTS idx_cost_centers_code 
    ON finance.cost_centers(cost_center_code);
CREATE INDEX IF NOT EXISTS idx_cost_centers_name 
    ON finance.cost_centers(cost_center_name);
CREATE INDEX IF NOT EXISTS idx_cost_centers_type 
    ON finance.cost_centers(cost_center_type) WHERE is_active = TRUE;

-- Hierarchical indexes
CREATE INDEX IF NOT EXISTS idx_cost_centers_parent 
    ON finance.cost_centers(parent_cost_center_id) WHERE parent_cost_center_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_cost_centers_hierarchy 
    ON finance.cost_centers(hierarchy_level);
CREATE INDEX IF NOT EXISTS idx_cost_centers_path 
    ON finance.cost_centers USING GIST(cost_center_path);

-- Organizational indexes
CREATE INDEX IF NOT EXISTS idx_cost_centers_department 
    ON finance.cost_centers(department_id) WHERE department_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_cost_centers_location 
    ON finance.cost_centers(location_id) WHERE location_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_cost_centers_manager 
    ON finance.cost_centers(manager_id) WHERE manager_id IS NOT NULL;

-- Financial indexes
CREATE INDEX IF NOT EXISTS idx_cost_centers_gl_account 
    ON finance.cost_centers(gl_account_code) WHERE gl_account_code IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_cost_centers_budget 
    ON finance.cost_centers(budget_amount DESC) WHERE budget_amount IS NOT NULL;

-- Status indexes
CREATE INDEX IF NOT EXISTS idx_cost_centers_active 
    ON finance.cost_centers(is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_cost_centers_billable 
    ON finance.cost_centers(is_billable) WHERE is_billable = TRUE;

-- Date range indexes
CREATE INDEX IF NOT EXISTS idx_cost_centers_effective_dates 
    ON finance.cost_centers(effective_start_date, effective_end_date);

-- JSONB and array indexes
CREATE INDEX IF NOT EXISTS idx_cost_centers_metadata 
    ON finance.cost_centers USING GIN(metadata);
CREATE INDEX IF NOT EXISTS idx_cost_centers_tags 
    ON finance.cost_centers USING GIN(tags);

-- Composite indexes for common query patterns
CREATE INDEX IF NOT EXISTS idx_cost_centers_dept_location 
    ON finance.cost_centers(department_id, location_id) 
    WHERE department_id IS NOT NULL AND location_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_cost_centers_type_active 
    ON finance.cost_centers(cost_center_type, is_active) 
    WHERE is_active = TRUE;

-- =============================================================================
-- TRIGGERS FOR AUTOMATION
-- =============================================================================

-- Trigger to maintain hierarchy level and path
CREATE OR REPLACE FUNCTION finance.maintain_cost_center_hierarchy()
RETURNS TRIGGER AS $$
DECLARE
    parent_path LTREE;
    parent_level INTEGER;
BEGIN
    -- Calculate hierarchy level based on parent
    IF NEW.parent_cost_center_id IS NULL THEN
        NEW.hierarchy_level = 1;
        NEW.cost_center_path = text2ltree(NEW.cost_center_code);
    ELSE
        -- Get parent hierarchy info
        SELECT hierarchy_level, cost_center_path 
        INTO parent_level, parent_path
        FROM finance.cost_centers
        WHERE cost_center_id = NEW.parent_cost_center_id;
        
        -- Default to level 2 if parent not found
        IF parent_level IS NULL THEN
            NEW.hierarchy_level = 2;
            NEW.cost_center_path = text2ltree(NEW.cost_center_code);
        ELSE
            NEW.hierarchy_level = parent_level + 1;
            NEW.cost_center_path = parent_path || text2ltree(NEW.cost_center_code);
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Drop existing trigger if exists
DROP TRIGGER IF EXISTS trg_cost_centers_hierarchy ON finance.cost_centers;

-- Create hierarchy maintenance trigger
CREATE TRIGGER trg_cost_centers_hierarchy
    BEFORE INSERT OR UPDATE OF parent_cost_center_id ON finance.cost_centers
    FOR EACH ROW
    EXECUTE FUNCTION finance.maintain_cost_center_hierarchy();

-- Trigger to update updated_at timestamp
DROP TRIGGER IF EXISTS trg_cost_centers_updated_at ON finance.cost_centers;
CREATE TRIGGER trg_cost_centers_updated_at
    BEFORE UPDATE ON finance.cost_centers
    FOR EACH ROW
    EXECUTE FUNCTION public.update_updated_at_column();

