COMMENT ON TABLE finance.cost_centers IS 
'Master table for organizational cost centers used in labor cost tracking and budget management. 
Enables accurate labor cost allocation, budget tracking, and financial reporting. Supports 
hierarchical cost center structures for complex organizations and integrates with general ledger.';

COMMENT ON COLUMN finance.cost_centers.cost_center_id IS 'Unique identifier for the cost center (UUID)';
COMMENT ON COLUMN finance.cost_centers.cost_center_code IS 'Business-readable cost center code (e.g., CC-OPS-001)';
COMMENT ON COLUMN finance.cost_centers.cost_center_name IS 'Descriptive name of the cost center';
COMMENT ON COLUMN finance.cost_centers.cost_center_type IS 'Classification of cost center (operational, capital, project, etc.)';
COMMENT ON COLUMN finance.cost_centers.parent_cost_center_id IS 'Parent cost center for hierarchical structure';
COMMENT ON COLUMN finance.cost_centers.hierarchy_level IS 'Depth in cost center hierarchy (1 = top level)';
COMMENT ON COLUMN finance.cost_centers.cost_center_path IS 'LTREE path for efficient hierarchical queries';
COMMENT ON COLUMN finance.cost_centers.department_id IS 'Associated department for cost allocation';
COMMENT ON COLUMN finance.cost_centers.location_id IS 'Associated location for geographic cost tracking';
COMMENT ON COLUMN finance.cost_centers.budget_amount IS 'Annual or period budget for this cost center';
COMMENT ON COLUMN finance.cost_centers.actual_amount IS 'Year-to-date actual expenses';
COMMENT ON COLUMN finance.cost_centers.is_billable IS 'Whether costs can be billed to clients/customers';
COMMENT ON COLUMN finance.cost_centers.is_profit_center IS 'Whether this cost center generates revenue';
COMMENT ON COLUMN finance.cost_centers.gl_account_code IS 'General Ledger account code for financial integration';
COMMENT ON COLUMN finance.cost_centers.allocation_method IS 'Method for allocating overhead costs';
COMMENT ON COLUMN finance.cost_centers.effective_start_date IS 'Date when cost center becomes active';
COMMENT ON COLUMN finance.cost_centers.effective_end_date IS 'Date when cost center expires (NULL = indefinite)';

