-- View for cost center hierarchy
CREATE OR REPLACE VIEW finance.vw_cost_center_hierarchy AS
WITH RECURSIVE cost_center_tree AS (
    -- Anchor: top-level cost centers
    SELECT
        cost_center_id,
        cost_center_code,
        cost_center_name,
        cost_center_type,
        parent_cost_center_id,
        hierarchy_level,
        cost_center_name::TEXT AS path,
        ARRAY[cost_center_name::TEXT] AS path_array,
        1 AS tree_depth
    FROM finance.cost_centers
    WHERE parent_cost_center_id IS NULL 
    AND is_active = TRUE
    
    UNION ALL
    
    -- Recursive: child cost centers
    SELECT
        c.cost_center_id,
        c.cost_center_code,
        c.cost_center_name,
        c.cost_center_type,
        c.parent_cost_center_id,
        c.hierarchy_level,
        (ct.path || ' > ' || c.cost_center_name)::TEXT,
        ct.path_array || ARRAY[c.cost_center_name::TEXT],
        ct.tree_depth + 1
    FROM finance.cost_centers c
    INNER JOIN cost_center_tree ct ON c.parent_cost_center_id = ct.cost_center_id
    WHERE c.is_active = TRUE
)
SELECT * FROM cost_center_tree
ORDER BY path;

COMMENT ON VIEW finance.vw_cost_center_hierarchy IS 
'Hierarchical view of cost centers showing parent-child relationships';

-- View for cost center budget summary
CREATE OR REPLACE VIEW finance.vw_cost_center_budget_summary AS
SELECT
    cc.cost_center_id,
    cc.cost_center_code,
    cc.cost_center_name,
    cc.cost_center_type,
    d.department_name,
    l.location_name,
    cc.budget_amount,
    cc.actual_amount,
    cc.budget_amount - cc.actual_amount AS budget_variance,
    CASE 
        WHEN cc.budget_amount > 0 
        THEN ROUND((cc.budget_amount - cc.actual_amount) / cc.budget_amount * 100, 2)
        ELSE 0 
    END AS budget_variance_percentage,
    cc.is_active,
    cc.is_billable,
    cc.gl_account_code,
    cc.effective_start_date,
    cc.effective_end_date
FROM finance.cost_centers cc
LEFT JOIN hr.departments d ON cc.department_id = d.department_id
LEFT JOIN operations.locations l ON cc.location_id = l.location_id
WHERE cc.is_active = TRUE
ORDER BY cc.cost_center_code;

COMMENT ON VIEW finance.vw_cost_center_budget_summary IS 
'Budget summary view for cost centers with variance calculations';

