-- Procedure to archive inactive cost centers
CREATE OR REPLACE PROCEDURE finance.archive_inactive_cost_centers(
    p_days_inactive INTEGER DEFAULT 365
)
LANGUAGE plpgsql
AS $$
DECLARE
    v_archived_count INTEGER;
BEGIN
    -- Update cost centers that have been inactive beyond threshold
    UPDATE finance.cost_centers
    SET 
        is_active = FALSE,
        effective_end_date = CURRENT_DATE,
        updated_at = CURRENT_TIMESTAMP
    WHERE is_active = TRUE
    AND effective_end_date < CURRENT_DATE - (p_days_inactive || ' days')::INTERVAL;
    
    GET DIAGNOSTICS v_archived_count = ROW_COUNT;
    
    RAISE NOTICE 'Archived % inactive cost centers', v_archived_count;
    
    -- Log the operation
    INSERT INTO system.maintenance_logs (
        log_type,
        component,
        message,
        started_at,
        completed_at,
        status,
        metadata
    ) VALUES (
        'DATA_MAINTENANCE',
        'finance.archive_inactive_cost_centers',
        format('Archived %s inactive cost centers', v_archived_count),
        CURRENT_TIMESTAMP,
        CURRENT_TIMESTAMP,
        'SUCCESS',
        jsonb_build_object('archived_count', v_archived_count)
    );
END;
$$;

COMMENT ON PROCEDURE finance.archive_inactive_cost_centers IS 
'Archives cost centers that have been inactive beyond specified threshold';


