-- =============================================================================
-- NEW TABLE: finance.labor_cost_rates
-- Purpose: Store labor cost rates by position, location, and time period
-- =============================================================================

CREATE TABLE IF NOT EXISTS finance.labor_cost_rates (
    rate_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    rate_code VARCHAR(50) UNIQUE NOT NULL CHECK (rate_code ~ '^[A-Z0-9_-]{5,50}$'),
    position_id UUID NOT NULL REFERENCES hr.positions(position_id),
    location_id UUID REFERENCES operations.locations(location_id),
    department_id UUID REFERENCES hr.departments(department_id),
    effective_start_date DATE NOT NULL,
    effective_end_date DATE,
    base_hourly_rate NUMERIC(10,2) NOT NULL CHECK (base_hourly_rate >= 0),
    overtime_multiplier NUMERIC(3,2) DEFAULT 1.5 CHECK (overtime_multiplier >= 1.0),
    weekend_multiplier NUMERIC(3,2) DEFAULT 1.5,
    holiday_multiplier NUMERIC(3,2) DEFAULT 2.0,
    night_shift_differential NUMERIC(5,2) DEFAULT 0.00,
    shift_premium NUMERIC(5,2) DEFAULT 0.00,
    benefits_rate_percentage NUMERIC(5,2) DEFAULT 0.00,
    payroll_tax_rate_percentage NUMERIC(5,2) DEFAULT 0.00,
    total_loaded_rate NUMERIC(10,2) GENERATED ALWAYS AS (
        base_hourly_rate * (1 + COALESCE(benefits_rate_percentage, 0) / 100 + 
                           COALESCE(payroll_tax_rate_percentage, 0) / 100)
    ) STORED,
    rate_source VARCHAR(50) NOT NULL DEFAULT 'CONTRACT'
      CHECK (rate_source IN ('CONTRACT', 'UNION', 'MARKET', 'INTERNAL', 'REGULATORY')),
    approval_status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
      CHECK (approval_status IN ('PENDING', 'APPROVED', 'REJECTED', 'ARCHIVED')),
    approved_by UUID REFERENCES hr.employees(employee_id),
    approved_at TIMESTAMP WITH TIME ZONE,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    updated_by UUID REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB,
    CONSTRAINT chk_rate_dates CHECK (
        effective_end_date IS NULL OR effective_end_date >= effective_start_date
    )
);

-- Indexes for labor_cost_rates
CREATE INDEX IF NOT EXISTS idx_labor_cost_rates_position 
ON finance.labor_cost_rates(position_id, effective_start_date DESC);

CREATE INDEX IF NOT EXISTS idx_labor_cost_rates_location 
ON finance.labor_cost_rates(location_id) WHERE location_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_labor_cost_rates_department 
ON finance.labor_cost_rates(department_id) WHERE department_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_labor_cost_rates_active 
ON finance.labor_cost_rates(is_active, effective_start_date DESC) WHERE is_active = TRUE;

CREATE INDEX IF NOT EXISTS idx_labor_cost_rates_metadata 
ON finance.labor_cost_rates USING GIN(metadata);

COMMENT ON TABLE finance.labor_cost_rates IS 
'Stores labor cost rates by position, location, and time period for accurate cost forecasting';


-- =============================================================================
-- NEW TABLE: finance.labor_budget_allocations
-- Purpose: Track labor budget allocations by period, department, and position
-- =============================================================================

CREATE TABLE IF NOT EXISTS finance.labor_budget_allocations (
    allocation_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    allocation_code VARCHAR(50) UNIQUE NOT NULL,
    budget_id UUID NOT NULL REFERENCES finance.budgets(budget_id),
    department_id UUID NOT NULL REFERENCES hr.departments(department_id),
    location_id UUID REFERENCES operations.locations(location_id),
    position_id UUID REFERENCES hr.positions(position_id),
    allocation_period VARCHAR(20) NOT NULL 
      CHECK (allocation_period IN ('DAILY', 'WEEKLY', 'MONTHLY', 'QUARTERLY', 'ANNUAL')),
    period_start_date DATE NOT NULL,
    period_end_date DATE NOT NULL,
    allocated_hours NUMERIC(10,2) NOT NULL CHECK (allocated_hours >= 0),
    allocated_amount NUMERIC(14,2) NOT NULL CHECK (allocated_amount >= 0),
    actual_hours NUMERIC(10,2) DEFAULT 0,
    actual_amount NUMERIC(14,2) DEFAULT 0,
    variance_hours NUMERIC(10,2) GENERATED ALWAYS AS (allocated_hours - actual_hours) STORED,
    variance_amount NUMERIC(14,2) GENERATED ALWAYS AS (allocated_amount - actual_amount) STORED,
    variance_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
        CASE 
            WHEN allocated_amount > 0 
            THEN ((allocated_amount - actual_amount) / allocated_amount * 100)
            ELSE 0 
        END
    ) STORED,
    utilization_rate NUMERIC(5,2) GENERATED ALWAYS AS (
        CASE 
            WHEN allocated_hours > 0 
            THEN (actual_hours / allocated_hours * 100)
            ELSE 0 
        END
    ) STORED,
    forecast_confidence NUMERIC(5,2) DEFAULT 100.00,
    adjustment_reason TEXT,
    adjusted_by UUID REFERENCES hr.employees(employee_id),
    adjusted_at TIMESTAMP WITH TIME ZONE,
    is_locked BOOLEAN NOT NULL DEFAULT FALSE,
    created_by UUID NOT NULL,
    updated_by UUID,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB,
    CONSTRAINT chk_allocation_dates CHECK (period_end_date >= period_start_date)
);

-- Indexes for labor_budget_allocations
CREATE INDEX IF NOT EXISTS idx_labor_budget_allocations_budget 
ON finance.labor_budget_allocations(budget_id);

CREATE INDEX IF NOT EXISTS idx_labor_budget_allocations_period 
ON finance.labor_budget_allocations(period_start_date, period_end_date);

CREATE INDEX IF NOT EXISTS idx_labor_budget_allocations_department 
ON finance.labor_budget_allocations(department_id);

CREATE INDEX IF NOT EXISTS idx_labor_budget_allocations_variance 
ON finance.labor_budget_allocations(variance_percentage DESC);

CREATE INDEX IF NOT EXISTS idx_labor_budget_allocations_locked 
ON finance.labor_budget_allocations(is_locked) WHERE is_locked = TRUE;

COMMENT ON TABLE finance.labor_budget_allocations IS 
'Tracks labor budget allocations by period, department, and position for cost control';

-- =============================================================================
-- NEW TABLE: finance.labor_cost_forecast_history
-- Purpose: Track historical labor cost forecasts for accuracy analysis
-- =============================================================================

CREATE TABLE IF NOT EXISTS finance.labor_cost_forecast_history (
    forecast_history_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    forecast_run_id UUID NOT NULL,
    forecast_date DATE NOT NULL,
    forecast_created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    department_id UUID NOT NULL REFERENCES hr.departments(department_id),
    location_id UUID REFERENCES operations.locations(location_id),
    position_id UUID REFERENCES hr.positions(position_id),
    forecast_period_start DATE NOT NULL,
    forecast_period_end DATE NOT NULL,
    forecasted_hours NUMERIC(10,2) NOT NULL,
    forecasted_cost NUMERIC(14,2) NOT NULL,
    actual_hours NUMERIC(10,2),
    actual_cost NUMERIC(14,2),
    forecast_accuracy_hours NUMERIC(5,2) GENERATED ALWAYS AS (
        CASE 
            WHEN actual_hours IS NOT NULL AND forecasted_hours > 0
            THEN (1 - ABS(actual_hours - forecasted_hours) / forecasted_hours) * 100
            ELSE NULL
        END
    ) STORED,
    forecast_accuracy_cost NUMERIC(5,2) GENERATED ALWAYS AS (
        CASE 
            WHEN actual_cost IS NOT NULL AND forecasted_cost > 0
            THEN (1 - ABS(actual_cost - forecasted_cost) / forecasted_cost) * 100
            ELSE NULL
        END
    ) STORED,
    forecast_method VARCHAR(50) NOT NULL,
    forecast_model_version VARCHAR(20),
    confidence_interval_low NUMERIC(14,2),
    confidence_interval_high NUMERIC(14,2),
    assumptions JSONB,
    variances JSONB,
    created_by UUID NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB,
    CONSTRAINT chk_forecast_dates CHECK (
        forecast_period_end >= forecast_period_start AND
        forecast_date <= forecast_period_start
    )
);

-- Indexes for labor_cost_forecast_history
CREATE INDEX IF NOT EXISTS idx_forecast_history_date 
ON finance.labor_cost_forecast_history(forecast_date DESC);

CREATE INDEX IF NOT EXISTS idx_forecast_history_period 
ON finance.labor_cost_forecast_history(forecast_period_start, forecast_period_end);

CREATE INDEX IF NOT EXISTS idx_forecast_history_accuracy 
ON finance.labor_cost_forecast_history(forecast_accuracy_cost DESC) 
