CREATE INDEX IF NOT EXISTS idx_forecast_history_metadata 
ON finance.labor_cost_forecast_history USING GIN(metadata);

COMMENT ON TABLE finance.labor_cost_forecast_history IS 
'Tracks historical labor cost forecasts for accuracy analysis and model improvement';


-- =============================================================================
-- NEW TABLE: finance.labor_cost_variance_analysis
-- Purpose: Detailed variance analysis between forecasted and actual labor costs
-- =============================================================================

CREATE TABLE IF NOT EXISTS finance.labor_cost_variance_analysis (
    variance_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    analysis_code VARCHAR(50) UNIQUE NOT NULL,
    analysis_period_start DATE NOT NULL,
    analysis_period_end DATE NOT NULL,
    department_id UUID NOT NULL REFERENCES hr.departments(department_id),
    location_id UUID REFERENCES operations.locations(location_id),
    position_id UUID REFERENCES hr.positions(position_id),
    budgeted_amount NUMERIC(14,2) NOT NULL,
    forecasted_amount NUMERIC(14,2) NOT NULL,
    actual_amount NUMERIC(14,2) NOT NULL,
    budget_variance NUMERIC(14,2) GENERATED ALWAYS AS (budgeted_amount - actual_amount) STORED,
    forecast_variance NUMERIC(14,2) GENERATED ALWAYS AS (forecasted_amount - actual_amount) STORED,
    budget_variance_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
        CASE WHEN budgeted_amount > 0 
        THEN ((budgeted_amount - actual_amount) / budgeted_amount * 100) 
        ELSE 0 END
    ) STORED,
    forecast_variance_percentage NUMERIC(5,2) GENERATED ALWAYS AS (
        CASE WHEN forecasted_amount > 0 
        THEN ((forecasted_amount - actual_amount) / forecasted_amount * 100) 
        ELSE 0 END
    ) STORED,
    variance_category VARCHAR(50) NOT NULL 
      CHECK (variance_category IN ('FAVORABLE', 'UNFAVORABLE', 'NEUTRAL')),
    variance_reason VARCHAR(200)[],
    variance_drivers JSONB,
    corrective_actions JSONB,
    responsible_party UUID REFERENCES hr.employees(employee_id),
    resolution_status VARCHAR(20) DEFAULT 'OPEN'
      CHECK (resolution_status IN ('OPEN', 'IN_PROGRESS', 'RESOLVED', 'ACCEPTED')),
    resolved_at TIMESTAMP WITH TIME ZONE,
    resolved_by UUID REFERENCES hr.employees(employee_id),
    created_by UUID NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    metadata JSONB,
    CONSTRAINT chk_analysis_dates CHECK (analysis_period_end >= analysis_period_start)
);

-- Indexes for labor_cost_variance_analysis
CREATE INDEX IF NOT EXISTS idx_variance_analysis_period 
ON finance.labor_cost_variance_analysis(analysis_period_start, analysis_period_end);

CREATE INDEX IF NOT EXISTS idx_variance_analysis_department 
ON finance.labor_cost_variance_analysis(department_id);

CREATE INDEX IF NOT EXISTS idx_variance_analysis_category 
ON finance.labor_cost_variance_analysis(variance_category);

CREATE INDEX IF NOT EXISTS idx_variance_analysis_status 
ON finance.labor_cost_variance_analysis(resolution_status);

CREATE INDEX IF NOT EXISTS idx_variance_analysis_drivers 
ON finance.labor_cost_variance_analysis USING GIN(variance_drivers);

COMMENT ON TABLE finance.labor_cost_variance_analysis IS 
'Detailed variance analysis between forecasted and actual labor costs with root cause tracking';


