-- =============================================================================
-- Serial No: MV-007 | MATERIALIZED VIEW: finance.mv_labor_cost_forecast
-- =============================================================================
-- Purpose: Labor cost forecasting based on scheduled shifts and historical patterns
-- Business Case: This materialized view provides accurate labor cost forecasts by 
--   combining scheduled shift data with historical cost patterns and budget 
--   information. It enables finance teams to project labor costs with high 
--   accuracy, identify potential budget overruns before they occur, and optimize 
--   staffing decisions based on cost implications. The view supports financial 
--   planning, budget management, and cost control initiatives by providing 
--   real-time visibility into projected labor expenses.
-- Refresh Strategy: Hourly refresh during scheduling cycles, daily at minimum
-- KPI: Forecast accuracy, Budget variance reduction, Cost optimization effectiveness
-- Feature Reference: F-FIN-002, F-BUDGET-003, F-FORECAST-003
-- Dependencies: scheduling.shifts, scheduling.shift_assignments, hr.employees,
--               hr.departments, hr.positions, operations.locations, finance.budgets,
--               finance.payroll_records, analytics.forecasted_staffing
-- =============================================================================
-- =============================================================================
-- Serial No: MV-007 | MATERIALIZED VIEW: finance.mv_labor_cost_forecast
-- =============================================================================
-- Purpose: Labor cost forecasting based on scheduled shifts and historical patterns
-- Business Case: This materialized view provides accurate labor cost forecasts by 
--   combining scheduled shift data with historical cost patterns and budget 
--   information. It enables finance teams to project labor costs with high 
--   accuracy, identify potential budget overruns before they occur, and optimize 
--   staffing decisions based on cost implications.
-- Refresh Strategy: Hourly refresh during scheduling cycles, daily at minimum
-- KPI: Forecast accuracy, Budget variance reduction, Cost optimization effectiveness
-- Feature Reference: F-FIN-002, F-BUDGET-003, F-FORECAST-003
-- =============================================================================

-- Drop existing materialized view if exists
DROP MATERIALIZED VIEW IF EXISTS finance.mv_labor_cost_forecast CASCADE;

-- Create the corrected materialized view
CREATE MATERIALIZED VIEW finance.mv_labor_cost_forecast AS
WITH 
-- Base shift data with cost calculations
shift_cost_base AS (
    SELECT
        sh.shift_id,
        sh.schedule_id,
        sh.start_time::DATE AS shift_date,
        sh.start_time,
        sh.end_time,
        sh.department_id,
        sh.location_id,
        sh.position_id,
        sh.shift_type AS shift_category,
        sh.shift_status,
        sh.required_employee_count,
        sh.pay_rate_multiplier,
        1.5 AS overtime_multiplier,
        0.00 AS shift_differential,
        EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600 
            AS planned_shift_hours,
        DATE_TRUNC('day', sh.start_time) AS forecast_date,
        DATE_TRUNC('week', sh.start_time) AS forecast_week,
        DATE_TRUNC('month', sh.start_time) AS forecast_month,
        EXTRACT(YEAR FROM sh.start_time) AS forecast_year,
        EXTRACT(MONTH FROM sh.start_time) AS forecast_month_num,
        EXTRACT(WEEK FROM sh.start_time) AS forecast_week_num
    FROM scheduling.shifts sh
    WHERE sh.start_time >= CURRENT_TIMESTAMP - INTERVAL '90 days'
    AND sh.start_time <= CURRENT_TIMESTAMP + INTERVAL '90 days'
),

-- Employee assignment costs
assignment_costs AS (
    SELECT
        sa.shift_id,
        sa.employee_id,
        sa.assignment_status,
        sa.assignment_type,
        sa.scheduled_start_time,
        sa.scheduled_end_time,
        sa.actual_start_time,
        sa.actual_end_time,
        sa.applied_pay_rate,
        sa.overtime_hours,
        sa.shift_differential_hours,
        sa.special_allowance,
        EXTRACT(EPOCH FROM (sa.scheduled_end_time - sa.scheduled_start_time)) / 3600 
            AS scheduled_hours,
        CASE 
            WHEN sa.actual_start_time IS NOT NULL AND sa.actual_end_time IS NOT NULL
            THEN EXTRACT(EPOCH FROM (sa.actual_end_time - sa.actual_start_time)) / 3600
            ELSE 0
        END AS actual_hours,
        -- FIXED: Get hourly_rate from employees table, not shifts
        COALESCE(e.hourly_rate, 15.00) AS employee_hourly_rate,
        CASE 
            WHEN sa.assignment_type = 'OVERTIME' THEN COALESCE(sa.overtime_multiplier, 1.5)
            ELSE 1.0
        END AS pay_multiplier,
        CASE 
            WHEN sh.pay_rate_multiplier > 1.0 THEN (sh.pay_rate_multiplier - 1.0)
            ELSE COALESCE(sa.shift_differential_hours, 0)
        END AS differential_amount
    FROM scheduling.shift_assignments sa
    JOIN scheduling.shifts sh ON sa.shift_id = sh.shift_id
    LEFT JOIN hr.employees e ON sa.employee_id = e.employee_id
    WHERE sa.scheduled_start_time >= CURRENT_TIMESTAMP - INTERVAL '90 days'
    AND sa.scheduled_start_time <= CURRENT_TIMESTAMP + INTERVAL '90 days'
),

-- Historical payroll patterns (last 12 months)
historical_payroll AS (
    SELECT
        pr.employee_id,
        DATE_TRUNC('month', pr.pay_period_start) AS payroll_month,
        AVG(pr.regular_hours) AS avg_regular_hours,
        AVG(pr.overtime_hours) AS avg_overtime_hours,
        AVG(pr.regular_pay) AS avg_regular_pay,
        AVG(pr.overtime_pay) AS avg_overtime_pay,
        AVG(pr.gross_pay) AS avg_gross_pay,
        SUM(pr.regular_hours) AS total_regular_hours,
        SUM(pr.overtime_hours) AS total_overtime_hours,
        SUM(pr.gross_pay) AS total_gross_pay,
        COUNT(*) AS pay_periods_count
    FROM finance.payroll_records pr
    WHERE pr.pay_period_start >= CURRENT_DATE - INTERVAL '12 months'
    AND pr.status IN ('PROCESSED', 'PAID')
    GROUP BY pr.employee_id, DATE_TRUNC('month', pr.pay_period_start)
),

-- Department budgets
department_budgets AS (
    SELECT
        b.department_id,
        b.location_id,
        b.position_id,
        DATE_TRUNC('month', b.start_date) AS budget_month,
        b.amount AS budgeted_amount,
        b.actual_amount,
        b.variance_threshold,
        b.budget_status,
        b.forecast_method
    FROM finance.budgets b
    WHERE b.budget_type IN ('OPERATIONAL', 'DEPARTMENT', 'LOCATION')
    AND b.start_date >= CURRENT_DATE - INTERVAL '3 months'
    AND b.end_date <= CURRENT_DATE + INTERVAL '12 months'
    AND b.budget_status IN ('APPROVED', 'FINAL')
),

-- Aggregated shift costs by period
shift_cost_aggregation AS (
    SELECT
        scb.forecast_date,
        scb.forecast_week,
        scb.forecast_month,
        scb.forecast_year,
        scb.forecast_month_num,
        scb.forecast_week_num,
        scb.department_id,
        scb.location_id,
        scb.position_id,
        scb.shift_category,
        scb.shift_status,
        COUNT(DISTINCT scb.shift_id) AS total_shifts,
        SUM(scb.planned_shift_hours * scb.required_employee_count) AS total_planned_hours,
        SUM(CASE WHEN ac.assignment_status IN ('CONFIRMED', 'ASSIGNED') 
            THEN ac.scheduled_hours ELSE 0 END) AS total_scheduled_hours,
        SUM(CASE WHEN ac.assignment_status IN ('CONFIRMED', 'ASSIGNED') 
            THEN ac.actual_hours ELSE 0 END) AS total_actual_hours,
        SUM(CASE WHEN ac.assignment_status IN ('CONFIRMED', 'ASSIGNED') 
            THEN ac.scheduled_hours * ac.employee_hourly_rate * ac.pay_multiplier ELSE 0 END) 
            AS projected_labor_cost,
        SUM(CASE WHEN ac.assignment_status IN ('CONFIRMED', 'ASSIGNED') 
            THEN ac.overtime_hours * ac.employee_hourly_rate * ac.pay_multiplier ELSE 0 END) 
            AS projected_overtime_cost,
        SUM(CASE WHEN ac.assignment_status IN ('CONFIRMED', 'ASSIGNED') 
            THEN ac.differential_amount * ac.scheduled_hours ELSE 0 END) 
            AS projected_differential_cost,
        SUM(CASE WHEN ac.assignment_status IN ('CONFIRMED', 'ASSIGNED') 
            THEN ac.special_allowance ELSE 0 END) AS projected_allowances,
        -- FIXED: Calculate total_projected_cost in the CTE
        SUM(CASE WHEN ac.assignment_status IN ('CONFIRMED', 'ASSIGNED') 
            THEN (ac.scheduled_hours * ac.employee_hourly_rate * ac.pay_multiplier) +
                 (ac.overtime_hours * ac.employee_hourly_rate * ac.pay_multiplier) +
                 (ac.differential_amount * ac.scheduled_hours) +
                 ac.special_allowance ELSE 0 END) 
            AS total_projected_cost,
        COUNT(DISTINCT CASE WHEN ac.assignment_status IN ('CONFIRMED', 'ASSIGNED') 
            THEN ac.employee_id END) AS unique_employees_assigned,
        AVG(ac.employee_hourly_rate) AS avg_hourly_rate,
        SUM(CASE WHEN ac.assignment_type = 'OVERTIME' THEN ac.scheduled_hours ELSE 0 END) 
            AS total_overtime_hours
    FROM shift_cost_base scb
    LEFT JOIN assignment_costs ac ON scb.shift_id = ac.shift_id
    GROUP BY 
        scb.forecast_date,
        scb.forecast_week,
        scb.forecast_month,
        scb.forecast_year,
        scb.forecast_month_num,
        scb.forecast_week_num,
        scb.department_id,
        scb.location_id,
        scb.position_id,
        scb.shift_category,
        scb.shift_status
),

-- Historical cost patterns by department
historical_cost_patterns AS (
    SELECT
        hp.employee_id,
        hp.payroll_month,
        AVG(hp.avg_gross_pay) AS avg_monthly_labor_cost,
        AVG(hp.avg_overtime_hours / NULLIF(hp.avg_regular_hours, 0)) * 100 
            AS avg_overtime_percentage
    FROM historical_payroll hp
    GROUP BY hp.employee_id, hp.payroll_month
),

-- Budget variance analysis
budget_variance AS (
    SELECT
        db.department_id,
        db.location_id,
        db.position_id,
        db.budget_month,
        db.budgeted_amount,
        db.actual_amount,
        db.variance_threshold,
        (db.actual_amount - db.budgeted_amount) AS budget_variance,
        CASE 
            WHEN db.budgeted_amount > 0 
            THEN ((db.actual_amount - db.budgeted_amount) / db.budgeted_amount * 100)
            ELSE 0
        END AS variance_percentage,
        CASE 
            WHEN ABS((db.actual_amount - db.budgeted_amount) / NULLIF(db.budgeted_amount, 0)) 
                > (db.variance_threshold / 100) THEN 'EXCEEDS_THRESHOLD'
            WHEN db.actual_amount > db.budgeted_amount THEN 'OVER_BUDGET'
            WHEN db.actual_amount < db.budgeted_amount THEN 'UNDER_BUDGET'
            ELSE 'ON_BUDGET'
        END AS budget_status_category
    FROM department_budgets db
)

-- Final forecast output
SELECT
    sca.forecast_date,
    sca.forecast_week,
    sca.forecast_month,
    sca.forecast_year,
    sca.forecast_month_num,
    sca.forecast_week_num,
    sca.department_id,
    d.department_name,
    sca.location_id,
    l.location_name,
    l.city,
    l.state,
    sca.position_id,
    p.position_title,
    p.job_level,
    sca.shift_category,
    sca.shift_status,
    
    -- Shift Metrics
    sca.total_shifts,
    sca.total_planned_hours,
    sca.total_scheduled_hours,
    sca.total_actual_hours,
    sca.unique_employees_assigned,
    sca.avg_hourly_rate,
    sca.total_overtime_hours,
    
    -- Cost Projections
    ROUND(sca.projected_labor_cost, 2) AS projected_labor_cost,
    ROUND(sca.projected_overtime_cost, 2) AS projected_overtime_cost,
    ROUND(sca.projected_differential_cost, 2) AS projected_differential_cost,
    ROUND(sca.projected_allowances, 2) AS projected_allowances,
    ROUND(sca.total_projected_cost, 2) AS total_projected_cost,
    
    -- Historical Comparisons
    ROUND(COALESCE(hcp.avg_monthly_labor_cost, 0), 2) AS historical_avg_monthly_cost,
    ROUND(COALESCE(hcp.avg_overtime_percentage, 0), 2) AS historical_overtime_percentage,
    
    -- Budget Comparisons
    ROUND(COALESCE(bv.budgeted_amount, 0), 2) AS monthly_budget,
    ROUND(COALESCE(bv.actual_amount, 0), 2) AS monthly_actual,
    ROUND(COALESCE(bv.budget_variance, 0), 2) AS budget_variance,
    ROUND(COALESCE(bv.variance_percentage, 0), 2) AS budget_variance_percentage,
    COALESCE(bv.budget_status_category, 'NO_BUDGET') AS budget_status_category,
    
    -- Forecast Accuracy Metrics
    ROUND(
        CASE 
            WHEN sca.total_planned_hours > 0 
            THEN (sca.total_scheduled_hours / sca.total_planned_hours * 100)
            ELSE 0
        END, 2
    ) AS schedule_fill_rate,
    
    ROUND(
        CASE 
            WHEN sca.total_scheduled_hours > 0 
            THEN (sca.total_actual_hours / sca.total_scheduled_hours * 100)
            ELSE 0
        END, 2
    ) AS schedule_adherence_rate,
    
    -- Cost Efficiency Metrics (Now using CTE column)
    ROUND(
        CASE 
            WHEN sca.total_actual_hours > 0 
            THEN sca.total_projected_cost / sca.total_actual_hours
            ELSE 0
        END, 2
    ) AS cost_per_actual_hour,
    
    ROUND(
        CASE 
            WHEN sca.total_planned_hours > 0 
            THEN sca.total_projected_cost / sca.total_planned_hours
            ELSE 0
        END, 2
    ) AS cost_per_planned_hour,
    
    -- Overtime Analysis
    ROUND(
        CASE 
            WHEN sca.total_scheduled_hours > 0 
            THEN (sca.total_overtime_hours / sca.total_scheduled_hours * 100)
            ELSE 0
        END, 2
    ) AS overtime_percentage,
    
    -- Risk Indicators
    -- FIXED: Use raw CTE values instead of calculated column
    CASE 
        WHEN bv.variance_percentage > bv.variance_threshold THEN 'HIGH_RISK'
        WHEN bv.variance_percentage > 0 THEN 'MEDIUM_RISK'
        -- FIXED: Calculate overtime percentage inline instead of referencing column
        WHEN (sca.total_overtime_hours / NULLIF(sca.total_scheduled_hours, 0) * 100) > 20 THEN 'MEDIUM_RISK'
        ELSE 'LOW_RISK'
    END AS cost_risk_level,
    
    -- Forecast Confidence
    CASE 
        WHEN sca.total_scheduled_hours >= sca.total_planned_hours * 0.9 THEN 'HIGH'
        WHEN sca.total_scheduled_hours >= sca.total_planned_hours * 0.7 THEN 'MEDIUM'
        ELSE 'LOW'
    END AS forecast_confidence,
    
    -- Timestamps
    CURRENT_TIMESTAMP AS calculated_at,
    CURRENT_DATE AS forecast_as_of_date
    
FROM shift_cost_aggregation sca
LEFT JOIN hr.departments d ON sca.department_id = d.department_id
LEFT JOIN operations.locations l ON sca.location_id = l.location_id
LEFT JOIN hr.positions p ON sca.position_id = p.position_id
LEFT JOIN historical_cost_patterns hcp ON sca.department_id = hcp.employee_id
    AND sca.forecast_month = hcp.payroll_month
LEFT JOIN budget_variance bv ON sca.department_id = bv.department_id
    AND sca.location_id = bv.location_id
    AND sca.position_id = bv.position_id
    AND sca.forecast_month = bv.budget_month
ORDER BY 
    sca.forecast_date DESC, 
    sca.department_id, 
    sca.location_id, 
    sca.position_id;

-- =============================================================================
-- INDEXES FOR PERFORMANCE OPTIMIZATION
-- =============================================================================

-- Primary unique index for concurrent refresh
CREATE UNIQUE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_primary
ON finance.mv_labor_cost_forecast(
    forecast_date, 
    department_id, 
    location_id, 
    position_id, 
    shift_category
);

-- Date-based indexes for time-series queries
CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_date
ON finance.mv_labor_cost_forecast(forecast_date DESC);

CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_month
ON finance.mv_labor_cost_forecast(forecast_month);

CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_week
ON finance.mv_labor_cost_forecast(forecast_week);

-- Organizational dimension indexes
CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_department
ON finance.mv_labor_cost_forecast(department_id);

CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_location
ON finance.mv_labor_cost_forecast(location_id);

CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_position
ON finance.mv_labor_cost_forecast(position_id);

-- Cost and risk indexes for filtering
CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_total_cost
ON finance.mv_labor_cost_forecast(total_projected_cost DESC);

CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_risk_level
ON finance.mv_labor_cost_forecast(cost_risk_level);

CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_budget_status
ON finance.mv_labor_cost_forecast(budget_status_category);

-- Variance indexes for budget analysis
CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_variance
ON finance.mv_labor_cost_forecast(budget_variance_percentage DESC);

-- Composite indexes for common query patterns
CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_dept_month
ON finance.mv_labor_cost_forecast(department_id, forecast_month);

CREATE INDEX IF NOT EXISTS idx_mv_labor_cost_forecast_loc_date
ON finance.mv_labor_cost_forecast(location_id, forecast_date);

-- =============================================================================
-- COMMENTS FOR DOCUMENTATION
-- =============================================================================

COMMENT ON MATERIALIZED VIEW finance.mv_labor_cost_forecast IS 
'Labor cost forecasting materialized view combining scheduled shifts, historical 
patterns, and budget information. Provides projected labor costs, budget variance 
analysis, and risk indicators for financial planning and cost control.';

COMMENT ON COLUMN finance.mv_labor_cost_forecast.forecast_date IS 
'Date for which labor costs are forecasted';

COMMENT ON COLUMN finance.mv_labor_cost_forecast.total_projected_cost IS 
'Sum of all projected labor costs including base, overtime, differentials, and allowances';

COMMENT ON COLUMN finance.mv_labor_cost_forecast.projected_labor_cost IS 
'Base labor cost projection from scheduled hours and pay rates';

COMMENT ON COLUMN finance.mv_labor_cost_forecast.projected_overtime_cost IS 
'Projected overtime labor cost based on overtime hours and multipliers';

COMMENT ON COLUMN finance.mv_labor_cost_forecast.monthly_budget IS 
'Budgeted labor cost amount for the month from finance.budgets';

COMMENT ON COLUMN finance.mv_labor_cost_forecast.budget_variance IS 
'Difference between actual/projected costs and budgeted amount';

COMMENT ON COLUMN finance.mv_labor_cost_forecast.cost_risk_level IS 
'Risk indicator for cost overruns: HIGH_RISK, MEDIUM_RISK, LOW_RISK';

COMMENT ON COLUMN finance.mv_labor_cost_forecast.forecast_confidence IS 
'Confidence level in forecast accuracy: HIGH, MEDIUM, LOW based on fill rate';

COMMENT ON COLUMN finance.mv_labor_cost_forecast.cost_per_actual_hour IS 
'Average labor cost per actual hour worked';

COMMENT ON COLUMN finance.mv_labor_cost_forecast.cost_per_planned_hour IS 
'Average labor cost per planned hour';

-- =============================================================================
-- VERIFICATION QUERY
-- =============================================================================

-- Test the materialized view
SELECT 
    forecast_date,
    department_name,
    location_name,
    total_projected_cost,
    monthly_budget,
    budget_variance_percentage,
    cost_risk_level,
    forecast_confidence
FROM finance.mv_labor_cost_forecast
WHERE forecast_date >= CURRENT_DATE
ORDER BY forecast_date DESC
LIMIT 10;




-- =============================================================================
-- FIX: Add shift_date column to scheduling.shifts table
-- =============================================================================

-- Add shift_date as a generated column (recommended - stays in sync with start_time)
ALTER TABLE scheduling.shifts
ADD COLUMN IF NOT EXISTS shift_date DATE 
GENERATED ALWAYS AS (start_time::DATE) STORED;

-- Add comment for documentation
COMMENT ON COLUMN scheduling.shifts.shift_date IS 
'Date portion of shift start_time for easier date-based queries and reporting';

-- Create index for performance on date-based queries
CREATE INDEX IF NOT EXISTS idx_shifts_shift_date 
ON scheduling.shifts(shift_date DESC);

-- Create composite index for common query patterns
CREATE INDEX IF NOT EXISTS idx_shifts_date_department 
ON scheduling.shifts(shift_date, department_id);

CREATE INDEX IF NOT EXISTS idx_shifts_date_location 
ON scheduling.shifts(shift_date, location_id);

-- Verify the column was added
SELECT column_name, data_type, is_generated
FROM information_schema.columns
WHERE table_schema = 'scheduling'
AND table_name = 'shifts'
AND column_name = 'shift_date';



-- =============================================================================
-- Serial No: 1 | PROCEDURE: scheduling.create_schedule_from_template
-- =============================================================================
-- Purpose: Create a new schedule from an existing template with shift generation
-- Business Case: This procedure automates the creation of schedules from predefined
-- templates, ensuring consistency in scheduling practices while reducing the time
-- and effort required to create new schedules. It validates template availability,
-- generates shifts based on template patterns, and updates usage statistics for
-- template performance tracking. The procedure includes comprehensive error
-- handling and logging to support troubleshooting and audit requirements.
-- KPI: Schedule creation time, Template usage rate, Shift generation accuracy,
--      Error rate during schedule creation, Template effectiveness score
-- Feature Reference: 1, 2, 3, 4, 5
-- =============================================================================

CREATE OR REPLACE PROCEDURE scheduling.create_schedule_from_template(
    p_template_id UUID,
    p_schedule_name VARCHAR(200),
    p_start_date DATE,
    p_end_date DATE,
    p_created_by UUID,
    INOUT p_new_schedule_id UUID,
    INOUT p_message TEXT,
    INOUT p_status_code INTEGER
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_template_record scheduling.schedule_templates%ROWTYPE;
    v_schedule_code VARCHAR(50);
    v_location_code VARCHAR(10);
    v_sequence_number INTEGER;
    v_shift_count INTEGER := 0;
    v_error_context TEXT;
    v_schedule_duration INTEGER;
    v_max_schedule_days INTEGER := 90;
BEGIN
    -- Initialize outputs
    p_status_code := 200;
    p_message := 'Success';
    p_new_schedule_id := NULL;

    -- Validate input parameters
    IF p_template_id IS NULL THEN
        p_status_code := 400;
        p_message := 'Template ID cannot be null';
        RAISE EXCEPTION '%', p_message;
    END IF;

    IF p_start_date IS NULL OR p_end_date IS NULL THEN
        p_status_code := 400;
        p_message := 'Start date and end date are required';
        RAISE EXCEPTION '%', p_message;
    END IF;

    IF p_end_date < p_start_date THEN
        p_status_code := 400;
        p_message := 'End date must be after start date';
        RAISE EXCEPTION '%', p_message;
    END IF;

    -- Validate schedule duration
    v_schedule_duration := (p_end_date - p_start_date) + 1;
    IF v_schedule_duration > v_max_schedule_days THEN
        p_status_code := 400;
        p_message := 'Schedule duration cannot exceed ' || v_max_schedule_days || ' days';
        RAISE EXCEPTION '%', p_message;
    END IF;

    -- Validate created_by user exists
    IF NOT EXISTS (SELECT 1 FROM hr.employees WHERE employee_id = p_created_by) THEN
        p_status_code := 400;
        p_message := 'Invalid created_by user ID';
        RAISE EXCEPTION '%', p_message;
    END IF;

    -- Get template details
    SELECT * INTO v_template_record
    FROM scheduling.schedule_templates
    WHERE template_id = p_template_id
      AND is_active = TRUE;

    IF NOT FOUND THEN
        p_status_code := 404;
        p_message := 'Template not found or inactive';
        RAISE EXCEPTION '%', p_message;
    END IF;

    -- Get location code for schedule code generation
    SELECT location_code INTO v_location_code
    FROM operations.locations
    WHERE location_id = v_template_record.location_id;

    -- Generate unique schedule code
    SELECT COALESCE(MAX(CAST(SUBSTRING(schedule_code FROM 5) AS INTEGER)), 0) + 1
    INTO v_sequence_number
    FROM scheduling.schedules
    WHERE schedule_code LIKE 'SCH-' || COALESCE(v_location_code, 'DEF') || '-%';

    v_schedule_code := 'SCH-' || COALESCE(v_location_code, 'DEF') || '-' || 
                       LPAD(v_sequence_number::TEXT, 6, '0');

    -- Check for overlapping schedules
    IF EXISTS (
        SELECT 1
        FROM scheduling.schedules
        WHERE location_id = v_template_record.location_id
          AND department_id = v_template_record.department_id
          AND (
              (start_date BETWEEN p_start_date AND p_end_date)
              OR (end_date BETWEEN p_start_date AND p_end_date)
              OR (p_start_date BETWEEN start_date AND end_date)
          )
          AND schedule_status NOT IN ('ARCHIVED', 'CANCELLED')
    ) THEN
        p_status_code := 409;
        p_message := 'Overlapping schedule already exists for this location and department';
        RAISE EXCEPTION '%', p_message;
    END IF;

    -- Create new schedule
    INSERT INTO scheduling.schedules (
        schedule_code,
        name,
        description,
        location_id,
        department_id,
        start_date,
        end_date,
        schedule_status,
        template_id,
        schedule_type,
        created_by,
        updated_by,
        created_at,
        updated_at
    ) VALUES (
        v_schedule_code,
        p_schedule_name,
        v_template_record.description,
        v_template_record.location_id,
        v_template_record.department_id,
        p_start_date,
        p_end_date,
        'DRAFT'::scheduling.schedule_status_enum,
        p_template_id,
        'REGULAR',
        p_created_by,
        p_created_by,
        CURRENT_TIMESTAMP,
        CURRENT_TIMESTAMP
    ) RETURNING schedule_id INTO p_new_schedule_id;

    -- Generate shifts from template pattern
    -- Note: This assumes pattern JSONB contains shift definitions
    -- Actual implementation depends on pattern structure
    INSERT INTO scheduling.shifts (
        schedule_id,
        location_id,
        department_id,
        position_id,
        role_id,
        start_time,
        end_time,
        shift_status,
        shift_type,
        required_skill_level,
        pay_rate_multiplier,
        created_by,
        updated_by,
        created_at,
        updated_at
    )
    SELECT
        p_new_schedule_id,
        v_template_record.location_id,
        v_template_record.department_id,
        COALESCE(
            (pattern->>'position_id')::UUID,
            v_template_record.position_id
        ),
        v_template_record.position_id, -- Using as role_id fallback
        (gs.date::DATE + COALESCE(
            (pattern->>'start_time')::TIME,
            '09:00:00'::TIME
        ))::TIMESTAMP WITH TIME ZONE,
        (gs.date::DATE + COALESCE(
            (pattern->>'end_time')::TIME,
            '17:00:00'::TIME
        ))::TIMESTAMP WITH TIME ZONE,
        'OPEN'::scheduling.shift_status_enum,
        'REGULAR',
        COALESCE((pattern->>'required_skill_level')::INTEGER, 3),
        1.00,
        p_created_by,
        p_created_by,
        CURRENT_TIMESTAMP,
        CURRENT_TIMESTAMP
    FROM generate_series(p_start_date, p_end_date, '1 day'::INTERVAL) AS gs(date)
    CROSS JOIN LATERAL (
        SELECT 
            COALESCE(
                v_template_record.pattern,
                '{"start_time": "09:00:00", "end_time": "17:00:00", "position_id": null, "required_skill_level": 3}'::JSONB
            ) AS pattern
    ) AS pattern_data
    WHERE EXTRACT(DOW FROM gs.date) BETWEEN 1 AND 5; -- Monday to Friday by default

    GET DIAGNOSTICS v_shift_count = ROW_COUNT;

    -- Update template usage statistics
    UPDATE scheduling.schedule_templates
    SET usage_count = usage_count + 1,
        last_used_at = CURRENT_TIMESTAMP,
        updated_at = CURRENT_TIMESTAMP,
        updated_by = p_created_by
    WHERE template_id = p_template_id;

    -- Log successful creation
    INSERT INTO system.audit_log (
        table_name,
        record_id,
        operation,
        old_data,
        new_data,
        changed_by,
        changed_at
    ) VALUES (
        'scheduling.schedules',
        p_new_schedule_id,
        'INSERT',
        NULL,
        jsonb_build_object(
            'schedule_id', p_new_schedule_id,
            'schedule_code', v_schedule_code,
            'template_id', p_template_id,
            'shift_count', v_shift_count
        ),
        p_created_by,
        CURRENT_TIMESTAMP
    );

    p_message := 'Schedule created successfully with ' || v_shift_count || ' shifts';
    p_status_code := 200;

EXCEPTION
    WHEN OTHERS THEN
        GET STACKED DIAGNOSTICS v_error_context = PG_EXCEPTION_CONTEXT;
        p_status_code := 500;
        p_message := 'Error creating schedule: ' || SQLERRM || ' Context: ' || v_error_context;

        -- Log error to audit log
        INSERT INTO system.audit_log (
            table_name,
            record_id,
            operation,
            old_data,
            new_data,
            changed_by,
            changed_at
        ) VALUES (
            'scheduling.schedules',
            COALESCE(p_new_schedule_id, '00000000-0000-0000-0000-000000000000'::UUID),
            'ERROR',
            NULL,
            jsonb_build_object(
                'error_code', SQLSTATE,
                'error_message', SQLERRM,
                'error_context', v_error_context,
                'template_id', p_template_id,
                'start_date', p_start_date,
                'end_date', p_end_date
            ),
            p_created_by,
            CURRENT_TIMESTAMP
        );

        -- Also log to error_logs if table exists
        BEGIN
            INSERT INTO system.error_logs (
                error_code,
                error_type,
                error_category,
                error_message,
                error_details,
                stack_trace,
                user_id,
                occurred_at,
                created_by
            ) VALUES (
                SQLSTATE,
                'APPLICATION',
                'HIGH',
                SQLERRM,
                jsonb_build_object(
                    'template_id', p_template_id,
                    'start_date', p_start_date,
                    'end_date', p_end_date,
                    'created_by', p_created_by
                ),
                v_error_context,
                p_created_by,
                CURRENT_TIMESTAMP,
                p_created_by
            );
        EXCEPTION WHEN OTHERS THEN
            -- Ignore if error_logs table doesn't exist
            NULL;
        END;

        RAISE NOTICE 'Schedule creation failed: %', p_message;
END;
$$;

