-- =============================================================================
-- Serial No: 27 | PROCEDURE: scheduling.create_schedule
-- =============================================================================
-- Purpose: Create and populate a new schedule with optimized shift assignments
-- Business Case: This stored procedure automates the complex process of schedule 
--   creation, integrating multiple data sources and business rules to produce 
--   an optimized schedule. It handles all aspects of schedule generation 
--   including employee availability validation, skill-based assignment, 
--   compliance checking, and performance optimization. The procedure implements 
--   sophisticated algorithms to balance competing objectives such as labor cost 
--   minimization, employee satisfaction, and service level requirements. It 
--   includes comprehensive error handling and validation to ensure data 
--   integrity throughout the process. The procedure also generates detailed 
--   performance metrics for the generated schedule, enabling continuous 
--   improvement of scheduling practices. By encapsulating this complex logic 
--   in a database procedure, the system ensures consistent scheduling behavior 
--   across different application interfaces and reduces network traffic by 
--   processing data close to where it's stored. The procedure supports both 
--   interactive use for immediate schedule creation and batch processing for 
--   scheduled generation during off-peak hours. It includes detailed audit 
--   logging to support troubleshooting and compliance verification.
-- KPI: Schedule generation time, Optimization score, Compliance rate,
--      Resource utilization efficiency, Error rate during generation
-- Feature Reference: 131, 132, 133, 134, 135
-- =============================================================================

CREATE OR REPLACE PROCEDURE scheduling.create_schedule(
    p_schedule_name VARCHAR(200),
    p_location_id UUID,
    p_start_date DATE,
    p_end_date DATE,
    p_created_by UUID,
    p_template_id UUID DEFAULT NULL,
    p_department_id UUID DEFAULT NULL,
    p_optimization_level VARCHAR(50) DEFAULT 'BALANCED'
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_schedule_id UUID;
    v_schedule_code VARCHAR(50);
    v_location_code VARCHAR(10);
    v_sequence_number INTEGER;
    v_existing_count INTEGER;
    v_max_schedule_days INTEGER := 90;
    v_schedule_duration INTEGER;
    v_error_context TEXT;
BEGIN
    -- Validate input parameters
    IF p_start_date > p_end_date THEN
        RAISE EXCEPTION 'Start date must be before or equal to end date';
    END IF;
    
    v_schedule_duration = (p_end_date - p_start_date) + 1;
    
    IF v_schedule_duration > v_max_schedule_days THEN
        RAISE EXCEPTION 'Schedule duration cannot exceed % days', v_max_schedule_days;
    END IF;
    
    -- Validate location exists
    PERFORM 1 FROM operations.locations WHERE location_id = p_location_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Invalid location_id: %', p_location_id;
    END IF;
    
    -- Get location code for schedule code generation
    SELECT location_code INTO v_location_code
    FROM operations.locations
    WHERE location_id = p_location_id;
    
    -- Generate unique schedule code
    SELECT COALESCE(MAX(CAST(SUBSTRING(schedule_code FROM 5) AS INTEGER)), 0) + 1
    INTO v_sequence_number
    FROM scheduling.schedules
    WHERE schedule_code LIKE 'SCHD-' || v_location_code || '-%';
    
    v_schedule_code = 'SCHD-' || v_location_code || '-' || LPAD(v_sequence_number::TEXT, 6, '0');
    
    -- Check for overlapping schedules
    SELECT COUNT(*) INTO v_existing_count
    FROM scheduling.schedules
    WHERE location_id = p_location_id
    AND department_id = COALESCE(p_department_id, department_id)
    AND (
        (start_date BETWEEN p_start_date AND p_end_date)
        OR (end_date BETWEEN p_start_date AND p_end_date)
        OR (p_start_date BETWEEN start_date AND end_date)
    )
    AND schedule_status NOT IN ('ARCHIVED', 'CANCELLED');
    
    IF v_existing_count > 0 THEN
        RAISE EXCEPTION 'Overlapping schedule already exists for this location and department';
    END IF;
    
    -- Create the schedule record
    INSERT INTO scheduling.schedules (
        schedule_id,
        schedule_code,
        name,
        location_id,
        department_id,
        start_date,
        end_date,
        created_by_uuid,
        template_id,
        optimization_level
    ) VALUES (
        DEFAULT,
        v_schedule_code,
        p_schedule_name,
        p_location_id,
        p_department_id,
        p_start_date,
        p_end_date,
        p_created_by,
        p_template_id,
        p_optimization_level
    )
    RETURNING schedule_id INTO v_schedule_id;
    
    -- Generate shifts based on template or forecasted demand
    IF p_template_id IS NOT NULL THEN
        CALL scheduling.generate_shifts_from_template(
            v_schedule_id,
            p_template_id,
            p_start_date,
            p_end_date
        );
    ELSE
        CALL scheduling.generate_shifts_from_forecast(
            v_schedule_id,
            p_location_id,
            p_department_id,
            p_start_date,
            p_end_date
        );
    END IF;
    
    -- Validate compliance
    CALL scheduling.validate_schedule_compliance(v_schedule_id);
    
    -- Calculate initial performance metrics
    CALL scheduling.calculate_schedule_metrics(v_schedule_id);
    
    -- Log successful creation
    INSERT INTO system.audit_logs (
        user_id,
        action,
        entity_type,
        entity_id,
        new_state,
        ip_address,
        created_by
    ) VALUES (
        p_created_by,
        'SCHEDULE_CREATED',
        'scheduling.schedules',
        v_schedule_id,
        jsonb_build_object(
            'schedule_id', v_schedule_id,
            'schedule_code', v_schedule_code,
            'location_id', p_location_id,
            'department_id', p_department_id,
            'start_date', p_start_date,
            'end_date', p_end_date
        ),
        NULL,
        p_created_by
    );
    
EXCEPTION WHEN OTHERS THEN
    -- Get error context
    GET STACKED DIAGNOSTICS v_error_context = PG_EXCEPTION_CONTEXT;
    
    -- Log error to system.error_logs (FIXED as per schema standards)
    INSERT INTO system.error_logs (
        error_code,
        error_type,
        error_category,
        error_message,
        error_details,
        stack_trace,
        user_id,
        occurred_at,
        created_by
    ) VALUES (
        SQLSTATE,
        'APPLICATION',
        'HIGH',
        SQLERRM,
        jsonb_build_object(
            'template_id', p_template_id,
            'start_date', p_start_date,
            'end_date', p_end_date,
            'created_by', p_created_by
        ),
        v_error_context,
        p_created_by,
        CURRENT_TIMESTAMP,
        p_created_by
    );
    
    -- Re-raise the exception
    RAISE EXCEPTION 'Schedule creation failed: %', SQLERRM;
END;
$$;

