-- =============================================================================
-- Serial No: V-001 | VIEW: scheduling.vw_schedule_dashboard
-- =============================================================================
-- Purpose: Comprehensive dashboard view showing schedule summary metrics for management reporting
-- Business Case: This view provides management with a consolidated view of schedule performance
--              metrics, enabling quick assessment of staffing levels, coverage gaps, and schedule
--              status across departments and locations. It aggregates data from schedules, shifts,
--              and assignments to provide actionable insights for workforce planning and operational
--              decision-making. The view supports real-time monitoring of schedule health and
--              facilitates proactive management of staffing issues before they impact operations.
-- KPI: Schedule coverage rate, Staffing gap identification, Schedule status tracking,
--      Employee utilization rate, Dashboard query performance
-- Feature Reference: F-SCH-001, F-REP-001, F-ANA-001, F-MGT-001
-- =============================================================================

DROP VIEW IF EXISTS scheduling.vw_schedule_dashboard CASCADE;

CREATE OR REPLACE VIEW scheduling.vw_schedule_dashboard AS
SELECT
    -- Schedule Identity
    s.schedule_id,
    s.schedule_code,
    s.name AS schedule_name,
    s.description,
    s.schedule_status AS status,
    -- Temporal Attributes
    s.start_date AS effective_start_date,
    s.end_date AS effective_end_date,
    -- Organizational Context
    d.department_id,
    d.department_name,
    l.location_id,
    l.location_name,
    l.city,
    l.state,
    -- Shift Metrics
    COUNT(DISTINCT sh.shift_id) AS total_shifts,
    COALESCE(SUM(sh.required_employee_count), 0) AS total_required_staff,
    -- Calculate assigned staff from shift_assignments table
    COUNT(DISTINCT CASE 
        WHEN sa.assignment_status IN ('CONFIRMED', 'ASSIGNED', 'IN_PROGRESS') 
        THEN sa.employee_id 
    END) AS total_assigned_staff,
    -- Calculate coverage percentage
    ROUND(
        CASE 
            WHEN COALESCE(SUM(sh.required_employee_count), 0) > 0 
            THEN (COUNT(DISTINCT CASE 
                    WHEN sa.assignment_status IN ('CONFIRMED', 'ASSIGNED', 'IN_PROGRESS') 
                    THEN sa.employee_id 
                END)::NUMERIC / SUM(sh.required_employee_count) * 100)
            ELSE 0 
        END, 2
    ) AS avg_coverage_percentage,
    -- Employee Metrics
    COUNT(DISTINCT sa.employee_id) AS unique_employees_scheduled,
    -- Schedule Status Breakdown
    COUNT(DISTINCT CASE WHEN sh.shift_status = 'OPEN' THEN sh.shift_id END) AS open_shifts,
    COUNT(DISTINCT CASE WHEN sh.shift_status = 'ASSIGNED' THEN sh.shift_id END) AS assigned_shifts,
    COUNT(DISTINCT CASE WHEN sh.shift_status = 'CONFIRMED' THEN sh.shift_id END) AS confirmed_shifts,
    COUNT(DISTINCT CASE WHEN sh.shift_status = 'IN_PROGRESS' THEN sh.shift_id END) AS in_progress_shifts,
    COUNT(DISTINCT CASE WHEN sh.shift_status = 'COMPLETED' THEN sh.shift_id END) AS completed_shifts,
    COUNT(DISTINCT CASE WHEN sh.shift_status = 'CANCELLED' THEN sh.shift_id END) AS cancelled_shifts,
    -- Coverage Gap Analysis
    COALESCE(SUM(sh.required_employee_count), 0) - 
    COUNT(DISTINCT CASE 
        WHEN sa.assignment_status IN ('CONFIRMED', 'ASSIGNED', 'IN_PROGRESS') 
        THEN sa.employee_id 
    END) AS staffing_gap,
    -- Time Metrics
    ROUND(SUM(EXTRACT(EPOCH FROM (sh.end_time - sh.start_time)) / 3600), 2) AS total_planned_hours,
    -- Audit Information
    s.created_by_uuid AS created_by,
    s.created_at,
    s.updated_by_uuid AS updated_by,
    s.updated_at,
    -- Schedule Configuration
    s.schedule_type,
    s.optimization_level,
    s.constraint_violation_count,
    s.performance_score,
    -- Data Freshness
    CURRENT_TIMESTAMP AS calculated_at
FROM scheduling.schedules s
JOIN hr.departments d ON s.department_id = d.department_id
JOIN operations.locations l ON s.location_id = l.location_id
LEFT JOIN scheduling.shifts sh ON s.schedule_id = sh.schedule_id
    AND sh.shift_status NOT IN ('CANCELLED')
LEFT JOIN scheduling.shift_assignments sa ON sh.shift_id = sa.shift_id
    AND sa.assignment_status NOT IN ('CANCELLED', 'EXCUSED_ABSENCE')
WHERE s.is_active = TRUE
GROUP BY 
    s.schedule_id, 
    s.schedule_code, 
    s.name, 
    s.description,
    s.schedule_status,
    s.start_date, 
    s.end_date,
    d.department_id,
    d.department_name,
    l.location_id,
    l.location_name,
    l.city,
    l.state,
    s.created_by_uuid,
    s.created_at,
    s.updated_by_uuid,
    s.updated_at,
    s.schedule_type,
    s.optimization_level,
    s.constraint_violation_count,
    s.performance_score
ORDER BY 
    s.start_date DESC, 
    d.department_name, 
    l.location_name;

