-- =============================================================================
-- COMMENTS FOR DOCUMENTATION
-- =============================================================================
COMMENT ON VIEW scheduling.vw_schedule_dashboard IS
'Comprehensive dashboard view showing schedule summary metrics for management reporting.
Aggregates data from schedules, shifts, and assignments to provide actionable insights.
Supports real-time monitoring of schedule health and staffing coverage.
KEY FIXES APPLIED:
- Corrected column names to match actual schema (name vs schedule_name, start_date vs effective_start_date)
- Fixed coverage calculation using shift_assignments table instead of non-existent shift columns
- Added shift status breakdown for operational visibility
- Added staffing gap analysis for proactive management
- Added schedule configuration fields for context
- Filtered to active schedules only for relevance
- Added calculated_at timestamp for data freshness tracking';

COMMENT ON COLUMN scheduling.vw_schedule_dashboard.schedule_id IS 'Unique identifier for the schedule';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.schedule_code IS 'Business-readable schedule code';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.schedule_name IS 'Descriptive name of the schedule';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.status IS 'Current schedule status (DRAFT, PUBLISHED, EXECUTING, etc.)';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.effective_start_date IS 'Schedule start date';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.effective_end_date IS 'Schedule end date';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.department_name IS 'Department responsible for the schedule';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.location_name IS 'Location where schedule applies';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.total_shifts IS 'Total number of shifts in the schedule';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.total_required_staff IS 'Sum of required employee counts across all shifts';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.total_assigned_staff IS 'Count of unique employees assigned to shifts';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.avg_coverage_percentage IS 'Percentage of required positions that are filled (0-100)';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.unique_employees_scheduled IS 'Number of unique employees scheduled';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.open_shifts IS 'Shifts still available for assignment';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.assigned_shifts IS 'Shifts assigned but not yet confirmed';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.confirmed_shifts IS 'Shifts confirmed by employees';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.staffing_gap IS 'Difference between required and assigned staff (negative = overstaffed)';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.total_planned_hours IS 'Total scheduled hours across all shifts';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.constraint_violation_count IS 'Number of scheduling constraint violations detected';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.performance_score IS 'Overall schedule performance score (0-100)';
COMMENT ON COLUMN scheduling.vw_schedule_dashboard.calculated_at IS 'Timestamp when the view data was calculated';

-- =============================================================================
-- USAGE EXAMPLES
-- =============================================================================
-- Example 1: Get all active schedules with coverage below 80%

SELECT 
    schedule_code,
    schedule_name,
    department_name,
    location_name,
    total_shifts,
    total_required_staff,
    total_assigned_staff,
    avg_coverage_percentage,
    staffing_gap
FROM scheduling.vw_schedule_dashboard
WHERE avg_coverage_percentage < 80
AND status IN ('PUBLISHED', 'EXECUTING')
ORDER BY avg_coverage_percentage ASC;


-- Example 2: Get schedule summary by department

SELECT 
    department_name,
    COUNT(*) as schedule_count,
    AVG(avg_coverage_percentage) as avg_coverage,
    SUM(total_shifts) as total_shifts,
    SUM(staffing_gap) as total_staffing_gap
FROM scheduling.vw_schedule_dashboard
WHERE effective_start_date >= CURRENT_DATE
GROUP BY department_name
ORDER BY avg_coverage ASC;


-- Example 3: Monitor schedules with constraint violations

SELECT 
    schedule_code,
    schedule_name,
    constraint_violation_count,
    performance_score,
    status
FROM scheduling.vw_schedule_dashboard
WHERE constraint_violation_count > 0
ORDER BY constraint_violation_count DESC, performance_score ASC;


-- =============================================================================
-- VERIFICATION QUERY
-- =============================================================================
-- Verify view exists and is accessible
SELECT 
    schemaname,
    viewname,
    definition
FROM pg_views
WHERE schemaname = 'scheduling'
AND viewname = 'vw_schedule_dashboard';

-- Test the view with sample data

SELECT 
    schedule_code,
    schedule_name,
    department_name,
    location_name,
    status,
    total_shifts,
    total_required_staff,
    total_assigned_staff,
    avg_coverage_percentage,
    staffing_gap,
    performance_score
FROM scheduling.vw_schedule_dashboard
WHERE effective_start_date >= CURRENT_DATE - INTERVAL '30 days'
ORDER BY effective_start_date DESC
LIMIT 10;




ALTER TABLE scheduling.shift_assignments
ADD COLUMN IF NOT EXISTS productive_duration_minutes INTEGER
GENERATED ALWAYS AS (
    CASE 
        WHEN actual_start_time IS NOT NULL AND actual_end_time IS NOT NULL 
        THEN EXTRACT(EPOCH FROM (actual_end_time - actual_start_time)) / 60
        ELSE EXTRACT(EPOCH FROM (scheduled_end_time - scheduled_start_time)) / 60
    END - 
    COALESCE(
        EXTRACT(EPOCH FROM (break_end_time - break_start_time)) / 60, 
        0
    )
) STORED;




