    'WEEKLY',
    'BIWEEKLY',
    'MONTHLY',
    'CUSTOM',
    'ROTATING',
    'SEASONAL',
    'EVENT_BASED'
);

COMMENT ON TYPE scheduling.schedule_type IS 'Defines the recurrence pattern and cadence of schedules';

-- Enum: Shift types for categorization
