COMMENT ON TYPE scheduling.shift_type IS 'Categorizes shifts by purpose and compensation rules';

-- Enum: Assignment types for employee shifts
CREATE TYPE scheduling.assignment_type AS ENUM (
    'REGULAR',
    'OVERTIME',
    'CALL_IN',
    'SUBSTITUTE',
    'VOLUNTARY',
