COMMENT ON TYPE scheduling.assignment_type IS 'Defines how an employee is assigned to a shift';

-- Enum: Approval status for workflow management
CREATE TYPE scheduling.approval_status AS ENUM (
    'PENDING',
    'APPROVED',
    'REJECTED',
    'REVOKED',
    'EXPIRED'
);

COMMENT ON TYPE scheduling.approval_status IS 'Tracks the approval status in workflow processes';

-- Enum: Employee status for HR management
CREATE TYPE hr.employee_status AS ENUM (
    'ACTIVE',
    'ON_LEAVE',
    'SUSPENDED',
    'TERMINATED',
    'RETIRED',
    'INACTIVE'
