-- Serial No: 1 | TABLE: scheduling.employee_performance_history
-- Description: Stores historical performance data for employees to inform scheduling decisions
-- Business Case: Enables performance-based scheduling by tracking historical productivity, quality metrics,
--                attendance patterns, and customer satisfaction scores. Provides data-driven insights for
--                optimal employee-shift matching, skill-based assignment, and performance trend analysis.
--                Supports continuous improvement initiatives by identifying training needs and performance
--                outliers. Integrates with scheduling algorithms to optimize workforce utilization and
--                quality outcomes.
-- KPI: 1. Performance prediction accuracy (>85%), 2. Schedule optimization effectiveness (>90%),
--      3. Performance trend analysis coverage (>95%), 4. Data completeness rate (>98%),
--      5. Real-time performance data availability (>99%), 6. Performance improvement rate (>10%),
--      7. Anomaly detection accuracy (>95%)
-- Feature Reference: F001, F002, F003, F004, F005, F006, F007, F008, F009, F010, F011, F012, F013
CREATE TABLE IF NOT EXISTS scheduling.employee_performance_history (
    performance_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    performance_code VARCHAR(50) UNIQUE NOT NULL CHECK (performance_code ~ '^PER-[A-Z0-9]{3,8}-[A-Z0-9]{6}$'),

    -- Employee and shift context
    employee_id UUID NOT NULL REFERENCES hr.employees(employee_id),
    shift_id UUID REFERENCES scheduling.shifts(shift_id),

    -- Performance timing
    performance_date DATE NOT NULL DEFAULT CURRENT_DATE
        CHECK (performance_date >= CURRENT_DATE - INTERVAL '2 years'),
    evaluation_period_start DATE NOT NULL,
    evaluation_period_end DATE NOT NULL CHECK (evaluation_period_end >= evaluation_period_start),

    -- Performance metrics
    metric_type VARCHAR(50) NOT NULL
        CHECK (metric_type IN ('PRODUCTIVITY', 'QUALITY', 'ATTENDANCE', 'CUSTOMER_SATISFACTION',
                              'EFFICIENCY', 'ACCURACY', 'SPEED', 'SAFETY', 'TEAMWORK', 'LEADERSHIP')),
    metric_value NUMERIC(10,2) NOT NULL,
    metric_unit VARCHAR(20) NOT NULL
        CHECK (metric_unit IN ('UNITS_PER_HOUR', 'PERCENTAGE', 'SCORE_1_5', 'SCORE_1_100',
                              'MINUTES', 'HOURS', 'COUNT', 'RATING')),
    target_value NUMERIC(10,2),
    variance NUMERIC(10,2) GENERATED ALWAYS AS (metric_value - COALESCE(target_value, 0)) STORED,
    variance_percentage NUMERIC(10,2) GENERATED ALWAYS AS (
        CASE
            WHEN COALESCE(target_value, 0) != 0 THEN ((metric_value - target_value) / target_value * 100)
            ELSE 0
        END
    ) STORED,

    -- Performance categorization
    performance_category VARCHAR(20) NOT NULL
        CHECK (performance_category IN ('EXCEEDS_EXPECTATIONS', 'MEETS_EXPECTATIONS', 'NEEDS_IMPROVEMENT', 'UNSATISFACTORY')),
    performance_trend VARCHAR(20) CHECK (performance_trend IN ('IMPROVING', 'STABLE', 'DECLINING', 'VOLATILE')),

    -- Context and evaluation
    context JSONB DEFAULT '{}'::jsonb,
    evaluator_id UUID REFERENCES hr.employees(employee_id),
    evaluation_method VARCHAR(50)
        CHECK (evaluation_method IN ('AUTOMATED', 'MANAGER_REVIEW', 'PEER_REVIEW', 'SELF_ASSESSMENT', 'CUSTOMER_FEEDBACK')),
    confidence_score NUMERIC(3,2) CHECK (confidence_score BETWEEN 0 AND 1),

    -- Impact assessment
    business_impact VARCHAR(20)
        CHECK (business_impact IN ('HIGH', 'MEDIUM', 'LOW', 'NEGLIGIBLE')),
    improvement_opportunities TEXT[],
    action_items TEXT[],

    -- Audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,

    -- System metadata
    metadata JSONB DEFAULT '{}'::jsonb,

    -- Constraints
    CONSTRAINT chk_evaluation_period CHECK (
        evaluation_period_end <= evaluation_period_start + INTERVAL '1 year'
    ),
    CONSTRAINT chk_metric_values CHECK (
        (metric_unit = 'PERCENTAGE' AND metric_value BETWEEN 0 AND 100) OR
        (metric_unit = 'SCORE_1_5' AND metric_value BETWEEN 1 AND 5) OR
        (metric_unit = 'SCORE_1_100' AND metric_value BETWEEN 1 AND 100) OR
        (metric_unit IN ('UNITS_PER_HOUR', 'MINUTES', 'HOURS', 'COUNT', 'RATING') AND metric_value >= 0)
    ),
    CONSTRAINT chk_target_value CHECK (target_value >= 0)
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_performance_employee
ON scheduling.employee_performance_history(employee_id);

CREATE INDEX IF NOT EXISTS idx_performance_shift
ON scheduling.employee_performance_history(shift_id)
WHERE shift_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_performance_date
ON scheduling.employee_performance_history(performance_date DESC);

CREATE INDEX IF NOT EXISTS idx_performance_metric
ON scheduling.employee_performance_history(metric_type, performance_date);

CREATE INDEX IF NOT EXISTS idx_performance_value
ON scheduling.employee_performance_history(metric_value);

CREATE INDEX IF NOT EXISTS idx_performance_category
ON scheduling.employee_performance_history(performance_category, performance_date);

CREATE INDEX IF NOT EXISTS idx_performance_context
ON scheduling.employee_performance_history USING GIN(context);

CREATE INDEX IF NOT EXISTS idx_performance_metadata
ON scheduling.employee_performance_history USING GIN(metadata);

-- Comments
COMMENT ON TABLE scheduling.employee_performance_history IS 'Historical performance data used for performance-based scheduling and workforce optimization';
COMMENT ON COLUMN scheduling.employee_performance_history.variance_percentage IS 'Percentage variance from target (positive = above target)';
COMMENT ON COLUMN scheduling.employee_performance_history.confidence_score IS 'Confidence level in the performance measurement (0-1)';



-- Serial No: | TABLE: scheduling.employee_preferences
-- Description: Comprehensive tracking of employee preferences for scheduling
-- Business Case: Captures detailed employee preferences to improve schedule satisfaction, retention,
--                and work-life balance. Supports complex preference types including schedule patterns,
--                shift times, days off, location preferences, team preferences, and training opportunities.
--                Enables preference-based scheduling algorithms that balance employee satisfaction
--                with operational requirements. Provides mechanisms for preference validation,
--                approval workflows, and preference fulfillment tracking.
-- KPI: 1. Preference fulfillment rate (>80%), 2. Schedule satisfaction score (>4/5),
--      3. Retention rate improvement (>15%), 4. Preference change frequency (<monthly),
--      5. Preference approval time (<48 hours), 6. Preference accuracy rate (>95%),
--      7. Employee engagement score improvement (>10%)
-- Feature Reference: F001, F002, F003, F004, F005, F006, F007, F008, F009, F010, F011, F012, F013
CREATE TABLE IF NOT EXISTS scheduling.employee_preferences (
    preference_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    preference_code VARCHAR(50) UNIQUE NOT NULL CHECK (preference_code ~ '^PREF-[A-Z0-9]{3,8}-[A-Z0-9]{6}$'),

    -- Employee context
    employee_id UUID NOT NULL REFERENCES hr.employees(employee_id),

    -- Preference details
    preference_category VARCHAR(50) NOT NULL
        CHECK (preference_category IN ('SCHEDULE_PATTERNS', 'SHIFT_TIMES', 'DAYS_OFF',
                                      'LOCATION_PREFERENCES', 'TEAM_PREFERENCES', 'TRAINING_PREFERENCES',
                                      'WORK_HOURS', 'BREAK_PREFERENCES', 'OVERTIME_PREFERENCES')),
    preference_type VARCHAR(50) NOT NULL,
    preference_value TEXT NOT NULL,
    preference_weight NUMERIC(3,2) NOT NULL DEFAULT 1.0 CHECK (preference_weight BETWEEN 0.1 AND 1.0),

    -- Preference timing
    effective_start_date DATE NOT NULL DEFAULT CURRENT_DATE,
    effective_end_date DATE,
    priority INTEGER DEFAULT 0 CHECK (priority BETWEEN -10 AND 10),

    -- Validation and approval
    is_approved BOOLEAN NOT NULL DEFAULT FALSE,
    approval_notes TEXT,
    approved_by UUID REFERENCES hr.employees(employee_id),
    approval_date TIMESTAMP WITH TIME ZONE,
    validation_status VARCHAR(20) DEFAULT 'PENDING'
        CHECK (validation_status IN ('PENDING', 'VALID', 'INVALID', 'NEEDS_REVIEW')),

    -- Source tracking
    source_system VARCHAR(50) NOT NULL DEFAULT 'EMPLOYEE_SELF_SERVICE'
        CHECK (source_system IN ('EMPLOYEE_SELF_SERVICE', 'MANAGER', 'HR_SYSTEM', 'IMPORTED', 'AUTOMATED')),
    source_reference VARCHAR(100),

    -- Impact tracking
    fulfillment_count INTEGER NOT NULL DEFAULT 0 CHECK (fulfillment_count >= 0),
    last_fulfilled_at TIMESTAMP WITH TIME ZONE,
    fulfillment_rate NUMERIC(5,2) CHECK (fulfillment_rate BETWEEN 0 AND 100),
    impact_score NUMERIC(5,2) CHECK (impact_score BETWEEN 0 AND 100),

    -- Additional details
    notes TEXT,
    constraints JSONB DEFAULT '{}'::jsonb,
    alternatives TEXT[] DEFAULT '{}',

    -- Versioning
    version INTEGER NOT NULL DEFAULT 1 CHECK (version >= 1),
    parent_preference_id UUID REFERENCES scheduling.employee_preferences(preference_id),

    -- Audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,

    -- System metadata
    metadata JSONB DEFAULT '{}'::jsonb,

    -- Constraints
    CONSTRAINT chk_preference_dates CHECK (
        effective_end_date IS NULL OR effective_end_date >= effective_start_date
    ),
    CONSTRAINT chk_preference_approval CHECK (
        (is_approved = TRUE AND approved_by IS NOT NULL AND approval_date IS NOT NULL) OR
        (is_approved = FALSE AND approved_by IS NULL AND approval_date IS NULL)
    ),
    CONSTRAINT chk_preference_fulfillment CHECK (
        (last_fulfilled_at IS NULL AND fulfillment_count = 0) OR
        (last_fulfilled_at IS NOT NULL AND fulfillment_count > 0)
    )
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_preferences_employee
ON scheduling.employee_preferences(employee_id);

CREATE INDEX IF NOT EXISTS idx_preferences_category
ON scheduling.employee_preferences(preference_category);

CREATE INDEX IF NOT EXISTS idx_preferences_type
ON scheduling.employee_preferences(preference_type);

CREATE INDEX IF NOT EXISTS idx_preferences_dates
ON scheduling.employee_preferences(effective_start_date, effective_end_date);

CREATE INDEX IF NOT EXISTS idx_preferences_priority
ON scheduling.employee_preferences(priority DESC);

CREATE INDEX IF NOT EXISTS idx_preferences_approved
ON scheduling.employee_preferences(is_approved)
WHERE is_approved = TRUE;

CREATE INDEX IF NOT EXISTS idx_preferences_fulfillment
ON scheduling.employee_preferences(fulfillment_rate DESC NULLS LAST);

CREATE INDEX IF NOT EXISTS idx_preferences_metadata
ON scheduling.employee_preferences USING GIN(metadata);

CREATE INDEX IF NOT EXISTS idx_preferences_constraints
ON scheduling.employee_preferences USING GIN(constraints);

-- Comments
COMMENT ON TABLE scheduling.employee_preferences IS 'Comprehensive employee preferences for scheduling and workforce planning';
COMMENT ON COLUMN scheduling.employee_preferences.preference_weight IS 'Relative importance of this preference (0.1-1.0)';
COMMENT ON COLUMN scheduling.employee_preferences.fulfillment_rate IS 'Percentage of times this preference was fulfilled when applicable';



-- =============================================================================
-- Serial No: 6 | TABLE: scheduling.demand_forecasting_models
-- =============================================================================
-- Description: Stores configuration and metadata for demand forecasting models
-- Business Case: Powers demand-driven scheduling by providing accurate forecasts of business volume,
--                customer traffic, transaction patterns, and service requirements. Enables proactive
--                staffing based on predicted demand rather than historical averages. Supports multiple
--                forecasting methodologies (ARIMA, exponential smoothing, machine learning) and allows
--                for model comparison, validation, and continuous improvement. Reduces overstaffing
--                and understaffing costs while improving service levels.
-- KPI: 1. Forecast accuracy (>85%), 2. Model adoption rate (>90%),
--      3. Forecast recency (<24 hours), 4. Prediction confidence interval (>95%),
--      5. Model retraining frequency (>weekly), 6. Forecast error reduction rate (>15%),
--      7. Business impact measurement coverage (>80%)
-- Feature Reference: F001, F002, F003, F004, F005, F006, F007, F008, F009, F010, F011, F012, F013
-- =============================================================================

CREATE TABLE IF NOT EXISTS scheduling.demand_forecasting_models (
    -- Primary identifiers
    model_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    model_code VARCHAR(50) UNIQUE NOT NULL 
        CHECK (model_code ~ '^MOD-[A-Z0-9]{3,8}-[A-Z0-9]{6}$'),
    
    -- Core model information
    name VARCHAR(200) NOT NULL,
    description TEXT,
    
    -- Model characteristics
    model_type VARCHAR(50) NOT NULL
        CHECK (model_type IN ('ARIMA', 'EXPONENTIAL_SMOOTHING', 'MACHINE_LEARNING',
                             'ENSEMBLE', 'NEURAL_NETWORK', 'TIME_SERIES', 'REGRESSION')),
    forecasting_target VARCHAR(50) NOT NULL
        CHECK (forecasting_target IN ('CUSTOMER_TRAFFIC', 'TRANSACTIONS', 'REVENUE',
                                     'SERVICE_TIME', 'ORDER_VOLUME', 'PEAK_HOURS')),
    
    -- Organizational context (using existing schema tables)
    location_id UUID NOT NULL REFERENCES operations.locations(location_id),
    department_id UUID REFERENCES hr.departments(department_id),
    position_id UUID REFERENCES hr.positions(position_id),
    
    -- Model configuration
    input_features JSONB NOT NULL DEFAULT '[]'::jsonb,
    model_parameters JSONB DEFAULT '{}'::jsonb,
    hyperparameters JSONB DEFAULT '{}'::jsonb,
    feature_importance JSONB DEFAULT '{}'::jsonb,
    
    -- Training data
    training_data_start DATE NOT NULL,
    training_data_end DATE NOT NULL 
        CHECK (training_data_end >= training_data_start),
    training_data_size INTEGER NOT NULL CHECK (training_data_size >= 100),
    validation_split NUMERIC(5,4) NOT NULL DEFAULT 0.2 
        CHECK (validation_split BETWEEN 0.1 AND 0.5),
    
    -- Performance metrics
    validation_metrics JSONB DEFAULT '{}'::jsonb,
    accuracy_metrics JSONB DEFAULT '{}'::jsonb,
    mae NUMERIC(10,4) CHECK (mae >= 0),
    mse NUMERIC(10,4) CHECK (mse >= 0),
    rmse NUMERIC(10,4) CHECK (rmse >= 0),
    r_squared NUMERIC(5,4) CHECK (r_squared BETWEEN -1 AND 1),
    
    -- Forecasting parameters
    confidence_interval NUMERIC(5,2) NOT NULL DEFAULT 95.00
        CHECK (confidence_interval BETWEEN 50.00 AND 99.99),
    forecast_horizon VARCHAR(20) NOT NULL
        CHECK (forecast_horizon IN ('SHORT_TERM', 'MEDIUM_TERM', 'LONG_TERM')),
    forecast_frequency VARCHAR(20) NOT NULL
        CHECK (forecast_frequency IN ('HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
    
    -- Model lifecycle
    status VARCHAR(20) NOT NULL DEFAULT 'DEVELOPMENT'
        CHECK (status IN ('DEVELOPMENT', 'TESTING', 'VALIDATION', 'APPROVED', 'DEPLOYED', 'DEPRECATED', 'RETIRED')),
    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_production BOOLEAN NOT NULL DEFAULT FALSE,
    
    -- Refresh and maintenance
    refresh_frequency VARCHAR(20) NOT NULL
        CHECK (refresh_frequency IN ('REALTIME', 'HOURLY', 'DAILY', 'WEEKLY', 'MONTHLY')),
    last_refresh_at TIMESTAMP WITH TIME ZONE,
    next_refresh_at TIMESTAMP WITH TIME ZONE,
    retraining_frequency VARCHAR(20)
        CHECK (retraining_frequency IN ('DAILY', 'WEEKLY', 'MONTHLY', 'QUARTERLY', 'YEARLY')),
    last_retrained_at TIMESTAMP WITH TIME ZONE,
    
    -- Audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    approved_by UUID REFERENCES hr.employees(employee_id),
    approved_at TIMESTAMP WITH TIME ZONE,
    
    -- System metadata
    metadata JSONB DEFAULT '{}'::jsonb,
    tags TEXT[] DEFAULT '{}',
    
    -- Constraints
    CONSTRAINT chk_training_data_range CHECK (
        training_data_end <= training_data_start + INTERVAL '5 years'
    ),
    CONSTRAINT chk_model_metrics CHECK (
        (mae IS NULL AND mse IS NULL AND rmse IS NULL) OR
        (mae IS NOT NULL AND mse IS NOT NULL AND rmse IS NOT NULL)
    ),
    CONSTRAINT chk_refresh_schedule CHECK (
        (refresh_frequency = 'REALTIME' AND next_refresh_at IS NULL) OR
        (refresh_frequency != 'REALTIME' AND next_refresh_at IS NOT NULL)
    ),
    CONSTRAINT chk_training_dates_valid CHECK (
        training_data_end >= training_data_start
    )
);

