COMMENT ON COLUMN scheduling.demand_forecasting_models.is_production IS 'Indicates if model is actively used in production scheduling';


-- =============================================================================
-- Serial No: 7 | TABLE: scheduling.staffing_optimization_rules
-- =============================================================================
-- Description: Stores business rules that guide the staffing optimization engine
-- Business Case: Encodes business constraints, optimization priorities, compliance requirements,
--                and operational preferences into the scheduling algorithm. Enables systematic
--                balancing of competing objectives (cost, coverage, compliance, preferences)
--                through configurable rule weights and priorities. Supports complex rule hierarchies,
--                conditional logic, and rule versioning. Provides transparency into optimization
--                decisions and enables continuous improvement of scheduling outcomes.
-- KPI: 1. Rule coverage completeness (>95%), 2. Optimization speed (<5 minutes),
--      3. Schedule quality score (>85%), 4. Rule violation rate (<2%),
--      5. Optimization objective achievement (>90%), 6. Rule maintenance efficiency (>80%),
--      7. User satisfaction with optimization results (>4/5)
-- Feature Reference: F001, F002, F003, F004, F005, F006, F007, F008, F009, F010, F011, F012, F013
-- =============================================================================

CREATE TABLE IF NOT EXISTS scheduling.staffing_optimization_rules (
    -- Primary identifiers
    rule_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    rule_code VARCHAR(50) UNIQUE NOT NULL 
        CHECK (rule_code ~ '^RUL-[A-Z0-9]{3,8}-[A-Z0-9]{6}$'),
    
    -- Core rule information
    name VARCHAR(200) NOT NULL,
    description TEXT NOT NULL,
    
    -- Rule characteristics
    rule_type VARCHAR(50) NOT NULL
        CHECK (rule_type IN ('HARD_CONSTRAINT', 'SOFT_CONSTRAINT', 'PRIORITY_RULE',
                            'COST_OPTIMIZATION', 'COMPLIANCE_RULE', 'PREFERENCE_RULE')),
    rule_category VARCHAR(50) NOT NULL
        CHECK (rule_category IN ('COVERAGE', 'COST', 'COMPLIANCE', 'PREFERENCE', 
                                'SKILL', 'AVAILABILITY', 'WORKLOAD', 'FAIRNESS')),
    
    -- Rule definition
    rule_expression TEXT NOT NULL,
    rule_parameters JSONB DEFAULT '{}'::jsonb,
    rule_conditions JSONB DEFAULT '{}'::jsonb,
    
    -- Rule priority and impact
    priority INTEGER NOT NULL DEFAULT 50 CHECK (priority BETWEEN 1 AND 100),
    weight NUMERIC(5,2) NOT NULL DEFAULT 1.0 CHECK (weight BETWEEN 0.1 AND 10.0),
    severity VARCHAR(20) NOT NULL DEFAULT 'MEDIUM'
        CHECK (severity IN ('LOW', 'MEDIUM', 'HIGH', 'CRITICAL')),
    enforcement_level VARCHAR(50) NOT NULL DEFAULT 'MANDATORY'
        CHECK (enforcement_level IN ('MANDATORY', 'STRONGLY_PREFERRED', 'PREFERRED', 'DESIRABLE', 'INFORMATIONAL')),
    
    -- Rule applicability
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    effective_start_date DATE NOT NULL DEFAULT CURRENT_DATE,
    effective_end_date DATE,
    applicable_locations UUID[] DEFAULT '{}',
    applicable_departments UUID[] DEFAULT '{}',
    applicable_positions UUID[] DEFAULT '{}',
    applicable_employee_types TEXT[] DEFAULT '{}',
    
    -- Performance tracking
    execution_count INTEGER NOT NULL DEFAULT 0 CHECK (execution_count >= 0),
    violation_count INTEGER NOT NULL DEFAULT 0 CHECK (violation_count >= 0),
    last_executed_at TIMESTAMP WITH TIME ZONE,
    average_impact_score NUMERIC(5,2) CHECK (average_impact_score BETWEEN 0 AND 100),
    
    -- Versioning
    version_number VARCHAR(20) NOT NULL DEFAULT '1.0',
    parent_rule_id UUID REFERENCES scheduling.staffing_optimization_rules(rule_id),
    
    -- Approval workflow
    approval_status VARCHAR(20) NOT NULL DEFAULT 'DRAFT'
        CHECK (approval_status IN ('DRAFT', 'REVIEW', 'APPROVED', 'REJECTED', 'RETIRED')),
    approved_by UUID REFERENCES hr.employees(employee_id),
    approved_at TIMESTAMP WITH TIME ZONE,
    approval_notes TEXT,
    
    -- Audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- System metadata
    metadata JSONB DEFAULT '{}'::jsonb,
    tags TEXT[] DEFAULT '{}',
    
    -- Constraints
    CONSTRAINT chk_rule_dates CHECK (
        effective_end_date IS NULL OR effective_end_date >= effective_start_date
    ),
    CONSTRAINT chk_rule_impact CHECK (
        violation_count <= execution_count
    ),
    CONSTRAINT chk_rule_approval CHECK (
        (approval_status = 'APPROVED' AND approved_at IS NOT NULL AND approved_by IS NOT NULL) OR
        (approval_status != 'APPROVED')
    ),
    CONSTRAINT chk_rule_version_format CHECK (
        version_number ~ '^\d+\.\d+$'
    )
);

