-- =============================================================================
-- Serial No: 8 | TABLE: scheduling.cross_location_staff_pool
-- =============================================================================
-- Description: Manages pools of employees who can work across multiple locations
-- Business Case: Enables flexible staffing across multiple locations to optimize labor utilization,
--                reduce staffing gaps, and respond to unexpected demand fluctuations. Supports
--                regional staffing strategies, emergency coverage, and specialized skill sharing.
--                Provides mechanisms for employee preferences, travel considerations, and
--                location-specific certification requirements. Reduces overall labor costs
--                while improving service consistency across locations.
-- KPI: 1. Cross-location utilization rate (>85%), 2. Staffing gap reduction (>90%),
--      3. Response time (<15 minutes), 4. Employee satisfaction with cross-location assignments (>4/5),
--      5. Cost savings from optimized staffing (>15%), 6. Compliance rate for cross-location rules (>95%),
--      7. Assignment acceptance rate (>80%)
-- Feature Reference: F001, F002, F003, F004, F005, F006, F007, F008, F009, F010, F011, F012, F013
-- =============================================================================

CREATE TABLE IF NOT EXISTS scheduling.cross_location_staff_pool (
    -- Primary identifiers
    pool_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    pool_code VARCHAR(50) UNIQUE NOT NULL 
        CHECK (pool_code ~ '^POL-[A-Z0-9]{3,8}-[A-Z0-9]{6}$'),
    
    -- Core pool information
    name VARCHAR(200) NOT NULL,
    description TEXT,
    
    -- Pool characteristics
    pool_type VARCHAR(50) NOT NULL
        CHECK (pool_type IN ('REGIONAL', 'DEPARTMENTAL', 'SPECIALIZED', 'EMERGENCY',
                            'FLOAT', 'RESERVE', 'ON_CALL')),
    coverage_radius NUMERIC(10,2) CHECK (coverage_radius >= 0),
    geographic_area GEOGRAPHY(POLYGON, 4326),
    
    -- Pool management
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    max_assignments_per_employee INTEGER DEFAULT 3 CHECK (max_assignments_per_employee >= 1),
    min_assignments_per_employee INTEGER DEFAULT 0 CHECK (min_assignments_per_employee >= 0),
    minimum_notice_period INTERVAL DEFAULT '15 minutes',
    maximum_travel_time INTERVAL DEFAULT '1 hour',
    
    -- Eligibility criteria
    required_certifications UUID[] DEFAULT '{}',
    required_skills UUID[] DEFAULT '{}',
    experience_level_requirements JSONB DEFAULT '{}'::jsonb,
    eligibility_rules JSONB DEFAULT '{}'::jsonb,
    
    -- Performance metrics
    total_assignments INTEGER NOT NULL DEFAULT 0 CHECK (total_assignments >= 0),
    successful_assignments INTEGER NOT NULL DEFAULT 0 CHECK (successful_assignments >= 0),
    fill_rate NUMERIC(5,2) GENERATED ALWAYS AS (
        CASE
            WHEN total_assignments > 0 THEN (successful_assignments::NUMERIC / total_assignments * 100.0)
            ELSE 0
        END
    ) STORED,
    average_response_time INTERVAL,
    employee_satisfaction_score NUMERIC(5,2) CHECK (employee_satisfaction_score BETWEEN 0 AND 100),
    
    -- Scheduling preferences
    preferred_scheduling_window INTERVAL DEFAULT '2 weeks',
    blackout_dates DATE[] DEFAULT '{}',
    peak_coverage_times JSONB DEFAULT '{}'::jsonb,
    
    -- Organizational context (using existing schema tables)
    region_id UUID,
    managing_department_id UUID REFERENCES hr.departments(department_id),
    primary_location_id UUID REFERENCES operations.locations(location_id),
    
    -- Audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- System metadata
    metadata JSONB DEFAULT '{}'::jsonb,
    tags TEXT[] DEFAULT '{}',
    
    -- Constraints
    CONSTRAINT chk_pool_assignments CHECK (
        successful_assignments <= total_assignments
    ),
    CONSTRAINT chk_travel_time CHECK (
        maximum_travel_time <= INTERVAL '4 hours'
    ),
    CONSTRAINT chk_notice_period CHECK (
        minimum_notice_period <= INTERVAL '24 hours'
    ),
    CONSTRAINT chk_assignment_limits CHECK (
        max_assignments_per_employee >= min_assignments_per_employee
    )
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_staff_pool_region
