COMMENT ON COLUMN scheduling.cross_location_staff_pool.pool_id IS 'Unique identifier for the staff pool';
COMMENT ON COLUMN scheduling.cross_location_staff_pool.pool_code IS 'Business-readable pool code (format: POL-XXX-YYYYYY)';
COMMENT ON COLUMN scheduling.cross_location_staff_pool.geographic_area IS 'Geographic polygon defining the coverage area for this pool';
COMMENT ON COLUMN scheduling.cross_location_staff_pool.fill_rate IS 'Percentage of staffing requests successfully filled by this pool (calculated)';
