COMMENT ON COLUMN scheduling.cross_location_staff_pool.required_skills IS 'Array of skill IDs required for pool eligibility';
COMMENT ON COLUMN scheduling.cross_location_staff_pool.eligibility_rules IS 'JSON object defining complex eligibility criteria';
