-- =============================================================================
-- Serial No: 15 | TABLE: scheduling.schedule_exceptions
-- =============================================================================
-- Description: One-time schedule changes and exceptions management
-- Business Case: This table manages exceptions to regular schedules including shift additions,
--                removals, swaps, and time-off requests. It supports flexible scheduling
--                adjustments while maintaining audit trails and compliance checks. The table
--                enables rapid response to changing business needs and employee circumstances.
--                It provides controlled exception approval workflows and impact assessment.
--                By tracking all schedule exceptions, the organization can analyze patterns
--                of schedule changes and identify opportunities to improve schedule stability.
--                The exception management supports compliance with labor regulations regarding
--                schedule change notifications and employee consent requirements.
-- KPI: Exception approval time (<4 hours), Exception compliance rate (>98%),
--      Exception impact assessment accuracy (>90%), Exception tracking completeness (>95%),
--      Manager exception handling efficiency (>85%), Employee satisfaction with exception process (>4/5),
--      Exception recurrence rate (<5%)
-- Feature Reference: F-SCH-035, F-SCH-036, F-SCH-037, F-SCH-038, F-SCH-039
CREATE TABLE IF NOT EXISTS scheduling.schedule_exceptions (
    exception_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    exception_code VARCHAR(50) UNIQUE NOT NULL CHECK (exception_code ~ '^EXP-[A-Z0-9]{3,8}-[A-Z0-9]{6}$'),
    
    -- Exception context
    schedule_id UUID REFERENCES scheduling.schedules(schedule_id),
    shift_id UUID REFERENCES scheduling.shifts(shift_id),
    employee_id UUID REFERENCES hr.employees(employee_id),
    
    -- Exception details
    exception_date DATE NOT NULL,
    exception_type VARCHAR(50) NOT NULL
        CHECK (exception_type IN ('ADDITIONAL_SHIFT', 'REMOVED_SHIFT', 'SWAP',
                                 'TIME_OFF', 'TIME_CHANGE', 'LOCATION_CHANGE',
                                 'POSITION_CHANGE', 'SPECIAL_ASSIGNMENT')),
    description TEXT NOT NULL,
    
    -- Timing details (for time changes)
    original_start_time TIMESTAMP WITH TIME ZONE,
    original_end_time TIMESTAMP WITH TIME ZONE,
    new_start_time TIMESTAMP WITH TIME ZONE,
    new_end_time TIMESTAMP WITH TIME ZONE,
    
    -- Employee details (for swaps)
    original_employee_id UUID REFERENCES hr.employees(employee_id),
    new_employee_id UUID REFERENCES hr.employees(employee_id),
    
    -- Approval workflow
    status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
        CHECK (status IN ('PENDING', 'APPROVED', 'REJECTED', 'CANCELLED', 'EXPIRED')),
    requested_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    requested_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    approved_by UUID REFERENCES hr.employees(employee_id),
    approved_at TIMESTAMP WITH TIME ZONE,
    approval_notes TEXT,
    rejection_reason TEXT,
    
    -- Impact assessment
    business_impact VARCHAR(20)
        CHECK (business_impact IN ('POSITIVE', 'NEUTRAL', 'NEGATIVE', 'SIGNIFICANT')),
    coverage_impact NUMERIC(5,2) CHECK (coverage_impact BETWEEN -100 AND 100),
    cost_impact NUMERIC(10,2),
    compliance_impact VARCHAR(20)
        CHECK (compliance_impact IN ('COMPLIANT', 'NON_COMPLIANT', 'NEEDS_REVIEW')),
    
    -- Request source
    request_source VARCHAR(50) NOT NULL DEFAULT 'EMPLOYEE'
        CHECK (request_source IN ('EMPLOYEE', 'MANAGER', 'SYSTEM', 'AUTOMATED', 'EXTERNAL')),
    
    -- Related exceptions (for multi-part changes)
    parent_exception_id UUID REFERENCES scheduling.schedule_exceptions(exception_id),
    related_exceptions UUID[] DEFAULT '{}',
    
    -- Audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- System metadata
    metadata JSONB DEFAULT '{}'::JSONB,
    
    -- Constraints
    CONSTRAINT chk_exception_timing CHECK (
        (exception_type NOT IN ('TIME_CHANGE', 'TIME_OFF') AND
         original_start_time IS NULL AND original_end_time IS NULL AND
         new_start_time IS NULL AND new_end_time IS NULL) OR
        (exception_type IN ('TIME_CHANGE', 'TIME_OFF') AND
         original_start_time IS NOT NULL AND original_end_time IS NOT NULL)
    ),
    CONSTRAINT chk_swap_logic CHECK (
        (exception_type != 'SWAP' AND original_employee_id IS NULL AND new_employee_id IS NULL) OR
        (exception_type = 'SWAP' AND original_employee_id IS NOT NULL AND new_employee_id IS NOT NULL)
    ),
    CONSTRAINT chk_approval_logic CHECK (
        (status = 'APPROVED' AND approved_by IS NOT NULL AND approved_at IS NOT NULL) OR
        (status != 'APPROVED' AND approved_by IS NULL AND approved_at IS NULL)
    ),
    CONSTRAINT chk_exception_dates CHECK (
        exception_date >= CURRENT_DATE - INTERVAL '365 days'
    )
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_schedule_exceptions_schedule
ON scheduling.schedule_exceptions(schedule_id)
WHERE schedule_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_schedule_exceptions_employee
ON scheduling.schedule_exceptions(employee_id)
WHERE employee_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_schedule_exceptions_shift
ON scheduling.schedule_exceptions(shift_id)
WHERE shift_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_schedule_exceptions_date_type
ON scheduling.schedule_exceptions(exception_date, exception_type);

CREATE INDEX IF NOT EXISTS idx_schedule_exceptions_status
ON scheduling.schedule_exceptions(status, requested_at);

CREATE INDEX IF NOT EXISTS idx_schedule_exceptions_approved
ON scheduling.schedule_exceptions(approved_at)
WHERE approved_at IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_schedule_exceptions_parent
ON scheduling.schedule_exceptions(parent_exception_id)
WHERE parent_exception_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_schedule_exceptions_requested
ON scheduling.schedule_exceptions(requested_by, requested_at DESC);

CREATE INDEX IF NOT EXISTS idx_schedule_exceptions_metadata
ON scheduling.schedule_exceptions USING GIN(metadata);

-- Trigger for audit columns
DROP TRIGGER IF EXISTS trg_schedule_exceptions_updated_at ON scheduling.schedule_exceptions;
CREATE TRIGGER trg_schedule_exceptions_updated_at
BEFORE UPDATE ON scheduling.schedule_exceptions
FOR EACH ROW
EXECUTE FUNCTION public.update_updated_at_column();

-- Comments
COMMENT ON TABLE scheduling.schedule_exceptions IS 'One-time schedule changes and exceptions management. Manages exceptions to regular schedules including shift additions, removals, swaps, and time-off requests. Supports flexible scheduling adjustments while maintaining audit trails and compliance checks.';
COMMENT ON COLUMN scheduling.schedule_exceptions.exception_id IS 'Unique identifier for exception record (UUID)';
COMMENT ON COLUMN scheduling.schedule_exceptions.exception_code IS 'Business-readable exception code (format: EXP-XXX-XXXXXX)';
COMMENT ON COLUMN scheduling.schedule_exceptions.schedule_id IS 'Reference to schedule (if applicable)';
COMMENT ON COLUMN scheduling.schedule_exceptions.shift_id IS 'Reference to shift (if applicable)';
COMMENT ON COLUMN scheduling.schedule_exceptions.employee_id IS 'Reference to employee';
COMMENT ON COLUMN scheduling.schedule_exceptions.exception_type IS 'Type of exception (ADDITIONAL_SHIFT, REMOVED_SHIFT, SWAP, TIME_OFF, etc.)';
COMMENT ON COLUMN scheduling.schedule_exceptions.status IS 'Current status of exception request';
COMMENT ON COLUMN scheduling.schedule_exceptions.coverage_impact IS 'Percentage impact on coverage (-100 to +100)';
COMMENT ON COLUMN scheduling.schedule_exceptions.request_source IS 'Source of exception request (EMPLOYEE, MANAGER, SYSTEM, etc.)';
COMMENT ON COLUMN scheduling.schedule_exceptions.related_exceptions IS 'Array of exception IDs related to this exception';
COMMENT ON COLUMN scheduling.schedule_exceptions.compliance_impact IS 'Compliance impact assessment (COMPLIANT, NON_COMPLIANT, NEEDS_REVIEW)';



-- =============================================================================
-- Serial No: 16 | TABLE: scheduling.schedule_approvals
-- =============================================================================
-- Description: Multi-level schedule approval workflow tracking
-- Business Case: Manages complex approval workflows for schedule publication,
--                ensuring appropriate review and authorization at each level.
--                Supports configurable approval hierarchies, delegation rules,
--                and escalation procedures. Provides audit trails for all
--                approval decisions and enables compliance with internal controls.
-- KPI: 1. Approval cycle time (<24 hours), 2. Approval completeness rate (>99%),
--      3. Escalation rate (<5%), 4. Delegate approval accuracy (>95%),
--      5. Approval audit trail completeness (>100%), 6. Manager approval efficiency (>90%),
--      7. System approval automation rate (>70%)
-- Feature Reference: F-SCH-016, F-APP-001, F-APP-002, F-APP-003, F-APP-004,
--                    F-APP-005, F-APP-006, F-APP-007, F-APP-008, F-APP-009,
--                    F-APP-010, F-APP-011, F-APP-012
-- =============================================================================

-- Create approval status enum if not exists (aligned with schema standards)
DO $$BEGIN
IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'approval_status_enum') THEN
CREATE TYPE scheduling.approval_status_enum AS ENUM (
    'PENDING',      -- Awaiting approval decision
    'APPROVED',     -- Approved by approver
    'REJECTED',     -- Rejected by approver
    'REVOKED',      -- Approval revoked after granting
    'EXPIRED',      -- Approval request expired
    'DELEGATED',    -- Delegated to another approver
    'ESCALATED',    -- Escalated to higher level
    'CANCELLED'     -- Approval request cancelled
);
RAISE NOTICE 'Created enum type: scheduling.approval_status_enum';
ELSE
RAISE NOTICE 'Enum type scheduling.approval_status_enum already exists';
END IF;
END$$;

COMMENT ON TYPE scheduling.approval_status_enum IS
'Defines the status of schedule approval requests in the workflow.
PENDING: Awaiting approval decision; APPROVED: Approved by approver;
REJECTED: Rejected by approver; REVOKED: Approval revoked after granting;
EXPIRED: Approval request expired; DELEGATED: Delegated to another approver;
ESCALATED: Escalated to higher level; CANCELLED: Approval request cancelled.';

-- Create the schedule_approvals table
CREATE TABLE IF NOT EXISTS scheduling.schedule_approvals (
    -- Primary identifiers
    approval_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    approval_code VARCHAR(50) UNIQUE NOT NULL 
        CHECK (approval_code ~ '^APR-[A-Z0-9]{3,8}-[A-Z0-9]{6}$'),
    
    -- Schedule relationship
    schedule_id UUID NOT NULL REFERENCES scheduling.schedules(schedule_id) ON DELETE CASCADE,
    
    -- Approver details
    approver_id UUID NOT NULL REFERENCES hr.employees(employee_id),
    approver_role VARCHAR(50) NOT NULL
        CHECK (approver_role IN ('MANAGER', 'DIRECTOR', 'VP', 'HR', 'FINANCE', 'OPERATIONS', 'COMPLIANCE')),
    approval_level INTEGER NOT NULL CHECK (approval_level BETWEEN 1 AND 10),
    approval_chain_position INTEGER DEFAULT 1 CHECK (approval_chain_position >= 1),
    
    -- Approval details
    status scheduling.approval_status_enum NOT NULL DEFAULT 'PENDING',
    comments TEXT,
    decision_reason TEXT,
    rejection_reason TEXT,
    
    -- Timing and deadlines
    requested_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    due_by TIMESTAMP WITH TIME ZONE,
    completed_at TIMESTAMP WITH TIME ZONE,
    response_time INTERVAL GENERATED ALWAYS AS (
        CASE
            WHEN completed_at IS NOT NULL THEN completed_at - requested_at
            ELSE NULL
        END
    ) STORED,
    
    -- Delegation tracking
    is_delegated BOOLEAN NOT NULL DEFAULT FALSE,
    delegated_from UUID REFERENCES hr.employees(employee_id),
    delegated_at TIMESTAMP WITH TIME ZONE,
    delegation_reason TEXT,
    
    -- Escalation tracking
    is_escalated BOOLEAN NOT NULL DEFAULT FALSE,
    escalated_to UUID REFERENCES hr.employees(employee_id),
    escalated_at TIMESTAMP WITH TIME ZONE,
    escalation_reason TEXT,
    escalation_level INTEGER DEFAULT 0 CHECK (escalation_level >= 0),
    
    -- Attachment and evidence
    attachment_urls TEXT[] DEFAULT '{}',
    review_notes TEXT,
    supporting_documents JSONB DEFAULT '{}'::jsonb,
    
    -- Workflow metadata
    workflow_instance_id UUID,
    previous_approval_id UUID REFERENCES scheduling.schedule_approvals(approval_id),
    next_approval_id UUID,
    is_final_approval BOOLEAN NOT NULL DEFAULT FALSE,
    requires_signature BOOLEAN DEFAULT FALSE,
    signature_obtained BOOLEAN DEFAULT FALSE,
    
    -- Audit columns
    created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by UUID REFERENCES hr.employees(employee_id),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- System metadata
    metadata JSONB DEFAULT '{}'::jsonb,
    tags TEXT[] DEFAULT '{}',
    
    -- Constraints
    CONSTRAINT chk_approval_timing CHECK (
        (completed_at IS NULL AND (due_by IS NULL OR due_by > requested_at)) OR
        (completed_at IS NOT NULL AND completed_at >= requested_at AND (due_by IS NULL OR due_by > requested_at))
    ),
    CONSTRAINT chk_delegation_logic CHECK (
        (is_delegated = FALSE AND delegated_from IS NULL AND delegated_at IS NULL) OR
        (is_delegated = TRUE AND delegated_from IS NOT NULL AND delegated_at IS NOT NULL)
    ),
    CONSTRAINT chk_escalation_logic CHECK (
        (is_escalated = FALSE AND escalated_to IS NULL AND escalated_at IS NULL) OR
        (is_escalated = TRUE AND escalated_to IS NOT NULL AND escalated_at IS NOT NULL)
    ),
    CONSTRAINT chk_approval_completion CHECK (
        (status IN ('APPROVED', 'REJECTED', 'REVOKED', 'CANCELLED') AND completed_at IS NOT NULL) OR
        (status IN ('PENDING', 'EXPIRED', 'DELEGATED', 'ESCALATED') AND completed_at IS NULL)
    ),
    CONSTRAINT chk_workflow_chain CHECK (
        (previous_approval_id IS NULL AND approval_chain_position = 1) OR
        (previous_approval_id IS NOT NULL AND approval_chain_position > 1)
    )
);
