        SELECT 1 FROM information_schema.tables 
        WHERE table_schema = 'scheduling' 
        AND table_name = 'schedule_approvals'
    ) THEN
        RAISE NOTICE 'Table scheduling.schedule_approvals does not exist. Creating...';
        
        -- Create the table with all columns
        CREATE TABLE scheduling.schedule_approvals (
            approval_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
            approval_code VARCHAR(50) UNIQUE 
                CHECK (approval_code ~ '^APR-[A-Z0-9]{3,8}-[A-Z0-9]{6}$'),
            schedule_id UUID NOT NULL REFERENCES scheduling.schedules(schedule_id) ON DELETE CASCADE,
            approver_id UUID NOT NULL REFERENCES hr.employees(employee_id),
            approver_role VARCHAR(50) 
                CHECK (approver_role IN ('MANAGER', 'DIRECTOR', 'VP', 'HR', 'FINANCE', 'OPERATIONS', 'COMPLIANCE')),
            approval_level INTEGER CHECK (approval_level BETWEEN 1 AND 10),
            approval_chain_position INTEGER DEFAULT 1 CHECK (approval_chain_position >= 1),
            status scheduling.approval_status_enum NOT NULL DEFAULT 'PENDING',
            comments TEXT,
            decision_reason TEXT,
            rejection_reason TEXT,
            requested_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            due_by TIMESTAMP WITH TIME ZONE,
            completed_at TIMESTAMP WITH TIME ZONE,
            response_time INTERVAL GENERATED ALWAYS AS (
                CASE
                    WHEN completed_at IS NOT NULL THEN completed_at - requested_at
                    ELSE NULL
                END
            ) STORED,
            is_delegated BOOLEAN NOT NULL DEFAULT FALSE,
            delegated_from UUID REFERENCES hr.employees(employee_id),
            delegated_at TIMESTAMP WITH TIME ZONE,
            delegation_reason TEXT,
            is_escalated BOOLEAN NOT NULL DEFAULT FALSE,
            escalated_to UUID REFERENCES hr.employees(employee_id),
            escalated_at TIMESTAMP WITH TIME ZONE,
            escalation_reason TEXT,
            escalation_level INTEGER DEFAULT 0 CHECK (escalation_level >= 0),
            attachment_urls TEXT[] DEFAULT '{}',
            review_notes TEXT,
            supporting_documents JSONB DEFAULT '{}'::jsonb,
            workflow_instance_id UUID,
            previous_approval_id UUID REFERENCES scheduling.schedule_approvals(approval_id),
            next_approval_id UUID,
            is_final_approval BOOLEAN NOT NULL DEFAULT FALSE,
            requires_signature BOOLEAN DEFAULT FALSE,
            signature_obtained BOOLEAN DEFAULT FALSE,
            tags TEXT[] DEFAULT '{}',
            created_by UUID NOT NULL REFERENCES hr.employees(employee_id),
            created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_by UUID REFERENCES hr.employees(employee_id),
            updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
            metadata JSONB DEFAULT '{}'::jsonb,
            CONSTRAINT chk_approval_timing CHECK (
                (completed_at IS NULL AND (due_by IS NULL OR due_by > requested_at)) OR
                (completed_at IS NOT NULL AND completed_at >= requested_at AND (due_by IS NULL OR due_by > requested_at))
            ),
            CONSTRAINT chk_delegation_logic CHECK (
                (is_delegated = FALSE AND delegated_from IS NULL AND delegated_at IS NULL) OR
                (is_delegated = TRUE AND delegated_from IS NOT NULL AND delegated_at IS NOT NULL)
            ),
            CONSTRAINT chk_escalation_logic CHECK (
                (is_escalated = FALSE AND escalated_to IS NULL AND escalated_at IS NULL) OR
                (is_escalated = TRUE AND escalated_to IS NOT NULL AND escalated_at IS NOT NULL)
            ),
            CONSTRAINT chk_approval_completion CHECK (
                (status IN ('APPROVED', 'REJECTED', 'REVOKED', 'CANCELLED') AND completed_at IS NOT NULL) OR
                (status IN ('PENDING', 'EXPIRED', 'DELEGATED', 'ESCALATED') AND completed_at IS NULL)
            ),
            CONSTRAINT chk_workflow_chain CHECK (
                (previous_approval_id IS NULL AND approval_chain_position = 1) OR
                (previous_approval_id IS NOT NULL AND approval_chain_position > 1)
            )
        );
        
        RAISE NOTICE 'Table scheduling.schedule_approvals created successfully';
    ELSE
        RAISE NOTICE 'Table scheduling.schedule_approvals already exists';
    END IF;
END $$;

