-- =============================================================================
-- TRIGGERS FOR AUTOMATION
-- =============================================================================

-- Trigger to update updated_at timestamp
DROP TRIGGER IF EXISTS trg_schedule_approvals_updated_at ON scheduling.schedule_approvals;
CREATE TRIGGER trg_schedule_approvals_updated_at
BEFORE UPDATE ON scheduling.schedule_approvals
FOR EACH ROW
EXECUTE FUNCTION public.update_updated_at_column();

-- Trigger to validate approval workflow
CREATE OR REPLACE FUNCTION scheduling.validate_approval_workflow()
RETURNS TRIGGER AS $$
BEGIN
    -- Validate approval chain consistency
    IF NEW.previous_approval_id IS NOT NULL THEN
        -- Verify previous approval exists and is completed
        IF NOT EXISTS (
            SELECT 1 FROM scheduling.schedule_approvals
            WHERE approval_id = NEW.previous_approval_id
            AND status IN ('APPROVED', 'REJECTED')
            AND schedule_id = NEW.schedule_id
        ) THEN
            RAISE EXCEPTION 'Previous approval in chain must be completed before proceeding';
        END IF;
    END IF;
    
    -- Validate completion status
    IF NEW.status IN ('APPROVED', 'REJECTED', 'REVOKED', 'CANCELLED') AND NEW.completed_at IS NULL THEN
        NEW.completed_at := CURRENT_TIMESTAMP;
    END IF;
    
    -- Validate response time calculation
    IF NEW.completed_at IS NOT NULL AND OLD.completed_at IS NULL THEN
        -- First time completion, response_time will be calculated automatically
        NULL;
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_schedule_approvals_workflow ON scheduling.schedule_approvals;
CREATE TRIGGER trg_schedule_approvals_workflow
BEFORE INSERT OR UPDATE OF status, previous_approval_id ON scheduling.schedule_approvals
FOR EACH ROW
EXECUTE FUNCTION scheduling.validate_approval_workflow();

-- Trigger to auto-generate approval code
CREATE OR REPLACE FUNCTION scheduling.generate_approval_code()
RETURNS TRIGGER AS $$
DECLARE
    v_schedule_code VARCHAR(50);
    v_sequence_number INTEGER;
BEGIN
    IF NEW.approval_code IS NULL THEN
        -- Get schedule code
        SELECT schedule_code INTO v_schedule_code
        FROM scheduling.schedules
        WHERE schedule_id = NEW.schedule_id;
        
        -- Generate sequence number for this schedule
        SELECT COALESCE(MAX(CAST(SUBSTRING(approval_code FROM 13) AS INTEGER)), 0) + 1
        INTO v_sequence_number
        FROM scheduling.schedule_approvals
        WHERE schedule_id = NEW.schedule_id
        AND approval_code LIKE 'APR-%-' || SUBSTRING(v_schedule_code FROM 5);
        
        -- Format approval code: APR-SCHD-XXXXXX
        NEW.approval_code := 'APR-' || SUBSTRING(v_schedule_code FROM 5) || '-' || 
                             LPAD(v_sequence_number::TEXT, 6, '0');
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_schedule_approvals_code ON scheduling.schedule_approvals;
CREATE TRIGGER trg_schedule_approvals_code
BEFORE INSERT ON scheduling.schedule_approvals
FOR EACH ROW
EXECUTE FUNCTION scheduling.generate_approval_code();

