COMMENT ON COLUMN scheduling.schedule_approvals.supporting_documents IS 'JSONB storage for document references and metadata';

-- =============================================================================
-- Serial No: 17 | TABLE: scheduling.schedule_history
-- =============================================================================
-- Description: Comprehensive audit trail of schedule changes and events
-- Business Case: Provides complete historical record of all schedule modifications,
--                enabling audit compliance, change analysis, and rollback capabilities.
--                Supports regulatory compliance, dispute resolution, and historical
--                trend analysis. Enables reconstruction of schedule states at any
--                point in time and provides transparency into all scheduling decisions.
-- KPI: 1. History completeness rate (>100%), 2. Audit trail accuracy (>99%),
--      3. Change tracking latency (<5 minutes), 4. Historical data retention compliance (>99%),
--      5. Audit query performance (<3 seconds), 6. Change analysis efficiency (>90%),
--      7. Rollback capability availability (>95%)
-- Feature Reference: F-SCH-017, F-AUD-001, F-AUD-002, F-AUD-003, F-AUD-004,
--                    F-AUD-005, F-AUD-006, F-AUD-007, F-AUD-008, F-AUD-009,
--                    F-AUD-010, F-AUD-011, F-AUD-012
-- =============================================================================

-- Create the schedule_history table
CREATE TABLE IF NOT EXISTS scheduling.schedule_history (
    -- Primary identifiers
    history_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    history_code VARCHAR(50) UNIQUE NOT NULL 
        CHECK (history_code ~ '^HIS-[A-Z0-9]{3,8}-[A-Z0-9]{6}$'),
    
    -- Entity reference
    schedule_id UUID NOT NULL REFERENCES scheduling.schedules(schedule_id) ON DELETE CASCADE,
    entity_type VARCHAR(50) NOT NULL
        CHECK (entity_type IN ('SCHEDULE', 'SHIFT', 'ASSIGNMENT', 'EXCEPTION', 'APPROVAL', 'TEMPLATE', 'COVERAGE')),
    entity_id UUID NOT NULL,
    
    -- Change details
    change_type VARCHAR(50) NOT NULL
        CHECK (change_type IN ('CREATED', 'UPDATED', 'DELETED', 'PUBLISHED', 'ARCHIVED',
                              'APPROVED', 'REJECTED', 'CANCELLED', 'RESTORED', 'ROLLED_BACK',
                              'SWAPPED', 'REASSIGNED', 'COVERAGE_CHANGED')),
    changed_fields TEXT[] NOT NULL DEFAULT '{}',
    old_values JSONB,
    new_values JSONB,
    changed_data JSONB NOT NULL DEFAULT '{}'::jsonb,
    change_summary TEXT,
    
    -- Context and impact
    change_reason VARCHAR(200),
    business_justification TEXT,
    impact_assessment VARCHAR(20)
        CHECK (impact_assessment IN ('CRITICAL', 'HIGH', 'MEDIUM', 'LOW', 'NEGLIGIBLE')),
    affected_employees UUID[],
    affected_shifts UUID[],
    compliance_impact BOOLEAN DEFAULT FALSE,
    cost_impact NUMERIC(12,2),
    
    -- Source and method
    change_source VARCHAR(50) NOT NULL
        CHECK (change_source IN ('USER', 'SYSTEM', 'API', 'IMPORT', 'AUTOMATED', 'BATCH', 'INTEGRATION')),
    change_method VARCHAR(50)
        CHECK (change_method IN ('MANUAL', 'AUTOMATED', 'SCRIPT', 'MIGRATION', 'SYNC', 'ALGORITHM')),
    source_system VARCHAR(100),
    ip_address INET,
    user_agent TEXT,
    client_application VARCHAR(100),
    
    -- Session and transaction
    session_id UUID,
    transaction_id UUID,
    request_id UUID,
    
    -- Versioning and sequencing
    version_number INTEGER NOT NULL DEFAULT 1 CHECK (version_number >= 1),
    sequence_number BIGINT,
    is_reversible BOOLEAN DEFAULT TRUE,
    rollback_reference UUID,
    
    -- Audit columns
    changed_by UUID NOT NULL REFERENCES hr.employees(employee_id),
    changed_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    
    -- System metadata
    metadata JSONB DEFAULT '{}'::jsonb,
    tags TEXT[] DEFAULT '{}',
    
    -- Constraints
    CONSTRAINT chk_history_data CHECK (
        jsonb_typeof(changed_data) = 'object'
    ),
    CONSTRAINT chk_change_values CHECK (
        (old_values IS NULL AND new_values IS NOT NULL AND change_type = 'CREATED') OR
        (old_values IS NOT NULL AND new_values IS NOT NULL AND change_type = 'UPDATED') OR
        (old_values IS NOT NULL AND new_values IS NULL AND change_type = 'DELETED') OR
        (old_values IS NULL AND new_values IS NULL AND change_type IN ('PUBLISHED', 'ARCHIVED', 'APPROVED', 'REJECTED', 'CANCELLED', 'RESTORED', 'ROLLED_BACK'))
    ),
    CONSTRAINT chk_version_sequence CHECK (
        (version_number = 1 AND sequence_number IS NULL) OR
        (version_number > 1 AND sequence_number IS NOT NULL)
    )
);


