-- =============================================================================
-- TRIGGERS FOR AUTOMATION
-- =============================================================================

-- Trigger to update updated_at timestamp (using changed_at as it's history)
-- Note: History tables typically don't have updated_at as they're immutable
-- But we include it for consistency with schema standards

-- Trigger to auto-generate history code
CREATE OR REPLACE FUNCTION scheduling.generate_history_code()
RETURNS TRIGGER AS $$
DECLARE
    v_schedule_code VARCHAR(50);
    v_sequence_number BIGINT;
BEGIN
    IF NEW.history_code IS NULL THEN
        -- Get schedule code
        SELECT schedule_code INTO v_schedule_code
        FROM scheduling.schedules
        WHERE schedule_id = NEW.schedule_id;
        
        -- Generate sequence number
        SELECT COALESCE(MAX(sequence_number), 0) + 1
        INTO v_sequence_number
        FROM scheduling.schedule_history
        WHERE schedule_id = NEW.schedule_id;
        
        NEW.sequence_number := v_sequence_number;
        NEW.version_number := v_sequence_number;
        
        -- Format history code: HIS-SCHD-XXXXXX
        NEW.history_code := 'HIS-' || SUBSTRING(v_schedule_code FROM 5) || '-' || 
                            LPAD(v_sequence_number::TEXT, 6, '0');
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_schedule_history_code ON scheduling.schedule_history;
CREATE TRIGGER trg_schedule_history_code
BEFORE INSERT ON scheduling.schedule_history
FOR EACH ROW
EXECUTE FUNCTION scheduling.generate_history_code();

-- Trigger to validate change data structure
CREATE OR REPLACE FUNCTION scheduling.validate_history_change()
RETURNS TRIGGER AS $$
BEGIN
    -- Ensure changed_data is not empty for meaningful history
    IF NEW.changed_data = '{}'::jsonb AND NEW.change_type NOT IN ('PUBLISHED', 'ARCHIVED', 'APPROVED', 'REJECTED', 'CANCELLED') THEN
        RAISE EXCEPTION 'changed_data cannot be empty for change type %', NEW.change_type;
    END IF;
    
    -- Validate impact assessment for certain change types
    IF NEW.change_type IN ('DELETED', 'ROLLED_BACK') AND NEW.impact_assessment IS NULL THEN
        NEW.impact_assessment := 'HIGH';
    END IF;
    
    -- Set compliance impact flag based on change type
    IF NEW.change_type IN ('APPROVED', 'REJECTED', 'PUBLISHED') THEN
        NEW.compliance_impact := TRUE;
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_schedule_history_validate ON scheduling.schedule_history;
CREATE TRIGGER trg_schedule_history_validate
BEFORE INSERT ON scheduling.schedule_history
FOR EACH ROW
EXECUTE FUNCTION scheduling.validate_history_change();

-- Trigger to capture session context automatically
CREATE OR REPLACE FUNCTION scheduling.capture_history_context()
RETURNS TRIGGER AS $$
BEGIN
    -- Capture session context if not provided
    IF NEW.session_id IS NULL THEN
        NEW.session_id := uuid(current_setting('app.session_id', true));
    END IF;
    
    IF NEW.ip_address IS NULL THEN
        NEW.ip_address := current_setting('app.client_ip', true)::INET;
    END IF;
    
    IF NEW.client_application IS NULL THEN
        NEW.client_application := current_setting('app.client_name', true);
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_schedule_history_context ON scheduling.schedule_history;
CREATE TRIGGER trg_schedule_history_context
BEFORE INSERT ON scheduling.schedule_history
FOR EACH ROW
EXECUTE FUNCTION scheduling.capture_history_context();

