COMMENT ON TABLE scheduling.schedule_history IS 
'Comprehensive audit trail of schedule changes and events. Provides complete historical 
record of all schedule modifications, enabling audit compliance, change analysis, and 
rollback capabilities. Supports regulatory compliance, dispute resolution, and historical 
trend analysis. Enables reconstruction of schedule states at any point in time.';

COMMENT ON COLUMN scheduling.schedule_history.history_id IS 'Unique identifier for the history record (UUID)';
COMMENT ON COLUMN scheduling.schedule_history.history_code IS 'Business-readable history code (format: HIS-SCHD-XXXXXX)';
COMMENT ON COLUMN scheduling.schedule_history.schedule_id IS 'Reference to the parent schedule';
COMMENT ON COLUMN scheduling.schedule_history.entity_type IS 'Type of entity changed (SCHEDULE, SHIFT, ASSIGNMENT, etc.)';
COMMENT ON COLUMN scheduling.schedule_history.entity_id IS 'ID of the specific entity that was changed';
COMMENT ON COLUMN scheduling.schedule_history.change_type IS 'Type of change operation (CREATED, UPDATED, DELETED, etc.)';
COMMENT ON COLUMN scheduling.schedule_history.changed_fields IS 'Array of field names that were changed in this event';
COMMENT ON COLUMN scheduling.schedule_history.old_values IS 'JSONB storage of values before the change';
COMMENT ON COLUMN scheduling.schedule_history.new_values IS 'JSONB storage of values after the change';
COMMENT ON COLUMN scheduling.schedule_history.changed_data IS 'Complete change data in JSONB format';
COMMENT ON COLUMN scheduling.schedule_history.change_summary IS 'Human-readable summary of the change';
COMMENT ON COLUMN scheduling.schedule_history.impact_assessment IS 'Assessment of change impact (CRITICAL, HIGH, MEDIUM, LOW, NEGLIGIBLE)';
COMMENT ON COLUMN scheduling.schedule_history.affected_employees IS 'Array of employee IDs affected by this change';
COMMENT ON COLUMN scheduling.schedule_history.affected_shifts IS 'Array of shift IDs affected by this change';
COMMENT ON COLUMN scheduling.schedule_history.compliance_impact IS 'Indicates if change has compliance implications';
COMMENT ON COLUMN scheduling.schedule_history.cost_impact IS 'Estimated cost impact of the change';
COMMENT ON COLUMN scheduling.schedule_history.change_source IS 'Source of the change (USER, SYSTEM, API, etc.)';
COMMENT ON COLUMN scheduling.schedule_history.change_method IS 'Method used to make the change (MANUAL, AUTOMATED, etc.)';
COMMENT ON COLUMN scheduling.schedule_history.ip_address IS 'IP address from which the change was made';
COMMENT ON COLUMN scheduling.schedule_history.session_id IS 'Session identifier for the change';
COMMENT ON COLUMN scheduling.schedule_history.transaction_id IS 'Database transaction ID for the change';
COMMENT ON COLUMN scheduling.schedule_history.version_number IS 'Version number for this history record';
COMMENT ON COLUMN scheduling.schedule_history.sequence_number IS 'Sequential number for ordering history records';
COMMENT ON COLUMN scheduling.schedule_history.is_reversible IS 'Indicates if this change can be rolled back';
COMMENT ON COLUMN scheduling.schedule_history.rollback_reference IS 'Reference to rollback history record if applicable';

-- =============================================================================
-- HELPER VIEWS FOR COMMON QUERIES
-- =============================================================================

-- View for approval workflow status
CREATE OR REPLACE VIEW scheduling.vw_approval_workflow_status AS
SELECT
    sa.schedule_id,
    s.schedule_code,
    s.name AS schedule_name,
    COUNT(sa.approval_id) AS total_approvals_required,
    COUNT(CASE WHEN sa.status = 'APPROVED' THEN 1 END) AS approvals_completed,
    COUNT(CASE WHEN sa.status = 'PENDING' THEN 1 END) AS approvals_pending,
    COUNT(CASE WHEN sa.status = 'REJECTED' THEN 1 END) AS approvals_rejected,
    ROUND(
        COUNT(CASE WHEN sa.status = 'APPROVED' THEN 1 END)::NUMERIC / 
        NULLIF(COUNT(sa.approval_id), 0) * 100, 2
    ) AS approval_completion_percentage,
    MAX(sa.completed_at) AS last_approval_at,
    MIN(CASE WHEN sa.status = 'PENDING' THEN sa.due_by END) AS next_due_by,
    BOOL_AND(sa.is_final_approval) AS all_approvals_final,
    CASE
        WHEN COUNT(CASE WHEN sa.status = 'REJECTED' THEN 1 END) > 0 THEN 'REJECTED'
        WHEN COUNT(CASE WHEN sa.status = 'PENDING' THEN 1 END) > 0 THEN 'PENDING'
        WHEN COUNT(CASE WHEN sa.status = 'APPROVED' THEN 1 END) = COUNT(sa.approval_id) THEN 'FULLY_APPROVED'
        ELSE 'IN_PROGRESS'
    END AS workflow_status
FROM scheduling.schedule_approvals sa
JOIN scheduling.schedules s ON sa.schedule_id = s.schedule_id
WHERE s.schedule_status IN ('PENDING_APPROVAL', 'APPROVED', 'PUBLISHED')
GROUP BY sa.schedule_id, s.schedule_code, s.name;

COMMENT ON VIEW scheduling.vw_approval_workflow_status IS 
'Aggregated view of approval workflow status for schedules';

-- View for recent schedule changes
CREATE OR REPLACE VIEW scheduling.vw_recent_schedule_changes AS
SELECT
    sh.history_id,
    sh.history_code,
    sh.schedule_id,
    s.schedule_code,
    sh.entity_type,
    sh.entity_id,
    sh.change_type,
    sh.changed_fields,
    sh.change_summary,
    sh.impact_assessment,
    sh.change_source,
    sh.changed_by,
    e.first_name || ' ' || e.last_name AS changed_by_name,
    sh.changed_at,
    sh.compliance_impact,
    sh.cost_impact
FROM scheduling.schedule_history sh
JOIN scheduling.schedules s ON sh.schedule_id = s.schedule_id
LEFT JOIN hr.employees e ON sh.changed_by = e.employee_id
WHERE sh.changed_at >= CURRENT_TIMESTAMP - INTERVAL '30 days'
ORDER BY sh.changed_at DESC;

COMMENT ON VIEW scheduling.vw_recent_schedule_changes IS 
'Recent schedule changes with employee names and context';

-- View for approval bottlenecks
CREATE OR REPLACE VIEW scheduling.vw_approval_bottlenecks AS
SELECT
    sa.approver_id,
    e.first_name || ' ' || e.last_name AS approver_name,
    sa.approver_role,
    COUNT(sa.approval_id) AS pending_approvals,
    AVG(EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - sa.requested_at)) / 3600) AS avg_hours_pending,
    MAX(sa.requested_at) AS oldest_request,
    COUNT(CASE WHEN sa.due_by < CURRENT_TIMESTAMP THEN 1 END) AS overdue_approvals,
    sa.approval_level
FROM scheduling.schedule_approvals sa
JOIN hr.employees e ON sa.approver_id = e.employee_id
WHERE sa.status = 'PENDING'
GROUP BY sa.approver_id, e.first_name, e.last_name, sa.approver_role, sa.approval_level
HAVING COUNT(sa.approval_id) > 0
ORDER BY pending_approvals DESC, avg_hours_pending DESC;

COMMENT ON VIEW scheduling.vw_approval_bottlenecks IS 
'Identifies approval bottlenecks and approvers with pending items';

-- =============================================================================
-- MAINTENANCE PROCEDURES
-- =============================================================================

-- Procedure to archive old approval records
CREATE OR REPLACE PROCEDURE scheduling.archive_old_approvals(
    p_days_old INTEGER DEFAULT 365,
    p_batch_size INTEGER DEFAULT 1000
)
LANGUAGE plpgsql
AS $$
DECLARE
    v_archived_count INTEGER;
BEGIN
    -- Archive approvals older than specified days
    WITH archived AS (
        DELETE FROM scheduling.schedule_approvals
        WHERE approval_id IN (
            SELECT approval_id
            FROM scheduling.schedule_approvals
            WHERE completed_at < CURRENT_TIMESTAMP - (p_days_old || ' days')::INTERVAL
            AND status IN ('APPROVED', 'REJECTED', 'CANCELLED', 'REVOKED')
            LIMIT p_batch_size
        )
        RETURNING *
    )
    INSERT INTO scheduling.schedule_approvals_archive
    SELECT * FROM archived;
    
    GET DIAGNOSTICS v_archived_count = ROW_COUNT;
    
    RAISE NOTICE 'Archived % old approval records', v_archived_count;
    
    -- Log the operation
    INSERT INTO system.maintenance_logs (
        log_type,
        component,
        message,
        started_at,
        completed_at,
        status,
        metadata
    ) VALUES (
        'DATA_ARCHIVE',
        'scheduling.archive_old_approvals',
        format('Archived %s approval records older than %s days', v_archived_count, p_days_old),
        CURRENT_TIMESTAMP,
        CURRENT_TIMESTAMP,
        'SUCCESS',
        jsonb_build_object('archived_count', v_archived_count, 'days_old', p_days_old)
    );
END;
$$;

COMMENT ON PROCEDURE scheduling.archive_old_approvals IS 
'Archives old approval records to maintain table performance';

-- Procedure to clean up old history records
CREATE OR REPLACE PROCEDURE scheduling.cleanup_old_history(
    p_days_old INTEGER DEFAULT 730,
    p_batch_size INTEGER DEFAULT 5000
)
LANGUAGE plpgsql
AS $$
DECLARE
    v_deleted_count INTEGER;
BEGIN
    -- Delete history records older than specified days (after archiving)
    WITH deleted AS (
        DELETE FROM scheduling.schedule_history
        WHERE history_id IN (
            SELECT history_id
            FROM scheduling.schedule_history
            WHERE changed_at < CURRENT_TIMESTAMP - (p_days_old || ' days')::INTERVAL
            AND impact_assessment NOT IN ('CRITICAL', 'HIGH')
            LIMIT p_batch_size
        )
        RETURNING *
    )
    INSERT INTO scheduling.schedule_history_archive
    SELECT * FROM deleted;
    
    GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
    
    RAISE NOTICE 'Cleaned up % old history records', v_deleted_count;
    
    -- Log the operation
    INSERT INTO system.maintenance_logs (
        log_type,
        component,
        message,
        started_at,
        completed_at,
        status,
        metadata
    ) VALUES (
        'DATA_CLEANUP',
        'scheduling.cleanup_old_history',
        format('Cleaned up %s history records older than %s days', v_deleted_count, p_days_old),
        CURRENT_TIMESTAMP,
        CURRENT_TIMESTAMP,
        'SUCCESS',
        jsonb_build_object('deleted_count', v_deleted_count, 'days_old', p_days_old)
    );
END;
$$;

COMMENT ON PROCEDURE scheduling.cleanup_old_history IS 
'Clean up old history records while preserving critical changes';

