    first_name,
    last_name,
    skill_name,
    certification_name,
    status,
    proficiency_level,
    is_shift_qualified,
    days_until_expiry,
    qualified_positions,
    qualified_locations
FROM scheduling.vw_employee_shift_qualifications
LIMIT 10;

