    'REGULATORY', 'PARTNER', 'CUSTOM'
);
RAISE NOTICE 'Created enum type: scheduling.export_target_system_enum';
ELSE
RAISE NOTICE 'Enum type scheduling.export_target_system_enum already exists';
END IF;
END$$;

