-- Serial No: P-001 | PROCEDURE: scheduling.refresh_all_materialized_views
-- Purpose: Comprehensive refresh of all materialized views in dependency order
-- Business Case: This procedure ensures all materialized views are refreshed in the correct
-- order to maintain data consistency across dependent views. It handles errors gracefully,
-- logs refresh statistics, and provides monitoring capabilities for data freshness.
-- KPI: Refresh success rate, Total refresh duration, Data consistency score

CREATE OR REPLACE PROCEDURE scheduling.refresh_all_materialized_views(
    p_concurrent BOOLEAN DEFAULT TRUE,
    p_log_results BOOLEAN DEFAULT TRUE
)
LANGUAGE plpgsql
AS $$
DECLARE
    v_start_time TIMESTAMPTZ := CURRENT_TIMESTAMP;
    v_view_record RECORD;
    v_error_message TEXT;
    v_success_count INTEGER := 0;
    v_failure_count INTEGER := 0;
    v_duration_ms INTEGER;
BEGIN
    -- Log start of refresh process
    IF p_log_results THEN
        INSERT INTO system.maintenance_logs (
            log_type, component, message, started_at
        ) VALUES (
            'MATERIALIZED_VIEW_REFRESH',
            'scheduling.refresh_all_materialized_views',
            'Starting refresh of all materialized views',
            v_start_time
        );
    END IF;

    -- Refresh views in dependency order
    FOR v_view_record IN (
        SELECT 
            schemaname || '.' || matviewname AS view_name,
            matviewname,
            schemaname
        FROM pg_matviews
        WHERE schemaname IN ('scheduling', 'analytics', 'compliance', 'finance', 'performance')
        ORDER BY 
            CASE 
                WHEN matviewname = 'mv_daily_coverage_summary' THEN 1
                WHEN matviewname = 'mv_employee_compliance' THEN 2
                WHEN matviewname = 'mv_shift_pattern_analysis' THEN 3
                WHEN matviewname = 'mv_schedule_optimization_metrics' THEN 4
                WHEN matviewname = 'mv_compliance_dashboard' THEN 5
                WHEN matviewname = 'mv_workforce_productivity' THEN 6
                WHEN matviewname = 'mv_labor_cost_forecast' THEN 7
                WHEN matviewname = 'mv_shift_bidding_analytics' THEN 8
                ELSE 9
            END
    ) LOOP
        BEGIN
            RAISE NOTICE 'Refreshing view: %', v_view_record.view_name;
            
            -- Refresh the view
            IF p_concurrent AND v_view_record.matviewname LIKE 'mv_%' THEN
                EXECUTE format('REFRESH MATERIALIZED VIEW CONCURRENTLY %I.%I', 
                               v_view_record.schemaname, v_view_record.matviewname);
            ELSE
                EXECUTE format('REFRESH MATERIALIZED VIEW %I.%I', 
                               v_view_record.schemaname, v_view_record.matviewname);
            END IF;
            
            v_success_count := v_success_count + 1;
            
            -- Log success
            IF p_log_results THEN
                INSERT INTO system.maintenance_logs (
                    log_type, component, message, started_at, completed_at, status
                ) VALUES (
                    'MATERIALIZED_VIEW_REFRESH',
                    v_view_record.view_name,
                    'Successfully refreshed',
                    v_start_time,
                    CURRENT_TIMESTAMP,
                    'SUCCESS'
                );
            END IF;
            
        EXCEPTION WHEN OTHERS THEN
            GET STACKED DIAGNOSTICS v_error_message = MESSAGE_TEXT;
            v_failure_count := v_failure_count + 1;
            
            -- Log failure
            IF p_log_results THEN
                INSERT INTO system.maintenance_logs (
                    log_type, component, message, started_at, completed_at, status, error_message
                ) VALUES (
                    'MATERIALIZED_VIEW_REFRESH',
                    v_view_record.view_name,
                    'Failed to refresh',
                    v_start_time,
                    CURRENT_TIMESTAMP,
                    'FAILED',
                    v_error_message
                );
            END IF;
            
            RAISE WARNING 'Failed to refresh view %: %', v_view_record.view_name, v_error_message;
        END;
    END LOOP;
    
    v_duration_ms := EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP - v_start_time)) * 1000;
    
    -- Log completion
    IF p_log_results THEN
        INSERT INTO system.maintenance_logs (
            log_type, component, message, started_at, completed_at, status, metadata
        ) VALUES (
            'MATERIALIZED_VIEW_REFRESH',
            'scheduling.refresh_all_materialized_views',
            format('Completed refresh: %s succeeded, %s failed', v_success_count, v_failure_count),
            v_start_time,
            CURRENT_TIMESTAMP,
            CASE WHEN v_failure_count = 0 THEN 'SUCCESS' ELSE 'PARTIAL' END,
            jsonb_build_object(
                'success_count', v_success_count,
                'failure_count', v_failure_count,
                'duration_ms', v_duration_ms
            )
        );
    END IF;
    
    RAISE NOTICE 'Refresh completed: % succeeded, % failed in % ms', 
                 v_success_count, v_failure_count, v_duration_ms;
END;
$$;

COMMENT ON PROCEDURE scheduling.refresh_all_materialized_views IS 
'Comprehensive refresh of all materialized views in dependency order with error handling and logging';


